    q4_q5_k_q8k_triple_packed_qkv_panel16_mr4: u64 = 0,
    q4_q5_k_q8k_triple_packed_qkv_panel16_mr2: u64 = 0,
    q4_q5_k_q8k_triple_packed_qkv_panel16_mr1: u64 = 0,
    q4_q5_k_prepared_panel: u64 = 0,
    q8_0_direct: u64 = 0,
    q8_0_pair: u64 = 0,
    q8_0_triple: u64 = 0,
    q8_k_q8k_activation: u64 = 0,
    q8k_activation_alloc_ns: u64 = 0,
    q8k_activation_quant_ns: u64 = 0,
    q8_0_activation_alloc_ns: u64 = 0,
    q8_0_activation_quant_ns: u64 = 0,
