    fn nsToMs(ns: u64) f64 {
        return @as(f64, @floatFromInt(ns)) / 1_000_000.0;
    }

    pub fn print(self: NativeQuantDispatchStats) void {
        std.debug.print(
            "quant_dispatch q4q5={} q4q5_pair={} q4q5_triple={} packed_qkv_mr4={} packed_qkv_mr2={} q4q5_panel={} dequant={} dequant_pair={} dequant_triple={} q8_0={} q8_0_pair={} q8_0_triple={} q8k_alloc_ms={d:.3} q8k_quant_ms={d:.3} q4q5_compute_ms={d:.3} q4q5_pair_compute_ms={d:.3} q4q5_triple_compute_ms={d:.3} dequant_fetch_ms={d:.3} dequant_sgemm_compute_ms={d:.3}\n",
            .{
                self.q4_q5_k_q8k_activation,
                self.q4_q5_k_q8k_activation_pair,
                self.q4_q5_k_q8k_activation_triple,
                self.q4_q5_k_q8k_triple_packed_qkv_panel16_mr4,
                self.q4_q5_k_q8k_triple_packed_qkv_panel16_mr2,
                self.q4_q5_k_prepared_panel,
                self.dequant_sgemm,
                self.dequant_sgemm_pair,
                self.dequant_sgemm_triple,
                self.q8_0_direct,
                self.q8_0_pair,
                self.q8_0_triple,
                nsToMs(self.q8k_activation_alloc_ns),
                nsToMs(self.q8k_activation_quant_ns),
                nsToMs(self.q4q5_q8k_compute_ns),
                nsToMs(self.q4q5_q8k_pair_compute_ns),
                nsToMs(self.q4q5_q8k_triple_compute_ns),
                nsToMs(self.dequant_fetch_ns),
                nsToMs(self.dequant_sgemm_compute_ns),
            },
        );
    }
};

