pub inline fn nativeQuantDispatchStatsEnabled() bool {
    return builtin.is_test or build_options.enable_native_quant_dispatch_stats;
}

pub fn resetNativeQuantDispatchStats() void {
    if (!nativeQuantDispatchStatsEnabled()) return;
    native_quant_dispatch_stats.reset();
}

pub fn nativeQuantDispatchStats() NativeQuantDispatchStats {
    if (!nativeQuantDispatchStatsEnabled()) return .{};
    return native_quant_dispatch_stats.snapshot();
}

pub fn resetNativeQuantDispatchStatsForTest() void {
    resetNativeQuantDispatchStats();
}

pub fn nativeQuantDispatchStatsForTest() NativeQuantDispatchStats {
    return nativeQuantDispatchStats();
}

pub fn nativeQuantMatmulOperatorPlanForTensor(
    weight: CT,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) ?ops.OperatorPlan {
    const storage = toBuf(weight).quantized_storage orelse return null;
    const format = backend_contracts.quantFormatFromGgufTensorType(storage.tensor_type) orelse return null;
    const plan = quant_matmul.plan(.{
        .rows = rows,
        .in_dim = in_dim,
        .out_dim = out_dim,
        .format = format,
    });
    if (plan.operator == .fallback) return null;
    return .{ .quant_matmul = plan };
}

pub fn nativeTensorHasQuantizedStorage(weight: CT) bool {
    return toBuf(weight).quantized_storage != null;
}

