fn noteNativeQuantDispatch(kind: NativeQuantDispatchKind) void {
    if (!nativeQuantDispatchStatsEnabled()) return;
    switch (kind) {
        .dequant_sgemm => _ = native_quant_dispatch_stats.dequant_sgemm.fetchAdd(1, .monotonic),
        .dequant_sgemm_pair => _ = native_quant_dispatch_stats.dequant_sgemm_pair.fetchAdd(1, .monotonic),
        .dequant_sgemm_triple => _ = native_quant_dispatch_stats.dequant_sgemm_triple.fetchAdd(1, .monotonic),
        .legacy_activation => _ = native_quant_dispatch_stats.legacy_activation.fetchAdd(1, .monotonic),
        .legacy_activation_pair => _ = native_quant_dispatch_stats.legacy_activation_pair.fetchAdd(1, .monotonic),
        .legacy_activation_triple => _ = native_quant_dispatch_stats.legacy_activation_triple.fetchAdd(1, .monotonic),
        .q4_q5_k_q8k_activation => _ = native_quant_dispatch_stats.q4_q5_k_q8k_activation.fetchAdd(1, .monotonic),
        .q4_q5_k_q8k_activation_pair => _ = native_quant_dispatch_stats.q4_q5_k_q8k_activation_pair.fetchAdd(1, .monotonic),
        .q4_q5_k_q8k_activation_triple => _ = native_quant_dispatch_stats.q4_q5_k_q8k_activation_triple.fetchAdd(1, .monotonic),
        .q4_q5_k_q8k_triple_packed_qkv_panel16_mr8 => _ = native_quant_dispatch_stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr8.fetchAdd(1, .monotonic),
        .q4_q5_k_q8k_triple_packed_qkv_panel16_mr4 => _ = native_quant_dispatch_stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr4.fetchAdd(1, .monotonic),
        .q4_q5_k_q8k_triple_packed_qkv_panel16_mr2 => _ = native_quant_dispatch_stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr2.fetchAdd(1, .monotonic),
        .q4_q5_k_q8k_triple_packed_qkv_panel16_mr1 => _ = native_quant_dispatch_stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr1.fetchAdd(1, .monotonic),
        .q4_q5_k_prepared_panel => _ = native_quant_dispatch_stats.q4_q5_k_prepared_panel.fetchAdd(1, .monotonic),
        .q8_0_direct => _ = native_quant_dispatch_stats.q8_0_direct.fetchAdd(1, .monotonic),
        .q8_0_pair => _ = native_quant_dispatch_stats.q8_0_pair.fetchAdd(1, .monotonic),
        .q8_0_triple => _ = native_quant_dispatch_stats.q8_0_triple.fetchAdd(1, .monotonic),
        .q8_k_q8k_activation => _ = native_quant_dispatch_stats.q8_k_q8k_activation.fetchAdd(1, .monotonic),
    }
}

fn nativeQuantPhaseStart() u64 {
    if (!nativeQuantDispatchStatsEnabled()) return 0;
    var timespec: std.posix.timespec = undefined;
    switch (std.posix.errno(std.posix.system.clock_gettime(std.posix.CLOCK.MONOTONIC, &timespec))) {
        .SUCCESS => return @intCast(@as(i128, timespec.sec) * std.time.ns_per_s + timespec.nsec),
        else => return 0,
    }
}

fn noteNativeQuantPhase(kind: NativeQuantPhaseKind, start_ns: u64) void {
    if (start_ns == 0 or !nativeQuantDispatchStatsEnabled()) return;
    const elapsed = nativeQuantPhaseStart() - start_ns;
    switch (kind) {
        .q8k_activation_alloc => _ = native_quant_dispatch_stats.q8k_activation_alloc_ns.fetchAdd(elapsed, .monotonic),
        .q8k_activation_quant => _ = native_quant_dispatch_stats.q8k_activation_quant_ns.fetchAdd(elapsed, .monotonic),
        .q8_0_activation_alloc => _ = native_quant_dispatch_stats.q8_0_activation_alloc_ns.fetchAdd(elapsed, .monotonic),
        .q8_0_activation_quant => _ = native_quant_dispatch_stats.q8_0_activation_quant_ns.fetchAdd(elapsed, .monotonic),
        .q8_0_compute => _ = native_quant_dispatch_stats.q8_0_compute_ns.fetchAdd(elapsed, .monotonic),
        .legacy_activation_alloc => _ = native_quant_dispatch_stats.legacy_activation_alloc_ns.fetchAdd(elapsed, .monotonic),
        .legacy_activation_quant => _ = native_quant_dispatch_stats.legacy_activation_quant_ns.fetchAdd(elapsed, .monotonic),
        .legacy_compute => _ = native_quant_dispatch_stats.legacy_compute_ns.fetchAdd(elapsed, .monotonic),
        .q4q5_q8k_compute => _ = native_quant_dispatch_stats.q4q5_q8k_compute_ns.fetchAdd(elapsed, .monotonic),
        .q4q5_q8k_pair_compute => _ = native_quant_dispatch_stats.q4q5_q8k_pair_compute_ns.fetchAdd(elapsed, .monotonic),
        .q4q5_q8k_triple_compute => _ = native_quant_dispatch_stats.q4q5_q8k_triple_compute_ns.fetchAdd(elapsed, .monotonic),
        .dequant_fetch => _ = native_quant_dispatch_stats.dequant_fetch_ns.fetchAdd(elapsed, .monotonic),
        .dequant_sgemm_compute => _ = native_quant_dispatch_stats.dequant_sgemm_compute_ns.fetchAdd(elapsed, .monotonic),
    }
}

const ReservationState = struct {
    count: usize,
    reservation: run_memory.Reservation,
};

fn shouldUseCpuChunkedDenseFallback(name: []const u8) bool {
    return std.mem.eql(u8, name, "lm_head.weight") or
        std.mem.endsWith(u8, name, ".self_attn.q_proj.weight") or
        std.mem.endsWith(u8, name, ".self_attn.k_proj.weight") or
        std.mem.endsWith(u8, name, ".self_attn.v_proj.weight") or
        std.mem.endsWith(u8, name, ".self_attn.o_proj.weight") or
        std.mem.endsWith(u8, name, ".mlp.gate_proj.weight") or
        std.mem.endsWith(u8, name, ".mlp.up_proj.weight") or
        std.mem.endsWith(u8, name, ".mlp.down_proj.weight") or
        std.mem.endsWith(u8, name, ".block_sparse_moe.gate.weight") or
        std.mem.endsWith(u8, name, ".w1.weight") or
        std.mem.endsWith(u8, name, ".w2.weight") or
        std.mem.endsWith(u8, name, ".w3.weight") or
        std.mem.endsWith(u8, name, ".c_attn.weight") or
        std.mem.endsWith(u8, name, ".c_proj.weight") or
        std.mem.endsWith(u8, name, ".c_fc.weight") or
        std.mem.endsWith(u8, name, ".fc1.weight") or
        std.mem.endsWith(u8, name, ".fc2.weight");
}

fn quantizedDequantSgemmEnabled() bool {
    // Global all-format dequant-SGEMM is intentionally opt-in: it may cache
    // dense f32 copies up to the configured cache budget. On cache denial,
    // transient dense scratch is denied unless explicitly enabled for
    // benchmarking with TERMITE_QUANT_DEQUANT_SGEMM_SCRATCH=1.
    switch (quantized_dequant_sgemm_override.load(.monotonic)) {
        0 => return false,
        1 => return true,
        else => {},
    }
    const value = std.c.getenv("TERMITE_QUANT_DEQUANT_SGEMM") orelse return false;
    return !std.mem.eql(u8, std.mem.span(value), "0");
}

fn quantDequantDenseCacheEnabled() bool {
    return platform.env.getenvBoolDefault("TERMITE_QUANT_DEQUANT_CACHE", true);
}

fn quantDequantSgemmScratchEnabled() bool {
    switch (quantized_dequant_sgemm_scratch_override.load(.monotonic)) {
        0 => return false,
        1 => return true,
        else => {},
    }
    const value = std.c.getenv("TERMITE_QUANT_DEQUANT_SGEMM_SCRATCH") orelse return false;
    return !std.mem.eql(u8, std.mem.span(value), "0");
}

fn quantDequantDenseCacheMaxBytes() usize {
    return parseEnvUsize("TERMITE_QUANT_DEQUANT_SGEMM_CACHE_BYTES") orelse 512 * 1024 * 1024;
}

fn dequantSgemmSupportedQuant(known: gguf_tensor_types.KnownTensorType) bool {
    return switch (known) {
        .Q1_0,
        .Q4_0,
        .Q4_1,
        .Q5_0,
        .Q5_1,
        .Q8_0,
        .Q8_1,
        .Q2_K,
        .Q3_K,
        .Q4_K,
        .Q5_K,
        .Q6_K,
        .Q8_K,
        => true,
        else => false,
    };
}

fn clipClapDequantSgemmEnabled() bool {
    switch (clipclap_dequant_sgemm_override.load(.monotonic)) {
        0 => return false,
        1 => return true,
        else => {},
    }
    return false;
}

fn isClipClapProjectionWeightName(name: []const u8) bool {
    return std.mem.eql(u8, name, "text_projection.weight") or
        std.mem.eql(u8, name, "visual_projection.weight") or
        std.mem.startsWith(u8, name, "text_projection.") or
        std.mem.startsWith(u8, name, "visual_projection.") or
        std.mem.startsWith(u8, name, "audio_projection.") or
        std.mem.eql(u8, name, "clip.text_projection.weight") or
        std.mem.eql(u8, name, "clip.visual_projection.weight") or
        std.mem.startsWith(u8, name, "clap.text_projection.") or
        std.mem.startsWith(u8, name, "clap.audio_projection.");
}

fn shouldUseClipClapDequantSgemm(
    name: []const u8,
    rows: usize,
    out_dim: usize,
    tensor_type: gguf_tensor_types.TensorType,
) bool {
    if (!clipClapDequantSgemmEnabled()) return false;
    if (out_dim < 512) return false;
    const known = switch (tensor_type) {
        .known => |value| value,
        else => return false,
    };
    if (!dequantSgemmSupportedQuant(known)) return false;

    const known_prefix =
        std.mem.startsWith(u8, name, "text_model.") or
        std.mem.startsWith(u8, name, "vision_model.") or
        std.mem.startsWith(u8, name, "audio_model.");

    if (isClipClapProjectionWeightName(name)) {
        return rows <= 4;
    }

    if (rows < 16 or !known_prefix) return false;

    return std.mem.endsWith(u8, name, ".self_attn.q_proj.weight") or
        std.mem.endsWith(u8, name, ".self_attn.k_proj.weight") or
        std.mem.endsWith(u8, name, ".self_attn.v_proj.weight") or
        std.mem.endsWith(u8, name, ".self_attn.out_proj.weight") or
        std.mem.endsWith(u8, name, ".attention.self.query.weight") or
        std.mem.endsWith(u8, name, ".attention.self.key.weight") or
        std.mem.endsWith(u8, name, ".attention.self.value.weight") or
        std.mem.endsWith(u8, name, ".attention.output.dense.weight") or
        std.mem.endsWith(u8, name, ".mlp.fc1.weight") or
        std.mem.endsWith(u8, name, ".mlp.fc2.weight") or
        std.mem.endsWith(u8, name, ".intermediate.dense.weight") or
        std.mem.endsWith(u8, name, ".output.dense.weight");
}

fn shouldUseQuantizedDequantSgemm(
    name: []const u8,
    rows: usize,
    out_dim: usize,
    storage: *const QuantizedStorage,
) bool {
    if (storage.packed_expert != null) return false;
    const known = switch (storage.tensor_type) {
        .known => |value| value,
        else => return false,
    };
    if (!dequantSgemmSupportedQuant(known)) return false;
    if (quantizedDequantSgemmEnabled()) return true;
    return shouldUseClipClapDequantSgemm(name, rows, out_dim, storage.tensor_type);
}

fn canFallbackDenseBudgetPressure(name: []const u8, entry: *const LazyWeightEntry) bool {
    return entry.expert_coord == null and shouldUseCpuChunkedDenseFallback(name);
}

fn shouldDegradeQuantBudgetPressure(entry: *const LazyWeightEntry) bool {
    return entry.expert_coord == null;
}

fn noteSharedCacheDenial(
    run_budget: ?*run_memory.RunBudget,
    tier_cache: *const tier_cache_mod.SharedCache,
    tier: ResidencyTier,
    bytes: usize,
) void {
    if (run_budget) |budget| {
        budget.noteSharedCacheDenial(
            tier,
            bytes,
            switch (tier) {
                .disk => 0,
                .host => tier_cache.host_bytes,
                .backend => tier_cache.backend_bytes,
            },
            switch (tier) {
                .disk => 0,
                .host => tier_cache.budget.host_limit_bytes,
                .backend => tier_cache.budget.backend_limit_bytes,
            },
        );
    }
}

fn logSharedCacheDenial(stage: []const u8, tier_cache: *const tier_cache_mod.SharedCache, name: []const u8) void {
    var buf: [256]u8 = undefined;
    const detail = tier_cache.lastDenialString(&buf) catch "shared tier cache memory budget exceeded";
    std.log.warn("native shared cache denial stage={s} weight={s}: {s}", .{
        stage,
        if (name.len > 0) name else "<unnamed>",
        detail,
    });
}

/// Internal wrapper: an owned or borrowed f32 slice.
