    tier_cache: ?tier_cache_mod.SharedCache = null,
    shared_prefetch: ?*tier_shared_mod.SharedPrefetchState = null,
    allow_direct_quant: bool = true,
    gliner_head_dense_cache: std.StringHashMapUnmanaged(DenseDequantCacheEntry) = .{},
    gliner_head_dense_cache_bytes: usize = 0,
    gliner_head_dense_cache_lock: std.atomic.Mutex = .unlocked,
    quant_dequant_cache_hits: u64 = 0,
    quant_dequant_cache_misses: u64 = 0,
    quant_dequant_cache_inserts: u64 = 0,
    quant_dequant_cache_disabled: u64 = 0,
    quant_dequant_cache_too_large: u64 = 0,
    quant_dequant_cache_capacity_denied: u64 = 0,
    quant_dequant_cache_tier_denied: u64 = 0,
    quant_dequant_cache_scratch_fallbacks: u64 = 0,
    quant_dequant_cache_scratch_denied: u64 = 0,
};

/// Internal wrapper: an owned or borrowed f32 slice.
const Buf = struct {
    data: []f32,
    allocator: std.mem.Allocator,
    owned: bool,
    shared_data_refcount: ?*usize = null,
    logical_shape: ?[]i64 = null,
    logical_shape_inline: bool = false,
    inline_logical_shape: [8]i64 = undefined,
    view_strides: ?[]usize = null,
    view_base_offset: usize = 0,
    declared_dtype: ?tensor_mod.DType = null,
    name: []const u8 = "",
    lazy_entry: ?*LazyWeightEntry = null,
    quantized_storage: ?*const QuantizedStorage = null,
    owned_quantized_storage: ?*QuantizedStorage = null,
    source_tensor: ?*const tensor_mod.Tensor = null,
    owned_source_tensor: ?*tensor_mod.Tensor = null,
    reservation: ?run_memory.Reservation = null,
};

fn toBuf(ct: CT) *Buf {
    return @ptrCast(@alignCast(ct));
}

fn maybeLogLargeTensor(op_name: []const u8, len: usize, shape: ?[]const i64) void {
    if (len >= large_tensor_log_threshold) {
        std.log.warn("{s} large tensor len={d} shape={?any}", .{ op_name, len, shape });
    }
}

fn releaseOwnedDenseData(buf: *Buf) void {
    if (!buf.owned) return;
    if (buf.shared_data_refcount) |refcount| {
        std.debug.assert(refcount.* > 0);
        refcount.* -= 1;
        if (refcount.* == 0) {
            buf.allocator.free(buf.data);
            buf.allocator.destroy(refcount);
        }
    } else {
        buf.allocator.free(buf.data);
    }
    buf.owned = false;
    buf.shared_data_refcount = null;
}

fn releaseLogicalShape(buf: *Buf) void {
    if (buf.logical_shape) |shape| {
        if (!buf.logical_shape_inline) buf.allocator.free(shape);
    }
    buf.logical_shape = null;
    buf.logical_shape_inline = false;
}

fn materializeViewData(buf: *Buf) !void {
    const logical_shape = buf.logical_shape orelse return;
    const view_strides = buf.view_strides orelse return;
    if (logical_shape.len != view_strides.len) return error.InvalidTensorShape;

    const out_len = if (logical_shape.len == 0) @as(usize, 1) else safeShapeNumel(logical_shape) orelse return error.InvalidTensorShape;
    maybeLogLargeTensor("materialize_view", out_len, logical_shape);
    const output = try buf.allocator.alloc(f32, out_len);
    errdefer buf.allocator.free(output);

    if (logical_shape.len == 0) {
        if (buf.view_base_offset >= buf.data.len) return error.InvalidTensorShape;
        output[0] = buf.data[buf.view_base_offset];
    } else {
        var out_strides: [8]usize = undefined;
        computeStrides(logical_shape, out_strides[0..logical_shape.len]);
        for (0..out_len) |flat_out| {
            var remaining = flat_out;
            var flat_in = buf.view_base_offset;
            for (0..logical_shape.len) |d| {
                const coord = remaining / out_strides[d];
                remaining %= out_strides[d];
                flat_in += coord * view_strides[d];
            }
            if (flat_in >= buf.data.len) {
                std.log.warn("materialize view OOB logical_shape={any} strides={any} base_offset={d} flat_out={d} flat_in={d} data_len={d}", .{
                    logical_shape,
                    view_strides,
                    buf.view_base_offset,
                    flat_out,
                    flat_in,
                    buf.data.len,
                });
                return error.InvalidTensorShape;
            }
            output[flat_out] = buf.data[flat_in];
        }
    }

    releaseOwnedDenseData(buf);
    const refcount = try buf.allocator.create(usize);
    refcount.* = 1;
    buf.data = output;
    buf.owned = true;
    buf.shared_data_refcount = refcount;
    buf.allocator.free(view_strides);
    buf.view_strides = null;
    buf.view_base_offset = 0;
}

// Abramowitz & Stegun 7.1.26 — max error ~1.5e-7
fn erfApprox(x: f32) f32 {
    const a1: f32 = 0.254829592;
    const a2: f32 = -0.284496736;
    const a3: f32 = 1.421413741;
    const a4: f32 = -1.453152027;
    const a5: f32 = 1.061405429;
    const p: f32 = 0.3275911;
    const sign: f32 = if (x < 0) -1.0 else 1.0;
    const ax = @abs(x);
    const t = 1.0 / (1.0 + p * ax);
    const poly = ((((a5 * t + a4) * t + a3) * t + a2) * t + a1) * t;
    return sign * (1.0 - poly * @exp(-ax * ax));
}

fn getData(ct: CT) []f32 {
    const buf = toBuf(ct);
    if (buf.view_strides != null) {
        materializeViewData(buf) catch |err| std.debug.panic("failed to materialize tensor view: {s}", .{@errorName(err)});
    }
    return buf.data;
}

fn ownedDenseBufWithMaxSharedRefs(ct: CT, max_shared_refs: usize) ?*Buf {
    const buf = toBuf(ct);
    if (!buf.owned or buf.shared_data_refcount == null) return null;
    if (buf.shared_data_refcount.?.* == 0 or buf.shared_data_refcount.?.* > max_shared_refs) return null;
    if (buf.view_strides != null) return null;
    if (buf.lazy_entry != null or buf.quantized_storage != null or buf.source_tensor != null or buf.owned_quantized_storage != null or buf.owned_source_tensor != null) return null;
    return buf;
}

fn uniqueOwnedDenseBuf(ct: CT) ?*Buf {
    return ownedDenseBufWithMaxSharedRefs(ct, 1);
}

fn aliasDenseBufWithShape(self: *NativeCompute, input: CT, shape: []const i64) !CT {
    const source = toBuf(input);
    if (source.view_strides != null or source.lazy_entry != null or source.quantized_storage != null or source.source_tensor != null or source.owned_quantized_storage != null or source.owned_source_tensor != null) {
        return error.UnsupportedTensorType;
    }

    if (source.owned and source.shared_data_refcount != null) {
        source.shared_data_refcount.?.* += 1;

        const alias = try self.allocator.create(Buf);
        errdefer source.shared_data_refcount.?.* -= 1;
        alias.* = .{
            .data = source.data,
            .allocator = self.allocator,
            .owned = true,
            .shared_data_refcount = source.shared_data_refcount,
            .logical_shape = try self.allocator.dupe(i64, shape),
            .view_strides = null,
            .view_base_offset = 0,
            .declared_dtype = source.declared_dtype,
            .name = source.name,
            .lazy_entry = null,
            .quantized_storage = null,
            .owned_quantized_storage = null,
            .source_tensor = null,
            .owned_source_tensor = null,
            .reservation = null,
        };
        return alias;
    }

    const alias = try self.allocator.create(Buf);
    alias.* = .{
        .data = source.data,
        .allocator = self.allocator,
        .owned = false,
        .shared_data_refcount = null,
        .logical_shape = try self.allocator.dupe(i64, shape),
        .view_strides = null,
        .view_base_offset = 0,
        .declared_dtype = source.declared_dtype,
        .name = source.name,
        .lazy_entry = null,
        .quantized_storage = null,
        .owned_quantized_storage = null,
        .source_tensor = null,
        .owned_source_tensor = null,
        .reservation = null,
    };
    return alias;
}

fn logicalStridesOrContiguous(input: CT, resolved_shape: []const i64, scratch: []usize) []const usize {
    const buf = toBuf(input);
    if (buf.view_strides) |strides| return strides;
    computeStrides(resolved_shape, scratch[0..resolved_shape.len]);
    return scratch[0..resolved_shape.len];
}

fn makeDenseViewAlias(
    self: *NativeCompute,
    input: CT,
    shape: []const i64,
    strides: []const usize,
    base_offset: usize,
) !CT {
    const source = toBuf(input);
    if (source.lazy_entry != null or source.quantized_storage != null or source.source_tensor != null or source.owned_quantized_storage != null or source.owned_source_tensor != null) {
        return error.UnsupportedTensorType;
    }

    const alias = try self.allocator.create(Buf);
    errdefer self.allocator.destroy(alias);

    if (source.owned and source.shared_data_refcount != null) {
        source.shared_data_refcount.?.* += 1;
        errdefer source.shared_data_refcount.?.* -= 1;
        alias.* = .{
            .data = source.data,
            .allocator = self.allocator,
            .owned = true,
            .shared_data_refcount = source.shared_data_refcount,
            .logical_shape = try self.allocator.dupe(i64, shape),
            .view_strides = try self.allocator.dupe(usize, strides),
            .view_base_offset = base_offset,
            .declared_dtype = source.declared_dtype,
            .name = source.name,
            .lazy_entry = null,
            .quantized_storage = null,
            .owned_quantized_storage = null,
            .source_tensor = null,
            .owned_source_tensor = null,
            .reservation = null,
        };
        return alias;
    }

    alias.* = .{
        .data = source.data,
        .allocator = self.allocator,
        .owned = false,
        .shared_data_refcount = null,
        .logical_shape = try self.allocator.dupe(i64, shape),
        .view_strides = try self.allocator.dupe(usize, strides),
        .view_base_offset = base_offset,
        .declared_dtype = source.declared_dtype,
        .name = source.name,
        .lazy_entry = null,
        .quantized_storage = null,
        .owned_quantized_storage = null,
        .source_tensor = null,
        .owned_source_tensor = null,
        .reservation = null,
    };
    return alias;
}

const DenseReadPlan = struct {
    data: []const f32,
    strides: []const usize,
    base_offset: usize,
};

const BroadcastReadAccess = struct {
    plan: DenseReadPlan,
    mode: enum {
        general,
        linear,
        scalar,
    },
};

const BinaryBroadcastShape = struct {
    a_shape: []const i64,
    b_shape: []const i64,
    out_shape: []const i64,
    out_len: usize,
};

const BroadcastBlockRepeatPlan = struct {
    prefix_count: usize,
    repeat_count: usize,
    block_len: usize,
    base_offset: usize,
};

const ShapeAwareBinaryOp = enum {
    add,
    mul,
    sub,
    div,
    lt,
};

fn denseReadPlanForResolvedShape(tensor: CT, resolved_shape: []const i64, scratch: []usize) DenseReadPlan {
    const buf = toBuf(tensor);
    if (buf.view_strides != null and buf.lazy_entry == null and buf.quantized_storage == null and buf.source_tensor == null and buf.owned_quantized_storage == null and buf.owned_source_tensor == null) {
        return .{
            .data = buf.data,
            .strides = buf.view_strides.?,
            .base_offset = buf.view_base_offset,
        };
    }
    const dense = getData(tensor);
    computeStrides(resolved_shape, scratch[0..resolved_shape.len]);
    return .{
        .data = dense,
        .strides = scratch[0..resolved_shape.len],
        .base_offset = 0,
    };
}

fn classifyBroadcastReadAccess(plan: DenseReadPlan, operand_shape: []const i64, out_shape: []const i64) BroadcastReadAccess {
    if (operand_shape.len == 0) {
        return .{ .plan = plan, .mode = .scalar };
    }

    if (safeShapeNumel(operand_shape)) |operand_len| {
        if (operand_len == 1) {
            return .{ .plan = plan, .mode = .scalar };
        }
    }

    if (std.mem.eql(i64, operand_shape, out_shape) and operand_shape.len > 0) {
        var expected_strides: [8]usize = undefined;
        computeStrides(operand_shape, expected_strides[0..operand_shape.len]);
        if (std.mem.eql(usize, plan.strides, expected_strides[0..operand_shape.len])) {
            return .{ .plan = plan, .mode = .linear };
        }
    }

    return .{ .plan = plan, .mode = .general };
}

fn detectBroadcastBlockRepeatPlan(plan: DenseReadPlan, operand_shape: []const i64, out_shape: []const i64) ?BroadcastBlockRepeatPlan {
    if (operand_shape.len == 0 or out_shape.len == 0) return null;
    if (operand_shape.len > out_shape.len or operand_shape.len > 8 or out_shape.len > 8) return null;

    const rank_offset = out_shape.len - operand_shape.len;
    var effective_shape: [8]i64 = undefined;
    var effective_strides: [8]usize = undefined;
    for (0..out_shape.len) |dim| {
        if (dim < rank_offset) {
            effective_shape[dim] = 1;
            effective_strides[dim] = 0;
            continue;
        }
        const operand_dim = dim - rank_offset;
        const operand_extent = operand_shape[operand_dim];
        if (operand_extent <= 0) return null;
        const operand_stride = plan.strides[operand_dim];
        effective_shape[dim] = if (operand_extent > 1 and operand_stride != 0) operand_extent else 1;
        effective_strides[dim] = if (effective_shape[dim] > 1) operand_stride else 0;
    }

    var first_non_broadcast: ?usize = null;
    var last_non_broadcast: usize = 0;
    for (effective_shape[0..out_shape.len], 0..) |extent, dim| {
        if (extent > 1) {
            if (first_non_broadcast == null) first_non_broadcast = dim;
            last_non_broadcast = dim;
        }
    }
    if (first_non_broadcast == null) return null;

    var prefix_len: usize = 0;
    while (prefix_len < out_shape.len and effective_shape[prefix_len] > 1) : (prefix_len += 1) {}

    var suffix_start: usize = out_shape.len;
    while (suffix_start > prefix_len and effective_shape[suffix_start - 1] > 1) : (suffix_start -= 1) {}

    for (prefix_len..suffix_start) |dim| {
        if (effective_shape[dim] > 1) return null;
    }

    var expected_strides: [8]usize = undefined;
    computeStrides(effective_shape[0..out_shape.len], expected_strides[0..out_shape.len]);
    for (0..out_shape.len) |dim| {
        if (effective_shape[dim] > 1 and effective_strides[dim] != expected_strides[dim]) return null;
    }

    const prefix_count = safeShapeNumel(effective_shape[0..prefix_len]) orelse 1;
    const repeat_count = safeShapeNumel(out_shape[prefix_len..suffix_start]) orelse return null;
    const block_len = safeShapeNumel(effective_shape[suffix_start..out_shape.len]) orelse 1;
    if (block_len == 0 or repeat_count == 0) return null;
    if (plan.base_offset + prefix_count * block_len > plan.data.len) return null;

    return .{
        .prefix_count = prefix_count,
        .repeat_count = repeat_count,
        .block_len = block_len,
        .base_offset = plan.base_offset,
    };
}

inline fn applyShapeAwareBinaryScalar(a_val: f32, b_val: f32, comptime op: ShapeAwareBinaryOp) f32 {
    return switch (op) {
        .add => a_val + b_val,
        .mul => a_val * b_val,
        .sub => a_val - b_val,
        .div => a_val / b_val,
        .lt => if (a_val < b_val) 1.0 else 0.0,
    };
}

inline fn sameBroadcastBlockRepeatLoop(a: BroadcastBlockRepeatPlan, b: BroadcastBlockRepeatPlan) bool {
    return a.prefix_count == b.prefix_count and a.repeat_count == b.repeat_count and a.block_len == b.block_len;
}

fn preferredBinaryStoredShape(a: CT, b: CT, loose_out_shape: []const i64, out_len: usize) ?[]const i64 {
    const a_len = toBuf(a).data.len;
    const b_len = toBuf(b).data.len;
    if (a_len >= b_len) {
        if (tensorStoredShape(a)) |shape| {
            if (std.mem.eql(i64, shape, loose_out_shape) and shapeMatchesElementCount(shape, out_len)) return shape;
        }
    }
    if (b_len >= a_len) {
        if (tensorStoredShape(b)) |shape| {
            if (std.mem.eql(i64, shape, loose_out_shape) and shapeMatchesElementCount(shape, out_len)) return shape;
        }
    }
    return null;
}

fn resolveBinaryBroadcastShape(
    a: CT,
    b: CT,
    a_shape_buf: *[8]i64,
    b_shape_buf: *[8]i64,
    out_shape_buf: *[8]i64,
) !BinaryBroadcastShape {
    var a_symbolic_buf: [8]i64 = undefined;
    var b_symbolic_buf: [8]i64 = undefined;
    const a_symbolic = symbolicShapeForBroadcast(a, &a_symbolic_buf);
    const b_symbolic = symbolicShapeForBroadcast(b, &b_symbolic_buf);

    var loose_out_shape_buf: [8]i64 = undefined;
    const loose_out_rank = computeBroadcastShape3Loose(a_symbolic, b_symbolic, &.{}, &loose_out_shape_buf) orelse return error.ShapeMismatch;
    const loose_out_shape = loose_out_shape_buf[0..loose_out_rank];

    const a_shape = concretizeBroadcastOperandShape(a_symbolic, toBuf(a).data.len, loose_out_shape, a_shape_buf);
    const b_shape = concretizeBroadcastOperandShape(b_symbolic, toBuf(b).data.len, loose_out_shape, b_shape_buf);
    const out_rank = computeBroadcastShape3(a_shape, b_shape, &.{}, out_shape_buf) orelse return error.ShapeMismatch;
    const out_shape = out_shape_buf[0..out_rank];
    const out_len = if (out_rank == 0) @as(usize, 1) else shapeNumel(out_shape);
    return .{
        .a_shape = a_shape,
        .b_shape = b_shape,
        .out_shape = out_shape,
        .out_len = out_len,
    };
}

fn applyShapeAwareBinaryOp(self: *NativeCompute, a: CT, b: CT, comptime op: ShapeAwareBinaryOp) !?CT {
    if (toBuf(a).source_tensor != null or toBuf(a).quantized_storage != null or toBuf(a).lazy_entry != null) return null;
    if (toBuf(b).source_tensor != null or toBuf(b).quantized_storage != null or toBuf(b).lazy_entry != null) return null;
    if (toBuf(a).view_strides == null and toBuf(b).view_strides == null) return null;

    var a_shape_buf: [8]i64 = undefined;
    var b_shape_buf: [8]i64 = undefined;
    var out_shape_buf: [8]i64 = undefined;
    const shapes = resolveBinaryBroadcastShape(a, b, &a_shape_buf, &b_shape_buf, &out_shape_buf) catch return null;

    var a_stride_scratch: [8]usize = undefined;
    var b_stride_scratch: [8]usize = undefined;
    const a_plan = denseReadPlanForResolvedShape(a, shapes.a_shape, a_stride_scratch[0..shapes.a_shape.len]);
    const b_plan = denseReadPlanForResolvedShape(b, shapes.b_shape, b_stride_scratch[0..shapes.b_shape.len]);
    const a_access = classifyBroadcastReadAccess(a_plan, shapes.a_shape, shapes.out_shape);
    const b_access = classifyBroadcastReadAccess(b_plan, shapes.b_shape, shapes.out_shape);
    var a_stepper = if (a_access.mode == .general) BroadcastStepper.init(shapes.out_shape, shapes.a_shape, a_plan.strides) else null;
    var b_stepper = if (b_access.mode == .general) BroadcastStepper.init(shapes.out_shape, shapes.b_shape, b_plan.strides) else null;

    if (shapes.out_shape.len == 4 and shapes.out_shape[0] == 1 and shapes.out_shape[1] == 8 and shapes.out_shape[2] == 5776 and shapes.out_shape[3] == 64) {
        std.log.warn("shape-aware binary suspicious op={s} a_shape={any} b_shape={any} out_shape={any} a_stored={?any} b_stored={?any} a_mode={s} b_mode={s}", .{
            @tagName(op),
            shapes.a_shape,
            shapes.b_shape,
            shapes.out_shape,
            tensorStoredShape(a),
            tensorStoredShape(b),
            @tagName(a_access.mode),
            @tagName(b_access.mode),
        });
    }
    maybeLogLargeTensor(@tagName(op), shapes.out_len, shapes.out_shape);
    // Two-stage cleanup: while we hold the raw buffer, free it on error.
    // Once makeBuf succeeds the Buf takes ownership, so we null `raw_output`
    // to disarm this errdefer and add a second one that frees the Buf via
    // freeTensor (which also drops the data + refcount).  Without this, a
    // failing withLogicalShape after a successful makeBuf would either
    // leak the Buf metadata or double-free the data.
    const output = try self.allocator.alloc(f32, shapes.out_len);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    if (a_access.mode == .general and b_access.mode != .general) {
        if (detectBroadcastBlockRepeatPlan(a_plan, shapes.a_shape, shapes.out_shape)) |repeat_plan| {
            var out_offset: usize = 0;
            for (0..repeat_plan.prefix_count) |prefix_idx| {
                const lhs_base = repeat_plan.base_offset + prefix_idx * repeat_plan.block_len;
                const lhs_block = a_plan.data[lhs_base .. lhs_base + repeat_plan.block_len];
                for (0..repeat_plan.repeat_count) |_| {
                    for (lhs_block, 0..) |a_val, j| {
                        const i = out_offset + j;
                        const b_offset = switch (b_access.mode) {
                            .scalar => b_plan.base_offset,
                            .linear => b_plan.base_offset + i,
                            .general => unreachable,
                        };
                        if (b_offset >= b_plan.data.len) return error.ShapeMismatch;
                        output[i] = applyShapeAwareBinaryScalar(a_val, b_plan.data[b_offset], op);
                    }
                    out_offset += repeat_plan.block_len;
                }
            }
            if (out_offset != shapes.out_len) return error.ShapeMismatch;
            const result = try self.makeBuf(output, true);
            raw_output = null;
            errdefer freeTensor(self, result);
            return self.withLogicalShape(result, shapes.out_shape);
        }
    }
    if (b_access.mode == .general and a_access.mode != .general) {
        if (detectBroadcastBlockRepeatPlan(b_plan, shapes.b_shape, shapes.out_shape)) |repeat_plan| {
            var out_offset: usize = 0;
            for (0..repeat_plan.prefix_count) |prefix_idx| {
                const rhs_base = repeat_plan.base_offset + prefix_idx * repeat_plan.block_len;
                const rhs_block = b_plan.data[rhs_base .. rhs_base + repeat_plan.block_len];
                for (0..repeat_plan.repeat_count) |_| {
                    for (rhs_block, 0..) |b_val, j| {
                        const i = out_offset + j;
                        const a_offset = switch (a_access.mode) {
                            .scalar => a_plan.base_offset,
                            .linear => a_plan.base_offset + i,
                            .general => unreachable,
                        };
                        if (a_offset >= a_plan.data.len) return error.ShapeMismatch;
                        output[i] = applyShapeAwareBinaryScalar(a_plan.data[a_offset], b_val, op);
                    }
                    out_offset += repeat_plan.block_len;
                }
            }
            if (out_offset != shapes.out_len) return error.ShapeMismatch;
            const result = try self.makeBuf(output, true);
            raw_output = null;
            errdefer freeTensor(self, result);
            return self.withLogicalShape(result, shapes.out_shape);
        }
    }
    for (0..shapes.out_len) |i| {
        const a_offset = switch (a_access.mode) {
            .scalar => a_plan.base_offset,
            .linear => a_plan.base_offset + i,
            .general => a_plan.base_offset + a_stepper.?.currentOffset(),
        };
        const b_offset = switch (b_access.mode) {
            .scalar => b_plan.base_offset,
            .linear => b_plan.base_offset + i,
            .general => b_plan.base_offset + b_stepper.?.currentOffset(),
        };
        if (a_offset >= a_plan.data.len or b_offset >= b_plan.data.len) {
            std.log.warn("shape-aware binary offset mismatch op={s} i={d} out_shape={any} a_shape={any} b_shape={any} offsets={d}/{d} lens={d}/{d} modes={s}/{s} a_strides={any} b_strides={any} a_base={d} b_base={d}", .{
                @tagName(op),
                i,
                shapes.out_shape,
                shapes.a_shape,
                shapes.b_shape,
                a_offset,
                b_offset,
                a_plan.data.len,
                b_plan.data.len,
                @tagName(a_access.mode),
                @tagName(b_access.mode),
                a_plan.strides,
                b_plan.strides,
                a_plan.base_offset,
                b_plan.base_offset,
            });
            return error.ShapeMismatch;
        }
        const a_val = a_plan.data[a_offset];
        const b_val = b_plan.data[b_offset];
        output[i] = applyShapeAwareBinaryScalar(a_val, b_val, op);
        if (a_stepper) |*stepper| stepper.advance();
        if (b_stepper) |*stepper| stepper.advance();
    }

    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    return self.withLogicalShape(result, shapes.out_shape);
}

fn applyShapeAwareBinaryConsumeLeft(a: CT, b: CT, comptime op: ShapeAwareBinaryOp) !?CT {
    if (toBuf(a).source_tensor != null or toBuf(a).quantized_storage != null or toBuf(a).lazy_entry != null) return null;
    if (toBuf(b).source_tensor != null or toBuf(b).quantized_storage != null or toBuf(b).lazy_entry != null) return null;
    const a_buf = ownedDenseBufWithMaxSharedRefs(a, 2) orelse return null;
    if (toBuf(b).view_strides == null) return null;

    var a_shape_buf: [8]i64 = undefined;
    var b_shape_buf: [8]i64 = undefined;
    var out_shape_buf: [8]i64 = undefined;
    const shapes = resolveBinaryBroadcastShape(a, b, &a_shape_buf, &b_shape_buf, &out_shape_buf) catch return null;
    if (!binaryOutputMatchesLhsShape(a, shapes.out_shape, shapes.out_len)) return null;

    var b_stride_scratch: [8]usize = undefined;
    const b_plan = denseReadPlanForResolvedShape(b, shapes.b_shape, b_stride_scratch[0..shapes.b_shape.len]);
    const b_access = classifyBroadcastReadAccess(b_plan, shapes.b_shape, shapes.out_shape);
    if (b_access.mode == .general) {
        if (detectBroadcastBlockRepeatPlan(b_plan, shapes.b_shape, shapes.out_shape)) |repeat_plan| {
            const a_data = a_buf.data;
            var out_offset: usize = 0;
            for (0..repeat_plan.prefix_count) |prefix_idx| {
                const rhs_base = repeat_plan.base_offset + prefix_idx * repeat_plan.block_len;
                const rhs_block = b_plan.data[rhs_base .. rhs_base + repeat_plan.block_len];
                for (0..repeat_plan.repeat_count) |_| {
                    const a_block = a_data[out_offset .. out_offset + repeat_plan.block_len];
                    switch (op) {
                        .add => {
                            for (a_block, rhs_block) |*dst, src| {
                                dst.* += src;
                            }
                        },
                        .mul => {
                            for (a_block, rhs_block) |*dst, src| {
                                dst.* *= src;
                            }
                        },
                        .sub => {
                            for (a_block, rhs_block) |*dst, src| {
                                dst.* -= src;
                            }
                        },
                        .div => {
                            for (a_block, rhs_block) |*dst, src| {
                                dst.* /= src;
                            }
                        },
                        .lt => {
                            for (a_block, rhs_block) |*dst, src| {
                                dst.* = if (dst.* < src) 1.0 else 0.0;
                            }
                        },
                    }
                    out_offset += repeat_plan.block_len;
                }
            }
            if (out_offset != shapes.out_len) return error.ShapeMismatch;
            return a;
        }
    }
    var b_stepper = if (b_access.mode == .general) BroadcastStepper.init(shapes.out_shape, shapes.b_shape, b_plan.strides) else null;

    const a_data = a_buf.data;
    for (0..shapes.out_len) |i| {
        const b_offset = switch (b_access.mode) {
            .scalar => b_plan.base_offset,
            .linear => b_plan.base_offset + i,
            .general => b_plan.base_offset + b_stepper.?.currentOffset(),
        };
        if (b_offset >= b_plan.data.len) return error.ShapeMismatch;
        const b_val = b_plan.data[b_offset];
        switch (op) {
            .add => a_data[i] += b_val,
            .mul => a_data[i] *= b_val,
            .sub => a_data[i] -= b_val,
            .div => a_data[i] /= b_val,
            .lt => a_data[i] = if (a_data[i] < b_val) 1.0 else 0.0,
        }
        if (b_stepper) |*stepper| stepper.advance();
    }
    return a;
}

fn binaryOutputMatchesLhsShape(a: CT, out_shape: []const i64, out_len: usize) bool {
    if (toBuf(a).data.len != out_len) return false;
    if (tensorStoredShape(a)) |shape| {
        if (shape.len != out_shape.len) return false;
        if (resolveShapeFromDataLen(shape, out_len)) |resolved| {
            return std.mem.eql(i64, resolved[0..shape.len], out_shape);
        }
        return std.mem.eql(i64, shape, out_shape);
    }
    return true;
}

fn rank2TensorRead(
    data: []const f32,
    strides: []const usize,
    row_dim: usize,
    col_dim: usize,
    row: usize,
    col: usize,
) f32 {
    return data[row * strides[row_dim] + col * strides[col_dim]];
}

fn flattenedPrefixLastDimRead(
    shape: []const i64,
    strides: []const usize,
    data: []const f32,
    row_index: usize,
    col_index: usize,
) !f32 {
    if (shape.len == 0) return error.UnsupportedShape;
    const last_dim = shape.len - 1;
    var remaining = row_index;
    var flat_index = col_index * strides[last_dim];
    var dim_index = last_dim;
    while (dim_index > 0) {
        dim_index -= 1;
        const dim = positiveShapeDim(shape, dim_index) catch return error.UnsupportedShape;
        const coord = remaining % dim;
        remaining /= dim;
        flat_index += coord * strides[dim_index];
    }
    if (flat_index >= data.len) return error.InvalidTensorShape;
    return data[flat_index];
}

fn canAliasTranspose(shape: []const i64, perm: []const u8) bool {
    var expected_non_singleton: [8]usize = undefined;
    var expected_len: usize = 0;
    for (shape, 0..) |dim, axis| {
        if (dim != 1) {
            expected_non_singleton[expected_len] = axis;
            expected_len += 1;
        }
    }

    var seen_len: usize = 0;
    for (perm) |axis_u8| {
        const axis: usize = axis_u8;
        if (axis >= shape.len) return false;
        if (shape[axis] != 1) {
            if (seen_len >= expected_len or expected_non_singleton[seen_len] != axis) return false;
            seen_len += 1;
        }
    }
    return seen_len == expected_len;
}

fn tensorStoredShape(tensor: CT) ?[]const i64 {
    const buf = toBuf(tensor);
    if (buf.logical_shape) |shape| return shape;
    if (buf.quantized_storage) |storage| return storage.shape;
    if (buf.source_tensor) |source| return source.shape;
    if (buf.lazy_entry) |entry| {
        if (entry.loaded) |*loaded| {
            if (loaded.quantized_storage) |*storage| return storage.shape;
            return loaded.tensor.shape;
        }
    }
    return null;
}

fn storedOrDeclaredShape(tensor: CT, declared: []const i64) []const i64 {
    if (tensorStoredShape(tensor)) |shape| {
        const buf = toBuf(tensor);
        if (buf.view_strides == null and
            buf.source_tensor == null and
            buf.owned_source_tensor == null and
            buf.quantized_storage == null and
            buf.owned_quantized_storage == null and
            buf.lazy_entry == null)
        {
            if (!denseShapeCompatibleWithDataLen(shape, buf.data.len)) return declared;
        }
        return shape;
    }
    return declared;
}

fn tensorLogicalElementCount(tensor: CT, declared: []const i64) ?usize {
    const buf = toBuf(tensor);
    if (tensorStoredShape(tensor)) |shape| {
        if (buf.view_strides == null and
            buf.source_tensor == null and
            buf.owned_source_tensor == null and
            buf.quantized_storage == null and
            buf.owned_quantized_storage == null and
            buf.lazy_entry == null and
            !denseShapeCompatibleWithDataLen(shape, buf.data.len))
        {
            // Ignore invalid dense logical shapes and fall back to the declared
            // graph shape or the actual buffer length.
        } else if (safeShapeNumel(shape)) |numel| return numel;
    }
    if (safeShapeNumel(declared)) |numel| return numel;
    if (buf.source_tensor) |source| return source.elementCount();
    return buf.data.len;
}

fn denseShapeCompatibleWithDataLen(shape: []const i64, data_len: usize) bool {
    var positive_product: usize = 1;
    var unknown_dims: usize = 0;

    for (shape) |dim| {
        if (dim > 0) {
            positive_product = std.math.mul(usize, positive_product, @intCast(dim)) catch return false;
            continue;
        }
        unknown_dims += 1;
    }

    if (unknown_dims == 0) return positive_product == data_len;
    return positive_product > 0 and data_len % positive_product == 0;
}

fn shapeMatchesElementCount(shape: []const i64, element_count: usize) bool {
    if (resolveShapeFromDataLen(shape, element_count)) |_| return true;
    if (safeShapeNumel(shape)) |numel| return numel == element_count;
    // Symbolic shapes are still useful to preserve when the concrete element
    // count is carried by the buffer length.
    for (shape) |dim| {
        if (dim <= 0) return true;
    }
    return false;
}

fn propagateLogicalShapeLike(self: *NativeCompute, result: CT, source: CT) !CT {
    if (tensorStoredShape(source)) |shape| {
        if (shapeMatchesElementCount(shape, getData(result).len)) {
            if (resolveShapeFromDataLen(shape, getData(result).len)) |resolved| {
                return self.withLogicalShape(result, resolved[0..shape.len]);
            }
            return self.withLogicalShape(result, shape);
        }
    }
    return result;
}

fn propagateLogicalShapeFromBinaryOperands(self: *NativeCompute, result: CT, a: CT, b: CT) !CT {
    const result_len = toBuf(result).data.len;
    const a_len = toBuf(a).data.len;
    const b_len = toBuf(b).data.len;

    var a_symbolic_buf: [8]i64 = undefined;
    var b_symbolic_buf: [8]i64 = undefined;
    const a_symbolic = symbolicShapeForBroadcast(a, &a_symbolic_buf);
    const b_symbolic = symbolicShapeForBroadcast(b, &b_symbolic_buf);

    var loose_out_shape_buf: [8]i64 = undefined;
    if (computeBroadcastShape3Loose(a_symbolic, b_symbolic, &.{}, &loose_out_shape_buf)) |loose_out_rank| {
        const loose_out_shape = loose_out_shape_buf[0..loose_out_rank];
        if (preferredBinaryStoredShape(a, b, loose_out_shape, result_len)) |stored_shape| {
            return self.withLogicalShape(result, stored_shape);
        }

        var a_shape_buf: [8]i64 = undefined;
        var b_shape_buf: [8]i64 = undefined;
        const a_shape = concretizeBroadcastOperandShape(a_symbolic, a_len, loose_out_shape, &a_shape_buf);
        const b_shape = concretizeBroadcastOperandShape(b_symbolic, b_len, loose_out_shape, &b_shape_buf);

        var out_shape_buf: [8]i64 = undefined;
        if (computeBroadcastShape3(a_shape, b_shape, &.{}, &out_shape_buf)) |out_rank| {
            const out_shape = out_shape_buf[0..out_rank];
            if (resolveShapeFromDataLen(out_shape, result_len)) |resolved| {
                return self.withLogicalShape(result, resolved[0..out_rank]);
            }
            if (safeShapeNumel(out_shape)) |numel| {
                if (numel == result_len) {
                    return self.withLogicalShape(result, out_shape);
                }
            }
        }
    }

    if (a_len >= b_len) {
        if (tensorStoredShape(a)) |shape| {
            if (shapeMatchesElementCount(shape, result_len)) {
                if (resolveShapeFromDataLen(shape, result_len)) |resolved| {
                    return self.withLogicalShape(result, resolved[0..shape.len]);
                }
                return self.withLogicalShape(result, shape);
            }
        }
    }
    if (b_len >= a_len) {
        if (tensorStoredShape(b)) |shape| {
            if (shapeMatchesElementCount(shape, result_len)) {
                if (resolveShapeFromDataLen(shape, result_len)) |resolved| {
                    return self.withLogicalShape(result, resolved[0..shape.len]);
                }
                return self.withLogicalShape(result, shape);
            }
        }
    }
    return result;
}

fn positiveShapeDim(shape: []const i64, dim: usize) anyerror!usize {
    if (dim >= shape.len) return error.UnsupportedShape;
    if (shape[dim] <= 0) return error.UnsupportedShape;
    return @intCast(shape[dim]);
}

fn resolveSymbolicDimFromElementCount(total_len: usize, known_factor: usize) anyerror!usize {
    if (known_factor == 0 or total_len % known_factor != 0) return error.UnsupportedShape;
    return total_len / known_factor;
}

fn copyShape(shape: []const i64) [8]i64 {
    var out: [8]i64 = undefined;
    for (shape, 0..) |d, i| out[i] = d;
    return out;
}

fn indexOfAxis(axes: []const u8, axis: u8) ?usize {
    for (axes, 0..) |candidate, i| {
        if (candidate == axis) return i;
    }
    return null;
}

fn resolveDotOperandShapeFromPeer(
    data_len: usize,
    declared_shape: []const i64,
    stored_shape: ?[]const i64,
    peer_shape: []const i64,
    contracting_dim: u8,
    batch_dims: []const u8,
    peer_contracting_dim: u8,
    peer_batch_dims: []const u8,
) ?[8]i64 {
    if (declared_shape.len == 0 or declared_shape.len > 8) return null;

    var resolved: [8]i64 = undefined;
    var known_product: usize = 1;
    var unresolved_axes: [8]usize = undefined;
    var unresolved_count: usize = 0;

    for (declared_shape, 0..) |declared_dim, i| {
        const axis: u8 = @intCast(i);
        var dim = declared_dim;

        if (dim <= 0 and axis == contracting_dim and peer_contracting_dim < peer_shape.len and peer_shape[peer_contracting_dim] > 0) {
            dim = peer_shape[peer_contracting_dim];
        }

        if (dim <= 0) {
            if (indexOfAxis(batch_dims, axis)) |batch_index| {
                if (batch_index < peer_batch_dims.len) {
                    const peer_axis = peer_batch_dims[batch_index];
                    if (peer_axis < peer_shape.len and peer_shape[peer_axis] > 0) {
                        dim = peer_shape[peer_axis];
                    }
                }
            }
        }

        if (dim <= 0) {
            resolved[i] = -1;
            unresolved_axes[unresolved_count] = i;
            unresolved_count += 1;
            continue;
        }

        resolved[i] = dim;
        known_product = std.math.mul(usize, known_product, @intCast(dim)) catch return null;
    }

    if (unresolved_count > 1) {
        if (stored_shape) |shape| {
            var idx: usize = 0;
            while (idx < unresolved_count) {
                if (unresolved_count <= 1) break;
                const axis = unresolved_axes[idx];
                if (axis >= shape.len) {
                    idx += 1;
                    continue;
                }
                const hinted_dim = shape[axis];
                if (hinted_dim <= 1) {
                    idx += 1;
                    continue;
                }
                const candidate_product = std.math.mul(usize, known_product, @intCast(hinted_dim)) catch {
                    idx += 1;
                    continue;
                };
                if (candidate_product == 0 or data_len % candidate_product != 0) {
                    idx += 1;
                    continue;
                }
                resolved[axis] = hinted_dim;
                known_product = candidate_product;
                unresolved_count -= 1;
                unresolved_axes[idx] = unresolved_axes[unresolved_count];
            }
        }
    }

    if (unresolved_count == 1) {
        const idx = unresolved_axes[0];
        if (known_product == 0 or data_len % known_product != 0) return null;
        resolved[idx] = @intCast(data_len / known_product);
    }
    if (unresolved_count > 1) return null;

    if (safeShapeNumel(resolved[0..declared_shape.len])) |numel| {
        if (numel == data_len) return resolved;
    }
    return null;
}

const CollapsedTransposePlan = struct {
    shape: [8]i64,
    perm: [8]u8,
    rank: usize,
};

fn collapseLeadingDynamicDimsForTranspose(
    shape: []const i64,
    perm: []const u8,
    element_count: usize,
) ?CollapsedTransposePlan {
    var prefix_len: usize = 0;
    while (prefix_len < shape.len and shape[prefix_len] <= 0) : (prefix_len += 1) {}
    if (prefix_len == 0 or prefix_len >= shape.len) return null;
    for (shape[prefix_len..]) |dim| {
        if (dim <= 0) return null;
    }
    for (0..prefix_len) |i| {
        if (perm[i] != i) return null;
    }

    const suffix_numel = safeShapeNumel(shape[prefix_len..]) orelse return null;
    if (suffix_numel == 0 or element_count % suffix_numel != 0) return null;

    var plan: CollapsedTransposePlan = undefined;
    plan.rank = shape.len - prefix_len + 1;
    plan.shape[0] = @intCast(element_count / suffix_numel);
    for (shape[prefix_len..], 0..) |dim, i| {
        plan.shape[i + 1] = dim;
    }
    plan.perm[0] = 0;
    for (perm[prefix_len..], prefix_len..) |axis, i| {
        if (axis < prefix_len) return null;
        plan.perm[i - prefix_len + 1] = @intCast(axis - prefix_len + 1);
    }
    return plan;
}

fn inferReshapeShapeWithNumel(input_shape: []const i64, target_shape: []const i64, input_numel: usize) ?[8]i64 {
    if (target_shape.len > 8) return null;
    var resolved: [8]i64 = undefined;
    var negative_count: usize = 0;
    for (target_shape, 0..) |dim, i| {
        resolved[i] = dim;
        if (dim < 0) negative_count += 1;
    }

    if (negative_count > 1 and target_shape.len == input_shape.len) {
        for (target_shape, 0..) |dim, i| {
            if (dim >= 0) continue;
            const input_dim = input_shape[i];
            if (input_dim > 0) resolved[i] = input_dim;
        }
    }

    if (negative_count == 0 and input_shape.len > 0 and target_shape.len > 0 and input_shape[0] > 1 and target_shape[0] > 1 and target_shape.len != input_shape.len) {
        const target_numel = safeShapeNumel(target_shape) orelse return null;
        if (target_numel > 0 and input_numel > target_numel and input_numel % target_numel == 0) {
            const batch_factor = input_numel / target_numel;
            const scaled = @as(usize, @intCast(target_shape[0])) * batch_factor;
            resolved[0] = std.math.cast(i64, scaled) orelse return null;
            if (safeShapeNumel(resolved[0..target_shape.len])) |resolved_numel| {
                if (resolved_numel == input_numel) return resolved;
            }
        }
    }

    if (negative_count == 0 and input_shape.len > 0 and target_shape.len > 0 and input_shape[0] > 1 and target_shape[0] == 1) {
        const target_numel = safeShapeNumel(target_shape) orelse return null;
        if (target_numel > 0 and input_numel > target_numel and input_numel % target_numel == 0) {
            const batch_factor = input_numel / target_numel;
            if (batch_factor == @as(usize, @intCast(input_shape[0]))) {
                resolved[0] = input_shape[0];
                if (safeShapeNumel(resolved[0..target_shape.len])) |resolved_numel| {
                    if (resolved_numel == input_numel) return resolved;
                }
            }
        }
    }

    // Collapse inner singleton input dims (e.g. `{77, 1, 512}` → `{77, 512}`) so
    // that attention-head splits can still resolve against the effective shape.
    if (negative_count > 1 and input_shape.len >= 3 and target_shape.len == input_shape.len + 1 and resolved[0] == 1) {
        var collapsed: [8]i64 = undefined;
        var collapsed_len: usize = 0;
        for (input_shape, 0..) |dim, i| {
            if (i > 0 and i < input_shape.len - 1 and dim == 1) continue;
            collapsed[collapsed_len] = dim;
            collapsed_len += 1;
        }
        if (collapsed_len < input_shape.len and target_shape.len == collapsed_len + 2) {
            const input_last = collapsed[collapsed_len - 1];
            const target_last = target_shape[target_shape.len - 1];
            if (input_last > 0 and target_last > 0 and @rem(input_last, target_last) == 0) {
                for (0..collapsed_len - 1) |i| {
                    const target_index = i + 1;
                    if (resolved[target_index] < 0 and collapsed[i] > 0) {
                        resolved[target_index] = collapsed[i];
                    }
                }
                if (resolved[target_shape.len - 2] < 0) {
                    resolved[target_shape.len - 2] = @divTrunc(input_last, target_last);
                }
            }
        }
    }

    if (negative_count > 1 and input_shape.len == 3 and target_shape.len == 4 and resolved[1] > 0 and resolved[3] > 0) {
        const hidden = input_shape[2];
        if (hidden > 0 and @rem(hidden, resolved[3]) == 0) {
            if (resolved[0] < 0 and input_shape[0] > 0) resolved[0] = input_shape[0];
            if (resolved[2] < 0) resolved[2] = @divTrunc(hidden, resolved[3]);
        }
    }

    // Unflatten multi-head attention outputs:
    //   [batch * heads, seq, head_dim] -> [batch, heads, seq, head_dim]
    if (negative_count > 1 and input_shape.len == 3 and target_shape.len == 4 and resolved[1] > 0) {
        const head_count: usize = @intCast(resolved[1]);
        var unflatten_known_product: usize = head_count;
        var can_unflatten = head_count > 0;
        if (input_shape[1] > 0) {
            unflatten_known_product = std.math.mul(usize, unflatten_known_product, @intCast(input_shape[1])) catch 0;
            can_unflatten = can_unflatten and unflatten_known_product > 0;
        }
        if (input_shape[2] > 0) {
            unflatten_known_product = std.math.mul(usize, unflatten_known_product, @intCast(input_shape[2])) catch 0;
            can_unflatten = can_unflatten and unflatten_known_product > 0;
        } else {
            can_unflatten = false;
        }
        if (can_unflatten and input_shape[1] > 0 and input_numel % unflatten_known_product == 0) {
            if (resolved[2] < 0) {
                resolved[2] = input_shape[1];
            }
            if (resolved[3] < 0) {
                resolved[3] = input_shape[2];
            }
            if (input_shape[0] > 0 and resolved[0] < 0) {
                const batch_heads: usize = @intCast(input_shape[0]);
                if (batch_heads % head_count == 0) {
                    resolved[0] = @intCast(batch_heads / head_count);
                }
            }
            var unresolved: usize = 0;
            var unresolved_index: usize = 0;
            var known_product: usize = head_count;
            var valid = true;
            for ([_]usize{ 0, 2, 3 }) |axis| {
                const dim = resolved[axis];
                if (dim > 0) {
                    known_product = std.math.mul(usize, known_product, @intCast(dim)) catch {
                        valid = false;
                        break;
                    };
                } else {
                    unresolved += 1;
                    unresolved_index = axis;
                }
            }
            if (valid and unresolved == 1 and known_product > 0 and input_numel % known_product == 0) {
                resolved[unresolved_index] = @intCast(input_numel / known_product);
            }
        }
    }

    if (negative_count > 1 and target_shape.len == input_shape.len + 1 and target_shape.len >= 2) {
        const input_last = input_shape[input_shape.len - 1];
        const target_last = target_shape[target_shape.len - 1];
        if (input_last > 0) {
            for (0..input_shape.len - 1) |i| {
                if (resolved[i] < 0 and input_shape[i] > 0) resolved[i] = input_shape[i];
            }
            if (resolved[target_shape.len - 1] < 0 and resolved[target_shape.len - 2] > 0 and @rem(input_last, resolved[target_shape.len - 2]) == 0) {
                resolved[target_shape.len - 1] = @divTrunc(input_last, resolved[target_shape.len - 2]);
            }
        }
        if (input_last > 0 and target_last > 0 and @rem(input_last, target_last) == 0) {
            if (resolved[0] > 0 and input_numel % @as(usize, @intCast(input_last)) == 0) {
                const prefix_numel = input_numel / @as(usize, @intCast(input_last));
                const leading_dim: usize = @intCast(resolved[0]);
                if (leading_dim > 0 and prefix_numel % leading_dim == 0 and resolved[1] < 0) {
                    resolved[1] = @intCast(prefix_numel / leading_dim);
                }
            }
            for (0..input_shape.len - 1) |i| {
                if (resolved[i] < 0 and input_shape[i] > 0) resolved[i] = input_shape[i];
            }
            if (resolved[input_shape.len - 1] < 0) {
                resolved[input_shape.len - 1] = @divTrunc(input_last, target_last);
            }
        }
    }

    if (negative_count > 1 and input_shape.len == 3 and target_shape.len == 4 and resolved[1] > 0) {
        const input_last = input_shape[2];
        if (input_last > 0 and @rem(input_last, resolved[1]) == 0) {
            if (resolved[3] < 0) {
                resolved[3] = @divTrunc(input_last, resolved[1]);
            }
            if (resolved[2] < 0) {
                if (input_shape[1] > 0) {
                    resolved[2] = input_shape[1];
                } else {
                    const prefix_numel = input_numel / @as(usize, @intCast(input_last));
                    if (resolved[0] < 0) {
                        resolved[0] = 1;
                        resolved[2] = @intCast(prefix_numel);
                    }
                }
            }
            if (resolved[0] < 0 and input_shape[0] > 0) {
                resolved[0] = input_shape[0];
            }
        }
    }

    if (negative_count > 1 and target_shape.len == 4 and resolved[0] < 0 and resolved[1] < 0 and resolved[2] > 0 and resolved[3] > 0) {
        const head_count: usize = @intCast(resolved[2]);
        const head_dim: usize = @intCast(resolved[3]);
        const hidden = std.math.mul(usize, head_count, head_dim) catch 0;
        if (hidden > 0 and input_numel % hidden == 0) {
            const prefix = input_numel / hidden;
            if (input_shape.len > 0 and input_shape[0] > 0) {
                const batch: usize = @intCast(input_shape[0]);
                if (batch > 0 and prefix % batch == 0) {
                    resolved[0] = input_shape[0];
                    resolved[1] = @intCast(prefix / batch);
                }
            } else {
                resolved[0] = 1;
                resolved[1] = @intCast(prefix);
            }
        }
    }

    if (negative_count > 1 and target_shape.len == input_shape.len + 2 and target_shape.len >= 3 and resolved[0] == 1) {
        const input_last = input_shape[input_shape.len - 1];
        const target_last = target_shape[target_shape.len - 1];
        if (input_last > 0 and target_last > 0 and @rem(input_last, target_last) == 0) {
            for (0..input_shape.len - 1) |i| {
                const target_index = i + 1;
                if (resolved[target_index] < 0 and input_shape[i] > 0) {
                    resolved[target_index] = input_shape[i];
                }
            }
            if (resolved[target_shape.len - 2] < 0) {
                resolved[target_shape.len - 2] = @divTrunc(input_last, target_last);
            }
        }
    }

    if (negative_count > 1 and input_shape.len == 2 and target_shape.len == 4 and target_shape[1] == 1 and target_shape[2] == 1) {
        const batch = input_shape[0];
        const seq_len = input_shape[1];
        if (batch > 0 and seq_len > 0 and input_numel == @as(usize, @intCast(batch)) * @as(usize, @intCast(seq_len))) {
            if (resolved[0] < 0) resolved[0] = batch;
            if (resolved[3] < 0) resolved[3] = seq_len;
        }
    }

    if (negative_count > 1 and target_shape.len + 1 == input_shape.len and target_shape.len >= 3) {
        var valid = true;
        for (0..target_shape.len - 1) |i| {
            const input_dim = input_shape[i];
            if (resolved[i] < 0 and input_dim > 0) {
                resolved[i] = input_dim;
            } else if (resolved[i] > 0 and input_dim > 0 and resolved[i] != input_dim) {
                valid = false;
                break;
            }
        }
        if (valid) {
            var collapsed: usize = 1;
            for (input_shape[target_shape.len - 1 .. input_shape.len]) |dim| {
                if (dim <= 0) {
                    valid = false;
                    break;
                }
                collapsed = std.math.mul(usize, collapsed, @intCast(dim)) catch {
                    valid = false;
                    break;
                };
            }
            if (valid) {
                const last_index = target_shape.len - 1;
                if (resolved[last_index] < 0) {
                    resolved[last_index] = @intCast(collapsed);
                } else if (resolved[last_index] != @as(i64, @intCast(collapsed))) {
                    valid = false;
                }
            }
        }
    }

    if (negative_count > 1 and target_shape.len + 1 == input_shape.len and target_shape.len >= 2 and resolved[0] > 0 and input_shape[0] > 0 and resolved[0] == input_shape[0]) {
        var valid = true;
        for (1..target_shape.len - 1) |i| {
            const input_dim = input_shape[i];
            if (resolved[i] < 0 and input_dim > 0) {
                resolved[i] = input_dim;
            } else if (resolved[i] > 0 and input_dim > 0 and resolved[i] != input_dim) {
                valid = false;
                break;
            }
        }
        if (valid) {
            var collapsed: usize = 1;
            for (input_shape[target_shape.len - 1 .. input_shape.len]) |dim| {
                if (dim <= 0) {
                    valid = false;
                    break;
                }
                collapsed = std.math.mul(usize, collapsed, @intCast(dim)) catch {
                    valid = false;
                    break;
                };
            }
            if (valid) {
                const last_index = target_shape.len - 1;
                if (resolved[last_index] < 0) {
                    resolved[last_index] = @intCast(collapsed);
                } else if (resolved[last_index] != @as(i64, @intCast(collapsed))) {
                    valid = false;
                }
            }
        }
    }

    if (negative_count > 1 and target_shape.len + 1 == input_shape.len and target_shape.len == 2) {
        var trailing_aligned = true;
        for (1..target_shape.len) |i| {
            const input_dim = input_shape[i + 1];
            if (resolved[i] < 0 and input_dim > 0) {
                resolved[i] = input_dim;
            } else if (resolved[i] > 0 and input_dim > 0 and resolved[i] != input_dim) {
                trailing_aligned = false;
                break;
            }
        }
        if (trailing_aligned and resolved[0] < 0) {
            var collapsed: usize = 1;
            var valid = true;
            for (input_shape[0..2]) |dim| {
                if (dim <= 0) {
                    valid = false;
                    break;
                }
                collapsed = std.math.mul(usize, collapsed, @intCast(dim)) catch {
                    valid = false;
                    break;
                };
            }
            if (valid) resolved[0] = @intCast(collapsed);
        }
    }

    if (negative_count > 1) {
        var known_product: usize = 1;
        var valid = true;
        for (resolved[0..target_shape.len]) |dim| {
            if (dim <= 0) continue;
            known_product = std.math.mul(usize, known_product, @intCast(dim)) catch {
                valid = false;
                break;
            };
        }
        if (valid and known_product == input_numel) {
            for (0..target_shape.len) |i| {
                if (resolved[i] < 0) resolved[i] = 1;
            }
            negative_count = 0;
        }
    }

    var infer_index: ?usize = null;
    var known_product: usize = 1;

    for (resolved[0..target_shape.len], 0..) |dim, i| {
        if (dim == -1) {
            if (infer_index != null) return null;
            infer_index = i;
            continue;
        }
        if (dim <= 0) return null;
        known_product = std.math.mul(usize, known_product, @intCast(dim)) catch return null;
    }

    if (infer_index) |idx| {
        if (known_product == 0 or input_numel % known_product != 0) return null;
        resolved[idx] = @intCast(input_numel / known_product);
    } else if (known_product != input_numel) {
        return null;
    }

    for (resolved[0..target_shape.len]) |dim| {
        if (dim <= 0) return null;
    }
    return resolved;
}

fn inferReshapeShape(input_shape: []const i64, target_shape: []const i64) ?[8]i64 {
    const input_numel = safeShapeNumel(input_shape) orelse return null;
    return inferReshapeShapeWithNumel(input_shape, target_shape, input_numel);
}

fn exactIntegerCubeRoot(value: usize) ?usize {
    if (value == 0) return 0;
    var root: usize = 1;
    while (true) : (root += 1) {
        const square = std.math.mul(usize, root, root) catch return null;
        const cube = std.math.mul(usize, square, root) catch return null;
        if (cube == value) return root;
        if (cube > value) return null;
    }
}

fn exactIntegerSquareRoot(value: usize) ?usize {
    if (value == 0) return 0;
    var root: usize = 1;
    while (true) : (root += 1) {
        const square = std.math.mul(usize, root, root) catch return null;
        if (square == value) return root;
        if (square > value) return null;
    }
}

fn inferTransformerLeadingHeads(total: usize) ?struct { leading: usize, sequence: usize } {
    const common_heads = [_]usize{ 128, 96, 80, 64, 48, 40, 32, 24, 20, 16, 12, 10, 8, 6, 4, 3, 2, 1 };
    for (common_heads) |heads| {
        if (total % heads != 0) continue;
        const sequence = total / heads;
        if (sequence == 0) continue;
        return .{ .leading = heads, .sequence = sequence };
    }
    return null;
}

fn resolveShapeFromDataLen(shape: []const i64, data_len: usize) ?[8]i64 {
    if (shape.len > 8) return null;

    if (shape.len == 2 and shape[0] < 0 and shape[1] < 0) {
        if (exactIntegerSquareRoot(data_len)) |shared_dim| {
            return .{ @intCast(shared_dim), @intCast(shared_dim), 0, 0, 0, 0, 0, 0 };
        }
    }

    if (shape.len == 3 and shape[0] < 0 and shape[1] < 0 and shape[2] > 0) {
        const trailing_dim: usize = @intCast(shape[2]);
        if (trailing_dim > 0 and data_len % trailing_dim == 0) {
            const matrix_elems = data_len / trailing_dim;
            if (exactIntegerSquareRoot(matrix_elems)) |shared_dim| {
                return .{ @intCast(shared_dim), @intCast(shared_dim), shape[2], 0, 0, 0, 0, 0 };
            }
            if (inferTransformerLeadingHeads(matrix_elems)) |dims| {
                return .{ @intCast(dims.leading), @intCast(dims.sequence), shape[2], 0, 0, 0, 0, 0 };
            }
        }
    }

    if (shape.len == 4 and shape[0] > 0 and shape[1] < 0 and shape[2] < 0 and shape[3] > 0) {
        const batch: usize = @intCast(shape[0]);
        const trailing_dim: usize = @intCast(shape[3]);
        const known = std.math.mul(usize, batch, trailing_dim) catch return null;
        if (known > 0 and data_len % known == 0) {
            if (inferTransformerLeadingHeads(data_len / known)) |dims| {
                return .{ shape[0], @intCast(dims.leading), @intCast(dims.sequence), shape[3], 0, 0, 0, 0 };
            }
        }
    }

    if (shape.len == 4 and shape[0] < 0 and shape[1] > 1 and shape[2] < 0 and shape[3] < 0) {
        const head_count: usize = @intCast(shape[1]);
        if (head_count > 0 and data_len % head_count == 0) {
            if (exactIntegerCubeRoot(data_len / head_count)) |shared_dim| {
                return .{ @intCast(shared_dim), shape[1], @intCast(shared_dim), @intCast(shared_dim), 0, 0, 0, 0 };
            }
        }
    }

    var resolved: [8]i64 = undefined;
    var infer_index: ?usize = null;
    var known_product: usize = 1;

    for (shape, 0..) |dim, i| {
        resolved[i] = dim;
        if (dim > 0) {
            known_product = std.math.mul(usize, known_product, @intCast(dim)) catch return null;
            continue;
        }
        if (infer_index != null) return null;
        infer_index = i;
    }

    if (infer_index) |idx| {
        if (known_product == 0 or data_len % known_product != 0) return null;
        resolved[idx] = @intCast(data_len / known_product);
        return resolved;
    }

    if (known_product != data_len) return null;
    return resolved;
}

fn resolveShapeFromTensorMetadata(tensor: CT, shape: []const i64, data_len: usize) ?[8]i64 {
    if (resolveShapeFromDataLen(shape, data_len)) |resolved| return resolved;
    if (shape.len > 8) return null;

    const buf = toBuf(tensor);
    const view_strides = buf.view_strides orelse return null;
    if (view_strides.len != shape.len) return null;

    var resolved: [8]i64 = undefined;
    var infer_index: ?usize = null;
    var known_product: usize = 1;

    for (shape, view_strides, 0..) |dim, stride, i| {
        if (dim > 0) {
            resolved[i] = dim;
            known_product = std.math.mul(usize, known_product, @intCast(dim)) catch return null;
            continue;
        }

        if (stride == 0) {
            resolved[i] = 1;
            continue;
        }

        if (infer_index != null) return null;
        infer_index = i;
        resolved[i] = dim;
    }

    if (infer_index) |idx| {
        if (known_product == 0 or data_len % known_product != 0) return null;
        resolved[idx] = @intCast(data_len / known_product);
        return resolved;
    }

    if (known_product != data_len) return null;
    return resolved;
}

fn resolveSoftmaxLastDim(input: CT, dim: u32) ?usize {
    if (dim != 0) return @intCast(dim);
    const data_len = toBuf(input).data.len;
    if (tensorStoredShape(input)) |shape| {
        if (shape.len > 0) {
            if (resolveShapeFromDataLen(shape, data_len)) |resolved| {
                const last_dim = resolved[shape.len - 1];
                if (last_dim > 0) return @intCast(last_dim);
            }
            const raw_last_dim = shape[shape.len - 1];
            if (raw_last_dim > 0) return @intCast(raw_last_dim);
        }
    }
    if (data_len > 0) return data_len;
    return null;
}

fn symbolicShapeForBroadcast(tensor: CT, scratch: *[8]i64) []const i64 {
    const data_len = toBuf(tensor).data.len;
    if (tensorStoredShape(tensor)) |shape| {
        if (resolveShapeFromDataLen(shape, data_len)) |resolved| {
            for (0..shape.len) |i| scratch[i] = resolved[i];
            return scratch[0..shape.len];
        }
        for (shape, 0..) |dim, i| scratch[i] = dim;
        return scratch[0..shape.len];
    }
    scratch[0] = if (data_len == 0) 0 else @intCast(data_len);
    return scratch[0..1];
}

fn concretizeBroadcastOperandShape(
    operand_shape: []const i64,
    data_len: usize,
    out_shape: []const i64,
    scratch: *[8]i64,
) []const i64 {
    if (operand_shape.len == 0) return scratch[0..0];
    if (resolveShapeFromDataLen(operand_shape, data_len)) |resolved| {
        for (0..operand_shape.len) |i| scratch[i] = resolved[i];
        return scratch[0..operand_shape.len];
    }

    if (out_shape.len >= operand_shape.len) {
        var infer_index: ?usize = null;
        var known_product: usize = 1;
        const rank_offset = out_shape.len - operand_shape.len;
        var valid = true;

        for (operand_shape, 0..) |dim, i| {
            if (dim > 0) {
                scratch[i] = dim;
            } else {
                const candidate = out_shape[rank_offset + i];
                if (candidate > 0) {
                    scratch[i] = candidate;
                } else {
                    scratch[i] = 1;
                    if (infer_index == null) infer_index = i;
                }
            }
            known_product = std.math.mul(usize, known_product, @intCast(scratch[i])) catch {
                valid = false;
                break;
            };
        }

        if (valid) {
            if (infer_index) |idx| {
                if (known_product > 0 and data_len % known_product == 0) {
                    const inferred = data_len / known_product;
                    scratch[idx] = @intCast(if (inferred == 0) 1 else inferred);
                } else {
                    valid = false;
                }
            }
            if (valid) {
                if (safeShapeNumel(scratch[0..operand_shape.len])) |numel| {
                    if (numel == data_len) return scratch[0..operand_shape.len];
                }
            }
        }
    }

    for (operand_shape, 0..) |dim, i| {
        scratch[i] = if (dim > 0) dim else 1;
    }
    if (safeShapeNumel(scratch[0..operand_shape.len])) |numel| {
        if (numel == data_len) return scratch[0..operand_shape.len];
    }

    if (operand_shape.len == 1 and data_len > 0) {
        scratch[0] = @intCast(data_len);
    }
    return scratch[0..operand_shape.len];
}

fn computeBroadcastShape3Loose(a_shape: []const i64, b_shape: []const i64, c_shape: []const i64, out_shape: *[8]i64) ?usize {
    const out_rank = @max(a_shape.len, @max(b_shape.len, c_shape.len));
    if (out_rank > 8) return null;

    var idx: usize = 0;
    while (idx < out_rank) : (idx += 1) {
        const rev_idx = out_rank - 1 - idx;
        const dims = [_]i64{
            if (idx < a_shape.len) a_shape[a_shape.len - 1 - idx] else 1,
            if (idx < b_shape.len) b_shape[b_shape.len - 1 - idx] else 1,
            if (idx < c_shape.len) c_shape[c_shape.len - 1 - idx] else 1,
        };

        var resolved_dim: i64 = 1;
        var symbolic = false;
        for (dims) |dim| {
            if (dim == 1) continue;
            if (dim > 1) {
                if (resolved_dim == 1 or resolved_dim <= 0) {
                    resolved_dim = dim;
                } else if (resolved_dim != dim) {
                    return null;
                }
            } else {
                symbolic = true;
            }
        }
        out_shape[rev_idx] = if (resolved_dim == 1 and symbolic) -1 else resolved_dim;
    }

    return out_rank;
}

fn shapeHasDynamicDim(shape: []const i64) bool {
    for (shape) |dim| {
        if (dim <= 0) return true;
    }
    return false;
}

fn sameShape(a: []const i64, b: []const i64) bool {
    if (a.len != b.len) return false;
    for (a, b) |av, bv| {
        if (av != bv) return false;
    }
    return true;
}

fn dynamicShapeCompatibleWithConcreteCandidate(symbolic_shape: []const i64, candidate_shape: []const i64) bool {
    if (symbolic_shape.len != candidate_shape.len) return false;
    var has_dynamic = false;
    for (symbolic_shape, candidate_shape) |symbolic_dim, candidate_dim| {
        if (candidate_dim <= 0) return false;
        if (symbolic_dim <= 0) {
            has_dynamic = true;
            continue;
        }
        if (symbolic_dim != candidate_dim) return false;
    }
    return has_dynamic;
}

fn isStaleSingletonAttentionMaskShape(shape: []const i64) bool {
    if (shape.len != 4) return false;
    if (shape[1] != 1 or shape[2] != 1) return false;
    return shape[0] <= 0 or shape[3] <= 0;
}

fn flattenedImportedOperandCompatibleWithShape(
    operand_shape: []const i64,
    data_len: usize,
    candidate_shape: []const i64,
    candidate_numel: usize,
) bool {
    if (data_len == 1) return true;
    if (data_len != candidate_numel) return false;
    if (sameShape(operand_shape, candidate_shape)) return true;
    if (operand_shape.len == 1) {
        const operand_numel = safeShapeNumel(operand_shape) orelse return false;
        return operand_numel == candidate_numel;
    }
    if (candidate_shape.len == 1 and isStaleSingletonAttentionMaskShape(operand_shape)) return true;
    return dynamicShapeCompatibleWithConcreteCandidate(operand_shape, candidate_shape);
}

fn importedFlattenedBroadcastFallbackShape(
    a_shape: []const i64,
    b_shape: []const i64,
    c_shape: []const i64,
    a_len: usize,
    b_len: usize,
    c_len: usize,
    out_shape: *[8]i64,
) ?usize {
    const max_len = @max(a_len, @max(b_len, c_len));
    if (max_len == 0) return null;

    var best_shape: []const i64 = &.{};
    const Candidate = struct {
        shape: []const i64,
        len: usize,
    };
    const candidates = [_]Candidate{
        .{ .shape = a_shape, .len = a_len },
        .{ .shape = b_shape, .len = b_len },
        .{ .shape = c_shape, .len = c_len },
    };
    for (candidates) |candidate| {
        if (candidate.len != max_len or candidate.shape.len == 0 or candidate.shape.len > 8) continue;
        const candidate_numel = safeShapeNumel(candidate.shape) orelse continue;
        if (candidate_numel != max_len) continue;
        if (!flattenedImportedOperandCompatibleWithShape(a_shape, a_len, candidate.shape, candidate_numel)) continue;
        if (!flattenedImportedOperandCompatibleWithShape(b_shape, b_len, candidate.shape, candidate_numel)) continue;
        if (!flattenedImportedOperandCompatibleWithShape(c_shape, c_len, candidate.shape, candidate_numel)) continue;
        if (candidate.shape.len > best_shape.len) {
            best_shape = candidate.shape;
        }
    }

    if (best_shape.len == 0) {
        const flat_shape = [_]i64{@intCast(max_len)};
        if (!flattenedImportedOperandCompatibleWithShape(a_shape, a_len, &flat_shape, max_len)) return null;
        if (!flattenedImportedOperandCompatibleWithShape(b_shape, b_len, &flat_shape, max_len)) return null;
        if (!flattenedImportedOperandCompatibleWithShape(c_shape, c_len, &flat_shape, max_len)) return null;
        out_shape[0] = flat_shape[0];
        return flat_shape.len;
    }

    for (best_shape, 0..) |dim, i| out_shape[i] = dim;
    return best_shape.len;
}

fn coerceImportedFlattenedBroadcastOperandShape(
    symbolic_shape: []const i64,
    operand_shape: []const i64,
    data_len: usize,
    out_shape: []const i64,
    scratch: *[8]i64,
) []const i64 {
    if (data_len <= 1 or operand_shape.len == 0 or out_shape.len == 0 or out_shape.len > 8) return operand_shape;
    const out_numel = safeShapeNumel(out_shape) orelse return operand_shape;
    if (out_numel != data_len) return operand_shape;
    if (sameShape(operand_shape, out_shape)) return operand_shape;
    const can_coerce = if (operand_shape.len == 1) blk: {
        break :blk (safeShapeNumel(operand_shape) orelse 0) == out_numel;
    } else if (out_shape.len == 1 and isStaleSingletonAttentionMaskShape(symbolic_shape)) blk: {
        break :blk true;
    } else blk: {
        break :blk dynamicShapeCompatibleWithConcreteCandidate(symbolic_shape, out_shape);
    };
    if (!can_coerce) return operand_shape;

    for (out_shape, 0..) |dim, i| scratch[i] = dim;
    return scratch[0..out_shape.len];
}

fn computeBroadcastShape3(a_shape: []const i64, b_shape: []const i64, c_shape: []const i64, out_shape: *[8]i64) ?usize {
    const out_rank = @max(a_shape.len, @max(b_shape.len, c_shape.len));
    if (out_rank > 8) return null;

    var idx: usize = 0;
    while (idx < out_rank) : (idx += 1) {
        const rev_idx = out_rank - 1 - idx;
        const dims = [_]i64{
            if (idx < a_shape.len) a_shape[a_shape.len - 1 - idx] else 1,
            if (idx < b_shape.len) b_shape[b_shape.len - 1 - idx] else 1,
            if (idx < c_shape.len) c_shape[c_shape.len - 1 - idx] else 1,
        };

        var resolved_dim: i64 = 1;
        for (dims) |dim| {
            if (dim == 1) continue;
            if (resolved_dim == 1) {
                resolved_dim = dim;
            } else if (resolved_dim != dim) {
                return null;
            }
        }
        out_shape[rev_idx] = resolved_dim;
    }

    return out_rank;
}

fn broadcastIndexForOutput(
    out_flat: usize,
    out_shape: []const i64,
    out_strides: []const usize,
    operand_shape: []const i64,
    operand_strides: []const usize,
) usize {
    if (operand_shape.len == 0) return 0;

    var remaining = out_flat;
    var flat_operand: usize = 0;
    const rank_offset = out_shape.len - operand_shape.len;

    for (0..out_shape.len) |out_dim| {
        const coord = if (out_strides[out_dim] == 0) 0 else remaining / out_strides[out_dim];
        if (out_strides[out_dim] != 0) remaining %= out_strides[out_dim];
        if (out_dim < rank_offset) continue;

        const operand_dim = out_dim - rank_offset;
        if (operand_shape[operand_dim] > 1) {
            flat_operand += coord * operand_strides[operand_dim];
        }
    }

    return flat_operand;
}

fn broadcastTensorOffsetForOutputBatch(
    out_flat: usize,
    out_shape: []const i64,
    out_strides: []const usize,
    operand_shape: []const i64,
    operand_axes: []const u8,
    tensor_strides: []const usize,
) usize {
    if (operand_shape.len == 0) return 0;

    var remaining = out_flat;
    var tensor_offset: usize = 0;
    const rank_offset = out_shape.len - operand_shape.len;

    for (0..out_shape.len) |out_dim| {
        const coord = if (out_strides[out_dim] == 0) 0 else remaining / out_strides[out_dim];
        if (out_strides[out_dim] != 0) remaining %= out_strides[out_dim];
        if (out_dim < rank_offset) continue;

        const operand_dim = out_dim - rank_offset;
        if (operand_shape[operand_dim] > 1) {
            const axis = operand_axes[operand_dim];
            tensor_offset += coord * tensor_strides[axis];
        }
    }

    return tensor_offset;
}

const BroadcastStepper = struct {
    out_shape: []const i64,
    operand_shape: []const i64,
    operand_strides: []const usize,
    rank_offset: usize,
    coords: [8]usize = [_]usize{0} ** 8,
    operand_offset: usize = 0,

    fn init(out_shape: []const i64, operand_shape: []const i64, operand_strides: []const usize) BroadcastStepper {
        return .{
            .out_shape = out_shape,
            .operand_shape = operand_shape,
            .operand_strides = operand_strides,
            .rank_offset = out_shape.len - operand_shape.len,
        };
    }

    fn currentOffset(self: *const BroadcastStepper) usize {
        return self.operand_offset;
    }

    fn advance(self: *BroadcastStepper) void {
        if (self.out_shape.len == 0) return;

        var dim = self.out_shape.len;
        while (dim > 0) {
            dim -= 1;
            const out_dim_extent = @as(usize, @intCast(self.out_shape[dim]));
            self.coords[dim] += 1;

            if (dim >= self.rank_offset) {
                const operand_dim = dim - self.rank_offset;
                if (self.operand_shape[operand_dim] > 1) {
                    self.operand_offset += self.operand_strides[operand_dim];
                }
            }

            if (self.coords[dim] < out_dim_extent) return;

            self.coords[dim] = 0;
            if (dim >= self.rank_offset) {
                const operand_dim = dim - self.rank_offset;
                if (self.operand_shape[operand_dim] > 1) {
                    self.operand_offset -= self.operand_strides[operand_dim] * out_dim_extent;
                }
            }
        }
    }
};

const Gather2DLayout = struct {
    rows: usize,
    dim: usize,
};

fn inferGather2DLayoutFromElementCount(total_len: usize, max_row: usize) ?Gather2DLayout {
    if (total_len == 0) return null;
    if (max_row == 0) {
        return .{ .rows = 1, .dim = total_len };
    }

    var candidate: ?Gather2DLayout = null;
    var factor: usize = 1;
    while (factor <= total_len / factor) : (factor += 1) {
        if (total_len % factor != 0) continue;

        const rows_a = total_len / factor;
        const dim_a = factor;
        if (rows_a > max_row) {
            if (candidate) |existing| {
                if (existing.rows != rows_a or existing.dim != dim_a) return null;
            } else {
                candidate = .{ .rows = rows_a, .dim = dim_a };
            }
        }

        const other = total_len / factor;
        if (other != factor and factor > max_row) {
            if (candidate) |existing| {
                if (existing.rows != factor or existing.dim != other) return null;
            } else {
                candidate = .{ .rows = factor, .dim = other };
            }
        }
    }

    return candidate;
}

const ConcatLayout = struct {
    outer: usize,
    axis_size: usize,
    inner: usize,
};

fn resolveConcatShapeFromDataLen(shape: []const i64, axis: usize, data_len: usize) ?[8]i64 {
    if (shape.len > 8 or axis >= shape.len) return null;
    var resolved: [8]i64 = undefined;
    var non_axis_product: usize = 1;
    for (shape, 0..) |dim, i| {
        resolved[i] = dim;
        if (i == axis) continue;
        if (dim <= 0) return null;
        non_axis_product = std.math.mul(usize, non_axis_product, @intCast(dim)) catch return null;
    }
    if (non_axis_product == 0 or data_len % non_axis_product != 0) return null;
    const axis_size = data_len / non_axis_product;
    if (axis_size == 0) return null;
    resolved[axis] = @intCast(axis_size);
    return resolved;
}

fn tensorResolvedStrides(buf: *const Buf, resolved_shape: []const i64, dense_strides_buf: *[8]usize) []const usize {
    if (buf.view_strides) |strides| return strides;
    computeStrides(resolved_shape, dense_strides_buf[0..resolved_shape.len]);
    return dense_strides_buf[0..resolved_shape.len];
}

fn tensorOffsetForResolvedCoords(
    buf: *const Buf,
    resolved_shape: []const i64,
    resolved_strides: []const usize,
    coords: []const usize,
) usize {
    var flat: usize = buf.view_base_offset;
    for (resolved_shape, 0..) |dim, d| {
        const coord = if (dim == 1) 0 else coords[d];
        flat += coord * resolved_strides[d];
    }
    return flat;
}

fn concatWithResolvedBroadcastShapes(
    self: *NativeCompute,
    a: CT,
    b: CT,
    axis: usize,
    resolved_a_shape: []const i64,
    resolved_b_shape: []const i64,
    out_shape: []const i64,
) !CT {
    const rank = out_shape.len;
    const out_numel = safeShapeNumel(out_shape) orelse return error.UnsupportedShape;
    const a_data = getData(a);
    const b_data = getData(b);
    const a_buf = toBuf(a);
    const b_buf = toBuf(b);
    const a_axis = @as(usize, @intCast(resolved_a_shape[axis]));

    var out_strides_buf: [8]usize = undefined;
    computeStrides(out_shape, out_strides_buf[0..rank]);

    var a_dense_strides_buf: [8]usize = undefined;
    var b_dense_strides_buf: [8]usize = undefined;
    const a_strides = tensorResolvedStrides(a_buf, resolved_a_shape, &a_dense_strides_buf);
    const b_strides = tensorResolvedStrides(b_buf, resolved_b_shape, &b_dense_strides_buf);

    const output = try self.allocator.alloc(f32, out_numel);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    var coords: [8]usize = undefined;
    for (0..out_numel) |flat_out| {
        var remaining = flat_out;
        for (0..rank) |d| {
            const stride = out_strides_buf[d];
            coords[d] = if (stride == 0) 0 else remaining / stride;
            if (stride != 0) remaining %= stride;
        }

        if (coords[axis] < a_axis) {
            const flat_a = tensorOffsetForResolvedCoords(a_buf, resolved_a_shape, a_strides, coords[0..rank]);
            if (flat_a >= a_data.len) return error.InvalidTensorShape;
            output[flat_out] = a_data[flat_a];
            continue;
        }

        coords[axis] -= a_axis;
        const flat_b = tensorOffsetForResolvedCoords(b_buf, resolved_b_shape, b_strides, coords[0..rank]);
        if (flat_b >= b_data.len) return error.InvalidTensorShape;
        output[flat_out] = b_data[flat_b];
    }

    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    return self.withLogicalShape(result, out_shape);
}

fn resolveConcatLayout(shape: []const i64, axis: usize, data_len: usize) ?ConcatLayout {
    if (axis >= shape.len) return null;

    var outer = safeShapeNumel(shape[0..axis]);
    var inner = safeShapeNumel(shape[axis + 1 ..]);
    var axis_size: ?usize = if (shape[axis] > 0) @intCast(shape[axis]) else null;

    const known_count: usize =
        @as(usize, @intFromBool(outer != null)) +
        @as(usize, @intFromBool(axis_size != null)) +
        @as(usize, @intFromBool(inner != null));
    if (known_count < 2) return null;

    if (outer == null) {
        const known = std.math.mul(usize, axis_size.?, inner.?) catch return null;
        if (known == 0 or data_len % known != 0) return null;
        outer = data_len / known;
    }
    if (axis_size == null) {
        const known = std.math.mul(usize, outer.?, inner.?) catch return null;
        if (known == 0 or data_len % known != 0) return null;
        axis_size = data_len / known;
    }
    if (inner == null) {
        const known = std.math.mul(usize, outer.?, axis_size.?) catch return null;
        if (known == 0 or data_len % known != 0) return null;
        inner = data_len / known;
    }

    const total = std.math.mul(usize, outer.?, axis_size.?) catch return null;
    if ((std.math.mul(usize, total, inner.?) catch return null) != data_len) return null;

    return .{
        .outer = outer.?,
        .axis_size = axis_size.?,
        .inner = inner.?,
    };
}

fn allKnownDimsAreOne(shape: []const i64) bool {
    for (shape) |dim| {
        if (dim > 1) return false;
    }
    return true;
}

// Quantised matmul parallelism config.
//
// Quantised linears now go through the same persistent futex pool that sgemm
// uses, so per-call threading overhead is comparable to dense.  Parallel
// dispatch is on by default; set `TERMITE_QUANT_PARALLEL=0` to force the
// serial path (useful for A/B comparisons or single-threaded debugging).
//
// Knobs (set unset / "0" / a value as needed):
//   TERMITE_QUANT_PARALLEL          gate, default on
//   TERMITE_QUANT_PARALLEL_WORKERS  worker count cap, default `pool.max_workers`
//   TERMITE_QUANT_PARALLEL_MIN_WORK minimum (rows * cols * blocks) work to
//                                   bother threading; default 16,384
//   TERMITE_QUANT_COL_PARALLEL_MAX_ROWS
//                                   max rows eligible for column splitting;
//                                   default 2 globally, with measured Q4/Q5
//                                   prepared Q8_K paths using 384 when a real
//                                   parallel dispatcher is available
//   TERMITE_QUANT_PARALLEL_DEBUG    print plan decisions per call
fn quantParallelEnabled() bool {
    return platform.env.getenvBoolDefault("TERMITE_QUANT_PARALLEL", true);
}

fn parseEnvUsize(name: [:0]const u8) ?usize {
    return platform.env.getenvUsize(name.ptr);
}

fn quantParallelMaxWorkers() usize {
    return @min(parseEnvUsize("TERMITE_QUANT_PARALLEL_WORKERS") orelse max_q4_k_parallel_workers, max_q4_k_parallel_workers);
}

fn quantParallelMinWorkUnitsPerWorker() usize {
    return parseEnvUsize("TERMITE_QUANT_PARALLEL_MIN_WORK") orelse 16_384;
}

fn quantColumnParallelMaxRows(dispatch_available: bool) usize {
    _ = dispatch_available;
    if (parseEnvUsize("TERMITE_QUANT_COL_PARALLEL_MAX_ROWS")) |value| return value;
    return quant_col_parallel_max_rows;
}

fn q4q5PreparedQ8KColumnParallelMaxRows(dispatch_available: bool) usize {
    if (parseEnvUsize("TERMITE_QUANT_COL_PARALLEL_MAX_ROWS")) |value| return value;
    return if (dispatch_available) quant_col_parallel_dispatch_max_rows else quant_col_parallel_max_rows;
}

fn q4q5PreparedQ8KColumnParallelMaxRowsForShape(
    dispatch_available: bool,
    known: ?gguf_tensor_types.KnownTensorType,
    panel16_available: bool,
) usize {
    if (parseEnvUsize("TERMITE_QUANT_COL_PARALLEL_MAX_ROWS")) |value| return value;
    if (!panel16_available) return quant_col_parallel_max_rows;
    const kind = known orelse return quant_col_parallel_max_rows;
    if (kind != .Q4_K and kind != .Q5_K) return quant_col_parallel_max_rows;
    return q4q5PreparedQ8KColumnParallelMaxRows(dispatch_available);
}

fn quantParallelDispatchAvailable(io: ?std.Io) bool {
    return io != null or linalg.pool.have_futex;
}

fn quantParallelDebugRequested() bool {
    return platform.env.getenvBool("TERMITE_QUANT_PARALLEL_DEBUG");
}

