}

fn chooseQ4Q5Panel16DirectShape(rows: usize, out_dim: usize, row_blocks: usize) bool {
    if (out_dim % prepared_k_panel16_nr != 0) return false;
    // GGML routes K-quants through Q8_K activations and shape-specific
    // packed kernels. For CLIP/CLAP-sized native direct calls, the prepared
    // panel16 route is the only direct path that behaves like a tiled matmul.
    const row_blocks_ok = row_blocks == 2 or row_blocks == 3 or row_blocks == 6 or row_blocks == 8 or row_blocks == 12;
    if (!row_blocks_ok) return false;
    if (rows == 1) return out_dim >= 512;
    if (rows == 2) return out_dim >= 512;
    if (rows < 4) return false;
    if (rows < 384) return true;

    // CLAP text can run at the full 514-token context.  The same panel16
    // MR4/MR2 direct path remains well-shaped there; keep larger arbitrary
    // row counts on the existing generic quant route until measured.
    return rows == 514 and
        (row_blocks == 3 or row_blocks == 12) and
        (out_dim == 768 or out_dim == 3072);
}

fn useQ4Q5Panel16DirectForShape(rows: usize, out_dim: usize, row_blocks: usize, has_panel16: bool) bool {
    if (!has_panel16) return false;
    if (q4q5Panel16DirectOverrideForBench()) |forced| return forced;
    return chooseQ4Q5Panel16DirectShape(rows, out_dim, row_blocks);
}

