fn chooseQ4Q5Panel16MR8DirectShape(rows: usize, out_dim: usize, row_blocks: usize, known: gguf_tensor_types.KnownTensorType) bool {
    if (known != .Q4_K and known != .Q5_K) return false;
    if (row_blocks == 6) return rows >= 32 and rows < 64 and rows % 4 == 0 and out_dim == 3072;
    if (rows < 77 or rows > 308) return false;
    if (rows % 77 != 0 and rows % 8 != 0) return false;
    if (row_blocks == 3) return out_dim == 768 or out_dim == 3072;
    if (row_blocks == 12) return rows % 8 == 0 and out_dim == 768;
    return false;
}

fn useQ4Q5Panel16MR8DirectForShape(rows: usize, out_dim: usize, row_blocks: usize, known: gguf_tensor_types.KnownTensorType, has_panel16: bool) bool {
    if (!useQ4Q5Panel16DirectForShape(rows, out_dim, row_blocks, has_panel16)) return false;
    return chooseQ4Q5Panel16MR8DirectShape(rows, out_dim, row_blocks, known);
}

