fn chooseQ4Q5PackedQKVPanel16Shape(rows: usize, out_dim: usize, known: gguf_tensor_types.KnownTensorType) bool {
    if (known != .Q4_K and known != .Q5_K) return false;
    if (rows == 0 or out_dim % prepared_k_panel16_nr != 0) return false;
    if (rows <= 2) return out_dim == 512 or out_dim == 768;
    if (rows < 4) return false;
    // CLIP text hidden-512 QKV is the one non-768 bucket where the physical
    // packed QKV panel consistently beats the unpacked panel16 path.
    if (rows == 77 and out_dim == 512) return true;
    if (out_dim != 768) return false;
    if (rows == 50) return true;
    if (rows == 514) return true;
    if (rows < 65 or rows >= 384) return false;
    // With Io/futex-backed column dispatch, packed-QKV reuses the physical
    // panel across Q/K/V and wins on measured CLIP text, CLAP text, and CLIP
    // vision buckets.
    return true;
}

fn useQ4Q5PackedQKVPanel16ForShape(rows: usize, out_dim: usize, known: gguf_tensor_types.KnownTensorType) bool {
    if (q4q5PackedQKVPanel16OverrideForBench()) |forced| return forced;
    return chooseQ4Q5PackedQKVPanel16Shape(rows, out_dim, known);
}

pub fn q4q5PackedQKVPanel16AutoRouteNameForBench(rows: usize, in_dim: usize, out_dim: usize, known: gguf_tensor_types.KnownTensorType) []const u8 {
    if (!q4q5Panel16DirectEnabled()) return "legacyTriple";
    if (!useQ4Q5PackedQKVPanel16ForShape(rows, out_dim, known)) return "panel16Split";
    if (in_dim % 256 == 0 and chooseQ4Q5Panel16MR8DirectShape(rows, out_dim, in_dim / 256, known)) {
        const uses_mr4_tail = rows % 8 >= 4;
        const uses_mr2_tail = rows % 4 >= 2;
        const uses_mr1_tail = rows % 2 == 1;
        if (uses_mr4_tail and uses_mr2_tail and uses_mr1_tail) return "packedMR8+MR4+MR2+MR1";
        if (uses_mr4_tail and uses_mr2_tail) return "packedMR8+MR4+MR2";
        if (uses_mr4_tail and uses_mr1_tail) return "packedMR8+MR4+MR1";
        if (uses_mr2_tail and uses_mr1_tail) return "packedMR8+MR2+MR1";
        if (uses_mr4_tail) return "packedMR8+MR4";
        if (uses_mr2_tail) return "packedMR8+MR2";
        if (uses_mr1_tail) return "packedMR8+MR1";
        return "packedMR8";
    }
    const uses_mr2_tail = rows % 4 >= 2;
    const uses_mr1_tail = rows % 2 == 1;
    if (rows >= 4) {
        if (uses_mr2_tail and uses_mr1_tail) return "packedMR4+MR2+MR1";
        if (uses_mr2_tail) return "packedMR4+MR2";
        if (uses_mr1_tail) return "packedMR4+MR1";
        return "packedMR4";
    }
    if (rows >= 2) return if (uses_mr1_tail) "packedMR2+MR1" else "packedMR2";
    return "packedMR1";
}

