fn shouldUseQ8_0ActivationQuant(rows: usize, out_dim: usize, row_blocks: usize) bool {
    if (!q8_0ActivationQuantEnabled()) return false;
    if (out_dim < 512 or row_blocks < 3) return false;
    if (rows >= 16) return true;
    // Q8_0 f32-input decode remains memory dominated for CLIP/CLAP pooled
    // projections. Quantizing the small activation row once lets us reuse the
    // int8-dot prepared panel kernel instead of rereading/scaling f32 blocks
    // for every output column.
    return true;
}

fn shouldUseQ8_0GroupedActivationPair(rows: usize, out_dim: usize, row_blocks: usize) bool {
    if (!shouldUseQ8_0ActivationQuant(rows, out_dim, row_blocks)) return false;
    if (rows >= 77 and out_dim >= 512) return false;
    return true;
}

