fn shouldUseKFamilyQ8KActivationShape(rows: usize, out_dim: usize, row_blocks: usize) bool {
    if (out_dim < 512 or row_blocks < 1) return false;
    if (rows >= 16) return true;
    // Single-token pooled/MLP projections are dominated by repeated f32
    // dequant work. For CLIP/CLAP-sized K (768 => 3 QK blocks), quantizing
    // activations once and using the int8-dot direct kernel wins without
    // falling back to dequant-SGEMM.
    if (row_blocks >= 3) return true;
    return false;
}

