}

fn convertTensorToOwnedF32(allocator: std.mem.Allocator, tensor: *const tensor_mod.Tensor) ![]f32 {
    const count = tensor.elementCount();
    const out = try allocator.alloc(f32, count);
    switch (tensor.dtype) {
        .f32 => {
            if (tensor.asFloat32IfAligned()) |src| {
                @memcpy(out, src);
            } else {
                const src_bytes: [*]const u8 = tensor.data.ptr;
                for (0..count) |i| {
                    const offset = i * 4;
                    const bits: u32 = @bitCast([4]u8{
                        src_bytes[offset],
                        src_bytes[offset + 1],
                        src_bytes[offset + 2],
                        src_bytes[offset + 3],
                    });
                    out[i] = @bitCast(bits);
                }
            }
        },
        .f16 => {
            const src_bytes: [*]const u8 = tensor.data.ptr;
            for (0..count) |i| {
                const offset = i * 2;
                const half: f16 = @bitCast([2]u8{ src_bytes[offset], src_bytes[offset + 1] });
                out[i] = @floatCast(half);
            }
        },
        .bf16 => {
            const src_bytes: [*]const u8 = tensor.data.ptr;
            for (0..count) |i| {
                const offset = i * 2;
                const bits: u16 = @bitCast([2]u8{ src_bytes[offset], src_bytes[offset + 1] });
                out[i] = @bitCast(@as(u32, bits) << 16);
            }
        },
        .f64 => {
            const src_bytes: [*]const u8 = tensor.data.ptr;
            for (0..count) |i| {
                const offset = i * 8;
                const bits = std.mem.readInt(u64, src_bytes[offset..][0..8], .little);
                const value: f64 = @bitCast(bits);
                out[i] = @floatCast(value);
            }
        },
        .i8 => {
            const src = tensor.asInt8();
            for (src, 0..) |value, i| out[i] = @floatFromInt(value);
        },
        .i16 => {
            const src_bytes: [*]const u8 = tensor.data.ptr;
            for (0..count) |i| {
                const offset = i * 2;
                const value = std.mem.readInt(i16, src_bytes[offset..][0..2], .little);
                out[i] = @floatFromInt(value);
            }
        },
        .i32 => {
            const src_bytes: [*]const u8 = tensor.data.ptr;
            for (0..count) |i| {
                const offset = i * 4;
                const value = std.mem.readInt(i32, src_bytes[offset..][0..4], .little);
                out[i] = @floatFromInt(value);
            }
        },
        .i64 => {
            const src_bytes: [*]const u8 = tensor.data.ptr;
            for (0..count) |i| {
                const offset = i * 8;
                const value = std.mem.readInt(i64, src_bytes[offset..][0..8], .little);
                out[i] = @floatFromInt(value);
            }
        },
        .u8 => {
            const src = std.mem.bytesAsSlice(u8, tensor.data);
            for (src, 0..) |value, i| out[i] = @floatFromInt(value);
        },
        .bool_ => {
            const src = std.mem.bytesAsSlice(u8, tensor.data);
            for (src, 0..) |value, i| out[i] = if (value == 0) 0.0 else 1.0;
        },
    }
    return out;
}

fn convertTensorRowsToF32(
    tensor: *const tensor_mod.Tensor,
    row_start: usize,
    row_count: usize,
    row_width: usize,
    out: []f32,
) !void {
    std.debug.assert(out.len >= row_count * row_width);
    const elem_start = row_start * row_width;
    const elem_count = row_count * row_width;
    switch (tensor.dtype) {
        .f32 => {
            if (tensor.asFloat32IfAligned()) |src| {
                @memcpy(out[0..elem_count], src[elem_start .. elem_start + elem_count]);
            } else {
                const src_bytes: [*]const u8 = tensor.data.ptr;
                for (0..elem_count) |i| {
                    const offset = (elem_start + i) * 4;
                    const bits: u32 = @bitCast([4]u8{
                        src_bytes[offset],
                        src_bytes[offset + 1],
                        src_bytes[offset + 2],
                        src_bytes[offset + 3],
                    });
                    out[i] = @bitCast(bits);
                }
            }
        },
        .f16 => {
            const src_bytes: [*]const u8 = tensor.data.ptr;
            for (0..elem_count) |i| {
                const offset = (elem_start + i) * 2;
                const half: f16 = @bitCast([2]u8{ src_bytes[offset], src_bytes[offset + 1] });
                out[i] = @floatCast(half);
            }
        },
        .bf16 => {
            const src_bytes: [*]const u8 = tensor.data.ptr;
            for (0..elem_count) |i| {
                const offset = (elem_start + i) * 2;
                const bits: u16 = @bitCast([2]u8{ src_bytes[offset], src_bytes[offset + 1] });
                out[i] = @bitCast(@as(u32, bits) << 16);
            }
        },
        else => return error.UnsupportedTensorType,
    }
}

fn shouldBorrowEmbeddingTensor(name: []const u8) bool {
    return std.mem.eql(u8, name, "model.embed_tokens.weight") or
        std.mem.eql(u8, name, "wte.weight");
}

const WeightF32View = struct {
    data: []const f32,
    owned: ?[]f32 = null,
};

fn denseWeightView(self: *NativeCompute, weight: CT) !WeightF32View {
    const buf = toBuf(weight);
    if (buf.data.len != 0) return .{ .data = buf.data };
    if (buf.source_tensor) |tensor| {
        const converted = try convertTensorToOwnedF32(self.allocator, tensor);
        return .{ .data = converted, .owned = converted };
    }
    return error.MissingWeight;
}

fn denseTensorView(self: *NativeCompute, tensor: CT) !WeightF32View {
    const buf = toBuf(tensor);
    if (buf.data.len != 0) return .{ .data = getData(tensor) };
    if (buf.source_tensor != null or buf.quantized_storage != null or buf.lazy_entry != null) {
        const converted = try toFloat32Op(self, tensor, self.allocator);
        return .{ .data = converted, .owned = converted };
    }
    return .{ .data = getData(tensor) };
}

fn borrowTensorF32IfAligned(tensor: *const tensor_mod.Tensor) ?[]const f32 {
    if (tensor.dtype != .f32) return null;
    return tensor.asFloat32IfAligned();
}

fn tensorF32View(self: *NativeCompute, tensor: *const tensor_mod.Tensor) !WeightF32View {
    if (borrowTensorF32IfAligned(tensor)) |data| {
        return .{ .data = data };
    }
    const converted = try convertTensorToOwnedF32(self.allocator, tensor);
    return .{ .data = converted, .owned = converted };
}

fn linearNoBiasSourceTensorChunked(
    self: *NativeCompute,
    input: []const f32,
    tensor: *const tensor_mod.Tensor,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    if (tensor.shape.len != 2) return error.UnsupportedTensorType;
    if (tensor.shape[0] != out_dim or tensor.shape[1] != in_dim) return error.ShapeMismatch;
    if (tensor.dtype != .f32 and tensor.dtype != .f16 and tensor.dtype != .bf16) {
        return error.UnsupportedTensorType;
    }

    // Fast path: f16 weights, naturally aligned, can be consumed directly by
    // sgemmTransBF16Weights without materializing an f32 copy.  This halves
    // the weight bandwidth -- the dominant cost for transformer linear ops.
    if (tensor.dtype == .f16) {
        if (tensor.asFloat16IfAligned()) |weight_f16| {
            try self.dispatchSgemmTransBF16Weights(
                rows,
                out_dim,
                in_dim,
                1.0,
                input,
                weight_f16,
                0.0,
                output,
            );
            return;
        }
    }

    const target_weight_bytes: usize = 8 * 1024 * 1024;
    const block_rows = @max(@as(usize, 1), @min(out_dim, target_weight_bytes / (@max(@as(usize, 1), in_dim) * @sizeOf(f32))));
    const weight_block = try self.allocator.alloc(f32, block_rows * in_dim);
    defer self.allocator.free(weight_block);
    const output_block = try self.allocator.alloc(f32, rows * block_rows);
    defer self.allocator.free(output_block);

    var row_start: usize = 0;
    while (row_start < out_dim) : (row_start += block_rows) {
        const row_count = @min(block_rows, out_dim - row_start);
        try convertTensorRowsToF32(tensor, row_start, row_count, in_dim, weight_block[0 .. row_count * in_dim]);
        @memset(output_block[0 .. rows * row_count], 0.0);
        try self.dispatchSgemmTransB(
            rows,
            row_count,
            in_dim,
            1.0,
            input,
            weight_block[0 .. row_count * in_dim],
            0.0,
            output_block[0 .. rows * row_count],
        );
        for (0..rows) |r| {
            const src = output_block[r * row_count ..][0..row_count];
            const dst = output[r * out_dim + row_start ..][0..row_count];
            @memcpy(dst, src);
        }
    }
}

fn matmulRhsSourceTensorChunked(
    self: *NativeCompute,
    lhs: []const f32,
    rhs_tensor: *const tensor_mod.Tensor,
    output: []f32,
    m: usize,
    k: usize,
    n: usize,
) !void {
    if (rhs_tensor.shape.len != 2) return error.UnsupportedTensorType;
    if (rhs_tensor.shape[0] != k or rhs_tensor.shape[1] != n) return error.ShapeMismatch;
    if (rhs_tensor.dtype != .f32 and rhs_tensor.dtype != .f16 and rhs_tensor.dtype != .bf16) {
        return error.UnsupportedTensorType;
    }

    const target_weight_bytes: usize = 8 * 1024 * 1024;
    const k_block = @max(@as(usize, 1), @min(k, target_weight_bytes / (@max(@as(usize, 1), n) * @sizeOf(f32))));
    const lhs_block = try self.allocator.alloc(f32, m * k_block);
    defer self.allocator.free(lhs_block);
    const rhs_block = try self.allocator.alloc(f32, k_block * n);
    defer self.allocator.free(rhs_block);
    const rhs_block_transposed = try self.allocator.alloc(f32, n * k_block);
    defer self.allocator.free(rhs_block_transposed);

    var k_start: usize = 0;
    while (k_start < k) : (k_start += k_block) {
        const cur_k = @min(k_block, k - k_start);
        for (0..m) |row| {
            @memcpy(
                lhs_block[row * cur_k ..][0..cur_k],
                lhs[row * k + k_start ..][0..cur_k],
            );
        }
        try convertTensorRowsToF32(rhs_tensor, k_start, cur_k, n, rhs_block[0 .. cur_k * n]);
        for (0..cur_k) |ki| {
            for (0..n) |j| {
                rhs_block_transposed[j * cur_k + ki] = rhs_block[ki * n + j];
            }
        }
        try self.dispatchSgemmTransB(
            m,
            n,
            cur_k,
            1.0,
            lhs_block[0 .. m * cur_k],
            rhs_block_transposed[0 .. n * cur_k],
            1.0,
            output,
        );
    }
}

fn linearNoBiasLazyEntryChunked(
    self: *NativeCompute,
    input: []const f32,
    entry: *LazyWeightEntry,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    var maybe_loaded: ?LoadedWeight = null;
    defer if (maybe_loaded) |*loaded| loaded.deinit();
    const tensor: *const tensor_mod.Tensor = if (entry.loaded) |*loaded|
        if (loaded.quantized_storage == null) &loaded.tensor else return error.UnsupportedTensorType
    else blk: {
        const tensor_store = self.data.tensor_store orelse return error.MissingWeight;
        maybe_loaded = try tensor_store.loadTensorRef(&entry.tensor_ref);
        if (maybe_loaded.?.quantized_storage != null) return error.UnsupportedTensorType;
        break :blk &maybe_loaded.?.tensor;
    };
    // Forwards to the source-tensor path which handles the f16-aligned fast
    // path internally; this means lazy-loaded f16 weights also skip the
    // f16->f32 materialization step.
    try linearNoBiasSourceTensorChunked(self, input, tensor, output, rows, in_dim, out_dim);
}

fn loadEphemeralQuantizedLazyWeight(
    self: *NativeCompute,
    entry: *LazyWeightEntry,
    name: []const u8,
) !?CT {
    if (!shouldDegradeQuantBudgetPressure(entry)) return null;
    const tensor_store = self.data.tensor_store orelse return null;
    var storage = (try tensor_store.loadQuantizedStorageRef(&entry.tensor_ref)) orelse return null;
    try prepareNativeQuantizedStorage(&storage);
    return self.makeBufWithOwnedQuantizedStorage(name, entry, storage);
}

pub const NativeCompute = struct {
    allocator: std.mem.Allocator,
    data: *WeightStore,
    run_budget: ?*run_memory.RunBudget = null,
    weight_reservations: std.StringHashMapUnmanaged(ReservationState) = .empty,
    /// Optional Io for parallel GEMM dispatch.  When non-null, sgemm calls
    /// route through linalg's Io-aware variants and parallel work is
    /// scheduled on the runtime's thread pool.  When null, sgemm uses the
    /// process-wide futex pool inside lib/linalg directly.  Tests typically
    /// pass null; production session creation supplies the application's Io.
    io: ?std.Io = null,

    pub fn init(allocator: std.mem.Allocator, data: *WeightStore, run_budget: ?*run_memory.RunBudget) NativeCompute {
        initPrefetchQueue(data, allocator);
        return .{ .allocator = allocator, .data = data, .run_budget = run_budget };
    }

    pub fn initWithIo(
        allocator: std.mem.Allocator,
        data: *WeightStore,
        run_budget: ?*run_memory.RunBudget,
        io: std.Io,
    ) NativeCompute {
        initPrefetchQueue(data, allocator);
        return .{ .allocator = allocator, .data = data, .run_budget = run_budget, .io = io };
    }

    // Dispatchers select the canonical Io API when this backend was constructed
    // with one; otherwise fall through to the *Sync escape hatch.  Cancellation
    // mid-matmul leaves C in a partial state -- caller's `errdefer` paths must
    // assume the output buffer is incompletely written when error.Canceled
    // surfaces.

    inline fn dispatchSgemmTransB(
        self: *const NativeCompute,
        m: usize,
        n: usize,
        k: usize,
        alpha: f32,
        a: []const f32,
        b: []const f32,
        beta: f32,
        c_out: []f32,
    ) error{Canceled}!void {
        if (self.io) |io| {
            return native.sgemmTransB(io, m, n, k, alpha, a, b, beta, c_out);
        }
        native.sgemmTransBSync(m, n, k, alpha, a, b, beta, c_out);
    }

    inline fn dispatchSgemm(
        self: *const NativeCompute,
        m: usize,
        n: usize,
        k: usize,
        alpha: f32,
        a: []const f32,
        b: []const f32,
        beta: f32,
        c_out: []f32,
    ) error{Canceled}!void {
        if (self.io) |io| {
            return native.sgemm(io, m, n, k, alpha, a, b, beta, c_out);
        }
        native.sgemmSync(m, n, k, alpha, a, b, beta, c_out);
    }

    inline fn dispatchSgemmTransBF16Weights(
        self: *const NativeCompute,
        m: usize,
        n: usize,
        k: usize,
        alpha: f32,
        a: []const f32,
        b: []const f16,
        beta: f32,
        c_out: []f32,
    ) error{Canceled}!void {
        if (self.io) |io| {
            return native.sgemmTransBF16Weights(io, m, n, k, alpha, a, b, beta, c_out);
        }
        native.sgemmTransBF16WeightsSync(m, n, k, alpha, a, b, beta, c_out);
    }

    pub fn computeBackend(self: *NativeCompute) ComputeBackend {
        return .{ .ptr = self, .vtable = &vtable_impl };
    }

    pub fn importHostTensor(self: *NativeCompute, tensor: *const tensor_mod.Tensor) !CT {
        const converted = try convertTensorToOwnedF32(self.allocator, tensor);
        errdefer self.allocator.free(converted);
        return self.importDenseTensor(tensor.name, tensor.dtype, tensor.shape, converted);
    }

    pub fn importOwnedStaticTensor(self: *NativeCompute, tensor: tensor_mod.Tensor) !CT {
        const can_keep_typed =
            tensor.shape.len == 2 and
            (tensor.dtype == .f32 or tensor.dtype == .f16 or tensor.dtype == .bf16);
        if (can_keep_typed) {
            return self.makeBufWithOwnedSourceTensor(tensor);
        }

        var owned_tensor = tensor;
        defer owned_tensor.deinit();
        const converted = try convertTensorToOwnedF32(self.allocator, &owned_tensor);
        errdefer self.allocator.free(converted);
        return self.importDenseTensor(owned_tensor.name, owned_tensor.dtype, owned_tensor.shape, converted);
    }

    pub fn importDenseTensor(
        self: *NativeCompute,
        name: []const u8,
        dtype: tensor_mod.DType,
        shape: []const i64,
        data: []f32,
    ) !CT {
        const buf = try self.makeBuf(data, true);
        errdefer self.freeImportedTensor(buf);
        toBuf(buf).logical_shape = try self.allocator.dupe(i64, shape);
        toBuf(buf).declared_dtype = dtype;
        toBuf(buf).name = name;
        return buf;
    }

    fn freeImportedTensor(self: *NativeCompute, tensor: CT) void {
        self.computeBackend().free(tensor);
    }

    fn withLogicalShape(self: *NativeCompute, tensor: CT, shape: []const i64) !CT {
        const buf = toBuf(tensor);
        releaseLogicalShape(buf);
        if (shape.len <= buf.inline_logical_shape.len) {
            @memcpy(buf.inline_logical_shape[0..shape.len], shape);
            buf.logical_shape = buf.inline_logical_shape[0..shape.len];
            buf.logical_shape_inline = true;
        } else {
            buf.logical_shape = try self.allocator.dupe(i64, shape);
            buf.logical_shape_inline = false;
        }
        return tensor;
    }

    fn makeBuf(self: *NativeCompute, data: []f32, owned: bool) !CT {
        return self.makeBufWithEntry(data, owned, "", null, null, null);
    }

    fn makeOwnedBuf(self: *NativeCompute, data: []f32) !CT {
        errdefer self.allocator.free(data);
        return self.makeBuf(data, true);
    }

    fn makeBufWithEntry(
        self: *NativeCompute,
        data: []f32,
        owned: bool,
        name: []const u8,
        lazy_entry: ?*LazyWeightEntry,
        quantized_storage: ?*const QuantizedStorage,
        source_tensor: ?*const tensor_mod.Tensor,
    ) !CT {
        const b = try self.allocator.create(Buf);
        var shared_data_refcount: ?*usize = null;
        errdefer if (shared_data_refcount) |refcount| self.allocator.destroy(refcount);
        if (owned) {
            shared_data_refcount = try self.allocator.create(usize);
            shared_data_refcount.?.* = 1;
        }
        b.* = .{
            .data = data,
            .allocator = self.allocator,
            .owned = owned,
            .shared_data_refcount = shared_data_refcount,
            .logical_shape = null,
            .view_strides = null,
            .view_base_offset = 0,
            .declared_dtype = null,
            .name = name,
            .lazy_entry = lazy_entry,
            .quantized_storage = quantized_storage,
            .owned_quantized_storage = null,
            .source_tensor = source_tensor,
            .owned_source_tensor = null,
            .reservation = null,
        };
        return b;
    }

    fn aliasOwnedBufWithShape(self: *NativeCompute, input: CT, shape: []const i64) !CT {
        const source = toBuf(input);
        if (!source.owned or source.shared_data_refcount == null) return error.UnsupportedTensorType;
        source.shared_data_refcount.?.* += 1;

        const alias = try self.allocator.create(Buf);
        errdefer {
            source.shared_data_refcount.?.* -= 1;
        }
        alias.* = .{
            .data = source.data,
            .allocator = self.allocator,
            .owned = true,
            .shared_data_refcount = source.shared_data_refcount,
            .logical_shape = try self.allocator.dupe(i64, shape),
            .view_strides = null,
            .view_base_offset = 0,
            .declared_dtype = source.declared_dtype,
            .name = source.name,
            .lazy_entry = null,
            .quantized_storage = null,
            .owned_quantized_storage = null,
            .source_tensor = null,
            .owned_source_tensor = null,
            .reservation = null,
        };
        return alias;
    }

    fn makeBufWithOwnedQuantizedStorage(
        self: *NativeCompute,
        name: []const u8,
        lazy_entry: ?*LazyWeightEntry,
        storage: QuantizedStorage,
    ) !CT {
        const owned_storage = try self.allocator.create(QuantizedStorage);
        errdefer self.allocator.destroy(owned_storage);
        owned_storage.* = storage;
        const b = try self.allocator.create(Buf);
        b.* = .{
            .data = empty_f32[0..],
            .allocator = self.allocator,
            .owned = false,
            .shared_data_refcount = null,
            .logical_shape = null,
            .view_strides = null,
            .view_base_offset = 0,
            .declared_dtype = null,
            .name = name,
            .lazy_entry = lazy_entry,
            .quantized_storage = owned_storage,
            .owned_quantized_storage = owned_storage,
            .source_tensor = null,
            .owned_source_tensor = null,
            .reservation = null,
        };
        return b;
    }

    fn makeBufWithOwnedSourceTensor(self: *NativeCompute, tensor: tensor_mod.Tensor) !CT {
        const owned_tensor = try self.allocator.create(tensor_mod.Tensor);
        errdefer self.allocator.destroy(owned_tensor);
        owned_tensor.* = tensor;
        errdefer owned_tensor.deinit();

        const b = try self.allocator.create(Buf);
        errdefer self.allocator.destroy(b);
        b.* = .{
            .data = empty_f32[0..],
            .allocator = self.allocator,
            .owned = false,
            .shared_data_refcount = null,
            .logical_shape = null,
            .view_strides = null,
            .view_base_offset = 0,
            .declared_dtype = owned_tensor.dtype,
            .name = owned_tensor.name,
            .lazy_entry = null,
            .quantized_storage = null,
            .owned_quantized_storage = null,
            .source_tensor = owned_tensor,
            .owned_source_tensor = owned_tensor,
            .reservation = null,
        };
        return self.withLogicalShape(b, owned_tensor.shape);
    }
};

pub fn initPrefetchQueue(data: *WeightStore, allocator: std.mem.Allocator) void {
    if (data.prefetch_initialized) return;
    data.prefetch = PrefetchQueue.initWithPriority(allocator, data, &prefetchProcess, &prefetchPriority);
    data.prefetch_initialized = true;
    var lazy_it = data.lazy_weights.iterator();
    while (lazy_it.next()) |entry| {
        entry.value_ptr.guard = data.prefetch.mutexPtr();
    }
}

pub fn startPrefetchWorker(data: *WeightStore) !void {
    try data.prefetch.start();
}

pub fn stopPrefetchWorker(data: *WeightStore) void {
    data.prefetch.stop();
}

pub fn deinitPrefetchQueue(data: *WeightStore) void {
    deinitGlinerHeadDenseCache(data);
    if (!data.prefetch_initialized) return;
    data.prefetch.deinit();
    data.prefetch_initialized = false;
}

pub fn deinitGlinerHeadDenseCache(data: *WeightStore) void {
    while (!data.gliner_head_dense_cache_lock.tryLock()) {
        std.Thread.yield() catch {};
    }
    defer data.gliner_head_dense_cache_lock.unlock();

    var it = data.gliner_head_dense_cache.iterator();
    while (it.next()) |entry| {
        data.allocator.free(entry.key_ptr.*);
        data.allocator.free(entry.value_ptr.data);
        if (data.tier_cache) |*tier_cache| tier_cache.noteRelease(.host, entry.value_ptr.bytes);
    }
    data.gliner_head_dense_cache.deinit(data.allocator);
    data.gliner_head_dense_cache = .{};
    data.gliner_head_dense_cache_bytes = 0;
}

pub fn quantDequantCacheStats(data: *WeightStore) QuantDequantCacheStats {
    while (!data.gliner_head_dense_cache_lock.tryLock()) {
        std.Thread.yield() catch {};
    }
    defer data.gliner_head_dense_cache_lock.unlock();

    return .{
        .entries = data.gliner_head_dense_cache.count(),
        .bytes = data.gliner_head_dense_cache_bytes,
        .hits = data.quant_dequant_cache_hits,
        .misses = data.quant_dequant_cache_misses,
        .inserts = data.quant_dequant_cache_inserts,
        .disabled = data.quant_dequant_cache_disabled,
        .too_large = data.quant_dequant_cache_too_large,
        .capacity_denied = data.quant_dequant_cache_capacity_denied,
        .tier_denied = data.quant_dequant_cache_tier_denied,
        .scratch_fallbacks = data.quant_dequant_cache_scratch_fallbacks,
        .scratch_denied = data.quant_dequant_cache_scratch_denied,
    };
}

// --- SIMD helpers ---

// SIMD width / vector aliases canonically live in `quant_codec.zig`
// alongside the encoders.  The decoder dot kernels in this file still
// depend on them; keeping the local aliases as one-line indirections
// to the canonical source means a future physical move of the dot
// kernels into quant_codec is a pure file split rather than an API
// change.
const VEC_LEN = quant_codec.vec_len;
const F32xN = quant_codec.F32xN;
const I32xN = quant_codec.I32xN;
const I8xN = quant_codec.I8xN;
const U8xN = quant_codec.U8xN;
const U8x16 = @Vector(16, u8);
const U8x8 = @Vector(8, u8);
const I8x8 = @Vector(8, i8);
const I32x4 = @Vector(4, i32);
const F32x4 = @Vector(4, f32);
const F32x8 = @Vector(8, f32);
const I32x8 = @Vector(8, i32);
const empty_f32: [0]f32 = .{};
const empty_u8: [0]u8 = .{};

fn quantizedStorageBudgetBytes(storage: *const QuantizedStorage) usize {
    const prepared_bytes = storage.prepared.ownedBytes();
    const group_cache_bytes = if (storage.prepared_group_cache) |cache| cache.ownedBytes() else 0;
    if (storage.packed_expert) |packed_view| {
        const count: usize = @max(@as(usize, 1), @as(usize, @intCast(packed_view.expert_count)));
        return @max(@as(usize, 1), storage.raw_bytes.len / count) + prepared_bytes + group_cache_bytes;
    }
    return storage.raw_bytes.len + prepared_bytes + group_cache_bytes;
}

fn preparedKBlockAdditionalBytes(storage: *const QuantizedStorage) usize {
    const known = switch (storage.tensor_type) {
        .known => |value| value,
        else => return 0,
    };
    if (known != .Q1_0 and known != .Q4_0 and known != .Q4_1 and known != .Q5_0 and known != .Q5_1 and known != .Q2_K and known != .Q3_K and known != .Q4_K and known != .Q5_K and known != .Q6_K and known != .Q8_0 and known != .Q8_1 and known != .Q8_K) return 0;
    if ((known == .Q1_0 or known == .Q4_0 or known == .Q4_1 or known == .Q5_0 or known == .Q5_1 or known == .Q2_K or known == .Q3_K) and storage.packed_expert != null) return 0;
    if ((known == .Q5_K or known == .Q6_K) and storage.packed_expert != null) return 0;
    if ((known == .Q8_0 or known == .Q8_1 or known == .Q8_K) and storage.packed_expert != null) return 0;
    const block_size = gguf_tensor_types.bytesPerBlock(storage.tensor_type) orelse return 0;
    if (block_size == 0 or storage.raw_bytes.len % block_size != 0) return 0;
    const block_count = storage.raw_bytes.len / block_size;
    const prepared_block_size: usize = if (known == .Q8_0 or known == .Q8_1)
        prepared_q8_0_block_bytes
    else if (known == .Q1_0)
        prepared_q1_0_block_bytes
    else if (known == .Q4_0 or known == .Q4_1 or known == .Q5_0 or known == .Q5_1)
        prepared_legacy_block_bytes
    else if (known == .Q2_K or known == .Q3_K)
        prepared_k16_block_bytes
    else
        prepared_q4_k_block_bytes;
    var additional: usize = if (known != .Q8_K and storage.preparedBytes(.row_major_blocks) == null) block_count * prepared_block_size else 0;
    if (known == .Q1_0 and storage.preparedBytes(.panel4) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 128 == 0) additional += preparedQ1_0PanelByteSize(out_dim, in_dim / 128);
    }
    if ((known == .Q4_0 or known == .Q4_1 or known == .Q5_0 or known == .Q5_1) and storage.preparedBytes(.panel4) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 32 == 0) additional += preparedLegacyPanelByteSize(out_dim, in_dim / 32);
    }
    if ((known == .Q2_K or known == .Q3_K) and storage.preparedBytes(.panel4) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 256 == 0) additional += preparedK16PanelByteSize(out_dim, in_dim / 256);
    }
    if (known == .Q3_K and q3KNoDmnPanelPreparedEnabled() and storage.preparedBytes(.panel4_k16_no_min) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 256 == 0) {
            const row_blocks = in_dim / 256;
            if (q3KNoDmnPanelPreparedEnabledForShape(out_dim, row_blocks)) additional += preparedQ3KNoDmnPanelByteSize(out_dim, row_blocks);
        }
    }
    if (k16Panel8DirectEnabledFor(known) and storage.preparedBytes(.panel8) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 256 == 0) additional += preparedK16Panel8ByteSize(out_dim, in_dim / 256);
    }
    if (k16Panel16PreparedEnabledFor(known) and storage.preparedBytes(.panel16) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 256 == 0) additional += preparedK16Panel16ByteSize(out_dim, in_dim / 256);
    }
    if ((known == .Q8_0 or known == .Q8_1) and storage.preparedBytes(.panel4) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 32 == 0) additional += preparedQ8_0PanelByteSize(out_dim, in_dim / 32);
    }
    if ((known == .Q8_0 or known == .Q8_1) and q8_0Panel8PrepareEnabled() and storage.preparedBytes(.panel8) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 32 == 0) additional += preparedQ8_0Panel8ByteSize(out_dim, in_dim / 32);
    }
    if (known == .Q8_K and storage.preparedBytes(.panel4) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 256 == 0) additional += preparedQ8_KPanelByteSize(out_dim, in_dim / 256);
    }
    if (q8KPanel8DirectEnabled() and known == .Q8_K and storage.preparedBytes(.panel8) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 256 == 0) additional += preparedQ8_KPanel8ByteSize(out_dim, in_dim / 256);
    }
    if (q8KPanel16PreparedEnabled() and known == .Q8_K and storage.preparedBytes(.panel16) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 256 == 0) additional += preparedQ8_KPanel16ByteSize(out_dim, in_dim / 256);
    }
    if ((known == .Q4_K or known == .Q5_K or known == .Q6_K) and storage.preparedBytes(.panel4) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 256 == 0) additional += preparedKPanelByteSize(out_dim, in_dim / 256);
    }
    if ((known == .Q4_K or known == .Q5_K or known == .Q6_K) and storage.preparedBytes(.panel8) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 256 == 0) additional += preparedKPanel8ByteSizeForKnown(known, out_dim, in_dim / 256);
    }
    if ((known == .Q4_K or known == .Q5_K or (known == .Q6_K and q6KPanel16PreparedEnabled())) and storage.preparedBytes(.panel16) == null and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0) {
        const out_dim: usize = @intCast(storage.shape[0]);
        const in_dim: usize = @intCast(storage.shape[1]);
        if (in_dim % 256 == 0) additional += preparedKPanel16ByteSize(out_dim, in_dim / 256);
    }
    return additional;
}

fn expectedQuantizedStorageLoadBytes(storage: *const QuantizedStorage) usize {
    return quantizedStorageBudgetBytes(storage) + preparedKBlockAdditionalBytes(storage);
}

fn getIo(ctx: *anyopaque) ?std.Io {
