fn backendKind(_: *anyopaque) BackendKind {
    return .native;
}

fn deinitBackend(ctx: *anyopaque) void {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    if (self.run_budget) |run_budget| {
        var it = self.weight_reservations.iterator();
        while (it.next()) |entry| {
            run_budget.release(entry.value_ptr.reservation);
            self.allocator.free(entry.key_ptr.*);
        }
    } else {
        var it = self.weight_reservations.iterator();
        while (it.next()) |entry| self.allocator.free(entry.key_ptr.*);
    }
    self.weight_reservations.deinit(self.allocator);
    self.allocator.destroy(self);
}

fn freeTensor(ctx: *anyopaque, tensor: CT) void {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const b = toBuf(tensor);
    if (b.lazy_entry) |entry| {
        if (entry.guard) |guard| {
            while (!guard.tryLock()) {
                std.Thread.yield() catch {};
            }
            defer guard.unlock();
            if (entry.pin_count > 0) entry.pin_count -= 1;
        } else if (entry.pin_count > 0) {
            entry.pin_count -= 1;
        }
        if (b.name.len > 0) releaseWeightReservation(self, b.name);
    }
    releaseOwnedDenseData(b);
    releaseLogicalShape(b);
    if (b.view_strides) |strides| b.allocator.free(strides);
    if (b.owned_quantized_storage) |storage| {
        storage.deinit();
        self.allocator.destroy(storage);
    }
    if (b.owned_source_tensor) |source| {
        source.deinit();
        self.allocator.destroy(source);
    }
    b.allocator.destroy(b);
}

fn acquireWeightReservation(self: *NativeCompute, name: []const u8, bytes: usize) !void {
    if (self.run_budget == null or name.len == 0) return;
    if (self.weight_reservations.getPtr(name)) |state| {
        state.count += 1;
        return;
    }
    const reservation = try self.run_budget.?.tryReserveWeight(.host, bytes);
    try self.weight_reservations.put(self.allocator, try self.allocator.dupe(u8, name), .{
        .count = 1,
        .reservation = reservation,
    });
}

fn releaseWeightReservation(self: *NativeCompute, name: []const u8) void {
    if (self.run_budget == null or name.len == 0) return;
    if (self.weight_reservations.fetchRemove(name)) |removed| {
        if (removed.value.count > 1) {
            self.weight_reservations.put(self.allocator, removed.key, .{
                .count = removed.value.count - 1,
                .reservation = removed.value.reservation,
            }) catch {
                self.allocator.free(removed.key);
                self.run_budget.?.release(removed.value.reservation);
                return;
            };
            return;
        }
        self.allocator.free(removed.key);
        self.run_budget.?.release(removed.value.reservation);
    }
}

fn getWeight(ctx: *anyopaque, name: []const u8) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    if (self.data.resident_weights.getPtr(name)) |w| {
        if (w.quantized_storage) |*storage| {
            try ensurePreparedKBlock(self, storage);
            const view = if (w.tensor.data.len > 0)
                try tensorF32View(self, &w.tensor)
            else
                WeightF32View{ .data = empty_f32[0..] };
            const tensor = try self.makeBufWithEntry(@constCast(view.data), view.owned != null, name, null, storage, null);
            errdefer freeTensor(self, tensor);
            return self.withLogicalShape(tensor, w.tensor.shape);
        }
        if (w.tensor.dtype == .f32) {
            const view = try tensorF32View(self, &w.tensor);
            const tensor = try self.makeBufWithEntry(@constCast(view.data), view.owned != null, name, null, null, null);
            errdefer freeTensor(self, tensor);
            return self.withLogicalShape(tensor, w.tensor.shape);
        }
        if (shouldBorrowEmbeddingTensor(name)) {
            return self.makeBufWithEntry(empty_f32[0..], false, name, null, null, &w.tensor);
        }
        const converted = try convertTensorToOwnedF32(self.allocator, &w.tensor);
        const tensor = try self.makeBufWithEntry(converted, true, name, null, null, null);
        errdefer freeTensor(self, tensor);
        return self.withLogicalShape(tensor, w.tensor.shape);
    }

    self.data.prefetch.lock();
    defer self.data.prefetch.unlock();
    if (self.data.lazy_weights.getPtr(name)) |entry| {
        ensureLazyWeightLoadedLocked(self.data, self.run_budget, entry) catch |err| switch (err) {
            error.MemoryBudgetExceeded => {
                if (self.data.tier_cache) |*tier_cache| {
                    logSharedCacheDenial("get_weight_host_load", tier_cache, name);
                }
                if (try loadEphemeralQuantizedLazyWeight(self, entry, name)) |ephemeral_quantized| {
                    return ephemeral_quantized;
                }
                if (canFallbackDenseBudgetPressure(name, entry)) {
                    return self.makeBufWithEntry(empty_f32[0..], false, name, entry, null, null);
                }
                return err;
            },
            else => return err,
        };
        entry.pin_count += 1;
        const loaded = &(entry.loaded.?);
        if (loaded.quantized_storage) |*storage| {
            try ensurePreparedKBlock(self, storage);
            const view = if (loaded.tensor.data.len > 0)
                try tensorF32View(self, &loaded.tensor)
            else
                WeightF32View{ .data = empty_f32[0..] };
            const tensor = try self.makeBufWithEntry(@constCast(view.data), view.owned != null, name, entry, storage, null);
            errdefer freeTensor(self, tensor);
            return self.withLogicalShape(tensor, loaded.tensor.shape);
        }
        if (loaded.tensor.dtype == .f32) {
            const view = try tensorF32View(self, &loaded.tensor);
            const tensor = try self.makeBufWithEntry(@constCast(view.data), view.owned != null, name, entry, null, null);
            errdefer freeTensor(self, tensor);
            return self.withLogicalShape(tensor, loaded.tensor.shape);
        }
        if (shouldBorrowEmbeddingTensor(name)) {
            return self.makeBufWithEntry(empty_f32[0..], false, name, entry, null, &loaded.tensor);
        }
        const converted = try convertTensorToOwnedF32(self.allocator, &loaded.tensor);
        const tensor = try self.makeBufWithEntry(converted, true, name, entry, null, null);
        errdefer freeTensor(self, tensor);
        return self.withLogicalShape(tensor, loaded.tensor.shape);
    }

    std.log.debug("MissingWeight: '{s}'", .{name});
    return error.MissingWeight;
}

pub fn quantizedEmbeddingRows(storage: *const QuantizedStorage, dim: usize) !usize {
    if (dim == 0 or storage.shape.len == 0) return error.InvalidTensorShape;
    const cols_i64 = storage.shape[storage.shape.len - 1];
    if (cols_i64 <= 0) return error.InvalidTensorShape;
    const cols: usize = @intCast(cols_i64);
    if (cols != dim) return error.InvalidTensorShape;

    const block_size = gguf_tensor_types.bytesPerBlock(storage.tensor_type) orelse return error.UnsupportedTensorType;
    const values_per_block = gguf_tensor_types.valuesPerBlock(storage.tensor_type) orelse return error.UnsupportedTensorType;
    if (dim % values_per_block != 0) return error.InvalidQuantizedDataSize;
    const row_bytes = (dim / values_per_block) * block_size;
    if (row_bytes == 0 or storage.raw_bytes.len % row_bytes != 0) return error.InvalidQuantizedDataSize;
    const rows_from_bytes = storage.raw_bytes.len / row_bytes;

    var rows_from_shape: usize = 1;
    for (storage.shape[0 .. storage.shape.len - 1]) |axis| {
        if (axis <= 0) return error.InvalidTensorShape;
        rows_from_shape = std.math.mul(usize, rows_from_shape, @intCast(axis)) catch return error.UnsupportedShape;
    }
    if (rows_from_shape != rows_from_bytes) return error.InvalidQuantizedDataSize;
    return rows_from_shape;
}

fn prefetchWeightHint(ctx: *anyopaque, name: []const u8, hint: u32) void {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    if (self.data.resident_weights.contains(name)) return;
    self.data.prefetch.lock();
    defer self.data.prefetch.unlock();
    if (self.data.lazy_weights.getPtr(name)) |entry| {
        if (self.data.shared_prefetch) |shared_prefetch| {
            entry.prefetch_score = shared_prefetch.noteRequest(name, hint) catch entry.prefetch_score;
        } else {
            entry.prefetch_score +|= hint;
        }
        enqueuePrefetchLocked(self.data, entry) catch {};
        self.data.prefetch.signal();
    }
}

fn drainPrefetchBudget(ctx: *anyopaque, max_items: usize) void {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    self.data.prefetch.drainBudget(max_items);
}

fn enqueuePrefetchLocked(data: *WeightStore, entry: *LazyWeightEntry) !void {
    if (entry.pending_prefetch) return;
    entry.pending_prefetch = true;
    try data.prefetch.appendLocked(entry);
}

fn prefetchProcess(ctx: *anyopaque, entry: *LazyWeightEntry) void {
    const data: *WeightStore = @ptrCast(@alignCast(ctx));
    entry.pending_prefetch = false;
    ensureLazyWeightLoadedLocked(data, null, entry) catch {};
    if (data.shared_prefetch) |shared_prefetch| {
        entry.prefetch_score = shared_prefetch.noteComplete(entry.tensor_ref.name) catch 0;
    } else {
        entry.prefetch_score = 0;
    }
}

fn prefetchPriority(entry: *LazyWeightEntry) u64 {
    return entry.prefetch_score;
}

fn ensureLazyWeightLoadedLocked(data: *WeightStore, run_budget: ?*run_memory.RunBudget, entry: *LazyWeightEntry) !void {
    if (entry.expert_coord) |coord| {
        if (data.residency) |*residency| {
            try residency.noteTouch(coord, data.moe_num_experts);
        }
    }
    if (entry.loaded != null) return;
    const tensor_store = data.tensor_store orelse return error.MissingWeight;
    var direct_quant_storage: ?QuantizedStorage = null;
    errdefer if (direct_quant_storage) |*storage| storage.deinit();

    var expected_bytes = if (entry.loaded_bytes != 0) entry.loaded_bytes else entry.tensor_ref.byte_len;
    if (data.allow_direct_quant) {
        direct_quant_storage = try tensor_store.loadQuantizedStorageRef(&entry.tensor_ref);
        if (direct_quant_storage) |*storage| {
            expected_bytes = expectedQuantizedStorageLoadBytes(storage);
        }
    }
    if (entry.expert_coord) |coord| {
        evictColdExpertsLocked(data, coord, .host);
    } else {
        evictColdNonExpertWeightsToFitLocked(data, .host, expected_bytes, entry);
    }
    if (data.tier_cache) |*tier_cache| {
        if (!tier_cache.canFitAdditional(.host, expected_bytes)) {
            if (entry.expert_coord) |coord| {
                evictColdExpertsToFitLocked(data, coord, .host, expected_bytes);
            } else {
                evictColdNonExpertWeightsToFitLocked(data, .host, expected_bytes, entry);
            }
            if (!tier_cache.canFitAdditional(.host, expected_bytes)) {
                tier_cache.noteDenied(.host, expected_bytes);
                noteSharedCacheDenial(run_budget, tier_cache, .host, expected_bytes);
                return error.MemoryBudgetExceeded;
            }
        }
    }

    if (data.allow_direct_quant) {
        if (direct_quant_storage) |*storage_ref| {
            try prepareNativeQuantizedStorageBudgetedLocked(data, run_budget, storage_ref);
            entry.loaded = .{
                .tensor = .{
                    .data = empty_u8[0..],
                    .dtype = .f32,
                    .shape = &.{},
                    .name = entry.tensor_ref.name,
                    .allocator = data.allocator,
                    .owns_data = false,
                    .owns_shape = false,
                },
                .quantized = true,
                .quantized_storage = storage_ref.*,
            };
            direct_quant_storage = null;
            entry.loaded_bytes = quantizedStorageBudgetBytes(&entry.loaded.?.quantized_storage.?);
        } else {
            entry.loaded = try tensor_store.loadTensorRef(&entry.tensor_ref);
            if (entry.loaded.?.quantized_storage) |*storage| {
                storage.deinit();
                entry.loaded.?.quantized_storage = null;
                entry.loaded.?.quantized = false;
            }
            entry.loaded_bytes = entry.loaded.?.tensor.data.len;
        }
    } else {
        entry.loaded = try tensor_store.loadTensorRef(&entry.tensor_ref);
        if (entry.loaded.?.quantized_storage) |*storage| {
            storage.deinit();
            entry.loaded.?.quantized_storage = null;
            entry.loaded.?.quantized = false;
        }
        entry.loaded_bytes = entry.loaded.?.tensor.data.len;
    }
    entry.active_tier = .host;
    if (data.tier_cache) |*tier_cache| {
        tier_cache.noteResident(.host, entry.loaded_bytes);
    }
    if (entry.expert_coord) |coord| {
        if (data.residency) |*residency| {
            try residency.noteLoad(coord, data.moe_num_experts, entry.projection_mask, entry.loaded_bytes);
        }
        evictColdExpertsLocked(data, coord, .host);
    }
}

fn evictColdExpertsLocked(data: *WeightStore, protected: ExpertCoord, tier: ResidencyTier) void {
    while (shouldEvictTierLocked(data, protected.layer_index, tier)) {
        const victim = findEvictionVictimLocked(data, protected, tier) orelse break;
        unloadExpertTierLocked(data, victim, tier);
    }
}

fn evictColdExpertsToFitLocked(data: *WeightStore, protected: ExpertCoord, tier: ResidencyTier, required_bytes: usize) void {
    while (true) {
        const tier_cache = data.tier_cache orelse break;
        if (tier_cache.canFitAdditional(tier, required_bytes)) break;
        const victim = findEvictionVictimLocked(data, protected, tier) orelse break;
        unloadExpertTierLocked(data, victim, tier);
    }
}

fn evictColdNonExpertWeightsToFitLocked(
    data: *WeightStore,
    tier: ResidencyTier,
    required_bytes: usize,
    protected: ?*LazyWeightEntry,
) void {
    while (true) {
        const tier_cache = data.tier_cache orelse break;
        if (tier_cache.canFitAdditional(tier, required_bytes)) break;
        const victim = findNonExpertEvictionVictimLocked(data, tier, protected) orelse break;
        unloadLazyEntryTierLocked(data, victim, tier);
    }
}

fn shouldEvictTierLocked(data: *const WeightStore, layer_index: usize, tier: ResidencyTier) bool {
    if (data.tier_cache) |tier_cache| {
        if (tier_cache.isOverBudget(tier)) return true;
    }
    if (tier == .host) {
        if (data.residency) |residency| {
            return residency.isOverCapacity(layer_index);
        }
    }
    return false;
}

fn findEvictionVictimLocked(data: *WeightStore, protected: ExpertCoord, tier: ResidencyTier) ?ExpertCoord {
    const residency = data.residency;
    var best: ?ExpertCoord = null;

    var it = data.lazy_weights.iterator();
    while (it.next()) |entry| {
        const coord = entry.value_ptr.expert_coord orelse continue;
        if (tier == .backend and coord.layer_index != protected.layer_index) continue;
        if (coord.expert_index == protected.expert_index) continue;
        if (!entryResidentAtTier(entry.value_ptr.*, tier)) continue;
        if (!expertCanEvictLocked(data, coord, tier)) continue;
        if (best == null or (residency != null and residency.?.isMoreEvictable(coord, best.?))) {
            best = coord;
        }
    }
    return best;
}

fn findNonExpertEvictionVictimLocked(
    data: *WeightStore,
    tier: ResidencyTier,
    protected: ?*LazyWeightEntry,
) ?*LazyWeightEntry {
    var best: ?*LazyWeightEntry = null;

    var it = data.lazy_weights.iterator();
    while (it.next()) |entry| {
        const candidate = entry.value_ptr;
        if (candidate.expert_coord != null) continue;
        if (protected != null and candidate == protected.?) continue;
        if (!entryResidentAtTier(candidate.*, tier)) continue;
        if (candidate.pin_count != 0) continue;

        if (best == null or
            candidate.prefetch_score < best.?.prefetch_score or
            (candidate.prefetch_score == best.?.prefetch_score and candidate.loaded_bytes > best.?.loaded_bytes))
        {
            best = candidate;
        }
    }
    return best;
}

fn entryResidentAtTier(entry: LazyWeightEntry, tier: ResidencyTier) bool {
    return switch (tier) {
        .disk => false,
        .host => entry.loaded != null,
        .backend => false,
    };
}

fn expertCanEvictLocked(data: *const WeightStore, coord: ExpertCoord, tier: ResidencyTier) bool {
    var has_loaded_projection = false;
    var it = data.lazy_weights.iterator();
    while (it.next()) |entry| {
        const entry_coord = entry.value_ptr.expert_coord orelse continue;
        if (entry_coord.layer_index != coord.layer_index or entry_coord.expert_index != coord.expert_index) continue;
        if (!entryResidentAtTier(entry.value_ptr.*, tier)) continue;
        has_loaded_projection = true;
        if (entry.value_ptr.pin_count != 0) return false;
    }
    return has_loaded_projection;
}

fn unloadExpertTierLocked(data: *WeightStore, coord: ExpertCoord, tier: ResidencyTier) void {
    var it = data.lazy_weights.iterator();
    while (it.next()) |entry| {
        const entry_coord = entry.value_ptr.expert_coord orelse continue;
        if (entry_coord.layer_index != coord.layer_index or entry_coord.expert_index != coord.expert_index) continue;
        switch (tier) {
            .host => if (entry.value_ptr.loaded) |*loaded| {
                loaded.deinit();
                entry.value_ptr.loaded = null;
                entry.value_ptr.active_tier = entry.value_ptr.placement.spill_tier;
                if (data.tier_cache) |*tier_cache| {
                    tier_cache.noteRelease(.host, entry.value_ptr.loaded_bytes);
                }
                if (data.residency) |*residency| {
                    residency.noteUnload(coord, entry.value_ptr.projection_mask, entry.value_ptr.loaded_bytes);
                }
            },
            else => {},
        }
    }
}

fn unloadLazyEntryTierLocked(data: *WeightStore, entry: *LazyWeightEntry, tier: ResidencyTier) void {
    switch (tier) {
        .host => if (entry.loaded) |*loaded| {
            loaded.deinit();
            entry.loaded = null;
            entry.active_tier = entry.placement.spill_tier;
            if (data.tier_cache) |*tier_cache| {
                tier_cache.noteRelease(.host, entry.loaded_bytes);
            }
        },
        else => {},
    }
}

fn freeLazyWeights(data: *WeightStore, allocator: std.mem.Allocator) void {
    var lazy_it = data.lazy_weights.iterator();
    while (lazy_it.next()) |entry| {
        if (entry.value_ptr.loaded) |*loaded| {
            loaded.deinit();
            if (data.tier_cache) |*tier_cache| {
                tier_cache.noteRelease(.host, entry.value_ptr.loaded_bytes);
            }
        }
        entry.value_ptr.tensor_ref.deinit(allocator);
        allocator.free(entry.key_ptr.*);
    }
}

fn embeddingLookup(ctx: *anyopaque, weight: CT, ids: []const i64, total: usize, dim: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const out_len = std.math.mul(usize, total, dim) catch return error.UnsupportedShape;
    const out = try self.allocator.alloc(f32, out_len);
    errdefer self.allocator.free(out);
    const weight_buf = toBuf(weight);
    if (weight_buf.quantized_storage) |storage| {
        const rows = try quantizedEmbeddingRows(storage, dim);
        for (0..total) |i| {
            if (ids[i] < 0) return error.InvalidTensorShape;
            const idx: usize = @intCast(ids[i]);
            if (idx >= rows) return error.InvalidTensorShape;
            try quant_codec.dequantizeRow(storage.tensor_type, storage.raw_bytes, dim, idx, out[i * dim .. (i + 1) * dim]);
        }
    } else if (weight_buf.source_tensor) |tensor| {
        if (tensor.shape.len != 2) return error.InvalidTensorShape;
        if (tensor.shape[0] <= 0 or tensor.shape[1] <= 0) return error.InvalidTensorShape;
        const rows: usize = @intCast(tensor.shape[0]);
        const cols: usize = @intCast(tensor.shape[1]);
        if (cols != dim) return error.InvalidTensorShape;
        switch (tensor.dtype) {
            .f32 => {
                if (tensor.asFloat32IfAligned()) |src| {
                    for (0..total) |i| {
                        if (ids[i] < 0) return error.InvalidTensorShape;
                        const idx: usize = @intCast(ids[i]);
                        if (idx >= rows) return error.InvalidTensorShape;
                        @memcpy(out[i * dim .. (i + 1) * dim], src[idx * dim .. (idx + 1) * dim]);
                    }
                } else {
                    const src_bytes: [*]const u8 = tensor.data.ptr;
                    for (0..total) |i| {
                        if (ids[i] < 0) return error.InvalidTensorShape;
                        const idx: usize = @intCast(ids[i]);
                        if (idx >= rows) return error.InvalidTensorShape;
                        const row_offset = idx * dim * @sizeOf(f32);
                        for (0..dim) |j| {
                            const offset = row_offset + j * @sizeOf(f32);
                            const bits = std.mem.readInt(u32, src_bytes[offset..][0..4], .little);
                            out[i * dim + j] = @bitCast(bits);
                        }
                    }
                }
            },
            .f16 => {
                // Byte-wise reconstruction.  Bench-measured at ~1.0x against
                // a reinterpret-as-[]f16 + @floatCast variant — LLVM already
                // auto-vectorizes this loop into vcvtph2ps / NEON fcvtl
                // widening on hosts that have it, so the safer non-aligned
                // path costs us nothing.
                const src_bytes: [*]const u8 = tensor.data.ptr;
                for (0..total) |i| {
                    if (ids[i] < 0) return error.InvalidTensorShape;
                    const idx: usize = @intCast(ids[i]);
                    if (idx >= rows) return error.InvalidTensorShape;
                    const row_offset = idx * dim * 2;
                    for (0..dim) |j| {
                        const offset = row_offset + j * 2;
                        const half: f16 = @bitCast(std.mem.readInt(u16, src_bytes[offset..][0..2], .little));
                        out[i * dim + j] = @floatCast(half);
                    }
                }
            },
            .bf16 => {
                // bf16 → f32 is a left-shift of the bit pattern by 16.  Hot
                // path for CLIP token embeddings stored in bf16; bench shows
                // ~2.7x over a byte-wise loop on AVX-512 thanks to the
                // packed u16-load + shift-and-store pattern below.  Falls
                // back to the byte-wise path when the source isn't 2-byte
                // aligned (file-mapped tensor data is sometimes only u8
                // aligned), so the @alignCast in the fast branch never
                // triggers UB.
                const src_bytes: [*]const u8 = tensor.data.ptr;
                if (@intFromPtr(src_bytes) % @alignOf(u16) == 0) {
                    const VEC_BF16 = 8;
                    const U32xV = @Vector(VEC_BF16, u32);
                    const F32xV = @Vector(VEC_BF16, f32);
                    const shift_v: U32xV = @splat(16);
                    const src_bf16: [*]const u16 = @ptrCast(@alignCast(src_bytes));
                    for (0..total) |i| {
                        if (ids[i] < 0) return error.InvalidTensorShape;
                        const idx: usize = @intCast(ids[i]);
                        if (idx >= rows) return error.InvalidTensorShape;
                        const src_row = src_bf16[idx * dim ..][0..dim];
                        const dst_row = out[i * dim ..][0..dim];
                        var j: usize = 0;
                        while (j + VEC_BF16 <= dim) : (j += VEC_BF16) {
                            var bits: U32xV = undefined;
                            inline for (0..VEC_BF16) |lane| bits[lane] = src_row[j + lane];
                            const shifted = bits << shift_v;
                            const f: F32xV = @bitCast(shifted);
                            dst_row[j..][0..VEC_BF16].* = f;
                        }
                        while (j < dim) : (j += 1) {
                            const bits: u32 = @as(u32, src_row[j]) << 16;
                            dst_row[j] = @bitCast(bits);
                        }
                    }
                } else {
                    for (0..total) |i| {
                        if (ids[i] < 0) return error.InvalidTensorShape;
                        const idx: usize = @intCast(ids[i]);
                        if (idx >= rows) return error.InvalidTensorShape;
                        const row_offset = idx * dim * 2;
                        for (0..dim) |j| {
                            const offset = row_offset + j * 2;
                            const bits = std.mem.readInt(u16, src_bytes[offset..][0..2], .little);
                            out[i * dim + j] = @bitCast(@as(u32, bits) << 16);
                        }
                    }
                }
            },
            else => return error.UnsupportedTensorType,
        }
    } else {
        const emb_table = getData(weight);
        if (dim == 0 or emb_table.len % dim != 0) return error.InvalidTensorShape;
        const rows = emb_table.len / dim;
        for (0..total) |i| {
            if (ids[i] < 0) return error.InvalidTensorShape;
            const idx: usize = @intCast(ids[i]);
            if (idx >= rows) return error.InvalidTensorShape;
            @memcpy(out[i * dim .. (i + 1) * dim], emb_table[idx * dim .. (idx + 1) * dim]);
        }
    }
    return self.makeBuf(out, true);
}

const QuantLinearKind = enum {
    single_no_bias,
    single_bias,
    pair_no_bias,
    pair_bias,
    triple_bias,
};

const QuantLinearRequest = struct {
    compute: *NativeCompute,
    kind: QuantLinearKind,
    input: []const f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    storage_a: *const QuantizedStorage,
    storage_b: ?*const QuantizedStorage = null,
    storage_c: ?*const QuantizedStorage = null,
    name_a: []const u8 = "",
    name_b: []const u8 = "",
    name_c: []const u8 = "",
    bias_a: ?[]const f32 = null,
    bias_b: ?[]const f32 = null,
    bias_c: ?[]const f32 = null,
    output_a: []f32,
    output_b: ?[]f32 = null,
    output_c: ?[]f32 = null,
    weight_buf_a: ?*const Buf = null,
    weight_buf_b: ?*const Buf = null,
    weight_buf_c: ?*const Buf = null,
    plan: ?ops.OperatorPlan = null,
};

fn validateQuantLinearPlan(plan: ops.OperatorPlan, storage: *const QuantizedStorage, rows: usize, in_dim: usize, out_dim: usize) !void {
    switch (plan) {
        .quant_matmul => |q| {
            if (q.operator == .fallback or q.rows != rows or q.in_dim != in_dim or q.out_dim != out_dim) {
                return error.InvalidPartitionPlan;
            }
            const expected = backend_contracts.quantFormatFromGgufTensorType(storage.tensor_type) orelse return error.InvalidPartitionPlan;
            if (q.format != expected) return error.InvalidPartitionPlan;
        },
        else => return error.InvalidPartitionPlan,
    }
}

fn dispatchQuantizedLinear(request: QuantLinearRequest) !bool {
    if (request.plan) |plan| {
        try validateQuantLinearPlan(plan, request.storage_a, request.rows, request.in_dim, request.out_dim);
    }
    const self = request.compute;
    switch (request.kind) {
        .single_no_bias => {
            if (shouldUseQuantizedDequantSgemm(request.name_a, request.rows, request.out_dim, request.storage_a)) {
                if (try tryLinearQuantizedDequantSgemmNoBias(self, request.storage_a, request.name_a, request.input, request.output_a, request.rows, request.in_dim, request.out_dim)) return true;
            }
            if (try linearNoBiasQuantized(self.io, request.storage_a, request.input, request.output_a, request.rows, request.in_dim, request.out_dim)) return true;
            return false;
        },
        .single_bias => {
            const bias = request.bias_a orelse return false;
            if (shouldUseQuantizedDequantSgemm(request.name_a, request.rows, request.out_dim, request.storage_a)) {
                if (try tryLinearQuantizedDequantSgemm(self, request.storage_a, request.name_a, request.input, bias, request.output_a, request.rows, request.in_dim, request.out_dim)) return true;
            }
            if (q4q5FusedSingleBiasEnabled()) {
                if (try linearQ4Q5KPreparedQ8KActivationWithBias(self.io, request.storage_a, request.input, bias, request.output_a, request.rows, request.in_dim, request.out_dim)) return true;
            }
            if (try linearNoBiasQuantized(self.io, request.storage_a, request.input, request.output_a, request.rows, request.in_dim, request.out_dim)) {
                addLinearBiasRows(request.output_a, bias, request.rows, request.out_dim);
                return true;
            }
            return false;
        },
        .pair_no_bias => {
            const storage_b = request.storage_b orelse return false;
            const output_b = request.output_b orelse return false;
            if (try linearNoBiasQuantizedPair(self.io, self.allocator, request.storage_a, storage_b, request.input, request.output_a, output_b, request.rows, request.in_dim, request.out_dim)) return true;
            return false;
        },
        .pair_bias => {
            const storage_b = request.storage_b orelse return false;
            const output_b = request.output_b orelse return false;
            const bias_a = request.bias_a orelse return false;
            const bias_b = request.bias_b orelse return false;
            if (shouldUseQuantizedDequantSgemm(request.name_a, request.rows, request.out_dim, request.storage_a) and
                shouldUseQuantizedDequantSgemm(request.name_b, request.rows, request.out_dim, storage_b))
            {
                if (try tryLinearQuantizedDequantSgemmPair(self, request.storage_a, request.name_a, bias_a, storage_b, request.name_b, bias_b, request.input, request.output_a, output_b, request.rows, request.in_dim, request.out_dim)) return true;
            }
            if (request.storage_a.tensor_type.eql(.{ .known = .Q8_0 }) and
                storage_b.tensor_type.eql(.{ .known = .Q8_0 }) and
                request.storage_a.packed_expert == null and
                storage_b.packed_expert == null and
                request.storage_a.shape.len == 2 and
                storage_b.shape.len == 2 and
                request.storage_a.shape[0] == request.out_dim and
                request.storage_a.shape[1] == request.in_dim and
                storage_b.shape[0] == request.out_dim and
                storage_b.shape[1] == request.in_dim)
            {
                try linearQ8_0Pair(self.allocator, self.io, request.input, request.storage_a.raw_bytes, storage_b.raw_bytes, request.storage_a.preparedBytes(.row_major_blocks), storage_b.preparedBytes(.row_major_blocks), request.storage_a.preparedBytes(.panel4), storage_b.preparedBytes(.panel4), request.storage_a.preparedBytes(.panel8), storage_b.preparedBytes(.panel8), bias_a, bias_b, request.output_a, output_b, request.rows, request.in_dim, request.out_dim);
                return true;
            }
            if (try linearNoBiasQuantizedPair(self.io, self.allocator, request.storage_a, storage_b, request.input, request.output_a, output_b, request.rows, request.in_dim, request.out_dim)) {
                addLinearBiasRows(request.output_a, bias_a, request.rows, request.out_dim);
                addLinearBiasRows(output_b, bias_b, request.rows, request.out_dim);
                return true;
            }
            return false;
        },
        .triple_bias => {
            const storage_b = request.storage_b orelse return false;
            const storage_c = request.storage_c orelse return false;
            const output_b = request.output_b orelse return false;
            const output_c = request.output_c orelse return false;
            const bias_a = request.bias_a orelse return false;
            const bias_b = request.bias_b orelse return false;
            const bias_c = request.bias_c orelse return false;
            if (shouldUseQuantizedDequantSgemm(request.name_a, request.rows, request.out_dim, request.storage_a) and
                shouldUseQuantizedDequantSgemm(request.name_b, request.rows, request.out_dim, storage_b) and
                shouldUseQuantizedDequantSgemm(request.name_c, request.rows, request.out_dim, storage_c))
            {
                if (try tryLinearQuantizedDequantSgemmTriple(self, request.storage_a, request.name_a, bias_a, storage_b, request.name_b, bias_b, storage_c, request.name_c, bias_c, request.input, request.output_a, output_b, output_c, request.rows, request.in_dim, request.out_dim)) return true;
            }
            if (request.weight_buf_a) |weight_buf_a| {
                if (request.weight_buf_b) |weight_buf_b| {
                    if (request.weight_buf_c) |weight_buf_c| {
                        try ensureQ4Q5QKVPanel16Cache(self, weight_buf_a, weight_buf_b, weight_buf_c, request.storage_a, storage_b, storage_c, request.in_dim, request.out_dim, request.rows);
                    }
                }
            }
            if (try linearQuantizedTriple(self.io, request.storage_a, storage_b, storage_c, request.input, bias_a, bias_b, bias_c, request.output_a, output_b, output_c, request.rows, request.in_dim, request.out_dim)) return true;
            return false;
        },
    }
}

fn linearOp(ctx: *anyopaque, input: CT, weight: CT, bias: CT, rows: usize, in_dim: usize, out_dim: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const output = try self.allocator.alloc(f32, rows * out_dim);
    errdefer self.allocator.free(output);
    const weight_buf = toBuf(weight);

    if (weight_buf.quantized_storage) |storage| {
        if (try dispatchQuantizedLinear(.{
            .compute = self,
            .kind = .single_bias,
            .input = getData(input),
            .rows = rows,
            .in_dim = in_dim,
            .out_dim = out_dim,
            .storage_a = storage,
            .name_a = weight_buf.name,
            .bias_a = getData(bias),
            .output_a = output,
        })) {
            return self.makeBuf(output, true);
        }
        if (getData(weight).len == 0) {
            std.log.err(
                "quantized linear fallback unavailable for {s}: shape={any} rows={d} in_dim={d} out_dim={d} tensor_type={any}",
                .{ weight_buf.name, storage.shape, rows, in_dim, out_dim, storage.tensor_type },
            );
            return error.UnsupportedTensorType;
        }
    }

    const bias_data = getData(bias);
    for (0..rows) |r| {
        @memcpy(output[r * out_dim .. (r + 1) * out_dim], bias_data[0..out_dim]);
    }

    if (weight_buf.source_tensor) |tensor| {
        try linearNoBiasSourceTensorChunked(self, getData(input), tensor, output, rows, in_dim, out_dim);
    } else if (weight_buf.lazy_entry) |entry| {
        if (weight_buf.data.len == 0 and canFallbackDenseBudgetPressure(weight_buf.name, entry)) {
            try linearNoBiasLazyEntryChunked(self, getData(input), entry, output, rows, in_dim, out_dim);
        } else {
            const weight_view = try denseWeightView(self, weight);
            defer if (weight_view.owned) |owned| self.allocator.free(owned);
            try self.dispatchSgemmTransB(rows, out_dim, in_dim, 1.0, getData(input), weight_view.data, 1.0, output);
        }
    } else {
        const weight_view = try denseWeightView(self, weight);
        defer if (weight_view.owned) |owned| self.allocator.free(owned);
        try self.dispatchSgemmTransB(rows, out_dim, in_dim, 1.0, getData(input), weight_view.data, 1.0, output);
    }
    const result = try self.makeBuf(output, true);
    return self.withLogicalShape(result, &.{ @intCast(rows), @intCast(out_dim) });
}

fn addLinearBiasRows(output: []f32, bias: []const f32, rows: usize, out_dim: usize) void {
    const bias_row = bias[0..out_dim];
    for (0..rows) |r| {
        const out_row = output[r * out_dim ..][0..out_dim];
        for (out_row, bias_row) |*value, bias_value| value.* += bias_value;
    }
}

const DenseDequantForSgemm = struct {
    data: []const f32,
    owned: ?[]f32 = null,

    fn deinit(self: *DenseDequantForSgemm, allocator: std.mem.Allocator) void {
        if (self.owned) |owned| allocator.free(owned);
        self.* = .{ .data = &.{} };
    }
};

fn denseDequantForSgemm(
    self: *NativeCompute,
    storage: *const QuantizedStorage,
    name: []const u8,
    in_dim: usize,
    out_dim: usize,
) !?DenseDequantForSgemm {
    if (storage.shape.len != 2 or storage.shape[0] != out_dim or storage.shape[1] != in_dim) return error.InvalidQuantizedLinearShape;
    if (try cachedQuantDequantDenseWeight(self, name, storage, in_dim, out_dim)) |cached| {
        return .{ .data = cached };
    }
    if (!quantDequantSgemmScratchEnabled()) {
        self.data.quant_dequant_cache_scratch_denied += 1;
        return null;
    }

    const scratch = try self.allocator.alloc(f32, out_dim * in_dim);
    errdefer self.allocator.free(scratch);
    try quant_codec.dequantizeToFloat32(storage.tensor_type, storage.raw_bytes, scratch);
    self.data.quant_dequant_cache_scratch_fallbacks += 1;
    return .{ .data = scratch, .owned = scratch };
}

fn tryLinearQuantizedDequantSgemm(
    self: *NativeCompute,
    storage: *const QuantizedStorage,
    name: []const u8,
    input: []const f32,
    bias: []const f32,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !bool {
    const dequant_start = nativeQuantPhaseStart();
    var dense_weight = (try denseDequantForSgemm(self, storage, name, in_dim, out_dim)) orelse return false;
    defer dense_weight.deinit(self.allocator);
    noteNativeQuantDispatch(.dequant_sgemm);
    noteNativeQuantPhase(.dequant_fetch, dequant_start);

    const bias_row = bias[0..out_dim];
    for (0..rows) |row| {
        @memcpy(output[row * out_dim ..][0..out_dim], bias_row);
    }
    const sgemm_start = nativeQuantPhaseStart();
    try self.dispatchSgemmTransB(rows, out_dim, in_dim, 1.0, input, dense_weight.data, 1.0, output);
    noteNativeQuantPhase(.dequant_sgemm_compute, sgemm_start);
    return true;
}

fn tryLinearQuantizedDequantSgemmNoBias(
    self: *NativeCompute,
    storage: *const QuantizedStorage,
    name: []const u8,
