    noteNativeQuantPhase(.dequant_sgemm_compute, sgemm_start);
    return true;
}

fn tryLinearQuantizedDequantSgemmTriple(
    self: *NativeCompute,
    storage_a: *const QuantizedStorage,
    name_a: []const u8,
    bias_a: []const f32,
    storage_b: *const QuantizedStorage,
    name_b: []const u8,
    bias_b: []const f32,
    storage_c: *const QuantizedStorage,
    name_c: []const u8,
    bias_c: []const f32,
    input: []const f32,
    output_a: []f32,
    output_b: []f32,
    output_c: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !bool {
    const dequant_start = nativeQuantPhaseStart();
    var dense_a = (try denseDequantForSgemm(self, storage_a, name_a, in_dim, out_dim)) orelse return false;
    defer dense_a.deinit(self.allocator);
    var dense_b = (try denseDequantForSgemm(self, storage_b, name_b, in_dim, out_dim)) orelse return false;
    defer dense_b.deinit(self.allocator);
    var dense_c = (try denseDequantForSgemm(self, storage_c, name_c, in_dim, out_dim)) orelse return false;
    defer dense_c.deinit(self.allocator);
    noteNativeQuantDispatch(.dequant_sgemm_triple);
    noteNativeQuantPhase(.dequant_fetch, dequant_start);

    for (0..rows) |row| {
        @memcpy(output_a[row * out_dim ..][0..out_dim], bias_a[0..out_dim]);
        @memcpy(output_b[row * out_dim ..][0..out_dim], bias_b[0..out_dim]);
        @memcpy(output_c[row * out_dim ..][0..out_dim], bias_c[0..out_dim]);
    }
    const sgemm_start = nativeQuantPhaseStart();
    try self.dispatchSgemmTransB(rows, out_dim, in_dim, 1.0, input, dense_a.data, 1.0, output_a);
    try self.dispatchSgemmTransB(rows, out_dim, in_dim, 1.0, input, dense_b.data, 1.0, output_b);
    try self.dispatchSgemmTransB(rows, out_dim, in_dim, 1.0, input, dense_c.data, 1.0, output_c);
    noteNativeQuantPhase(.dequant_sgemm_compute, sgemm_start);
    return true;
}

fn cachedQuantDequantDenseWeight(
    self: *NativeCompute,
    name: []const u8,
    storage: *const QuantizedStorage,
    in_dim: usize,
    out_dim: usize,
) !?[]const f32 {
    const bytes = out_dim * in_dim * @sizeOf(f32);
    const max_bytes = quantDequantDenseCacheMaxBytes();

    while (!self.data.gliner_head_dense_cache_lock.tryLock()) {
        std.Thread.yield() catch {};
    }
    defer self.data.gliner_head_dense_cache_lock.unlock();

    if (!quantDequantDenseCacheEnabled()) {
        self.data.quant_dequant_cache_disabled += 1;
        return null;
    }
    if (bytes == 0 or bytes > max_bytes) {
        self.data.quant_dequant_cache_too_large += 1;
        return null;
    }

    if (self.data.gliner_head_dense_cache.get(name)) |entry| {
        self.data.quant_dequant_cache_hits += 1;
        return entry.data;
    }
    self.data.quant_dequant_cache_misses += 1;

    if (self.data.gliner_head_dense_cache_bytes + bytes > max_bytes) {
        self.data.quant_dequant_cache_capacity_denied += 1;
        return null;
    }
    if (self.data.tier_cache) |*tier_cache| {
        if (!tier_cache.canFitAdditional(.host, bytes)) {
            self.data.quant_dequant_cache_tier_denied += 1;
            tier_cache.noteDenied(.host, bytes);
            noteSharedCacheDenial(self.run_budget, tier_cache, .host, bytes);
            logSharedCacheDenial("quant_dequant_dense_cache", tier_cache, name);
            return null;
        }
    }

    const owned_name = try self.data.allocator.dupe(u8, name);
    errdefer self.data.allocator.free(owned_name);
    const dense_weight = try self.data.allocator.alloc(f32, out_dim * in_dim);
    errdefer self.data.allocator.free(dense_weight);
    try quant_codec.dequantizeToFloat32(storage.tensor_type, storage.raw_bytes, dense_weight);

    try self.data.gliner_head_dense_cache.put(self.data.allocator, owned_name, .{
        .data = dense_weight,
        .bytes = bytes,
    });
    self.data.gliner_head_dense_cache_bytes += bytes;
    self.data.quant_dequant_cache_inserts += 1;
    if (self.data.tier_cache) |*tier_cache| tier_cache.noteResident(.host, bytes);
    return dense_weight;
}

inline fn optionalLinearBiasAt(bias: ?[]const f32, col: usize) f32 {
    return if (bias) |values| values[col] else 0.0;
}

inline fn optionalLinearBiasVec8(bias: ?[]const f32, col: usize) F32x8 {
    return if (bias) |values| values[col..][0..8].* else @splat(0.0);
}

inline fn storeF32x8(dest: []f32, col: usize, values: F32x8) void {
    inline for (0..8) |lane| {
        dest[col + lane] = values[lane];
    }
}

fn linearLoRAOp(
    ctx: *anyopaque,
    input: CT,
    base_weight: CT,
    bias: CT,
    lora_a: CT,
    lora_b: CT,
    alpha: f32,
    rank: usize,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    _ = rank;

    const input_data = getData(input);
    const base_w_data = getData(base_weight);
    const bias_data = getData(bias);
    const lora_a_data = getData(lora_a);
    const lora_b_data = getData(lora_b);

    const lora_rank: usize = if (in_dim == 0) 0 else lora_a_data.len / in_dim;

    // Base linear: Y = input @ W^T + bias.  Same path as `linearOp` (just
    // inlined here so we can add the LoRA residual into the same buffer).
    const output = try self.allocator.alloc(f32, rows * out_dim);
    errdefer self.allocator.free(output);
    for (0..rows) |r| {
        @memcpy(output[r * out_dim .. (r + 1) * out_dim], bias_data[0..out_dim]);
    }
    try self.dispatchSgemmTransB(rows, out_dim, in_dim, 1.0, input_data, base_w_data, 1.0, output);

    // LoRA residual: Y += alpha * (input @ A^T) @ B^T, where A is
    // [lora_rank, in_dim] and B is [out_dim, lora_rank].  The previous
    // implementation materialised a merged [out_dim, in_dim] f32 weight
    // per call (~9MB for DeBERTa-base intermediate.dense and freshly
    // allocated each inference).  Splitting into two small sgemms keeps
    // the math identical, drops the per-call allocation to
    // `rows * lora_rank * 4` bytes (~8KB at typical shapes), and keeps
    // the LoRA tensors L2-resident.
    if (alpha != 0.0 and lora_rank > 0) {
        const intermediate = try self.allocator.alloc(f32, rows * lora_rank);
        defer self.allocator.free(intermediate);
        // intermediate = input @ A^T  (sgemmTransB treats lora_a_data as B
        // with shape [n=lora_rank, k=in_dim] and transposes internally).
        try self.dispatchSgemmTransB(rows, lora_rank, in_dim, 1.0, input_data, lora_a_data, 0.0, intermediate);
        // output += alpha * intermediate @ B^T  (B is [out_dim, lora_rank]).
        try self.dispatchSgemmTransB(rows, out_dim, lora_rank, alpha, intermediate, lora_b_data, 1.0, output);
    }

    const result = try self.makeBuf(output, true);
    return self.withLogicalShape(result, &.{ @intCast(rows), @intCast(out_dim) });
}

fn layerNormOp(ctx: *anyopaque, input: CT, gamma: CT, beta: CT, dim: usize, eps: f32) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const output = try self.allocator.dupe(f32, getData(input));
    activations_mod.layerNorm(output, getData(gamma), getData(beta), dim, eps);
    const result = try self.makeOwnedBuf(output);
    errdefer freeTensor(self, result);
    return propagateLogicalShapeLike(self, result, input);
}

fn layerNormConsumeInputOp(_: *anyopaque, input: CT, gamma: CT, beta: CT, dim: usize, eps: f32) anyerror!?CT {
    const buf = uniqueOwnedDenseBuf(input) orelse return null;
    activations_mod.layerNorm(buf.data, getData(gamma), getData(beta), dim, eps);
    return input;
}

fn geluOp(ctx: *anyopaque, input: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const output = try self.allocator.dupe(f32, getData(input));
    activations_mod.gelu(output);
    const result = try self.makeOwnedBuf(output);
    errdefer freeTensor(self, result);
    return propagateLogicalShapeLike(self, result, input);
}

fn geluNewOp(ctx: *anyopaque, input: CT) anyerror!CT {
    return geluOp(ctx, input);
}

fn applyUnaryConsume(op: ops.UnaryConsumeOp, data: []f32) void {
    switch (op) {
        .gelu => activations_mod.gelu(data),
        .relu => activations_mod.relu(data),
        .silu => activations_mod.silu(data),
        .quick_gelu => activations_mod.quickGelu(data),
        .sigmoid => activations_mod.sigmoid(data),
        .tanh_act, .tanh_prim => {
            for (data) |*v| v.* = std.math.tanh(v.*);
        },
        .negate => {
            var i: usize = 0;
            while (i + VEC_LEN <= data.len) : (i += VEC_LEN) {
                const va: F32xN = data[i..][0..VEC_LEN].*;
                data[i..][0..VEC_LEN].* = -va;
            }
            while (i < data.len) : (i += 1) data[i] = -data[i];
        },
        .sqrt => {
            for (data) |*v| v.* = @sqrt(v.*);
        },
        .rsqrt => {
            for (data) |*v| v.* = 1.0 / @sqrt(v.*);
        },
        .exp => {
            for (data) |*v| v.* = @exp(v.*);
        },
        .log => {
            for (data) |*v| v.* = @log(v.*);
        },
        .sin => {
            for (data) |*v| v.* = @sin(v.*);
        },
        .cos => {
            for (data) |*v| v.* = @cos(v.*);
        },
        .erf => {
            for (data) |*v| v.* = erfApprox(v.*);
        },
        .abs => {
            for (data) |*v| v.* = @abs(v.*);
        },
    }
}

fn unaryConsumeOp(_: *anyopaque, op: ops.UnaryConsumeOp, input: CT) anyerror!?CT {
    const buf = uniqueOwnedDenseBuf(input) orelse return null;
    applyUnaryConsume(op, buf.data);
    return input;
}

fn addOp(ctx: *anyopaque, a: CT, b: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    if (try applyShapeAwareBinaryOp(self, a, b, .add)) |result| {
        return result;
    }
    const a_view = try denseTensorView(self, a);
    defer if (a_view.owned) |owned| self.allocator.free(owned);
    const b_view = try denseTensorView(self, b);
    defer if (b_view.owned) |owned| self.allocator.free(owned);
    const a_data = a_view.data;
    const b_data = b_view.data;
    // Handle implicit broadcasting for primitive add (bias in lowered linear).
    if (a_data.len != b_data.len) {
        const output = try primBinaryBroadcast(self.allocator, a_data, b_data, .add_prim);
        const result = try self.makeOwnedBuf(output);
        errdefer freeTensor(self, result);
        return propagateLogicalShapeFromBinaryOperands(self, result, a, b);
    }
    const output = try self.allocator.alloc(f32, a_data.len);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    var i: usize = 0;
    while (i + VEC_LEN <= a_data.len) : (i += VEC_LEN) {
        const va: F32xN = a_data[i..][0..VEC_LEN].*;
        const vb: F32xN = b_data[i..][0..VEC_LEN].*;
        output[i..][0..VEC_LEN].* = va + vb;
    }
    while (i < a_data.len) : (i += 1) {
        output[i] = a_data[i] + b_data[i];
    }
    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    return propagateLogicalShapeFromBinaryOperands(self, result, a, b);
}

fn addConsumeLeftOp(_: *anyopaque, a: CT, b: CT) anyerror!?CT {
    if (try applyShapeAwareBinaryConsumeLeft(a, b, .add)) |result| return result;
    const a_buf = ownedDenseBufWithMaxSharedRefs(a, 2) orelse return null;
    const a_data = a_buf.data;
    const b_data = getData(b);
    if (a_data.len < b_data.len) return null;
    if (b_data.len == 0 and a_data.len != 0) return error.ShapeMismatch;

    if (a_data.len == b_data.len) {
        var i: usize = 0;
        while (i + VEC_LEN <= a_data.len) : (i += VEC_LEN) {
            const va: F32xN = a_data[i..][0..VEC_LEN].*;
            const vb: F32xN = b_data[i..][0..VEC_LEN].*;
            a_data[i..][0..VEC_LEN].* = va + vb;
        }
        while (i < a_data.len) : (i += 1) a_data[i] += b_data[i];
        return a;
    }

    if (b_data.len == 0) return error.ShapeMismatch;
    for (0..a_data.len) |i| {
        a_data[i] += b_data[i % b_data.len];
    }
    return a;
}

fn addConsumeRightOp(_: *anyopaque, a: CT, b: CT) anyerror!?CT {
    if (try applyShapeAwareBinaryConsumeLeft(b, a, .add)) |result| return result;
    const b_buf = ownedDenseBufWithMaxSharedRefs(b, 2) orelse return null;
    const a_data = getData(a);
    const b_data = b_buf.data;
    if (b_data.len < a_data.len) return null;
    if (a_data.len == 0 and b_data.len != 0) return error.ShapeMismatch;

    if (b_data.len == a_data.len) {
        var i: usize = 0;
        while (i + VEC_LEN <= b_data.len) : (i += VEC_LEN) {
            const va: F32xN = a_data[i..][0..VEC_LEN].*;
            const vb: F32xN = b_data[i..][0..VEC_LEN].*;
            b_data[i..][0..VEC_LEN].* = va + vb;
        }
        while (i < b_data.len) : (i += 1) b_data[i] += a_data[i];
        return b;
    }

    if (a_data.len == 0) return error.ShapeMismatch;
    for (0..b_data.len) |i| {
        b_data[i] += a_data[i % a_data.len];
    }
    return b;
}

fn multiplyConsumeLeftOp(_: *anyopaque, a: CT, b: CT) anyerror!?CT {
    if (try applyShapeAwareBinaryConsumeLeft(a, b, .mul)) |result| return result;
    const a_buf = ownedDenseBufWithMaxSharedRefs(a, 2) orelse return null;
    const a_data = a_buf.data;
    const b_data = getData(b);
    if (a_data.len < b_data.len) return null;
    if (b_data.len == 0 and a_data.len != 0) return error.ShapeMismatch;

    if (a_data.len == b_data.len) {
        var i: usize = 0;
        while (i + VEC_LEN <= a_data.len) : (i += VEC_LEN) {
            const va: F32xN = a_data[i..][0..VEC_LEN].*;
            const vb: F32xN = b_data[i..][0..VEC_LEN].*;
            a_data[i..][0..VEC_LEN].* = va * vb;
        }
        while (i < a_data.len) : (i += 1) a_data[i] *= b_data[i];
        return a;
    }

    if (b_data.len == 0) return error.ShapeMismatch;
    for (0..a_data.len) |i| {
        a_data[i] *= b_data[i % b_data.len];
    }
    return a;
}

fn multiplyConsumeRightOp(_: *anyopaque, a: CT, b: CT) anyerror!?CT {
    if (try applyShapeAwareBinaryConsumeLeft(b, a, .mul)) |result| return result;
    const b_buf = ownedDenseBufWithMaxSharedRefs(b, 2) orelse return null;
    const a_data = getData(a);
    const b_data = b_buf.data;
    if (b_data.len < a_data.len) return null;
    if (a_data.len == 0 and b_data.len != 0) return error.ShapeMismatch;

    if (b_data.len == a_data.len) {
        var i: usize = 0;
        while (i + VEC_LEN <= b_data.len) : (i += VEC_LEN) {
            const va: F32xN = a_data[i..][0..VEC_LEN].*;
            const vb: F32xN = b_data[i..][0..VEC_LEN].*;
            b_data[i..][0..VEC_LEN].* = va * vb;
        }
        while (i < b_data.len) : (i += 1) b_data[i] *= a_data[i];
        return b;
    }

    if (a_data.len == 0) return error.ShapeMismatch;
    for (0..b_data.len) |i| {
        b_data[i] *= a_data[i % a_data.len];
    }
    return b;
}

fn subtractConsumeLeftOp(_: *anyopaque, a: CT, b: CT) anyerror!?CT {
    if (try applyShapeAwareBinaryConsumeLeft(a, b, .sub)) |result| return result;
    const a_buf = ownedDenseBufWithMaxSharedRefs(a, 2) orelse return null;
    const a_data = a_buf.data;
    const b_data = getData(b);
    if (a_data.len < b_data.len) return null;
    if (b_data.len == 0 and a_data.len != 0) return error.ShapeMismatch;

    if (a_data.len == b_data.len) {
        var i: usize = 0;
        while (i + VEC_LEN <= a_data.len) : (i += VEC_LEN) {
            const va: F32xN = a_data[i..][0..VEC_LEN].*;
            const vb: F32xN = b_data[i..][0..VEC_LEN].*;
            a_data[i..][0..VEC_LEN].* = va - vb;
        }
        while (i < a_data.len) : (i += 1) a_data[i] -= b_data[i];
        return a;
    }

    if (b_data.len == 0) return error.ShapeMismatch;
    for (0..a_data.len) |i| {
        a_data[i] -= b_data[i % b_data.len];
    }
    return a;
}

fn divideConsumeLeftOp(_: *anyopaque, a: CT, b: CT) anyerror!?CT {
    if (try applyShapeAwareBinaryConsumeLeft(a, b, .div)) |result| return result;
    const a_buf = ownedDenseBufWithMaxSharedRefs(a, 2) orelse return null;
    const a_data = a_buf.data;
    const b_data = getData(b);
    if (a_data.len < b_data.len) return null;
    if (b_data.len == 0 and a_data.len != 0) return error.ShapeMismatch;

    if (a_data.len == b_data.len) {
        var i: usize = 0;
        while (i + VEC_LEN <= a_data.len) : (i += VEC_LEN) {
            const va: F32xN = a_data[i..][0..VEC_LEN].*;
            const vb: F32xN = b_data[i..][0..VEC_LEN].*;
            a_data[i..][0..VEC_LEN].* = va / vb;
        }
        while (i < a_data.len) : (i += 1) a_data[i] /= b_data[i];
        return a;
    }

    if (b_data.len == 0) return error.ShapeMismatch;
    for (0..a_data.len) |i| {
        a_data[i] /= b_data[i % b_data.len];
    }
    return a;
}

fn lessThanConsumeLeftOp(_: *anyopaque, a: CT, b: CT) anyerror!?CT {
    if (try applyShapeAwareBinaryConsumeLeft(a, b, .lt)) |result| return result;
    const a_buf = ownedDenseBufWithMaxSharedRefs(a, 2) orelse return null;
    const a_data = a_buf.data;
    const b_data = getData(b);
    if (a_data.len < b_data.len) return null;
    if (b_data.len == 0 and a_data.len != 0) return error.ShapeMismatch;

    if (a_data.len == b_data.len) {
        for (0..a_data.len) |i| {
            a_data[i] = if (a_data[i] < b_data[i]) 1.0 else 0.0;
        }
        return a;
    }

    if (b_data.len == 0) return error.ShapeMismatch;
    for (0..a_data.len) |i| {
        a_data[i] = if (a_data[i] < b_data[i % b_data.len]) 1.0 else 0.0;
    }
    return a;
}

fn canConsumeWhereSelectBranch(
    branch: CT,
    other: CT,
    cond: CT,
    branch_shape: []const i64,
    out_shape: []const i64,
    out_len: usize,
) ?*Buf {
    if (branch == other or branch == cond) return null;
    if (!std.mem.eql(i64, branch_shape, out_shape)) return null;
    // Reshape aliases keep one extra shared reference alive. That is still
    // safe for last-use interpreter consume paths because the sibling handle
    // is freed immediately after this node.
    const branch_buf = ownedDenseBufWithMaxSharedRefs(branch, 2) orelse return null;
    if (branch_buf.data.len != out_len) return null;
    return branch_buf;
}

fn whereSelectConsumeTrueOp(ctx: *anyopaque, cond: CT, on_true: CT, on_false: CT) anyerror!?CT {
    _ = ctx;
    var c_shape_symbolic_buf: [8]i64 = undefined;
    var t_shape_symbolic_buf: [8]i64 = undefined;
    var f_shape_symbolic_buf: [8]i64 = undefined;
    const c_shape_symbolic = symbolicShapeForBroadcast(cond, &c_shape_symbolic_buf);
    const t_shape_symbolic = symbolicShapeForBroadcast(on_true, &t_shape_symbolic_buf);
    const f_shape_symbolic = symbolicShapeForBroadcast(on_false, &f_shape_symbolic_buf);

    var loose_out_shape_buf: [8]i64 = undefined;
    const loose_out_rank = computeBroadcastShape3Loose(c_shape_symbolic, t_shape_symbolic, f_shape_symbolic, &loose_out_shape_buf) orelse return error.ShapeMismatch;
    const loose_out_shape = loose_out_shape_buf[0..loose_out_rank];

    var c_shape_buf: [8]i64 = undefined;
    var t_shape_buf: [8]i64 = undefined;
    var f_shape_buf: [8]i64 = undefined;
    const c_shape = concretizeBroadcastOperandShape(c_shape_symbolic, toBuf(cond).data.len, loose_out_shape, &c_shape_buf);
    const t_shape = concretizeBroadcastOperandShape(t_shape_symbolic, toBuf(on_true).data.len, loose_out_shape, &t_shape_buf);
    const f_shape = concretizeBroadcastOperandShape(f_shape_symbolic, toBuf(on_false).data.len, loose_out_shape, &f_shape_buf);

    var out_shape_buf: [8]i64 = undefined;
    const out_rank = computeBroadcastShape3(c_shape, t_shape, f_shape, &out_shape_buf) orelse return error.ShapeMismatch;
    const out_shape = out_shape_buf[0..out_rank];
    const out_len = if (out_rank == 0) @as(usize, 1) else shapeNumel(out_shape);

    const t_buf = canConsumeWhereSelectBranch(on_true, on_false, cond, t_shape, out_shape, out_len) orelse return null;

    var c_strides_scratch: [8]usize = undefined;
    var f_strides_scratch: [8]usize = undefined;
    const c_plan = denseReadPlanForResolvedShape(cond, c_shape, c_strides_scratch[0..c_shape.len]);
    const f_plan = denseReadPlanForResolvedShape(on_false, f_shape, f_strides_scratch[0..f_shape.len]);
    const c_access = classifyBroadcastReadAccess(c_plan, c_shape, out_shape);
    const f_access = classifyBroadcastReadAccess(f_plan, f_shape, out_shape);
    if (c_access.mode == .general and f_access.mode != .general) {
        if (detectBroadcastBlockRepeatPlan(c_plan, c_shape, out_shape)) |repeat_plan| {
            var out_offset: usize = 0;
            for (0..repeat_plan.prefix_count) |prefix_idx| {
                const cond_base = repeat_plan.base_offset + prefix_idx * repeat_plan.block_len;
                const cond_block = c_plan.data[cond_base .. cond_base + repeat_plan.block_len];
                for (0..repeat_plan.repeat_count) |_| {
                    for (cond_block, 0..) |cond_val, j| {
                        const i = out_offset + j;
                        const f_offset = switch (f_access.mode) {
                            .scalar => f_plan.base_offset,
                            .linear => f_plan.base_offset + i,
                            .general => unreachable,
                        };
                        if (f_offset >= f_plan.data.len) return error.ShapeMismatch;
                        if (cond_val == 0.0) t_buf.data[i] = f_plan.data[f_offset];
                    }
                    out_offset += repeat_plan.block_len;
                }
            }
            if (out_offset != out_len) {
                std.log.warn("where_select repeat loop short write out_offset={d} out_len={d} out_shape={any} cond_shape={any} true_shape={any} false_shape={any}", .{
                    out_offset,
                    out_len,
                    out_shape,
                    c_shape,
                    t_shape,
                    f_shape,
                });
                return error.ShapeMismatch;
            }
            return on_true;
        }
    }
    var c_stepper = if (c_access.mode == .general) BroadcastStepper.init(out_shape, c_shape, c_plan.strides) else null;
    var f_stepper = if (f_access.mode == .general) BroadcastStepper.init(out_shape, f_shape, f_plan.strides) else null;

    for (0..out_len) |i| {
        const c_offset = switch (c_access.mode) {
            .scalar => c_plan.base_offset,
            .linear => c_plan.base_offset + i,
            .general => c_plan.base_offset + c_stepper.?.currentOffset(),
        };
        const f_offset = switch (f_access.mode) {
            .scalar => f_plan.base_offset,
            .linear => f_plan.base_offset + i,
            .general => f_plan.base_offset + f_stepper.?.currentOffset(),
        };
        if (c_offset >= c_plan.data.len or f_offset >= f_plan.data.len) return error.ShapeMismatch;
        if (c_plan.data[c_offset] == 0.0) t_buf.data[i] = f_plan.data[f_offset];
        if (c_stepper) |*stepper| stepper.advance();
        if (f_stepper) |*stepper| stepper.advance();
    }
    return on_true;
}

fn whereSelectConsumeFalseOp(ctx: *anyopaque, cond: CT, on_true: CT, on_false: CT) anyerror!?CT {
    _ = ctx;
    var c_shape_symbolic_buf: [8]i64 = undefined;
    var t_shape_symbolic_buf: [8]i64 = undefined;
    var f_shape_symbolic_buf: [8]i64 = undefined;
    const c_shape_symbolic = symbolicShapeForBroadcast(cond, &c_shape_symbolic_buf);
    const t_shape_symbolic = symbolicShapeForBroadcast(on_true, &t_shape_symbolic_buf);
    const f_shape_symbolic = symbolicShapeForBroadcast(on_false, &f_shape_symbolic_buf);

    var loose_out_shape_buf: [8]i64 = undefined;
    const loose_out_rank = computeBroadcastShape3Loose(c_shape_symbolic, t_shape_symbolic, f_shape_symbolic, &loose_out_shape_buf) orelse return error.ShapeMismatch;
    const loose_out_shape = loose_out_shape_buf[0..loose_out_rank];

    var c_shape_buf: [8]i64 = undefined;
    var t_shape_buf: [8]i64 = undefined;
    var f_shape_buf: [8]i64 = undefined;
    const c_shape = concretizeBroadcastOperandShape(c_shape_symbolic, toBuf(cond).data.len, loose_out_shape, &c_shape_buf);
    const t_shape = concretizeBroadcastOperandShape(t_shape_symbolic, toBuf(on_true).data.len, loose_out_shape, &t_shape_buf);
    const f_shape = concretizeBroadcastOperandShape(f_shape_symbolic, toBuf(on_false).data.len, loose_out_shape, &f_shape_buf);

    var out_shape_buf: [8]i64 = undefined;
    const out_rank = computeBroadcastShape3(c_shape, t_shape, f_shape, &out_shape_buf) orelse return error.ShapeMismatch;
    const out_shape = out_shape_buf[0..out_rank];
    const out_len = if (out_rank == 0) @as(usize, 1) else shapeNumel(out_shape);

    const f_buf = canConsumeWhereSelectBranch(on_false, on_true, cond, f_shape, out_shape, out_len) orelse return null;

    var c_strides_scratch: [8]usize = undefined;
    var t_strides_scratch: [8]usize = undefined;
    const c_plan = denseReadPlanForResolvedShape(cond, c_shape, c_strides_scratch[0..c_shape.len]);
    const t_plan = denseReadPlanForResolvedShape(on_true, t_shape, t_strides_scratch[0..t_shape.len]);
    const c_access = classifyBroadcastReadAccess(c_plan, c_shape, out_shape);
    const t_access = classifyBroadcastReadAccess(t_plan, t_shape, out_shape);
    if (c_access.mode == .general and t_access.mode != .general) {
        if (detectBroadcastBlockRepeatPlan(c_plan, c_shape, out_shape)) |repeat_plan| {
            var out_offset: usize = 0;
            for (0..repeat_plan.prefix_count) |prefix_idx| {
                const cond_base = repeat_plan.base_offset + prefix_idx * repeat_plan.block_len;
                const cond_block = c_plan.data[cond_base .. cond_base + repeat_plan.block_len];
                for (0..repeat_plan.repeat_count) |_| {
                    for (cond_block, 0..) |cond_val, j| {
                        const i = out_offset + j;
                        const t_offset = switch (t_access.mode) {
                            .scalar => t_plan.base_offset,
                            .linear => t_plan.base_offset + i,
                            .general => unreachable,
                        };
                        if (t_offset >= t_plan.data.len) return error.ShapeMismatch;
                        if (cond_val != 0.0) f_buf.data[i] = t_plan.data[t_offset];
                    }
                    out_offset += repeat_plan.block_len;
                }
            }
            if (out_offset != out_len) {
                std.log.warn("where_select cond-repeat short write out_offset={d} out_len={d} out_shape={any} cond_shape={any} true_shape={any} false_shape={any}", .{
                    out_offset,
                    out_len,
                    out_shape,
                    c_shape,
                    t_shape,
                    f_shape,
                });
                return error.ShapeMismatch;
            }
            return on_false;
        }
    }
    var c_stepper = if (c_access.mode == .general) BroadcastStepper.init(out_shape, c_shape, c_plan.strides) else null;
    var t_stepper = if (t_access.mode == .general) BroadcastStepper.init(out_shape, t_shape, t_plan.strides) else null;

    for (0..out_len) |i| {
        const c_offset = switch (c_access.mode) {
            .scalar => c_plan.base_offset,
            .linear => c_plan.base_offset + i,
            .general => c_plan.base_offset + c_stepper.?.currentOffset(),
        };
        const t_offset = switch (t_access.mode) {
            .scalar => t_plan.base_offset,
            .linear => t_plan.base_offset + i,
            .general => t_plan.base_offset + t_stepper.?.currentOffset(),
        };
        if (c_offset >= c_plan.data.len or t_offset >= t_plan.data.len) return error.ShapeMismatch;
        if (c_plan.data[c_offset] != 0.0) f_buf.data[i] = t_plan.data[t_offset];
        if (c_stepper) |*stepper| stepper.advance();
        if (t_stepper) |*stepper| stepper.advance();
    }
    return on_false;
}

fn sdpaOp(ctx: *anyopaque, q_ct: CT, k_ct: CT, v_ct: CT, mask: []const i64, attn_bias_ct: ?CT, batch: usize, seq_len: usize, num_heads: usize, head_dim: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const Q = getData(q_ct);
    const K = getData(k_ct);
    const V = getData(v_ct);
    const bias: ?[]const f32 = if (attn_bias_ct) |b| getData(b) else null;
    var effective_batch = batch;
    var effective_seq_len = seq_len;
    const q_rows = if (head_dim == 0) 0 else Q.len / head_dim;
    if (effective_batch == 0 and num_heads > 0 and mask.len > 0 and q_rows > 0 and q_rows % num_heads == 0) {
        const q_tokens = q_rows / num_heads;
        if (q_tokens % mask.len == 0) {
            effective_batch = q_tokens / mask.len;
        } else {
            effective_batch = 1;
        }
    }
    if (effective_batch == 0) effective_batch = 1;
    if (effective_seq_len == 0 and effective_batch > 0 and mask.len % effective_batch == 0) {
        effective_seq_len = mask.len / effective_batch;
    }
    if (effective_batch > 0 and mask.len >= effective_batch and mask.len % effective_batch == 0) {
        const mask_seq_len = mask.len / effective_batch;
        if (mask_seq_len > 0 and (effective_seq_len == 0 or mask_seq_len < effective_seq_len)) {
            effective_seq_len = mask_seq_len;
        }
    }
    if (effective_seq_len == 0 and effective_batch > 0 and num_heads > 0 and q_rows > 0 and q_rows % (effective_batch * num_heads) == 0) {
        effective_seq_len = q_rows / (effective_batch * num_heads);
    }
    if (effective_batch == 0 or effective_seq_len == 0 or (effective_batch > 0 and effective_seq_len > 0 and mask.len < effective_batch * effective_seq_len)) {
        std.log.warn("sdpa runtime dims batch={d} seq_len={d} mask_len={d} q_rows={d} q_len={d} num_heads={d} head_dim={d} attrs_batch={d} attrs_seq_len={d}", .{
            effective_batch,
            effective_seq_len,
            mask.len,
            q_rows,
            Q.len,
            num_heads,
            head_dim,
            batch,
            seq_len,
        });
    }
    const bias_shared_len = num_heads * effective_seq_len * effective_seq_len;
    const bias_batched_len = effective_batch * bias_shared_len;
    const bh = effective_batch * num_heads;
    const scale: f32 = 1.0 / @sqrt(@as(f32, @floatFromInt(head_dim)));

    // Flash path: tile Q/K/V and run streaming softmax instead of materializing
    // the [seq, seq] score matrix.  Benchmarked to win at every shape tested
    // (1.13x at seq=32, 1.4x at seq=1500), so we apply it broadly.  Bench at
    // scratch/bench_thresholds.zig if you change this threshold.  Floor is
    // seq>=32 to leave room for sequences too short to amortize the
    // streaming-softmax book-keeping (untested below 32).  Disabled when mask
    // is fewer than batch*seq entries because the inputs would need synthetic
    // per-batch masks that the materialized path currently silently
    // broadcasts; safer to keep that case on the legacy path.
    const flash_eligible = effective_seq_len >= 32 and
        mask.len >= effective_batch * effective_seq_len and
        (bias == null or bias.?.len == bias_shared_len or bias.?.len == bias_batched_len);
    if (flash_eligible) {
        const flash_output = try linalg.flashAttentionHost(
            self.allocator,
            Q,
            K,
            V,
            bias,
            mask,
            effective_batch,
            effective_seq_len,
            num_heads,
            head_dim,
        );
        var raw_flash_output: ?[]f32 = flash_output;
        errdefer if (raw_flash_output) |raw| self.allocator.free(raw);
        const result = try self.makeBuf(flash_output, true);
        raw_flash_output = null;
        errdefer freeTensor(self, result);
        if (tensorStoredShape(q_ct)) |shape| {
            if (shape.len == 4) {
                const concrete_shape = [_]i64{ @intCast(effective_batch), @intCast(num_heads), @intCast(effective_seq_len), @intCast(head_dim) };
                return self.withLogicalShape(result, &concrete_shape);
            }
            if (shape.len == 3) {
                const concrete_shape = [_]i64{ @intCast(effective_batch * num_heads), @intCast(effective_seq_len), @intCast(head_dim) };
                return self.withLogicalShape(result, &concrete_shape);
            }
        }
        if (effective_batch > 1 or num_heads > 1) {
            const fallback_shape = [_]i64{ @intCast(effective_batch), @intCast(num_heads), @intCast(effective_seq_len), @intCast(head_dim) };
            return self.withLogicalShape(result, &fallback_shape);
        }
        const fallback_shape = [_]i64{ @intCast(effective_batch * num_heads), @intCast(effective_seq_len), @intCast(head_dim) };
        return self.withLogicalShape(result, &fallback_shape);
    }

    const output = try self.allocator.alloc(f32, bh * effective_seq_len * head_dim);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    @memset(output, 0.0);

    const scores = try self.allocator.alloc(f32, effective_seq_len * effective_seq_len);
    defer self.allocator.free(scores);

    for (0..bh) |bh_idx| {
        const b = bh_idx / num_heads;
        const h = bh_idx % num_heads;
        for (0..effective_seq_len) |qi| {
            const q_ptr = Q[(bh_idx * effective_seq_len + qi) * head_dim ..].ptr;
            for (0..effective_seq_len) |ki| {
                const k_ptr = K[(bh_idx * effective_seq_len + ki) * head_dim ..].ptr;
                scores[qi * effective_seq_len + ki] = linalg.dot(q_ptr[0..head_dim], k_ptr[0..head_dim]) * scale;
            }
        }

        // Add position bias if provided: bias[h, qi, ki]
        if (bias) |b_data| {
            const head_offset = if (b_data.len == bias_batched_len)
                bh_idx * effective_seq_len * effective_seq_len
            else
                h * effective_seq_len * effective_seq_len;
            for (0..effective_seq_len) |qi| {
                for (0..effective_seq_len) |ki| {
                    scores[qi * effective_seq_len + ki] += b_data[head_offset + qi * effective_seq_len + ki];
                }
            }
        }

        for (0..effective_seq_len) |qi| {
            for (0..effective_seq_len) |ki| {
                if (mask[b * effective_seq_len + ki] == 0) {
                    scores[qi * effective_seq_len + ki] = -std.math.inf(f32);
                }
            }
        }

        activations_mod.softmax(scores, effective_seq_len);

        for (0..effective_seq_len) |qi| {
            const out_ptr = output[(bh_idx * effective_seq_len + qi) * head_dim ..].ptr;
            for (0..effective_seq_len) |vi| {
                const w = scores[qi * effective_seq_len + vi];
                if (w == 0.0) continue;
                const v_ptr = V[(bh_idx * effective_seq_len + vi) * head_dim ..].ptr;
                linalg.axpy(w, v_ptr[0..head_dim], out_ptr[0..head_dim]);
            }
        }
    }

    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    if (tensorStoredShape(q_ct)) |shape| {
        if (shape.len == 4) {
            const concrete_shape = [_]i64{ @intCast(effective_batch), @intCast(num_heads), @intCast(effective_seq_len), @intCast(head_dim) };
            return self.withLogicalShape(result, &concrete_shape);
        }
        if (shape.len == 3) {
            const concrete_shape = [_]i64{ @intCast(effective_batch * num_heads), @intCast(effective_seq_len), @intCast(head_dim) };
            return self.withLogicalShape(result, &concrete_shape);
        }
    }
    if (effective_batch > 1 or num_heads > 1) {
        const fallback_shape = [_]i64{ @intCast(effective_batch), @intCast(num_heads), @intCast(effective_seq_len), @intCast(head_dim) };
        return self.withLogicalShape(result, &fallback_shape);
    }
    const fallback_shape = [_]i64{ @intCast(effective_batch * num_heads), @intCast(effective_seq_len), @intCast(head_dim) };
    return self.withLogicalShape(result, &fallback_shape);
}

fn linearNoBiasOp(ctx: *anyopaque, input: CT, weight: CT, rows: usize, in_dim: usize, out_dim: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const output = try self.allocator.alloc(f32, rows * out_dim);
    errdefer self.allocator.free(output);
    @memset(output, 0.0);
    const weight_buf = toBuf(weight);
    if (weight_buf.quantized_storage) |storage| {
        if (try dispatchQuantizedLinear(.{
            .compute = self,
            .kind = .single_no_bias,
            .input = getData(input),
            .rows = rows,
            .in_dim = in_dim,
            .out_dim = out_dim,
            .storage_a = storage,
            .name_a = weight_buf.name,
            .output_a = output,
        })) {
            return makeLinearNoBiasResult(self, output, rows, out_dim);
        }
        if (getData(weight).len == 0) {
            std.log.err(
                "quantized linear-no-bias fallback unavailable for {s}: shape={any} rows={d} in_dim={d} out_dim={d} tensor_type={any}",
                .{ weight_buf.name, storage.shape, rows, in_dim, out_dim, storage.tensor_type },
            );
            return error.UnsupportedTensorType;
        }
    }
    if (weight_buf.source_tensor) |tensor| {
        try linearNoBiasSourceTensorChunked(self, getData(input), tensor, output, rows, in_dim, out_dim);
        return makeLinearNoBiasResult(self, output, rows, out_dim);
    }
    if (weight_buf.lazy_entry) |entry| {
        if (weight_buf.data.len == 0 and canFallbackDenseBudgetPressure(weight_buf.name, entry)) {
            try linearNoBiasLazyEntryChunked(self, getData(input), entry, output, rows, in_dim, out_dim);
            return makeLinearNoBiasResult(self, output, rows, out_dim);
        }
    }
    const weight_view = try denseWeightView(self, weight);
    defer if (weight_view.owned) |owned| self.allocator.free(owned);
    try self.dispatchSgemmTransB(rows, out_dim, in_dim, 1.0, getData(input), weight_view.data, 0.0, output);
    return makeLinearNoBiasResult(self, output, rows, out_dim);
}

fn linearNoBiasPlannedOp(ctx: *anyopaque, request: *const ops.LinearNoBiasPlannedRequest) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const weight_buf = toBuf(request.weight);
    const storage = weight_buf.quantized_storage orelse
        return linearNoBiasOp(ctx, request.input, request.weight, request.rows, request.in_dim, request.out_dim);
    try validateQuantLinearPlan(request.operator_plan, storage, request.rows, request.in_dim, request.out_dim);

    var output_opt: ?[]f32 = try self.allocator.alloc(f32, request.rows * request.out_dim);
    errdefer if (output_opt) |output| self.allocator.free(output);
    const output = output_opt.?;
    @memset(output, 0.0);
    if (try dispatchQuantizedLinear(.{
        .compute = self,
        .kind = .single_no_bias,
        .input = getData(request.input),
        .rows = request.rows,
        .in_dim = request.in_dim,
        .out_dim = request.out_dim,
        .storage_a = storage,
        .name_a = weight_buf.name,
        .output_a = output,
        .plan = request.operator_plan,
    })) {
        const result = try makeLinearNoBiasResult(self, output, request.rows, request.out_dim);
        output_opt = null;
        return result;
    }
    return error.UnsupportedOperation;
}

fn linearPlannedOp(ctx: *anyopaque, request: *const ops.LinearPlannedRequest) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const weight_buf = toBuf(request.weight);
    const storage = weight_buf.quantized_storage orelse
        return linearOp(ctx, request.input, request.weight, request.bias, request.rows, request.in_dim, request.out_dim);
    try validateQuantLinearPlan(request.operator_plan, storage, request.rows, request.in_dim, request.out_dim);

    var output_opt: ?[]f32 = try self.allocator.alloc(f32, request.rows * request.out_dim);
    errdefer if (output_opt) |output| self.allocator.free(output);
    const output = output_opt.?;
    @memset(output, 0.0);
    if (try dispatchQuantizedLinear(.{
        .compute = self,
        .kind = .single_bias,
        .input = getData(request.input),
        .rows = request.rows,
        .in_dim = request.in_dim,
        .out_dim = request.out_dim,
        .storage_a = storage,
        .name_a = weight_buf.name,
        .bias_a = getData(request.bias),
        .output_a = output,
        .plan = request.operator_plan,
    })) {
        const result = try makeLinearNoBiasResult(self, output, request.rows, request.out_dim);
        output_opt = null;
        return result;
    }
    return error.UnsupportedOperation;
}

fn makeLinearNoBiasResult(self: *NativeCompute, output: []f32, rows: usize, out_dim: usize) !CT {
    const result = try self.makeBuf(output, true);
    errdefer freeTensor(self, result);
    const shape = [_]i64{ @intCast(rows), @intCast(out_dim) };
    return self.withLogicalShape(result, &shape);
}

fn linearNoBiasPairOp(
    ctx: *anyopaque,
    input: CT,
    weight_a: CT,
    weight_b: CT,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) anyerror!ops.LinearNoBiasPairResult {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const weight_buf_a = toBuf(weight_a);
    const weight_buf_b = toBuf(weight_b);
    if (weight_buf_a.quantized_storage) |storage_a| {
        if (weight_buf_b.quantized_storage) |storage_b| {
            const first_output = try self.allocator.alloc(f32, rows * out_dim);
            errdefer self.allocator.free(first_output);
            const second_output = try self.allocator.alloc(f32, rows * out_dim);
            errdefer self.allocator.free(second_output);
            if (try dispatchQuantizedLinear(.{
                .compute = self,
                .kind = .pair_no_bias,
                .input = getData(input),
                .rows = rows,
                .in_dim = in_dim,
                .out_dim = out_dim,
                .storage_a = storage_a,
                .storage_b = storage_b,
                .name_a = weight_buf_a.name,
                .name_b = weight_buf_b.name,
                .output_a = first_output,
                .output_b = second_output,
            })) {
                return .{
                    .first = try self.makeBuf(first_output, true),
                    .second = try self.makeBuf(second_output, true),
                };
            }
            self.allocator.free(first_output);
            self.allocator.free(second_output);
        }
    }

    const first = try linearNoBiasOp(ctx, input, weight_a, rows, in_dim, out_dim);
    errdefer freeTensor(ctx, first);
    const second = try linearNoBiasOp(ctx, input, weight_b, rows, in_dim, out_dim);
    return .{ .first = first, .second = second };
}

fn inferMulMatIdExpertAxis(shape: []const i64, expert_count: usize) ?usize {
    if (shape.len != 3) return null;
    if (expert_count != 0) {
        if (shape[2] == @as(i64, @intCast(expert_count))) return 2;
        if (shape[0] == @as(i64, @intCast(expert_count))) return 0;
        if (shape[1] == @as(i64, @intCast(expert_count))) return 1;
    }
    return 2;
}

fn mulMatIdWeightIndex(
    shape: []const i64,
    packed_view: ?QuantizedStorage.PackedExpertView,
    expert_id: usize,
    out_index: usize,
    in_index: usize,
    in_dim: usize,
    out_dim: usize,
) !usize {
    if (shape.len == 2) {
        if (shape[1] != @as(i64, @intCast(in_dim))) return error.UnsupportedShape;
        const rows: usize = @intCast(shape[0]);
        if ((expert_id + 1) * out_dim > rows) return error.InvalidPackedExpertTensor;
        return (expert_id * out_dim + out_index) * in_dim + in_index;
    }
    if (shape.len != 3) return error.UnsupportedShape;

    const expert_count = if (packed_view) |view| @as(usize, view.expert_count) else 0;
    const expert_axis = if (packed_view) |view| @as(usize, view.expert_axis) else inferMulMatIdExpertAxis(shape, expert_count) orelse return error.InvalidPackedExpertTensor;
    if (expert_axis >= shape.len) return error.InvalidPackedExpertTensor;
    if (expert_id >= @as(usize, @intCast(shape[expert_axis]))) return error.InvalidPackedExpertTensor;

    var in_axis: ?usize = null;
    var out_axis: ?usize = null;
    for (0..shape.len) |axis| {
        if (axis == expert_axis) continue;
        const dim: usize = @intCast(shape[axis]);
        if (in_axis == null and dim == in_dim) {
            in_axis = axis;
        } else if (out_axis == null and dim >= out_dim) {
            out_axis = axis;
        }
    }
    if (in_axis == null or out_axis == null) {
        for (0..shape.len) |axis| {
            if (axis == expert_axis) continue;
            if (in_axis == null) {
                const dim: usize = @intCast(shape[axis]);
                if (dim == in_dim) in_axis = axis;
            } else if (out_axis == null and axis != in_axis.?) {
                out_axis = axis;
            }
        }
    }
    const resolved_in_axis = in_axis orelse return error.UnsupportedShape;
    const resolved_out_axis = out_axis orelse return error.UnsupportedShape;

    const logical_out = (if (packed_view) |view| @as(usize, view.row_offset) else 0) + out_index;
    if (logical_out >= @as(usize, @intCast(shape[resolved_out_axis]))) return error.InvalidPackedExpertTensor;

    var strides_buf: [3]usize = undefined;
    computeStrides(shape, strides_buf[0..shape.len]);
    var indices = [_]usize{ 0, 0, 0 };
    indices[expert_axis] = expert_id;
    indices[resolved_in_axis] = in_index;
    indices[resolved_out_axis] = logical_out;
    var flat: usize = 0;
    for (0..shape.len) |axis| flat += indices[axis] * strides_buf[axis];
    return flat;
}

fn dotQuantizedBlock(
    tensor_type: gguf_tensor_types.TensorType,
    input_block: []const f32,
    block: []const u8,
) !f32 {
    return switch (tensor_type) {
        .known => |known| switch (known) {
            .Q4_0 => dotQ4_0Block(input_block, block),
            .Q4_1 => dotQ4_1Block(input_block, block),
            .Q5_0 => dotQ5_0Block(input_block, block),
            .Q5_1 => dotQ5_1Block(input_block, block),
            .Q8_0 => dotQ8_0Block(input_block, block),
            .Q8_1 => dotQ8_1Block(input_block, block),
            .Q2_K => dotQ2_KBlock(input_block, block),
            .Q3_K => dotQ3_KBlock(input_block, block),
            .Q4_K => dotQ4_KBlock(input_block, block),
            .Q5_K => dotQ5_KBlock(input_block, block),
            .Q6_K => dotQ6_KBlock(input_block, block),
            .Q8_K => dotQ8_KBlock(input_block, block),
            .I8_S => dotI8SBlock(input_block, block),
            .IQ4_NL => dotIQ4NLBlock(input_block, block),
            .IQ4_XS => dotIQ4XSBlock(input_block, block),
            else => return error.UnsupportedTensorType,
        },
        .bitnet_tl2 => return error.UnsupportedTensorType,
        .unknown => return error.UnsupportedTensorType,
    };
}

fn mulMatIdQuantizedOp(
    storage: *const QuantizedStorage,
    input: []const f32,
    expert_ids: []const u32,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    if (expert_ids.len != rows) return error.InvalidPackedExpertTensor;
    if (input.len < rows * in_dim or output.len < rows * out_dim) return error.UnexpectedOutputShape;

    const values_per_block = gguf_tensor_types.valuesPerBlock(storage.tensor_type) orelse return error.UnsupportedTensorType;
    const block_size = gguf_tensor_types.bytesPerBlock(storage.tensor_type) orelse return error.UnsupportedTensorType;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;

    const packed_meta = if (storage.packed_expert) |packed_view|
        try packedQuantizedMatrixMeta(storage.shape, packed_view, in_dim, out_dim, storage.tensor_type)
    else
        null;

    if (packed_meta == null) {
        if (storage.shape.len != 2) return error.UnsupportedShape;
        if (storage.shape[1] != @as(i64, @intCast(in_dim))) return error.InvalidQuantizedLinearShape;
    }

    for (0..rows) |r| {
        const input_row = input[r * in_dim ..][0..in_dim];
        const out_row = output[r * out_dim ..][0..out_dim];
        const expert_id = expert_ids[r];
        for (0..out_dim) |o| {
            const row_block_base = if (packed_meta) |meta| blk: {
                const packed_view = storage.packed_expert.?;
                break :blk try quant_codec.packedExpertLinearRowBlockBase(
                    meta.layout,
                    expert_id,
                    o,
                    packed_view.row_offset,
                );
            } else blk: {
                const source_row = @as(usize, @intCast(expert_id)) * out_dim + o;
                if (source_row >= @as(usize, @intCast(storage.shape[0]))) return error.InvalidPackedExpertTensor;
                break :blk source_row * row_blocks;
            };

            var acc: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const block_off = (row_block_base + block_idx) * block_size;
                if (block_off + block_size > storage.raw_bytes.len) return error.InvalidQuantizedDataSize;
                const block = storage.raw_bytes[block_off .. block_off + block_size];
                const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
                acc += try dotQuantizedBlock(storage.tensor_type, input_block, block);
            }
            out_row[o] = acc;
        }
    }
}

fn mulMatIdOp(ctx: *anyopaque, request: *const ops.MulMatIdRequest) anyerror!?CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    if (request.expert_ids.len != request.rows) return error.InvalidPackedExpertTensor;
    const input = getData(request.input);
    if (input.len < request.rows * request.in_dim) return error.UnexpectedOutputShape;

    const weight_buf = toBuf(request.weight);
    if (weight_buf.quantized_storage) |storage| {
        const out = try self.allocator.alloc(f32, request.rows * request.out_dim);
        errdefer self.allocator.free(out);
        try mulMatIdQuantizedOp(
            storage,
            input,
            request.expert_ids,
            out,
            request.rows,
            request.in_dim,
            request.out_dim,
        );
        return try self.makeBuf(out, true);
    }

    const weight_shape = try tensorShapeOp(ctx, request.weight, self.allocator);
    defer self.allocator.free(weight_shape);
    const weight = try toFloat32Op(ctx, request.weight, self.allocator);
    defer self.allocator.free(weight);

    const out = try self.allocator.alloc(f32, request.rows * request.out_dim);
    errdefer self.allocator.free(out);
    for (0..request.rows) |row| {
        const expert_id: usize = request.expert_ids[row];
        for (0..request.out_dim) |out_index| {
            var sum: f32 = 0.0;
            for (0..request.in_dim) |in_index| {
                const weight_index = try mulMatIdWeightIndex(weight_shape, null, expert_id, out_index, in_index, request.in_dim, request.out_dim);
                if (weight_index >= weight.len) return error.UnexpectedOutputShape;
                sum += input[row * request.in_dim + in_index] * weight[weight_index];
            }
            out[row * request.out_dim + out_index] = sum;
        }
    }
    return try self.makeBuf(out, true);
}

fn linearPairOp(
    ctx: *anyopaque,
    input: CT,
    weight_a: CT,
    bias_a: CT,
    weight_b: CT,
    bias_b: CT,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) anyerror!ops.LinearPairResult {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const weight_buf_a = toBuf(weight_a);
    const weight_buf_b = toBuf(weight_b);

    if (weight_buf_a.quantized_storage) |storage_a| {
        if (weight_buf_b.quantized_storage) |storage_b| {
            var first_raw: ?[]f32 = try self.allocator.alloc(f32, rows * out_dim);
            errdefer if (first_raw) |raw| self.allocator.free(raw);
            var second_raw: ?[]f32 = try self.allocator.alloc(f32, rows * out_dim);
            errdefer if (second_raw) |raw| self.allocator.free(raw);

            const used_quant_pair = try dispatchQuantizedLinear(.{
                .compute = self,
                .kind = .pair_bias,
                .input = getData(input),
                .rows = rows,
                .in_dim = in_dim,
                .out_dim = out_dim,
                .storage_a = storage_a,
                .storage_b = storage_b,
                .name_a = weight_buf_a.name,
                .name_b = weight_buf_b.name,
                .bias_a = getData(bias_a),
                .bias_b = getData(bias_b),
                .output_a = first_raw.?,
                .output_b = second_raw.?,
            });

            if (used_quant_pair) {
                const first = try self.makeBuf(first_raw.?, true);
                first_raw = null;
                errdefer freeTensor(ctx, first);
                const second = try self.makeBuf(second_raw.?, true);
                second_raw = null;
                return .{ .first = first, .second = second };
            }

            self.allocator.free(first_raw.?);
            first_raw = null;
            self.allocator.free(second_raw.?);
            second_raw = null;
        }
    }

    const first = try linearOp(ctx, input, weight_a, bias_a, rows, in_dim, out_dim);
    errdefer freeTensor(ctx, first);
    const second = try linearOp(ctx, input, weight_b, bias_b, rows, in_dim, out_dim);
    return .{ .first = first, .second = second };
}

fn linearTripleOp(
    ctx: *anyopaque,
    input: CT,
    weight_a: CT,
    bias_a: CT,
    weight_b: CT,
    bias_b: CT,
    weight_c: CT,
    bias_c: CT,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) anyerror!ops.LinearTripleResult {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const weight_buf_a = toBuf(weight_a);
    const weight_buf_b = toBuf(weight_b);
    const weight_buf_c = toBuf(weight_c);

    if (weight_buf_a.quantized_storage) |storage_a| {
        if (weight_buf_b.quantized_storage) |storage_b| {
            if (weight_buf_c.quantized_storage) |storage_c| {
                var first_raw: ?[]f32 = try self.allocator.alloc(f32, rows * out_dim);
                errdefer if (first_raw) |raw| self.allocator.free(raw);
                var second_raw: ?[]f32 = try self.allocator.alloc(f32, rows * out_dim);
                errdefer if (second_raw) |raw| self.allocator.free(raw);
                var third_raw: ?[]f32 = try self.allocator.alloc(f32, rows * out_dim);
                errdefer if (third_raw) |raw| self.allocator.free(raw);

                const used_quant_triple = try dispatchQuantizedLinear(.{
                    .compute = self,
                    .kind = .triple_bias,
                    .input = getData(input),
                    .rows = rows,
                    .in_dim = in_dim,
                    .out_dim = out_dim,
                    .storage_a = storage_a,
                    .storage_b = storage_b,
                    .storage_c = storage_c,
                    .name_a = weight_buf_a.name,
                    .name_b = weight_buf_b.name,
                    .name_c = weight_buf_c.name,
                    .bias_a = getData(bias_a),
                    .bias_b = getData(bias_b),
                    .bias_c = getData(bias_c),
                    .output_a = first_raw.?,
                    .output_b = second_raw.?,
                    .output_c = third_raw.?,
                    .weight_buf_a = weight_buf_a,
                    .weight_buf_b = weight_buf_b,
                    .weight_buf_c = weight_buf_c,
                });

                if (used_quant_triple) {
                    const first = try self.makeBuf(first_raw.?, true);
                    first_raw = null;
                    errdefer freeTensor(ctx, first);
                    const second = try self.makeBuf(second_raw.?, true);
                    second_raw = null;
                    errdefer freeTensor(ctx, second);
                    const third = try self.makeBuf(third_raw.?, true);
                    third_raw = null;
                    return .{ .first = first, .second = second, .third = third };
                }

                self.allocator.free(first_raw.?);
                first_raw = null;
                self.allocator.free(second_raw.?);
                second_raw = null;
                self.allocator.free(third_raw.?);
                third_raw = null;
            }
        }
    }

    const first = try linearOp(ctx, input, weight_a, bias_a, rows, in_dim, out_dim);
    errdefer freeTensor(ctx, first);
    const second = try linearOp(ctx, input, weight_b, bias_b, rows, in_dim, out_dim);
    errdefer freeTensor(ctx, second);
    const third = try linearOp(ctx, input, weight_c, bias_c, rows, in_dim, out_dim);
    return .{ .first = first, .second = second, .third = third };
}

pub fn linearNoBiasQuantized(
    io: ?std.Io,
    storage: *const QuantizedStorage,
    input: []const f32,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !bool {
    if (storage.tensor_type.eql(.{ .known = .Q4_K }) or
        storage.tensor_type.eql(.{ .known = .Q5_K }) or
        storage.tensor_type.eql(.{ .known = .Q6_K }))
    {
        if (storage.tensor_type.eql(.{ .known = .Q6_K }) and storage.packed_expert == null) {
            const values_per_block = gguf_tensor_types.valuesPerBlock(storage.tensor_type).?;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (storage.shape.len == 2 and
                storage.shape[0] == out_dim and
                storage.shape[1] == in_dim and
                shouldUseQ6_KQ8KActivationQuant(rows, out_dim, row_blocks) and
                storage.preparedBytes(.row_major_blocks) != null)
            {
                const panel16_blocks = if (q6KPanel16SingleEnabledForShape(rows, out_dim, row_blocks)) storage.preparedBytes(.panel16) else null;
                try linearNoBiasQ6KPreparedQ8KActivation(storage.allocator, io, input, storage.preparedBytes(.row_major_blocks).?, storage.preparedBytes(.panel4), storage.preparedBytes(.panel8), panel16_blocks, output, rows, in_dim, out_dim);
                return true;
            }
        }
        if ((storage.tensor_type.eql(.{ .known = .Q4_K }) or storage.tensor_type.eql(.{ .known = .Q5_K })) and storage.packed_expert == null) {
            const values_per_block = gguf_tensor_types.valuesPerBlock(storage.tensor_type).?;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (storage.shape.len == 2 and
                storage.shape[0] == out_dim and
                storage.shape[1] == in_dim and
                shouldUseQ4_Q5_KQ8KActivationQuant(rows, out_dim, row_blocks) and
                storage.preparedBytes(.row_major_blocks) != null)
            {
                try linearNoBiasQ4Q5KPreparedQ8KActivation(storage.allocator, io, input, storage.preparedBytes(.row_major_blocks).?, storage.preparedBytes(.panel4), storage.preparedBytes(.panel8), storage.preparedBytes(.panel16), null, output, rows, in_dim, out_dim, switch (storage.tensor_type) {
                    .known => |known| known,
                    else => unreachable,
                });
                noteNativeQuantDispatch(.q4_q5_k_q8k_activation);
                return true;
            }
        }
        if (storage.preparedBytes(.row_major_blocks)) |prepared_headers| {
            if (storage.packed_expert) |packed_view| {
                if (storage.tensor_type.eql(.{ .known = .Q4_K })) {
                    try linearNoBiasPackedQ4KPrepared(input, storage, packed_view, prepared_headers, output, rows, in_dim, out_dim);
                    return true;
                }
            } else {
                if (storage.shape.len != 2) return false;
                if (storage.shape[0] != out_dim or storage.shape[1] != in_dim) return false;
                if (storage.tensor_type.eql(.{ .known = .Q6_K })) {
                    try linearNoBiasQ6KPrepared(io, input, prepared_headers, output, rows, in_dim, out_dim);
                } else {
                    if (storage.preparedBytes(.panel4)) |panel_blocks| {
                        try linearNoBiasQ4Q5KPreparedPanel(input, prepared_headers, panel_blocks, output, rows, in_dim, out_dim);
                        noteNativeQuantDispatch(.q4_q5_k_prepared_panel);
                        return true;
                    }
                    try linearNoBiasQ4KPrepared(io, input, prepared_headers, output, rows, in_dim, out_dim);
                }
                return true;
            }
        }
    }

    switch (storage.tensor_type) {
        .known => |known| if (known == .Q1_0) {
            if (storage.packed_expert != null) return false;
            if (storage.shape.len != 2) return false;
            if (storage.shape[0] != out_dim or storage.shape[1] != in_dim) return false;
            const values_per_block: usize = 128;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const input_blocks = in_dim / 32;
            if (shouldUseQ8_0ActivationQuant(rows, out_dim, input_blocks)) {
                if (storage.preparedBytes(.row_major_blocks)) |prepared_blocks| {
                    try linearNoBiasQ1_0PreparedActivation(storage.allocator, io, input, prepared_blocks, storage.preparedBytes(.panel4), output, rows, in_dim, out_dim);
                    return true;
                }
            }
        },
        else => {},
    }

    switch (storage.tensor_type) {
        .known => |known| if (known == .Q2_K or known == .Q3_K) {
            if (storage.packed_expert != null) return false;
            if (storage.shape.len != 2) return false;
            if (storage.shape[0] != out_dim or storage.shape[1] != in_dim) return false;
            const values_per_block: usize = 256;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (shouldUseQ4_Q5_KQ8KActivationQuant(rows, out_dim, row_blocks)) {
                if (known == .Q3_K and q3KNoDmnPanelSingleEnabledForShape(rows, out_dim, row_blocks)) {
                    if (storage.preparedBytes(.row_major_blocks)) |prepared_blocks| {
                        if (storage.preparedBytes(.panel4_k16_no_min)) |q3_panel_blocks| {
                            try linearNoBiasQ3KNoDmnPanelActivation(storage.allocator, io, input, prepared_blocks, q3_panel_blocks, output, rows, in_dim, out_dim);
                            return true;
                        }
                    }
                }
                if (k16Panel16SingleEnabledForShape(known, rows, out_dim, row_blocks)) {
                    if (storage.preparedBytes(.row_major_blocks)) |prepared_blocks| {
                        if (storage.preparedBytes(.panel16)) |panel16_blocks| {
                            if (known == .Q2_K) {
                                try linearNoBiasK16PreparedQ8KActivationPanel16(true, storage.allocator, io, input, prepared_blocks, panel16_blocks, output, rows, in_dim, out_dim);
                            } else {
                                try linearNoBiasK16PreparedQ8KActivationPanel16(false, storage.allocator, io, input, prepared_blocks, panel16_blocks, output, rows, in_dim, out_dim);
                            }
                            return true;
                        }
                    }
                }
                if (k16RawQ8DirectEnabledFor(known)) {
                    if (known == .Q2_K) {
                        try linearNoBiasK16RawQ8KActivation(true, storage.allocator, io, input, storage.raw_bytes, output, rows, in_dim, out_dim);
                    } else {
                        try linearNoBiasK16RawQ8KActivation(false, storage.allocator, io, input, storage.raw_bytes, output, rows, in_dim, out_dim);
                    }
                    return true;
                }
                if (storage.preparedBytes(.row_major_blocks)) |prepared_blocks| {
                    const panel8_blocks = if (k16Panel8DirectEnabledFor(known)) storage.preparedBytes(.panel8) else null;
                    if (known == .Q2_K) {
                        try linearNoBiasK16PreparedQ8KActivation(true, storage.allocator, io, input, prepared_blocks, storage.preparedBytes(.panel4), panel8_blocks, output, rows, in_dim, out_dim);
                    } else {
                        try linearNoBiasK16PreparedQ8KActivation(false, storage.allocator, io, input, prepared_blocks, storage.preparedBytes(.panel4), panel8_blocks, output, rows, in_dim, out_dim);
                    }
                    return true;
                }
            }
        },
        else => {},
    }

    switch (storage.tensor_type) {
        .known => |known| if (known == .Q4_0 or known == .Q4_1 or known == .Q5_0 or known == .Q5_1) {
            if (storage.packed_expert != null) return false;
            if (storage.shape.len != 2) return false;
            if (storage.shape[0] != out_dim or storage.shape[1] != in_dim) return false;
            const values_per_block: usize = 32;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (shouldUseQ8_0ActivationQuant(rows, out_dim, row_blocks)) {
                if (storage.preparedBytes(.row_major_blocks)) |prepared_blocks| {
                    try linearNoBiasLegacyPreparedActivation(storage.allocator, io, input, prepared_blocks, storage.preparedBytes(.panel4), known != .Q4_0, output, rows, in_dim, out_dim);
                    noteNativeQuantDispatch(.legacy_activation);
                    return true;
                }
            }
        },
        else => {},
    }

    if (storage.tensor_type.eql(.{ .known = .Q8_1 }) and storage.packed_expert == null) {
        if (storage.shape.len != 2) return false;
        if (storage.shape[0] != out_dim or storage.shape[1] != in_dim) return false;
        const values_per_block: usize = 32;
        if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
        const row_blocks = in_dim / values_per_block;
        if (shouldUseQ8_0ActivationQuant(rows, out_dim, row_blocks)) {
            if (storage.preparedBytes(.row_major_blocks)) |prepared_blocks| {
                try linearNoBiasQ8_1PreparedActivation(storage.allocator, io, input, prepared_blocks, storage.preparedBytes(.panel4), output, rows, in_dim, out_dim);
                return true;
            }
        }
    }

    // Q8_0 has its own inlined kernel that avoids the function-pointer
    // dispatch in the generic path -- LLVM can fuse the dot loop body into
    // the col tile and the inputs are amortised across 2 cols (NR=2).
    if (storage.tensor_type.eql(.{ .known = .Q8_0 }) and storage.packed_expert == null) {
        if (storage.shape.len != 2) return false;
        if (storage.shape[0] != out_dim or storage.shape[1] != in_dim) return false;
        try linearNoBiasQ8_0(storage.allocator, io, input, storage.raw_bytes, storage.preparedBytes(.row_major_blocks), storage.preparedBytes(.panel4), storage.preparedBytes(.panel8), output, rows, in_dim, out_dim);
        noteNativeQuantDispatch(.q8_0_direct);
        return true;
    }

    if (storage.tensor_type.eql(.{ .known = .Q8_K }) and storage.packed_expert == null) {
        const values_per_block = gguf_tensor_types.valuesPerBlock(storage.tensor_type).?;
        if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
        const row_blocks = in_dim / values_per_block;
        if (storage.shape.len == 2 and
            storage.shape[0] == out_dim and
            storage.shape[1] == in_dim and
            shouldUseQ8_KQ8KActivationQuant(rows, out_dim, row_blocks))
        {
            const panel8_blocks = if (q8KPanel8DirectEnabled()) storage.preparedBytes(.panel8) else null;
            const panel16_blocks = if (q8KPanel16SingleEnabledForShape(rows, out_dim, row_blocks)) storage.preparedBytes(.panel16) else null;
            try linearNoBiasQ8KQ8KActivation(storage.allocator, io, input, storage.raw_bytes, storage.preparedBytes(.panel4), panel8_blocks, panel16_blocks, output, rows, in_dim, out_dim);
            noteNativeQuantDispatch(.q8_k_q8k_activation);
            return true;
        }
    }

    switch (storage.tensor_type) {
        .known => |known| if (known == .I2_S) {
            if (storage.packed_expert != null) return false;
            if (storage.shape.len != 2) return false;
            if (storage.shape[0] != out_dim or storage.shape[1] != in_dim) return false;
            try linearNoBiasI2SActivationQuantized(storage.allocator, input, storage.raw_bytes, output, rows, in_dim, out_dim);
            return true;
        } else if (known == .TL1) {
            if (storage.packed_expert != null) return false;
            if (storage.shape.len != 2) return false;
            if (storage.shape[0] != out_dim or storage.shape[1] != in_dim) return false;
            try linearNoBiasTL1ActivationQuantized(storage.allocator, input, storage.raw_bytes, storage.shape, output, rows, in_dim, out_dim);
            return true;
        },
        .bitnet_tl2 => {
            if (storage.packed_expert != null) return false;
            if (storage.shape.len != 2) return false;
            if (storage.shape[0] != out_dim or storage.shape[1] != in_dim) return false;
            try linearNoBiasTL2ActivationQuantized(storage.allocator, input, storage.raw_bytes, storage.shape, output, rows, in_dim, out_dim);
            return true;
        },
        .unknown => {},
    }

    // Comptime-typed dispatch: the dot kernel is inlined into the row/col
    // walk, no fn-pointer indirection.  Only routes single-tensor (no
    // packed_expert) cases here -- the packed-expert and I8_S paths still
    // need the runtime fn-pointer fallback below.
    if (storage.packed_expert == null) {
        if (storage.shape.len != 2) return false;
        if (storage.shape[0] != out_dim or storage.shape[1] != in_dim) return false;
        switch (storage.tensor_type) {
            .known => |known| switch (known) {
                .Q1_0 => return try typedDispatch(.Q1_0, io, input, storage.raw_bytes, output, rows, in_dim, out_dim),
                .Q4_0 => return try typedDispatch(.Q4_0, io, input, storage.raw_bytes, output, rows, in_dim, out_dim),
                .Q4_1 => return try typedDispatch(.Q4_1, io, input, storage.raw_bytes, output, rows, in_dim, out_dim),
                .Q5_0 => return try typedDispatch(.Q5_0, io, input, storage.raw_bytes, output, rows, in_dim, out_dim),
                .Q5_1 => return try typedDispatch(.Q5_1, io, input, storage.raw_bytes, output, rows, in_dim, out_dim),
                .Q8_1 => return try typedDispatch(.Q8_1, io, input, storage.raw_bytes, output, rows, in_dim, out_dim),
                .Q2_K => return try typedDispatch(.Q2_K, io, input, storage.raw_bytes, output, rows, in_dim, out_dim),
                .Q3_K => return try typedDispatch(.Q3_K, io, input, storage.raw_bytes, output, rows, in_dim, out_dim),
                .Q5_K => return try typedDispatch(.Q5_K, io, input, storage.raw_bytes, output, rows, in_dim, out_dim),
                .Q6_K => return try typedDispatch(.Q6_K, io, input, storage.raw_bytes, output, rows, in_dim, out_dim),
                .Q8_K => return try typedDispatch(.Q8_K, io, input, storage.raw_bytes, output, rows, in_dim, out_dim),
                .IQ4_NL => return try typedDispatch(.IQ4_NL, io, input, storage.raw_bytes, output, rows, in_dim, out_dim),
                .IQ4_XS => return try typedDispatch(.IQ4_XS, io, input, storage.raw_bytes, output, rows, in_dim, out_dim),
                else => {}, // fall through to fn-ptr path below (e.g. I8_S)
            },
            else => {},
        }
    }

    const dot_fn: *const fn ([]const f32, []const u8) f32 = switch (storage.tensor_type) {
        .known => |known| switch (known) {
            .Q1_0 => &dotQ1_0Block,
            .Q4_0 => &dotQ4_0Block,
            .Q4_1 => &dotQ4_1Block,
            .Q5_0 => &dotQ5_0Block,
            .Q5_1 => &dotQ5_1Block,
            .Q8_0 => &dotQ8_0Block,
            .Q8_1 => &dotQ8_1Block,
            .Q2_K => &dotQ2_KBlock,
            .Q3_K => &dotQ3_KBlock,
            .Q4_K => &dotQ4_KBlock,
            .Q5_K => &dotQ5_KBlock,
            .Q6_K => &dotQ6_KBlock,
            .Q8_K => &dotQ8_KBlock,
            .I8_S => &dotI8SBlock,
            .IQ4_NL => &dotIQ4NLBlock,
            .IQ4_XS => &dotIQ4XSBlock,
            else => return false,
        },
        .bitnet_tl2 => return false,
        .unknown => return false,
    };

    if (storage.packed_expert) |packed_view| {
        try linearNoBiasPackedQuantized(input, storage, packed_view, output, rows, in_dim, out_dim, storage.tensor_type);
    } else {
        if (storage.shape.len != 2) return false;
        if (storage.shape[0] != out_dim or storage.shape[1] != in_dim) return false;
        try linearNoBiasQuantizedGeneric(io, input, storage.raw_bytes, output, rows, in_dim, out_dim, storage.tensor_type, dot_fn);
    }
    return true;
}

pub fn linearNoBiasQuantizedPair(
    io: ?std.Io,
    allocator: std.mem.Allocator,
    storage_a: *const QuantizedStorage,
    storage_b: *const QuantizedStorage,
    input: []const f32,
    output_a: []f32,
    output_b: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !bool {
    if (!storage_a.tensor_type.eql(storage_b.tensor_type)) return false;
    if (storage_a.packed_expert != null or storage_b.packed_expert != null) return false;
    if (storage_a.shape.len != 2 or storage_b.shape.len != 2) return false;
    if (storage_a.shape[0] != out_dim or storage_a.shape[1] != in_dim) return false;
    if (storage_b.shape[0] != out_dim or storage_b.shape[1] != in_dim) return false;

    if (storage_a.tensor_type.eql(.{ .known = .Q4_K }) or storage_a.tensor_type.eql(.{ .known = .Q5_K })) {
        // The old Q4_K pair helper shares some block reads, but it bypasses
        // the prepared single-kernel row/column dispatch and is slower on
        // CLIP/CLAP Q/K shapes.  Q5_K uses the same prepared K-block layout,
        // so it can reuse this optimized single-kernel dispatch too.
        if (storage_a.preparedBytes(.row_major_blocks) != null and storage_b.preparedBytes(.row_major_blocks) != null) {
            const values_per_block = gguf_tensor_types.valuesPerBlock(storage_a.tensor_type).?;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (shouldUseQ4_Q5_KQ8KActivationQuant(rows, out_dim, row_blocks)) {
                const known = switch (storage_a.tensor_type) {
                    .known => |value| value,
                    else => unreachable,
                };
                const q8_block_size: usize = 292;
                const q_input_len = rows * row_blocks * q8_block_size;
                if (q_input_len <= q8_k_activation_stack_max_bytes) {
                    var q_input_buf: [q8_k_activation_stack_max_bytes]u8 = undefined;
                    const q_input = q_input_buf[0..q_input_len];
                    const quant_start = nativeQuantPhaseStart();
                    try quantizeQ8_KActivationRowsDispatch(io, input, q_input, rows, in_dim, row_blocks);
                    noteNativeQuantPhase(.q8k_activation_quant, quant_start);
                    const compute_start = nativeQuantPhaseStart();
                    try linearKPreparedQ8KActivationPairDispatch(false, io, q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_a.preparedBytes(.panel8), storage_a.preparedBytes(.panel16), output_a, storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), storage_b.preparedBytes(.panel8), storage_b.preparedBytes(.panel16), output_b, rows, in_dim, out_dim, known);
                    noteNativeQuantPhase(.q4q5_q8k_pair_compute, compute_start);
                } else {
                    const alloc_start = nativeQuantPhaseStart();
                    const q_input = try allocator.alloc(u8, q_input_len);
                    defer allocator.free(q_input);
                    noteNativeQuantPhase(.q8k_activation_alloc, alloc_start);
                    const quant_start = nativeQuantPhaseStart();
                    try quantizeQ8_KActivationRowsDispatch(io, input, q_input, rows, in_dim, row_blocks);
                    noteNativeQuantPhase(.q8k_activation_quant, quant_start);
                    const compute_start = nativeQuantPhaseStart();
                    try linearKPreparedQ8KActivationPairDispatch(false, io, q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_a.preparedBytes(.panel8), storage_a.preparedBytes(.panel16), output_a, storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), storage_b.preparedBytes(.panel8), storage_b.preparedBytes(.panel16), output_b, rows, in_dim, out_dim, known);
                    noteNativeQuantPhase(.q4q5_q8k_pair_compute, compute_start);
                }
                noteNativeQuantDispatch(.q4_q5_k_q8k_activation_pair);
                return true;
            }
            try linearNoBiasQ4KPrepared(io, input, storage_a.preparedBytes(.row_major_blocks).?, output_a, rows, in_dim, out_dim);
            try linearNoBiasQ4KPrepared(io, input, storage_b.preparedBytes(.row_major_blocks).?, output_b, rows, in_dim, out_dim);
            return true;
        }
    }
    if (storage_a.tensor_type.eql(.{ .known = .Q6_K })) {
        if (storage_a.preparedBytes(.row_major_blocks) != null and storage_b.preparedBytes(.row_major_blocks) != null) {
            const values_per_block = gguf_tensor_types.valuesPerBlock(storage_a.tensor_type).?;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (shouldUseQ6_KQ8KActivationQuant(rows, out_dim, row_blocks)) {
                const q8_block_size: usize = 292;
                const q_input_len = rows * row_blocks * q8_block_size;
                const use_panel16 = q6KPanel16GroupedEnabledForShape(rows, out_dim, row_blocks, 2);
                const panel16_a = if (use_panel16) storage_a.preparedBytes(.panel16) else null;
                const panel16_b = if (use_panel16) storage_b.preparedBytes(.panel16) else null;
                if (q_input_len <= q8_k_activation_stack_max_bytes) {
                    var q_input_buf: [q8_k_activation_stack_max_bytes]u8 = undefined;
                    const q_input = q_input_buf[0..q_input_len];
                    const quant_start = nativeQuantPhaseStart();
                    try quantizeQ8_KActivationRowsDispatch(io, input, q_input, rows, in_dim, row_blocks);
                    noteNativeQuantPhase(.q8k_activation_quant, quant_start);
                    try linearKPreparedQ8KActivationPairDispatch(true, io, q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_a.preparedBytes(.panel8), panel16_a, output_a, storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), storage_b.preparedBytes(.panel8), panel16_b, output_b, rows, in_dim, out_dim, null);
                } else {
                    const alloc_start = nativeQuantPhaseStart();
                    const q_input = try allocator.alloc(u8, q_input_len);
                    defer allocator.free(q_input);
                    noteNativeQuantPhase(.q8k_activation_alloc, alloc_start);
                    const quant_start = nativeQuantPhaseStart();
                    try quantizeQ8_KActivationRowsDispatch(io, input, q_input, rows, in_dim, row_blocks);
                    noteNativeQuantPhase(.q8k_activation_quant, quant_start);
                    try linearKPreparedQ8KActivationPairDispatch(true, io, q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_a.preparedBytes(.panel8), panel16_a, output_a, storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), storage_b.preparedBytes(.panel8), panel16_b, output_b, rows, in_dim, out_dim, null);
                }
                return true;
            }
            try linearNoBiasQ6KPrepared(io, input, storage_a.preparedBytes(.row_major_blocks).?, output_a, rows, in_dim, out_dim);
            try linearNoBiasQ6KPrepared(io, input, storage_b.preparedBytes(.row_major_blocks).?, output_b, rows, in_dim, out_dim);
            return true;
        }
    }

    switch (storage_a.tensor_type) {
        .known => |known| if (known == .Q1_0) {
            const values_per_block: usize = 128;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const input_blocks = in_dim / 32;
            if (shouldUseQ8_0ActivationQuant(rows, out_dim, input_blocks)) {
                if (storage_a.preparedBytes(.row_major_blocks)) |prepared_a| {
                    if (storage_b.preparedBytes(.row_major_blocks)) |prepared_b| {
                        try linearNoBiasQ1_0PreparedActivationPair(
                            allocator,
                            io,
                            input,
                            prepared_a,
                            prepared_b,
                            storage_a.preparedBytes(.panel4),
                            storage_b.preparedBytes(.panel4),
                            output_a,
                            output_b,
                            rows,
                            in_dim,
                            out_dim,
                        );
                        return true;
                    }
                }
            }
            if (genericQuantPairDotFn(storage_a.tensor_type)) |dot_fn| {
                try linearNoBiasQuantizedGenericPair(
                    io,
                    input,
                    storage_a.raw_bytes,
                    dot_fn,
                    storage_b.raw_bytes,
                    dot_fn,
                    output_a,
                    output_b,
                    rows,
                    in_dim,
                    out_dim,
                    storage_a.tensor_type,
                );
                return true;
            }
        } else if (known == .Q2_K or known == .Q3_K) {
            const values_per_block: usize = 256;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (shouldUseQ4_Q5_KQ8KActivationQuant(rows, out_dim, row_blocks)) {
                if (storage_a.preparedBytes(.row_major_blocks)) |prepared_a| {
                    if (storage_b.preparedBytes(.row_major_blocks)) |prepared_b| {
                        if (known == .Q3_K and q3KNoDmnGroupedEnabledFor(rows, out_dim, row_blocks, 2)) {
                            if (storage_a.preparedBytes(.panel4_k16_no_min)) |q3_panel_a| {
                                if (storage_b.preparedBytes(.panel4_k16_no_min)) |q3_panel_b| {
                                    try linearNoBiasQ3KNoDmnPanelActivationPair(
                                        allocator,
                                        io,
                                        input,
                                        prepared_a,
                                        prepared_b,
                                        q3_panel_a,
                                        q3_panel_b,
                                        output_a,
                                        output_b,
                                        rows,
                                        in_dim,
                                        out_dim,
                                    );
                                    return true;
                                }
                            }
                        }
                        const panel8_a = if (k16Panel8DirectEnabledFor(known)) storage_a.preparedBytes(.panel8) else null;
                        const panel8_b = if (k16Panel8DirectEnabledFor(known)) storage_b.preparedBytes(.panel8) else null;
                        if (known == .Q2_K) {
                            try linearNoBiasK16PreparedQ8KActivationPair(true, allocator, io, input, prepared_a, prepared_b, storage_a.preparedBytes(.panel4), storage_b.preparedBytes(.panel4), panel8_a, panel8_b, output_a, output_b, rows, in_dim, out_dim);
                        } else {
                            try linearNoBiasK16PreparedQ8KActivationPair(false, allocator, io, input, prepared_a, prepared_b, storage_a.preparedBytes(.panel4), storage_b.preparedBytes(.panel4), panel8_a, panel8_b, output_a, output_b, rows, in_dim, out_dim);
                        }
                        return true;
                    }
                }
            }
            if (genericQuantPairDotFn(storage_a.tensor_type)) |dot_fn| {
                try linearNoBiasQuantizedGenericPair(
                    io,
                    input,
                    storage_a.raw_bytes,
                    dot_fn,
                    storage_b.raw_bytes,
                    dot_fn,
                    output_a,
                    output_b,
                    rows,
                    in_dim,
                    out_dim,
                    storage_a.tensor_type,
                );
                return true;
            }
        } else if (known == .Q4_0 or known == .Q4_1 or known == .Q5_0 or known == .Q5_1) {
            const values_per_block: usize = 32;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if ((known == .Q5_0 or known == .Q5_1) and shouldUseQ8_0ActivationQuant(rows, out_dim, row_blocks)) {
                if (storage_a.preparedBytes(.row_major_blocks)) |prepared_a| {
                    if (storage_b.preparedBytes(.row_major_blocks)) |prepared_b| {
                        try linearNoBiasLegacyPreparedActivationPair(
                            allocator,
                            io,
                            input,
                            prepared_a,
                            prepared_b,
                            storage_a.preparedBytes(.panel4),
                            storage_b.preparedBytes(.panel4),
                            output_a,
                            output_b,
                            rows,
                            in_dim,
                            out_dim,
                            known == .Q5_0 or known == .Q5_1,
                        );
                        noteNativeQuantDispatch(.legacy_activation_pair);
                        return true;
                    }
                }
            }
            if (known == .Q4_0 or known == .Q4_1) {
                if (!(try linearNoBiasQuantized(io, storage_a, input, output_a, rows, in_dim, out_dim))) return false;
                if (!(try linearNoBiasQuantized(io, storage_b, input, output_b, rows, in_dim, out_dim))) return false;
                noteNativeQuantDispatch(.legacy_activation_pair);
                return true;
            }
            if (genericQuantPairDotFn(storage_a.tensor_type)) |dot_fn| {
                try linearNoBiasQuantizedGenericPair(
                    io,
                    input,
                    storage_a.raw_bytes,
                    dot_fn,
                    storage_b.raw_bytes,
                    dot_fn,
                    output_a,
                    output_b,
                    rows,
                    in_dim,
                    out_dim,
                    storage_a.tensor_type,
                );
                return true;
            }
        } else if (known == .Q8_0) {
            const values_per_block: usize = 32;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (!shouldUseQ8_0GroupedActivationPair(rows, out_dim, row_blocks)) {
                if (!(try linearNoBiasQuantized(io, storage_a, input, output_a, rows, in_dim, out_dim))) return false;
                if (!(try linearNoBiasQuantized(io, storage_b, input, output_b, rows, in_dim, out_dim))) return false;
                return true;
            }
            // Avoid the runtime dot-function pair fallback for Q8_0; use the
            // specialized MR/NR tiled path with one shared worker dispatch.
            try linearNoBiasQ8_0Pair(
                allocator,
                io,
                input,
                storage_a.raw_bytes,
                storage_b.raw_bytes,
                storage_a.preparedBytes(.row_major_blocks),
                storage_b.preparedBytes(.row_major_blocks),
                storage_a.preparedBytes(.panel4),
                storage_b.preparedBytes(.panel4),
                storage_a.preparedBytes(.panel8),
                storage_b.preparedBytes(.panel8),
                output_a,
                output_b,
                rows,
                in_dim,
                out_dim,
            );
            noteNativeQuantDispatch(.q8_0_pair);
            return true;
        } else if (known == .Q8_1) {
            const values_per_block: usize = 32;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (!shouldUseQ8_1GroupedActivationPair(rows, out_dim, row_blocks)) {
                if (!(try linearNoBiasQuantized(io, storage_a, input, output_a, rows, in_dim, out_dim))) return false;
                if (!(try linearNoBiasQuantized(io, storage_b, input, output_b, rows, in_dim, out_dim))) return false;
                return true;
            }
            if (shouldUseQ8_0ActivationQuant(rows, out_dim, row_blocks)) {
                if (storage_a.preparedBytes(.row_major_blocks)) |prepared_a| {
                    if (storage_b.preparedBytes(.row_major_blocks)) |prepared_b| {
                        try linearNoBiasQ8_1PreparedActivationPair(
                            allocator,
                            io,
                            input,
                            prepared_a,
                            prepared_b,
                            storage_a.preparedBytes(.panel4),
                            storage_b.preparedBytes(.panel4),
                            storage_a.preparedBytes(.panel8),
                            storage_b.preparedBytes(.panel8),
                            output_a,
                            output_b,
                            rows,
                            in_dim,
                            out_dim,
                        );
                        return true;
                    }
                }
            }
        } else if (known == .Q8_K) {
            const values_per_block = gguf_tensor_types.valuesPerBlock(storage_a.tensor_type).?;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (shouldUseQ8_KQ8KActivationQuant(rows, out_dim, row_blocks)) {
                const q_input_len = rows * row_blocks * 292;
                const use_shared_q8k_pair = q_input_len <= q8_k_activation_stack_max_bytes and (rows <= 9 or rows >= 64);
                if (use_shared_q8k_pair) {
                    const panel8_a = if (q8KPanel8DirectEnabled()) storage_a.preparedBytes(.panel8) else null;
                    const panel8_b = if (q8KPanel8DirectEnabled()) storage_b.preparedBytes(.panel8) else null;
                    const panel16_a = if (q8KPanel16DirectEnabled()) storage_a.preparedBytes(.panel16) else null;
                    const panel16_b = if (q8KPanel16DirectEnabled()) storage_b.preparedBytes(.panel16) else null;
                    try linearNoBiasQ8KQ8KActivationPair(
                        allocator,
                        io,
                        input,
                        storage_a.raw_bytes,
                        storage_b.raw_bytes,
                        storage_a.preparedBytes(.panel4),
                        storage_b.preparedBytes(.panel4),
                        panel8_a,
                        panel8_b,
                        panel16_a,
                        panel16_b,
                        output_a,
                        output_b,
                        rows,
                        in_dim,
                        out_dim,
                    );
                    return true;
                }
                if (!(try linearNoBiasQuantized(io, storage_a, input, output_a, rows, in_dim, out_dim))) return false;
                if (!(try linearNoBiasQuantized(io, storage_b, input, output_b, rows, in_dim, out_dim))) return false;
                return true;
            }
        } else if (known == .I2_S) {
            try linearNoBiasI2SPairActivationQuantized(
                allocator,
                input,
                storage_a.raw_bytes,
                storage_b.raw_bytes,
                output_a,
                output_b,
                rows,
                in_dim,
                out_dim,
            );
            return true;
        } else if (known == .TL1) {
            try linearNoBiasTL1PairActivationQuantized(
                allocator,
                input,
                storage_a.raw_bytes,
                storage_b.raw_bytes,
                storage_a.shape,
                storage_b.shape,
                output_a,
                output_b,
                rows,
                in_dim,
                out_dim,
            );
            return true;
        } else if (genericQuantPairDotFn(storage_a.tensor_type)) |dot_fn| {
            try linearNoBiasQuantizedGenericPair(
                io,
                input,
                storage_a.raw_bytes,
                dot_fn,
                storage_b.raw_bytes,
                dot_fn,
                output_a,
                output_b,
                rows,
                in_dim,
                out_dim,
                storage_a.tensor_type,
            );
            return true;
        },
        .bitnet_tl2 => {
            try linearNoBiasTL2PairActivationQuantized(
                allocator,
                input,
                storage_a.raw_bytes,
                storage_b.raw_bytes,
                storage_a.shape,
                storage_b.shape,
                output_a,
                output_b,
                rows,
                in_dim,
                out_dim,
            );
            return true;
        },
        else => {},
    }
    return false;
}

fn linearQ4Q5KPreparedQ8KActivationWithBias(
    io: ?std.Io,
    storage: *const QuantizedStorage,
    input: []const f32,
    bias: []const f32,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !bool {
    if (!(storage.tensor_type.eql(.{ .known = .Q4_K }) or storage.tensor_type.eql(.{ .known = .Q5_K }))) return false;
    if (storage.packed_expert != null) return false;
    const values_per_block = gguf_tensor_types.valuesPerBlock(storage.tensor_type).?;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    if (storage.shape.len != 2 or storage.shape[0] != out_dim or storage.shape[1] != in_dim) return false;
    if (!shouldUseQ4_Q5_KQ8KActivationQuant(rows, out_dim, row_blocks)) return false;
    const prepared_blocks = storage.preparedBytes(.row_major_blocks) orelse return false;
    try linearNoBiasQ4Q5KPreparedQ8KActivation(storage.allocator, io, input, prepared_blocks, storage.preparedBytes(.panel4), storage.preparedBytes(.panel8), storage.preparedBytes(.panel16), bias, output, rows, in_dim, out_dim, switch (storage.tensor_type) {
        .known => |known| known,
        else => unreachable,
    });
    noteNativeQuantDispatch(.q4_q5_k_q8k_activation);
    return true;
}

pub fn linearNoBiasQuantizedTriple(
    io: ?std.Io,
    storage_a: *const QuantizedStorage,
    storage_b: *const QuantizedStorage,
    storage_c: *const QuantizedStorage,
    input: []const f32,
    output_a: []f32,
    output_b: []f32,
    output_c: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !bool {
    return linearQuantizedTriple(
        io,
        storage_a,
        storage_b,
        storage_c,
        input,
        null,
        null,
        null,
        output_a,
        output_b,
        output_c,
        rows,
        in_dim,
        out_dim,
    );
}

pub fn linearQuantizedTriple(
    io: ?std.Io,
    storage_a: *const QuantizedStorage,
    storage_b: *const QuantizedStorage,
    storage_c: *const QuantizedStorage,
    input: []const f32,
    bias_a: ?[]const f32,
    bias_b: ?[]const f32,
    bias_c: ?[]const f32,
    output_a: []f32,
    output_b: []f32,
    output_c: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !bool {
    if (!storage_a.tensor_type.eql(storage_b.tensor_type) or !storage_a.tensor_type.eql(storage_c.tensor_type)) return false;
    if (storage_a.packed_expert != null or storage_b.packed_expert != null or storage_c.packed_expert != null) return false;
    if (storage_a.shape.len != 2 or storage_b.shape.len != 2 or storage_c.shape.len != 2) return false;
    if (storage_a.shape[0] != out_dim or storage_a.shape[1] != in_dim) return false;
    if (storage_b.shape[0] != out_dim or storage_b.shape[1] != in_dim) return false;
    if (storage_c.shape[0] != out_dim or storage_c.shape[1] != in_dim) return false;
    if (bias_a != null and bias_a.?.len < out_dim) return error.InvalidQuantizedLinearShape;
    if (bias_b != null and bias_b.?.len < out_dim) return error.InvalidQuantizedLinearShape;
    if (bias_c != null and bias_c.?.len < out_dim) return error.InvalidQuantizedLinearShape;

    if (storage_a.tensor_type.eql(.{ .known = .Q4_K }) or storage_a.tensor_type.eql(.{ .known = .Q5_K })) {
        if (storage_a.preparedBytes(.row_major_blocks) != null and storage_b.preparedBytes(.row_major_blocks) != null and storage_c.preparedBytes(.row_major_blocks) != null) {
            const values_per_block = gguf_tensor_types.valuesPerBlock(storage_a.tensor_type).?;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            const known = switch (storage_a.tensor_type) {
                .known => |value| value,
                else => unreachable,
            };
            const packed_qkv_shape_enabled = chooseQ4Q5PackedQKVPanel16Shape(rows, out_dim, known);
            const use_packed_qkv_panel16 = useQ4Q5PackedQKVPanel16ForShape(rows, out_dim, known);
            const packed_qkv_blocks = if (use_packed_qkv_panel16) preparedQKVPanel16GroupPackedBytes(storage_a, out_dim, row_blocks) else null;
            if (shouldUseQ4_Q5_KQ8KActivationQuant(rows, out_dim, row_blocks) or (packed_qkv_shape_enabled and packed_qkv_blocks != null)) {
                const q8_block_size: usize = 292;
                const q_input_len = rows * row_blocks * q8_block_size;
                if (q_input_len <= q8_k_activation_stack_max_bytes) {
                    var q_input_buf: [q8_k_activation_stack_max_bytes]u8 = undefined;
                    const q_input = q_input_buf[0..q_input_len];
                    const quant_start = nativeQuantPhaseStart();
                    try quantizeQ8_KActivationRowsDispatch(io, input, q_input, rows, in_dim, row_blocks);
                    noteNativeQuantPhase(.q8k_activation_quant, quant_start);
                    const compute_start = nativeQuantPhaseStart();
                    const packed_qkv_panel16_mr2 = use_packed_qkv_panel16;
                    const fuse_triple_bias = q4q5FusedTripleBiasEnabled() and packed_qkv_blocks != null;
                    try linearKPreparedQ8KActivationTripleDispatch(false, io, q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_a.preparedBytes(.panel8), storage_a.preparedBytes(.panel16), if (fuse_triple_bias) bias_a else null, output_a, storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), storage_b.preparedBytes(.panel8), storage_b.preparedBytes(.panel16), if (fuse_triple_bias) bias_b else null, output_b, storage_c.preparedBytes(.row_major_blocks).?, storage_c.preparedBytes(.panel4), storage_c.preparedBytes(.panel8), storage_c.preparedBytes(.panel16), packed_qkv_blocks, packed_qkv_panel16_mr2, if (fuse_triple_bias) bias_c else null, output_c, rows, in_dim, out_dim, known);
                    noteNativeQuantPhase(.q4q5_q8k_triple_compute, compute_start);
                    if (!fuse_triple_bias) {
                        if (bias_a) |bias| addLinearBiasRows(output_a, bias, rows, out_dim);
                        if (bias_b) |bias| addLinearBiasRows(output_b, bias, rows, out_dim);
                        if (bias_c) |bias| addLinearBiasRows(output_c, bias, rows, out_dim);
                    }
                } else {
                    const alloc_start = nativeQuantPhaseStart();
                    const q_input = try storage_a.allocator.alloc(u8, q_input_len);
                    defer storage_a.allocator.free(q_input);
                    noteNativeQuantPhase(.q8k_activation_alloc, alloc_start);
                    const quant_start = nativeQuantPhaseStart();
                    try quantizeQ8_KActivationRowsDispatch(io, input, q_input, rows, in_dim, row_blocks);
                    noteNativeQuantPhase(.q8k_activation_quant, quant_start);
                    const compute_start = nativeQuantPhaseStart();
                    const packed_qkv_panel16_mr2 = use_packed_qkv_panel16;
                    const fuse_triple_bias = q4q5FusedTripleBiasEnabled() and packed_qkv_blocks != null;
                    try linearKPreparedQ8KActivationTripleDispatch(false, io, q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_a.preparedBytes(.panel8), storage_a.preparedBytes(.panel16), if (fuse_triple_bias) bias_a else null, output_a, storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), storage_b.preparedBytes(.panel8), storage_b.preparedBytes(.panel16), if (fuse_triple_bias) bias_b else null, output_b, storage_c.preparedBytes(.row_major_blocks).?, storage_c.preparedBytes(.panel4), storage_c.preparedBytes(.panel8), storage_c.preparedBytes(.panel16), packed_qkv_blocks, packed_qkv_panel16_mr2, if (fuse_triple_bias) bias_c else null, output_c, rows, in_dim, out_dim, known);
                    noteNativeQuantPhase(.q4q5_q8k_triple_compute, compute_start);
                    if (!fuse_triple_bias) {
                        if (bias_a) |bias| addLinearBiasRows(output_a, bias, rows, out_dim);
                        if (bias_b) |bias| addLinearBiasRows(output_b, bias, rows, out_dim);
                        if (bias_c) |bias| addLinearBiasRows(output_c, bias, rows, out_dim);
                    }
                }
                noteNativeQuantDispatch(.q4_q5_k_q8k_activation_triple);
                return true;
            }
            try linearQ4KPreparedTriple(
                io,
                input,
                storage_a.preparedBytes(.row_major_blocks).?,
                storage_b.preparedBytes(.row_major_blocks).?,
                storage_c.preparedBytes(.row_major_blocks).?,
                bias_a,
                bias_b,
                bias_c,
                output_a,
                output_b,
                output_c,
                rows,
                in_dim,
                out_dim,
            );
            return true;
        }
    }
    if (storage_a.tensor_type.eql(.{ .known = .Q6_K })) {
        if (storage_a.preparedBytes(.row_major_blocks) != null and storage_b.preparedBytes(.row_major_blocks) != null and storage_c.preparedBytes(.row_major_blocks) != null) {
            const values_per_block = gguf_tensor_types.valuesPerBlock(storage_a.tensor_type).?;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (shouldUseQ6_KQ8KActivationQuant(rows, out_dim, row_blocks)) {
                if (!shouldUseQ6KSharedActivationTriple(rows, out_dim, row_blocks)) {
                    if (!(try linearNoBiasQuantized(io, storage_a, input, output_a, rows, in_dim, out_dim))) return false;
                    if (!(try linearNoBiasQuantized(io, storage_b, input, output_b, rows, in_dim, out_dim))) return false;
                    if (!(try linearNoBiasQuantized(io, storage_c, input, output_c, rows, in_dim, out_dim))) return false;
                    if (bias_a) |bias| addLinearBiasRows(output_a, bias, rows, out_dim);
                    if (bias_b) |bias| addLinearBiasRows(output_b, bias, rows, out_dim);
                    if (bias_c) |bias| addLinearBiasRows(output_c, bias, rows, out_dim);
                    return true;
                }
                if (rows == 1) {
                    if (!(try linearNoBiasQuantized(io, storage_a, input, output_a, rows, in_dim, out_dim))) return false;
                    if (!(try linearNoBiasQuantized(io, storage_b, input, output_b, rows, in_dim, out_dim))) return false;
                    if (!(try linearNoBiasQuantized(io, storage_c, input, output_c, rows, in_dim, out_dim))) return false;
                    if (bias_a) |bias| addLinearBiasRows(output_a, bias, rows, out_dim);
                    if (bias_b) |bias| addLinearBiasRows(output_b, bias, rows, out_dim);
                    if (bias_c) |bias| addLinearBiasRows(output_c, bias, rows, out_dim);
                    return true;
                }
                const q8_block_size: usize = 292;
                const q_input_len = rows * row_blocks * q8_block_size;
                const use_panel16 = q6KPanel16GroupedEnabledForShape(rows, out_dim, row_blocks, 3);
                const panel16_a = if (use_panel16) storage_a.preparedBytes(.panel16) else null;
                const panel16_b = if (use_panel16) storage_b.preparedBytes(.panel16) else null;
                const panel16_c = if (use_panel16) storage_c.preparedBytes(.panel16) else null;
                if (q_input_len <= q8_k_activation_stack_max_bytes) {
                    var q_input_buf: [q8_k_activation_stack_max_bytes]u8 = undefined;
                    const q_input = q_input_buf[0..q_input_len];
                    const quant_start = nativeQuantPhaseStart();
                    try quantizeQ8_KActivationRowsDispatch(io, input, q_input, rows, in_dim, row_blocks);
                    noteNativeQuantPhase(.q8k_activation_quant, quant_start);
                    try linearKPreparedQ8KActivationTripleDispatch(true, io, q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_a.preparedBytes(.panel8), panel16_a, null, output_a, storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), storage_b.preparedBytes(.panel8), panel16_b, null, output_b, storage_c.preparedBytes(.row_major_blocks).?, storage_c.preparedBytes(.panel4), storage_c.preparedBytes(.panel8), panel16_c, null, false, null, output_c, rows, in_dim, out_dim, null);
                } else {
                    const alloc_start = nativeQuantPhaseStart();
                    const q_input = try storage_a.allocator.alloc(u8, q_input_len);
                    defer storage_a.allocator.free(q_input);
                    noteNativeQuantPhase(.q8k_activation_alloc, alloc_start);
                    const quant_start = nativeQuantPhaseStart();
                    try quantizeQ8_KActivationRowsDispatch(io, input, q_input, rows, in_dim, row_blocks);
                    noteNativeQuantPhase(.q8k_activation_quant, quant_start);
                    try linearKPreparedQ8KActivationTripleDispatch(true, io, q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_a.preparedBytes(.panel8), panel16_a, null, output_a, storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), storage_b.preparedBytes(.panel8), panel16_b, null, output_b, storage_c.preparedBytes(.row_major_blocks).?, storage_c.preparedBytes(.panel4), storage_c.preparedBytes(.panel8), panel16_c, null, false, null, output_c, rows, in_dim, out_dim, null);
                }
                if (bias_a) |bias| addLinearBiasRows(output_a, bias, rows, out_dim);
                if (bias_b) |bias| addLinearBiasRows(output_b, bias, rows, out_dim);
                if (bias_c) |bias| addLinearBiasRows(output_c, bias, rows, out_dim);
                return true;
            }
            try linearNoBiasQ6KPrepared(io, input, storage_a.preparedBytes(.row_major_blocks).?, output_a, rows, in_dim, out_dim);
            try linearNoBiasQ6KPrepared(io, input, storage_b.preparedBytes(.row_major_blocks).?, output_b, rows, in_dim, out_dim);
            try linearNoBiasQ6KPrepared(io, input, storage_c.preparedBytes(.row_major_blocks).?, output_c, rows, in_dim, out_dim);
            if (bias_a) |bias| addLinearBiasRows(output_a, bias, rows, out_dim);
            if (bias_b) |bias| addLinearBiasRows(output_b, bias, rows, out_dim);
            if (bias_c) |bias| addLinearBiasRows(output_c, bias, rows, out_dim);
            noteNativeQuantDispatch(.legacy_activation_triple);
            return true;
        }
    }

    switch (storage_a.tensor_type) {
        .known => |known| if (known == .Q1_0) {
            const values_per_block: usize = 128;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const input_blocks = in_dim / 32;
            if (shouldUseQ8_0ActivationQuant(rows, out_dim, input_blocks)) {
                if (storage_a.preparedBytes(.row_major_blocks)) |prepared_a| {
                    if (storage_b.preparedBytes(.row_major_blocks)) |prepared_b| {
                        if (storage_c.preparedBytes(.row_major_blocks)) |prepared_c| {
                            try linearQ1_0PreparedActivationTriple(
                                storage_a.allocator,
                                io,
                                input,
                                prepared_a,
                                prepared_b,
                                prepared_c,
                                storage_a.preparedBytes(.panel4),
                                storage_b.preparedBytes(.panel4),
                                storage_c.preparedBytes(.panel4),
                                bias_a,
                                bias_b,
                                bias_c,
                                output_a,
                                output_b,
                                output_c,
                                rows,
                                in_dim,
                                out_dim,
                            );
                            return true;
                        }
                    }
                }
            }
            if (genericQuantPairDotFn(storage_a.tensor_type)) |dot_fn| {
                try linearNoBiasQuantizedGeneric(io, input, storage_a.raw_bytes, output_a, rows, in_dim, out_dim, storage_a.tensor_type, dot_fn);
                try linearNoBiasQuantizedGeneric(io, input, storage_b.raw_bytes, output_b, rows, in_dim, out_dim, storage_b.tensor_type, dot_fn);
                try linearNoBiasQuantizedGeneric(io, input, storage_c.raw_bytes, output_c, rows, in_dim, out_dim, storage_c.tensor_type, dot_fn);
                if (bias_a) |bias| addLinearBiasRows(output_a, bias, rows, out_dim);
                if (bias_b) |bias| addLinearBiasRows(output_b, bias, rows, out_dim);
                if (bias_c) |bias| addLinearBiasRows(output_c, bias, rows, out_dim);
                return true;
            }
        } else if (known == .Q2_K or known == .Q3_K) {
            const values_per_block: usize = 256;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (shouldUseQ4_Q5_KQ8KActivationQuant(rows, out_dim, row_blocks)) {
                if (storage_a.preparedBytes(.row_major_blocks)) |prepared_a| {
                    if (storage_b.preparedBytes(.row_major_blocks)) |prepared_b| {
                        if (storage_c.preparedBytes(.row_major_blocks)) |prepared_c| {
                            if (known == .Q3_K and q3KNoDmnGroupedEnabledFor(rows, out_dim, row_blocks, 3)) {
                                if (storage_a.preparedBytes(.panel4_k16_no_min)) |q3_panel_a| {
                                    if (storage_b.preparedBytes(.panel4_k16_no_min)) |q3_panel_b| {
                                        if (storage_c.preparedBytes(.panel4_k16_no_min)) |q3_panel_c| {
                                            try linearQ3KNoDmnPanelActivationTriple(
                                                storage_a.allocator,
                                                io,
                                                input,
                                                prepared_a,
                                                prepared_b,
                                                prepared_c,
                                                q3_panel_a,
                                                q3_panel_b,
                                                q3_panel_c,
                                                bias_a,
                                                bias_b,
                                                bias_c,
                                                output_a,
                                                output_b,
                                                output_c,
                                                rows,
                                                in_dim,
                                                out_dim,
                                            );
                                            return true;
                                        }
                                    }
                                }
                            }
                            const panel8_a = if (k16Panel8DirectEnabledFor(known)) storage_a.preparedBytes(.panel8) else null;
                            const panel8_b = if (k16Panel8DirectEnabledFor(known)) storage_b.preparedBytes(.panel8) else null;
                            const panel8_c = if (k16Panel8DirectEnabledFor(known)) storage_c.preparedBytes(.panel8) else null;
                            if (known == .Q2_K) {
                                try linearK16PreparedQ8KActivationTriple(true, storage_a.allocator, io, input, prepared_a, prepared_b, prepared_c, storage_a.preparedBytes(.panel4), storage_b.preparedBytes(.panel4), storage_c.preparedBytes(.panel4), panel8_a, panel8_b, panel8_c, bias_a, bias_b, bias_c, output_a, output_b, output_c, rows, in_dim, out_dim);
                            } else {
                                try linearK16PreparedQ8KActivationTriple(false, storage_a.allocator, io, input, prepared_a, prepared_b, prepared_c, storage_a.preparedBytes(.panel4), storage_b.preparedBytes(.panel4), storage_c.preparedBytes(.panel4), panel8_a, panel8_b, panel8_c, bias_a, bias_b, bias_c, output_a, output_b, output_c, rows, in_dim, out_dim);
                            }
                            return true;
                        }
                    }
                }
            }
            if (genericQuantPairDotFn(storage_a.tensor_type)) |dot_fn| {
                try linearNoBiasQuantizedGeneric(io, input, storage_a.raw_bytes, output_a, rows, in_dim, out_dim, storage_a.tensor_type, dot_fn);
                try linearNoBiasQuantizedGeneric(io, input, storage_b.raw_bytes, output_b, rows, in_dim, out_dim, storage_b.tensor_type, dot_fn);
                try linearNoBiasQuantizedGeneric(io, input, storage_c.raw_bytes, output_c, rows, in_dim, out_dim, storage_c.tensor_type, dot_fn);
                if (bias_a) |bias| addLinearBiasRows(output_a, bias, rows, out_dim);
                if (bias_b) |bias| addLinearBiasRows(output_b, bias, rows, out_dim);
                if (bias_c) |bias| addLinearBiasRows(output_c, bias, rows, out_dim);
                return true;
            }
        } else if (known == .Q4_0 or known == .Q4_1 or known == .Q5_0 or known == .Q5_1) {
            const values_per_block: usize = 32;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (shouldUseQ8_0ActivationQuant(rows, out_dim, row_blocks)) {
                if (storage_a.preparedBytes(.row_major_blocks)) |prepared_a| {
                    if (storage_b.preparedBytes(.row_major_blocks)) |prepared_b| {
                        if (storage_c.preparedBytes(.row_major_blocks)) |prepared_c| {
                            try linearLegacyPreparedActivationTriple(
                                storage_a.allocator,
                                io,
                                input,
                                prepared_a,
                                prepared_b,
                                prepared_c,
                                storage_a.preparedBytes(.panel4),
                                storage_b.preparedBytes(.panel4),
                                storage_c.preparedBytes(.panel4),
                                bias_a,
                                bias_b,
                                bias_c,
                                output_a,
                                output_b,
                                output_c,
                                rows,
                                in_dim,
                                out_dim,
                                known != .Q4_0,
                            );
                            noteNativeQuantDispatch(.legacy_activation_triple);
                            return true;
                        }
                    }
                }
            }
            if (genericQuantPairDotFn(storage_a.tensor_type)) |dot_fn| {
                try linearNoBiasQuantizedGeneric(io, input, storage_a.raw_bytes, output_a, rows, in_dim, out_dim, storage_a.tensor_type, dot_fn);
                try linearNoBiasQuantizedGeneric(io, input, storage_b.raw_bytes, output_b, rows, in_dim, out_dim, storage_b.tensor_type, dot_fn);
                try linearNoBiasQuantizedGeneric(io, input, storage_c.raw_bytes, output_c, rows, in_dim, out_dim, storage_c.tensor_type, dot_fn);
                if (bias_a) |bias| addLinearBiasRows(output_a, bias, rows, out_dim);
                if (bias_b) |bias| addLinearBiasRows(output_b, bias, rows, out_dim);
                if (bias_c) |bias| addLinearBiasRows(output_c, bias, rows, out_dim);
                return true;
            }
        } else if (known == .Q8_0) {
            const values_per_block: usize = 32;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (!shouldUseQ8_0GroupedActivationTriple(rows, out_dim, row_blocks)) {
                if (!(try linearNoBiasQuantized(io, storage_a, input, output_a, rows, in_dim, out_dim))) return false;
                if (!(try linearNoBiasQuantized(io, storage_b, input, output_b, rows, in_dim, out_dim))) return false;
                if (!(try linearNoBiasQuantized(io, storage_c, input, output_c, rows, in_dim, out_dim))) return false;
                if (bias_a) |bias| addLinearBiasRows(output_a, bias, rows, out_dim);
                if (bias_b) |bias| addLinearBiasRows(output_b, bias, rows, out_dim);
                if (bias_c) |bias| addLinearBiasRows(output_c, bias, rows, out_dim);
                return true;
            }
            try linearQ8_0Triple(
                storage_a.allocator,
                io,
                input,
                storage_a.raw_bytes,
                storage_b.raw_bytes,
                storage_c.raw_bytes,
                storage_a.preparedBytes(.row_major_blocks),
                storage_b.preparedBytes(.row_major_blocks),
                storage_c.preparedBytes(.row_major_blocks),
                storage_a.preparedBytes(.panel4),
                storage_b.preparedBytes(.panel4),
                storage_c.preparedBytes(.panel4),
                storage_a.preparedBytes(.panel8),
                storage_b.preparedBytes(.panel8),
                storage_c.preparedBytes(.panel8),
                bias_a,
                bias_b,
                bias_c,
                output_a,
                output_b,
                output_c,
                rows,
                in_dim,
                out_dim,
            );
            noteNativeQuantDispatch(.q8_0_triple);
            return true;
        } else if (known == .Q8_1) {
            const values_per_block: usize = 32;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (!shouldUseQ8_1GroupedActivationTriple(rows, out_dim, row_blocks)) {
                if (!(try linearNoBiasQuantized(io, storage_a, input, output_a, rows, in_dim, out_dim))) return false;
                if (!(try linearNoBiasQuantized(io, storage_b, input, output_b, rows, in_dim, out_dim))) return false;
                if (!(try linearNoBiasQuantized(io, storage_c, input, output_c, rows, in_dim, out_dim))) return false;
                if (bias_a) |bias| addLinearBiasRows(output_a, bias, rows, out_dim);
                if (bias_b) |bias| addLinearBiasRows(output_b, bias, rows, out_dim);
                if (bias_c) |bias| addLinearBiasRows(output_c, bias, rows, out_dim);
                return true;
            }
            if (shouldUseQ8_0ActivationQuant(rows, out_dim, row_blocks)) {
                if (storage_a.preparedBytes(.row_major_blocks)) |prepared_a| {
                    if (storage_b.preparedBytes(.row_major_blocks)) |prepared_b| {
                        if (storage_c.preparedBytes(.row_major_blocks)) |prepared_c| {
                            try linearQ8_1PreparedActivationTriple(
                                storage_a.allocator,
                                io,
                                input,
                                prepared_a,
                                prepared_b,
                                prepared_c,
                                storage_a.preparedBytes(.panel4),
                                storage_b.preparedBytes(.panel4),
                                storage_c.preparedBytes(.panel4),
                                storage_a.preparedBytes(.panel8),
                                storage_b.preparedBytes(.panel8),
                                storage_c.preparedBytes(.panel8),
                                bias_a,
                                bias_b,
                                bias_c,
                                output_a,
                                output_b,
                                output_c,
                                rows,
                                in_dim,
                                out_dim,
                            );
                            return true;
                        }
                    }
                }
            }
        } else if (known == .Q8_K) {
            const values_per_block = gguf_tensor_types.valuesPerBlock(storage_a.tensor_type).?;
            if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
            const row_blocks = in_dim / values_per_block;
            if (shouldUseQ8_KQ8KActivationQuant(rows, out_dim, row_blocks)) {
                const q_input_len = rows * row_blocks * 292;
                const use_shared_stack_triple = q_input_len <= q8_k_activation_stack_max_bytes and (rows <= 4 or rows == 9 or rows >= 64);
                if (use_shared_stack_triple) {
                    const panel8_a = if (q8KPanel8DirectEnabled()) storage_a.preparedBytes(.panel8) else null;
                    const panel8_b = if (q8KPanel8DirectEnabled()) storage_b.preparedBytes(.panel8) else null;
                    const panel8_c = if (q8KPanel8DirectEnabled()) storage_c.preparedBytes(.panel8) else null;
                    const panel16_a = if (q8KPanel16DirectEnabled()) storage_a.preparedBytes(.panel16) else null;
                    const panel16_b = if (q8KPanel16DirectEnabled()) storage_b.preparedBytes(.panel16) else null;
                    const panel16_c = if (q8KPanel16DirectEnabled()) storage_c.preparedBytes(.panel16) else null;
                    try linearQ8KQ8KActivationTriple(
                        storage_a.allocator,
                        io,
                        input,
                        storage_a.raw_bytes,
                        storage_b.raw_bytes,
                        storage_c.raw_bytes,
                        storage_a.preparedBytes(.panel4),
                        storage_b.preparedBytes(.panel4),
                        storage_c.preparedBytes(.panel4),
                        panel8_a,
                        panel8_b,
                        panel8_c,
                        panel16_a,
                        panel16_b,
                        panel16_c,
                        bias_a,
                        bias_b,
                        bias_c,
                        output_a,
                        output_b,
                        output_c,
                        rows,
                        in_dim,
                        out_dim,
                    );
                    return true;
                }
                if (!(try linearNoBiasQuantized(io, storage_a, input, output_a, rows, in_dim, out_dim))) return false;
                if (!(try linearNoBiasQuantized(io, storage_b, input, output_b, rows, in_dim, out_dim))) return false;
                if (!(try linearNoBiasQuantized(io, storage_c, input, output_c, rows, in_dim, out_dim))) return false;
                if (bias_a) |bias| addLinearBiasRows(output_a, bias, rows, out_dim);
                if (bias_b) |bias| addLinearBiasRows(output_b, bias, rows, out_dim);
                if (bias_c) |bias| addLinearBiasRows(output_c, bias, rows, out_dim);
                return true;
            }
        } else if (genericQuantPairDotFn(storage_a.tensor_type)) |dot_fn| {
            try linearNoBiasQuantizedGeneric(io, input, storage_a.raw_bytes, output_a, rows, in_dim, out_dim, storage_a.tensor_type, dot_fn);
            try linearNoBiasQuantizedGeneric(io, input, storage_b.raw_bytes, output_b, rows, in_dim, out_dim, storage_b.tensor_type, dot_fn);
            try linearNoBiasQuantizedGeneric(io, input, storage_c.raw_bytes, output_c, rows, in_dim, out_dim, storage_c.tensor_type, dot_fn);
            if (bias_a) |bias| addLinearBiasRows(output_a, bias, rows, out_dim);
            if (bias_b) |bias| addLinearBiasRows(output_b, bias, rows, out_dim);
            if (bias_c) |bias| addLinearBiasRows(output_c, bias, rows, out_dim);
            return true;
        },
        else => {},
    }

    return false;
}

fn linearNoBiasQuantizedGenericPair(
    io: ?std.Io,
    input: []const f32,
    weight_raw_a: []const u8,
    dot_fn_a: *const fn ([]const f32, []const u8) f32,
    weight_raw_b: []const u8,
    dot_fn_b: *const fn ([]const f32, []const u8) f32,
    output_a: []f32,
    output_b: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    tensor_type: gguf_tensor_types.TensorType,
) !void {
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const values_per_block = gguf_tensor_types.valuesPerBlock(tensor_type).?;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * block_size;
    if (weight_raw_a.len != out_dim * row_stride or weight_raw_b.len != out_dim * row_stride) {
        return error.InvalidQuantizedDataSize;
    }

    if (try linearNoBiasQuantizedGenericPairParallel(
        io,
        input,
        weight_raw_a,
        dot_fn_a,
        weight_raw_b,
        dot_fn_b,
        output_a,
        output_b,
        rows,
        in_dim,
        out_dim,
        row_blocks,
        block_size,
        values_per_block,
        row_stride,
    )) {
        return;
    }

    try linearNoBiasQuantizedGenericPairRange(
        input,
        weight_raw_a,
        dot_fn_a,
        weight_raw_b,
        dot_fn_b,
        output_a,
        output_b,
        rows,
        in_dim,
        out_dim,
        0,
        out_dim,
        block_size,
        values_per_block,
        row_stride,
    );
}

fn linearNoBiasQuantizedGenericRange(
    input: []const f32,
    weight_raw: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    block_size: usize,
    values_per_block: usize,
    row_stride: usize,
    dot_fn: *const fn ([]const f32, []const u8) f32,
) !void {
    if (out_start > out_end or out_end > out_dim) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    for (0..rows) |r| {
        const input_row = input[r * in_dim ..][0..in_dim];
        const out_row = output[r * out_dim ..][0..out_dim];
        for (out_start..out_end) |o| {
            const row_offset = o * row_stride;
            var acc: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const blk = weight_raw[row_offset + block_idx * block_size ..][0..block_size];
                const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
                acc += dot_fn(input_block, blk);
            }
            out_row[o] = acc;
        }
    }
}

fn linearNoBiasQuantizedGenericPairRange(
    input: []const f32,
    weight_raw_a: []const u8,
    dot_fn_a: *const fn ([]const f32, []const u8) f32,
    weight_raw_b: []const u8,
    dot_fn_b: *const fn ([]const f32, []const u8) f32,
    output_a: []f32,
    output_b: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    block_size: usize,
    values_per_block: usize,
    row_stride: usize,
) !void {
    if (out_start > out_end or out_end > out_dim) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    for (0..rows) |r| {
        const input_row = input[r * in_dim ..][0..in_dim];
        const out_row_a = output_a[r * out_dim ..][0..out_dim];
        const out_row_b = output_b[r * out_dim ..][0..out_dim];
        for (out_start..out_end) |o| {
            const row_offset = o * row_stride;
            var acc_a: f32 = 0.0;
            var acc_b: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const block_off = row_offset + block_idx * block_size;
                const blk_a = weight_raw_a[block_off..][0..block_size];
                const blk_b = weight_raw_b[block_off..][0..block_size];
                const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
                acc_a += dot_fn_a(input_block, blk_a);
                acc_b += dot_fn_b(input_block, blk_b);
            }
            out_row_a[o] = acc_a;
            out_row_b[o] = acc_b;
        }
    }
}

fn linearNoBiasPackedQuantized(
    input: []const f32,
    storage: *const QuantizedStorage,
    packed_view: QuantizedStorage.PackedExpertView,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    tensor_type: gguf_tensor_types.TensorType,
) !void {
    const meta = try packedQuantizedMatrixMeta(storage.shape, packed_view, in_dim, out_dim, tensor_type);
    for (0..rows) |r| {
        const input_row = input[r * in_dim ..][0..in_dim];
        const out_row = output[r * out_dim ..][0..out_dim];
        for (0..out_dim) |o| {
            const row_block_base = try packedExpertRowBlockBase(meta, packed_view, o);
            var acc: f32 = 0.0;
            for (0..meta.row_blocks) |block_idx| {
                const block_off = (row_block_base + block_idx) * meta.block_size;
                const block = storage.raw_bytes[block_off .. block_off + meta.block_size];
                const input_block = input_row[block_idx * meta.values_per_block ..][0..meta.values_per_block];
                acc += switch (tensor_type) {
                    .known => |known| switch (known) {
                        .Q4_0 => dotQ4_0Block(input_block, block),
                        .Q4_1 => dotQ4_1Block(input_block, block),
                        .Q5_0 => dotQ5_0Block(input_block, block),
                        .Q5_1 => dotQ5_1Block(input_block, block),
                        .Q8_0 => dotQ8_0Block(input_block, block),
                        .Q8_1 => dotQ8_1Block(input_block, block),
                        .Q2_K => dotQ2_KBlock(input_block, block),
                        .Q3_K => dotQ3_KBlock(input_block, block),
                        .Q4_K => dotQ4_KBlock(input_block, block),
                        .Q5_K => dotQ5_KBlock(input_block, block),
                        .Q6_K => dotQ6_KBlock(input_block, block),
                        .Q8_K => dotQ8_KBlock(input_block, block),
                        .I8_S => dotI8SBlock(input_block, block),
                        .IQ4_NL => dotIQ4NLBlock(input_block, block),
                        .IQ4_XS => dotIQ4XSBlock(input_block, block),
                        else => return error.UnsupportedTensorType,
                    },
                    .bitnet_tl2 => return error.UnsupportedTensorType,
                    .unknown => return error.UnsupportedTensorType,
                };
            }
            out_row[o] = acc;
        }
    }
}

