const prepared_q3_k_panel_block_bytes = prepared_q3_k_panel_values_offset + prepared_q3_k_panel_values_bytes;

pub fn prepareNativeQuantizedStorage(storage: *QuantizedStorage) !void {
    const known = switch (storage.tensor_type) {
        .known => |value| value,
        else => return,
    };
    if (known == .Q8_K) {
        if (storage.packed_expert != null) return;
        try prepareQ8_KPanelPackedStorage(storage);
        if (q8KPanel8DirectEnabled()) try prepareQ8_KPanel8PackedStorage(storage);
        if (q8KPanel16PreparedEnabled()) try prepareQ8_KPanel16PackedStorage(storage);
        return;
    }
    if (known != .Q1_0 and known != .Q4_0 and known != .Q4_1 and known != .Q5_0 and known != .Q5_1 and known != .Q2_K and known != .Q3_K and known != .Q4_K and known != .Q5_K and known != .Q6_K and known != .Q8_0 and known != .Q8_1) return;
    if ((known == .Q1_0 or known == .Q4_0 or known == .Q4_1 or known == .Q5_0 or known == .Q5_1 or known == .Q2_K or known == .Q3_K) and storage.packed_expert != null) return;
    if ((known == .Q5_K or known == .Q6_K) and storage.packed_expert != null) return;
    if ((known == .Q8_0 or known == .Q8_1) and storage.packed_expert != null) return;

    const block_size = gguf_tensor_types.bytesPerBlock(storage.tensor_type).?;
    if (storage.raw_bytes.len % block_size != 0) return error.InvalidQuantizedDataSize;
    const block_count = storage.raw_bytes.len / block_size;
    const prepared_block_size: usize = if (known == .Q8_0 or known == .Q8_1)
        prepared_q8_0_block_bytes
    else if (known == .Q1_0)
        prepared_q1_0_block_bytes
    else if (known == .Q4_0 or known == .Q4_1 or known == .Q5_0 or known == .Q5_1)
        prepared_legacy_block_bytes
    else if (known == .Q2_K or known == .Q3_K)
        prepared_k16_block_bytes
    else
        prepared_q4_k_block_bytes;

    if (storage.preparedBytes(.row_major_blocks) == null) {
        const prepared = try storage.allocator.alloc(u8, block_count * prepared_block_size);
        errdefer storage.allocator.free(prepared);

        var scales: [8]u8 = undefined;
        var mins: [8]u8 = undefined;
        for (0..block_count) |block_idx| {
            const block = storage.raw_bytes[block_idx * block_size ..][0..block_size];
            const prepared_block = prepared[block_idx * prepared_block_size ..][0..prepared_block_size];
            switch (known) {
                .Q4_K => writePreparedQ4KBlock(prepared_block, block, &scales, &mins),
                .Q5_K => writePreparedQ5KBlock(prepared_block, block, &scales, &mins),
                .Q6_K => writePreparedQ6KBlock(prepared_block, block),
                .Q8_0 => writePreparedQ8_0Block(prepared_block, block),
                .Q8_1 => writePreparedQ8_1Block(prepared_block, block),
                .Q1_0 => writePreparedQ1_0Block(prepared_block, block),
                .Q4_0, .Q4_1, .Q5_0, .Q5_1 => writePreparedLegacyBlock(known, prepared_block, block),
                .Q2_K => writePreparedQ2KBlock(prepared_block, block),
                .Q3_K => writePreparedQ3KBlock(prepared_block, block),
                else => unreachable,
            }
        }

        storage.setPreparedBytes(.row_major_blocks, prepared, 0, @intCast(block_count));
    }

    if (known == .Q8_0 or known == .Q8_1) {
        try prepareQ8_0PanelPackedStorage(storage);
        if (q8_0Panel8PrepareEnabled()) try prepareQ8_0Panel8PackedStorage(storage);
    } else if (known == .Q1_0) {
        try prepareQ1_0PanelPackedStorage(storage);
    } else if (known == .Q4_0 or known == .Q4_1 or known == .Q5_0 or known == .Q5_1) {
        try prepareLegacyPanelPackedStorage(storage);
    } else if (known == .Q2_K or known == .Q3_K) {
        try prepareK16PanelPackedStorage(storage);
        if (known == .Q3_K) try prepareQ3KNoDmnPanelPackedStorage(storage);
        if (k16Panel8DirectEnabledFor(known)) try prepareK16Panel8PackedStorage(storage);
        if (k16Panel16PreparedEnabledFor(known)) try prepareK16Panel16PackedStorage(storage);
    } else {
        try preparePreparedKPanelPackedStorage(storage);
        try preparePreparedKPanel8PackedStorage(storage);
        if (known == .Q4_K or known == .Q5_K or (known == .Q6_K and q6KPanel16PreparedEnabled())) try preparePreparedKPanel16PackedStorage(storage);
    }
}

fn nativePreparedStorageComplete(storage: *const QuantizedStorage, known: gguf_tensor_types.KnownTensorType) bool {
    if (known == .Q8_K) {
        if (storage.preparedBytes(.panel4) == null) return preparedKBlockAdditionalBytes(storage) == 0;
        if (q8KPanel8DirectEnabled() and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0 and @rem(storage.shape[1], 256) == 0) {
            const out_dim: usize = @intCast(storage.shape[0]);
            const row_blocks: usize = @intCast(@divExact(storage.shape[1], 256));
            if (storage.preparedBytes(.panel8) == null and preparedQ8_KPanel8ByteSize(out_dim, row_blocks) != 0) return false;
        }
        if (q8KPanel16PreparedEnabled() and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0 and @rem(storage.shape[1], 256) == 0) {
            const out_dim: usize = @intCast(storage.shape[0]);
            const row_blocks: usize = @intCast(@divExact(storage.shape[1], 256));
            if (storage.preparedBytes(.panel16) == null and preparedQ8_KPanel16ByteSize(out_dim, row_blocks) != 0) return false;
        }
        return true;
    }
    if (storage.preparedBytes(.row_major_blocks) == null) return false;
    if (known == .Q4_K or known == .Q5_K or known == .Q6_K) {
        if (storage.preparedBytes(.panel4) == null) return false;
        if (k16Panel8DirectEnabled() and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0 and @rem(storage.shape[1], 256) == 0) {
            const out_dim: usize = @intCast(storage.shape[0]);
            const row_blocks: usize = @intCast(@divExact(storage.shape[1], 256));
            if (storage.preparedBytes(.panel8) == null and preparedKPanel8ByteSizeForKnown(known, out_dim, row_blocks) != 0) return false;
        }
        if ((known == .Q4_K or known == .Q5_K or (known == .Q6_K and q6KPanel16PreparedEnabled())) and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0 and @rem(storage.shape[1], 256) == 0) {
            const out_dim: usize = @intCast(storage.shape[0]);
            const row_blocks: usize = @intCast(@divExact(storage.shape[1], 256));
            if (storage.preparedBytes(.panel16) == null and preparedKPanel16ByteSize(out_dim, row_blocks) != 0) return false;
        }
        return true;
    }
    if (known == .Q2_K or known == .Q3_K) {
        if (storage.preparedBytes(.panel4) == null and preparedKBlockAdditionalBytes(storage) != 0) return false;
        if (k16Panel8DirectEnabledFor(known) and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0 and @rem(storage.shape[1], 256) == 0) {
            const out_dim: usize = @intCast(storage.shape[0]);
            const row_blocks: usize = @intCast(@divExact(storage.shape[1], 256));
            if (storage.preparedBytes(.panel8) == null and preparedK16Panel8ByteSize(out_dim, row_blocks) != 0) return false;
        }
        if (known == .Q3_K and q3KNoDmnPanelPreparedEnabled() and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0 and @rem(storage.shape[1], 256) == 0) {
            const out_dim: usize = @intCast(storage.shape[0]);
            const row_blocks: usize = @intCast(@divExact(storage.shape[1], 256));
            if (q3KNoDmnPanelPreparedEnabledForShape(out_dim, row_blocks) and storage.preparedBytes(.panel4_k16_no_min) == null and preparedQ3KNoDmnPanelByteSize(out_dim, row_blocks) != 0) return false;
        }
        if (k16Panel16PreparedEnabledFor(known) and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0 and @rem(storage.shape[1], 256) == 0) {
            const out_dim: usize = @intCast(storage.shape[0]);
            const row_blocks: usize = @intCast(@divExact(storage.shape[1], 256));
            if (storage.preparedBytes(.panel16) == null and preparedK16Panel16ByteSize(out_dim, row_blocks) != 0) return false;
        }
        return true;
    }
    if (known == .Q8_0 or known == .Q8_1) {
        if (storage.preparedBytes(.panel4) == null and preparedKBlockAdditionalBytes(storage) != 0) return false;
        if (q8_0Panel8PrepareEnabled() and storage.shape.len == 2 and storage.shape[0] > 0 and storage.shape[1] > 0 and @rem(storage.shape[1], 32) == 0) {
            const out_dim: usize = @intCast(storage.shape[0]);
            const row_blocks: usize = @intCast(@divExact(storage.shape[1], 32));
            if (storage.preparedBytes(.panel8) == null and preparedQ8_0Panel8ByteSize(out_dim, row_blocks) != 0) return false;
        }
        return true;
    }
    if (known == .Q8_0 or known == .Q8_1 or known == .Q1_0 or known == .Q4_0 or known == .Q4_1 or known == .Q5_0 or known == .Q5_1 or known == .Q4_K or known == .Q5_K or known == .Q6_K) {
        return storage.preparedBytes(.panel4) != null or preparedKBlockAdditionalBytes(storage) == 0;
    }
    return true;
}

fn ensurePreparedKBlock(self: *NativeCompute, storage: *QuantizedStorage) !void {
    const known = switch (storage.tensor_type) {
        .known => |value| value,
        else => return,
    };
    if (known != .Q1_0 and known != .Q4_0 and known != .Q4_1 and known != .Q5_0 and known != .Q5_1 and known != .Q2_K and known != .Q3_K and known != .Q4_K and known != .Q5_K and known != .Q6_K and known != .Q8_0 and known != .Q8_1 and known != .Q8_K) return;
    if (nativePreparedStorageComplete(storage, known)) return;
    while (!self.data.quantized_prepare_lock.tryLock()) {
        std.Thread.yield() catch {};
    }
    defer self.data.quantized_prepare_lock.unlock();
    if (nativePreparedStorageComplete(storage, known)) return;
    const additional_bytes = preparedKBlockAdditionalBytes(storage);
    var reserved_bytes: usize = 0;
    if (self.data.tier_cache) |*tier_cache| {
        if (additional_bytes != 0) {
            if (!tier_cache.canFitAdditional(.host, additional_bytes)) {
                tier_cache.noteDenied(.host, additional_bytes);
                noteSharedCacheDenial(self.run_budget, tier_cache, .host, additional_bytes);
                return;
            }
            tier_cache.noteResident(.host, additional_bytes);
            reserved_bytes = additional_bytes;
        }
    }
    errdefer if (reserved_bytes != 0) {
        if (self.data.tier_cache) |*tier_cache| tier_cache.noteRelease(.host, reserved_bytes);
    };
    try prepareNativeQuantizedStorage(storage);
}

fn prepareNativeQuantizedStorageBudgetedLocked(
    data: *WeightStore,
    run_budget: ?*run_memory.RunBudget,
    storage: *QuantizedStorage,
) !void {
    const known = switch (storage.tensor_type) {
        .known => |value| value,
        else => return,
    };
    if (known != .Q1_0 and known != .Q4_0 and known != .Q4_1 and known != .Q5_0 and known != .Q5_1 and known != .Q2_K and known != .Q3_K and known != .Q4_K and known != .Q5_K and known != .Q6_K and known != .Q8_0 and known != .Q8_1 and known != .Q8_K) return;
    if (nativePreparedStorageComplete(storage, known)) return;

    const additional_bytes = preparedKBlockAdditionalBytes(storage);
    if (additional_bytes == 0) return;

    if (data.tier_cache) |*tier_cache| {
        evictColdNonExpertWeightsToFitLocked(data, .host, additional_bytes, null);
        if (!tier_cache.canFitAdditional(.host, additional_bytes)) {
            tier_cache.noteDenied(.host, additional_bytes);
            noteSharedCacheDenial(run_budget, tier_cache, .host, additional_bytes);
            return;
        }
    }

    try prepareNativeQuantizedStorage(storage);
}

fn writePreparedQ4KBlock(
    dest: []u8,
    raw_block: []const u8,
    scales_out: *[8]u8,
    mins_out: *[8]u8,
) void {
    std.debug.assert(dest.len == prepared_q4_k_block_bytes);
    const d = decodeFp16Le(raw_block[0], raw_block[1]);
    const dmin = decodeFp16Le(raw_block[2], raw_block[3]);
    unpackQ4KScaleMinsU8(raw_block[4..16], scales_out, mins_out);
    for (0..8) |i| {
        writeF32Le(dest[prepared_q4_k_dsc_offset + i * 4 ..][0..4], d * @as(f32, @floatFromInt(scales_out[i])));
        writeF32Le(dest[prepared_q4_k_dmn_offset + i * 4 ..][0..4], dmin * @as(f32, @floatFromInt(mins_out[i])));
    }
    unpackQ4KValues(raw_block[16..144], dest[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes]);
}

fn writePreparedQ5KBlock(
    dest: []u8,
    raw_block: []const u8,
    scales_out: *[8]u8,
    mins_out: *[8]u8,
) void {
    std.debug.assert(dest.len == prepared_q4_k_block_bytes);
    const d = decodeFp16Le(raw_block[0], raw_block[1]);
    const dmin = decodeFp16Le(raw_block[2], raw_block[3]);
    unpackQ4KScaleMinsU8(raw_block[4..16], scales_out, mins_out);
    for (0..8) |i| {
        writeF32Le(dest[prepared_q4_k_dsc_offset + i * 4 ..][0..4], d * @as(f32, @floatFromInt(scales_out[i])));
        writeF32Le(dest[prepared_q4_k_dmn_offset + i * 4 ..][0..4], dmin * @as(f32, @floatFromInt(mins_out[i])));
    }

    const qh = raw_block[16..48];
    const ql = raw_block[48..176];
    const values = dest[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    for (0..8) |sub| {
        const chunk = sub / 2;
        const is_high = sub % 2 == 1;
        const ql_off = chunk * 32;
        const out_off = sub * 32;
        const high_shift: u3 = @intCast(sub);
        for (0..32) |i| {
            const low = if (is_high) ql[ql_off + i] >> 4 else ql[ql_off + i] & 0x0F;
            const high = ((qh[i] >> high_shift) & 0x01) << 4;
            values[out_off + i] = low | high;
        }
    }
}

fn writePreparedQ6KBlock(dest: []u8, raw_block: []const u8) void {
    std.debug.assert(dest.len == prepared_q4_k_block_bytes);
    const ql = raw_block[0..128];
    const qh = raw_block[128..192];
    const scales = raw_block[192..208];
    const d = decodeFp16Le(raw_block[208], raw_block[209]);
    for (0..16) |sub| {
        const scale_i8: i8 = @bitCast(scales[sub]);
        writeF32Le(dest[sub * 4 ..][0..4], d * @as(f32, @floatFromInt(scale_i8)));
    }

    const values = dest[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    for (0..16) |sub| {
        const half = sub / 8;
        const group = (sub % 8) / 2;
        const l_base = (sub % 2) * 16;
        const ql_off = half * 64 + (group & 1) * 32;
        const qh_off = half * 32;
        const qh_shift: u3 = @intCast(group * 2);
        const nibble_shift: u3 = @intCast((group / 2) * 4);
        const out_off = sub * 16;
        for (0..16) |i| {
            const l = l_base + i;
            const low4: i32 = (ql[ql_off + l] >> nibble_shift) & 0x0F;
            const high2: i32 = (qh[qh_off + l] >> qh_shift) & 0x03;
            const q: i8 = @intCast((low4 | (high2 << 4)) - 32);
            values[out_off + i] = @bitCast(q);
        }
    }
}

fn writePreparedQ8_0Block(dest: []u8, raw_block: []const u8) void {
    std.debug.assert(dest.len == prepared_q8_0_block_bytes);
    std.debug.assert(raw_block.len == 34);
    writeF32Le(dest[prepared_q8_0_scale_offset..][0..4], decodeFp16Le(raw_block[0], raw_block[1]));
    @memcpy(dest[prepared_q8_0_values_offset..][0..prepared_q8_0_values_bytes], raw_block[2..34]);
}

fn writePreparedQ8_1Block(dest: []u8, raw_block: []const u8) void {
    std.debug.assert(dest.len == prepared_q8_0_block_bytes);
    std.debug.assert(raw_block.len == 36);
    writeF32Le(dest[prepared_q8_0_scale_offset..][0..4], decodeFp16Le(raw_block[0], raw_block[1]));
    @memcpy(dest[prepared_q8_0_values_offset..][0..prepared_q8_0_values_bytes], raw_block[4..36]);
}

fn writePreparedQ1_0Block(dest: []u8, raw_block: []const u8) void {
    std.debug.assert(dest.len == prepared_q1_0_block_bytes);
    std.debug.assert(raw_block.len == 18);
    writeF32Le(dest[prepared_q1_0_scale_offset..][0..4], decodeFp16Le(raw_block[0], raw_block[1]));
    const values = dest[prepared_q1_0_values_offset..][0..prepared_q1_0_values_bytes];
    const qs = raw_block[2..18];
    for (0..128) |i| {
        const bit = (qs[i / 8] >> @as(u3, @intCast(i % 8))) & 1;
        values[i] = @bitCast(if (bit != 0) @as(i8, 1) else @as(i8, -1));
    }
}

fn writePreparedLegacyBlock(
    kind: gguf_tensor_types.KnownTensorType,
    dest: []u8,
    raw_block: []const u8,
) void {
    std.debug.assert(dest.len == prepared_legacy_block_bytes);
    const d = decodeFp16Le(raw_block[0], raw_block[1]);
    const m: f32 = switch (kind) {
        .Q4_1, .Q5_1 => decodeFp16Le(raw_block[2], raw_block[3]),
        .Q4_0, .Q5_0 => 0.0,
        else => unreachable,
    };
    writeF32Le(dest[prepared_legacy_scale_offset..][0..4], d);
    writeF32Le(dest[prepared_legacy_min_offset..][0..4], m);
    const values = dest[prepared_legacy_values_offset..][0..prepared_legacy_values_bytes];
    switch (kind) {
        .Q4_0 => {
            std.debug.assert(raw_block.len == 18);
            const qs = raw_block[2..18];
            for (qs, 0..) |packed_byte, i| {
                values[i] = @bitCast(@as(i8, @intCast(@as(i32, packed_byte & 0x0F) - 8)));
                values[16 + i] = @bitCast(@as(i8, @intCast(@as(i32, packed_byte >> 4) - 8)));
            }
        },
        .Q4_1 => {
            std.debug.assert(raw_block.len == 20);
            const qs = raw_block[4..20];
            for (qs, 0..) |packed_byte, i| {
                values[i] = @intCast(packed_byte & 0x0F);
                values[16 + i] = @intCast(packed_byte >> 4);
            }
        },
        .Q5_0 => {
            std.debug.assert(raw_block.len == 22);
            const qh = std.mem.readInt(u32, raw_block[2..6], .little);
            const qs = raw_block[6..22];
            for (qs, 0..) |packed_byte, i| {
                const lo4: i32 = packed_byte & 0x0F;
                const hi4: i32 = packed_byte >> 4;
                const lo_hi1: i32 = @intCast((qh >> @as(u5, @intCast(i))) & 1);
                const hi_hi1: i32 = @intCast((qh >> @as(u5, @intCast(i + 16))) & 1);
                values[i] = @bitCast(@as(i8, @intCast((lo4 | (lo_hi1 << 4)) - 16)));
                values[16 + i] = @bitCast(@as(i8, @intCast((hi4 | (hi_hi1 << 4)) - 16)));
            }
        },
        .Q5_1 => {
            std.debug.assert(raw_block.len == 24);
            const qh = std.mem.readInt(u32, raw_block[4..8], .little);
            const qs = raw_block[8..24];
            for (qs, 0..) |packed_byte, i| {
                const lo4: i32 = packed_byte & 0x0F;
                const hi4: i32 = packed_byte >> 4;
                const lo_hi1: i32 = @intCast((qh >> @as(u5, @intCast(i))) & 1);
                const hi_hi1: i32 = @intCast((qh >> @as(u5, @intCast(i + 16))) & 1);
                values[i] = @intCast(lo4 | (lo_hi1 << 4));
                values[16 + i] = @intCast(hi4 | (hi_hi1 << 4));
            }
        },
        else => unreachable,
    }
}

fn writePreparedQ2KBlock(dest: []u8, raw_block: []const u8) void {
    std.debug.assert(dest.len == prepared_k16_block_bytes);
    std.debug.assert(raw_block.len == 84);
    const scales_raw = raw_block[0..16];
    const d = decodeFp16Le(raw_block[16], raw_block[17]);
    const dmin = decodeFp16Le(raw_block[18], raw_block[19]);
    const qs = raw_block[20..84];
    const values = dest[prepared_k16_values_offset..][0..prepared_k16_values_bytes];
    for (0..16) |sub| {
        const sc = @as(f32, @floatFromInt(scales_raw[sub] & 0x0F));
        const m = @as(f32, @floatFromInt(scales_raw[sub] >> 4));
        writeF32Le(dest[prepared_k16_dsc_offset + sub * 4 ..][0..4], d * sc);
        writeF32Le(dest[prepared_k16_dmn_offset + sub * 4 ..][0..4], dmin * m);
        const chunk = sub / 8;
        const group = (sub % 8) / 2;
        const l_base = (sub % 2) * 16;
        const q_base = chunk * 32;
        const shift: u3 = @intCast(group * 2);
        for (0..16) |i| {
            values[sub * 16 + i] = (qs[q_base + l_base + i] >> shift) & 0x03;
        }
    }
}

fn writePreparedQ3KBlock(dest: []u8, raw_block: []const u8) void {
    std.debug.assert(dest.len == prepared_k16_block_bytes);
    std.debug.assert(raw_block.len == 110);
    const hmask = raw_block[0..32];
    const qs = raw_block[32..96];
    const scale_data = raw_block[96..108];
    const d = decodeFp16Le(raw_block[108], raw_block[109]);
    var raw_scales: [16]i32 = undefined;
    for (0..4) |i| {
        raw_scales[i] = @as(i32, scale_data[i] & 0x0F) | (@as(i32, scale_data[8 + i] & 0x03) << 4);
        raw_scales[i + 4] = @as(i32, scale_data[4 + i] & 0x0F) | (@as(i32, (scale_data[8 + i] >> 2) & 0x03) << 4);
        raw_scales[i + 8] = @as(i32, (scale_data[i] >> 4) & 0x0F) | (@as(i32, (scale_data[8 + i] >> 4) & 0x03) << 4);
        raw_scales[i + 12] = @as(i32, (scale_data[4 + i] >> 4) & 0x0F) | (@as(i32, (scale_data[8 + i] >> 6) & 0x03) << 4);
    }
    const values = dest[prepared_k16_values_offset..][0..prepared_k16_values_bytes];
    for (0..16) |sub| {
        writeF32Le(dest[prepared_k16_dsc_offset + sub * 4 ..][0..4], d * @as(f32, @floatFromInt(raw_scales[sub] - 32)));
        writeF32Le(dest[prepared_k16_dmn_offset + sub * 4 ..][0..4], 0.0);
        const chunk = sub / 8;
        const group = (sub % 8) / 2;
        const l_base = (sub % 2) * 16;
        const q_base = chunk * 32;
        const shift: u3 = @intCast(group * 2);
        const hm_bit: u3 = @intCast(chunk * 4 + group);
        for (0..16) |i| {
            const l = l_base + i;
            const low2 = @as(i32, (qs[q_base + l] >> shift) & 0x03);
            const high1 = @as(i32, (hmask[l] >> hm_bit) & 0x01);
            values[sub * 16 + i] = @bitCast(@as(i8, @intCast(low2 + high1 * 4 - 4)));
        }
    }
}

