fn preparePreparedKPanel8PackedStorage(storage: *QuantizedStorage) !void {
    if (storage.preparedBytes(.panel8) != null) return;
    if (storage.packed_expert != null) return;
    if (storage.shape.len != 2 or storage.shape[0] <= 0 or storage.shape[1] <= 0) return;
    const prepared = storage.preparedBytes(.row_major_blocks) orelse return;
    const known = switch (storage.tensor_type) {
        .known => |value| value,
        else => return,
    };
    const out_dim: usize = @intCast(storage.shape[0]);
    const in_dim: usize = @intCast(storage.shape[1]);
    if (in_dim % 256 != 0) return;
    const row_blocks = in_dim / 256;
    if (prepared.len != out_dim * row_blocks * prepared_q4_k_block_bytes) return error.InvalidQuantizedDataSize;

    const panel_size = preparedKPanel8ByteSizeForKnown(known, out_dim, row_blocks);
    if (panel_size == 0) return;
    const panel = try storage.allocator.alloc(u8, panel_size);
    errdefer storage.allocator.free(panel);
    for (0..(out_dim / prepared_k_panel8_nr)) |panel_idx| {
        for (0..row_blocks) |block_idx| {
            if (known == .Q6_K) {
                const dest_base = (panel_idx * row_blocks + block_idx) * prepared_q6_k_panel8_block_bytes;
                inline for (0..prepared_k_panel8_nr) |lane| {
                    const out_row = panel_idx * prepared_k_panel8_nr + lane;
                    const src_base = (out_row * row_blocks + block_idx) * prepared_q4_k_block_bytes;
                    const src = prepared[src_base..][0..prepared_q4_k_block_bytes];
                    const raw_base = (out_row * row_blocks + block_idx) * 210;
                    const raw = storage.raw_bytes[raw_base..][0..210];
                    const d = decodeFp16Le(raw[208], raw[209]);
                    writeF32Le(panel[dest_base + prepared_q6_k_panel8_d_offset + lane * 4 ..][0..4], d);
                    for (0..16) |sub| {
                        panel[dest_base + prepared_q6_k_panel8_scales_offset + sub * prepared_k_panel8_nr + lane] = raw[192 + sub];
                        @memcpy(
                            panel[dest_base + prepared_q6_k_panel8_values_offset + (sub * prepared_k_panel8_nr + lane) * 16 ..][0..16],
                            src[prepared_q4_k_header_bytes + sub * 16 ..][0..16],
                        );
                    }
                }
            } else {
                const dest_base = (panel_idx * row_blocks + block_idx) * prepared_k_panel8_block_bytes;
                inline for (0..prepared_k_panel8_nr) |lane| {
                    const out_row = panel_idx * prepared_k_panel8_nr + lane;
                    const src_base = (out_row * row_blocks + block_idx) * prepared_q4_k_block_bytes;
                    const src = prepared[src_base..][0..prepared_q4_k_block_bytes];
                    for (0..8) |sub| {
                        @memcpy(
                            panel[dest_base + prepared_k_panel8_dsc_offset + (sub * prepared_k_panel8_nr + lane) * 4 ..][0..4],
                            src[prepared_q4_k_dsc_offset + sub * 4 ..][0..4],
                        );
                        @memcpy(
                            panel[dest_base + prepared_k_panel8_dmn_offset + (sub * prepared_k_panel8_nr + lane) * 4 ..][0..4],
                            src[prepared_q4_k_dmn_offset + sub * 4 ..][0..4],
                        );
                        @memcpy(
                            panel[dest_base + prepared_k_panel8_values_offset + (sub * prepared_k_panel8_nr + lane) * 32 ..][0..32],
                            src[prepared_q4_k_header_bytes + sub * 32 ..][0..32],
                        );
                    }
                }
            }
        }
    }
    storage.setPreparedBytes(.panel8, panel, prepared_k_panel8_nr, @intCast(row_blocks));
}

fn preparePreparedKPanel16PackedStorage(storage: *QuantizedStorage) !void {
    if (storage.preparedBytes(.panel16) != null) return;
    if (storage.packed_expert != null) return;
    if (storage.shape.len != 2 or storage.shape[0] <= 0 or storage.shape[1] <= 0) return;
    const prepared = storage.preparedBytes(.row_major_blocks) orelse return;
    const known = switch (storage.tensor_type) {
        .known => |value| value,
        else => return,
    };
    if (known != .Q4_K and known != .Q5_K and known != .Q6_K) return;
    const out_dim: usize = @intCast(storage.shape[0]);
    const in_dim: usize = @intCast(storage.shape[1]);
    if (in_dim % 256 != 0) return;
    const row_blocks = in_dim / 256;
    if (prepared.len != out_dim * row_blocks * prepared_q4_k_block_bytes) return error.InvalidQuantizedDataSize;

    const panel_size = preparedKPanel16ByteSize(out_dim, row_blocks);
    if (panel_size == 0) return;
    const panel = try storage.allocator.alloc(u8, panel_size);
    errdefer storage.allocator.free(panel);
    for (0..(out_dim / prepared_k_panel16_nr)) |panel_idx| {
        for (0..row_blocks) |block_idx| {
            const dest_base = (panel_idx * row_blocks + block_idx) * prepared_k_panel16_block_bytes;
            inline for (0..prepared_k_panel16_nr) |lane| {
                const out_row = panel_idx * prepared_k_panel16_nr + lane;
                const src_base = (out_row * row_blocks + block_idx) * prepared_q4_k_block_bytes;
                const src = prepared[src_base..][0..prepared_q4_k_block_bytes];
                if (known == .Q6_K) {
                    for (0..16) |sub| {
                        @memcpy(
                            panel[dest_base + prepared_k_panel16_dsc_offset + (sub * prepared_k_panel16_nr + lane) * 4 ..][0..4],
                            src[prepared_q4_k_dsc_offset + sub * 4 ..][0..4],
                        );
                        @memcpy(
                            panel[dest_base + prepared_k_panel16_values_offset + (sub * prepared_k_panel16_nr + lane) * 16 ..][0..16],
                            src[prepared_q4_k_header_bytes + sub * 16 ..][0..16],
                        );
                    }
                } else {
                    for (0..8) |sub| {
                        @memcpy(
                            panel[dest_base + prepared_k_panel16_dsc_offset + (sub * prepared_k_panel16_nr + lane) * 4 ..][0..4],
                            src[prepared_q4_k_dsc_offset + sub * 4 ..][0..4],
                        );
                        @memcpy(
                            panel[dest_base + prepared_k_panel16_dmn_offset + (sub * prepared_k_panel16_nr + lane) * 4 ..][0..4],
                            src[prepared_q4_k_dmn_offset + sub * 4 ..][0..4],
                        );
                        @memcpy(
                            panel[dest_base + prepared_k_panel16_values_offset + (sub * prepared_k_panel16_nr + lane) * 32 ..][0..32],
                            src[prepared_q4_k_header_bytes + sub * 32 ..][0..32],
                        );
                    }
                }
            }
        }
    }
    storage.setPreparedBytes(.panel16, panel, prepared_k_panel16_nr, @intCast(row_blocks));
}

fn clearPreparedGroupCache(storage: *QuantizedStorage) usize {
    if (storage.prepared_group_cache) |*cache| {
        const released = cache.ownedBytes();
        cache.deinit(storage.allocator);
        storage.prepared_group_cache = null;
        return released;
    }
    return 0;
}

fn preparedQKVPanel16GroupCacheMatches(storage: *const QuantizedStorage, key_b: []const u8, key_c: []const u8, expected_bytes: usize, row_blocks: usize) bool {
    const cache = storage.prepared_group_cache orelse return false;
    if (cache.format != .panel16_projection_group) return false;
    if (cache.projection_count != prepared_k_qkv_panel16_proj) return false;
    if (cache.panel_cols != prepared_k_panel16_nr) return false;
    if (cache.row_blocks != row_blocks) return false;
    if (cache.packed_bytes.len != expected_bytes) return false;
    if (cache.partner_count != 2) return false;
    const keys = cache.partnerKeys();
    return std.mem.eql(u8, keys[0], key_b) and std.mem.eql(u8, keys[1], key_c);
}

fn preparedQKVPanel16GroupPackedBytes(storage: *const QuantizedStorage, out_dim: usize, row_blocks: usize) ?[]const u8 {
    const expected_bytes = preparedKQKVPanel16ByteSize(out_dim, row_blocks);
    const cache = storage.prepared_group_cache orelse return null;
    if (cache.format != .panel16_projection_group) return null;
    if (cache.projection_count != prepared_k_qkv_panel16_proj) return null;
    if (cache.panel_cols != prepared_k_panel16_nr) return null;
    if (cache.row_blocks != row_blocks) return null;
    if (cache.packed_bytes.len != expected_bytes) return null;
    return cache.packed_bytes;
}

fn prepareQ4Q5QKVPanel16PackedStorage(
    storage_a: *QuantizedStorage,
    panel16_a: []const u8,
    panel16_b: []const u8,
    panel16_c: []const u8,
    key_b: []const u8,
    key_c: []const u8,
    out_dim: usize,
    row_blocks: usize,
) !usize {
    const expected_single = preparedKPanel16ByteSize(out_dim, row_blocks);
    if (panel16_a.len != expected_single or panel16_b.len != expected_single or panel16_c.len != expected_single) return error.InvalidQuantizedDataSize;
    const expected_bytes = preparedKQKVPanel16ByteSize(out_dim, row_blocks);
    if (expected_bytes == 0) return 0;
    if (preparedQKVPanel16GroupCacheMatches(storage_a, key_b, key_c, expected_bytes, row_blocks)) return 0;
    _ = clearPreparedGroupCache(storage_a);

    const packed_bytes = try storage_a.allocator.alloc(u8, expected_bytes);
    errdefer storage_a.allocator.free(packed_bytes);
    const key_b_copy = try storage_a.allocator.dupe(u8, key_b);
    errdefer storage_a.allocator.free(key_b_copy);
    const key_c_copy = try storage_a.allocator.dupe(u8, key_c);
    errdefer storage_a.allocator.free(key_c_copy);

    const panel_count = out_dim / prepared_k_panel16_nr;
    for (0..panel_count) |panel_idx| {
        for (0..row_blocks) |block_idx| {
            const src_off = (panel_idx * row_blocks + block_idx) * prepared_k_panel16_block_bytes;
            const dest_off = (panel_idx * row_blocks + block_idx) * prepared_k_qkv_panel16_block_bytes;
            const panels = [_][]const u8{
                panel16_a[src_off..][0..prepared_k_panel16_block_bytes],
                panel16_b[src_off..][0..prepared_k_panel16_block_bytes],
                panel16_c[src_off..][0..prepared_k_panel16_block_bytes],
            };
            inline for (0..8) |sub| {
                inline for (0..prepared_k_qkv_panel16_proj) |proj| {
                    const src = panels[proj];
                    const src_meta_off = sub * prepared_k_panel16_nr * 4;
                    const dest_meta_off = (sub * prepared_k_qkv_panel16_proj + proj) * prepared_k_panel16_nr * 4;
                    @memcpy(
                        packed_bytes[dest_off + prepared_k_qkv_panel16_dsc_offset + dest_meta_off ..][0 .. prepared_k_panel16_nr * 4],
                        src[prepared_k_panel16_dsc_offset + src_meta_off ..][0 .. prepared_k_panel16_nr * 4],
                    );
                    @memcpy(
                        packed_bytes[dest_off + prepared_k_qkv_panel16_dmn_offset + dest_meta_off ..][0 .. prepared_k_panel16_nr * 4],
                        src[prepared_k_panel16_dmn_offset + src_meta_off ..][0 .. prepared_k_panel16_nr * 4],
                    );
                    const src_values_off = sub * prepared_k_panel16_nr * 32;
                    const dest_values_off = (sub * prepared_k_qkv_panel16_proj + proj) * prepared_k_panel16_nr * 32;
                    @memcpy(
                        packed_bytes[dest_off + prepared_k_qkv_panel16_values_offset + dest_values_off ..][0 .. prepared_k_panel16_nr * 32],
                        src[prepared_k_panel16_values_offset + src_values_off ..][0 .. prepared_k_panel16_nr * 32],
                    );
                }
            }
        }
    }

    storage_a.prepared_group_cache = .{
        .format = .panel16_projection_group,
        .packed_bytes = packed_bytes,
        .partner_keys = .{ key_b_copy, key_c_copy },
        .partner_count = 2,
        .projection_count = prepared_k_qkv_panel16_proj,
        .panel_cols = prepared_k_panel16_nr,
        .row_blocks = @intCast(row_blocks),
    };
    return expected_bytes + key_b_copy.len + key_c_copy.len;
}

pub fn prepareQ4Q5QKVPanel16PackedStorageForBench(
    storage_a: *QuantizedStorage,
    storage_b: *const QuantizedStorage,
    storage_c: *const QuantizedStorage,
    key_b: []const u8,
    key_c: []const u8,
) !void {
    if (!storage_a.tensor_type.eql(storage_b.tensor_type) or !storage_a.tensor_type.eql(storage_c.tensor_type)) return error.InvalidQuantizedLinearShape;
    const known = switch (storage_a.tensor_type) {
        .known => |value| value,
        else => return error.UnsupportedQuantLinearBenchType,
    };
    if (known != .Q4_K and known != .Q5_K) return error.UnsupportedQuantLinearBenchType;
    if (storage_a.shape.len != 2 or storage_b.shape.len != 2 or storage_c.shape.len != 2) return error.InvalidQuantizedLinearShape;
    if (storage_a.shape[0] != storage_b.shape[0] or storage_a.shape[1] != storage_b.shape[1] or
        storage_a.shape[0] != storage_c.shape[0] or storage_a.shape[1] != storage_c.shape[1])
    {
        return error.InvalidQuantizedLinearShape;
    }
    const out_dim: usize = @intCast(storage_a.shape[0]);
    const in_dim: usize = @intCast(storage_a.shape[1]);
    if (in_dim % 256 != 0) return error.InvalidQuantizedLinearShape;
    _ = try prepareQ4Q5QKVPanel16PackedStorage(
        storage_a,
        storage_a.preparedBytes(.panel16) orelse return error.UnsupportedQuantLinearBenchType,
        storage_b.preparedBytes(.panel16) orelse return error.UnsupportedQuantLinearBenchType,
        storage_c.preparedBytes(.panel16) orelse return error.UnsupportedQuantLinearBenchType,
        key_b,
        key_c,
        out_dim,
        in_dim / 256,
    );
}

fn canPrepareQ4Q5QKVPanel16Cache(
    storage_a: *const QuantizedStorage,
    storage_b: *const QuantizedStorage,
    storage_c: *const QuantizedStorage,
    key_b: []const u8,
    key_c: []const u8,
    in_dim: usize,
    out_dim: usize,
    rows: usize,
) bool {
    if (!useQ4Q5Panel16DirectForShape(rows, out_dim, in_dim / 256, true)) return false;
    if (key_b.len == 0 or key_c.len == 0) return false;
    if (!storage_a.tensor_type.eql(storage_b.tensor_type) or !storage_a.tensor_type.eql(storage_c.tensor_type)) return false;
    const known = switch (storage_a.tensor_type) {
        .known => |value| value,
        else => return false,
    };
    if (known != .Q4_K and known != .Q5_K) return false;
    if (!useQ4Q5PackedQKVPanel16ForShape(rows, out_dim, known)) return false;
    if (storage_a.packed_expert != null or storage_b.packed_expert != null or storage_c.packed_expert != null) return false;
    if (storage_a.shape.len != 2 or storage_b.shape.len != 2 or storage_c.shape.len != 2) return false;
    if (storage_a.shape[0] != out_dim or storage_a.shape[1] != in_dim) return false;
    if (storage_b.shape[0] != out_dim or storage_b.shape[1] != in_dim) return false;
    if (storage_c.shape[0] != out_dim or storage_c.shape[1] != in_dim) return false;
    if (in_dim % 256 != 0 or out_dim % prepared_k_panel16_nr != 0) return false;
    return storage_a.preparedBytes(.panel16) != null and
        storage_b.preparedBytes(.panel16) != null and
        storage_c.preparedBytes(.panel16) != null;
}

fn ensureQ4Q5QKVPanel16Cache(
    self: *NativeCompute,
    weight_buf_a: *const Buf,
    weight_buf_b: *const Buf,
    weight_buf_c: *const Buf,
    storage_a_const: *const QuantizedStorage,
    storage_b: *const QuantizedStorage,
    storage_c: *const QuantizedStorage,
    in_dim: usize,
    out_dim: usize,
    rows: usize,
) !void {
    if (!canPrepareQ4Q5QKVPanel16Cache(storage_a_const, storage_b, storage_c, weight_buf_b.name, weight_buf_c.name, in_dim, out_dim, rows)) return;

    const row_blocks = in_dim / 256;
    const expected_bytes = preparedKQKVPanel16ByteSize(out_dim, row_blocks);
    if (expected_bytes == 0) return;
    if (preparedQKVPanel16GroupCacheMatches(storage_a_const, weight_buf_b.name, weight_buf_c.name, expected_bytes, row_blocks)) return;

    while (!self.data.quantized_prepare_lock.tryLock()) {
        std.Thread.yield() catch {};
    }
    defer self.data.quantized_prepare_lock.unlock();

    const storage_a = @constCast(storage_a_const);
    if (!canPrepareQ4Q5QKVPanel16Cache(storage_a, storage_b, storage_c, weight_buf_b.name, weight_buf_c.name, in_dim, out_dim, rows)) return;
    if (preparedQKVPanel16GroupCacheMatches(storage_a, weight_buf_b.name, weight_buf_c.name, expected_bytes, row_blocks)) return;

    const released_bytes = clearPreparedGroupCache(storage_a);
    if (released_bytes != 0) {
        if (self.data.tier_cache) |*tier_cache| tier_cache.noteRelease(.host, released_bytes);
        if (weight_buf_a.lazy_entry) |entry| entry.loaded_bytes = quantizedStorageBudgetBytes(storage_a);
    }

    if (self.data.tier_cache) |*tier_cache| {
        evictColdNonExpertWeightsToFitLocked(self.data, .host, expected_bytes, weight_buf_a.lazy_entry);
        if (!tier_cache.canFitAdditional(.host, expected_bytes)) {
            tier_cache.noteDenied(.host, expected_bytes);
            noteSharedCacheDenial(self.run_budget, tier_cache, .host, expected_bytes);
            logSharedCacheDenial("q4q5_qkv_panel16_cache", tier_cache, weight_buf_a.name);
            return;
        }
    }

    const inserted_bytes = try prepareQ4Q5QKVPanel16PackedStorage(
        storage_a,
        storage_a.preparedBytes(.panel16).?,
        storage_b.preparedBytes(.panel16).?,
        storage_c.preparedBytes(.panel16).?,
        weight_buf_b.name,
        weight_buf_c.name,
        out_dim,
        row_blocks,
    );
    if (inserted_bytes != 0) {
        if (self.data.tier_cache) |*tier_cache| tier_cache.noteResident(.host, inserted_bytes);
        if (weight_buf_a.lazy_entry) |entry| entry.loaded_bytes = quantizedStorageBudgetBytes(storage_a);
    }
}

fn prepareQ8_KPanelPackedStorage(storage: *QuantizedStorage) !void {
    if (storage.preparedBytes(.panel4) != null) return;
    if (storage.packed_expert != null) return;
    if (storage.shape.len != 2 or storage.shape[0] <= 0 or storage.shape[1] <= 0) return;
    const out_dim: usize = @intCast(storage.shape[0]);
    const in_dim: usize = @intCast(storage.shape[1]);
    if (in_dim % 256 != 0) return;
    const row_blocks = in_dim / 256;
    const block_size: usize = 292;
    if (storage.raw_bytes.len != out_dim * row_blocks * block_size) return error.InvalidQuantizedDataSize;

    const panel_size = preparedQ8_KPanelByteSize(out_dim, row_blocks);
    if (panel_size == 0) return;
    const panel = try storage.allocator.alloc(u8, panel_size);
    errdefer storage.allocator.free(panel);
    for (0..(out_dim / prepared_q8_0_panel_nr)) |panel_idx| {
        for (0..row_blocks) |block_idx| {
            const dest_base = (panel_idx * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
            inline for (0..prepared_q8_0_panel_nr) |lane| {
                const out_row = panel_idx * prepared_q8_0_panel_nr + lane;
                const src_base = (out_row * row_blocks + block_idx) * block_size;
                @memcpy(panel[dest_base + lane * block_size ..][0..block_size], storage.raw_bytes[src_base..][0..block_size]);
            }
        }
    }
    storage.setPreparedBytes(.panel4, panel, prepared_q8_0_panel_nr, @intCast(row_blocks));
}

