fn writeF32Le(dest: []u8, value: f32) void {
    std.debug.assert(dest.len == 4);
    std.mem.writeInt(u32, dest[0..4], @bitCast(value), .little);
}

const readF32Le = quant_codec.readF32Le;

inline fn readF32x4Le(bytes: []const u8) F32x4 {
    std.debug.assert(bytes.len >= 16);
    return .{
        readF32Le(bytes[0..4]),
        readF32Le(bytes[4..8]),
        readF32Le(bytes[8..12]),
        readF32Le(bytes[12..16]),
    };
}

inline fn readF32x8Le(bytes: []const u8) F32x8 {
    std.debug.assert(bytes.len >= 32);
    return .{
        readF32Le(bytes[0..4]),
        readF32Le(bytes[4..8]),
        readF32Le(bytes[8..12]),
        readF32Le(bytes[12..16]),
        readF32Le(bytes[16..20]),
        readF32Le(bytes[20..24]),
        readF32Le(bytes[24..28]),
        readF32Le(bytes[28..32]),
    };
}

inline fn i32ArrayToVec8(values: [8]i32) I32x8 {
    return .{
        values[0],
        values[1],
        values[2],
        values[3],
        values[4],
        values[5],
        values[6],
        values[7],
    };
}

inline fn f32x8ToArray(values: F32x8) [8]f32 {
    return .{
        values[0],
        values[1],
        values[2],
        values[3],
        values[4],
        values[5],
        values[6],
        values[7],
    };
}

fn preparedQ4KDsc(prepared_block: []const u8, sub: usize) f32 {
    return readF32Le(prepared_block[prepared_q4_k_dsc_offset + sub * 4 ..][0..4]);
}

fn preparedQ4KDmn(prepared_block: []const u8, sub: usize) f32 {
    return readF32Le(prepared_block[prepared_q4_k_dmn_offset + sub * 4 ..][0..4]);
}

inline fn q8_0BlockSize(comptime prepared: bool) usize {
    return if (prepared) prepared_q8_0_block_bytes else 34;
}

inline fn q8_0WeightScale(comptime prepared: bool, block: []const u8) f32 {
    return if (prepared)
        readF32Le(block[prepared_q8_0_scale_offset..][0..4])
    else
        decodeFp16Le(block[0], block[1]);
}

inline fn q8_0WeightValues(comptime prepared: bool, block: []const u8) *const [32]u8 {
    return if (prepared)
        block[prepared_q8_0_values_offset..][0..prepared_q8_0_values_bytes]
    else
        block[2..34];
}

fn linearNoBiasQ4KPrepared(
    io: ?std.Io,
    input: []const f32,
    prepared_blocks: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    if (try linearNoBiasQ4KPreparedParallel(io, input, prepared_blocks, output, rows, in_dim, out_dim)) {
        return;
    }
    try linearNoBiasQ4KPreparedTiled(input, prepared_blocks, output, rows, in_dim, out_dim);
}

fn linearQ4KPreparedTriple(
    io: ?std.Io,
    input: []const f32,
    prepared_blocks_a: []const u8,
    prepared_blocks_b: []const u8,
    prepared_blocks_c: []const u8,
    bias_a: ?[]const f32,
    bias_b: ?[]const f32,
    bias_c: ?[]const f32,
    output_a: []f32,
    output_b: []f32,
    output_c: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    if (try linearQ4KPreparedTripleParallel(
        io,
        input,
        prepared_blocks_a,
        prepared_blocks_b,
        prepared_blocks_c,
        bias_a,
        bias_b,
        bias_c,
        output_a,
        output_b,
        output_c,
        rows,
        in_dim,
        out_dim,
    )) {
        return;
    }
    try linearQ4KPreparedTripleFusedRange(
        input,
        prepared_blocks_a,
        prepared_blocks_b,
        prepared_blocks_c,
        bias_a,
        bias_b,
        bias_c,
        output_a,
        output_b,
        output_c,
        rows,
        in_dim,
        out_dim,
        0,
        out_dim,
    );
}

const max_q4_k_parallel_workers = linalg.pool.max_workers;
const quant_col_parallel_max_rows = 2;
const quant_col_parallel_dispatch_max_rows = 384;
const quant_col_parallel_min_out_dim = 512;
const quant_col_parallel_min_cols_per_worker = 64;
const small_row_q8_0_stack_max_in_dim = 4096;
const small_row_q8_k_stack_max_in_dim = 4096;
const q8_k_prepared_sum_stack_max_row_blocks = small_row_q8_k_stack_max_in_dim / 256;

const QuantLinearParallelPlan = struct {
    worker_count: usize = 1,

    fn disabled() QuantLinearParallelPlan {
        return .{
            .worker_count = 1,
        };
    }
};

// Compact representation of a worker's row range.  All four quantised
// linear dispatchers (Q4K-prepared, Q8_0, generic, generic-pair) used to
// duplicate the divCeil + bounds-check loop verbatim; centralising it
// here removes ~10 lines per dispatcher and makes the chunking strategy
// a single place to evolve (e.g. when MR>1 wants row-aligned chunks).
const QuantRowChunk = struct { start: usize, end: usize };
const QuantColChunk = struct { start: usize, end: usize };

fn chunkRowsForWorkers(
    rows: usize,
    plan: QuantLinearParallelPlan,
    out: *[max_q4_k_parallel_workers]QuantRowChunk,
) usize {
    var count: usize = 0;
    if (plan.worker_count == 0 or rows == 0) return 0;
    const rows_per_worker = std.math.divCeil(usize, rows, plan.worker_count) catch unreachable;
    for (0..plan.worker_count) |worker_idx| {
        const start = worker_idx * rows_per_worker;
        if (start >= rows) break;
        const end = @min(rows, start + rows_per_worker);
        out[count] = .{ .start = start, .end = end };
        count += 1;
    }
    return count;
}

fn chunkRowsForWorkersAligned(
    rows: usize,
    plan: QuantLinearParallelPlan,
    comptime align_rows: usize,
    out: *[max_q4_k_parallel_workers]QuantRowChunk,
) usize {
    if (align_rows <= 1 or plan.worker_count <= 1) return chunkRowsForWorkers(rows, plan, out);
    if (rows <= align_rows) return chunkRowsForWorkers(rows, plan, out);

    const rows_per_worker = std.math.divCeil(usize, rows, plan.worker_count) catch unreachable;
    const aligned_rows_per_worker = std.mem.alignForward(usize, @max(rows_per_worker, align_rows), align_rows);

    var count: usize = 0;
    var start: usize = 0;
    while (start < rows and count < plan.worker_count) {
        const remaining = rows - start;
        const end = if (count + 1 == plan.worker_count or remaining <= aligned_rows_per_worker + align_rows)
            rows
        else
            start + aligned_rows_per_worker;
        out[count] = .{ .start = start, .end = end };
        count += 1;
        start = end;
    }
    return count;
}

fn chunkColsForWorkers(
    out_dim: usize,
    plan: QuantLinearParallelPlan,
    out: *[max_q4_k_parallel_workers]QuantColChunk,
) usize {
    var count: usize = 0;
    if (plan.worker_count == 0 or out_dim == 0) return 0;
    const cols_per_worker = std.math.divCeil(usize, out_dim, plan.worker_count) catch unreachable;
    for (0..plan.worker_count) |worker_idx| {
        const start = worker_idx * cols_per_worker;
        if (start >= out_dim) break;
        const end = @min(out_dim, start + cols_per_worker);
        out[count] = .{ .start = start, .end = end };
        count += 1;
    }
    return count;
}

// Run the dispatched jobs and surface the first error any worker
// recorded into its `err` slot.  Each worker context type carries an
// `err: ?anyerror` field; this helper keeps the per-dispatcher tail
// boilerplate down to one call.
//
// When `io` is non-null, work routes through `pool.dispatchJobsIo` so it
// schedules on the caller's runtime thread pool and inherits cancellation
// semantics (matches the sgemm Io-vs-Sync split).  When null, falls back
// to the persistent futex pool -- the path tests, leaf benches, and any
// caller without an Io use.
fn dispatchAndCheckQuantWorkers(
    io: ?std.Io,
    jobs: []const linalg.pool.Job,
    contexts: anytype,
) !void {
    if (io) |runtime_io| {
        try linalg.pool.dispatchJobsIo(runtime_io, jobs);
    } else {
        linalg.pool.dispatchJobs(jobs);
    }
    for (contexts) |ctx| {
        if (ctx.err) |err| return err;
    }
}

