fn chooseQuantLinearParallelPlan(
    requested: bool,
    rows: usize,
    out_dim: usize,
    row_blocks: usize,
    max_workers: usize,
) QuantLinearParallelPlan {
    if (!requested) return .disabled();
    if (rows == 0 or out_dim == 0 or row_blocks == 0) return .disabled();

    const cpu_count = std.Thread.getCpuCount() catch 1;
    const capped_cpu_count = @max(@as(usize, 1), @min(cpu_count, max_workers));
    if (capped_cpu_count <= 1) return .disabled();

    const work_units = rows * out_dim * row_blocks;
    const min_work_units_per_worker = quantParallelMinWorkUnitsPerWorker();
    if (work_units < min_work_units_per_worker) return .disabled();
    return .{
        .worker_count = @min(capped_cpu_count, rows),
    };
}

fn chooseQuantLinearColumnParallelPlan(
    requested: bool,
    dispatch_available: bool,
    rows: usize,
    out_dim: usize,
    row_blocks: usize,
    max_workers: usize,
) QuantLinearParallelPlan {
    return chooseQuantLinearColumnParallelPlanWithMaxRows(
        requested,
        rows,
        out_dim,
        row_blocks,
        max_workers,
        quantColumnParallelMaxRows(dispatch_available),
    );
}

fn chooseQuantLinearColumnParallelPlanWithMaxRows(
    requested: bool,
    rows: usize,
    out_dim: usize,
    row_blocks: usize,
    max_workers: usize,
    max_rows: usize,
) QuantLinearParallelPlan {
    if (!requested) return .disabled();
    if (rows == 0 or out_dim == 0 or row_blocks == 0) return .disabled();
    if (rows > max_rows) return .disabled();
    if (out_dim < quant_col_parallel_min_out_dim) return .disabled();

    const cpu_count = std.Thread.getCpuCount() catch 1;
    const capped_cpu_count = @max(@as(usize, 1), @min(cpu_count, max_workers));
    if (capped_cpu_count <= 1) return .disabled();

    const work_units = rows * out_dim * row_blocks;
    const min_work_units_per_worker = quantParallelMinWorkUnitsPerWorker();
    if (work_units < min_work_units_per_worker) return .disabled();

    const worker_count = @min(capped_cpu_count, out_dim / quant_col_parallel_min_cols_per_worker);
    if (worker_count <= 1) return .disabled();
    return .{ .worker_count = worker_count };
}

fn chooseActivationQuantParallelPlan(
    requested: bool,
    rows: usize,
    in_dim: usize,
    max_workers: usize,
) QuantLinearParallelPlan {
    if (!requested) return .disabled();
    if (rows == 0 or in_dim == 0) return .disabled();

    const cpu_count = std.Thread.getCpuCount() catch 1;
    const capped_cpu_count = @max(@as(usize, 1), @min(cpu_count, max_workers));
    if (capped_cpu_count <= 1) return .disabled();

    const work_units = rows * in_dim;
    if (work_units < quantParallelMinWorkUnitsPerWorker()) return .disabled();
    return .{ .worker_count = @min(capped_cpu_count, rows) };
}

