            "q4k_triple_parallel workers={d} rows={d} out={d} row_blocks={d}\n",
            .{ plan.worker_count, rows, out_dim, row_blocks },
        );
    }

    var chunks: [max_q4_k_parallel_workers]QuantRowChunk = undefined;
    const num_chunks = chunkRowsForWorkers(rows, plan, &chunks);
    var contexts: [max_q4_k_parallel_workers]Q4KPreparedTripleWorkerCtx = undefined;
    var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
    for (chunks[0..num_chunks], 0..) |chunk, i| {
        contexts[i] = .{
            .input = input[chunk.start * in_dim .. chunk.end * in_dim],
            .prepared_blocks_a = prepared_blocks_a,
            .prepared_blocks_b = prepared_blocks_b,
            .prepared_blocks_c = prepared_blocks_c,
            .bias_a = bias_a,
            .bias_b = bias_b,
            .bias_c = bias_c,
            .output_a = output_a[chunk.start * out_dim .. chunk.end * out_dim],
            .output_b = output_b[chunk.start * out_dim .. chunk.end * out_dim],
            .output_c = output_c[chunk.start * out_dim .. chunk.end * out_dim],
            .rows = chunk.end - chunk.start,
            .in_dim = in_dim,
            .out_dim = out_dim,
            .out_start = 0,
            .out_end = out_dim,
            .err = null,
        };
        jobs[i] = .{ .fn_ptr = q4KPreparedTripleWorkerJob, .ctx = @ptrCast(&contexts[i]) };
    }
    try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
    return true;
}

// Adapter that turns the existing `q4KPreparedWorker(ctx: *Ctx)` into a
// `pool.Job.fn_ptr` (`fn(*anyopaque) void`).  Defining one tiny adapter
// per worker keeps `q4KPreparedWorker` pure-data and reusable.
fn q4KPreparedWorkerJob(raw: *anyopaque) void {
    q4KPreparedWorker(@ptrCast(@alignCast(raw)));
}

fn q6KPreparedWorkerJob(raw: *anyopaque) void {
    q6KPreparedWorker(@ptrCast(@alignCast(raw)));
}

fn q4KPreparedTripleWorkerJob(raw: *anyopaque) void {
    q4KPreparedTripleWorker(@ptrCast(@alignCast(raw)));
}

fn genericQuantPairDotFn(
    tensor_type: gguf_tensor_types.TensorType,
) ?*const fn ([]const f32, []const u8) f32 {
    return switch (tensor_type) {
        .known => |known| switch (known) {
            .Q1_0 => &dotQ1_0Block,
            .Q4_0 => &dotQ4_0Block,
            .Q4_1 => &dotQ4_1Block,
            .Q5_0 => &dotQ5_0Block,
            .Q5_1 => &dotQ5_1Block,
            .Q8_0 => &dotQ8_0Block,
            .Q8_1 => &dotQ8_1Block,
            .Q2_K => &dotQ2_KBlock,
            .Q3_K => &dotQ3_KBlock,
            .Q4_K => &dotQ4_KBlock,
            .Q5_K => &dotQ5_KBlock,
            .Q6_K => &dotQ6_KBlock,
            .Q8_K => &dotQ8_KBlock,
            .IQ4_NL => &dotIQ4NLBlock,
            .IQ4_XS => &dotIQ4XSBlock,
            else => null,
        },
        else => null,
    };
}

fn linearNoBiasQuantizedGenericParallel(
    io: ?std.Io,
    input: []const f32,
    weight_raw: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    row_blocks: usize,
    block_size: usize,
    values_per_block: usize,
    row_stride: usize,
    dot_fn: *const fn ([]const f32, []const u8) f32,
) !bool {
    const col_plan = chooseQuantLinearColumnParallelPlan(
        quantParallelEnabled(),
        quantParallelDispatchAvailable(io),
        rows,
        out_dim,
        row_blocks,
        quantParallelMaxWorkers(),
    );
    if (col_plan.worker_count > 1) {
        if (quantParallelDebugRequested()) {
            std.debug.print(
                "generic_quant_parallel_cols workers={d} rows={d} out={d} row_blocks={d}\n",
                .{ col_plan.worker_count, rows, out_dim, row_blocks },
            );
        }
        var chunks: [max_q4_k_parallel_workers]QuantColChunk = undefined;
        const num_chunks = chunkColsForWorkers(out_dim, col_plan, &chunks);
        var contexts: [max_q4_k_parallel_workers]QuantizedLinearWorkerCtx = undefined;
        var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
        for (chunks[0..num_chunks], 0..) |chunk, i| {
            contexts[i] = .{
                .input = input,
                .weight_raw = weight_raw,
                .output = output,
                .rows = rows,
                .in_dim = in_dim,
                .out_dim = out_dim,
                .out_start = chunk.start,
                .out_end = chunk.end,
                .block_size = block_size,
                .values_per_block = values_per_block,
                .row_stride = row_stride,
                .dot_fn = dot_fn,
                .err = null,
            };
            jobs[i] = .{ .fn_ptr = quantizedLinearWorkerJob, .ctx = @ptrCast(&contexts[i]) };
        }
        try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
        return true;
    }

    const plan = chooseQuantLinearParallelPlan(
        quantParallelEnabled(),
        rows,
        out_dim,
        row_blocks,
        quantParallelMaxWorkers(),
    );
    if (plan.worker_count <= 1) return false;
    if (quantParallelDebugRequested()) {
        std.debug.print(
            "generic_quant_parallel workers={d} rows={d} out={d} row_blocks={d}\n",
            .{ plan.worker_count, rows, out_dim, row_blocks },
        );
    }

    var chunks: [max_q4_k_parallel_workers]QuantRowChunk = undefined;
    const num_chunks = chunkRowsForWorkers(rows, plan, &chunks);
    var contexts: [max_q4_k_parallel_workers]QuantizedLinearWorkerCtx = undefined;
    var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
    for (chunks[0..num_chunks], 0..) |chunk, i| {
        contexts[i] = .{
            .input = input[chunk.start * in_dim .. chunk.end * in_dim],
            .weight_raw = weight_raw,
            .output = output[chunk.start * out_dim .. chunk.end * out_dim],
            .rows = chunk.end - chunk.start,
            .in_dim = in_dim,
            .out_dim = out_dim,
            .out_start = 0,
            .out_end = out_dim,
            .block_size = block_size,
            .values_per_block = values_per_block,
            .row_stride = row_stride,
            .dot_fn = dot_fn,
            .err = null,
        };
        jobs[i] = .{ .fn_ptr = quantizedLinearWorkerJob, .ctx = @ptrCast(&contexts[i]) };
    }
    try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
    return true;
}

