fn linearNoBiasQ4KPreparedTiled(
    input: []const f32,
    prepared_blocks: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    try linearQ4KPreparedTiledRange(input, prepared_blocks, output, rows, in_dim, out_dim, 0, out_dim);
}

fn linearQ4KPreparedTiledRange(
    input: []const f32,
    prepared_blocks: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) !void {
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q4_K };
    const values_per_block = gguf_tensor_types.valuesPerBlock(tensor_type).?;
    const prepared_row_stride = (in_dim / values_per_block) * prepared_q4_k_block_bytes;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    if (prepared_blocks.len != out_dim * prepared_row_stride) return error.InvalidQuantizedDataSize;
    if (out_start > out_end or out_end > out_dim) return error.InvalidQuantizedLinearShape;

    // MR=2 row tile: process row pairs together so each prepared block's
    // dequant work is amortised across two input rows (halves total dequant
    // work).  Last row handled by the MR=1 path below if `rows` is odd.
    var r: usize = 0;
    while (r + 2 <= rows) : (r += 2) {
        processQ4KRowPair(
            input,
            prepared_blocks,
            output,
            r,
            in_dim,
            out_dim,
            out_start,
            out_end,
            prepared_row_stride,
            row_blocks,
            values_per_block,
        );
    }
    if (r < rows) {
        processQ4KRowSingle(
            input,
            prepared_blocks,
            output,
            r,
            in_dim,
            out_dim,
            out_start,
            out_end,
            prepared_row_stride,
            row_blocks,
            values_per_block,
        );
    }
}

fn linearNoBiasQ6KPrepared(
    io: ?std.Io,
    input: []const f32,
    prepared_blocks: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    if (try linearNoBiasQ6KPreparedParallel(io, input, prepared_blocks, output, rows, in_dim, out_dim)) {
        return;
    }
    try linearQ6KPreparedTiledRange(input, prepared_blocks, output, rows, in_dim, out_dim, 0, out_dim);
}

fn linearQ6KPreparedTiledRange(
    input: []const f32,
    prepared_blocks: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) !void {
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q6_K };
    const values_per_block = gguf_tensor_types.valuesPerBlock(tensor_type).?;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    const prepared_row_stride = row_blocks * prepared_q4_k_block_bytes;
    if (prepared_blocks.len != out_dim * prepared_row_stride) return error.InvalidQuantizedDataSize;
    if (out_start > out_end or out_end > out_dim) return error.InvalidQuantizedLinearShape;

    var r: usize = 0;
    while (r + 2 <= rows) : (r += 2) {
        processQ6KRowPair(
            input,
            prepared_blocks,
            output,
            r,
            in_dim,
            out_dim,
            out_start,
            out_end,
            prepared_row_stride,
            row_blocks,
            values_per_block,
        );
    }
    if (r < rows) {
        processQ6KRowSingle(
            input,
            prepared_blocks,
            output,
            r,
            in_dim,
            out_dim,
            out_start,
            out_end,
            prepared_row_stride,
            row_blocks,
            values_per_block,
        );
    }
}

fn processQ6KRowSingle(
    input: []const f32,
    prepared_blocks: []const u8,
    output: []f32,
    r: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    prepared_row_stride: usize,
    row_blocks: usize,
    values_per_block: usize,
) void {
    const input_row = input[r * in_dim ..][0..in_dim];
    const out_row = output[r * out_dim ..][0..out_dim];

    var o: usize = out_start;
    while (o < out_end and (o % 4) != 0) : (o += 1) {
        const prepared_row_offset = o * prepared_row_stride;
        var acc: f32 = 0.0;
        for (0..row_blocks) |block_idx| {
            const prepared_block = prepared_blocks[prepared_row_offset + block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes];
            const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
            acc += dotQ6KPreparedBlock(input_block, prepared_block);
        }
        out_row[o] = acc;
    }

    while (o + 4 <= out_dim) : (o += 4) {
        if (o + 4 > out_end) break;
        var acc0: F32xN = @splat(0.0);
        var acc1: F32xN = @splat(0.0);
        var acc2: F32xN = @splat(0.0);
        var acc3: F32xN = @splat(0.0);
        const prepared_row_offset0 = o * prepared_row_stride;
        const prepared_row_offset1 = (o + 1) * prepared_row_stride;
        const prepared_row_offset2 = (o + 2) * prepared_row_stride;
        const prepared_row_offset3 = (o + 3) * prepared_row_stride;
        for (0..row_blocks) |block_idx| {
            const prepared_off = block_idx * prepared_q4_k_block_bytes;
            const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
            accumulateQ6KPreparedBlock4MR1(
                input_block,
                prepared_blocks[prepared_row_offset0 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks[prepared_row_offset1 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks[prepared_row_offset2 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks[prepared_row_offset3 + prepared_off ..][0..prepared_q4_k_block_bytes],
                &acc0,
                &acc1,
                &acc2,
                &acc3,
            );
        }
        out_row[o] = @reduce(.Add, acc0);
        out_row[o + 1] = @reduce(.Add, acc1);
        out_row[o + 2] = @reduce(.Add, acc2);
        out_row[o + 3] = @reduce(.Add, acc3);
    }

    while (o < out_end) : (o += 1) {
        const prepared_row_offset = o * prepared_row_stride;
        var acc: f32 = 0.0;
        for (0..row_blocks) |block_idx| {
            const prepared_block = prepared_blocks[prepared_row_offset + block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes];
            const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
            acc += dotQ6KPreparedBlock(input_block, prepared_block);
        }
        out_row[o] = acc;
    }
}

fn processQ6KRowPair(
    input: []const f32,
    prepared_blocks: []const u8,
    output: []f32,
    r: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    prepared_row_stride: usize,
    row_blocks: usize,
    values_per_block: usize,
) void {
    const input_r0 = input[r * in_dim ..][0..in_dim];
    const input_r1 = input[(r + 1) * in_dim ..][0..in_dim];
    const out_r0 = output[r * out_dim ..][0..out_dim];
    const out_r1 = output[(r + 1) * out_dim ..][0..out_dim];

    var o: usize = out_start;
    while (o < out_end and (o % 4) != 0) : (o += 1) {
        const prepared_row_offset = o * prepared_row_stride;
        var acc_r0: f32 = 0.0;
        var acc_r1: f32 = 0.0;
        for (0..row_blocks) |block_idx| {
            const prepared_block = prepared_blocks[prepared_row_offset + block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes];
            const block_off = block_idx * values_per_block;
            const sums = dotQ6KPreparedBlockMR2NR1(
                input_r0[block_off..][0..values_per_block],
                input_r1[block_off..][0..values_per_block],
                prepared_block,
            );
            acc_r0 += sums[0];
            acc_r1 += sums[1];
        }
        out_r0[o] = acc_r0;
        out_r1[o] = acc_r1;
    }

    while (o + 4 <= out_dim) : (o += 4) {
        if (o + 4 > out_end) break;
        var acc_r0_0: F32xN = @splat(0.0);
        var acc_r0_1: F32xN = @splat(0.0);
        var acc_r0_2: F32xN = @splat(0.0);
        var acc_r0_3: F32xN = @splat(0.0);
        var acc_r1_0: F32xN = @splat(0.0);
        var acc_r1_1: F32xN = @splat(0.0);
        var acc_r1_2: F32xN = @splat(0.0);
        var acc_r1_3: F32xN = @splat(0.0);
        const prepared_row_offset0 = o * prepared_row_stride;
        const prepared_row_offset1 = (o + 1) * prepared_row_stride;
        const prepared_row_offset2 = (o + 2) * prepared_row_stride;
        const prepared_row_offset3 = (o + 3) * prepared_row_stride;
        for (0..row_blocks) |block_idx| {
            const prepared_off = block_idx * prepared_q4_k_block_bytes;
            const block_input_off = block_idx * values_per_block;
            accumulateQ6KPreparedBlock4MR2(
                input_r0[block_input_off..][0..values_per_block],
                input_r1[block_input_off..][0..values_per_block],
                prepared_blocks[prepared_row_offset0 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks[prepared_row_offset1 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks[prepared_row_offset2 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks[prepared_row_offset3 + prepared_off ..][0..prepared_q4_k_block_bytes],
                &acc_r0_0,
                &acc_r0_1,
                &acc_r0_2,
                &acc_r0_3,
                &acc_r1_0,
                &acc_r1_1,
                &acc_r1_2,
                &acc_r1_3,
            );
        }
        out_r0[o] = @reduce(.Add, acc_r0_0);
        out_r0[o + 1] = @reduce(.Add, acc_r0_1);
        out_r0[o + 2] = @reduce(.Add, acc_r0_2);
        out_r0[o + 3] = @reduce(.Add, acc_r0_3);
        out_r1[o] = @reduce(.Add, acc_r1_0);
        out_r1[o + 1] = @reduce(.Add, acc_r1_1);
        out_r1[o + 2] = @reduce(.Add, acc_r1_2);
        out_r1[o + 3] = @reduce(.Add, acc_r1_3);
    }

    while (o < out_end) : (o += 1) {
        const prepared_row_offset = o * prepared_row_stride;
        var acc_r0: f32 = 0.0;
        var acc_r1: f32 = 0.0;
        for (0..row_blocks) |block_idx| {
            const prepared_block = prepared_blocks[prepared_row_offset + block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes];
            const block_off = block_idx * values_per_block;
            const sums = dotQ6KPreparedBlockMR2NR1(
                input_r0[block_off..][0..values_per_block],
                input_r1[block_off..][0..values_per_block],
                prepared_block,
            );
            acc_r0 += sums[0];
            acc_r1 += sums[1];
        }
        out_r0[o] = acc_r0;
        out_r1[o] = acc_r1;
    }
}

fn linearQ4KPreparedTripleFusedRange(
    input: []const f32,
    prepared_blocks_a: []const u8,
    prepared_blocks_b: []const u8,
    prepared_blocks_c: []const u8,
    bias_a: ?[]const f32,
    bias_b: ?[]const f32,
    bias_c: ?[]const f32,
    output_a: []f32,
    output_b: []f32,
    output_c: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) !void {
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q4_K };
    const values_per_block = gguf_tensor_types.valuesPerBlock(tensor_type).?;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    const prepared_row_stride = row_blocks * prepared_q4_k_block_bytes;
    if (prepared_blocks_a.len != out_dim * prepared_row_stride) return error.InvalidQuantizedDataSize;
    if (prepared_blocks_b.len != out_dim * prepared_row_stride) return error.InvalidQuantizedDataSize;
    if (prepared_blocks_c.len != out_dim * prepared_row_stride) return error.InvalidQuantizedDataSize;
    if (out_start > out_end or out_end > out_dim) return error.InvalidQuantizedLinearShape;

    var r: usize = 0;
    while (r + 2 <= rows) : (r += 2) {
        processQ4KTripleRowPair(
            input,
            prepared_blocks_a,
            prepared_blocks_b,
            prepared_blocks_c,
            bias_a,
            bias_b,
            bias_c,
            output_a,
            output_b,
            output_c,
            r,
            in_dim,
            out_dim,
            out_start,
            out_end,
            prepared_row_stride,
            row_blocks,
            values_per_block,
        );
    }
    if (r < rows) {
        processQ4KTripleRowSingle(
            input,
            prepared_blocks_a,
            prepared_blocks_b,
            prepared_blocks_c,
            bias_a,
            bias_b,
            bias_c,
            output_a,
            output_b,
            output_c,
            r,
            in_dim,
            out_dim,
            out_start,
            out_end,
            prepared_row_stride,
            row_blocks,
            values_per_block,
        );
    }
}

fn processQ4KRowSingle(
    input: []const f32,
    prepared_blocks: []const u8,
    output: []f32,
    r: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    prepared_row_stride: usize,
    row_blocks: usize,
    values_per_block: usize,
) void {
    const input_row = input[r * in_dim ..][0..in_dim];
    const out_row = output[r * out_dim ..][0..out_dim];
    var o: usize = out_start;
    // N-head: cols not 4-aligned (rare; out_start is usually 0).
    while (o < out_end and (o % 4) != 0) : (o += 1) {
        const prepared_row_offset = o * prepared_row_stride;
        var acc: f32 = 0.0;
        for (0..row_blocks) |block_idx| {
            const prepared_block = prepared_blocks[prepared_row_offset + block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes];
            const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
            acc += dotQ4KPreparedBlock(input_block, prepared_block);
        }
        out_row[o] = acc;
    }
    // Main 4-col tile (MR=1 NR=4).
    while (o + 4 <= out_dim) : (o += 4) {
        if (o + 4 > out_end) break;
        var acc0: F32xN = @splat(0.0);
        var acc1: F32xN = @splat(0.0);
        var acc2: F32xN = @splat(0.0);
        var acc3: F32xN = @splat(0.0);
        const prepared_row_offset0 = o * prepared_row_stride;
        const prepared_row_offset1 = (o + 1) * prepared_row_stride;
        const prepared_row_offset2 = (o + 2) * prepared_row_stride;
        const prepared_row_offset3 = (o + 3) * prepared_row_stride;
        for (0..row_blocks) |block_idx| {
            const prepared_off = block_idx * prepared_q4_k_block_bytes;
            const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
            accumulateQ4KPreparedBlock4MR1(
                input_block,
                prepared_blocks[prepared_row_offset0 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks[prepared_row_offset1 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks[prepared_row_offset2 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks[prepared_row_offset3 + prepared_off ..][0..prepared_q4_k_block_bytes],
                &acc0,
                &acc1,
                &acc2,
                &acc3,
            );
        }
        out_row[o] = @reduce(.Add, acc0);
        out_row[o + 1] = @reduce(.Add, acc1);
        out_row[o + 2] = @reduce(.Add, acc2);
        out_row[o + 3] = @reduce(.Add, acc3);
    }
    // N-tail: trailing cols not in a 4-col tile.
    while (o < out_end) : (o += 1) {
        const prepared_row_offset = o * prepared_row_stride;
        var acc: f32 = 0.0;
        for (0..row_blocks) |block_idx| {
            const prepared_block = prepared_blocks[prepared_row_offset + block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes];
            const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
            acc += dotQ4KPreparedBlock(input_block, prepared_block);
        }
        out_row[o] = acc;
    }
}

fn processQ4KRowPair(
    input: []const f32,
    prepared_blocks: []const u8,
    output: []f32,
    r: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    prepared_row_stride: usize,
    row_blocks: usize,
    values_per_block: usize,
) void {
    const input_r0 = input[r * in_dim ..][0..in_dim];
    const input_r1 = input[(r + 1) * in_dim ..][0..in_dim];
    const out_r0 = output[r * out_dim ..][0..out_dim];
    const out_r1 = output[(r + 1) * out_dim ..][0..out_dim];

    var o: usize = out_start;
    // N-head: same col range for both rows; do a scalar dot per row per col.
    // Each col still amortises the prepared-block read across 2 rows even
    // in scalar mode because the prepared bytes stay in L1 between the two
    // dotQ4KPreparedBlock calls.
    while (o < out_end and (o % 4) != 0) : (o += 1) {
        const prepared_row_offset = o * prepared_row_stride;
        var acc_r0: f32 = 0.0;
        var acc_r1: f32 = 0.0;
        for (0..row_blocks) |block_idx| {
            const prepared_block = prepared_blocks[prepared_row_offset + block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes];
            const block_off = block_idx * values_per_block;
            const sums = dotQ4KPreparedBlockMR2NR1(
                input_r0[block_off..][0..values_per_block],
                input_r1[block_off..][0..values_per_block],
                prepared_block,
            );
            acc_r0 += sums[0];
            acc_r1 += sums[1];
        }
        out_r0[o] = acc_r0;
        out_r1[o] = acc_r1;
    }
    // Main MR=2 NR=4 tile.  8 accumulators, each prepared block's dequant
    // is reused across both input rows.
    while (o + 4 <= out_dim) : (o += 4) {
        if (o + 4 > out_end) break;
        var acc_r0_0: F32xN = @splat(0.0);
        var acc_r0_1: F32xN = @splat(0.0);
        var acc_r0_2: F32xN = @splat(0.0);
        var acc_r0_3: F32xN = @splat(0.0);
        var acc_r1_0: F32xN = @splat(0.0);
        var acc_r1_1: F32xN = @splat(0.0);
        var acc_r1_2: F32xN = @splat(0.0);
        var acc_r1_3: F32xN = @splat(0.0);
        const prepared_row_offset0 = o * prepared_row_stride;
        const prepared_row_offset1 = (o + 1) * prepared_row_stride;
        const prepared_row_offset2 = (o + 2) * prepared_row_stride;
        const prepared_row_offset3 = (o + 3) * prepared_row_stride;
        for (0..row_blocks) |block_idx| {
            const prepared_off = block_idx * prepared_q4_k_block_bytes;
            const block_input_off = block_idx * values_per_block;
            accumulateQ4KPreparedBlock4MR2(
                input_r0[block_input_off..][0..values_per_block],
                input_r1[block_input_off..][0..values_per_block],
                prepared_blocks[prepared_row_offset0 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks[prepared_row_offset1 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks[prepared_row_offset2 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks[prepared_row_offset3 + prepared_off ..][0..prepared_q4_k_block_bytes],
                &acc_r0_0,
                &acc_r0_1,
                &acc_r0_2,
                &acc_r0_3,
                &acc_r1_0,
                &acc_r1_1,
                &acc_r1_2,
                &acc_r1_3,
            );
        }
        out_r0[o] = @reduce(.Add, acc_r0_0);
        out_r0[o + 1] = @reduce(.Add, acc_r0_1);
        out_r0[o + 2] = @reduce(.Add, acc_r0_2);
        out_r0[o + 3] = @reduce(.Add, acc_r0_3);
        out_r1[o] = @reduce(.Add, acc_r1_0);
        out_r1[o + 1] = @reduce(.Add, acc_r1_1);
        out_r1[o + 2] = @reduce(.Add, acc_r1_2);
        out_r1[o + 3] = @reduce(.Add, acc_r1_3);
    }
    // N-tail: same logic as N-head.
    while (o < out_end) : (o += 1) {
        const prepared_row_offset = o * prepared_row_stride;
        var acc_r0: f32 = 0.0;
        var acc_r1: f32 = 0.0;
        for (0..row_blocks) |block_idx| {
            const prepared_block = prepared_blocks[prepared_row_offset + block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes];
            const block_off = block_idx * values_per_block;
            const sums = dotQ4KPreparedBlockMR2NR1(
                input_r0[block_off..][0..values_per_block],
                input_r1[block_off..][0..values_per_block],
                prepared_block,
            );
            acc_r0 += sums[0];
            acc_r1 += sums[1];
        }
        out_r0[o] = acc_r0;
        out_r1[o] = acc_r1;
    }
}

fn linearNoBiasQ4Q5KPreparedPanel(
    input: []const f32,
    prepared_blocks: []const u8,
    panel_blocks: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    const values_per_block: usize = 256;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    const prepared_row_stride = row_blocks * prepared_q4_k_block_bytes;
    if (prepared_blocks.len != out_dim * prepared_row_stride) return error.InvalidQuantizedDataSize;
    if (panel_blocks.len != preparedKPanelByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;

    var r: usize = 0;
    while (r + 1 < rows) : (r += 2) {
        const input_r0 = input[r * in_dim ..][0..in_dim];
        const input_r1 = input[(r + 1) * in_dim ..][0..in_dim];
        const out_r0 = output[r * out_dim ..][0..out_dim];
        const out_r1 = output[(r + 1) * out_dim ..][0..out_dim];
        var o: usize = 0;
        while (o + prepared_q8_0_panel_nr <= out_dim) : (o += prepared_q8_0_panel_nr) {
            var acc_r0_0: F32xN = @splat(0.0);
            var acc_r0_1: F32xN = @splat(0.0);
            var acc_r0_2: F32xN = @splat(0.0);
            var acc_r0_3: F32xN = @splat(0.0);
            var acc_r1_0: F32xN = @splat(0.0);
            var acc_r1_1: F32xN = @splat(0.0);
            var acc_r1_2: F32xN = @splat(0.0);
            var acc_r1_3: F32xN = @splat(0.0);
            for (0..row_blocks) |block_idx| {
                const block_input_off = block_idx * values_per_block;
                accumulateQ4KPreparedBlock4MR2(
                    input_r0[block_input_off..][0..values_per_block],
                    input_r1[block_input_off..][0..values_per_block],
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 0),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 1),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 2),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 3),
                    &acc_r0_0,
                    &acc_r0_1,
                    &acc_r0_2,
                    &acc_r0_3,
                    &acc_r1_0,
                    &acc_r1_1,
                    &acc_r1_2,
                    &acc_r1_3,
                );
            }
            out_r0[o] = @reduce(.Add, acc_r0_0);
            out_r0[o + 1] = @reduce(.Add, acc_r0_1);
            out_r0[o + 2] = @reduce(.Add, acc_r0_2);
            out_r0[o + 3] = @reduce(.Add, acc_r0_3);
            out_r1[o] = @reduce(.Add, acc_r1_0);
            out_r1[o + 1] = @reduce(.Add, acc_r1_1);
            out_r1[o + 2] = @reduce(.Add, acc_r1_2);
            out_r1[o + 3] = @reduce(.Add, acc_r1_3);
        }
        while (o < out_dim) : (o += 1) {
            const prepared_row_offset = o * prepared_row_stride;
            var acc_r0: f32 = 0.0;
            var acc_r1: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const prepared_block = prepared_blocks[prepared_row_offset + block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes];
                const block_off = block_idx * values_per_block;
                const sums = dotQ4KPreparedBlockMR2NR1(
                    input_r0[block_off..][0..values_per_block],
                    input_r1[block_off..][0..values_per_block],
                    prepared_block,
                );
                acc_r0 += sums[0];
                acc_r1 += sums[1];
            }
            out_r0[o] = acc_r0;
            out_r1[o] = acc_r1;
        }
    }

    if (r < rows) {
        const input_row = input[r * in_dim ..][0..in_dim];
        const out_row = output[r * out_dim ..][0..out_dim];
        var o: usize = 0;
        while (o + prepared_q8_0_panel_nr <= out_dim) : (o += prepared_q8_0_panel_nr) {
            var acc0: F32xN = @splat(0.0);
            var acc1: F32xN = @splat(0.0);
            var acc2: F32xN = @splat(0.0);
            var acc3: F32xN = @splat(0.0);
            for (0..row_blocks) |block_idx| {
                const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
                accumulateQ4KPreparedBlock4MR1(
                    input_block,
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 0),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 1),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 2),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 3),
                    &acc0,
                    &acc1,
                    &acc2,
                    &acc3,
                );
            }
            out_row[o] = @reduce(.Add, acc0);
            out_row[o + 1] = @reduce(.Add, acc1);
            out_row[o + 2] = @reduce(.Add, acc2);
            out_row[o + 3] = @reduce(.Add, acc3);
        }
        while (o < out_dim) : (o += 1) {
            const prepared_row_offset = o * prepared_row_stride;
            var acc: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const prepared_block = prepared_blocks[prepared_row_offset + block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes];
                const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
                acc += dotQ4KPreparedBlock(input_block, prepared_block);
            }
            out_row[o] = acc;
        }
    }
}

fn processQ4KTripleRowSingle(
    input: []const f32,
    prepared_blocks_a: []const u8,
    prepared_blocks_b: []const u8,
    prepared_blocks_c: []const u8,
    bias_a: ?[]const f32,
    bias_b: ?[]const f32,
    bias_c: ?[]const f32,
    output_a: []f32,
    output_b: []f32,
    output_c: []f32,
    r: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    prepared_row_stride: usize,
    row_blocks: usize,
    values_per_block: usize,
) void {
    const input_row = input[r * in_dim ..][0..in_dim];
    const out_a = output_a[r * out_dim ..][0..out_dim];
    const out_b = output_b[r * out_dim ..][0..out_dim];
    const out_c = output_c[r * out_dim ..][0..out_dim];

    var o: usize = out_start;
    while (o < out_end and (o % 4) != 0) : (o += 1) {
        const prepared_row_offset = o * prepared_row_stride;
        var acc_a: f32 = 0.0;
        var acc_b: f32 = 0.0;
        var acc_c: f32 = 0.0;
        for (0..row_blocks) |block_idx| {
            const prepared_off = prepared_row_offset + block_idx * prepared_q4_k_block_bytes;
            const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
            acc_a += dotQ4KPreparedBlock(input_block, prepared_blocks_a[prepared_off..][0..prepared_q4_k_block_bytes]);
            acc_b += dotQ4KPreparedBlock(input_block, prepared_blocks_b[prepared_off..][0..prepared_q4_k_block_bytes]);
            acc_c += dotQ4KPreparedBlock(input_block, prepared_blocks_c[prepared_off..][0..prepared_q4_k_block_bytes]);
        }
        out_a[o] = acc_a + optionalLinearBiasAt(bias_a, o);
        out_b[o] = acc_b + optionalLinearBiasAt(bias_b, o);
        out_c[o] = acc_c + optionalLinearBiasAt(bias_c, o);
    }

    while (o + 4 <= out_dim) : (o += 4) {
        if (o + 4 > out_end) break;
        var acc_a0: F32xN = @splat(0.0);
        var acc_a1: F32xN = @splat(0.0);
        var acc_a2: F32xN = @splat(0.0);
        var acc_a3: F32xN = @splat(0.0);
        var acc_b0: F32xN = @splat(0.0);
        var acc_b1: F32xN = @splat(0.0);
        var acc_b2: F32xN = @splat(0.0);
        var acc_b3: F32xN = @splat(0.0);
        var acc_c0: F32xN = @splat(0.0);
        var acc_c1: F32xN = @splat(0.0);
        var acc_c2: F32xN = @splat(0.0);
        var acc_c3: F32xN = @splat(0.0);
        const prepared_row_offset0 = o * prepared_row_stride;
        const prepared_row_offset1 = (o + 1) * prepared_row_stride;
        const prepared_row_offset2 = (o + 2) * prepared_row_stride;
        const prepared_row_offset3 = (o + 3) * prepared_row_stride;
        for (0..row_blocks) |block_idx| {
            const prepared_off = block_idx * prepared_q4_k_block_bytes;
            const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
            accumulateQ4KPreparedBlock4MR1(
                input_block,
                prepared_blocks_a[prepared_row_offset0 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_a[prepared_row_offset1 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_a[prepared_row_offset2 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_a[prepared_row_offset3 + prepared_off ..][0..prepared_q4_k_block_bytes],
                &acc_a0,
                &acc_a1,
                &acc_a2,
                &acc_a3,
            );
            accumulateQ4KPreparedBlock4MR1(
                input_block,
                prepared_blocks_b[prepared_row_offset0 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_b[prepared_row_offset1 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_b[prepared_row_offset2 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_b[prepared_row_offset3 + prepared_off ..][0..prepared_q4_k_block_bytes],
                &acc_b0,
                &acc_b1,
                &acc_b2,
                &acc_b3,
            );
            accumulateQ4KPreparedBlock4MR1(
                input_block,
                prepared_blocks_c[prepared_row_offset0 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_c[prepared_row_offset1 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_c[prepared_row_offset2 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_c[prepared_row_offset3 + prepared_off ..][0..prepared_q4_k_block_bytes],
                &acc_c0,
                &acc_c1,
                &acc_c2,
                &acc_c3,
            );
        }
        out_a[o] = @reduce(.Add, acc_a0) + optionalLinearBiasAt(bias_a, o);
        out_a[o + 1] = @reduce(.Add, acc_a1) + optionalLinearBiasAt(bias_a, o + 1);
        out_a[o + 2] = @reduce(.Add, acc_a2) + optionalLinearBiasAt(bias_a, o + 2);
        out_a[o + 3] = @reduce(.Add, acc_a3) + optionalLinearBiasAt(bias_a, o + 3);
        out_b[o] = @reduce(.Add, acc_b0) + optionalLinearBiasAt(bias_b, o);
        out_b[o + 1] = @reduce(.Add, acc_b1) + optionalLinearBiasAt(bias_b, o + 1);
        out_b[o + 2] = @reduce(.Add, acc_b2) + optionalLinearBiasAt(bias_b, o + 2);
        out_b[o + 3] = @reduce(.Add, acc_b3) + optionalLinearBiasAt(bias_b, o + 3);
        out_c[o] = @reduce(.Add, acc_c0) + optionalLinearBiasAt(bias_c, o);
        out_c[o + 1] = @reduce(.Add, acc_c1) + optionalLinearBiasAt(bias_c, o + 1);
        out_c[o + 2] = @reduce(.Add, acc_c2) + optionalLinearBiasAt(bias_c, o + 2);
        out_c[o + 3] = @reduce(.Add, acc_c3) + optionalLinearBiasAt(bias_c, o + 3);
    }

    while (o < out_end) : (o += 1) {
        const prepared_row_offset = o * prepared_row_stride;
        var acc_a: f32 = 0.0;
        var acc_b: f32 = 0.0;
        var acc_c: f32 = 0.0;
        for (0..row_blocks) |block_idx| {
            const prepared_off = prepared_row_offset + block_idx * prepared_q4_k_block_bytes;
            const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
            acc_a += dotQ4KPreparedBlock(input_block, prepared_blocks_a[prepared_off..][0..prepared_q4_k_block_bytes]);
            acc_b += dotQ4KPreparedBlock(input_block, prepared_blocks_b[prepared_off..][0..prepared_q4_k_block_bytes]);
            acc_c += dotQ4KPreparedBlock(input_block, prepared_blocks_c[prepared_off..][0..prepared_q4_k_block_bytes]);
        }
        out_a[o] = acc_a + optionalLinearBiasAt(bias_a, o);
        out_b[o] = acc_b + optionalLinearBiasAt(bias_b, o);
        out_c[o] = acc_c + optionalLinearBiasAt(bias_c, o);
    }
}

fn processQ4KTripleRowPair(
    input: []const f32,
    prepared_blocks_a: []const u8,
    prepared_blocks_b: []const u8,
    prepared_blocks_c: []const u8,
    bias_a: ?[]const f32,
    bias_b: ?[]const f32,
    bias_c: ?[]const f32,
    output_a: []f32,
    output_b: []f32,
    output_c: []f32,
    r: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    prepared_row_stride: usize,
    row_blocks: usize,
    values_per_block: usize,
) void {
    const input_r0 = input[r * in_dim ..][0..in_dim];
    const input_r1 = input[(r + 1) * in_dim ..][0..in_dim];
    const out_a_r0 = output_a[r * out_dim ..][0..out_dim];
    const out_a_r1 = output_a[(r + 1) * out_dim ..][0..out_dim];
    const out_b_r0 = output_b[r * out_dim ..][0..out_dim];
    const out_b_r1 = output_b[(r + 1) * out_dim ..][0..out_dim];
    const out_c_r0 = output_c[r * out_dim ..][0..out_dim];
    const out_c_r1 = output_c[(r + 1) * out_dim ..][0..out_dim];

    var o: usize = out_start;
    while (o < out_end and (o % 4) != 0) : (o += 1) {
        const prepared_row_offset = o * prepared_row_stride;
        var acc_a_r0: f32 = 0.0;
        var acc_a_r1: f32 = 0.0;
        var acc_b_r0: f32 = 0.0;
        var acc_b_r1: f32 = 0.0;
        var acc_c_r0: f32 = 0.0;
        var acc_c_r1: f32 = 0.0;
        for (0..row_blocks) |block_idx| {
            const prepared_off = prepared_row_offset + block_idx * prepared_q4_k_block_bytes;
            const block_off = block_idx * values_per_block;
            const sums_a = dotQ4KPreparedBlockMR2NR1(
                input_r0[block_off..][0..values_per_block],
                input_r1[block_off..][0..values_per_block],
                prepared_blocks_a[prepared_off..][0..prepared_q4_k_block_bytes],
            );
            const sums_b = dotQ4KPreparedBlockMR2NR1(
                input_r0[block_off..][0..values_per_block],
                input_r1[block_off..][0..values_per_block],
                prepared_blocks_b[prepared_off..][0..prepared_q4_k_block_bytes],
            );
            const sums_c = dotQ4KPreparedBlockMR2NR1(
                input_r0[block_off..][0..values_per_block],
                input_r1[block_off..][0..values_per_block],
                prepared_blocks_c[prepared_off..][0..prepared_q4_k_block_bytes],
            );
            acc_a_r0 += sums_a[0];
            acc_a_r1 += sums_a[1];
            acc_b_r0 += sums_b[0];
            acc_b_r1 += sums_b[1];
            acc_c_r0 += sums_c[0];
            acc_c_r1 += sums_c[1];
        }
        const bias_a_value = optionalLinearBiasAt(bias_a, o);
        const bias_b_value = optionalLinearBiasAt(bias_b, o);
        const bias_c_value = optionalLinearBiasAt(bias_c, o);
        out_a_r0[o] = acc_a_r0 + bias_a_value;
        out_a_r1[o] = acc_a_r1 + bias_a_value;
        out_b_r0[o] = acc_b_r0 + bias_b_value;
        out_b_r1[o] = acc_b_r1 + bias_b_value;
        out_c_r0[o] = acc_c_r0 + bias_c_value;
        out_c_r1[o] = acc_c_r1 + bias_c_value;
    }

    while (o + 4 <= out_dim) : (o += 4) {
        if (o + 4 > out_end) break;
        var a_r0_0: F32xN = @splat(0.0);
        var a_r0_1: F32xN = @splat(0.0);
        var a_r0_2: F32xN = @splat(0.0);
        var a_r0_3: F32xN = @splat(0.0);
        var a_r1_0: F32xN = @splat(0.0);
        var a_r1_1: F32xN = @splat(0.0);
        var a_r1_2: F32xN = @splat(0.0);
        var a_r1_3: F32xN = @splat(0.0);
        var b_r0_0: F32xN = @splat(0.0);
        var b_r0_1: F32xN = @splat(0.0);
        var b_r0_2: F32xN = @splat(0.0);
        var b_r0_3: F32xN = @splat(0.0);
        var b_r1_0: F32xN = @splat(0.0);
        var b_r1_1: F32xN = @splat(0.0);
        var b_r1_2: F32xN = @splat(0.0);
        var b_r1_3: F32xN = @splat(0.0);
        var c_r0_0: F32xN = @splat(0.0);
        var c_r0_1: F32xN = @splat(0.0);
        var c_r0_2: F32xN = @splat(0.0);
        var c_r0_3: F32xN = @splat(0.0);
        var c_r1_0: F32xN = @splat(0.0);
        var c_r1_1: F32xN = @splat(0.0);
        var c_r1_2: F32xN = @splat(0.0);
        var c_r1_3: F32xN = @splat(0.0);
        const prepared_row_offset0 = o * prepared_row_stride;
        const prepared_row_offset1 = (o + 1) * prepared_row_stride;
        const prepared_row_offset2 = (o + 2) * prepared_row_stride;
        const prepared_row_offset3 = (o + 3) * prepared_row_stride;
        for (0..row_blocks) |block_idx| {
            const prepared_off = block_idx * prepared_q4_k_block_bytes;
            const block_input_off = block_idx * values_per_block;
            const input_block_r0 = input_r0[block_input_off..][0..values_per_block];
            const input_block_r1 = input_r1[block_input_off..][0..values_per_block];
            accumulateQ4KPreparedBlock4MR2(
                input_block_r0,
                input_block_r1,
                prepared_blocks_a[prepared_row_offset0 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_a[prepared_row_offset1 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_a[prepared_row_offset2 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_a[prepared_row_offset3 + prepared_off ..][0..prepared_q4_k_block_bytes],
                &a_r0_0,
                &a_r0_1,
                &a_r0_2,
                &a_r0_3,
                &a_r1_0,
                &a_r1_1,
                &a_r1_2,
                &a_r1_3,
            );
            accumulateQ4KPreparedBlock4MR2(
                input_block_r0,
                input_block_r1,
                prepared_blocks_b[prepared_row_offset0 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_b[prepared_row_offset1 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_b[prepared_row_offset2 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_b[prepared_row_offset3 + prepared_off ..][0..prepared_q4_k_block_bytes],
                &b_r0_0,
                &b_r0_1,
                &b_r0_2,
                &b_r0_3,
                &b_r1_0,
                &b_r1_1,
                &b_r1_2,
                &b_r1_3,
            );
            accumulateQ4KPreparedBlock4MR2(
                input_block_r0,
                input_block_r1,
                prepared_blocks_c[prepared_row_offset0 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_c[prepared_row_offset1 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_c[prepared_row_offset2 + prepared_off ..][0..prepared_q4_k_block_bytes],
                prepared_blocks_c[prepared_row_offset3 + prepared_off ..][0..prepared_q4_k_block_bytes],
                &c_r0_0,
                &c_r0_1,
                &c_r0_2,
                &c_r0_3,
                &c_r1_0,
                &c_r1_1,
                &c_r1_2,
                &c_r1_3,
            );
        }
        const bias_a0 = optionalLinearBiasAt(bias_a, o);
        const bias_a1 = optionalLinearBiasAt(bias_a, o + 1);
        const bias_a2 = optionalLinearBiasAt(bias_a, o + 2);
        const bias_a3 = optionalLinearBiasAt(bias_a, o + 3);
        const bias_b0 = optionalLinearBiasAt(bias_b, o);
        const bias_b1 = optionalLinearBiasAt(bias_b, o + 1);
        const bias_b2 = optionalLinearBiasAt(bias_b, o + 2);
        const bias_b3 = optionalLinearBiasAt(bias_b, o + 3);
        const bias_c0 = optionalLinearBiasAt(bias_c, o);
        const bias_c1 = optionalLinearBiasAt(bias_c, o + 1);
        const bias_c2 = optionalLinearBiasAt(bias_c, o + 2);
        const bias_c3 = optionalLinearBiasAt(bias_c, o + 3);

        out_a_r0[o] = @reduce(.Add, a_r0_0) + bias_a0;
        out_a_r0[o + 1] = @reduce(.Add, a_r0_1) + bias_a1;
        out_a_r0[o + 2] = @reduce(.Add, a_r0_2) + bias_a2;
        out_a_r0[o + 3] = @reduce(.Add, a_r0_3) + bias_a3;
        out_a_r1[o] = @reduce(.Add, a_r1_0) + bias_a0;
        out_a_r1[o + 1] = @reduce(.Add, a_r1_1) + bias_a1;
        out_a_r1[o + 2] = @reduce(.Add, a_r1_2) + bias_a2;
        out_a_r1[o + 3] = @reduce(.Add, a_r1_3) + bias_a3;

        out_b_r0[o] = @reduce(.Add, b_r0_0) + bias_b0;
        out_b_r0[o + 1] = @reduce(.Add, b_r0_1) + bias_b1;
        out_b_r0[o + 2] = @reduce(.Add, b_r0_2) + bias_b2;
        out_b_r0[o + 3] = @reduce(.Add, b_r0_3) + bias_b3;
        out_b_r1[o] = @reduce(.Add, b_r1_0) + bias_b0;
        out_b_r1[o + 1] = @reduce(.Add, b_r1_1) + bias_b1;
        out_b_r1[o + 2] = @reduce(.Add, b_r1_2) + bias_b2;
        out_b_r1[o + 3] = @reduce(.Add, b_r1_3) + bias_b3;

        out_c_r0[o] = @reduce(.Add, c_r0_0) + bias_c0;
        out_c_r0[o + 1] = @reduce(.Add, c_r0_1) + bias_c1;
        out_c_r0[o + 2] = @reduce(.Add, c_r0_2) + bias_c2;
        out_c_r0[o + 3] = @reduce(.Add, c_r0_3) + bias_c3;
        out_c_r1[o] = @reduce(.Add, c_r1_0) + bias_c0;
        out_c_r1[o + 1] = @reduce(.Add, c_r1_1) + bias_c1;
        out_c_r1[o + 2] = @reduce(.Add, c_r1_2) + bias_c2;
        out_c_r1[o + 3] = @reduce(.Add, c_r1_3) + bias_c3;
    }

    while (o < out_end) : (o += 1) {
        const prepared_row_offset = o * prepared_row_stride;
        var acc_a_r0: f32 = 0.0;
        var acc_a_r1: f32 = 0.0;
        var acc_b_r0: f32 = 0.0;
        var acc_b_r1: f32 = 0.0;
        var acc_c_r0: f32 = 0.0;
        var acc_c_r1: f32 = 0.0;
        for (0..row_blocks) |block_idx| {
            const prepared_off = prepared_row_offset + block_idx * prepared_q4_k_block_bytes;
            const block_off = block_idx * values_per_block;
            const sums_a = dotQ4KPreparedBlockMR2NR1(
                input_r0[block_off..][0..values_per_block],
                input_r1[block_off..][0..values_per_block],
                prepared_blocks_a[prepared_off..][0..prepared_q4_k_block_bytes],
            );
            const sums_b = dotQ4KPreparedBlockMR2NR1(
                input_r0[block_off..][0..values_per_block],
                input_r1[block_off..][0..values_per_block],
                prepared_blocks_b[prepared_off..][0..prepared_q4_k_block_bytes],
            );
            const sums_c = dotQ4KPreparedBlockMR2NR1(
                input_r0[block_off..][0..values_per_block],
                input_r1[block_off..][0..values_per_block],
                prepared_blocks_c[prepared_off..][0..prepared_q4_k_block_bytes],
            );
            acc_a_r0 += sums_a[0];
            acc_a_r1 += sums_a[1];
            acc_b_r0 += sums_b[0];
            acc_b_r1 += sums_b[1];
            acc_c_r0 += sums_c[0];
            acc_c_r1 += sums_c[1];
        }
        const bias_a_value = optionalLinearBiasAt(bias_a, o);
        const bias_b_value = optionalLinearBiasAt(bias_b, o);
        const bias_c_value = optionalLinearBiasAt(bias_c, o);
        out_a_r0[o] = acc_a_r0 + bias_a_value;
        out_a_r1[o] = acc_a_r1 + bias_a_value;
        out_b_r0[o] = acc_b_r0 + bias_b_value;
        out_b_r1[o] = acc_b_r1 + bias_b_value;
        out_c_r0[o] = acc_c_r0 + bias_c_value;
        out_c_r1[o] = acc_c_r1 + bias_c_value;
    }
}

fn linearNoBiasPackedQ4KPrepared(
    input: []const f32,
    storage: *const QuantizedStorage,
    packed_view: QuantizedStorage.PackedExpertView,
    prepared_blocks: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q4_K };
    const meta = try packedQuantizedMatrixMeta(storage.shape, packed_view, in_dim, out_dim, tensor_type);
    if (prepared_blocks.len != storage.raw_bytes.len / meta.block_size * prepared_q4_k_block_bytes) {
        return error.InvalidQuantizedDataSize;
    }

    for (0..rows) |r| {
        const input_row = input[r * in_dim ..][0..in_dim];
        const out_row = output[r * out_dim ..][0..out_dim];
        for (0..out_dim) |o| {
            const row_block_base = try packedExpertRowBlockBase(meta, packed_view, o);
            var acc: f32 = 0.0;
            for (0..meta.row_blocks) |block_idx| {
                const block_index = row_block_base + block_idx;
                const prepared_block = prepared_blocks[block_index * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes];
                const input_block = input_row[block_idx * meta.values_per_block ..][0..meta.values_per_block];
                acc += dotQ4KPreparedBlock(input_block, prepared_block);
            }
            out_row[o] = acc;
        }
    }
}

fn linearNoBiasQ4KPreparedPair(
    input: []const f32,
    prepared_blocks_a: []const u8,
    prepared_blocks_b: []const u8,
    output_a: []f32,
    output_b: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q4_K };
    const values_per_block = gguf_tensor_types.valuesPerBlock(tensor_type).?;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    const prepared_row_stride = row_blocks * prepared_q4_k_block_bytes;
    if (prepared_blocks_a.len != out_dim * prepared_row_stride or prepared_blocks_b.len != out_dim * prepared_row_stride) {
        return error.InvalidQuantizedDataSize;
    }

    for (0..rows) |r| {
        const input_row = input[r * in_dim ..][0..in_dim];
        const out_row_a = output_a[r * out_dim ..][0..out_dim];
        const out_row_b = output_b[r * out_dim ..][0..out_dim];
        for (0..out_dim) |o| {
            const prepared_row_offset = o * prepared_row_stride;
            var acc_a: f32 = 0.0;
            var acc_b: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const prepared_off = prepared_row_offset + block_idx * prepared_q4_k_block_bytes;
                const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
                acc_a += dotQ4KPreparedBlock(input_block, prepared_blocks_a[prepared_off..][0..prepared_q4_k_block_bytes]);
                acc_b += dotQ4KPreparedBlock(input_block, prepared_blocks_b[prepared_off..][0..prepared_q4_k_block_bytes]);
            }
            out_row_a[o] = acc_a;
            out_row_b[o] = acc_b;
        }
    }
}

// --- Comptime-typed quant linear ---
//
// `linearNoBiasQuantizedGeneric` takes a runtime `dot_fn` pointer per
// block.  The pointer hides the kernel body from the optimiser, so
// LLVM can't inline the dot loop into the surrounding row/col walk and
// every block dispatch pays a function-call cost.
//
// `linearNoBiasQuantizedTyped` makes the format a comptime parameter
// instead.  Each known tensor type generates its own specialised range
// and parallel kernel where the dot body is fully visible -- the
// compiler inlines, constant-folds the block-size arithmetic, and
// schedules the inner loop the same way it does for the dense sgemm
// microkernel.  For workhorse formats (Q4_0/Q4_1/Q5_0/Q5_1/Q8_1/Q2_K/
// Q3_K/Q5_K/Q6_K/Q8_K/IQ4_NL/IQ4_XS) this is a free win over the
// fn-pointer path.
//
// Q4_K and Q8_0 keep their bespoke kernels (linearNoBiasQ4KPrepared
// and linearNoBiasQ8_0) because they have additional NR/MR tiling
// the comptime template doesn't model.

fn dotFnForKind(comptime kind: gguf_tensor_types.KnownTensorType) fn ([]const f32, []const u8) f32 {
    return switch (kind) {
        .Q1_0 => dotQ1_0Block,
        .Q4_0 => dotQ4_0Block,
        .Q4_1 => dotQ4_1Block,
        .Q5_0 => dotQ5_0Block,
        .Q5_1 => dotQ5_1Block,
        .Q8_0 => dotQ8_0Block,
        .Q8_1 => dotQ8_1Block,
        .Q2_K => dotQ2_KBlock,
        .Q3_K => dotQ3_KBlock,
        .Q4_K => dotQ4_KBlock,
        .Q5_K => dotQ5_KBlock,
        .Q6_K => dotQ6_KBlock,
        .Q8_K => dotQ8_KBlock,
        .IQ4_NL => dotIQ4NLBlock,
        .IQ4_XS => dotIQ4XSBlock,
        else => @compileError("dotFnForKind: no specialised dot kernel for " ++ @tagName(kind)),
    };
}

fn linearNoBiasQuantizedTypedRange(
    comptime kind: gguf_tensor_types.KnownTensorType,
    input: []const f32,
    weight_raw: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = kind };
    const block_size = comptime gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const values_per_block = comptime gguf_tensor_types.valuesPerBlock(tensor_type).?;
    const dot_fn = comptime dotFnForKind(kind);
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * block_size;
    std.debug.assert(out_start <= out_end and out_end <= out_dim);

    for (0..rows) |r| {
        const input_row = input[r * in_dim ..][0..in_dim];
        const out_row = output[r * out_dim ..][0..out_dim];
        for (out_start..out_end) |o| {
            const w_off = o * row_stride;
            var acc: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const blk = weight_raw[w_off + block_idx * block_size ..][0..block_size];
                const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
                acc += dot_fn(input_block, blk);
            }
            out_row[o] = acc;
        }
    }
}

const TypedQuantWorkerCtx = struct {
    input: []const f32,
    weight_raw: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize = 0,
    out_end: usize = 0,
    err: ?anyerror = null,
};

fn TypedQuantWorker(comptime kind: gguf_tensor_types.KnownTensorType) type {
    return struct {
        fn run(ctx: *TypedQuantWorkerCtx) void {
            linearNoBiasQuantizedTypedRange(
                kind,
                ctx.input,
                ctx.weight_raw,
                ctx.output,
                ctx.rows,
                ctx.in_dim,
                ctx.out_dim,
                ctx.out_start,
                ctx.out_end,
            );
        }
        fn job(raw: *anyopaque) void {
            run(@ptrCast(@alignCast(raw)));
        }
    };
}

fn linearNoBiasQuantizedTyped(
    comptime kind: gguf_tensor_types.KnownTensorType,
    io: ?std.Io,
    input: []const f32,
    weight_raw: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = kind };
    const block_size = comptime gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const values_per_block = comptime gguf_tensor_types.valuesPerBlock(tensor_type).?;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * block_size;
    if (weight_raw.len != out_dim * row_stride) return error.InvalidQuantizedDataSize;

    const col_plan = chooseQuantLinearColumnParallelPlan(
        quantParallelEnabled(),
        quantParallelDispatchAvailable(io),
        rows,
        out_dim,
        row_blocks,
        quantParallelMaxWorkers(),
    );
    if (col_plan.worker_count > 1) {
        if (quantParallelDebugRequested()) {
            std.debug.print(
                "typed_quant_parallel_cols kind={s} workers={d} rows={d} out={d} row_blocks={d}\n",
                .{ @tagName(kind), col_plan.worker_count, rows, out_dim, row_blocks },
            );
        }
        var chunks: [max_q4_k_parallel_workers]QuantColChunk = undefined;
        const num_chunks = chunkColsForWorkers(out_dim, col_plan, &chunks);
        var contexts: [max_q4_k_parallel_workers]TypedQuantWorkerCtx = undefined;
        var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
        const Worker = TypedQuantWorker(kind);
        for (chunks[0..num_chunks], 0..) |chunk, i| {
            contexts[i] = .{
                .input = input,
                .weight_raw = weight_raw,
                .output = output,
                .rows = rows,
                .in_dim = in_dim,
                .out_dim = out_dim,
                .out_start = chunk.start,
                .out_end = chunk.end,
            };
            jobs[i] = .{ .fn_ptr = Worker.job, .ctx = @ptrCast(&contexts[i]) };
        }
        try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
        return;
    }

    const plan = chooseQuantLinearParallelPlan(
        quantParallelEnabled(),
        rows,
        out_dim,
        row_blocks,
        quantParallelMaxWorkers(),
    );
    if (plan.worker_count > 1) {
        if (quantParallelDebugRequested()) {
            std.debug.print(
                "typed_quant_parallel kind={s} workers={d} rows={d} out={d} row_blocks={d}\n",
                .{ @tagName(kind), plan.worker_count, rows, out_dim, row_blocks },
            );
        }
        var chunks: [max_q4_k_parallel_workers]QuantRowChunk = undefined;
        const num_chunks = chunkRowsForWorkers(rows, plan, &chunks);
        var contexts: [max_q4_k_parallel_workers]TypedQuantWorkerCtx = undefined;
        var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
        const Worker = TypedQuantWorker(kind);
        for (chunks[0..num_chunks], 0..) |chunk, i| {
            contexts[i] = .{
                .input = input[chunk.start * in_dim .. chunk.end * in_dim],
                .weight_raw = weight_raw,
                .output = output[chunk.start * out_dim .. chunk.end * out_dim],
                .rows = chunk.end - chunk.start,
                .in_dim = in_dim,
                .out_dim = out_dim,
                .out_start = 0,
                .out_end = out_dim,
            };
            jobs[i] = .{ .fn_ptr = Worker.job, .ctx = @ptrCast(&contexts[i]) };
        }
        try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
        return;
    }

    linearNoBiasQuantizedTypedRange(kind, input, weight_raw, output, rows, in_dim, out_dim, 0, out_dim);
}

// Tiny shim that adapts `linearNoBiasQuantizedTyped` (returns void) to
// the `linearNoBiasQuantized` contract (returns `!bool`).  Returning
// `true` short-circuits the legacy fn-ptr path.
fn typedDispatch(
    comptime kind: gguf_tensor_types.KnownTensorType,
    io: ?std.Io,
    input: []const f32,
    weight_raw: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !bool {
    try linearNoBiasQuantizedTyped(kind, io, input, weight_raw, output, rows, in_dim, out_dim);
    return true;
}

// --- Function-pointer fallback ---
//
// Kept for paths that don't know the tensor type at comptime: the pair
// kernel (linearNoBiasQuantizedPair), and any future caller that
// genuinely has a runtime-only type.  All single-tensor known-format
// callers go through `linearNoBiasQuantizedTyped` above.

fn linearNoBiasQuantizedGeneric(
    io: ?std.Io,
    input: []const f32,
    weight_raw: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    tensor_type: gguf_tensor_types.TensorType,
    dot_fn: *const fn ([]const f32, []const u8) f32,
) !void {
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const values_per_block = gguf_tensor_types.valuesPerBlock(tensor_type).?;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * block_size;
    if (weight_raw.len != out_dim * row_stride) return error.InvalidQuantizedDataSize;

    if (try linearNoBiasQuantizedGenericParallel(
        io,
        input,
        weight_raw,
        output,
        rows,
        in_dim,
        out_dim,
        row_blocks,
        block_size,
        values_per_block,
        row_stride,
        dot_fn,
    )) {
        return;
    }

    try linearNoBiasQuantizedGenericRange(
        input,
        weight_raw,
        output,
        rows,
        in_dim,
        out_dim,
        0,
        out_dim,
        block_size,
        values_per_block,
        row_stride,
        dot_fn,
    );
}

// --- Q8_0 specialization ---
//
// `linearNoBiasQuantizedGenericRange` walks blocks via a function-pointer
// (`dot_fn`) which prevents the compiler from inlining or fusing across
// blocks/cols.  For Q8_0 specifically (and a workhorse format for DeBERTa-
// style encoders), spelling the inner kernel out lets LLVM see the full
// loop nest and amortise the input-block load across two output columns
// (NR=2) and lift `d` (the per-block fp16 scale) out of the SIMD core.

fn linearNoBiasQ8_0Block2NR(
    input_block: *const [32]f32,
    qs0: *const [32]u8,
    qs1: *const [32]u8,
) struct { f32, f32 } {
    var sum0: F32xN = @splat(0.0);
    var sum1: F32xN = @splat(0.0);
    comptime var i: usize = 0;
    inline while (i < 32) : (i += VEC_LEN) {
        const inp: F32xN = input_block[i..][0..VEC_LEN].*;
        const raw0: U8xN = qs0[i..][0..VEC_LEN].*;
        const raw1: U8xN = qs1[i..][0..VEC_LEN].*;
        const qi0: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw0));
        const qi1: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw1));
        const qf0: F32xN = @floatFromInt(qi0);
        const qf1: F32xN = @floatFromInt(qi1);
        sum0 += inp * qf0;
        sum1 += inp * qf1;
    }
    return .{ @reduce(.Add, sum0), @reduce(.Add, sum1) };
}

fn accumulateQ8_0Block2NR(
    input_block: *const [32]f32,
    qs0: *const [32]u8,
    qs1: *const [32]u8,
    d0: f32,
    d1: f32,
    acc0: *F32xN,
    acc1: *F32xN,
) void {
    const scale0: F32xN = @splat(d0);
    const scale1: F32xN = @splat(d1);
    comptime var i: usize = 0;
    inline while (i < 32) : (i += VEC_LEN) {
        const inp: F32xN = input_block[i..][0..VEC_LEN].*;
        const raw0: U8xN = qs0[i..][0..VEC_LEN].*;
        const raw1: U8xN = qs1[i..][0..VEC_LEN].*;
        const qi0: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw0));
        const qi1: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw1));
        acc0.* += inp * (scale0 * @as(F32xN, @floatFromInt(qi0)));
        acc1.* += inp * (scale1 * @as(F32xN, @floatFromInt(qi1)));
    }
}

fn accumulateQ8_0Block1NR(
    input_block: *const [32]f32,
    qs: *const [32]u8,
    d: f32,
    acc: *F32xN,
) void {
    const scale: F32xN = @splat(d);
    comptime var i: usize = 0;
    inline while (i < 32) : (i += VEC_LEN) {
        const inp: F32xN = input_block[i..][0..VEC_LEN].*;
        const raw: U8xN = qs[i..][0..VEC_LEN].*;
        const qi: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw));
        acc.* += inp * (scale * @as(F32xN, @floatFromInt(qi)));
    }
}

fn accumulateQ8_0Block2MR2NR(
    input_block_r0: *const [32]f32,
    input_block_r1: *const [32]f32,
    qs0: *const [32]u8,
    qs1: *const [32]u8,
    d0: f32,
    d1: f32,
    acc_r0c0: *F32xN,
    acc_r0c1: *F32xN,
    acc_r1c0: *F32xN,
    acc_r1c1: *F32xN,
) void {
    const scale0: F32xN = @splat(d0);
    const scale1: F32xN = @splat(d1);
    comptime var i: usize = 0;
    inline while (i < 32) : (i += VEC_LEN) {
        const inp_r0: F32xN = input_block_r0[i..][0..VEC_LEN].*;
        const inp_r1: F32xN = input_block_r1[i..][0..VEC_LEN].*;
        const raw0: U8xN = qs0[i..][0..VEC_LEN].*;
        const raw1: U8xN = qs1[i..][0..VEC_LEN].*;
        const qi0: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw0));
        const qi1: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw1));
        const w0 = scale0 * @as(F32xN, @floatFromInt(qi0));
        const w1 = scale1 * @as(F32xN, @floatFromInt(qi1));
        acc_r0c0.* += inp_r0 * w0;
        acc_r0c1.* += inp_r0 * w1;
        acc_r1c0.* += inp_r1 * w0;
        acc_r1c1.* += inp_r1 * w1;
    }
}

fn accumulateQ8_0Block2MR1NR(
    input_block_r0: *const [32]f32,
    input_block_r1: *const [32]f32,
    qs: *const [32]u8,
    d: f32,
    acc_r0: *F32xN,
    acc_r1: *F32xN,
) void {
    const scale: F32xN = @splat(d);
    comptime var i: usize = 0;
    inline while (i < 32) : (i += VEC_LEN) {
        const inp_r0: F32xN = input_block_r0[i..][0..VEC_LEN].*;
        const inp_r1: F32xN = input_block_r1[i..][0..VEC_LEN].*;
        const raw: U8xN = qs[i..][0..VEC_LEN].*;
        const qi: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw));
        const w = scale * @as(F32xN, @floatFromInt(qi));
        acc_r0.* += inp_r0 * w;
        acc_r1.* += inp_r1 * w;
    }
}

fn quantizeQ8_0ActivationRows(
    input: []const f32,
    q_values: []u8,
    scales: []f32,
    rows: usize,
    in_dim: usize,
    row_blocks: usize,
) void {
    const values_per_block: usize = 32;
    std.debug.assert(q_values.len == rows * row_blocks * values_per_block);
    std.debug.assert(scales.len == rows * row_blocks);
    for (0..rows) |r| {
        const input_row = input[r * in_dim ..][0..in_dim];
        for (0..row_blocks) |block_idx| {
            const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
            var max_abs: f32 = 0.0;
            for (input_block) |value| max_abs = @max(max_abs, @abs(value));
            const scale = if (max_abs == 0.0) @as(f32, 1.0) else max_abs / 127.0;
            const inv_scale = if (max_abs == 0.0) 0.0 else 1.0 / scale;
            const q_off = (r * row_blocks + block_idx) * values_per_block;
            scales[r * row_blocks + block_idx] = scale;
            for (input_block, 0..) |value, i| {
                const q = if (max_abs == 0.0)
                    @as(i8, 0)
                else
                    @as(i8, @intFromFloat(@min(@max(std.math.round(value * inv_scale), -127.0), 127.0)));
                q_values[q_off + i] = @bitCast(q);
            }
        }
    }
}

fn quantizeQ8_0ActivationRowsVectorized(
    input: []const f32,
    q_values: []u8,
    scales: []f32,
    rows: usize,
    in_dim: usize,
    row_blocks: usize,
) void {
    const values_per_block: usize = 32;
    std.debug.assert(q_values.len == rows * row_blocks * values_per_block);
    std.debug.assert(scales.len == rows * row_blocks);
    for (0..rows) |r| {
        const input_row = input[r * in_dim ..][0..in_dim];
        for (0..row_blocks) |block_idx| {
            const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
            var max_vec: F32xN = @splat(0.0);
            comptime var max_i: usize = 0;
            inline while (max_i < values_per_block) : (max_i += VEC_LEN) {
                const vals: F32xN = input_block[max_i..][0..VEC_LEN].*;
                max_vec = @max(max_vec, @abs(vals));
            }
            const max_abs = @reduce(.Max, max_vec);
            const scale = if (max_abs == 0.0) @as(f32, 1.0) else max_abs / 127.0;
            const inv_scale = if (max_abs == 0.0) 0.0 else 1.0 / scale;
            const q_off = (r * row_blocks + block_idx) * values_per_block;
            scales[r * row_blocks + block_idx] = scale;
            const block_out = q_values[q_off..][0..values_per_block];
            if (max_abs == 0.0) {
                @memset(block_out, 0);
            } else {
                const inv: F32xN = @splat(inv_scale);
                const lo: F32xN = @splat(-127.0);
                const hi: F32xN = @splat(127.0);
                comptime var quant_i: usize = 0;
                inline while (quant_i < values_per_block) : (quant_i += VEC_LEN) {
                    const vals: F32xN = input_block[quant_i..][0..VEC_LEN].*;
                    const rounded = @round(vals * inv);
                    const clipped = @min(@max(rounded, lo), hi);
                    const q: @Vector(VEC_LEN, i8) = @intFromFloat(clipped);
                    const raw: U8xN = @bitCast(q);
                    block_out[quant_i..][0..VEC_LEN].* = raw;
                }
            }
        }
    }
}

fn q8_0ActivationQuantWorker(ctx: *Q8_0ActivationQuantWorkerCtx) void {
    if (ctx.vectorized) {
        quantizeQ8_0ActivationRowsVectorized(ctx.input, ctx.q_values, ctx.scales, ctx.rows, ctx.in_dim, ctx.row_blocks);
    } else {
        quantizeQ8_0ActivationRows(ctx.input, ctx.q_values, ctx.scales, ctx.rows, ctx.in_dim, ctx.row_blocks);
    }
    ctx.err = null;
}

fn q8_0ActivationQuantWorkerJob(raw: *anyopaque) void {
    q8_0ActivationQuantWorker(@ptrCast(@alignCast(raw)));
}

fn quantizeQ8_0ActivationRowsDispatch(
    io: ?std.Io,
    input: []const f32,
    q_values: []u8,
    scales: []f32,
    rows: usize,
    in_dim: usize,
    row_blocks: usize,
) !void {
    const values_per_block: usize = 32;
    const vectorized = in_dim >= 2048;
    const plan = chooseActivationQuantParallelPlan(quantParallelEnabled(), rows, in_dim, quantParallelMaxWorkers());
    if (plan.worker_count <= 1) {
        if (vectorized) {
            quantizeQ8_0ActivationRowsVectorized(input, q_values, scales, rows, in_dim, row_blocks);
        } else {
            quantizeQ8_0ActivationRows(input, q_values, scales, rows, in_dim, row_blocks);
        }
        return;
    }
    if (quantParallelDebugRequested()) {
        std.debug.print("q8_0_activation_quant_parallel workers={d} rows={d} in={d} row_blocks={d}\n", .{ plan.worker_count, rows, in_dim, row_blocks });
    }

    var chunks: [max_q4_k_parallel_workers]QuantRowChunk = undefined;
    const num_chunks = chunkRowsForWorkers(rows, plan, &chunks);
    var contexts: [max_q4_k_parallel_workers]Q8_0ActivationQuantWorkerCtx = undefined;
    var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
    for (chunks[0..num_chunks], 0..) |chunk, i| {
        contexts[i] = .{
            .input = input[chunk.start * in_dim .. chunk.end * in_dim],
            .q_values = q_values[chunk.start * row_blocks * values_per_block .. chunk.end * row_blocks * values_per_block],
            .scales = scales[chunk.start * row_blocks .. chunk.end * row_blocks],
            .rows = chunk.end - chunk.start,
            .in_dim = in_dim,
            .row_blocks = row_blocks,
            .vectorized = vectorized,
        };
        jobs[i] = .{ .fn_ptr = q8_0ActivationQuantWorkerJob, .ctx = @ptrCast(&contexts[i]) };
    }
    try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
}

fn dotI8I8Block(q_input: *const [32]u8, q_weight: *const [32]u8) i32 {
    if (comptime native_aarch64_dotprod) {
        return dotI8I8BlockAarch64Sdot(q_input, q_weight);
    }
    return dotI8I8BlockPortable(q_input, q_weight);
}

fn dotI8I8BlockPortable(q_input: *const [32]u8, q_weight: *const [32]u8) i32 {
    var acc: I32xN = @splat(0);
    comptime var i: usize = 0;
    inline while (i < 32) : (i += VEC_LEN) {
        const raw_x: U8xN = q_input[i..][0..VEC_LEN].*;
        const raw_w: U8xN = q_weight[i..][0..VEC_LEN].*;
        const x: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw_x));
        const w: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw_w));
        acc += x * w;
    }
    return @reduce(.Add, acc);
}

inline fn aarch64Sdot16(acc_in: I32x4, raw_x: U8x16, raw_w: U8x16) I32x4 {
    var acc = acc_in;
    const x: @Vector(16, i8) = @bitCast(raw_x);
    const w: @Vector(16, i8) = @bitCast(raw_w);
    asm ("sdot %[acc].4s, %[x].16b, %[w].16b"
        : [acc] "+w" (acc),
        : [x] "w" (x),
          [w] "w" (w),
    );
    return acc;
}

fn dotI8I8BlockAarch64Sdot(q_input: *const [32]u8, q_weight: *const [32]u8) i32 {
    var acc: I32x4 = @splat(0);
    comptime var i: usize = 0;
    inline while (i < 32) : (i += 16) {
        const raw_x: U8x16 = q_input[i..][0..16].*;
        const raw_w: U8x16 = q_weight[i..][0..16].*;
        acc = aarch64Sdot16(acc, raw_x, raw_w);
    }
    return @reduce(.Add, acc);
}

fn dotI8I8Block16(q_input: *const [16]u8, q_weight: *const [16]u8) i32 {
    if (comptime native_aarch64_dotprod) {
        return @reduce(.Add, aarch64Sdot16(@splat(0), q_input.*, q_weight.*));
    }

    var acc: I32xN = @splat(0);
    comptime var i: usize = 0;
    inline while (i < 16) : (i += VEC_LEN) {
        const raw_x: U8xN = q_input[i..][0..VEC_LEN].*;
        const raw_w: U8xN = q_weight[i..][0..VEC_LEN].*;
        const x: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw_x));
        const w: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw_w));
        acc += x * w;
    }
    return @reduce(.Add, acc);
}

fn dotI8I8Block4_16(
    q_input: *const [16]u8,
    q_weight0: *const [16]u8,
    q_weight1: *const [16]u8,
    q_weight2: *const [16]u8,
    q_weight3: *const [16]u8,
) struct { i32, i32, i32, i32 } {
    if (comptime native_aarch64_dotprod) {
        const raw_x: U8x16 = q_input.*;
        const acc0 = aarch64Sdot16(@splat(0), raw_x, q_weight0.*);
        const acc1 = aarch64Sdot16(@splat(0), raw_x, q_weight1.*);
        const acc2 = aarch64Sdot16(@splat(0), raw_x, q_weight2.*);
        const acc3 = aarch64Sdot16(@splat(0), raw_x, q_weight3.*);
        return .{ @reduce(.Add, acc0), @reduce(.Add, acc1), @reduce(.Add, acc2), @reduce(.Add, acc3) };
    }

    var acc0: I32xN = @splat(0);
    var acc1: I32xN = @splat(0);
    var acc2: I32xN = @splat(0);
    var acc3: I32xN = @splat(0);
    comptime var i: usize = 0;
    inline while (i < 16) : (i += VEC_LEN) {
        const raw_x: U8xN = q_input[i..][0..VEC_LEN].*;
        const x: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw_x));
        const w0: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(q_weight0[i..][0..VEC_LEN].*));
        const w1: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(q_weight1[i..][0..VEC_LEN].*));
        const w2: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(q_weight2[i..][0..VEC_LEN].*));
        const w3: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(q_weight3[i..][0..VEC_LEN].*));
        acc0 += x * w0;
        acc1 += x * w1;
        acc2 += x * w2;
        acc3 += x * w3;
    }
    return .{ @reduce(.Add, acc0), @reduce(.Add, acc1), @reduce(.Add, acc2), @reduce(.Add, acc3) };
}

fn dotI8I8Block8_16(
    q_input: *const [16]u8,
    q_weight0: *const [16]u8,
    q_weight1: *const [16]u8,
    q_weight2: *const [16]u8,
    q_weight3: *const [16]u8,
    q_weight4: *const [16]u8,
    q_weight5: *const [16]u8,
    q_weight6: *const [16]u8,
    q_weight7: *const [16]u8,
) [8]i32 {
    const dots = dotI8I8Block8_16Vec(q_input, q_weight0, q_weight1, q_weight2, q_weight3, q_weight4, q_weight5, q_weight6, q_weight7);
    return .{
        dots[0],
        dots[1],
        dots[2],
        dots[3],
        dots[4],
        dots[5],
        dots[6],
        dots[7],
    };
}

inline fn dotI8I8Block8_16Vec(
    q_input: *const [16]u8,
    q_weight0: *const [16]u8,
    q_weight1: *const [16]u8,
    q_weight2: *const [16]u8,
    q_weight3: *const [16]u8,
    q_weight4: *const [16]u8,
    q_weight5: *const [16]u8,
    q_weight6: *const [16]u8,
    q_weight7: *const [16]u8,
) I32x8 {
    if (comptime native_aarch64_dotprod) {
        const raw_x: U8x16 = q_input.*;
        const acc0 = aarch64Sdot16(@splat(0), raw_x, q_weight0.*);
        const acc1 = aarch64Sdot16(@splat(0), raw_x, q_weight1.*);
        const acc2 = aarch64Sdot16(@splat(0), raw_x, q_weight2.*);
        const acc3 = aarch64Sdot16(@splat(0), raw_x, q_weight3.*);
        const acc4 = aarch64Sdot16(@splat(0), raw_x, q_weight4.*);
