    var acc31: I32x4 = @splat(0);
    var acc32: I32x4 = @splat(0);
    var acc33: I32x4 = @splat(0);
    comptime var i: usize = 0;
    inline while (i < 32) : (i += 16) {
        const raw_x0: U8x16 = q_input_r0[i..][0..16].*;
        const raw_x1: U8x16 = q_input_r1[i..][0..16].*;
        const raw_x2: U8x16 = q_input_r2[i..][0..16].*;
        const raw_x3: U8x16 = q_input_r3[i..][0..16].*;
        const raw_w0: U8x16 = q_weight0[i..][0..16].*;
        const raw_w1: U8x16 = q_weight1[i..][0..16].*;
        const raw_w2: U8x16 = q_weight2[i..][0..16].*;
        const raw_w3: U8x16 = q_weight3[i..][0..16].*;
        acc00 = aarch64Sdot16(acc00, raw_x0, raw_w0);
        acc01 = aarch64Sdot16(acc01, raw_x0, raw_w1);
        acc02 = aarch64Sdot16(acc02, raw_x0, raw_w2);
        acc03 = aarch64Sdot16(acc03, raw_x0, raw_w3);
        acc10 = aarch64Sdot16(acc10, raw_x1, raw_w0);
        acc11 = aarch64Sdot16(acc11, raw_x1, raw_w1);
        acc12 = aarch64Sdot16(acc12, raw_x1, raw_w2);
        acc13 = aarch64Sdot16(acc13, raw_x1, raw_w3);
        acc20 = aarch64Sdot16(acc20, raw_x2, raw_w0);
        acc21 = aarch64Sdot16(acc21, raw_x2, raw_w1);
        acc22 = aarch64Sdot16(acc22, raw_x2, raw_w2);
        acc23 = aarch64Sdot16(acc23, raw_x2, raw_w3);
        acc30 = aarch64Sdot16(acc30, raw_x3, raw_w0);
        acc31 = aarch64Sdot16(acc31, raw_x3, raw_w1);
        acc32 = aarch64Sdot16(acc32, raw_x3, raw_w2);
        acc33 = aarch64Sdot16(acc33, raw_x3, raw_w3);
    }
    return .{
        @reduce(.Add, acc00), @reduce(.Add, acc01), @reduce(.Add, acc02), @reduce(.Add, acc03),
        @reduce(.Add, acc10), @reduce(.Add, acc11), @reduce(.Add, acc12), @reduce(.Add, acc13),
        @reduce(.Add, acc20), @reduce(.Add, acc21), @reduce(.Add, acc22), @reduce(.Add, acc23),
        @reduce(.Add, acc30), @reduce(.Add, acc31), @reduce(.Add, acc32), @reduce(.Add, acc33),
    };
}

fn dotI8I8Block8MR4RowsVecAarch64Sdot(
    q_input_r0: *const [32]u8,
    q_input_r1: *const [32]u8,
    q_input_r2: *const [32]u8,
    q_input_r3: *const [32]u8,
    q_weight0: *const [32]u8,
    q_weight1: *const [32]u8,
    q_weight2: *const [32]u8,
    q_weight3: *const [32]u8,
    q_weight4: *const [32]u8,
    q_weight5: *const [32]u8,
    q_weight6: *const [32]u8,
    q_weight7: *const [32]u8,
) DotI8I8Block8MR4RowsVec {
    const rows01 = dotI8I8Block8MR2RowsVecAarch64Sdot(q_input_r0, q_input_r1, q_weight0, q_weight1, q_weight2, q_weight3, q_weight4, q_weight5, q_weight6, q_weight7);
    const rows23 = dotI8I8Block8MR2RowsVecAarch64Sdot(q_input_r2, q_input_r3, q_weight0, q_weight1, q_weight2, q_weight3, q_weight4, q_weight5, q_weight6, q_weight7);
    return .{
        .r0 = rows01.r0,
        .r1 = rows01.r1,
        .r2 = rows23.r0,
        .r3 = rows23.r1,
    };
}

fn dotI8I8Block8MR4RowsContiguousVecAarch64Sdot(
    q_input_r0: *const [32]u8,
    q_input_r1: *const [32]u8,
    q_input_r2: *const [32]u8,
    q_input_r3: *const [32]u8,
    values: []const u8,
) DotI8I8Block8MR4RowsVec {
    const rows01 = dotI8I8Block8MR2RowsContiguousVecAarch64Sdot(q_input_r0, q_input_r1, values);
    const rows23 = dotI8I8Block8MR2RowsContiguousVecAarch64Sdot(q_input_r2, q_input_r3, values);
    return .{
        .r0 = rows01.r0,
        .r1 = rows01.r1,
        .r2 = rows23.r0,
        .r3 = rows23.r1,
    };
}

fn dotI8I8Block4MR2Aarch64Sdot(
    q_input_r0: *const [32]u8,
    q_input_r1: *const [32]u8,
    q_weight0: *const [32]u8,
    q_weight1: *const [32]u8,
    q_weight2: *const [32]u8,
    q_weight3: *const [32]u8,
) struct { i32, i32, i32, i32, i32, i32, i32, i32 } {
    var acc00: I32x4 = @splat(0);
    var acc01: I32x4 = @splat(0);
    var acc02: I32x4 = @splat(0);
    var acc03: I32x4 = @splat(0);
    var acc10: I32x4 = @splat(0);
    var acc11: I32x4 = @splat(0);
    var acc12: I32x4 = @splat(0);
    var acc13: I32x4 = @splat(0);
    comptime var i: usize = 0;
    inline while (i < 32) : (i += 16) {
        const raw_x0: U8x16 = q_input_r0[i..][0..16].*;
        const raw_x1: U8x16 = q_input_r1[i..][0..16].*;
        const raw_w0: U8x16 = q_weight0[i..][0..16].*;
        const raw_w1: U8x16 = q_weight1[i..][0..16].*;
        const raw_w2: U8x16 = q_weight2[i..][0..16].*;
        const raw_w3: U8x16 = q_weight3[i..][0..16].*;
        acc00 = aarch64Sdot16(acc00, raw_x0, raw_w0);
        acc01 = aarch64Sdot16(acc01, raw_x0, raw_w1);
        acc02 = aarch64Sdot16(acc02, raw_x0, raw_w2);
        acc03 = aarch64Sdot16(acc03, raw_x0, raw_w3);
        acc10 = aarch64Sdot16(acc10, raw_x1, raw_w0);
        acc11 = aarch64Sdot16(acc11, raw_x1, raw_w1);
        acc12 = aarch64Sdot16(acc12, raw_x1, raw_w2);
        acc13 = aarch64Sdot16(acc13, raw_x1, raw_w3);
    }
    return .{
        @reduce(.Add, acc00),
        @reduce(.Add, acc01),
        @reduce(.Add, acc02),
        @reduce(.Add, acc03),
        @reduce(.Add, acc10),
        @reduce(.Add, acc11),
        @reduce(.Add, acc12),
        @reduce(.Add, acc13),
    };
}

fn linearQ8_0QuantizedInputRange(
    comptime prepared: bool,
    q_input: []const u8,
    input_scales: []const f32,
    weight_blocks: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    bias: ?[]const f32,
) void {
    const block_size: usize = q8_0BlockSize(prepared);
    const values_per_block: usize = 32;
    std.debug.assert(in_dim % values_per_block == 0);
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * block_size;

    var r: usize = 0;
    while (r + 2 <= rows) : (r += 2) {
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
        const input_q_row0 = q_input[r * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_q_row1 = q_input[(r + 1) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_scale_row0 = input_scales[r * row_blocks ..][0..row_blocks];
        const input_scale_row1 = input_scales[(r + 1) * row_blocks ..][0..row_blocks];
        var o: usize = out_start;
        while (o < out_end and (o % 4) != 0) : (o += 1) {
            const w_off = o * row_stride;
            var acc0: f32 = optionalLinearBiasAt(bias, o);
            var acc1: f32 = optionalLinearBiasAt(bias, o);
            for (0..row_blocks) |block_idx| {
                const w_blk = weight_blocks[w_off + block_idx * block_size ..][0..block_size];
                const weight_scale = q8_0WeightScale(prepared, w_blk);
                const scale0 = input_scale_row0[block_idx] * weight_scale;
                const scale1 = input_scale_row1[block_idx] * weight_scale;
                const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..32];
                const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..32];
                const qw = q8_0WeightValues(prepared, w_blk);
                acc0 += scale0 * @as(f32, @floatFromInt(dotI8I8Block(qx0, qw)));
                acc1 += scale1 * @as(f32, @floatFromInt(dotI8I8Block(qx1, qw)));
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
        }
        while (o + 4 <= out_dim) : (o += 4) {
            if (o + 4 > out_end) break;
            const w0_off = o * row_stride;
            const w1_off = (o + 1) * row_stride;
            const w2_off = (o + 2) * row_stride;
            const w3_off = (o + 3) * row_stride;
            var acc00: f32 = optionalLinearBiasAt(bias, o);
            var acc01: f32 = optionalLinearBiasAt(bias, o + 1);
            var acc02: f32 = optionalLinearBiasAt(bias, o + 2);
            var acc03: f32 = optionalLinearBiasAt(bias, o + 3);
            var acc10: f32 = optionalLinearBiasAt(bias, o);
            var acc11: f32 = optionalLinearBiasAt(bias, o + 1);
            var acc12: f32 = optionalLinearBiasAt(bias, o + 2);
            var acc13: f32 = optionalLinearBiasAt(bias, o + 3);
            for (0..row_blocks) |block_idx| {
                const block_off = block_idx * block_size;
                const w0_blk = weight_blocks[w0_off + block_off ..][0..block_size];
                const w1_blk = weight_blocks[w1_off + block_off ..][0..block_size];
                const w2_blk = weight_blocks[w2_off + block_off ..][0..block_size];
                const w3_blk = weight_blocks[w3_off + block_off ..][0..block_size];
                const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..32];
                const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..32];
                const dots = dotI8I8Block4MR2(qx0, qx1, q8_0WeightValues(prepared, w0_blk), q8_0WeightValues(prepared, w1_blk), q8_0WeightValues(prepared, w2_blk), q8_0WeightValues(prepared, w3_blk));
                const input_scale0 = input_scale_row0[block_idx];
                const input_scale1 = input_scale_row1[block_idx];
                const weight_scale0 = q8_0WeightScale(prepared, w0_blk);
                const weight_scale1 = q8_0WeightScale(prepared, w1_blk);
                const weight_scale2 = q8_0WeightScale(prepared, w2_blk);
                const weight_scale3 = q8_0WeightScale(prepared, w3_blk);
                acc00 += (input_scale0 * weight_scale0) * @as(f32, @floatFromInt(dots[0]));
                acc01 += (input_scale0 * weight_scale1) * @as(f32, @floatFromInt(dots[1]));
                acc02 += (input_scale0 * weight_scale2) * @as(f32, @floatFromInt(dots[2]));
                acc03 += (input_scale0 * weight_scale3) * @as(f32, @floatFromInt(dots[3]));
                acc10 += (input_scale1 * weight_scale0) * @as(f32, @floatFromInt(dots[4]));
                acc11 += (input_scale1 * weight_scale1) * @as(f32, @floatFromInt(dots[5]));
                acc12 += (input_scale1 * weight_scale2) * @as(f32, @floatFromInt(dots[6]));
                acc13 += (input_scale1 * weight_scale3) * @as(f32, @floatFromInt(dots[7]));
            }
            out_row0[o] = acc00;
            out_row0[o + 1] = acc01;
            out_row0[o + 2] = acc02;
            out_row0[o + 3] = acc03;
            out_row1[o] = acc10;
            out_row1[o + 1] = acc11;
            out_row1[o + 2] = acc12;
            out_row1[o + 3] = acc13;
        }
        while (o < out_end) : (o += 1) {
            const w_off = o * row_stride;
            var acc0: f32 = optionalLinearBiasAt(bias, o);
            var acc1: f32 = optionalLinearBiasAt(bias, o);
            for (0..row_blocks) |block_idx| {
                const w_blk = weight_blocks[w_off + block_idx * block_size ..][0..block_size];
                const weight_scale = q8_0WeightScale(prepared, w_blk);
                const scale0 = input_scale_row0[block_idx] * weight_scale;
                const scale1 = input_scale_row1[block_idx] * weight_scale;
                const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..32];
                const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..32];
                const qw = q8_0WeightValues(prepared, w_blk);
                acc0 += scale0 * @as(f32, @floatFromInt(dotI8I8Block(qx0, qw)));
                acc1 += scale1 * @as(f32, @floatFromInt(dotI8I8Block(qx1, qw)));
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
        }
    }

    while (r < rows) : (r += 1) {
        const out_row = output[r * out_dim ..][0..out_dim];
        const input_q_row = q_input[r * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_scale_row = input_scales[r * row_blocks ..][0..row_blocks];
        var o: usize = out_start;
        while (o < out_end and (o % 4) != 0) : (o += 1) {
            const w_off = o * row_stride;
            var acc: f32 = optionalLinearBiasAt(bias, o);
            for (0..row_blocks) |block_idx| {
                const w_blk = weight_blocks[w_off + block_idx * block_size ..][0..block_size];
                const weight_scale = q8_0WeightScale(prepared, w_blk);
                const input_scale = input_scale_row[block_idx];
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..32];
                const qw = q8_0WeightValues(prepared, w_blk);
                acc += (input_scale * weight_scale) * @as(f32, @floatFromInt(dotI8I8Block(qx, qw)));
            }
            out_row[o] = acc;
        }
        while (o + 4 <= out_dim) : (o += 4) {
            if (o + 4 > out_end) break;
            const w0_off = o * row_stride;
            const w1_off = (o + 1) * row_stride;
            const w2_off = (o + 2) * row_stride;
            const w3_off = (o + 3) * row_stride;
            var acc0: f32 = optionalLinearBiasAt(bias, o);
            var acc1: f32 = optionalLinearBiasAt(bias, o + 1);
            var acc2: f32 = optionalLinearBiasAt(bias, o + 2);
            var acc3: f32 = optionalLinearBiasAt(bias, o + 3);
            for (0..row_blocks) |block_idx| {
                const block_off = block_idx * block_size;
                const w0_blk = weight_blocks[w0_off + block_off ..][0..block_size];
                const w1_blk = weight_blocks[w1_off + block_off ..][0..block_size];
                const w2_blk = weight_blocks[w2_off + block_off ..][0..block_size];
                const w3_blk = weight_blocks[w3_off + block_off ..][0..block_size];
                const input_scale = input_scale_row[block_idx];
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..32];
                const dots = dotI8I8Block4(qx, q8_0WeightValues(prepared, w0_blk), q8_0WeightValues(prepared, w1_blk), q8_0WeightValues(prepared, w2_blk), q8_0WeightValues(prepared, w3_blk));
                acc0 += (input_scale * q8_0WeightScale(prepared, w0_blk)) * @as(f32, @floatFromInt(dots[0]));
                acc1 += (input_scale * q8_0WeightScale(prepared, w1_blk)) * @as(f32, @floatFromInt(dots[1]));
                acc2 += (input_scale * q8_0WeightScale(prepared, w2_blk)) * @as(f32, @floatFromInt(dots[2]));
                acc3 += (input_scale * q8_0WeightScale(prepared, w3_blk)) * @as(f32, @floatFromInt(dots[3]));
            }
            out_row[o] = acc0;
            out_row[o + 1] = acc1;
            out_row[o + 2] = acc2;
            out_row[o + 3] = acc3;
        }
        while (o < out_end) : (o += 1) {
            const w_off = o * row_stride;
            var acc: f32 = optionalLinearBiasAt(bias, o);
            for (0..row_blocks) |block_idx| {
                const w_blk = weight_blocks[w_off + block_idx * block_size ..][0..block_size];
                const weight_scale = q8_0WeightScale(prepared, w_blk);
                const input_scale = input_scale_row[block_idx];
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..32];
                const qw = q8_0WeightValues(prepared, w_blk);
                acc += (input_scale * weight_scale) * @as(f32, @floatFromInt(dotI8I8Block(qx, qw)));
            }
            out_row[o] = acc;
        }
    }
}

fn linearQ8_0QuantizedInputPreparedPanelMR4Rows(
    q_input: []const u8,
    input_scales: []const f32,
    prepared_blocks: []const u8,
    panel_blocks: []const u8,
    output: []f32,
    rows: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    bias: ?[]const f32,
    row_blocks: usize,
    row_stride: usize,
) usize {
    const block_size: usize = prepared_q8_0_block_bytes;
    const values_per_block: usize = 32;
    var r: usize = 0;
    while (r + 4 <= rows) : (r += 4) {
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
        const out_row2 = output[(r + 2) * out_dim ..][0..out_dim];
        const out_row3 = output[(r + 3) * out_dim ..][0..out_dim];
        const input_q_row0 = q_input[r * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_q_row1 = q_input[(r + 1) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_q_row2 = q_input[(r + 2) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_q_row3 = q_input[(r + 3) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_scale_row0 = input_scales[r * row_blocks ..][0..row_blocks];
        const input_scale_row1 = input_scales[(r + 1) * row_blocks ..][0..row_blocks];
        const input_scale_row2 = input_scales[(r + 2) * row_blocks ..][0..row_blocks];
        const input_scale_row3 = input_scales[(r + 3) * row_blocks ..][0..row_blocks];
        var o: usize = out_start;
        while (o < out_end and (o % prepared_q8_0_panel_nr) != 0) : (o += 1) {
            const w_off = o * row_stride;
            var acc0: f32 = optionalLinearBiasAt(bias, o);
            var acc1: f32 = acc0;
            var acc2: f32 = acc0;
            var acc3: f32 = acc0;
            for (0..row_blocks) |block_idx| {
                const w_blk = prepared_blocks[w_off + block_idx * block_size ..][0..block_size];
                const weight_scale = q8_0WeightScale(true, w_blk);
                const qw = q8_0WeightValues(true, w_blk);
                const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..32];
                const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..32];
                const qx2: *const [32]u8 = input_q_row2[block_idx * values_per_block ..][0..32];
                const qx3: *const [32]u8 = input_q_row3[block_idx * values_per_block ..][0..32];
                acc0 += (input_scale_row0[block_idx] * weight_scale) * @as(f32, @floatFromInt(dotI8I8Block(qx0, qw)));
                acc1 += (input_scale_row1[block_idx] * weight_scale) * @as(f32, @floatFromInt(dotI8I8Block(qx1, qw)));
                acc2 += (input_scale_row2[block_idx] * weight_scale) * @as(f32, @floatFromInt(dotI8I8Block(qx2, qw)));
                acc3 += (input_scale_row3[block_idx] * weight_scale) * @as(f32, @floatFromInt(dotI8I8Block(qx3, qw)));
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
            out_row2[o] = acc2;
            out_row3[o] = acc3;
        }
        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc = [_]f32{
                optionalLinearBiasAt(bias, o),
                optionalLinearBiasAt(bias, o + 1),
                optionalLinearBiasAt(bias, o + 2),
                optionalLinearBiasAt(bias, o + 3),
                optionalLinearBiasAt(bias, o),
                optionalLinearBiasAt(bias, o + 1),
                optionalLinearBiasAt(bias, o + 2),
                optionalLinearBiasAt(bias, o + 3),
                optionalLinearBiasAt(bias, o),
                optionalLinearBiasAt(bias, o + 1),
                optionalLinearBiasAt(bias, o + 2),
                optionalLinearBiasAt(bias, o + 3),
                optionalLinearBiasAt(bias, o),
                optionalLinearBiasAt(bias, o + 1),
                optionalLinearBiasAt(bias, o + 2),
                optionalLinearBiasAt(bias, o + 3),
            };
            for (0..row_blocks) |block_idx| {
                const panel_off = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
                const w0_blk = panel_blocks[panel_off..][0..block_size];
                const w1_blk = panel_blocks[panel_off + block_size ..][0..block_size];
                const w2_blk = panel_blocks[panel_off + 2 * block_size ..][0..block_size];
                const w3_blk = panel_blocks[panel_off + 3 * block_size ..][0..block_size];
                const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..32];
                const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..32];
                const qx2: *const [32]u8 = input_q_row2[block_idx * values_per_block ..][0..32];
                const qx3: *const [32]u8 = input_q_row3[block_idx * values_per_block ..][0..32];
                const dots = dotI8I8Block4MR4(
                    qx0,
                    qx1,
                    qx2,
                    qx3,
                    q8_0WeightValues(true, w0_blk),
                    q8_0WeightValues(true, w1_blk),
                    q8_0WeightValues(true, w2_blk),
                    q8_0WeightValues(true, w3_blk),
                );
                const weight_scales = [_]f32{
                    q8_0WeightScale(true, w0_blk),
                    q8_0WeightScale(true, w1_blk),
                    q8_0WeightScale(true, w2_blk),
                    q8_0WeightScale(true, w3_blk),
                };
                const input_scales_for_block = [_]f32{
                    input_scale_row0[block_idx],
                    input_scale_row1[block_idx],
                    input_scale_row2[block_idx],
                    input_scale_row3[block_idx],
                };
                inline for (0..4) |rr| {
                    inline for (0..4) |cc| {
                        acc[rr * 4 + cc] += (input_scales_for_block[rr] * weight_scales[cc]) * @as(f32, @floatFromInt(dots[rr * 4 + cc]));
                    }
                }
            }
            out_row0[o] = acc[0];
            out_row0[o + 1] = acc[1];
            out_row0[o + 2] = acc[2];
            out_row0[o + 3] = acc[3];
            out_row1[o] = acc[4];
            out_row1[o + 1] = acc[5];
            out_row1[o + 2] = acc[6];
            out_row1[o + 3] = acc[7];
            out_row2[o] = acc[8];
            out_row2[o + 1] = acc[9];
            out_row2[o + 2] = acc[10];
            out_row2[o + 3] = acc[11];
            out_row3[o] = acc[12];
            out_row3[o + 1] = acc[13];
            out_row3[o + 2] = acc[14];
            out_row3[o + 3] = acc[15];
        }
        while (o < out_end) : (o += 1) {
            const w_off = o * row_stride;
            var acc0: f32 = optionalLinearBiasAt(bias, o);
            var acc1: f32 = acc0;
            var acc2: f32 = acc0;
            var acc3: f32 = acc0;
            for (0..row_blocks) |block_idx| {
                const w_blk = prepared_blocks[w_off + block_idx * block_size ..][0..block_size];
                const weight_scale = q8_0WeightScale(true, w_blk);
                const qw = q8_0WeightValues(true, w_blk);
                const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..32];
                const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..32];
                const qx2: *const [32]u8 = input_q_row2[block_idx * values_per_block ..][0..32];
                const qx3: *const [32]u8 = input_q_row3[block_idx * values_per_block ..][0..32];
                acc0 += (input_scale_row0[block_idx] * weight_scale) * @as(f32, @floatFromInt(dotI8I8Block(qx0, qw)));
                acc1 += (input_scale_row1[block_idx] * weight_scale) * @as(f32, @floatFromInt(dotI8I8Block(qx1, qw)));
                acc2 += (input_scale_row2[block_idx] * weight_scale) * @as(f32, @floatFromInt(dotI8I8Block(qx2, qw)));
                acc3 += (input_scale_row3[block_idx] * weight_scale) * @as(f32, @floatFromInt(dotI8I8Block(qx3, qw)));
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
            out_row2[o] = acc2;
            out_row3[o] = acc3;
        }
    }
    return r;
}

fn linearQ8_0QuantizedInputPreparedPanelRange(
    q_input: []const u8,
    input_scales: []const f32,
    prepared_blocks: []const u8,
    panel_blocks: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    bias: ?[]const f32,
) void {
    const block_size: usize = prepared_q8_0_block_bytes;
    const values_per_block: usize = 32;
    std.debug.assert(in_dim % values_per_block == 0);
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * block_size;

    var r: usize = linearQ8_0QuantizedInputPreparedPanelMR4Rows(
        q_input,
        input_scales,
        prepared_blocks,
        panel_blocks,
        output,
        rows,
        out_dim,
        out_start,
        out_end,
        bias,
        row_blocks,
        row_stride,
    );
    while (r + 2 <= rows) : (r += 2) {
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
        const input_q_row0 = q_input[r * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_q_row1 = q_input[(r + 1) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_scale_row0 = input_scales[r * row_blocks ..][0..row_blocks];
        const input_scale_row1 = input_scales[(r + 1) * row_blocks ..][0..row_blocks];
        var o: usize = out_start;
        while (o < out_end and (o % prepared_q8_0_panel_nr) != 0) : (o += 1) {
            const w_off = o * row_stride;
            var acc0: f32 = optionalLinearBiasAt(bias, o);
            var acc1: f32 = optionalLinearBiasAt(bias, o);
            for (0..row_blocks) |block_idx| {
                const w_blk = prepared_blocks[w_off + block_idx * block_size ..][0..block_size];
                const weight_scale = q8_0WeightScale(true, w_blk);
                const scale0 = input_scale_row0[block_idx] * weight_scale;
                const scale1 = input_scale_row1[block_idx] * weight_scale;
                const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..32];
                const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..32];
                const qw = q8_0WeightValues(true, w_blk);
                acc0 += scale0 * @as(f32, @floatFromInt(dotI8I8Block(qx0, qw)));
                acc1 += scale1 * @as(f32, @floatFromInt(dotI8I8Block(qx1, qw)));
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
        }
        while ((o % 8) == 0 and o + 8 <= out_end) : (o += 8) {
            var acc00: f32 = optionalLinearBiasAt(bias, o);
            var acc01: f32 = optionalLinearBiasAt(bias, o + 1);
            var acc02: f32 = optionalLinearBiasAt(bias, o + 2);
            var acc03: f32 = optionalLinearBiasAt(bias, o + 3);
            var acc04: f32 = optionalLinearBiasAt(bias, o + 4);
            var acc05: f32 = optionalLinearBiasAt(bias, o + 5);
            var acc06: f32 = optionalLinearBiasAt(bias, o + 6);
            var acc07: f32 = optionalLinearBiasAt(bias, o + 7);
            var acc10: f32 = acc00;
            var acc11: f32 = acc01;
            var acc12: f32 = acc02;
            var acc13: f32 = acc03;
            var acc14: f32 = acc04;
            var acc15: f32 = acc05;
            var acc16: f32 = acc06;
            var acc17: f32 = acc07;
            for (0..row_blocks) |block_idx| {
                const panel_off0 = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
                const panel_off1 = (((o + 4) / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
                const w0_blk = panel_blocks[panel_off0..][0..block_size];
                const w1_blk = panel_blocks[panel_off0 + block_size ..][0..block_size];
                const w2_blk = panel_blocks[panel_off0 + 2 * block_size ..][0..block_size];
                const w3_blk = panel_blocks[panel_off0 + 3 * block_size ..][0..block_size];
                const w4_blk = panel_blocks[panel_off1..][0..block_size];
                const w5_blk = panel_blocks[panel_off1 + block_size ..][0..block_size];
                const w6_blk = panel_blocks[panel_off1 + 2 * block_size ..][0..block_size];
                const w7_blk = panel_blocks[panel_off1 + 3 * block_size ..][0..block_size];
                const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..32];
                const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..32];
                const dots = dotI8I8Block8MR2(
                    qx0,
                    qx1,
                    q8_0WeightValues(true, w0_blk),
                    q8_0WeightValues(true, w1_blk),
                    q8_0WeightValues(true, w2_blk),
                    q8_0WeightValues(true, w3_blk),
                    q8_0WeightValues(true, w4_blk),
                    q8_0WeightValues(true, w5_blk),
                    q8_0WeightValues(true, w6_blk),
                    q8_0WeightValues(true, w7_blk),
                );
                const input_scale0 = input_scale_row0[block_idx];
                const input_scale1 = input_scale_row1[block_idx];
                const weight_scale0 = q8_0WeightScale(true, w0_blk);
                const weight_scale1 = q8_0WeightScale(true, w1_blk);
                const weight_scale2 = q8_0WeightScale(true, w2_blk);
                const weight_scale3 = q8_0WeightScale(true, w3_blk);
                const weight_scale4 = q8_0WeightScale(true, w4_blk);
                const weight_scale5 = q8_0WeightScale(true, w5_blk);
                const weight_scale6 = q8_0WeightScale(true, w6_blk);
                const weight_scale7 = q8_0WeightScale(true, w7_blk);
                acc00 += (input_scale0 * weight_scale0) * @as(f32, @floatFromInt(dots[0]));
                acc01 += (input_scale0 * weight_scale1) * @as(f32, @floatFromInt(dots[1]));
                acc02 += (input_scale0 * weight_scale2) * @as(f32, @floatFromInt(dots[2]));
                acc03 += (input_scale0 * weight_scale3) * @as(f32, @floatFromInt(dots[3]));
                acc04 += (input_scale0 * weight_scale4) * @as(f32, @floatFromInt(dots[4]));
                acc05 += (input_scale0 * weight_scale5) * @as(f32, @floatFromInt(dots[5]));
                acc06 += (input_scale0 * weight_scale6) * @as(f32, @floatFromInt(dots[6]));
                acc07 += (input_scale0 * weight_scale7) * @as(f32, @floatFromInt(dots[7]));
                acc10 += (input_scale1 * weight_scale0) * @as(f32, @floatFromInt(dots[8]));
                acc11 += (input_scale1 * weight_scale1) * @as(f32, @floatFromInt(dots[9]));
                acc12 += (input_scale1 * weight_scale2) * @as(f32, @floatFromInt(dots[10]));
                acc13 += (input_scale1 * weight_scale3) * @as(f32, @floatFromInt(dots[11]));
                acc14 += (input_scale1 * weight_scale4) * @as(f32, @floatFromInt(dots[12]));
                acc15 += (input_scale1 * weight_scale5) * @as(f32, @floatFromInt(dots[13]));
                acc16 += (input_scale1 * weight_scale6) * @as(f32, @floatFromInt(dots[14]));
                acc17 += (input_scale1 * weight_scale7) * @as(f32, @floatFromInt(dots[15]));
            }
            out_row0[o] = acc00;
            out_row0[o + 1] = acc01;
            out_row0[o + 2] = acc02;
            out_row0[o + 3] = acc03;
            out_row0[o + 4] = acc04;
            out_row0[o + 5] = acc05;
            out_row0[o + 6] = acc06;
            out_row0[o + 7] = acc07;
            out_row1[o] = acc10;
            out_row1[o + 1] = acc11;
            out_row1[o + 2] = acc12;
            out_row1[o + 3] = acc13;
            out_row1[o + 4] = acc14;
            out_row1[o + 5] = acc15;
            out_row1[o + 6] = acc16;
            out_row1[o + 7] = acc17;
        }
        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc00: f32 = optionalLinearBiasAt(bias, o);
            var acc01: f32 = optionalLinearBiasAt(bias, o + 1);
            var acc02: f32 = optionalLinearBiasAt(bias, o + 2);
            var acc03: f32 = optionalLinearBiasAt(bias, o + 3);
            var acc10: f32 = optionalLinearBiasAt(bias, o);
            var acc11: f32 = optionalLinearBiasAt(bias, o + 1);
            var acc12: f32 = optionalLinearBiasAt(bias, o + 2);
            var acc13: f32 = optionalLinearBiasAt(bias, o + 3);
            for (0..row_blocks) |block_idx| {
                const panel_off = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
                const w0_blk = panel_blocks[panel_off..][0..block_size];
                const w1_blk = panel_blocks[panel_off + block_size ..][0..block_size];
                const w2_blk = panel_blocks[panel_off + 2 * block_size ..][0..block_size];
                const w3_blk = panel_blocks[panel_off + 3 * block_size ..][0..block_size];
                const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..32];
                const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..32];
                const dots = dotI8I8Block4MR2(qx0, qx1, q8_0WeightValues(true, w0_blk), q8_0WeightValues(true, w1_blk), q8_0WeightValues(true, w2_blk), q8_0WeightValues(true, w3_blk));
                const input_scale0 = input_scale_row0[block_idx];
                const input_scale1 = input_scale_row1[block_idx];
                const weight_scale0 = q8_0WeightScale(true, w0_blk);
                const weight_scale1 = q8_0WeightScale(true, w1_blk);
                const weight_scale2 = q8_0WeightScale(true, w2_blk);
                const weight_scale3 = q8_0WeightScale(true, w3_blk);
                acc00 += (input_scale0 * weight_scale0) * @as(f32, @floatFromInt(dots[0]));
                acc01 += (input_scale0 * weight_scale1) * @as(f32, @floatFromInt(dots[1]));
                acc02 += (input_scale0 * weight_scale2) * @as(f32, @floatFromInt(dots[2]));
                acc03 += (input_scale0 * weight_scale3) * @as(f32, @floatFromInt(dots[3]));
                acc10 += (input_scale1 * weight_scale0) * @as(f32, @floatFromInt(dots[4]));
                acc11 += (input_scale1 * weight_scale1) * @as(f32, @floatFromInt(dots[5]));
                acc12 += (input_scale1 * weight_scale2) * @as(f32, @floatFromInt(dots[6]));
                acc13 += (input_scale1 * weight_scale3) * @as(f32, @floatFromInt(dots[7]));
            }
            out_row0[o] = acc00;
            out_row0[o + 1] = acc01;
            out_row0[o + 2] = acc02;
            out_row0[o + 3] = acc03;
            out_row1[o] = acc10;
            out_row1[o + 1] = acc11;
            out_row1[o + 2] = acc12;
            out_row1[o + 3] = acc13;
        }
        while (o < out_end) : (o += 1) {
            const w_off = o * row_stride;
            var acc0: f32 = optionalLinearBiasAt(bias, o);
            var acc1: f32 = optionalLinearBiasAt(bias, o);
            for (0..row_blocks) |block_idx| {
                const w_blk = prepared_blocks[w_off + block_idx * block_size ..][0..block_size];
                const weight_scale = q8_0WeightScale(true, w_blk);
                const scale0 = input_scale_row0[block_idx] * weight_scale;
                const scale1 = input_scale_row1[block_idx] * weight_scale;
                const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..32];
                const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..32];
                const qw = q8_0WeightValues(true, w_blk);
                acc0 += scale0 * @as(f32, @floatFromInt(dotI8I8Block(qx0, qw)));
                acc1 += scale1 * @as(f32, @floatFromInt(dotI8I8Block(qx1, qw)));
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
        }
    }

    while (r < rows) : (r += 1) {
        const out_row = output[r * out_dim ..][0..out_dim];
        const input_q_row = q_input[r * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_scale_row = input_scales[r * row_blocks ..][0..row_blocks];
        var o: usize = out_start;
        while (o < out_end and (o % prepared_q8_0_panel_nr) != 0) : (o += 1) {
            const w_off = o * row_stride;
            var acc: f32 = optionalLinearBiasAt(bias, o);
            for (0..row_blocks) |block_idx| {
                const w_blk = prepared_blocks[w_off + block_idx * block_size ..][0..block_size];
                const input_scale = input_scale_row[block_idx];
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..32];
                acc += (input_scale * q8_0WeightScale(true, w_blk)) * @as(f32, @floatFromInt(dotI8I8Block(qx, q8_0WeightValues(true, w_blk))));
            }
            out_row[o] = acc;
        }
        while ((o % 8) == 0 and o + 8 <= out_end) : (o += 8) {
            var acc0: f32 = optionalLinearBiasAt(bias, o);
            var acc1: f32 = optionalLinearBiasAt(bias, o + 1);
            var acc2: f32 = optionalLinearBiasAt(bias, o + 2);
            var acc3: f32 = optionalLinearBiasAt(bias, o + 3);
            var acc4: f32 = optionalLinearBiasAt(bias, o + 4);
            var acc5: f32 = optionalLinearBiasAt(bias, o + 5);
            var acc6: f32 = optionalLinearBiasAt(bias, o + 6);
            var acc7: f32 = optionalLinearBiasAt(bias, o + 7);
            for (0..row_blocks) |block_idx| {
                const panel_off0 = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
                const panel_off1 = (((o + 4) / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
                const w0_blk = panel_blocks[panel_off0..][0..block_size];
                const w1_blk = panel_blocks[panel_off0 + block_size ..][0..block_size];
                const w2_blk = panel_blocks[panel_off0 + 2 * block_size ..][0..block_size];
                const w3_blk = panel_blocks[panel_off0 + 3 * block_size ..][0..block_size];
                const w4_blk = panel_blocks[panel_off1..][0..block_size];
                const w5_blk = panel_blocks[panel_off1 + block_size ..][0..block_size];
                const w6_blk = panel_blocks[panel_off1 + 2 * block_size ..][0..block_size];
                const w7_blk = panel_blocks[panel_off1 + 3 * block_size ..][0..block_size];
                const input_scale = input_scale_row[block_idx];
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..32];
                const dots = dotI8I8Block8(
                    qx,
                    q8_0WeightValues(true, w0_blk),
                    q8_0WeightValues(true, w1_blk),
                    q8_0WeightValues(true, w2_blk),
                    q8_0WeightValues(true, w3_blk),
                    q8_0WeightValues(true, w4_blk),
                    q8_0WeightValues(true, w5_blk),
                    q8_0WeightValues(true, w6_blk),
                    q8_0WeightValues(true, w7_blk),
                );
                acc0 += (input_scale * q8_0WeightScale(true, w0_blk)) * @as(f32, @floatFromInt(dots[0]));
                acc1 += (input_scale * q8_0WeightScale(true, w1_blk)) * @as(f32, @floatFromInt(dots[1]));
                acc2 += (input_scale * q8_0WeightScale(true, w2_blk)) * @as(f32, @floatFromInt(dots[2]));
                acc3 += (input_scale * q8_0WeightScale(true, w3_blk)) * @as(f32, @floatFromInt(dots[3]));
                acc4 += (input_scale * q8_0WeightScale(true, w4_blk)) * @as(f32, @floatFromInt(dots[4]));
                acc5 += (input_scale * q8_0WeightScale(true, w5_blk)) * @as(f32, @floatFromInt(dots[5]));
                acc6 += (input_scale * q8_0WeightScale(true, w6_blk)) * @as(f32, @floatFromInt(dots[6]));
                acc7 += (input_scale * q8_0WeightScale(true, w7_blk)) * @as(f32, @floatFromInt(dots[7]));
            }
            out_row[o] = acc0;
            out_row[o + 1] = acc1;
            out_row[o + 2] = acc2;
            out_row[o + 3] = acc3;
            out_row[o + 4] = acc4;
            out_row[o + 5] = acc5;
            out_row[o + 6] = acc6;
            out_row[o + 7] = acc7;
        }
        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc0: f32 = optionalLinearBiasAt(bias, o);
            var acc1: f32 = optionalLinearBiasAt(bias, o + 1);
            var acc2: f32 = optionalLinearBiasAt(bias, o + 2);
            var acc3: f32 = optionalLinearBiasAt(bias, o + 3);
            for (0..row_blocks) |block_idx| {
                const panel_off = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
                const w0_blk = panel_blocks[panel_off..][0..block_size];
                const w1_blk = panel_blocks[panel_off + block_size ..][0..block_size];
                const w2_blk = panel_blocks[panel_off + 2 * block_size ..][0..block_size];
                const w3_blk = panel_blocks[panel_off + 3 * block_size ..][0..block_size];
                const input_scale = input_scale_row[block_idx];
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..32];
                const dots = dotI8I8Block4(qx, q8_0WeightValues(true, w0_blk), q8_0WeightValues(true, w1_blk), q8_0WeightValues(true, w2_blk), q8_0WeightValues(true, w3_blk));
                acc0 += (input_scale * q8_0WeightScale(true, w0_blk)) * @as(f32, @floatFromInt(dots[0]));
                acc1 += (input_scale * q8_0WeightScale(true, w1_blk)) * @as(f32, @floatFromInt(dots[1]));
                acc2 += (input_scale * q8_0WeightScale(true, w2_blk)) * @as(f32, @floatFromInt(dots[2]));
                acc3 += (input_scale * q8_0WeightScale(true, w3_blk)) * @as(f32, @floatFromInt(dots[3]));
            }
            out_row[o] = acc0;
            out_row[o + 1] = acc1;
            out_row[o + 2] = acc2;
            out_row[o + 3] = acc3;
        }
        while (o < out_end) : (o += 1) {
            const w_off = o * row_stride;
            var acc: f32 = optionalLinearBiasAt(bias, o);
            for (0..row_blocks) |block_idx| {
                const w_blk = prepared_blocks[w_off + block_idx * block_size ..][0..block_size];
                const input_scale = input_scale_row[block_idx];
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..32];
                acc += (input_scale * q8_0WeightScale(true, w_blk)) * @as(f32, @floatFromInt(dotI8I8Block(qx, q8_0WeightValues(true, w_blk))));
            }
            out_row[o] = acc;
        }
    }
}

fn quantizeQ8_KActivationRows(
    input: []const f32,
    q_blocks: []u8,
    rows: usize,
    in_dim: usize,
    row_blocks: usize,
) void {
    @setEvalBranchQuota(20_000);
    const values_per_block: usize = 256;
    const block_size: usize = 292;
    std.debug.assert(q_blocks.len == rows * row_blocks * block_size);
    if (row_blocks == 3) {
        quantizeQ8_KActivationRows3(input, q_blocks, rows, in_dim);
        return;
    }
    for (0..rows) |r| {
        const input_row = input[r * in_dim ..][0..in_dim];
        for (0..row_blocks) |block_idx| {
            quant_codec.quantizeQ8_KBlock(
                input_row[block_idx * values_per_block ..][0..values_per_block],
                q_blocks[(r * row_blocks + block_idx) * block_size ..][0..block_size],
            );
        }
    }
}

fn quantizeQ8_KActivationRows3(
    input: []const f32,
    q_blocks: []u8,
    rows: usize,
    in_dim: usize,
) void {
    const values_per_block: usize = 256;
    const block_size: usize = 292;
    std.debug.assert(in_dim >= values_per_block * 3);
    std.debug.assert(q_blocks.len == rows * 3 * block_size);
    for (0..rows) |r| {
        const input_row = input[r * in_dim ..][0..in_dim];
        const q_row = q_blocks[r * 3 * block_size ..][0 .. 3 * block_size];
        quant_codec.quantizeQ8_KBlock(input_row[0..256], q_row[0..292]);
        quant_codec.quantizeQ8_KBlock(input_row[256..512], q_row[292..584]);
        quant_codec.quantizeQ8_KBlock(input_row[512..768], q_row[584..876]);
    }
}

fn q8KActivationQuantWorker(ctx: *Q8KActivationQuantWorkerCtx) void {
    quantizeQ8_KActivationRows(ctx.input, ctx.q_blocks, ctx.rows, ctx.in_dim, ctx.row_blocks);
    ctx.err = null;
}

fn q8KActivationQuantWorkerJob(raw: *anyopaque) void {
    q8KActivationQuantWorker(@ptrCast(@alignCast(raw)));
}

fn quantizeQ8_KActivationRowsDispatch(
    io: ?std.Io,
    input: []const f32,
    q_blocks: []u8,
    rows: usize,
    in_dim: usize,
    row_blocks: usize,
) !void {
    const block_size: usize = 292;
    const plan = chooseActivationQuantParallelPlan(quantParallelEnabled(), rows, in_dim, quantParallelMaxWorkers());
    if (plan.worker_count <= 1) {
        quantizeQ8_KActivationRows(input, q_blocks, rows, in_dim, row_blocks);
        return;
    }
    if (quantParallelDebugRequested()) {
        std.debug.print("q8_k_activation_quant_parallel workers={d} rows={d} in={d} row_blocks={d}\n", .{ plan.worker_count, rows, in_dim, row_blocks });
    }

    var chunks: [max_q4_k_parallel_workers]QuantRowChunk = undefined;
    const num_chunks = chunkRowsForWorkers(rows, plan, &chunks);
    var contexts: [max_q4_k_parallel_workers]Q8KActivationQuantWorkerCtx = undefined;
    var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
    for (chunks[0..num_chunks], 0..) |chunk, i| {
        contexts[i] = .{
            .input = input[chunk.start * in_dim .. chunk.end * in_dim],
            .q_blocks = q_blocks[chunk.start * row_blocks * block_size .. chunk.end * row_blocks * block_size],
            .rows = chunk.end - chunk.start,
            .in_dim = in_dim,
            .row_blocks = row_blocks,
        };
        jobs[i] = .{ .fn_ptr = q8KActivationQuantWorkerJob, .ctx = @ptrCast(&contexts[i]) };
    }
    try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
}

fn linearQ6KQ8KActivationRange(
    q_input: []const u8,
    weight_raw: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    @setEvalBranchQuota(20_000);
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    const q6_block_size: usize = 210;
    std.debug.assert(in_dim % values_per_block == 0);
    const row_blocks = in_dim / values_per_block;
    const input_row_stride = row_blocks * q8_block_size;
    const weight_row_stride = row_blocks * q6_block_size;

    for (0..rows) |r| {
        const q_input_row = q_input[r * input_row_stride ..][0..input_row_stride];
        const out_row = output[r * out_dim ..][0..out_dim];
        for (out_start..out_end) |o| {
            const weight_row = weight_raw[o * weight_row_stride ..][0..weight_row_stride];
            var acc: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                acc += dotQ6_KQ8_KBlock(
                    q_input_row[block_idx * q8_block_size ..][0..q8_block_size],
                    weight_row[block_idx * q6_block_size ..][0..q6_block_size],
                );
            }
            out_row[o] = acc;
        }
    }
}

fn linearQ8KQ8KActivationRange(
    q_input: []const u8,
    weight_raw: []const u8,
    panel_blocks: ?[]const u8,
    panel8_blocks: ?[]const u8,
    panel16_blocks: ?[]const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    @setEvalBranchQuota(20_000);
    const values_per_block: usize = 256;
    const block_size: usize = 292;
    std.debug.assert(in_dim % values_per_block == 0);
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * block_size;
    const use_fused_sdot = q8KFusedSdotEnabled();

    var r: usize = 0;
    while (r + 4 <= rows) : (r += 4) {
        const q_input_row0 = q_input[r * row_stride ..][0..row_stride];
        const q_input_row1 = q_input[(r + 1) * row_stride ..][0..row_stride];
        const q_input_row2 = q_input[(r + 2) * row_stride ..][0..row_stride];
        const q_input_row3 = q_input[(r + 3) * row_stride ..][0..row_stride];
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
        const out_row2 = output[(r + 2) * out_dim ..][0..out_dim];
        const out_row3 = output[(r + 3) * out_dim ..][0..out_dim];
        var o: usize = out_start;
        const panel_align: usize = if (panel16_blocks != null) prepared_k_panel16_nr else if (panel8_blocks != null) prepared_k_panel8_nr else prepared_q8_0_panel_nr;
        while (o < out_end and (o % panel_align) != 0) : (o += 1) {
            const weight_row = weight_raw[o * row_stride ..][0..row_stride];
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            var acc2: f32 = 0.0;
            var acc3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const off = block_idx * block_size;
                const w = weight_row[off..][0..block_size];
                acc0 += dotQ8KQ8KBlock(q_input_row0[off..][0..block_size], w);
                acc1 += dotQ8KQ8KBlock(q_input_row1[off..][0..block_size], w);
                acc2 += dotQ8KQ8KBlock(q_input_row2[off..][0..block_size], w);
                acc3 += dotQ8KQ8KBlock(q_input_row3[off..][0..block_size], w);
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
            out_row2[o] = acc2;
            out_row3[o] = acc3;
        }
        if (panel16_blocks) |panel16| {
            while ((o % prepared_k_panel16_nr) == 0 and o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
                var acc0: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                var acc1: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                var acc2: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                var acc3: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * block_size;
                    const panel_off = ((o / prepared_k_panel16_nr) * row_blocks + block_idx) * prepared_q8_k_panel16_block_bytes;
                    const sums = dotQ8KQ8KBlock16MR4(
                        q_input_row0[off..][0..block_size],
                        q_input_row1[off..][0..block_size],
                        q_input_row2[off..][0..block_size],
                        q_input_row3[off..][0..block_size],
                        panel16[panel_off..][0..prepared_q8_k_panel16_block_bytes],
                    );
                    inline for (0..prepared_k_panel16_nr) |lane| {
                        acc0[lane] += sums.r0[lane];
                        acc1[lane] += sums.r1[lane];
                        acc2[lane] += sums.r2[lane];
                        acc3[lane] += sums.r3[lane];
                    }
                }
                inline for (0..prepared_k_panel16_nr) |lane| {
                    out_row0[o + lane] = acc0[lane];
                    out_row1[o + lane] = acc1[lane];
                    out_row2[o + lane] = acc2[lane];
                    out_row3[o + lane] = acc3[lane];
                }
            }
        }
        if (panel8_blocks) |panel8| {
            while (o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc0: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                var acc1: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                var acc2: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                var acc3: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * block_size;
                    const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_q8_k_panel8_block_bytes;
                    const sums = dotQ8KQ8KBlock8MR4(
                        q_input_row0[off..][0..block_size],
                        q_input_row1[off..][0..block_size],
                        q_input_row2[off..][0..block_size],
                        q_input_row3[off..][0..block_size],
                        panel8[panel_off..][0..prepared_q8_k_panel8_block_bytes],
                    );
                    inline for (0..prepared_k_panel8_nr) |lane| {
                        acc0[lane] += sums.r0[lane];
                        acc1[lane] += sums.r1[lane];
                        acc2[lane] += sums.r2[lane];
                        acc3[lane] += sums.r3[lane];
                    }
                }
                inline for (0..prepared_k_panel8_nr) |lane| {
                    out_row0[o + lane] = acc0[lane];
                    out_row1[o + lane] = acc1[lane];
                    out_row2[o + lane] = acc2[lane];
                    out_row3[o + lane] = acc3[lane];
                }
            }
        }
        if (q8KRawNR8DirectEnabled()) {
            while (o + 8 <= out_end) : (o += 8) {
                var acc0: [8]f32 = [_]f32{0.0} ** 8;
                var acc1: [8]f32 = [_]f32{0.0} ** 8;
                var acc2: [8]f32 = [_]f32{0.0} ** 8;
                var acc3: [8]f32 = [_]f32{0.0} ** 8;
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * block_size;
                    const weights = q8KQ8KWeightBlock8(weight_raw, panel_blocks, row_blocks, row_stride, o, block_idx, true);
                    const sums = dotQ8KQ8KBlock8MR4Blocks(
                        q_input_row0[off..][0..block_size],
                        q_input_row1[off..][0..block_size],
                        q_input_row2[off..][0..block_size],
                        q_input_row3[off..][0..block_size],
                        weights,
                    );
                    inline for (0..8) |lane| {
                        acc0[lane] += sums.r0[lane];
                        acc1[lane] += sums.r1[lane];
                        acc2[lane] += sums.r2[lane];
                        acc3[lane] += sums.r3[lane];
                    }
                }
                inline for (0..8) |lane| {
                    out_row0[o + lane] = acc0[lane];
                    out_row1[o + lane] = acc1[lane];
                    out_row2[o + lane] = acc2[lane];
                    out_row3[o + lane] = acc3[lane];
                }
            }
        }
        while (o + 4 <= out_end) : (o += 4) {
            const w0_off = o * row_stride;
            const w1_off = (o + 1) * row_stride;
            const w2_off = (o + 2) * row_stride;
            const w3_off = (o + 3) * row_stride;
            var acc: [16]f32 = [_]f32{0.0} ** 16;
            for (0..row_blocks) |block_idx| {
                const off = block_idx * block_size;
                const panel_off = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
                const w0 = if (panel_blocks) |panel| panel[panel_off..][0..block_size] else weight_raw[w0_off + off ..][0..block_size];
                const w1 = if (panel_blocks) |panel| panel[panel_off + block_size ..][0..block_size] else weight_raw[w1_off + off ..][0..block_size];
                const w2 = if (panel_blocks) |panel| panel[panel_off + 2 * block_size ..][0..block_size] else weight_raw[w2_off + off ..][0..block_size];
                const w3 = if (panel_blocks) |panel| panel[panel_off + 3 * block_size ..][0..block_size] else weight_raw[w3_off + off ..][0..block_size];
                const sums = if (use_fused_sdot)
                    dotQ8KQ8KBlock4MR4FusedSdot(
                        q_input_row0[off..][0..block_size],
                        q_input_row1[off..][0..block_size],
                        q_input_row2[off..][0..block_size],
                        q_input_row3[off..][0..block_size],
                        w0,
                        w1,
                        w2,
                        w3,
                    )
                else
                    dotQ8KQ8KBlock4MR4(
                        q_input_row0[off..][0..block_size],
                        q_input_row1[off..][0..block_size],
                        q_input_row2[off..][0..block_size],
                        q_input_row3[off..][0..block_size],
                        w0,
                        w1,
                        w2,
                        w3,
                    );
                inline for (0..16) |idx| acc[idx] += sums[idx];
            }
            inline for (0..4) |lane| {
                out_row0[o + lane] = acc[lane];
                out_row1[o + lane] = acc[4 + lane];
                out_row2[o + lane] = acc[8 + lane];
                out_row3[o + lane] = acc[12 + lane];
            }
        }
        while (o < out_end) : (o += 1) {
            const weight_row = weight_raw[o * row_stride ..][0..row_stride];
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            var acc2: f32 = 0.0;
            var acc3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const off = block_idx * block_size;
                const w = weight_row[off..][0..block_size];
                acc0 += dotQ8KQ8KBlock(q_input_row0[off..][0..block_size], w);
                acc1 += dotQ8KQ8KBlock(q_input_row1[off..][0..block_size], w);
                acc2 += dotQ8KQ8KBlock(q_input_row2[off..][0..block_size], w);
                acc3 += dotQ8KQ8KBlock(q_input_row3[off..][0..block_size], w);
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
            out_row2[o] = acc2;
            out_row3[o] = acc3;
        }
    }

    while (r + 2 <= rows) : (r += 2) {
        const q_input_row0 = q_input[r * row_stride ..][0..row_stride];
        const q_input_row1 = q_input[(r + 1) * row_stride ..][0..row_stride];
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
        var o: usize = out_start;
        const panel_align: usize = if (panel16_blocks != null) prepared_k_panel16_nr else if (panel8_blocks != null) prepared_k_panel8_nr else prepared_q8_0_panel_nr;
        while (o < out_end and (o % panel_align) != 0) : (o += 1) {
            const weight_row = weight_raw[o * row_stride ..][0..row_stride];
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const off = block_idx * block_size;
                const w = weight_row[off..][0..block_size];
                acc0 += dotQ8KQ8KBlock(q_input_row0[off..][0..block_size], w);
                acc1 += dotQ8KQ8KBlock(q_input_row1[off..][0..block_size], w);
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
        }
        if (panel16_blocks) |panel16| {
            while ((o % prepared_k_panel16_nr) == 0 and o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
                var acc0: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                var acc1: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * block_size;
                    const panel_off = ((o / prepared_k_panel16_nr) * row_blocks + block_idx) * prepared_q8_k_panel16_block_bytes;
                    const sums = dotQ8KQ8KBlock16MR2(
                        q_input_row0[off..][0..block_size],
                        q_input_row1[off..][0..block_size],
                        panel16[panel_off..][0..prepared_q8_k_panel16_block_bytes],
                    );
                    inline for (0..prepared_k_panel16_nr) |lane| {
                        acc0[lane] += sums.r0[lane];
                        acc1[lane] += sums.r1[lane];
                    }
                }
                inline for (0..prepared_k_panel16_nr) |lane| {
                    out_row0[o + lane] = acc0[lane];
                    out_row1[o + lane] = acc1[lane];
                }
            }
        }
        if (panel8_blocks) |panel8| {
            while (o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc0: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                var acc1: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * block_size;
                    const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_q8_k_panel8_block_bytes;
                    const sums = dotQ8KQ8KBlock8MR2(
                        q_input_row0[off..][0..block_size],
                        q_input_row1[off..][0..block_size],
                        panel8[panel_off..][0..prepared_q8_k_panel8_block_bytes],
                    );
                    inline for (0..prepared_k_panel8_nr) |lane| {
                        acc0[lane] += sums.r0[lane];
                        acc1[lane] += sums.r1[lane];
                    }
                }
                inline for (0..prepared_k_panel8_nr) |lane| {
                    out_row0[o + lane] = acc0[lane];
                    out_row1[o + lane] = acc1[lane];
                }
            }
        }
        if (q8KRawNR8DirectEnabled()) {
            while (o + 8 <= out_end) : (o += 8) {
                var acc0: [8]f32 = [_]f32{0.0} ** 8;
                var acc1: [8]f32 = [_]f32{0.0} ** 8;
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * block_size;
                    const weights = q8KQ8KWeightBlock8(weight_raw, panel_blocks, row_blocks, row_stride, o, block_idx, true);
                    const sums = dotQ8KQ8KBlock8MR2Blocks(
                        q_input_row0[off..][0..block_size],
                        q_input_row1[off..][0..block_size],
                        weights,
                    );
                    inline for (0..8) |lane| {
                        acc0[lane] += sums.r0[lane];
                        acc1[lane] += sums.r1[lane];
                    }
                }
                inline for (0..8) |lane| {
                    out_row0[o + lane] = acc0[lane];
                    out_row1[o + lane] = acc1[lane];
                }
            }
        }
        while (o + 4 <= out_end) : (o += 4) {
            var acc00: f32 = 0.0;
            var acc01: f32 = 0.0;
            var acc02: f32 = 0.0;
            var acc03: f32 = 0.0;
            var acc10: f32 = 0.0;
            var acc11: f32 = 0.0;
            var acc12: f32 = 0.0;
            var acc13: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const off = block_idx * block_size;
                const w0_off = o * row_stride;
                const w1_off = (o + 1) * row_stride;
                const w2_off = (o + 2) * row_stride;
                const w3_off = (o + 3) * row_stride;
                const panel_off = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
                const w0 = if (panel_blocks) |panel| panel[panel_off..][0..block_size] else weight_raw[w0_off + off ..][0..block_size];
                const w1 = if (panel_blocks) |panel| panel[panel_off + block_size ..][0..block_size] else weight_raw[w1_off + off ..][0..block_size];
                const w2 = if (panel_blocks) |panel| panel[panel_off + 2 * block_size ..][0..block_size] else weight_raw[w2_off + off ..][0..block_size];
                const w3 = if (panel_blocks) |panel| panel[panel_off + 3 * block_size ..][0..block_size] else weight_raw[w3_off + off ..][0..block_size];
                const sums = if (use_fused_sdot)
                    dotQ8KQ8KBlock4MR2FusedSdot(
                        q_input_row0[off..][0..block_size],
                        q_input_row1[off..][0..block_size],
                        w0,
                        w1,
                        w2,
                        w3,
                    )
                else
                    dotQ8KQ8KBlock4MR2(
                        q_input_row0[off..][0..block_size],
                        q_input_row1[off..][0..block_size],
                        w0,
                        w1,
                        w2,
                        w3,
                    );
                acc00 += sums[0];
                acc01 += sums[1];
                acc02 += sums[2];
                acc03 += sums[3];
                acc10 += sums[4];
                acc11 += sums[5];
                acc12 += sums[6];
                acc13 += sums[7];
            }
            out_row0[o] = acc00;
            out_row0[o + 1] = acc01;
            out_row0[o + 2] = acc02;
            out_row0[o + 3] = acc03;
            out_row1[o] = acc10;
            out_row1[o + 1] = acc11;
            out_row1[o + 2] = acc12;
            out_row1[o + 3] = acc13;
        }
        while (o < out_end) : (o += 1) {
            const weight_row = weight_raw[o * row_stride ..][0..row_stride];
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const off = block_idx * block_size;
                const w = weight_row[off..][0..block_size];
                acc0 += dotQ8KQ8KBlock(q_input_row0[off..][0..block_size], w);
                acc1 += dotQ8KQ8KBlock(q_input_row1[off..][0..block_size], w);
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
        }
    }

    while (r < rows) : (r += 1) {
        const q_input_row = q_input[r * row_stride ..][0..row_stride];
        const out_row = output[r * out_dim ..][0..out_dim];
        var o: usize = out_start;
        const panel_align: usize = if (panel16_blocks != null) prepared_k_panel16_nr else if (panel8_blocks != null) prepared_k_panel8_nr else prepared_q8_0_panel_nr;
        while (o < out_end and (o % panel_align) != 0) : (o += 1) {
            const weight_row = weight_raw[o * row_stride ..][0..row_stride];
            var acc: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const off = block_idx * block_size;
                acc += dotQ8KQ8KBlock(q_input_row[off..][0..block_size], weight_row[off..][0..block_size]);
            }
            out_row[o] = acc;
        }
        if (panel16_blocks) |panel16| {
            while ((o % prepared_k_panel16_nr) == 0 and o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
                var acc: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * block_size;
                    const panel_off = ((o / prepared_k_panel16_nr) * row_blocks + block_idx) * prepared_q8_k_panel16_block_bytes;
                    const sums = dotQ8KQ8KBlock16(q_input_row[off..][0..block_size], panel16[panel_off..][0..prepared_q8_k_panel16_block_bytes]);
                    inline for (0..prepared_k_panel16_nr) |lane| acc[lane] += sums[lane];
                }
                inline for (0..prepared_k_panel16_nr) |lane| out_row[o + lane] = acc[lane];
            }
        }
        if (panel8_blocks) |panel8| {
            while (o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * block_size;
                    const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_q8_k_panel8_block_bytes;
                    const sums = dotQ8KQ8KBlock8(q_input_row[off..][0..block_size], panel8[panel_off..][0..prepared_q8_k_panel8_block_bytes]);
                    inline for (0..prepared_k_panel8_nr) |lane| acc[lane] += sums[lane];
                }
                inline for (0..prepared_k_panel8_nr) |lane| out_row[o + lane] = acc[lane];
            }
        }
        if (q8KRawNR8DirectEnabled()) {
            while (o + 8 <= out_end) : (o += 8) {
                var acc: [8]f32 = [_]f32{0.0} ** 8;
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * block_size;
                    const weights = q8KQ8KWeightBlock8(weight_raw, panel_blocks, row_blocks, row_stride, o, block_idx, true);
                    const sums = dotQ8KQ8KBlock8Blocks(q_input_row[off..][0..block_size], weights);
                    inline for (0..8) |lane| acc[lane] += sums[lane];
                }
                inline for (0..8) |lane| out_row[o + lane] = acc[lane];
            }
        }
        while (o + 4 <= out_end) : (o += 4) {
            const w0_off = o * row_stride;
            const w1_off = (o + 1) * row_stride;
            const w2_off = (o + 2) * row_stride;
            const w3_off = (o + 3) * row_stride;
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            var acc2: f32 = 0.0;
            var acc3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const off = block_idx * block_size;
                const panel_off = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
                const w0 = if (panel_blocks) |panel| panel[panel_off..][0..block_size] else weight_raw[w0_off + off ..][0..block_size];
                const w1 = if (panel_blocks) |panel| panel[panel_off + block_size ..][0..block_size] else weight_raw[w1_off + off ..][0..block_size];
                const w2 = if (panel_blocks) |panel| panel[panel_off + 2 * block_size ..][0..block_size] else weight_raw[w2_off + off ..][0..block_size];
                const w3 = if (panel_blocks) |panel| panel[panel_off + 3 * block_size ..][0..block_size] else weight_raw[w3_off + off ..][0..block_size];
                const sums = if (use_fused_sdot)
                    dotQ8KQ8KBlock4FusedSdot(
                        q_input_row[off..][0..block_size],
                        w0,
                        w1,
                        w2,
                        w3,
                    )
                else
                    dotQ8KQ8KBlock4(
                        q_input_row[off..][0..block_size],
                        w0,
                        w1,
                        w2,
                        w3,
                    );
                acc0 += sums[0];
                acc1 += sums[1];
                acc2 += sums[2];
                acc3 += sums[3];
            }
            out_row[o] = acc0;
            out_row[o + 1] = acc1;
            out_row[o + 2] = acc2;
            out_row[o + 3] = acc3;
        }
        while (o < out_end) : (o += 1) {
            const weight_row = weight_raw[o * row_stride ..][0..row_stride];
            var acc: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const off = block_idx * block_size;
                acc += dotQ8KQ8KBlock(q_input_row[off..][0..block_size], weight_row[off..][0..block_size]);
            }
            out_row[o] = acc;
        }
    }
}

inline fn preparedKPanelBlock(
    panel_blocks: ?[]const u8,
    prepared_blocks: []const u8,
    row_blocks: usize,
    prepared_row_stride: usize,
    out_col: usize,
    block_idx: usize,
    lane: usize,
) []const u8 {
    if (panel_blocks) |panel| {
        const panel_idx = out_col / prepared_q8_0_panel_nr;
        const panel_base = (panel_idx * row_blocks + block_idx) * prepared_q8_0_panel_nr * prepared_q4_k_block_bytes;
        return panel[panel_base + lane * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes];
    }
    const row_base = (out_col + lane) * prepared_row_stride + block_idx * prepared_q4_k_block_bytes;
    return prepared_blocks[row_base..][0..prepared_q4_k_block_bytes];
}

fn linearQ6KPreparedQ8KActivationRange(
    q_input: []const u8,
    prepared_blocks: []const u8,
    panel_blocks: ?[]const u8,
    panel8_blocks: ?[]const u8,
    panel16_blocks: ?[]const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    @setEvalBranchQuota(20_000);
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    std.debug.assert(in_dim % values_per_block == 0);
    const row_blocks = in_dim / values_per_block;
    const input_row_stride = row_blocks * q8_block_size;
    const prepared_row_stride = row_blocks * prepared_q4_k_block_bytes;
    const panel_align: usize = if (panel16_blocks != null) prepared_k_panel16_nr else if (panel8_blocks != null) prepared_k_panel8_nr else prepared_q8_0_panel_nr;

    var r: usize = 0;
    while (r + 4 <= rows) : (r += 4) {
        const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
        const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
        const q_input_row2 = q_input[(r + 2) * input_row_stride ..][0..input_row_stride];
        const q_input_row3 = q_input[(r + 3) * input_row_stride ..][0..input_row_stride];
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
        const out_row2 = output[(r + 2) * out_dim ..][0..out_dim];
        const out_row3 = output[(r + 3) * out_dim ..][0..out_dim];
        var o: usize = out_start;
        while (o < out_end and (o % panel_align) != 0) : (o += 1) {
            const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            var acc2: f32 = 0.0;
            var acc3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const prepared_off = block_idx * prepared_q4_k_block_bytes;
                const prepared_block = prepared_row[prepared_off..][0..prepared_q4_k_block_bytes];
                acc0 += dotQ6KPreparedQ8KBlock(q_input_row0[q8_off..][0..q8_block_size], prepared_block);
                acc1 += dotQ6KPreparedQ8KBlock(q_input_row1[q8_off..][0..q8_block_size], prepared_block);
                acc2 += dotQ6KPreparedQ8KBlock(q_input_row2[q8_off..][0..q8_block_size], prepared_block);
                acc3 += dotQ6KPreparedQ8KBlock(q_input_row3[q8_off..][0..q8_block_size], prepared_block);
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
            out_row2[o] = acc2;
            out_row3[o] = acc3;
        }
        if (panel16_blocks) |panel16| {
            while ((o % prepared_k_panel16_nr) == 0 and o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
                var acc0: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                var acc1: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                var acc2: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                var acc3: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                for (0..row_blocks) |block_idx| {
                    const q8_off = block_idx * q8_block_size;
                    const panel_off = ((o / prepared_k_panel16_nr) * row_blocks + block_idx) * prepared_k_panel16_block_bytes;
                    const sums = dotQ6KPreparedQ8KPanel16MR4(
                        q_input_row0[q8_off..][0..q8_block_size],
                        q_input_row1[q8_off..][0..q8_block_size],
                        q_input_row2[q8_off..][0..q8_block_size],
                        q_input_row3[q8_off..][0..q8_block_size],
                        panel16[panel_off..][0..prepared_k_panel16_block_bytes],
                    );
                    inline for (0..prepared_k_panel16_nr) |idx| {
                        acc0[idx] += sums.r0[idx];
                        acc1[idx] += sums.r1[idx];
                        acc2[idx] += sums.r2[idx];
                        acc3[idx] += sums.r3[idx];
                    }
                }
                inline for (0..prepared_k_panel16_nr) |idx| {
                    out_row0[o + idx] = acc0[idx];
                    out_row1[o + idx] = acc1[idx];
                    out_row2[o + idx] = acc2[idx];
                    out_row3[o + idx] = acc3[idx];
                }
            }
        }
        if (panel8_blocks) |panel8| {
            while ((o % prepared_k_panel8_nr) == 0 and o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc0: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                var acc1: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                var acc2: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                var acc3: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                for (0..row_blocks) |block_idx| {
                    const q8_off = block_idx * q8_block_size;
                    const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_q6_k_panel8_block_bytes;
                    const sums = dotQ6KPreparedQ8KPanel8MR4(
                        q_input_row0[q8_off..][0..q8_block_size],
                        q_input_row1[q8_off..][0..q8_block_size],
                        q_input_row2[q8_off..][0..q8_block_size],
                        q_input_row3[q8_off..][0..q8_block_size],
                        panel8[panel_off..][0..prepared_q6_k_panel8_block_bytes],
                    );
                    inline for (0..prepared_k_panel8_nr) |idx| {
                        acc0[idx] += sums.r0[idx];
                        acc1[idx] += sums.r1[idx];
                        acc2[idx] += sums.r2[idx];
                        acc3[idx] += sums.r3[idx];
                    }
                }
                inline for (0..prepared_k_panel8_nr) |idx| {
                    out_row0[o + idx] = acc0[idx];
                    out_row1[o + idx] = acc1[idx];
                    out_row2[o + idx] = acc2[idx];
                    out_row3[o + idx] = acc3[idx];
                }
            }
        }
        while (o + 4 <= out_dim) : (o += 4) {
            if (o + 4 > out_end) break;
            var acc_r0_0: f32 = 0.0;
            var acc_r0_1: f32 = 0.0;
            var acc_r0_2: f32 = 0.0;
            var acc_r0_3: f32 = 0.0;
            var acc_r1_0: f32 = 0.0;
            var acc_r1_1: f32 = 0.0;
            var acc_r1_2: f32 = 0.0;
            var acc_r1_3: f32 = 0.0;
            var acc_r2_0: f32 = 0.0;
            var acc_r2_1: f32 = 0.0;
            var acc_r2_2: f32 = 0.0;
            var acc_r2_3: f32 = 0.0;
            var acc_r3_0: f32 = 0.0;
            var acc_r3_1: f32 = 0.0;
            var acc_r3_2: f32 = 0.0;
            var acc_r3_3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const sums01 = dotQ6KPreparedQ8KBlock4MR2(
                    q_input_row0[q8_off..][0..q8_block_size],
                    q_input_row1[q8_off..][0..q8_block_size],
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 0),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 1),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 2),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 3),
                );
                const sums23 = dotQ6KPreparedQ8KBlock4MR2(
                    q_input_row2[q8_off..][0..q8_block_size],
                    q_input_row3[q8_off..][0..q8_block_size],
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 0),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 1),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 2),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 3),
                );
                acc_r0_0 += sums01[0];
                acc_r0_1 += sums01[1];
                acc_r0_2 += sums01[2];
                acc_r0_3 += sums01[3];
                acc_r1_0 += sums01[4];
                acc_r1_1 += sums01[5];
                acc_r1_2 += sums01[6];
                acc_r1_3 += sums01[7];
                acc_r2_0 += sums23[0];
                acc_r2_1 += sums23[1];
                acc_r2_2 += sums23[2];
                acc_r2_3 += sums23[3];
                acc_r3_0 += sums23[4];
                acc_r3_1 += sums23[5];
                acc_r3_2 += sums23[6];
                acc_r3_3 += sums23[7];
            }
            out_row0[o] = acc_r0_0;
            out_row0[o + 1] = acc_r0_1;
            out_row0[o + 2] = acc_r0_2;
            out_row0[o + 3] = acc_r0_3;
            out_row1[o] = acc_r1_0;
            out_row1[o + 1] = acc_r1_1;
            out_row1[o + 2] = acc_r1_2;
            out_row1[o + 3] = acc_r1_3;
            out_row2[o] = acc_r2_0;
            out_row2[o + 1] = acc_r2_1;
            out_row2[o + 2] = acc_r2_2;
            out_row2[o + 3] = acc_r2_3;
            out_row3[o] = acc_r3_0;
            out_row3[o + 1] = acc_r3_1;
            out_row3[o + 2] = acc_r3_2;
            out_row3[o + 3] = acc_r3_3;
        }
        while (o < out_end) : (o += 1) {
            const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            var acc2: f32 = 0.0;
            var acc3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const prepared_off = block_idx * prepared_q4_k_block_bytes;
                const prepared_block = prepared_row[prepared_off..][0..prepared_q4_k_block_bytes];
                acc0 += dotQ6KPreparedQ8KBlock(q_input_row0[q8_off..][0..q8_block_size], prepared_block);
                acc1 += dotQ6KPreparedQ8KBlock(q_input_row1[q8_off..][0..q8_block_size], prepared_block);
                acc2 += dotQ6KPreparedQ8KBlock(q_input_row2[q8_off..][0..q8_block_size], prepared_block);
                acc3 += dotQ6KPreparedQ8KBlock(q_input_row3[q8_off..][0..q8_block_size], prepared_block);
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
            out_row2[o] = acc2;
            out_row3[o] = acc3;
        }
    }

    while (r + 2 <= rows) : (r += 2) {
        const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
        const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
        var o: usize = out_start;
        while (o < out_end and (o % panel_align) != 0) : (o += 1) {
            const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const prepared_off = block_idx * prepared_q4_k_block_bytes;
                acc0 += dotQ6KPreparedQ8KBlock(
                    q_input_row0[q8_off..][0..q8_block_size],
                    prepared_row[prepared_off..][0..prepared_q4_k_block_bytes],
                );
                acc1 += dotQ6KPreparedQ8KBlock(
                    q_input_row1[q8_off..][0..q8_block_size],
                    prepared_row[prepared_off..][0..prepared_q4_k_block_bytes],
                );
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
        }
        if (panel16_blocks) |panel16| {
            while ((o % prepared_k_panel16_nr) == 0 and o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
                var acc0: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                var acc1: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                for (0..row_blocks) |block_idx| {
                    const q8_off = block_idx * q8_block_size;
                    const panel_off = ((o / prepared_k_panel16_nr) * row_blocks + block_idx) * prepared_k_panel16_block_bytes;
                    const sums = dotQ6KPreparedQ8KPanel16MR2(
                        q_input_row0[q8_off..][0..q8_block_size],
                        q_input_row1[q8_off..][0..q8_block_size],
                        panel16[panel_off..][0..prepared_k_panel16_block_bytes],
                    );
                    inline for (0..prepared_k_panel16_nr) |idx| {
                        acc0[idx] += sums.r0[idx];
                        acc1[idx] += sums.r1[idx];
                    }
                }
                inline for (0..prepared_k_panel16_nr) |idx| {
                    out_row0[o + idx] = acc0[idx];
                    out_row1[o + idx] = acc1[idx];
                }
            }
        }
        if (panel8_blocks) |panel8| {
            while ((o % prepared_k_panel8_nr) == 0 and o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc0: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                var acc1: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                for (0..row_blocks) |block_idx| {
                    const q8_off = block_idx * q8_block_size;
                    const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_q6_k_panel8_block_bytes;
                    const panel_block = panel8[panel_off..][0..prepared_q6_k_panel8_block_bytes];
                    const sums = dotQ6KPreparedQ8KPanel8MR2(
                        q_input_row0[q8_off..][0..q8_block_size],
                        q_input_row1[q8_off..][0..q8_block_size],
                        panel_block,
                    );
                    inline for (0..prepared_k_panel8_nr) |idx| {
                        acc0[idx] += sums.r0[idx];
                        acc1[idx] += sums.r1[idx];
                    }
                }
                inline for (0..prepared_k_panel8_nr) |idx| {
                    out_row0[o + idx] = acc0[idx];
                    out_row1[o + idx] = acc1[idx];
                }
            }
        }
        while (o + 4 <= out_dim) : (o += 4) {
            if (o + 4 > out_end) break;
            var acc_r0_0: f32 = 0.0;
            var acc_r0_1: f32 = 0.0;
            var acc_r0_2: f32 = 0.0;
            var acc_r0_3: f32 = 0.0;
            var acc_r1_0: f32 = 0.0;
            var acc_r1_1: f32 = 0.0;
            var acc_r1_2: f32 = 0.0;
            var acc_r1_3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const sums = dotQ6KPreparedQ8KBlock4MR2(
                    q_input_row0[q8_off..][0..q8_block_size],
                    q_input_row1[q8_off..][0..q8_block_size],
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 0),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 1),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 2),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 3),
                );
                acc_r0_0 += sums[0];
                acc_r0_1 += sums[1];
                acc_r0_2 += sums[2];
                acc_r0_3 += sums[3];
                acc_r1_0 += sums[4];
                acc_r1_1 += sums[5];
                acc_r1_2 += sums[6];
                acc_r1_3 += sums[7];
            }
            out_row0[o] = acc_r0_0;
            out_row0[o + 1] = acc_r0_1;
            out_row0[o + 2] = acc_r0_2;
            out_row0[o + 3] = acc_r0_3;
            out_row1[o] = acc_r1_0;
            out_row1[o + 1] = acc_r1_1;
            out_row1[o + 2] = acc_r1_2;
            out_row1[o + 3] = acc_r1_3;
        }
        while (o < out_end) : (o += 1) {
            const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const prepared_off = block_idx * prepared_q4_k_block_bytes;
                acc0 += dotQ6KPreparedQ8KBlock(
                    q_input_row0[q8_off..][0..q8_block_size],
                    prepared_row[prepared_off..][0..prepared_q4_k_block_bytes],
                );
                acc1 += dotQ6KPreparedQ8KBlock(
                    q_input_row1[q8_off..][0..q8_block_size],
                    prepared_row[prepared_off..][0..prepared_q4_k_block_bytes],
                );
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
        }
    }
    while (r < rows) : (r += 1) {
        const q_input_row = q_input[r * input_row_stride ..][0..input_row_stride];
        const out_row = output[r * out_dim ..][0..out_dim];
        var o: usize = out_start;
        while (o < out_end and (o % panel_align) != 0) : (o += 1) {
            const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
            var acc: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                acc += dotQ6KPreparedQ8KBlock(
                    q_input_row[block_idx * q8_block_size ..][0..q8_block_size],
                    prepared_row[block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes],
                );
            }
            out_row[o] = acc;
        }
        if (panel16_blocks) |panel16| {
            while ((o % prepared_k_panel16_nr) == 0 and o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
                var acc: [prepared_k_panel16_nr]f32 = [_]f32{0.0} ** prepared_k_panel16_nr;
                for (0..row_blocks) |block_idx| {
                    const q8_off = block_idx * q8_block_size;
                    const panel_off = ((o / prepared_k_panel16_nr) * row_blocks + block_idx) * prepared_k_panel16_block_bytes;
                    const sums = dotQ6KPreparedQ8KPanel16(
                        q_input_row[q8_off..][0..q8_block_size],
                        panel16[panel_off..][0..prepared_k_panel16_block_bytes],
                    );
                    inline for (0..prepared_k_panel16_nr) |idx| acc[idx] += sums[idx];
                }
                inline for (0..prepared_k_panel16_nr) |idx| out_row[o + idx] = acc[idx];
            }
        }
        if (panel8_blocks) |panel8| {
            while ((o % prepared_k_panel8_nr) == 0 and o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                for (0..row_blocks) |block_idx| {
                    const q8_off = block_idx * q8_block_size;
                    const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_q6_k_panel8_block_bytes;
                    const sums = dotQ6KPreparedQ8KPanel8(
                        q_input_row[q8_off..][0..q8_block_size],
                        panel8[panel_off..][0..prepared_q6_k_panel8_block_bytes],
                    );
                    inline for (0..prepared_k_panel8_nr) |idx| acc[idx] += sums[idx];
                }
                inline for (0..prepared_k_panel8_nr) |idx| out_row[o + idx] = acc[idx];
            }
        }
        while (o + 4 <= out_dim) : (o += 4) {
            if (o + 4 > out_end) break;
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            var acc2: f32 = 0.0;
            var acc3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const sums = dotQ6KPreparedQ8KBlock4(
                    q_input_row[q8_off..][0..q8_block_size],
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 0),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 1),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 2),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 3),
                );
                acc0 += sums[0];
                acc1 += sums[1];
                acc2 += sums[2];
                acc3 += sums[3];
            }
            out_row[o] = acc0;
            out_row[o + 1] = acc1;
            out_row[o + 2] = acc2;
            out_row[o + 3] = acc3;
        }
        while (o < out_end) : (o += 1) {
            const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
            var acc: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                acc += dotQ6KPreparedQ8KBlock(
                    q_input_row[block_idx * q8_block_size ..][0..q8_block_size],
                    prepared_row[block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes],
                );
            }
            out_row[o] = acc;
        }
    }
}

fn linearQ6KPreparedQ8KActivationGroupedRange(
    comptime projection_count: usize,
    q_input: []const u8,
    prepared_blocks: [projection_count][]const u8,
    panel_blocks: [projection_count]?[]const u8,
    panel8_blocks: [projection_count]?[]const u8,
    panel16_blocks: [projection_count]?[]const u8,
