                        const panel8 = panel8_blocks[projection_idx].?;
                        const sums = dotQ6KPreparedQ8KPanel8MR4(q0, q1, q2, q3, panel8[panel_off..][0..prepared_q6_k_panel8_block_bytes]);
                        inline for (0..prepared_k_panel8_nr) |lane| {
                            acc0[projection_idx][lane] += sums.r0[lane];
                            acc1[projection_idx][lane] += sums.r1[lane];
                            acc2[projection_idx][lane] += sums.r2[lane];
                            acc3[projection_idx][lane] += sums.r3[lane];
                        }
                    }
                }
                inline for (0..projection_count) |projection_idx| {
                    const out_row0 = outputs[projection_idx][r * out_dim ..][0..out_dim];
                    const out_row1 = outputs[projection_idx][(r + 1) * out_dim ..][0..out_dim];
                    const out_row2 = outputs[projection_idx][(r + 2) * out_dim ..][0..out_dim];
                    const out_row3 = outputs[projection_idx][(r + 3) * out_dim ..][0..out_dim];
                    inline for (0..prepared_k_panel8_nr) |lane| {
