            var acc2: [projection_count][4]f32 = [_][4]f32{[_]f32{0.0} ** 4} ** projection_count;
            var acc3: [projection_count][4]f32 = [_][4]f32{[_]f32{0.0} ** 4} ** projection_count;
            for (0..row_blocks) |block_idx| {
