                        out_row1[o + lane] = acc1[projection_idx][lane];
                    }
                }
            }
        }
        if (panel8_available) {
            while ((o % prepared_k_panel8_nr) == 0 and o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc0: [projection_count][prepared_k_panel8_nr]f32 = [_][prepared_k_panel8_nr]f32{[_]f32{0.0} ** prepared_k_panel8_nr} ** projection_count;
                var acc1: [projection_count][prepared_k_panel8_nr]f32 = [_][prepared_k_panel8_nr]f32{[_]f32{0.0} ** prepared_k_panel8_nr} ** projection_count;
                for (0..row_blocks) |block_idx| {
                    const q8_off = block_idx * q8_block_size;
                    const q0 = q_input_row0[q8_off..][0..q8_block_size];
                    const q1 = q_input_row1[q8_off..][0..q8_block_size];
                    const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_q6_k_panel8_block_bytes;
                    inline for (0..projection_count) |projection_idx| {
                        const panel8 = panel8_blocks[projection_idx].?;
                        const panel_block = panel8[panel_off..][0..prepared_q6_k_panel8_block_bytes];
                        const sums = dotQ6KPreparedQ8KPanel8MR2(q0, q1, panel_block);
                        inline for (0..prepared_k_panel8_nr) |lane| {
                            acc0[projection_idx][lane] += sums.r0[lane];
                            acc1[projection_idx][lane] += sums.r1[lane];
                        }
                    }
                }
                inline for (0..projection_count) |projection_idx| {
                    const out_row0 = outputs[projection_idx][r * out_dim ..][0..out_dim];
                    const out_row1 = outputs[projection_idx][(r + 1) * out_dim ..][0..out_dim];
                    inline for (0..prepared_k_panel8_nr) |lane| {
                        out_row0[o + lane] = acc0[projection_idx][lane];
                        out_row1[o + lane] = acc1[projection_idx][lane];
                    }
                }
            }
        }
        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc0: [projection_count][4]f32 = [_][4]f32{[_]f32{0.0} ** 4} ** projection_count;
            var acc1: [projection_count][4]f32 = [_][4]f32{[_]f32{0.0} ** 4} ** projection_count;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const q0 = q_input_row0[q8_off..][0..q8_block_size];
                const q1 = q_input_row1[q8_off..][0..q8_block_size];
                inline for (0..projection_count) |projection_idx| {
                    const sums = dotQ6KPreparedQ8KBlock4MR2(
                        q0,
                        q1,
                        preparedKPanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 0),
                        preparedKPanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 1),
                        preparedKPanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 2),
                        preparedKPanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 3),
                    );
                    inline for (0..4) |lane| {
                        acc0[projection_idx][lane] += sums[lane];
                        acc1[projection_idx][lane] += sums[lane + 4];
                    }
                }
            }
            inline for (0..projection_count) |projection_idx| {
                const out_row0 = outputs[projection_idx][r * out_dim ..][0..out_dim];
                const out_row1 = outputs[projection_idx][(r + 1) * out_dim ..][0..out_dim];
                inline for (0..4) |lane| {
                    out_row0[o + lane] = acc0[projection_idx][lane];
                    out_row1[o + lane] = acc1[projection_idx][lane];
                }
            }
        }
        while (o < out_end) : (o += 1) {
            var acc0: [projection_count]f32 = [_]f32{0.0} ** projection_count;
            var acc1: [projection_count]f32 = [_]f32{0.0} ** projection_count;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const prepared_off = block_idx * prepared_q4_k_block_bytes;
                inline for (0..projection_count) |projection_idx| {
                    const prepared_row = prepared_blocks[projection_idx][o * prepared_row_stride ..][0..prepared_row_stride];
                    const prepared_block = prepared_row[prepared_off..][0..prepared_q4_k_block_bytes];
                    acc0[projection_idx] += dotQ6KPreparedQ8KBlock(q_input_row0[q8_off..][0..q8_block_size], prepared_block);
                    acc1[projection_idx] += dotQ6KPreparedQ8KBlock(q_input_row1[q8_off..][0..q8_block_size], prepared_block);
                }
            }
            inline for (0..projection_count) |projection_idx| {
                outputs[projection_idx][r * out_dim + o] = acc0[projection_idx];
                outputs[projection_idx][(r + 1) * out_dim + o] = acc1[projection_idx];
            }
        }
    }

    while (r < rows) : (r += 1) {
        const q_input_row = q_input[r * input_row_stride ..][0..input_row_stride];
        var o: usize = out_start;
        while (o < out_end and (o % panel_align) != 0) : (o += 1) {
            var acc: [projection_count]f32 = [_]f32{0.0} ** projection_count;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const prepared_off = block_idx * prepared_q4_k_block_bytes;
                inline for (0..projection_count) |projection_idx| {
                    const prepared_row = prepared_blocks[projection_idx][o * prepared_row_stride ..][0..prepared_row_stride];
                    acc[projection_idx] += dotQ6KPreparedQ8KBlock(
                        q_input_row[q8_off..][0..q8_block_size],
                        prepared_row[prepared_off..][0..prepared_q4_k_block_bytes],
                    );
                }
            }
            inline for (0..projection_count) |projection_idx| {
                outputs[projection_idx][r * out_dim + o] = acc[projection_idx];
            }
        }
        if (panel16_available) {
            while ((o % prepared_k_panel16_nr) == 0 and o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
                var acc: [projection_count][prepared_k_panel16_nr]f32 = [_][prepared_k_panel16_nr]f32{[_]f32{0.0} ** prepared_k_panel16_nr} ** projection_count;
                for (0..row_blocks) |block_idx| {
                    const q8_off = block_idx * q8_block_size;
                    const q = q_input_row[q8_off..][0..q8_block_size];
                    const panel_off = ((o / prepared_k_panel16_nr) * row_blocks + block_idx) * prepared_k_panel16_block_bytes;
                    inline for (0..projection_count) |projection_idx| {
                        const panel16 = panel16_blocks[projection_idx].?;
                        const sums = dotQ6KPreparedQ8KPanel16(q, panel16[panel_off..][0..prepared_k_panel16_block_bytes]);
                        inline for (0..prepared_k_panel16_nr) |lane| {
                            acc[projection_idx][lane] += sums[lane];
                        }
                    }
                }
                inline for (0..projection_count) |projection_idx| {
                    const out_row = outputs[projection_idx][r * out_dim ..][0..out_dim];
                    inline for (0..prepared_k_panel16_nr) |lane| {
                        out_row[o + lane] = acc[projection_idx][lane];
                    }
                }
            }
        }
        if (panel8_available) {
            while ((o % prepared_k_panel8_nr) == 0 and o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc: [projection_count][8]f32 = [_][8]f32{[_]f32{0.0} ** 8} ** projection_count;
                for (0..row_blocks) |block_idx| {
                    const q8_off = block_idx * q8_block_size;
                    const q = q_input_row[q8_off..][0..q8_block_size];
                    inline for (0..projection_count) |projection_idx| {
                        const panel8 = panel8_blocks[projection_idx].?;
                        const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_q6_k_panel8_block_bytes;
                        const sums = dotQ6KPreparedQ8KPanel8(q, panel8[panel_off..][0..prepared_q6_k_panel8_block_bytes]);
                        inline for (0..8) |lane| {
                            acc[projection_idx][lane] += sums[lane];
                        }
                    }
                }
                inline for (0..projection_count) |projection_idx| {
                    const out_row = outputs[projection_idx][r * out_dim ..][0..out_dim];
                    inline for (0..8) |lane| {
                        out_row[o + lane] = acc[projection_idx][lane];
                    }
                }
            }
        }
        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc: [projection_count][4]f32 = [_][4]f32{[_]f32{0.0} ** 4} ** projection_count;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const q = q_input_row[q8_off..][0..q8_block_size];
                inline for (0..projection_count) |projection_idx| {
                    const sums = dotQ6KPreparedQ8KBlock4(
                        q,
                        preparedKPanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 0),
                        preparedKPanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 1),
                        preparedKPanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 2),
                        preparedKPanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 3),
                    );
                    inline for (0..4) |lane| {
                        acc[projection_idx][lane] += sums[lane];
                    }
                }
            }
            inline for (0..projection_count) |projection_idx| {
                const out_row = outputs[projection_idx][r * out_dim ..][0..out_dim];
                inline for (0..4) |lane| {
                    out_row[o + lane] = acc[projection_idx][lane];
                }
            }
        }
        while (o < out_end) : (o += 1) {
            var acc: [projection_count]f32 = [_]f32{0.0} ** projection_count;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const prepared_off = block_idx * prepared_q4_k_block_bytes;
                inline for (0..projection_count) |projection_idx| {
                    const prepared_row = prepared_blocks[projection_idx][o * prepared_row_stride ..][0..prepared_row_stride];
                    acc[projection_idx] += dotQ6KPreparedQ8KBlock(
                        q_input_row[q8_off..][0..q8_block_size],
                        prepared_row[prepared_off..][0..prepared_q4_k_block_bytes],
                    );
                }
            }
            inline for (0..projection_count) |projection_idx| {
                outputs[projection_idx][r * out_dim + o] = acc[projection_idx];
            }
        }
    }
}

fn linearQ4Q5KPreparedQ8KActivationRange(
    q_input: []const u8,
    prepared_blocks: []const u8,
    panel_blocks: ?[]const u8,
    panel8_blocks: ?[]const u8,
    panel16_blocks: ?[]const u8,
    bias: ?[]const f32,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    known: gguf_tensor_types.KnownTensorType,
) void {
    @setEvalBranchQuota(20_000);
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    std.debug.assert(in_dim % values_per_block == 0);
    const row_blocks = in_dim / values_per_block;
    const input_row_stride = row_blocks * q8_block_size;
    const prepared_row_stride = row_blocks * prepared_q4_k_block_bytes;

    var r: usize = 0;
    const use_panel16_direct = useQ4Q5Panel16DirectForShape(rows, out_dim, row_blocks, panel16_blocks != null);
    const use_panel16_mr8 = useQ4Q5Panel16MR8DirectForShape(rows, out_dim, row_blocks, known, panel16_blocks != null) and row_blocks <= q8_k_prepared_sum_stack_max_row_blocks;
    if (use_panel16_direct) {
        if (panel16_blocks) |panel16| {
            while (use_panel16_mr8 and r + 8 <= rows) : (r += 8) {
                var q_input_rows: [8][]const u8 = undefined;
                var out_rows: [8][]f32 = undefined;
                inline for (0..8) |row| {
                    q_input_rows[row] = q_input[(r + row) * input_row_stride ..][0..input_row_stride];
                    out_rows[row] = output[(r + row) * out_dim ..][0..out_dim];
                }
                var activation_sums: [8][q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
                var activation_scales: [8][q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;
                inline for (0..8) |row| {
                    for (0..row_blocks) |block_idx| {
                        const q8_off = block_idx * q8_block_size;
                        const block = q_input_rows[row][q8_off..][0..q8_block_size];
                        prepareQ8KActivationSums(block, &activation_sums[row][block_idx]);
                        activation_scales[row][block_idx] = @splat(readF32Le(block[0..4]));
                    }
                }
                var o: usize = out_start;
                while (o < out_end and (o % prepared_k_panel16_nr) != 0) : (o += 1) {
                    const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
                    var acc: [8]f32 = [_]f32{0.0} ** 8;
                    for (0..row_blocks) |block_idx| {
                        const q8_off = block_idx * q8_block_size;
                        const prepared_off = block_idx * prepared_q4_k_block_bytes;
                        const prepared_block = prepared_row[prepared_off..][0..prepared_q4_k_block_bytes];
                        inline for (0..8) |row| {
                            acc[row] += dotQ4Q5KPreparedQ8KBlock(q_input_rows[row][q8_off..][0..q8_block_size], prepared_block);
                        }
                    }
                    inline for (0..8) |row| {
                        out_rows[row][o] = acc[row] + optionalLinearBiasAt(bias, o);
                    }
                }
                while (o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
                    var acc_lo: [8]F32x8 = [_]F32x8{@splat(0.0)} ** 8;
                    var acc_hi: [8]F32x8 = [_]F32x8{@splat(0.0)} ** 8;
                    if (row_blocks == 3) {
                        const panel_base = (o / prepared_k_panel16_nr) * 3 * prepared_k_panel16_block_bytes;
                        inline for (0..3) |block_idx| {
                            const q8_off = block_idx * q8_block_size;
                            const panel_off = panel_base + block_idx * prepared_k_panel16_block_bytes;
                            var q_blocks: [8][]const u8 = undefined;
                            var sum_ptrs: [8]*const [8]F32x8 = undefined;
                            var scales: [8]F32x8 = undefined;
                            inline for (0..8) |row| {
                                q_blocks[row] = q_input_rows[row][q8_off..][0..q8_block_size];
                                sum_ptrs[row] = &activation_sums[row][block_idx];
                                scales[row] = activation_scales[row][block_idx];
                            }
                            accumulateQ4Q5KPreparedQ8KPanel16MR8BlockPreparedSums(
                                q_blocks,
                                sum_ptrs,
                                scales,
                                panel16[panel_off..][0..prepared_k_panel16_block_bytes],
                                &acc_lo,
                                &acc_hi,
                            );
                        }
                    } else {
                        for (0..row_blocks) |block_idx| {
                            const q8_off = block_idx * q8_block_size;
                            const panel_off = ((o / prepared_k_panel16_nr) * row_blocks + block_idx) * prepared_k_panel16_block_bytes;
                            var q_blocks: [8][]const u8 = undefined;
                            var sum_ptrs: [8]*const [8]F32x8 = undefined;
                            var scales: [8]F32x8 = undefined;
                            inline for (0..8) |row| {
                                q_blocks[row] = q_input_rows[row][q8_off..][0..q8_block_size];
                                sum_ptrs[row] = &activation_sums[row][block_idx];
                                scales[row] = activation_scales[row][block_idx];
                            }
                            accumulateQ4Q5KPreparedQ8KPanel16MR8BlockPreparedSums(
                                q_blocks,
                                sum_ptrs,
                                scales,
                                panel16[panel_off..][0..prepared_k_panel16_block_bytes],
                                &acc_lo,
                                &acc_hi,
                            );
                        }
                    }
                    inline for (0..8) |row| {
                        storeF32x16WithBias(out_rows[row], bias, o, acc_lo[row], acc_hi[row]);
                    }
                }
                while (o < out_end) : (o += 1) {
                    const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
                    var acc: [8]f32 = [_]f32{0.0} ** 8;
                    for (0..row_blocks) |block_idx| {
                        const q8_off = block_idx * q8_block_size;
                        const prepared_off = block_idx * prepared_q4_k_block_bytes;
                        const prepared_block = prepared_row[prepared_off..][0..prepared_q4_k_block_bytes];
                        inline for (0..8) |row| {
                            acc[row] += dotQ4Q5KPreparedQ8KBlock(q_input_rows[row][q8_off..][0..q8_block_size], prepared_block);
                        }
                    }
                    inline for (0..8) |row| {
                        out_rows[row][o] = acc[row] + optionalLinearBiasAt(bias, o);
                    }
                }
            }
            while (r + 4 <= rows) : (r += 4) {
                const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
                const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
                const q_input_row2 = q_input[(r + 2) * input_row_stride ..][0..input_row_stride];
                const q_input_row3 = q_input[(r + 3) * input_row_stride ..][0..input_row_stride];
                const out_row0 = output[r * out_dim ..][0..out_dim];
                const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
                const out_row2 = output[(r + 2) * out_dim ..][0..out_dim];
                const out_row3 = output[(r + 3) * out_dim ..][0..out_dim];
                const use_prepared_sums = row_blocks <= q8_k_prepared_sum_stack_max_row_blocks;
                var activation_sums0: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
                var activation_sums1: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
                var activation_sums2: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
                var activation_sums3: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
                var activation_scales0: [q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;
                var activation_scales1: [q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;
                var activation_scales2: [q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;
                var activation_scales3: [q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;
                if (use_prepared_sums) {
                    for (0..row_blocks) |block_idx| {
                        const q8_off = block_idx * q8_block_size;
                        const block0 = q_input_row0[q8_off..][0..q8_block_size];
                        const block1 = q_input_row1[q8_off..][0..q8_block_size];
                        const block2 = q_input_row2[q8_off..][0..q8_block_size];
                        const block3 = q_input_row3[q8_off..][0..q8_block_size];
                        prepareQ8KActivationSums(block0, &activation_sums0[block_idx]);
                        prepareQ8KActivationSums(block1, &activation_sums1[block_idx]);
                        prepareQ8KActivationSums(block2, &activation_sums2[block_idx]);
                        prepareQ8KActivationSums(block3, &activation_sums3[block_idx]);
                        activation_scales0[block_idx] = @splat(readF32Le(block0[0..4]));
                        activation_scales1[block_idx] = @splat(readF32Le(block1[0..4]));
                        activation_scales2[block_idx] = @splat(readF32Le(block2[0..4]));
                        activation_scales3[block_idx] = @splat(readF32Le(block3[0..4]));
                    }
                }
                var o: usize = out_start;
                while (o < out_end and (o % prepared_k_panel16_nr) != 0) : (o += 1) {
                    const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
                    var acc0: f32 = 0.0;
                    var acc1: f32 = 0.0;
                    var acc2: f32 = 0.0;
                    var acc3: f32 = 0.0;
                    for (0..row_blocks) |block_idx| {
                        const q8_off = block_idx * q8_block_size;
                        const prepared_off = block_idx * prepared_q4_k_block_bytes;
                        const prepared_block = prepared_row[prepared_off..][0..prepared_q4_k_block_bytes];
                        acc0 += dotQ4Q5KPreparedQ8KBlock(q_input_row0[q8_off..][0..q8_block_size], prepared_block);
                        acc1 += dotQ4Q5KPreparedQ8KBlock(q_input_row1[q8_off..][0..q8_block_size], prepared_block);
                        acc2 += dotQ4Q5KPreparedQ8KBlock(q_input_row2[q8_off..][0..q8_block_size], prepared_block);
                        acc3 += dotQ4Q5KPreparedQ8KBlock(q_input_row3[q8_off..][0..q8_block_size], prepared_block);
                    }
                    const bias_value = optionalLinearBiasAt(bias, o);
                    out_row0[o] = acc0 + bias_value;
                    out_row1[o] = acc1 + bias_value;
                    out_row2[o] = acc2 + bias_value;
                    out_row3[o] = acc3 + bias_value;
                }
                while (o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
                    var acc0_lo: F32x8 = @splat(0.0);
                    var acc0_hi: F32x8 = @splat(0.0);
                    var acc1_lo: F32x8 = @splat(0.0);
                    var acc1_hi: F32x8 = @splat(0.0);
                    var acc2_lo: F32x8 = @splat(0.0);
                    var acc2_hi: F32x8 = @splat(0.0);
                    var acc3_lo: F32x8 = @splat(0.0);
                    var acc3_hi: F32x8 = @splat(0.0);
                    if (use_prepared_sums and (row_blocks == 3 or row_blocks == 8 or row_blocks == 12)) {
                        inline for (.{ 3, 8, 12 }) |block_count| {
                            if (row_blocks == block_count) {
                                const panel_base = (o / prepared_k_panel16_nr) * block_count * prepared_k_panel16_block_bytes;
                                inline for (0..block_count) |block_idx| {
                                    const q8_off = block_idx * q8_block_size;
                                    const panel_off = panel_base + block_idx * prepared_k_panel16_block_bytes;
                                    const block0 = q_input_row0[q8_off..][0..q8_block_size];
                                    const block1 = q_input_row1[q8_off..][0..q8_block_size];
                                    const block2 = q_input_row2[q8_off..][0..q8_block_size];
                                    const block3 = q_input_row3[q8_off..][0..q8_block_size];
                                    const panel_block = panel16[panel_off..][0..prepared_k_panel16_block_bytes];
                                    accumulateQ4Q5KPreparedQ8KPanel16MR4BlockPreparedSums(
                                        block0,
                                        block1,
                                        block2,
                                        block3,
                                        &activation_sums0[block_idx],
                                        &activation_sums1[block_idx],
                                        &activation_sums2[block_idx],
                                        &activation_sums3[block_idx],
                                        activation_scales0[block_idx],
                                        activation_scales1[block_idx],
                                        activation_scales2[block_idx],
                                        activation_scales3[block_idx],
                                        panel_block,
                                        &acc0_lo,
                                        &acc0_hi,
                                        &acc1_lo,
                                        &acc1_hi,
                                        &acc2_lo,
                                        &acc2_hi,
                                        &acc3_lo,
                                        &acc3_hi,
                                    );
                                }
                            }
                        }
                    } else {
                        for (0..row_blocks) |block_idx| {
                            const q8_off = block_idx * q8_block_size;
                            const panel_off = ((o / prepared_k_panel16_nr) * row_blocks + block_idx) * prepared_k_panel16_block_bytes;
                            const block0 = q_input_row0[q8_off..][0..q8_block_size];
                            const block1 = q_input_row1[q8_off..][0..q8_block_size];
                            const block2 = q_input_row2[q8_off..][0..q8_block_size];
                            const block3 = q_input_row3[q8_off..][0..q8_block_size];
                            const panel_block = panel16[panel_off..][0..prepared_k_panel16_block_bytes];
                            if (use_prepared_sums) {
                                accumulateQ4Q5KPreparedQ8KPanel16MR4BlockPreparedSums(
                                    block0,
                                    block1,
                                    block2,
                                    block3,
                                    &activation_sums0[block_idx],
                                    &activation_sums1[block_idx],
                                    &activation_sums2[block_idx],
                                    &activation_sums3[block_idx],
                                    activation_scales0[block_idx],
                                    activation_scales1[block_idx],
                                    activation_scales2[block_idx],
                                    activation_scales3[block_idx],
                                    panel_block,
                                    &acc0_lo,
                                    &acc0_hi,
                                    &acc1_lo,
                                    &acc1_hi,
                                    &acc2_lo,
                                    &acc2_hi,
                                    &acc3_lo,
                                    &acc3_hi,
                                );
                            } else {
                                accumulateQ4Q5KPreparedQ8KPanel16MR4Block(block0, block1, block2, block3, panel_block, &acc0_lo, &acc0_hi, &acc1_lo, &acc1_hi, &acc2_lo, &acc2_hi, &acc3_lo, &acc3_hi);
                            }
                        }
                    }
                    storeF32x16WithBias(out_row0, bias, o, acc0_lo, acc0_hi);
                    storeF32x16WithBias(out_row1, bias, o, acc1_lo, acc1_hi);
                    storeF32x16WithBias(out_row2, bias, o, acc2_lo, acc2_hi);
                    storeF32x16WithBias(out_row3, bias, o, acc3_lo, acc3_hi);
                }
                while (o < out_end) : (o += 1) {
                    const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
                    var acc0: f32 = 0.0;
                    var acc1: f32 = 0.0;
                    var acc2: f32 = 0.0;
                    var acc3: f32 = 0.0;
                    for (0..row_blocks) |block_idx| {
                        const q8_off = block_idx * q8_block_size;
                        const prepared_off = block_idx * prepared_q4_k_block_bytes;
                        const prepared_block = prepared_row[prepared_off..][0..prepared_q4_k_block_bytes];
                        acc0 += dotQ4Q5KPreparedQ8KBlock(q_input_row0[q8_off..][0..q8_block_size], prepared_block);
                        acc1 += dotQ4Q5KPreparedQ8KBlock(q_input_row1[q8_off..][0..q8_block_size], prepared_block);
                        acc2 += dotQ4Q5KPreparedQ8KBlock(q_input_row2[q8_off..][0..q8_block_size], prepared_block);
                        acc3 += dotQ4Q5KPreparedQ8KBlock(q_input_row3[q8_off..][0..q8_block_size], prepared_block);
                    }
                    const bias_value = optionalLinearBiasAt(bias, o);
                    out_row0[o] = acc0 + bias_value;
                    out_row1[o] = acc1 + bias_value;
                    out_row2[o] = acc2 + bias_value;
                    out_row3[o] = acc3 + bias_value;
                }
            }
            while (r + 2 <= rows) : (r += 2) {
                const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
                const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
                const out_row0 = output[r * out_dim ..][0..out_dim];
                const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
                const use_prepared_sums = row_blocks <= q8_k_prepared_sum_stack_max_row_blocks;
                var activation_sums0: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
                var activation_sums1: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
                if (use_prepared_sums) {
                    for (0..row_blocks) |block_idx| {
                        const q8_off = block_idx * q8_block_size;
                        prepareQ8KActivationSums(q_input_row0[q8_off..][0..q8_block_size], &activation_sums0[block_idx]);
                        prepareQ8KActivationSums(q_input_row1[q8_off..][0..q8_block_size], &activation_sums1[block_idx]);
                    }
                }
                var o: usize = out_start;
                while (o < out_end and (o % prepared_k_panel16_nr) != 0) : (o += 1) {
                    const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
                    var acc0: f32 = 0.0;
                    var acc1: f32 = 0.0;
                    for (0..row_blocks) |block_idx| {
                        const q8_off = block_idx * q8_block_size;
                        const prepared_off = block_idx * prepared_q4_k_block_bytes;
                        const prepared_block = prepared_row[prepared_off..][0..prepared_q4_k_block_bytes];
                        acc0 += dotQ4Q5KPreparedQ8KBlock(q_input_row0[q8_off..][0..q8_block_size], prepared_block);
                        acc1 += dotQ4Q5KPreparedQ8KBlock(q_input_row1[q8_off..][0..q8_block_size], prepared_block);
                    }
                    const bias_value = optionalLinearBiasAt(bias, o);
                    out_row0[o] = acc0 + bias_value;
                    out_row1[o] = acc1 + bias_value;
                }
                while (o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
                    var acc0_lo: F32x8 = @splat(0.0);
                    var acc0_hi: F32x8 = @splat(0.0);
                    var acc1_lo: F32x8 = @splat(0.0);
                    var acc1_hi: F32x8 = @splat(0.0);
                    for (0..row_blocks) |block_idx| {
                        const q8_off = block_idx * q8_block_size;
                        const panel_off = ((o / prepared_k_panel16_nr) * row_blocks + block_idx) * prepared_k_panel16_block_bytes;
                        const block0 = q_input_row0[q8_off..][0..q8_block_size];
                        const block1 = q_input_row1[q8_off..][0..q8_block_size];
                        const panel_block = panel16[panel_off..][0..prepared_k_panel16_block_bytes];
                        if (use_prepared_sums) {
                            accumulateQ4Q5KPreparedQ8KPanel16MR2BlockPreparedSums(
                                block0,
                                block1,
                                &activation_sums0[block_idx],
                                &activation_sums1[block_idx],
                                panel_block,
                                &acc0_lo,
                                &acc0_hi,
                                &acc1_lo,
                                &acc1_hi,
                            );
                        } else {
                            accumulateQ4Q5KPreparedQ8KPanel16MR2Block(block0, block1, panel_block, &acc0_lo, &acc0_hi, &acc1_lo, &acc1_hi);
                        }
                    }
                    storeF32x16WithBias(out_row0, bias, o, acc0_lo, acc0_hi);
                    storeF32x16WithBias(out_row1, bias, o, acc1_lo, acc1_hi);
                }
                while (o < out_end) : (o += 1) {
                    const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
                    var acc0: f32 = 0.0;
                    var acc1: f32 = 0.0;
                    for (0..row_blocks) |block_idx| {
                        const q8_off = block_idx * q8_block_size;
                        const prepared_off = block_idx * prepared_q4_k_block_bytes;
                        const prepared_block = prepared_row[prepared_off..][0..prepared_q4_k_block_bytes];
                        acc0 += dotQ4Q5KPreparedQ8KBlock(q_input_row0[q8_off..][0..q8_block_size], prepared_block);
                        acc1 += dotQ4Q5KPreparedQ8KBlock(q_input_row1[q8_off..][0..q8_block_size], prepared_block);
                    }
                    const bias_value = optionalLinearBiasAt(bias, o);
                    out_row0[o] = acc0 + bias_value;
                    out_row1[o] = acc1 + bias_value;
                }
            }
        }
    }
    while (r + 2 <= rows) : (r += 2) {
        const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
        const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
        var o: usize = out_start;
        while (o < out_end and (o % 4) != 0) : (o += 1) {
            const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const prepared_off = block_idx * prepared_q4_k_block_bytes;
                acc0 += dotQ4Q5KPreparedQ8KBlock(
                    q_input_row0[q8_off..][0..q8_block_size],
                    prepared_row[prepared_off..][0..prepared_q4_k_block_bytes],
                );
                acc1 += dotQ4Q5KPreparedQ8KBlock(
                    q_input_row1[q8_off..][0..q8_block_size],
                    prepared_row[prepared_off..][0..prepared_q4_k_block_bytes],
                );
            }
            const bias_value = optionalLinearBiasAt(bias, o);
            out_row0[o] = acc0 + bias_value;
            out_row1[o] = acc1 + bias_value;
        }
        if (panel8_blocks) |panel8| {
            while ((o % prepared_k_panel8_nr) == 0 and o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc_r0: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                var acc_r1: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
                for (0..row_blocks) |block_idx| {
                    const q8_off = block_idx * q8_block_size;
                    const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_k_panel8_block_bytes;
                    const sums = dotQ4Q5KPreparedQ8KPanel8MR2(
                        q_input_row0[q8_off..][0..q8_block_size],
                        q_input_row1[q8_off..][0..q8_block_size],
                        panel8[panel_off..][0..prepared_k_panel8_block_bytes],
                    );
                    inline for (0..prepared_k_panel8_nr) |idx| {
                        acc_r0[idx] += sums.r0[idx];
                        acc_r1[idx] += sums.r1[idx];
                    }
                }
                inline for (0..prepared_k_panel8_nr) |idx| {
                    const bias_value = optionalLinearBiasAt(bias, o + idx);
                    out_row0[o + idx] = acc_r0[idx] + bias_value;
                    out_row1[o + idx] = acc_r1[idx] + bias_value;
                }
            }
        }
        while (o + 4 <= out_dim) : (o += 4) {
            if (o + 4 > out_end) break;
            var acc_r0_0: f32 = 0.0;
            var acc_r0_1: f32 = 0.0;
            var acc_r0_2: f32 = 0.0;
            var acc_r0_3: f32 = 0.0;
            var acc_r1_0: f32 = 0.0;
            var acc_r1_1: f32 = 0.0;
            var acc_r1_2: f32 = 0.0;
            var acc_r1_3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const sums = dotQ4Q5KPreparedQ8KBlock4MR2(
                    q_input_row0[q8_off..][0..q8_block_size],
                    q_input_row1[q8_off..][0..q8_block_size],
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 0),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 1),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 2),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 3),
                );
                acc_r0_0 += sums[0];
                acc_r0_1 += sums[1];
                acc_r0_2 += sums[2];
                acc_r0_3 += sums[3];
                acc_r1_0 += sums[4];
                acc_r1_1 += sums[5];
                acc_r1_2 += sums[6];
                acc_r1_3 += sums[7];
            }
            const bias0 = optionalLinearBiasAt(bias, o);
            const bias1 = optionalLinearBiasAt(bias, o + 1);
            const bias2 = optionalLinearBiasAt(bias, o + 2);
            const bias3 = optionalLinearBiasAt(bias, o + 3);
            out_row0[o] = acc_r0_0 + bias0;
            out_row0[o + 1] = acc_r0_1 + bias1;
            out_row0[o + 2] = acc_r0_2 + bias2;
            out_row0[o + 3] = acc_r0_3 + bias3;
            out_row1[o] = acc_r1_0 + bias0;
            out_row1[o + 1] = acc_r1_1 + bias1;
            out_row1[o + 2] = acc_r1_2 + bias2;
            out_row1[o + 3] = acc_r1_3 + bias3;
        }
        while (o < out_end) : (o += 1) {
            const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const prepared_off = block_idx * prepared_q4_k_block_bytes;
                acc0 += dotQ4Q5KPreparedQ8KBlock(
                    q_input_row0[q8_off..][0..q8_block_size],
                    prepared_row[prepared_off..][0..prepared_q4_k_block_bytes],
                );
                acc1 += dotQ4Q5KPreparedQ8KBlock(
                    q_input_row1[q8_off..][0..q8_block_size],
                    prepared_row[prepared_off..][0..prepared_q4_k_block_bytes],
                );
            }
            const bias_value = optionalLinearBiasAt(bias, o);
            out_row0[o] = acc0 + bias_value;
            out_row1[o] = acc1 + bias_value;
        }
    }

    while (r < rows) : (r += 1) {
        const q_input_row = q_input[r * input_row_stride ..][0..input_row_stride];
        const out_row = output[r * out_dim ..][0..out_dim];
        const use_prepared_sums = row_blocks <= q8_k_prepared_sum_stack_max_row_blocks;
        var activation_sums: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
        if (use_prepared_sums) {
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                prepareQ8KActivationSums(q_input_row[q8_off..][0..q8_block_size], &activation_sums[block_idx]);
            }
        }
        var o: usize = out_start;
        while (o < out_end and (o % 4) != 0) : (o += 1) {
            const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
            var acc: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                acc += dotQ4Q5KPreparedQ8KBlock(
                    q_input_row[block_idx * q8_block_size ..][0..q8_block_size],
                    prepared_row[block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes],
                );
            }
            out_row[o] = acc + optionalLinearBiasAt(bias, o);
        }
        if (use_panel16_direct) {
            if (panel16_blocks) |panel16| {
                while ((o % prepared_k_panel16_nr) == 0 and o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
                    var acc_lo: F32x8 = @splat(0.0);
                    var acc_hi: F32x8 = @splat(0.0);
                    for (0..row_blocks) |block_idx| {
                        const q8_off = block_idx * q8_block_size;
                        const panel_off = ((o / prepared_k_panel16_nr) * row_blocks + block_idx) * prepared_k_panel16_block_bytes;
                        const block = q_input_row[q8_off..][0..q8_block_size];
                        const panel_block = panel16[panel_off..][0..prepared_k_panel16_block_bytes];
                        if (use_prepared_sums) {
                            accumulateQ4Q5KPreparedQ8KPanel16MR1BlockPreparedSums(
                                block,
                                &activation_sums[block_idx],
                                panel_block,
                                &acc_lo,
                                &acc_hi,
                            );
                        } else {
                            accumulateQ4Q5KPreparedQ8KPanel16MR1Block(block, panel_block, &acc_lo, &acc_hi);
                        }
                    }
                    storeF32x16WithBias(out_row, bias, o, acc_lo, acc_hi);
                }
            }
        }
        if (panel8_blocks) |panel8| {
            while ((o % 8) == 0 and o + 8 <= out_end) : (o += 8) {
                var acc: [8]f32 = [_]f32{0.0} ** 8;
                for (0..row_blocks) |block_idx| {
                    const q8_off = block_idx * q8_block_size;
                    const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_k_panel8_block_bytes;
                    const sums = dotQ4Q5KPreparedQ8KPanel8(
                        q_input_row[q8_off..][0..q8_block_size],
                        panel8[panel_off..][0..prepared_k_panel8_block_bytes],
                    );
                    inline for (0..8) |idx| acc[idx] += sums[idx];
                }
                inline for (0..8) |idx| out_row[o + idx] = acc[idx] + optionalLinearBiasAt(bias, o + idx);
            }
        }
        while (o + 4 <= out_dim) : (o += 4) {
            if (o + 4 > out_end) break;
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            var acc2: f32 = 0.0;
            var acc3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const sums = dotQ4Q5KPreparedQ8KBlock4(
                    q_input_row[q8_off..][0..q8_block_size],
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 0),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 1),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 2),
                    preparedKPanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 3),
                );
                acc0 += sums[0];
                acc1 += sums[1];
                acc2 += sums[2];
                acc3 += sums[3];
            }
            out_row[o] = acc0 + optionalLinearBiasAt(bias, o);
            out_row[o + 1] = acc1 + optionalLinearBiasAt(bias, o + 1);
            out_row[o + 2] = acc2 + optionalLinearBiasAt(bias, o + 2);
            out_row[o + 3] = acc3 + optionalLinearBiasAt(bias, o + 3);
        }
        while (o < out_end) : (o += 1) {
            const prepared_row = prepared_blocks[o * prepared_row_stride ..][0..prepared_row_stride];
            var acc: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                acc += dotQ4Q5KPreparedQ8KBlock(
                    q_input_row[block_idx * q8_block_size ..][0..q8_block_size],
                    prepared_row[block_idx * prepared_q4_k_block_bytes ..][0..prepared_q4_k_block_bytes],
                );
            }
            out_row[o] = acc + optionalLinearBiasAt(bias, o);
        }
    }
}

fn linearQ4Q5KPreparedQ8KActivationPairPanel8Range(
    q_input: []const u8,
    prepared_blocks_a: []const u8,
    panel8_blocks_a: []const u8,
    output_a: []f32,
    prepared_blocks_b: []const u8,
    panel8_blocks_b: []const u8,
    output_b: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    std.debug.assert(in_dim % values_per_block == 0);
    const row_blocks = in_dim / values_per_block;
    const input_row_stride = row_blocks * q8_block_size;
    const prepared_row_stride = row_blocks * prepared_q4_k_block_bytes;

    for (0..rows) |r| {
        const q_input_row = q_input[r * input_row_stride ..][0..input_row_stride];
        const out_a = output_a[r * out_dim ..][0..out_dim];
        const out_b = output_b[r * out_dim ..][0..out_dim];
        var o: usize = out_start;
        while (o < out_end and (o % prepared_k_panel8_nr) != 0) : (o += 1) {
            const prepared_row_a = prepared_blocks_a[o * prepared_row_stride ..][0..prepared_row_stride];
            const prepared_row_b = prepared_blocks_b[o * prepared_row_stride ..][0..prepared_row_stride];
            var acc_a: f32 = 0.0;
            var acc_b: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const prepared_off = block_idx * prepared_q4_k_block_bytes;
                const q8_block = q_input_row[q8_off..][0..q8_block_size];
                acc_a += dotQ4Q5KPreparedQ8KBlock(q8_block, prepared_row_a[prepared_off..][0..prepared_q4_k_block_bytes]);
                acc_b += dotQ4Q5KPreparedQ8KBlock(q8_block, prepared_row_b[prepared_off..][0..prepared_q4_k_block_bytes]);
            }
            out_a[o] = acc_a;
            out_b[o] = acc_b;
        }
        while (o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
            var acc_a: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
            var acc_b: [prepared_k_panel8_nr]f32 = [_]f32{0.0} ** prepared_k_panel8_nr;
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_k_panel8_block_bytes;
                const q8_block = q_input_row[q8_off..][0..q8_block_size];
                const sums_a = dotQ4Q5KPreparedQ8KPanel8(q8_block, panel8_blocks_a[panel_off..][0..prepared_k_panel8_block_bytes]);
                const sums_b = dotQ4Q5KPreparedQ8KPanel8(q8_block, panel8_blocks_b[panel_off..][0..prepared_k_panel8_block_bytes]);
                inline for (0..prepared_k_panel8_nr) |idx| {
                    acc_a[idx] += sums_a[idx];
                    acc_b[idx] += sums_b[idx];
                }
