inline fn writeQ4Q5KPreparedQ8KPackedQKVPanel16MR8ProjectionPreparedSums(
    q_input_rows: [8][]const u8,
    activation_sums: *const [8][q8_k_prepared_sum_stack_max_row_blocks][8]F32x8,
    activation_scales: *const [8][q8_k_prepared_sum_stack_max_row_blocks]F32x8,
    packed_qkv_panel16: []const u8,
    bias_a: ?[]const f32,
    out_a_rows: [8][]f32,
    bias_b: ?[]const f32,
    out_b_rows: [8][]f32,
    bias_c: ?[]const f32,
    out_c_rows: [8][]f32,
    row_blocks: usize,
    o: usize,
) void {
    noteNativeQuantDispatch(.q4_q5_k_q8k_triple_packed_qkv_panel16_mr8);

    const q8_block_size: usize = 292;
    var acc_a_lo: [8]F32x8 = [_]F32x8{@splat(0.0)} ** 8;
    var acc_a_hi: [8]F32x8 = [_]F32x8{@splat(0.0)} ** 8;
    var acc_b_lo: [8]F32x8 = [_]F32x8{@splat(0.0)} ** 8;
    var acc_b_hi: [8]F32x8 = [_]F32x8{@splat(0.0)} ** 8;
    var acc_c_lo: [8]F32x8 = [_]F32x8{@splat(0.0)} ** 8;
    var acc_c_hi: [8]F32x8 = [_]F32x8{@splat(0.0)} ** 8;

    const packed_panel_base = (o / prepared_k_panel16_nr) * row_blocks * prepared_k_qkv_panel16_block_bytes;
    for (0..row_blocks) |block_idx| {
        var qx: [8][]const u8 = undefined;
        inline for (0..8) |row| {
            const q8_off = block_idx * q8_block_size;
            qx[row] = q_input_rows[row][q8_off + 4 ..][0..256];
        }
        const packed_off = packed_panel_base + block_idx * prepared_k_qkv_panel16_block_bytes;
        const block = packed_qkv_panel16[packed_off..][0..prepared_k_qkv_panel16_block_bytes];

        for (0..8) |sub| {
            const q_off = sub * 32;
            var qsubs: [8]*const [32]u8 = undefined;
            var x_scales: [8]F32x8 = undefined;
            var sums: [8]F32x8 = undefined;
            inline for (0..8) |row| {
                qsubs[row] = qx[row][q_off..][0..32];
                x_scales[row] = activation_scales[row][block_idx];
                sums[row] = activation_sums[row][block_idx][sub];
            }
            accumulateQ4Q5KPackedQKVPanel16NR16MR8ProjectionView(qsubs, x_scales, sums, packedQKVPanel16SubProjectionView(block, sub, 0), &acc_a_lo, &acc_a_hi);
            accumulateQ4Q5KPackedQKVPanel16NR16MR8ProjectionView(qsubs, x_scales, sums, packedQKVPanel16SubProjectionView(block, sub, 1), &acc_b_lo, &acc_b_hi);
            accumulateQ4Q5KPackedQKVPanel16NR16MR8ProjectionView(qsubs, x_scales, sums, packedQKVPanel16SubProjectionView(block, sub, 2), &acc_c_lo, &acc_c_hi);
        }
    }

    inline for (0..8) |row| {
        storeF32x16WithBias(out_a_rows[row], bias_a, o, acc_a_lo[row], acc_a_hi[row]);
        storeF32x16WithBias(out_b_rows[row], bias_b, o, acc_b_lo[row], acc_b_hi[row]);
        storeF32x16WithBias(out_c_rows[row], bias_c, o, acc_c_lo[row], acc_c_hi[row]);
    }
}

const q4q5_packed_qkv_row_tile_groups = 4;
const q4q5_packed_qkv_mr8_row_tile_groups = 4;

fn linearQ4Q5KPreparedQ8KActivationTriplePanel16RowTileMR8(
    q_input: []const u8,
    bias_a: ?[]const f32,
    output_a: []f32,
    bias_b: ?[]const f32,
    output_b: []f32,
    bias_c: ?[]const f32,
    output_c: []f32,
    packed_qkv_panel16: []const u8,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) usize {
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    std.debug.assert(in_dim % values_per_block == 0);
    std.debug.assert(out_start % prepared_k_panel16_nr == 0);
    std.debug.assert(out_end % prepared_k_panel16_nr == 0);
    const row_blocks = in_dim / values_per_block;
    if (row_blocks > q8_k_prepared_sum_stack_max_row_blocks) return 0;

    const input_row_stride = row_blocks * q8_block_size;
    const fast_rows = rows - (rows % 8);
    var r_tile: usize = 0;
    while (r_tile < fast_rows) : (r_tile += q4q5_packed_qkv_mr8_row_tile_groups * 8) {
        const groups = @min(q4q5_packed_qkv_mr8_row_tile_groups, (fast_rows - r_tile) / 8);
        var activation_sums: [q4q5_packed_qkv_mr8_row_tile_groups][8][q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
        var activation_scales: [q4q5_packed_qkv_mr8_row_tile_groups][8][q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;

        for (0..groups) |group| {
            const r = r_tile + group * 8;
            inline for (0..8) |row| {
                const q_input_row = q_input[(r + row) * input_row_stride ..][0..input_row_stride];
                for (0..row_blocks) |block_idx| {
                    const q8_off = block_idx * q8_block_size;
                    const block = q_input_row[q8_off..][0..q8_block_size];
                    prepareQ8KActivationSums(block, &activation_sums[group][row][block_idx]);
                    activation_scales[group][row][block_idx] = @splat(readF32Le(block[0..4]));
                }
            }
        }

        var o: usize = out_start;
        while (o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
            for (0..groups) |group| {
                const r = r_tile + group * 8;
                var q_input_rows: [8][]const u8 = undefined;
                var out_a_rows: [8][]f32 = undefined;
                var out_b_rows: [8][]f32 = undefined;
                var out_c_rows: [8][]f32 = undefined;
                inline for (0..8) |row| {
                    q_input_rows[row] = q_input[(r + row) * input_row_stride ..][0..input_row_stride];
                    out_a_rows[row] = output_a[(r + row) * out_dim ..][0..out_dim];
                    out_b_rows[row] = output_b[(r + row) * out_dim ..][0..out_dim];
                    out_c_rows[row] = output_c[(r + row) * out_dim ..][0..out_dim];
                }
                writeQ4Q5KPreparedQ8KPackedQKVPanel16MR8ProjectionPreparedSums(
                    q_input_rows,
                    &activation_sums[group],
                    &activation_scales[group],
                    packed_qkv_panel16,
                    bias_a,
                    out_a_rows,
                    bias_b,
                    out_b_rows,
                    bias_c,
                    out_c_rows,
                    row_blocks,
                    o,
                );
            }
        }
    }
    return fast_rows;
}

fn linearQ4Q5KPreparedQ8KActivationTriplePanel16RowTileMR4(
    q_input: []const u8,
    bias_a: ?[]const f32,
    output_a: []f32,
    bias_b: ?[]const f32,
    output_b: []f32,
    bias_c: ?[]const f32,
    output_c: []f32,
    packed_qkv_panel16: []const u8,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) usize {
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    std.debug.assert(in_dim % values_per_block == 0);
    std.debug.assert(out_start % prepared_k_panel16_nr == 0);
    std.debug.assert(out_end % prepared_k_panel16_nr == 0);
    const row_blocks = in_dim / values_per_block;
    if (row_blocks > q8_k_prepared_sum_stack_max_row_blocks) return 0;

    const input_row_stride = row_blocks * q8_block_size;
    const fast_rows = rows - (rows % 4);
    var r_tile: usize = 0;
    while (r_tile < fast_rows) : (r_tile += q4q5_packed_qkv_row_tile_groups * 4) {
        const groups = @min(q4q5_packed_qkv_row_tile_groups, (fast_rows - r_tile) / 4);
        var activation_sums0: [q4q5_packed_qkv_row_tile_groups][q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
        var activation_sums1: [q4q5_packed_qkv_row_tile_groups][q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
        var activation_sums2: [q4q5_packed_qkv_row_tile_groups][q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
        var activation_sums3: [q4q5_packed_qkv_row_tile_groups][q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
        var activation_scales0: [q4q5_packed_qkv_row_tile_groups][q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;
        var activation_scales1: [q4q5_packed_qkv_row_tile_groups][q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;
        var activation_scales2: [q4q5_packed_qkv_row_tile_groups][q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;
        var activation_scales3: [q4q5_packed_qkv_row_tile_groups][q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;

        for (0..groups) |group| {
            const r = r_tile + group * 4;
            const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
            const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
            const q_input_row2 = q_input[(r + 2) * input_row_stride ..][0..input_row_stride];
            const q_input_row3 = q_input[(r + 3) * input_row_stride ..][0..input_row_stride];
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const block0 = q_input_row0[q8_off..][0..q8_block_size];
                const block1 = q_input_row1[q8_off..][0..q8_block_size];
                const block2 = q_input_row2[q8_off..][0..q8_block_size];
                const block3 = q_input_row3[q8_off..][0..q8_block_size];
                prepareQ8KActivationSums(block0, &activation_sums0[group][block_idx]);
                prepareQ8KActivationSums(block1, &activation_sums1[group][block_idx]);
                prepareQ8KActivationSums(block2, &activation_sums2[group][block_idx]);
                prepareQ8KActivationSums(block3, &activation_sums3[group][block_idx]);
                activation_scales0[group][block_idx] = @splat(readF32Le(block0[0..4]));
                activation_scales1[group][block_idx] = @splat(readF32Le(block1[0..4]));
                activation_scales2[group][block_idx] = @splat(readF32Le(block2[0..4]));
                activation_scales3[group][block_idx] = @splat(readF32Le(block3[0..4]));
            }
        }

        var o: usize = out_start;
        while (o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
            for (0..groups) |group| {
                const r = r_tile + group * 4;
                const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
                const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
                const q_input_row2 = q_input[(r + 2) * input_row_stride ..][0..input_row_stride];
                const q_input_row3 = q_input[(r + 3) * input_row_stride ..][0..input_row_stride];
                const out_a0 = output_a[r * out_dim ..][0..out_dim];
                const out_a1 = output_a[(r + 1) * out_dim ..][0..out_dim];
                const out_a2 = output_a[(r + 2) * out_dim ..][0..out_dim];
                const out_a3 = output_a[(r + 3) * out_dim ..][0..out_dim];
                const out_b0 = output_b[r * out_dim ..][0..out_dim];
                const out_b1 = output_b[(r + 1) * out_dim ..][0..out_dim];
                const out_b2 = output_b[(r + 2) * out_dim ..][0..out_dim];
                const out_b3 = output_b[(r + 3) * out_dim ..][0..out_dim];
                const out_c0 = output_c[r * out_dim ..][0..out_dim];
                const out_c1 = output_c[(r + 1) * out_dim ..][0..out_dim];
                const out_c2 = output_c[(r + 2) * out_dim ..][0..out_dim];
                const out_c3 = output_c[(r + 3) * out_dim ..][0..out_dim];
                writeQ4Q5KPreparedQ8KPackedQKVPanel16MR4ProjectionPreparedSums(
                    q_input_row0,
                    q_input_row1,
                    q_input_row2,
                    q_input_row3,
                    &activation_sums0[group],
                    &activation_sums1[group],
                    &activation_sums2[group],
                    &activation_sums3[group],
                    &activation_scales0[group],
                    &activation_scales1[group],
                    &activation_scales2[group],
                    &activation_scales3[group],
                    packed_qkv_panel16,
                    bias_a,
                    out_a0,
                    out_a1,
                    out_a2,
                    out_a3,
                    bias_b,
                    out_b0,
                    out_b1,
                    out_b2,
                    out_b3,
                    bias_c,
                    out_c0,
                    out_c1,
                    out_c2,
                    out_c3,
                    row_blocks,
                    o,
                );
            }
        }
    }
    return fast_rows;
}

inline fn writeQ4Q5KPreparedQ8KPackedQKVPanel16MR2Projection(
    q_input_row0: []const u8,
    q_input_row1: []const u8,
    packed_qkv_panel16: []const u8,
    out_a0: []f32,
    out_a1: []f32,
    out_b0: []f32,
    out_b1: []f32,
    out_c0: []f32,
    out_c1: []f32,
    row_blocks: usize,
    o: usize,
) void {
    noteNativeQuantDispatch(.q4_q5_k_q8k_triple_packed_qkv_panel16_mr2);

    const q8_block_size: usize = 292;
    var acc_a0_lo: F32x8 = @splat(0.0);
    var acc_a0_hi: F32x8 = @splat(0.0);
    var acc_a1_lo: F32x8 = @splat(0.0);
    var acc_a1_hi: F32x8 = @splat(0.0);
    var acc_b0_lo: F32x8 = @splat(0.0);
    var acc_b0_hi: F32x8 = @splat(0.0);
    var acc_b1_lo: F32x8 = @splat(0.0);
    var acc_b1_hi: F32x8 = @splat(0.0);
    var acc_c0_lo: F32x8 = @splat(0.0);
    var acc_c0_hi: F32x8 = @splat(0.0);
    var acc_c1_lo: F32x8 = @splat(0.0);
    var acc_c1_hi: F32x8 = @splat(0.0);

    const packed_panel_base = (o / prepared_k_panel16_nr) * row_blocks * prepared_k_qkv_panel16_block_bytes;
    for (0..row_blocks) |block_idx| {
        const q8_off = block_idx * q8_block_size;
        const q8_block_r0 = q_input_row0[q8_off..][0..q8_block_size];
        const q8_block_r1 = q_input_row1[q8_off..][0..q8_block_size];
        const qx0 = q8_block_r0[4..260];
        const qx1 = q8_block_r1[4..260];
        const x_scale0: F32x8 = @splat(readF32Le(q8_block_r0[0..4]));
        const x_scale1: F32x8 = @splat(readF32Le(q8_block_r1[0..4]));
        const packed_off = packed_panel_base + block_idx * prepared_k_qkv_panel16_block_bytes;
        const block = packed_qkv_panel16[packed_off..][0..prepared_k_qkv_panel16_block_bytes];

        for (0..8) |sub| {
            const q_off = sub * 32;
            const activation_sum0: F32x8 = @splat(@as(f32, @floatFromInt(q8KBlockSum(q8_block_r0, sub))));
            const activation_sum1: F32x8 = @splat(@as(f32, @floatFromInt(q8KBlockSum(q8_block_r1, sub))));
            accumulateQ4Q5KPackedQKVPanel16NR16MR2(qx0, qx1, q_off, x_scale0, x_scale1, activation_sum0, activation_sum1, block, sub, 0, &acc_a0_lo, &acc_a0_hi, &acc_a1_lo, &acc_a1_hi);
            accumulateQ4Q5KPackedQKVPanel16NR16MR2(qx0, qx1, q_off, x_scale0, x_scale1, activation_sum0, activation_sum1, block, sub, 1, &acc_b0_lo, &acc_b0_hi, &acc_b1_lo, &acc_b1_hi);
            accumulateQ4Q5KPackedQKVPanel16NR16MR2(qx0, qx1, q_off, x_scale0, x_scale1, activation_sum0, activation_sum1, block, sub, 2, &acc_c0_lo, &acc_c0_hi, &acc_c1_lo, &acc_c1_hi);
        }
    }

    storeF32x16(out_a0, o, acc_a0_lo, acc_a0_hi);
    storeF32x16(out_a1, o, acc_a1_lo, acc_a1_hi);
    storeF32x16(out_b0, o, acc_b0_lo, acc_b0_hi);
    storeF32x16(out_b1, o, acc_b1_lo, acc_b1_hi);
    storeF32x16(out_c0, o, acc_c0_lo, acc_c0_hi);
    storeF32x16(out_c1, o, acc_c1_lo, acc_c1_hi);
}

inline fn writeQ4Q5KPreparedQ8KPackedQKVPanel16MR1Projection(
    q_input_row: []const u8,
    packed_qkv_panel16: []const u8,
    out_a: []f32,
    out_b: []f32,
    out_c: []f32,
    row_blocks: usize,
    o: usize,
) void {
    noteNativeQuantDispatch(.q4_q5_k_q8k_triple_packed_qkv_panel16_mr1);

    const q8_block_size: usize = 292;
    var acc_a_lo: F32x8 = @splat(0.0);
    var acc_a_hi: F32x8 = @splat(0.0);
    var acc_b_lo: F32x8 = @splat(0.0);
    var acc_b_hi: F32x8 = @splat(0.0);
    var acc_c_lo: F32x8 = @splat(0.0);
    var acc_c_hi: F32x8 = @splat(0.0);

    const packed_panel_base = (o / prepared_k_panel16_nr) * row_blocks * prepared_k_qkv_panel16_block_bytes;
    for (0..row_blocks) |block_idx| {
        const q8_off = block_idx * q8_block_size;
        const q8_block = q_input_row[q8_off..][0..q8_block_size];
        const qx = q8_block[4..260];
        const x_scale: F32x8 = @splat(readF32Le(q8_block[0..4]));
        const packed_off = packed_panel_base + block_idx * prepared_k_qkv_panel16_block_bytes;
        const block = packed_qkv_panel16[packed_off..][0..prepared_k_qkv_panel16_block_bytes];

        for (0..8) |sub| {
            const q_off = sub * 32;
            const activation_sum: F32x8 = @splat(@as(f32, @floatFromInt(q8KBlockSum(q8_block, sub))));
            accumulateQ4Q5KPackedQKVPanel16NR16MR1(qx, q_off, x_scale, activation_sum, block, sub, 0, &acc_a_lo, &acc_a_hi);
            accumulateQ4Q5KPackedQKVPanel16NR16MR1(qx, q_off, x_scale, activation_sum, block, sub, 1, &acc_b_lo, &acc_b_hi);
            accumulateQ4Q5KPackedQKVPanel16NR16MR1(qx, q_off, x_scale, activation_sum, block, sub, 2, &acc_c_lo, &acc_c_hi);
        }
    }

    storeF32x16(out_a, o, acc_a_lo, acc_a_hi);
    storeF32x16(out_b, o, acc_b_lo, acc_b_hi);
    storeF32x16(out_c, o, acc_c_lo, acc_c_hi);
}

inline fn writeQ4Q5KPreparedQ8KPackedQKVPanel16MR1ProjectionPreparedSums(
    q_input_row: []const u8,
    activation_sums: *const [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8,
    activation_scales: *const [q8_k_prepared_sum_stack_max_row_blocks]F32x8,
    packed_qkv_panel16: []const u8,
    out_a: []f32,
    out_b: []f32,
    out_c: []f32,
    row_blocks: usize,
    o: usize,
) void {
    noteNativeQuantDispatch(.q4_q5_k_q8k_triple_packed_qkv_panel16_mr1);

    const q8_block_size: usize = 292;
    var acc_a_lo: F32x8 = @splat(0.0);
    var acc_a_hi: F32x8 = @splat(0.0);
    var acc_b_lo: F32x8 = @splat(0.0);
    var acc_b_hi: F32x8 = @splat(0.0);
    var acc_c_lo: F32x8 = @splat(0.0);
    var acc_c_hi: F32x8 = @splat(0.0);

    const packed_panel_base = (o / prepared_k_panel16_nr) * row_blocks * prepared_k_qkv_panel16_block_bytes;
    for (0..row_blocks) |block_idx| {
        const q8_off = block_idx * q8_block_size;
        const qx = q_input_row[q8_off + 4 ..][0..256];
        const x_scale = activation_scales[block_idx];
        const packed_off = packed_panel_base + block_idx * prepared_k_qkv_panel16_block_bytes;
        const block = packed_qkv_panel16[packed_off..][0..prepared_k_qkv_panel16_block_bytes];

        for (0..8) |sub| {
            const q_off = sub * 32;
            const activation_sum = activation_sums[block_idx][sub];
            accumulateQ4Q5KPackedQKVPanel16NR16MR1(qx, q_off, x_scale, activation_sum, block, sub, 0, &acc_a_lo, &acc_a_hi);
            accumulateQ4Q5KPackedQKVPanel16NR16MR1(qx, q_off, x_scale, activation_sum, block, sub, 1, &acc_b_lo, &acc_b_hi);
            accumulateQ4Q5KPackedQKVPanel16NR16MR1(qx, q_off, x_scale, activation_sum, block, sub, 2, &acc_c_lo, &acc_c_hi);
        }
    }

    storeF32x16(out_a, o, acc_a_lo, acc_a_hi);
    storeF32x16(out_b, o, acc_b_lo, acc_b_hi);
    storeF32x16(out_c, o, acc_c_lo, acc_c_hi);
}

fn linearQ4Q5KPreparedQ8KActivationTriplePanel16Range(
    q_input: []const u8,
    prepared_blocks_a: []const u8,
    panel16_blocks_a: []const u8,
    bias_a: ?[]const f32,
    output_a: []f32,
    prepared_blocks_b: []const u8,
    panel16_blocks_b: []const u8,
    bias_b: ?[]const f32,
    output_b: []f32,
    prepared_blocks_c: []const u8,
    panel16_blocks_c: []const u8,
    bias_c: ?[]const f32,
    output_c: []f32,
    packed_qkv_panel16: ?[]const u8,
    packed_qkv_panel16_mr2: bool,
    packed_qkv_panel16_mr8: bool,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    @setEvalBranchQuota(50_000);
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    std.debug.assert(in_dim % values_per_block == 0);
    const row_blocks = in_dim / values_per_block;
    const input_row_stride = row_blocks * q8_block_size;
    const prepared_row_stride = row_blocks * prepared_q4_k_block_bytes;
    const triple_panel16_dot = q4q5TriplePanel16DotEnabled() or packed_qkv_panel16 != null;

    var r: usize = 0;
    if (q4q5PackedQKVPanel16RowTileEnabled() and
        packed_qkv_panel16_mr8 and
        packed_qkv_panel16 != null and
        row_blocks <= q8_k_prepared_sum_stack_max_row_blocks and
        out_start % prepared_k_panel16_nr == 0 and
        out_end % prepared_k_panel16_nr == 0)
    {
        r = linearQ4Q5KPreparedQ8KActivationTriplePanel16RowTileMR8(
            q_input,
            bias_a,
            output_a,
            bias_b,
            output_b,
            bias_c,
            output_c,
            packed_qkv_panel16.?,
            rows,
            in_dim,
            out_dim,
            out_start,
            out_end,
        );
    }
    if (q4q5PackedQKVPanel16RowTileEnabled() and
        !packed_qkv_panel16_mr8 and
        packed_qkv_panel16 != null and
        row_blocks <= q8_k_prepared_sum_stack_max_row_blocks and
        out_start % prepared_k_panel16_nr == 0 and
        out_end % prepared_k_panel16_nr == 0 and
        r < rows - (rows % 4))
    {
        const mr4_rows = linearQ4Q5KPreparedQ8KActivationTriplePanel16RowTileMR4(
            q_input,
            bias_a,
            output_a,
            bias_b,
            output_b,
            bias_c,
            output_c,
            packed_qkv_panel16.?,
            rows,
            in_dim,
            out_dim,
            out_start,
            out_end,
        );
        if (mr4_rows > r) r = mr4_rows;
    }
    while (r + 4 <= rows) : (r += 4) {
        const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
        const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
        const q_input_row2 = q_input[(r + 2) * input_row_stride ..][0..input_row_stride];
        const q_input_row3 = q_input[(r + 3) * input_row_stride ..][0..input_row_stride];
        const out_a0 = output_a[r * out_dim ..][0..out_dim];
        const out_a1 = output_a[(r + 1) * out_dim ..][0..out_dim];
        const out_a2 = output_a[(r + 2) * out_dim ..][0..out_dim];
        const out_a3 = output_a[(r + 3) * out_dim ..][0..out_dim];
        const out_b0 = output_b[r * out_dim ..][0..out_dim];
        const out_b1 = output_b[(r + 1) * out_dim ..][0..out_dim];
        const out_b2 = output_b[(r + 2) * out_dim ..][0..out_dim];
        const out_b3 = output_b[(r + 3) * out_dim ..][0..out_dim];
        const out_c0 = output_c[r * out_dim ..][0..out_dim];
        const out_c1 = output_c[(r + 1) * out_dim ..][0..out_dim];
        const out_c2 = output_c[(r + 2) * out_dim ..][0..out_dim];
        const out_c3 = output_c[(r + 3) * out_dim ..][0..out_dim];
        const use_projection_prepared_sums = row_blocks <= q8_k_prepared_sum_stack_max_row_blocks and (!triple_panel16_dot or packed_qkv_panel16 != null);
        var activation_sums0: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
        var activation_sums1: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
        var activation_sums2: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
        var activation_sums3: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
        var activation_scales0: [q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;
        var activation_scales1: [q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;
        var activation_scales2: [q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;
        var activation_scales3: [q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;
        if (use_projection_prepared_sums) {
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const block0 = q_input_row0[q8_off..][0..q8_block_size];
                const block1 = q_input_row1[q8_off..][0..q8_block_size];
                const block2 = q_input_row2[q8_off..][0..q8_block_size];
                const block3 = q_input_row3[q8_off..][0..q8_block_size];
                prepareQ8KActivationSums(block0, &activation_sums0[block_idx]);
                prepareQ8KActivationSums(block1, &activation_sums1[block_idx]);
                prepareQ8KActivationSums(block2, &activation_sums2[block_idx]);
                prepareQ8KActivationSums(block3, &activation_sums3[block_idx]);
                activation_scales0[block_idx] = @splat(readF32Le(block0[0..4]));
                activation_scales1[block_idx] = @splat(readF32Le(block1[0..4]));
                activation_scales2[block_idx] = @splat(readF32Le(block2[0..4]));
                activation_scales3[block_idx] = @splat(readF32Le(block3[0..4]));
            }
        }
        var o: usize = out_start;
        while (o < out_end and (o % prepared_k_panel16_nr) != 0) : (o += 1) {
            const prepared_row_a = prepared_blocks_a[o * prepared_row_stride ..][0..prepared_row_stride];
            const prepared_row_b = prepared_blocks_b[o * prepared_row_stride ..][0..prepared_row_stride];
            const prepared_row_c = prepared_blocks_c[o * prepared_row_stride ..][0..prepared_row_stride];
            const bias_a_value = optionalLinearBiasAt(bias_a, o);
            const bias_b_value = optionalLinearBiasAt(bias_b, o);
            const bias_c_value = optionalLinearBiasAt(bias_c, o);
            out_a0[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row0, prepared_row_a, row_blocks) + bias_a_value;
            out_a1[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row1, prepared_row_a, row_blocks) + bias_a_value;
            out_a2[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row2, prepared_row_a, row_blocks) + bias_a_value;
            out_a3[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row3, prepared_row_a, row_blocks) + bias_a_value;
            out_b0[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row0, prepared_row_b, row_blocks) + bias_b_value;
            out_b1[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row1, prepared_row_b, row_blocks) + bias_b_value;
            out_b2[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row2, prepared_row_b, row_blocks) + bias_b_value;
            out_b3[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row3, prepared_row_b, row_blocks) + bias_b_value;
            out_c0[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row0, prepared_row_c, row_blocks) + bias_c_value;
            out_c1[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row1, prepared_row_c, row_blocks) + bias_c_value;
            out_c2[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row2, prepared_row_c, row_blocks) + bias_c_value;
            out_c3[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row3, prepared_row_c, row_blocks) + bias_c_value;
        }
        while (o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
            if (triple_panel16_dot) {
                if (use_projection_prepared_sums) {
                    writeQ4Q5KPreparedQ8KPackedQKVPanel16MR4ProjectionPreparedSums(q_input_row0, q_input_row1, q_input_row2, q_input_row3, &activation_sums0, &activation_sums1, &activation_sums2, &activation_sums3, &activation_scales0, &activation_scales1, &activation_scales2, &activation_scales3, packed_qkv_panel16.?, bias_a, out_a0, out_a1, out_a2, out_a3, bias_b, out_b0, out_b1, out_b2, out_b3, bias_c, out_c0, out_c1, out_c2, out_c3, row_blocks, o);
                } else {
                    writeQ4Q5KPreparedQ8KPanel16TripleMR4Projection(q_input_row0, q_input_row1, q_input_row2, q_input_row3, panel16_blocks_a, panel16_blocks_b, panel16_blocks_c, packed_qkv_panel16, out_a0, out_a1, out_a2, out_a3, out_b0, out_b1, out_b2, out_b3, out_c0, out_c1, out_c2, out_c3, row_blocks, o);
                    addBiasTile16Rows4(out_a0, out_a1, out_a2, out_a3, bias_a, o);
                    addBiasTile16Rows4(out_b0, out_b1, out_b2, out_b3, bias_b, o);
                    addBiasTile16Rows4(out_c0, out_c1, out_c2, out_c3, bias_c, o);
                }
            } else if (use_projection_prepared_sums) {
                writeQ4Q5KPreparedQ8KPanel16MR4ProjectionPreparedSums(q_input_row0, q_input_row1, q_input_row2, q_input_row3, &activation_sums0, &activation_sums1, &activation_sums2, &activation_sums3, &activation_scales0, &activation_scales1, &activation_scales2, &activation_scales3, panel16_blocks_a, out_a0, out_a1, out_a2, out_a3, row_blocks, o);
                writeQ4Q5KPreparedQ8KPanel16MR4ProjectionPreparedSums(q_input_row0, q_input_row1, q_input_row2, q_input_row3, &activation_sums0, &activation_sums1, &activation_sums2, &activation_sums3, &activation_scales0, &activation_scales1, &activation_scales2, &activation_scales3, panel16_blocks_b, out_b0, out_b1, out_b2, out_b3, row_blocks, o);
                writeQ4Q5KPreparedQ8KPanel16MR4ProjectionPreparedSums(q_input_row0, q_input_row1, q_input_row2, q_input_row3, &activation_sums0, &activation_sums1, &activation_sums2, &activation_sums3, &activation_scales0, &activation_scales1, &activation_scales2, &activation_scales3, panel16_blocks_c, out_c0, out_c1, out_c2, out_c3, row_blocks, o);
                addBiasTile16Rows4(out_a0, out_a1, out_a2, out_a3, bias_a, o);
                addBiasTile16Rows4(out_b0, out_b1, out_b2, out_b3, bias_b, o);
                addBiasTile16Rows4(out_c0, out_c1, out_c2, out_c3, bias_c, o);
            } else {
                writeQ4Q5KPreparedQ8KPanel16MR4Projection(q_input_row0, q_input_row1, q_input_row2, q_input_row3, panel16_blocks_a, out_a0, out_a1, out_a2, out_a3, row_blocks, o);
                writeQ4Q5KPreparedQ8KPanel16MR4Projection(q_input_row0, q_input_row1, q_input_row2, q_input_row3, panel16_blocks_b, out_b0, out_b1, out_b2, out_b3, row_blocks, o);
                writeQ4Q5KPreparedQ8KPanel16MR4Projection(q_input_row0, q_input_row1, q_input_row2, q_input_row3, panel16_blocks_c, out_c0, out_c1, out_c2, out_c3, row_blocks, o);
                addBiasTile16Rows4(out_a0, out_a1, out_a2, out_a3, bias_a, o);
                addBiasTile16Rows4(out_b0, out_b1, out_b2, out_b3, bias_b, o);
                addBiasTile16Rows4(out_c0, out_c1, out_c2, out_c3, bias_c, o);
            }
        }
        while (o < out_end) : (o += 1) {
            const prepared_row_a = prepared_blocks_a[o * prepared_row_stride ..][0..prepared_row_stride];
            const prepared_row_b = prepared_blocks_b[o * prepared_row_stride ..][0..prepared_row_stride];
            const prepared_row_c = prepared_blocks_c[o * prepared_row_stride ..][0..prepared_row_stride];
            const bias_a_value = optionalLinearBiasAt(bias_a, o);
            const bias_b_value = optionalLinearBiasAt(bias_b, o);
            const bias_c_value = optionalLinearBiasAt(bias_c, o);
            out_a0[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row0, prepared_row_a, row_blocks) + bias_a_value;
            out_a1[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row1, prepared_row_a, row_blocks) + bias_a_value;
            out_a2[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row2, prepared_row_a, row_blocks) + bias_a_value;
            out_a3[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row3, prepared_row_a, row_blocks) + bias_a_value;
            out_b0[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row0, prepared_row_b, row_blocks) + bias_b_value;
            out_b1[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row1, prepared_row_b, row_blocks) + bias_b_value;
            out_b2[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row2, prepared_row_b, row_blocks) + bias_b_value;
            out_b3[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row3, prepared_row_b, row_blocks) + bias_b_value;
            out_c0[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row0, prepared_row_c, row_blocks) + bias_c_value;
            out_c1[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row1, prepared_row_c, row_blocks) + bias_c_value;
            out_c2[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row2, prepared_row_c, row_blocks) + bias_c_value;
            out_c3[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row3, prepared_row_c, row_blocks) + bias_c_value;
        }
    }

    while (r + 2 <= rows) : (r += 2) {
        const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
        const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
        const out_a0 = output_a[r * out_dim ..][0..out_dim];
        const out_a1 = output_a[(r + 1) * out_dim ..][0..out_dim];
        const out_b0 = output_b[r * out_dim ..][0..out_dim];
        const out_b1 = output_b[(r + 1) * out_dim ..][0..out_dim];
        const out_c0 = output_c[r * out_dim ..][0..out_dim];
        const out_c1 = output_c[(r + 1) * out_dim ..][0..out_dim];
        const use_projection_prepared_sums = !triple_panel16_dot and row_blocks <= q8_k_prepared_sum_stack_max_row_blocks;
        var activation_sums0: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
        var activation_sums1: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
        if (use_projection_prepared_sums) {
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                prepareQ8KActivationSums(q_input_row0[q8_off..][0..q8_block_size], &activation_sums0[block_idx]);
                prepareQ8KActivationSums(q_input_row1[q8_off..][0..q8_block_size], &activation_sums1[block_idx]);
            }
        }
        var o: usize = out_start;
        while (o < out_end and (o % prepared_k_panel16_nr) != 0) : (o += 1) {
            const prepared_row_a = prepared_blocks_a[o * prepared_row_stride ..][0..prepared_row_stride];
            const prepared_row_b = prepared_blocks_b[o * prepared_row_stride ..][0..prepared_row_stride];
            const prepared_row_c = prepared_blocks_c[o * prepared_row_stride ..][0..prepared_row_stride];
            const bias_a_value = optionalLinearBiasAt(bias_a, o);
            const bias_b_value = optionalLinearBiasAt(bias_b, o);
            const bias_c_value = optionalLinearBiasAt(bias_c, o);
            out_a0[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row0, prepared_row_a, row_blocks) + bias_a_value;
            out_a1[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row1, prepared_row_a, row_blocks) + bias_a_value;
            out_b0[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row0, prepared_row_b, row_blocks) + bias_b_value;
            out_b1[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row1, prepared_row_b, row_blocks) + bias_b_value;
            out_c0[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row0, prepared_row_c, row_blocks) + bias_c_value;
            out_c1[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row1, prepared_row_c, row_blocks) + bias_c_value;
        }
        while (o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
            if (triple_panel16_dot) {
                writeQ4Q5KPreparedQ8KPanel16TripleMR2Projection(q_input_row0, q_input_row1, panel16_blocks_a, panel16_blocks_b, panel16_blocks_c, if (packed_qkv_panel16_mr2) packed_qkv_panel16 else null, out_a0, out_a1, out_b0, out_b1, out_c0, out_c1, row_blocks, o);
                addBiasTile16Rows2(out_a0, out_a1, bias_a, o);
                addBiasTile16Rows2(out_b0, out_b1, bias_b, o);
                addBiasTile16Rows2(out_c0, out_c1, bias_c, o);
            } else if (use_projection_prepared_sums) {
                writeQ4Q5KPreparedQ8KPanel16MR2ProjectionPreparedSums(q_input_row0, q_input_row1, &activation_sums0, &activation_sums1, panel16_blocks_a, out_a0, out_a1, row_blocks, o);
                writeQ4Q5KPreparedQ8KPanel16MR2ProjectionPreparedSums(q_input_row0, q_input_row1, &activation_sums0, &activation_sums1, panel16_blocks_b, out_b0, out_b1, row_blocks, o);
                writeQ4Q5KPreparedQ8KPanel16MR2ProjectionPreparedSums(q_input_row0, q_input_row1, &activation_sums0, &activation_sums1, panel16_blocks_c, out_c0, out_c1, row_blocks, o);
                addBiasTile16Rows2(out_a0, out_a1, bias_a, o);
                addBiasTile16Rows2(out_b0, out_b1, bias_b, o);
                addBiasTile16Rows2(out_c0, out_c1, bias_c, o);
            } else {
                writeQ4Q5KPreparedQ8KPanel16MR2Projection(q_input_row0, q_input_row1, panel16_blocks_a, out_a0, out_a1, row_blocks, o);
                writeQ4Q5KPreparedQ8KPanel16MR2Projection(q_input_row0, q_input_row1, panel16_blocks_b, out_b0, out_b1, row_blocks, o);
                writeQ4Q5KPreparedQ8KPanel16MR2Projection(q_input_row0, q_input_row1, panel16_blocks_c, out_c0, out_c1, row_blocks, o);
                addBiasTile16Rows2(out_a0, out_a1, bias_a, o);
                addBiasTile16Rows2(out_b0, out_b1, bias_b, o);
                addBiasTile16Rows2(out_c0, out_c1, bias_c, o);
            }
        }
        while (o < out_end) : (o += 1) {
            const prepared_row_a = prepared_blocks_a[o * prepared_row_stride ..][0..prepared_row_stride];
            const prepared_row_b = prepared_blocks_b[o * prepared_row_stride ..][0..prepared_row_stride];
            const prepared_row_c = prepared_blocks_c[o * prepared_row_stride ..][0..prepared_row_stride];
            const bias_a_value = optionalLinearBiasAt(bias_a, o);
            const bias_b_value = optionalLinearBiasAt(bias_b, o);
            const bias_c_value = optionalLinearBiasAt(bias_c, o);
            out_a0[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row0, prepared_row_a, row_blocks) + bias_a_value;
            out_a1[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row1, prepared_row_a, row_blocks) + bias_a_value;
            out_b0[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row0, prepared_row_b, row_blocks) + bias_b_value;
            out_b1[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row1, prepared_row_b, row_blocks) + bias_b_value;
            out_c0[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row0, prepared_row_c, row_blocks) + bias_c_value;
            out_c1[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row1, prepared_row_c, row_blocks) + bias_c_value;
        }
    }

    while (r < rows) : (r += 1) {
        const q_input_row = q_input[r * input_row_stride ..][0..input_row_stride];
        const out_a = output_a[r * out_dim ..][0..out_dim];
        const out_b = output_b[r * out_dim ..][0..out_dim];
        const out_c = output_c[r * out_dim ..][0..out_dim];
        const use_projection_prepared_sums = row_blocks <= q8_k_prepared_sum_stack_max_row_blocks and packed_qkv_panel16 != null;
        var activation_sums: [q8_k_prepared_sum_stack_max_row_blocks][8]F32x8 = undefined;
        var activation_scales: [q8_k_prepared_sum_stack_max_row_blocks]F32x8 = undefined;
        if (use_projection_prepared_sums) {
            for (0..row_blocks) |block_idx| {
                const q8_off = block_idx * q8_block_size;
                const block = q_input_row[q8_off..][0..q8_block_size];
                prepareQ8KActivationSums(block, &activation_sums[block_idx]);
                activation_scales[block_idx] = @splat(readF32Le(block[0..4]));
            }
        }
        var o: usize = out_start;
        while (o < out_end and (o % prepared_k_panel16_nr) != 0) : (o += 1) {
            const prepared_row_a = prepared_blocks_a[o * prepared_row_stride ..][0..prepared_row_stride];
            const prepared_row_b = prepared_blocks_b[o * prepared_row_stride ..][0..prepared_row_stride];
            const prepared_row_c = prepared_blocks_c[o * prepared_row_stride ..][0..prepared_row_stride];
            out_a[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row, prepared_row_a, row_blocks) + optionalLinearBiasAt(bias_a, o);
            out_b[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row, prepared_row_b, row_blocks) + optionalLinearBiasAt(bias_b, o);
            out_c[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row, prepared_row_c, row_blocks) + optionalLinearBiasAt(bias_c, o);
        }
        if (packed_qkv_panel16) |packed_panel| {
            while (o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
                if (use_projection_prepared_sums) {
                    writeQ4Q5KPreparedQ8KPackedQKVPanel16MR1ProjectionPreparedSums(q_input_row, &activation_sums, &activation_scales, packed_panel, out_a, out_b, out_c, row_blocks, o);
                } else {
                    writeQ4Q5KPreparedQ8KPackedQKVPanel16MR1Projection(q_input_row, packed_panel, out_a, out_b, out_c, row_blocks, o);
                }
                addBiasTile16(out_a, bias_a, o);
                addBiasTile16(out_b, bias_b, o);
                addBiasTile16(out_c, bias_c, o);
            }
        }
        while (o < out_end) : (o += 1) {
            const prepared_row_a = prepared_blocks_a[o * prepared_row_stride ..][0..prepared_row_stride];
            const prepared_row_b = prepared_blocks_b[o * prepared_row_stride ..][0..prepared_row_stride];
            const prepared_row_c = prepared_blocks_c[o * prepared_row_stride ..][0..prepared_row_stride];
            out_a[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row, prepared_row_a, row_blocks) + optionalLinearBiasAt(bias_a, o);
            out_b[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row, prepared_row_b, row_blocks) + optionalLinearBiasAt(bias_b, o);
            out_c[o] = dotQ4Q5KPreparedQ8KPreparedRow(q_input_row, prepared_row_c, row_blocks) + optionalLinearBiasAt(bias_c, o);
        }
    }
}

fn linearQ8_0Range(
    input: []const f32,
    weight_raw: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    bias: ?[]const f32,
) void {
    const block_size: usize = 34; // 2 (fp16 d) + 32 (i8 qs)
    const values_per_block: usize = 32;
    std.debug.assert(in_dim % values_per_block == 0);
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * block_size;

    var r: usize = 0;
    // MR=2/NR=2 row tile: reuses the same two Q8_0 weight columns across
    // two input rows. Four vector accumulators stays conservative on AVX2.
    while (r + 2 <= rows) : (r += 2) {
        const input_row0 = input[r * in_dim ..][0..in_dim];
        const input_row1 = input[(r + 1) * in_dim ..][0..in_dim];
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];

        var o = out_start;
        while (o + 2 <= out_end) : (o += 2) {
            const w0_off = o * row_stride;
            const w1_off = (o + 1) * row_stride;
            var acc_r0c0: F32xN = @splat(0.0);
            var acc_r0c1: F32xN = @splat(0.0);
            var acc_r1c0: F32xN = @splat(0.0);
            var acc_r1c1: F32xN = @splat(0.0);
            for (0..row_blocks) |block_idx| {
                const w0_blk = weight_raw[w0_off + block_idx * block_size ..][0..block_size];
                const w1_blk = weight_raw[w1_off + block_idx * block_size ..][0..block_size];
                const d0 = decodeFp16Le(w0_blk[0], w0_blk[1]);
                const d1 = decodeFp16Le(w1_blk[0], w1_blk[1]);
                const input_blk_r0: *const [32]f32 = input_row0[block_idx * values_per_block ..][0..32];
                const input_blk_r1: *const [32]f32 = input_row1[block_idx * values_per_block ..][0..32];
                const qs0: *const [32]u8 = w0_blk[2..34];
                const qs1: *const [32]u8 = w1_blk[2..34];
                accumulateQ8_0Block2MR2NR(
                    input_blk_r0,
                    input_blk_r1,
                    qs0,
                    qs1,
                    d0,
                    d1,
                    &acc_r0c0,
                    &acc_r0c1,
                    &acc_r1c0,
                    &acc_r1c1,
                );
            }
            const bias0 = optionalLinearBiasAt(bias, o);
            const bias1 = optionalLinearBiasAt(bias, o + 1);
            out_row0[o] = @reduce(.Add, acc_r0c0) + bias0;
            out_row0[o + 1] = @reduce(.Add, acc_r0c1) + bias1;
            out_row1[o] = @reduce(.Add, acc_r1c0) + bias0;
            out_row1[o + 1] = @reduce(.Add, acc_r1c1) + bias1;
        }
        // N-tail for row pairs: keep the same range semantics for odd column
        // chunks while still sharing the remaining weight column across rows.
        while (o < out_end) : (o += 1) {
            const w_off = o * row_stride;
            var acc_r0: F32xN = @splat(0.0);
            var acc_r1: F32xN = @splat(0.0);
            for (0..row_blocks) |block_idx| {
                const w_blk = weight_raw[w_off + block_idx * block_size ..][0..block_size];
                const d = decodeFp16Le(w_blk[0], w_blk[1]);
                const input_blk_r0: *const [32]f32 = input_row0[block_idx * values_per_block ..][0..32];
                const input_blk_r1: *const [32]f32 = input_row1[block_idx * values_per_block ..][0..32];
                const qs: *const [32]u8 = w_blk[2..34];
                accumulateQ8_0Block2MR1NR(input_blk_r0, input_blk_r1, qs, d, &acc_r0, &acc_r1);
            }
            const bias_value = optionalLinearBiasAt(bias, o);
            out_row0[o] = @reduce(.Add, acc_r0) + bias_value;
            out_row1[o] = @reduce(.Add, acc_r1) + bias_value;
        }
    }

    while (r < rows) : (r += 1) {
        const input_row = input[r * in_dim ..][0..in_dim];
        const out_row = output[r * out_dim ..][0..out_dim];

        var o = out_start;
        // NR=2 col tile: shares each input_block load across two output cols.
        while (o + 2 <= out_end) : (o += 2) {
            const w0_off = o * row_stride;
            const w1_off = (o + 1) * row_stride;
            var acc0: F32xN = @splat(0.0);
            var acc1: F32xN = @splat(0.0);
            for (0..row_blocks) |block_idx| {
                const w0_blk = weight_raw[w0_off + block_idx * block_size ..][0..block_size];
                const w1_blk = weight_raw[w1_off + block_idx * block_size ..][0..block_size];
                const d0 = decodeFp16Le(w0_blk[0], w0_blk[1]);
                const d1 = decodeFp16Le(w1_blk[0], w1_blk[1]);
                const input_blk: *const [32]f32 = input_row[block_idx * values_per_block ..][0..32];
                const qs0: *const [32]u8 = w0_blk[2..34];
                const qs1: *const [32]u8 = w1_blk[2..34];
                accumulateQ8_0Block2NR(input_blk, qs0, qs1, d0, d1, &acc0, &acc1);
            }
            out_row[o] = @reduce(.Add, acc0) + optionalLinearBiasAt(bias, o);
            out_row[o + 1] = @reduce(.Add, acc1) + optionalLinearBiasAt(bias, o + 1);
        }
        // N-tail: trailing single col.  Generic dot keeps the inner loop
        // tight even at NR=1 since the body is fully inlined.
        while (o < out_end) : (o += 1) {
            const w_off = o * row_stride;
            var acc: F32xN = @splat(0.0);
            for (0..row_blocks) |block_idx| {
                const w_blk = weight_raw[w_off + block_idx * block_size ..][0..block_size];
                const d = decodeFp16Le(w_blk[0], w_blk[1]);
                const input_blk: *const [32]f32 = input_row[block_idx * values_per_block ..][0..32];
                const qs: *const [32]u8 = w_blk[2..34];
                accumulateQ8_0Block1NR(input_blk, qs, d, &acc);
            }
            out_row[o] = @reduce(.Add, acc) + optionalLinearBiasAt(bias, o);
        }
    }
}

fn linearQ8_0PreparedPanelRange(
    input: []const f32,
    prepared_blocks: []const u8,
    panel_blocks: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    bias: ?[]const f32,
) void {
    const block_size: usize = prepared_q8_0_block_bytes;
    const values_per_block: usize = 32;
    std.debug.assert(in_dim % values_per_block == 0);
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * block_size;

    var r: usize = 0;
    while (r + 2 <= rows) : (r += 2) {
        const input_row0 = input[r * in_dim ..][0..in_dim];
        const input_row1 = input[(r + 1) * in_dim ..][0..in_dim];
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];

        var o = out_start;
        while (o < out_end and (o % prepared_q8_0_panel_nr) != 0) : (o += 1) {
            const w_off = o * row_stride;
            var acc_r0: F32xN = @splat(0.0);
            var acc_r1: F32xN = @splat(0.0);
            for (0..row_blocks) |block_idx| {
                const w_blk = prepared_blocks[w_off + block_idx * block_size ..][0..block_size];
                const input_blk_r0: *const [32]f32 = input_row0[block_idx * values_per_block ..][0..32];
                const input_blk_r1: *const [32]f32 = input_row1[block_idx * values_per_block ..][0..32];
                accumulateQ8_0Block2MR1NR(
                    input_blk_r0,
                    input_blk_r1,
                    q8_0WeightValues(true, w_blk),
                    q8_0WeightScale(true, w_blk),
                    &acc_r0,
                    &acc_r1,
                );
            }
            const bias_value = optionalLinearBiasAt(bias, o);
            out_row0[o] = @reduce(.Add, acc_r0) + bias_value;
            out_row1[o] = @reduce(.Add, acc_r1) + bias_value;
        }

        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc_r0c0: F32xN = @splat(0.0);
            var acc_r0c1: F32xN = @splat(0.0);
            var acc_r0c2: F32xN = @splat(0.0);
            var acc_r0c3: F32xN = @splat(0.0);
            var acc_r1c0: F32xN = @splat(0.0);
            var acc_r1c1: F32xN = @splat(0.0);
            var acc_r1c2: F32xN = @splat(0.0);
            var acc_r1c3: F32xN = @splat(0.0);
            for (0..row_blocks) |block_idx| {
                const panel_off = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
                const w0_blk = panel_blocks[panel_off..][0..block_size];
                const w1_blk = panel_blocks[panel_off + block_size ..][0..block_size];
                const w2_blk = panel_blocks[panel_off + 2 * block_size ..][0..block_size];
                const w3_blk = panel_blocks[panel_off + 3 * block_size ..][0..block_size];
                const input_blk_r0: *const [32]f32 = input_row0[block_idx * values_per_block ..][0..32];
                const input_blk_r1: *const [32]f32 = input_row1[block_idx * values_per_block ..][0..32];
                accumulateQ8_0Block2MR2NR(
                    input_blk_r0,
                    input_blk_r1,
                    q8_0WeightValues(true, w0_blk),
                    q8_0WeightValues(true, w1_blk),
                    q8_0WeightScale(true, w0_blk),
                    q8_0WeightScale(true, w1_blk),
                    &acc_r0c0,
                    &acc_r0c1,
                    &acc_r1c0,
                    &acc_r1c1,
                );
                accumulateQ8_0Block2MR2NR(
                    input_blk_r0,
                    input_blk_r1,
                    q8_0WeightValues(true, w2_blk),
                    q8_0WeightValues(true, w3_blk),
                    q8_0WeightScale(true, w2_blk),
                    q8_0WeightScale(true, w3_blk),
                    &acc_r0c2,
                    &acc_r0c3,
                    &acc_r1c2,
                    &acc_r1c3,
                );
            }
            const bias0 = optionalLinearBiasAt(bias, o);
            const bias1 = optionalLinearBiasAt(bias, o + 1);
            const bias2 = optionalLinearBiasAt(bias, o + 2);
            const bias3 = optionalLinearBiasAt(bias, o + 3);
            out_row0[o] = @reduce(.Add, acc_r0c0) + bias0;
            out_row0[o + 1] = @reduce(.Add, acc_r0c1) + bias1;
            out_row0[o + 2] = @reduce(.Add, acc_r0c2) + bias2;
            out_row0[o + 3] = @reduce(.Add, acc_r0c3) + bias3;
            out_row1[o] = @reduce(.Add, acc_r1c0) + bias0;
            out_row1[o + 1] = @reduce(.Add, acc_r1c1) + bias1;
            out_row1[o + 2] = @reduce(.Add, acc_r1c2) + bias2;
            out_row1[o + 3] = @reduce(.Add, acc_r1c3) + bias3;
        }

        while (o < out_end) : (o += 1) {
            const w_off = o * row_stride;
            var acc_r0: F32xN = @splat(0.0);
            var acc_r1: F32xN = @splat(0.0);
            for (0..row_blocks) |block_idx| {
                const w_blk = prepared_blocks[w_off + block_idx * block_size ..][0..block_size];
                const input_blk_r0: *const [32]f32 = input_row0[block_idx * values_per_block ..][0..32];
                const input_blk_r1: *const [32]f32 = input_row1[block_idx * values_per_block ..][0..32];
                accumulateQ8_0Block2MR1NR(input_blk_r0, input_blk_r1, q8_0WeightValues(true, w_blk), q8_0WeightScale(true, w_blk), &acc_r0, &acc_r1);
            }
            const bias_value = optionalLinearBiasAt(bias, o);
            out_row0[o] = @reduce(.Add, acc_r0) + bias_value;
            out_row1[o] = @reduce(.Add, acc_r1) + bias_value;
        }
    }

    while (r < rows) : (r += 1) {
        const input_row = input[r * in_dim ..][0..in_dim];
        const out_row = output[r * out_dim ..][0..out_dim];

        var o = out_start;
        while (o < out_end and (o % prepared_q8_0_panel_nr) != 0) : (o += 1) {
            const w_off = o * row_stride;
            var acc: F32xN = @splat(0.0);
            for (0..row_blocks) |block_idx| {
                const w_blk = prepared_blocks[w_off + block_idx * block_size ..][0..block_size];
                const input_blk: *const [32]f32 = input_row[block_idx * values_per_block ..][0..32];
                accumulateQ8_0Block1NR(input_blk, q8_0WeightValues(true, w_blk), q8_0WeightScale(true, w_blk), &acc);
            }
            out_row[o] = @reduce(.Add, acc) + optionalLinearBiasAt(bias, o);
        }

        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc0: F32xN = @splat(0.0);
            var acc1: F32xN = @splat(0.0);
            var acc2: F32xN = @splat(0.0);
            var acc3: F32xN = @splat(0.0);
            for (0..row_blocks) |block_idx| {
                const panel_off = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
                const w0_blk = panel_blocks[panel_off..][0..block_size];
                const w1_blk = panel_blocks[panel_off + block_size ..][0..block_size];
                const w2_blk = panel_blocks[panel_off + 2 * block_size ..][0..block_size];
                const w3_blk = panel_blocks[panel_off + 3 * block_size ..][0..block_size];
                const input_blk: *const [32]f32 = input_row[block_idx * values_per_block ..][0..32];
                accumulateQ8_0Block2NR(
                    input_blk,
                    q8_0WeightValues(true, w0_blk),
                    q8_0WeightValues(true, w1_blk),
                    q8_0WeightScale(true, w0_blk),
                    q8_0WeightScale(true, w1_blk),
                    &acc0,
                    &acc1,
                );
                accumulateQ8_0Block2NR(
                    input_blk,
                    q8_0WeightValues(true, w2_blk),
                    q8_0WeightValues(true, w3_blk),
                    q8_0WeightScale(true, w2_blk),
                    q8_0WeightScale(true, w3_blk),
                    &acc2,
                    &acc3,
                );
            }
            out_row[o] = @reduce(.Add, acc0) + optionalLinearBiasAt(bias, o);
            out_row[o + 1] = @reduce(.Add, acc1) + optionalLinearBiasAt(bias, o + 1);
            out_row[o + 2] = @reduce(.Add, acc2) + optionalLinearBiasAt(bias, o + 2);
            out_row[o + 3] = @reduce(.Add, acc3) + optionalLinearBiasAt(bias, o + 3);
        }

        while (o < out_end) : (o += 1) {
            const w_off = o * row_stride;
            var acc: F32xN = @splat(0.0);
            for (0..row_blocks) |block_idx| {
                const w_blk = prepared_blocks[w_off + block_idx * block_size ..][0..block_size];
                const input_blk: *const [32]f32 = input_row[block_idx * values_per_block ..][0..32];
                accumulateQ8_0Block1NR(input_blk, q8_0WeightValues(true, w_blk), q8_0WeightScale(true, w_blk), &acc);
            }
            out_row[o] = @reduce(.Add, acc) + optionalLinearBiasAt(bias, o);
        }
    }
}

const Q8_0WorkerCtx = struct {
    input: []const f32,
    weight_raw: []const u8,
    prepared_blocks: ?[]const u8 = null,
    prepared_panel_blocks: ?[]const u8 = null,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize = 0,
    out_end: usize = 0,
    // The Q8_0 kernel is infallible -- it doesn't allocate or do I/O
    // -- but we keep the same `err` slot the other quant worker contexts
    // carry so `dispatchAndCheckQuantWorkers` can be used uniformly.
    err: ?anyerror = null,
};

