fn q8_0F32Apply(
    input: []const f32,
    weight_raw: []const u8,
    prepared_blocks: ?[]const u8,
    prepared_panel_blocks: ?[]const u8,
    bias: ?[]const f32,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    if (q8_0F32PreparedPanelEnabled()) {
        if (prepared_blocks) |prepared| {
            if (prepared_panel_blocks) |panel| {
                linearQ8_0PreparedPanelRange(input, prepared, panel, output, rows, in_dim, out_dim, out_start, out_end, bias);
                return;
            }
        }
    }
    linearQ8_0Range(input, weight_raw, output, rows, in_dim, out_dim, out_start, out_end, bias);
}

fn q8_0Worker(ctx: *Q8_0WorkerCtx) void {
    q8_0F32Apply(
        ctx.input,
        ctx.weight_raw,
        ctx.prepared_blocks,
        ctx.prepared_panel_blocks,
        null,
        ctx.output,
        ctx.rows,
        ctx.in_dim,
        ctx.out_dim,
        ctx.out_start,
        ctx.out_end,
    );
}

fn q8_0WorkerJob(raw: *anyopaque) void {
    q8_0Worker(@ptrCast(@alignCast(raw)));
}

fn q8_0ActivationApply(
    q_input: []const u8,
    input_scales: []const f32,
    weight_raw: []const u8,
    prepared_blocks: ?[]const u8,
    prepared_panel_blocks: ?[]const u8,
    prepared_panel8_blocks: ?[]const u8,
    bias: ?[]const f32,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    if (prepared_blocks) |prepared| {
        if (q8_0Panel8SingleDirectEnabledForShape(out_dim, in_dim / 32)) {
            if (prepared_panel8_blocks) |panel8| {
                linearQ8_0QuantizedInputGroupedPanel8Range(1, q_input, input_scales, .{prepared}, .{prepared_panel_blocks}, .{panel8}, .{bias}, .{output}, rows, in_dim, out_dim, out_start, out_end);
                return;
            }
        }
        if (prepared_panel_blocks) |panel| {
            linearQ8_0QuantizedInputPreparedPanelRange(q_input, input_scales, prepared, panel, output, rows, in_dim, out_dim, out_start, out_end, bias);
        } else {
            linearQ8_0QuantizedInputRange(
                true,
                q_input,
                input_scales,
                prepared,
                output,
                rows,
                in_dim,
                out_dim,
                out_start,
                out_end,
                bias,
            );
        }
    } else {
        linearQ8_0QuantizedInputRange(
            false,
            q_input,
            input_scales,
            weight_raw,
            output,
            rows,
            in_dim,
            out_dim,
            out_start,
            out_end,
            bias,
        );
    }
}

inline fn q8_0QuantizedWeightBlock(
    comptime prepared: bool,
    weight_blocks: []const u8,
    panel_blocks: ?[]const u8,
    row_blocks: usize,
    row_stride: usize,
    out_col: usize,
    block_idx: usize,
    allow_panel: bool,
) []const u8 {
    const block_size: usize = q8_0BlockSize(prepared);
    if (prepared and allow_panel) {
        if (panel_blocks) |panel| {
            const lane = out_col % prepared_q8_0_panel_nr;
            const panel_idx = out_col / prepared_q8_0_panel_nr;
            const panel_off = (panel_idx * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size + lane * block_size;
            return panel[panel_off..][0..block_size];
        }
    }
    return weight_blocks[out_col * row_stride + block_idx * block_size ..][0..block_size];
}

inline fn q8_0QuantizedWeightBlock8(
    comptime prepared: bool,
    weight_blocks: []const u8,
    panel_blocks: ?[]const u8,
    row_blocks: usize,
    row_stride: usize,
    out_col: usize,
    block_idx: usize,
    allow_panel: bool,
) [8][]const u8 {
    return .{
        q8_0QuantizedWeightBlock(prepared, weight_blocks, panel_blocks, row_blocks, row_stride, out_col, block_idx, allow_panel),
        q8_0QuantizedWeightBlock(prepared, weight_blocks, panel_blocks, row_blocks, row_stride, out_col + 1, block_idx, allow_panel),
        q8_0QuantizedWeightBlock(prepared, weight_blocks, panel_blocks, row_blocks, row_stride, out_col + 2, block_idx, allow_panel),
        q8_0QuantizedWeightBlock(prepared, weight_blocks, panel_blocks, row_blocks, row_stride, out_col + 3, block_idx, allow_panel),
        q8_0QuantizedWeightBlock(prepared, weight_blocks, panel_blocks, row_blocks, row_stride, out_col + 4, block_idx, allow_panel),
        q8_0QuantizedWeightBlock(prepared, weight_blocks, panel_blocks, row_blocks, row_stride, out_col + 5, block_idx, allow_panel),
        q8_0QuantizedWeightBlock(prepared, weight_blocks, panel_blocks, row_blocks, row_stride, out_col + 6, block_idx, allow_panel),
        q8_0QuantizedWeightBlock(prepared, weight_blocks, panel_blocks, row_blocks, row_stride, out_col + 7, block_idx, allow_panel),
    };
}

inline fn q8_0QuantizedWeightBlock4(
    comptime prepared: bool,
    weight_blocks: []const u8,
    panel_blocks: ?[]const u8,
    row_blocks: usize,
    row_stride: usize,
    out_col: usize,
    block_idx: usize,
    allow_panel: bool,
) [4][]const u8 {
    const block_size: usize = q8_0BlockSize(prepared);
    if (prepared and allow_panel) {
        if (panel_blocks) |panel| {
            const panel_idx = out_col / prepared_q8_0_panel_nr;
            const panel_off = (panel_idx * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size;
            return .{
                panel[panel_off..][0..block_size],
                panel[panel_off + block_size ..][0..block_size],
                panel[panel_off + 2 * block_size ..][0..block_size],
                panel[panel_off + 3 * block_size ..][0..block_size],
            };
        }
    }
    const block_off = block_idx * block_size;
    return .{
        weight_blocks[out_col * row_stride + block_off ..][0..block_size],
        weight_blocks[(out_col + 1) * row_stride + block_off ..][0..block_size],
        weight_blocks[(out_col + 2) * row_stride + block_off ..][0..block_size],
        weight_blocks[(out_col + 3) * row_stride + block_off ..][0..block_size],
    };
}

inline fn q8_0AddDotMR2(
    comptime prepared: bool,
    qx0: *const [32]u8,
    qx1: *const [32]u8,
    input_scale0: f32,
    input_scale1: f32,
    weight_block: []const u8,
    acc0: *f32,
    acc1: *f32,
) void {
    const weight_scale = q8_0WeightScale(prepared, weight_block);
    const qw = q8_0WeightValues(prepared, weight_block);
    acc0.* += (input_scale0 * weight_scale) * @as(f32, @floatFromInt(dotI8I8Block(qx0, qw)));
    acc1.* += (input_scale1 * weight_scale) * @as(f32, @floatFromInt(dotI8I8Block(qx1, qw)));
}

inline fn q8_0AddDotMR1(
    comptime prepared: bool,
    qx: *const [32]u8,
    input_scale: f32,
    weight_block: []const u8,
    acc: *f32,
) void {
    acc.* += (input_scale * q8_0WeightScale(prepared, weight_block)) * @as(f32, @floatFromInt(dotI8I8Block(qx, q8_0WeightValues(prepared, weight_block))));
}

inline fn q8_0AddDot4MR2(
    comptime prepared: bool,
    qx0: *const [32]u8,
    qx1: *const [32]u8,
    input_scale0: f32,
    input_scale1: f32,
    w0: []const u8,
    w1: []const u8,
    w2: []const u8,
    w3: []const u8,
    acc0: *[4]f32,
    acc1: *[4]f32,
) void {
    const dots = dotI8I8Block4MR2(qx0, qx1, q8_0WeightValues(prepared, w0), q8_0WeightValues(prepared, w1), q8_0WeightValues(prepared, w2), q8_0WeightValues(prepared, w3));
    const weight_scales = [_]f32{
        q8_0WeightScale(prepared, w0),
        q8_0WeightScale(prepared, w1),
        q8_0WeightScale(prepared, w2),
        q8_0WeightScale(prepared, w3),
    };
    inline for (0..4) |idx| {
        acc0[idx] += (input_scale0 * weight_scales[idx]) * @as(f32, @floatFromInt(dots[idx]));
        acc1[idx] += (input_scale1 * weight_scales[idx]) * @as(f32, @floatFromInt(dots[idx + 4]));
    }
}

