inline fn q8_0Panel8WeightScales(panel_block: []const u8) F32x8 {
    std.debug.assert(panel_block.len == prepared_q8_0_panel8_block_bytes);
    return readF32x8Le(panel_block[prepared_q8_0_panel8_scale_offset..][0..32]);
}

inline fn q8_0BiasVec8(bias: ?[]const f32, out_col: usize) F32x8 {
    return .{
        optionalLinearBiasAt(bias, out_col),
        optionalLinearBiasAt(bias, out_col + 1),
        optionalLinearBiasAt(bias, out_col + 2),
        optionalLinearBiasAt(bias, out_col + 3),
        optionalLinearBiasAt(bias, out_col + 4),
        optionalLinearBiasAt(bias, out_col + 5),
        optionalLinearBiasAt(bias, out_col + 6),
        optionalLinearBiasAt(bias, out_col + 7),
    };
}

inline fn dotQ8_0Panel8MR2Vec(
    qx0: *const [32]u8,
    qx1: *const [32]u8,
    input_scale0: f32,
    input_scale1: f32,
    panel_block: []const u8,
) Panel8MR2VecSums {
    std.debug.assert(panel_block.len == prepared_q8_0_panel8_block_bytes);
    const values = panel_block[prepared_q8_0_panel8_values_offset..][0..prepared_q8_0_panel8_values_bytes];
    const dots = dotI8I8Block8MR2RowsContiguousVec(qx0, qx1, values);
    const weight_scales = q8_0Panel8WeightScales(panel_block);
    return .{
        .r0 = (@as(F32x8, @splat(input_scale0)) * weight_scales) * @as(F32x8, @floatFromInt(dots.r0)),
        .r1 = (@as(F32x8, @splat(input_scale1)) * weight_scales) * @as(F32x8, @floatFromInt(dots.r1)),
    };
}

inline fn dotQ8_0Panel8MR2(
