    qx1: *const [32]u8,
    input_scale0: f32,
    input_scale1: f32,
    panel_block: []const u8,
) Panel8MR2Sums {
    const sums = dotQ8_0Panel8MR2Vec(qx0, qx1, input_scale0, input_scale1, panel_block);
    return .{ .r0 = f32x8ToArray(sums.r0), .r1 = f32x8ToArray(sums.r1) };
}

