inline fn q8KQ8KWeightBlock(
    weight_raw: []const u8,
    panel_blocks: ?[]const u8,
    row_blocks: usize,
    row_stride: usize,
    out_col: usize,
    block_idx: usize,
    allow_panel: bool,
) []const u8 {
    const block_size: usize = 292;
    if (allow_panel) {
        if (panel_blocks) |panel| {
            const lane = out_col % prepared_q8_0_panel_nr;
            const panel_idx = out_col / prepared_q8_0_panel_nr;
            const panel_off = (panel_idx * row_blocks + block_idx) * prepared_q8_0_panel_nr * block_size + lane * block_size;
            return panel[panel_off..][0..block_size];
        }
    }
    return weight_raw[out_col * row_stride + block_idx * block_size ..][0..block_size];
}

inline fn q8KQ8KWeightBlock8(
    weight_raw: []const u8,
    panel_blocks: ?[]const u8,
