    };
}

inline fn q8KGroupedBias(
    comptime projection_count: usize,
    biases: [projection_count]?[]const f32,
    projection_idx: usize,
    out_col: usize,
) f32 {
    return if (biases[projection_idx]) |bias| bias[out_col] else 0.0;
}

fn linearQ8KQ8KActivationGroupedRange(
    comptime projection_count: usize,
    q_input: []const u8,
    weight_raw: [projection_count][]const u8,
    panel_blocks: [projection_count]?[]const u8,
    panel8_blocks: [projection_count]?[]const u8,
    panel16_blocks: [projection_count]?[]const u8,
    outputs: [projection_count][]f32,
    biases: [projection_count]?[]const f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    @setEvalBranchQuota(20_000);
    const values_per_block: usize = 256;
    const block_size: usize = 292;
    std.debug.assert(in_dim % values_per_block == 0);
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * block_size;
    const use_fused_sdot = q8KFusedSdotEnabled();
    var have_panel8 = true;
    inline for (0..projection_count) |projection_idx| {
        have_panel8 = have_panel8 and panel8_blocks[projection_idx] != null;
    }
    var have_panel16 = true;
    inline for (0..projection_count) |projection_idx| {
        have_panel16 = have_panel16 and panel16_blocks[projection_idx] != null;
    }
    const panel_align: usize = if (have_panel16) prepared_k_panel16_nr else if (have_panel8) prepared_k_panel8_nr else prepared_q8_0_panel_nr;

    var r: usize = 0;
    while (r + 4 <= rows) : (r += 4) {
        const q_input_row0 = q_input[r * row_stride ..][0..row_stride];
        const q_input_row1 = q_input[(r + 1) * row_stride ..][0..row_stride];
        const q_input_row2 = q_input[(r + 2) * row_stride ..][0..row_stride];
        const q_input_row3 = q_input[(r + 3) * row_stride ..][0..row_stride];
        var o: usize = out_start;
        while (o < out_end and (o % panel_align) != 0) : (o += 1) {
            var acc0: [projection_count]f32 = [_]f32{0.0} ** projection_count;
            var acc1: [projection_count]f32 = [_]f32{0.0} ** projection_count;
            var acc2: [projection_count]f32 = [_]f32{0.0} ** projection_count;
            var acc3: [projection_count]f32 = [_]f32{0.0} ** projection_count;
            for (0..row_blocks) |block_idx| {
                const off = block_idx * block_size;
                const q0 = q_input_row0[off..][0..block_size];
                const q1 = q_input_row1[off..][0..block_size];
                const q2 = q_input_row2[off..][0..block_size];
                const q3 = q_input_row3[off..][0..block_size];
                inline for (0..projection_count) |projection_idx| {
                    const weight_block = q8KQ8KWeightBlock(weight_raw[projection_idx], panel_blocks[projection_idx], row_blocks, row_stride, o, block_idx, false);
                    acc0[projection_idx] += dotQ8KQ8KBlock(q0, weight_block);
                    acc1[projection_idx] += dotQ8KQ8KBlock(q1, weight_block);
                    acc2[projection_idx] += dotQ8KQ8KBlock(q2, weight_block);
                    acc3[projection_idx] += dotQ8KQ8KBlock(q3, weight_block);
                }
            }
            inline for (0..projection_count) |projection_idx| {
                const bias = q8KGroupedBias(projection_count, biases, projection_idx, o);
                outputs[projection_idx][r * out_dim + o] = acc0[projection_idx] + bias;
                outputs[projection_idx][(r + 1) * out_dim + o] = acc1[projection_idx] + bias;
                outputs[projection_idx][(r + 2) * out_dim + o] = acc2[projection_idx] + bias;
                outputs[projection_idx][(r + 3) * out_dim + o] = acc3[projection_idx] + bias;
            }
        }
        if (have_panel16) {
            while ((o % prepared_k_panel16_nr) == 0 and o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
                var acc0: [projection_count][prepared_k_panel16_nr]f32 = [_][prepared_k_panel16_nr]f32{[_]f32{0.0} ** prepared_k_panel16_nr} ** projection_count;
                var acc1: [projection_count][prepared_k_panel16_nr]f32 = [_][prepared_k_panel16_nr]f32{[_]f32{0.0} ** prepared_k_panel16_nr} ** projection_count;
                var acc2: [projection_count][prepared_k_panel16_nr]f32 = [_][prepared_k_panel16_nr]f32{[_]f32{0.0} ** prepared_k_panel16_nr} ** projection_count;
                var acc3: [projection_count][prepared_k_panel16_nr]f32 = [_][prepared_k_panel16_nr]f32{[_]f32{0.0} ** prepared_k_panel16_nr} ** projection_count;
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * block_size;
                    const q0 = q_input_row0[off..][0..block_size];
                    const q1 = q_input_row1[off..][0..block_size];
                    const q2 = q_input_row2[off..][0..block_size];
                    const q3 = q_input_row3[off..][0..block_size];
                    const panel_off = ((o / prepared_k_panel16_nr) * row_blocks + block_idx) * prepared_q8_k_panel16_block_bytes;
                    inline for (0..projection_count) |projection_idx| {
                        const sums = dotQ8KQ8KBlock16MR4(q0, q1, q2, q3, panel16_blocks[projection_idx].?[panel_off..][0..prepared_q8_k_panel16_block_bytes]);
                        inline for (0..prepared_k_panel16_nr) |lane| {
