                    const q0 = q_input_row0[off..][0..block_size];
                    const q1 = q_input_row1[off..][0..block_size];
                    const q2 = q_input_row2[off..][0..block_size];
                    const q3 = q_input_row3[off..][0..block_size];
                    inline for (0..projection_count) |projection_idx| {
                        const weights = q8KQ8KWeightBlock8(weight_raw[projection_idx], panel_blocks[projection_idx], row_blocks, row_stride, o, block_idx, true);
                        const sums = dotQ8KQ8KBlock8MR4Blocks(q0, q1, q2, q3, weights);
                        inline for (0..8) |lane| {
