                const off = block_idx * block_size;
                const q = q_input_row[off..][0..block_size];
                inline for (0..projection_count) |projection_idx| {
                    const weight_block = q8KQ8KWeightBlock(weight_raw[projection_idx], panel_blocks[projection_idx], row_blocks, row_stride, o, block_idx, false);
                    acc[projection_idx] += dotQ8KQ8KBlock(q, weight_block);
                }
            }
            inline for (0..projection_count) |projection_idx| {
                outputs[projection_idx][r * out_dim + o] = acc[projection_idx] + q8KGroupedBias(projection_count, biases, projection_idx, o);
            }
        }
    }
}

