        linearQ6KPreparedQ8KActivationGroupedRange(2, ctx.q_input, .{ ctx.prepared_blocks_a, ctx.prepared_blocks_b }, .{ ctx.panel_blocks_a, ctx.panel_blocks_b }, .{ ctx.panel8_blocks_a, ctx.panel8_blocks_b }, .{ ctx.panel16_blocks_a, ctx.panel16_blocks_b }, .{ ctx.output_a, ctx.output_b }, ctx.rows, ctx.in_dim, ctx.out_dim, ctx.out_start, ctx.out_end);
        return;
    }
    if (!ctx.q6) {
        if (useQ4Q5Panel16DirectForShape(ctx.rows, ctx.out_dim, ctx.in_dim / 256, ctx.panel16_blocks_a != null and ctx.panel16_blocks_b != null)) {
            if (ctx.panel16_blocks_a) |panel16_a| {
