                    kPreparedQ8KActivationApply(false, ctx.q_input, ctx.prepared_blocks_a, ctx.panel_blocks_a, ctx.panel8_blocks_a, panel16_a, ctx.output_a, ctx.rows, ctx.in_dim, ctx.out_dim, ctx.out_start, ctx.out_end, ctx.known);
