fn kPreparedQ8KActivationTripleWorker(ctx: *KPreparedQ8KActivationTripleWorkerCtx) void {
    if (ctx.q6 and shouldUseQ6KGroupedTriple(ctx.rows)) {
        linearQ6KPreparedQ8KActivationGroupedRange(3, ctx.q_input, .{ ctx.prepared_blocks_a, ctx.prepared_blocks_b, ctx.prepared_blocks_c }, .{ ctx.panel_blocks_a, ctx.panel_blocks_b, ctx.panel_blocks_c }, .{ ctx.panel8_blocks_a, ctx.panel8_blocks_b, ctx.panel8_blocks_c }, .{ ctx.panel16_blocks_a, ctx.panel16_blocks_b, ctx.panel16_blocks_c }, .{ ctx.output_a, ctx.output_b, ctx.output_c }, ctx.rows, ctx.in_dim, ctx.out_dim, ctx.out_start, ctx.out_end);
