    if (!ctx.q6) {
        if (useQ4Q5Panel16DirectForShape(ctx.rows, ctx.out_dim, ctx.in_dim / 256, ctx.panel16_blocks_a != null and ctx.panel16_blocks_b != null and ctx.panel16_blocks_c != null)) {
            if (ctx.panel16_blocks_a) |panel16_a| {
                if (ctx.panel16_blocks_b) |panel16_b| {
                    if (ctx.panel16_blocks_c) |panel16_c| {
                        if (q4q5FusedTripleDirectEnabled() or ctx.packed_qkv_panel16_blocks != null) {
                            linearQ4Q5KPreparedQ8KActivationTriplePanel16Range(ctx.q_input, ctx.prepared_blocks_a, panel16_a, ctx.bias_a, ctx.output_a, ctx.prepared_blocks_b, panel16_b, ctx.bias_b, ctx.output_b, ctx.prepared_blocks_c, panel16_c, ctx.bias_c, ctx.output_c, ctx.packed_qkv_panel16_blocks, ctx.packed_qkv_panel16_mr2, ctx.packed_qkv_panel16_mr8, ctx.rows, ctx.in_dim, ctx.out_dim, ctx.out_start, ctx.out_end);
                            return;
                        }
                        kPreparedQ8KActivationApply(false, ctx.q_input, ctx.prepared_blocks_a, ctx.panel_blocks_a, ctx.panel8_blocks_a, panel16_a, ctx.output_a, ctx.rows, ctx.in_dim, ctx.out_dim, ctx.out_start, ctx.out_end, ctx.known);
                        kPreparedQ8KActivationApply(false, ctx.q_input, ctx.prepared_blocks_b, ctx.panel_blocks_b, ctx.panel8_blocks_b, panel16_b, ctx.output_b, ctx.rows, ctx.in_dim, ctx.out_dim, ctx.out_start, ctx.out_end, ctx.known);
                        kPreparedQ8KActivationApply(false, ctx.q_input, ctx.prepared_blocks_c, ctx.panel_blocks_c, ctx.panel8_blocks_c, panel16_c, ctx.output_c, ctx.rows, ctx.in_dim, ctx.out_dim, ctx.out_start, ctx.out_end, ctx.known);
                        return;
                    }
                }
            }
        }
        if (ctx.panel8_blocks_a) |panel8_a| {
            if (ctx.panel8_blocks_b) |panel8_b| {
                if (ctx.panel8_blocks_c) |panel8_c| {
                    linearQ4Q5KPreparedQ8KActivationTriplePanel8Range(ctx.q_input, ctx.prepared_blocks_a, panel8_a, ctx.output_a, ctx.prepared_blocks_b, panel8_b, ctx.output_b, ctx.prepared_blocks_c, panel8_c, ctx.output_c, ctx.rows, ctx.in_dim, ctx.out_dim, ctx.out_start, ctx.out_end);
                    return;
                }
            }
        }
    }
    kPreparedQ8KActivationApply(ctx.q6, ctx.q_input, ctx.prepared_blocks_a, ctx.panel_blocks_a, ctx.panel8_blocks_a, ctx.panel16_blocks_a, ctx.output_a, ctx.rows, ctx.in_dim, ctx.out_dim, ctx.out_start, ctx.out_end, ctx.known);
    kPreparedQ8KActivationApply(ctx.q6, ctx.q_input, ctx.prepared_blocks_b, ctx.panel_blocks_b, ctx.panel8_blocks_b, ctx.panel16_blocks_b, ctx.output_b, ctx.rows, ctx.in_dim, ctx.out_dim, ctx.out_start, ctx.out_end, ctx.known);
