    panel16_blocks: ?[]const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    if (try linearNoBiasQ8KQ8KActivationParallel(io, q_input, weight_raw, panel_blocks, panel8_blocks, panel16_blocks, output, rows, in_dim, out_dim)) return;
    linearQ8KQ8KActivationRange(q_input, weight_raw, panel_blocks, panel8_blocks, panel16_blocks, output, rows, in_dim, out_dim, 0, out_dim);
}

fn linearNoBiasQ8KQ8KActivationPair(
    allocator: std.mem.Allocator,
    io: ?std.Io,
    input: []const f32,
    weight_raw_a: []const u8,
    weight_raw_b: []const u8,
    panel_blocks_a: ?[]const u8,
    panel_blocks_b: ?[]const u8,
    panel8_blocks_a: ?[]const u8,
    panel8_blocks_b: ?[]const u8,
    panel16_blocks_a: ?[]const u8,
    panel16_blocks_b: ?[]const u8,
    output_a: []f32,
    output_b: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    if (weight_raw_a.len != out_dim * row_blocks * q8_block_size) return error.InvalidQuantizedDataSize;
    if (weight_raw_b.len != out_dim * row_blocks * q8_block_size) return error.InvalidQuantizedDataSize;
    if (panel_blocks_a) |blocks| {
        if (blocks.len != preparedQ8_KPanelByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;
    }
    if (panel_blocks_b) |blocks| {
        if (blocks.len != preparedQ8_KPanelByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;
    }
    if (panel8_blocks_a) |blocks| {
        if (blocks.len != preparedQ8_KPanel8ByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;
    }
    if (panel8_blocks_b) |blocks| {
        if (blocks.len != preparedQ8_KPanel8ByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;
    }
    if (panel16_blocks_a) |blocks| {
        if (blocks.len != preparedQ8_KPanel16ByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;
    }
    if (panel16_blocks_b) |blocks| {
        if (blocks.len != preparedQ8_KPanel16ByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;
    }

    const q_input_len = rows * row_blocks * q8_block_size;
    if (q_input_len <= q8_k_activation_stack_max_bytes) {
        var q_input_buf: [q8_k_activation_stack_max_bytes]u8 = undefined;
        const q_input = q_input_buf[0..q_input_len];
        if (rows == 1) {
            quantizeQ8_KActivationRows(input, q_input, rows, in_dim, row_blocks);
        } else {
            try quantizeQ8_KActivationRowsDispatch(io, input, q_input, rows, in_dim, row_blocks);
        }
        try linearQ8KQ8KActivationPairDispatch(io, q_input, weight_raw_a, panel_blocks_a, panel8_blocks_a, panel16_blocks_a, output_a, weight_raw_b, panel_blocks_b, panel8_blocks_b, panel16_blocks_b, output_b, rows, in_dim, out_dim);
        return;
    }

    const q_input = try allocator.alloc(u8, q_input_len);
    defer allocator.free(q_input);
    try quantizeQ8_KActivationRowsDispatch(io, input, q_input, rows, in_dim, row_blocks);

