fn linearKPreparedQ8KActivationPairParallel(
    q6: bool,
    io: ?std.Io,
    q_input: []const u8,
    prepared_blocks_a: []const u8,
    panel_blocks_a: ?[]const u8,
    panel8_blocks_a: ?[]const u8,
    panel16_blocks_a: ?[]const u8,
    output_a: []f32,
    prepared_blocks_b: []const u8,
    panel_blocks_b: ?[]const u8,
    panel8_blocks_b: ?[]const u8,
    panel16_blocks_b: ?[]const u8,
    output_b: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    known: ?gguf_tensor_types.KnownTensorType,
) !bool {
    if (rows == 1) return false;
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    const row_blocks = in_dim / values_per_block;
    const dispatch_available = quantParallelDispatchAvailable(io);
    const panel16_available = panel16_blocks_a != null and panel16_blocks_b != null;
    const col_plan = chooseQuantLinearColumnParallelPlanWithMaxRows(
        quantParallelEnabled(),
        rows,
        out_dim,
        row_blocks,
        quantParallelMaxWorkers(),
        q4q5PreparedQ8KColumnParallelMaxRowsForShape(dispatch_available, known, !q6 and panel16_available),
    );
    if (col_plan.worker_count > 1) {
        if (quantParallelDebugRequested()) {
            std.debug.print("k_prepared_q8_k_activation_pair_parallel_cols q6={} workers={d} rows={d} out={d} row_blocks={d}\n", .{ q6, col_plan.worker_count, rows, out_dim, row_blocks });
        }
        var chunks: [max_q4_k_parallel_workers]QuantColChunk = undefined;
        const num_chunks = chunkColsForWorkers(out_dim, col_plan, &chunks);
        var contexts: [max_q4_k_parallel_workers]KPreparedQ8KActivationPairWorkerCtx = undefined;
        var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
        for (chunks[0..num_chunks], 0..) |chunk, i| {
            contexts[i] = .{
                .q_input = q_input,
                .prepared_blocks_a = prepared_blocks_a,
                .panel_blocks_a = panel_blocks_a,
                .panel8_blocks_a = panel8_blocks_a,
                .panel16_blocks_a = panel16_blocks_a,
                .prepared_blocks_b = prepared_blocks_b,
                .panel_blocks_b = panel_blocks_b,
                .panel8_blocks_b = panel8_blocks_b,
                .panel16_blocks_b = panel16_blocks_b,
                .output_a = output_a,
                .output_b = output_b,
                .rows = rows,
                .in_dim = in_dim,
                .out_dim = out_dim,
                .out_start = chunk.start,
                .out_end = chunk.end,
                .q6 = q6,
                .known = known,
            };
            jobs[i] = .{ .fn_ptr = kPreparedQ8KActivationPairWorkerJob, .ctx = @ptrCast(&contexts[i]) };
        }
        try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
        return true;
    }

    const plan = chooseQuantLinearParallelPlan(quantParallelEnabled(), rows, out_dim, row_blocks, quantParallelMaxWorkers());
    if (plan.worker_count <= 1) return false;

    var chunks: [max_q4_k_parallel_workers]QuantRowChunk = undefined;
    const use_panel16_direct = !q6 and useQ4Q5Panel16DirectForShape(rows, out_dim, row_blocks, panel16_blocks_a != null and panel16_blocks_b != null);
    const use_panel16_mr8 = use_panel16_direct and if (known) |value| useQ4Q5Panel16MR8DirectForShape(rows, out_dim, row_blocks, value, panel16_blocks_a != null and panel16_blocks_b != null) and row_blocks <= q8_k_prepared_sum_stack_max_row_blocks else false;
    const num_chunks = if (use_panel16_direct)
        if (use_panel16_mr8) chunkRowsForWorkersAligned(rows, plan, 8, &chunks) else chunkRowsForWorkersAligned(rows, plan, 4, &chunks)
    else
        chunkRowsForWorkers(rows, plan, &chunks);
    var contexts: [max_q4_k_parallel_workers]KPreparedQ8KActivationPairWorkerCtx = undefined;
    var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
    for (chunks[0..num_chunks], 0..) |chunk, i| {
        contexts[i] = .{
            .q_input = q_input[chunk.start * row_blocks * q8_block_size .. chunk.end * row_blocks * q8_block_size],
            .prepared_blocks_a = prepared_blocks_a,
            .panel_blocks_a = panel_blocks_a,
            .panel8_blocks_a = panel8_blocks_a,
            .panel16_blocks_a = panel16_blocks_a,
            .prepared_blocks_b = prepared_blocks_b,
            .panel_blocks_b = panel_blocks_b,
            .panel8_blocks_b = panel8_blocks_b,
            .panel16_blocks_b = panel16_blocks_b,
            .output_a = output_a[chunk.start * out_dim .. chunk.end * out_dim],
            .output_b = output_b[chunk.start * out_dim .. chunk.end * out_dim],
            .rows = chunk.end - chunk.start,
            .in_dim = in_dim,
            .out_dim = out_dim,
            .out_start = 0,
            .out_end = out_dim,
            .q6 = q6,
            .known = known,
        };
        jobs[i] = .{ .fn_ptr = kPreparedQ8KActivationPairWorkerJob, .ctx = @ptrCast(&contexts[i]) };
    }
    try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
    return true;
}

fn linearKPreparedQ8KActivationPairDispatch(
    q6: bool,
    io: ?std.Io,
    q_input: []const u8,
    prepared_blocks_a: []const u8,
    panel_blocks_a: ?[]const u8,
    panel8_blocks_a: ?[]const u8,
    panel16_blocks_a: ?[]const u8,
    output_a: []f32,
    prepared_blocks_b: []const u8,
    panel_blocks_b: ?[]const u8,
    panel8_blocks_b: ?[]const u8,
    panel16_blocks_b: ?[]const u8,
    output_b: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    known: ?gguf_tensor_types.KnownTensorType,
) !void {
    if (try linearKPreparedQ8KActivationPairParallel(q6, io, q_input, prepared_blocks_a, panel_blocks_a, panel8_blocks_a, panel16_blocks_a, output_a, prepared_blocks_b, panel_blocks_b, panel8_blocks_b, panel16_blocks_b, output_b, rows, in_dim, out_dim, known)) return;
    if (!q6 and useQ4Q5Panel16DirectForShape(rows, out_dim, in_dim / 256, panel16_blocks_a != null and panel16_blocks_b != null)) {
        if (panel16_blocks_a) |panel16_a| {
            if (panel16_blocks_b) |panel16_b| {
                kPreparedQ8KActivationApply(false, q_input, prepared_blocks_a, panel_blocks_a, panel8_blocks_a, panel16_a, output_a, rows, in_dim, out_dim, 0, out_dim, known);
                kPreparedQ8KActivationApply(false, q_input, prepared_blocks_b, panel_blocks_b, panel8_blocks_b, panel16_b, output_b, rows, in_dim, out_dim, 0, out_dim, known);
                return;
            }
        }
    }
    if (!q6) {
        if (panel8_blocks_a) |panel8_a| {
            if (panel8_blocks_b) |panel8_b| {
                linearQ4Q5KPreparedQ8KActivationPairPanel8Range(q_input, prepared_blocks_a, panel8_a, output_a, prepared_blocks_b, panel8_b, output_b, rows, in_dim, out_dim, 0, out_dim);
                return;
            }
        }
    }
    if (q6 and (rows == 2 or rows == 4 or rows == 5 or rows == 6 or rows == 8)) {
        linearQ6KPreparedQ8KActivationGroupedRange(2, q_input, .{ prepared_blocks_a, prepared_blocks_b }, .{ panel_blocks_a, panel_blocks_b }, .{ panel8_blocks_a, panel8_blocks_b }, .{ panel16_blocks_a, panel16_blocks_b }, .{ output_a, output_b }, rows, in_dim, out_dim, 0, out_dim);
        return;
    }
    kPreparedQ8KActivationApply(q6, q_input, prepared_blocks_a, panel_blocks_a, panel8_blocks_a, panel16_blocks_a, output_a, rows, in_dim, out_dim, 0, out_dim, known);
    kPreparedQ8KActivationApply(q6, q_input, prepared_blocks_b, panel_blocks_b, panel8_blocks_b, panel16_blocks_b, output_b, rows, in_dim, out_dim, 0, out_dim, known);
}

