                .bias_b = bias_b,
                .prepared_blocks_c = prepared_blocks_c,
                .panel_blocks_c = panel_blocks_c,
                .panel8_blocks_c = panel8_blocks_c,
                .panel16_blocks_c = panel16_blocks_c,
                .packed_qkv_panel16_blocks = packed_qkv_panel16_blocks,
                .packed_qkv_panel16_mr2 = packed_qkv_panel16_mr2,
                .packed_qkv_panel16_mr8 = use_packed_qkv_panel16_mr8,
                .output_a = output_a,
                .output_b = output_b,
                .bias_c = bias_c,
                .output_c = output_c,
                .rows = rows,
                .in_dim = in_dim,
                .out_dim = out_dim,
                .out_start = chunk.start,
                .out_end = chunk.end,
                .q6 = q6,
                .known = known,
            };
            jobs[i] = .{ .fn_ptr = kPreparedQ8KActivationTripleWorkerJob, .ctx = @ptrCast(&contexts[i]) };
        }
        try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
        return true;
    }

    const plan = chooseQuantLinearParallelPlan(quantParallelEnabled(), rows, out_dim, row_blocks, quantParallelMaxWorkers());
    if (plan.worker_count <= 1) return false;

    var chunks: [max_q4_k_parallel_workers]QuantRowChunk = undefined;
    const num_chunks = if (use_panel16_direct)
        if (use_panel16_mr8) chunkRowsForWorkersAligned(rows, plan, 8, &chunks) else chunkRowsForWorkersAligned(rows, plan, 4, &chunks)
    else
        chunkRowsForWorkers(rows, plan, &chunks);
    var contexts: [max_q4_k_parallel_workers]KPreparedQ8KActivationTripleWorkerCtx = undefined;
    var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
    for (chunks[0..num_chunks], 0..) |chunk, i| {
        contexts[i] = .{
            .q_input = q_input[chunk.start * row_blocks * q8_block_size .. chunk.end * row_blocks * q8_block_size],
            .prepared_blocks_a = prepared_blocks_a,
            .panel_blocks_a = panel_blocks_a,
            .panel8_blocks_a = panel8_blocks_a,
            .panel16_blocks_a = panel16_blocks_a,
            .bias_a = bias_a,
            .prepared_blocks_b = prepared_blocks_b,
            .panel_blocks_b = panel_blocks_b,
            .panel8_blocks_b = panel8_blocks_b,
            .panel16_blocks_b = panel16_blocks_b,
            .bias_b = bias_b,
            .prepared_blocks_c = prepared_blocks_c,
            .panel_blocks_c = panel_blocks_c,
            .panel8_blocks_c = panel8_blocks_c,
            .panel16_blocks_c = panel16_blocks_c,
            .packed_qkv_panel16_blocks = packed_qkv_panel16_blocks,
            .packed_qkv_panel16_mr2 = packed_qkv_panel16_mr2,
            .packed_qkv_panel16_mr8 = use_packed_qkv_panel16_mr8,
            .output_a = output_a[chunk.start * out_dim .. chunk.end * out_dim],
            .output_b = output_b[chunk.start * out_dim .. chunk.end * out_dim],
            .bias_c = bias_c,
            .output_c = output_c[chunk.start * out_dim .. chunk.end * out_dim],
            .rows = chunk.end - chunk.start,
            .in_dim = in_dim,
            .out_dim = out_dim,
            .out_start = 0,
            .out_end = out_dim,
            .q6 = q6,
            .known = known,
        };
        jobs[i] = .{ .fn_ptr = kPreparedQ8KActivationTripleWorkerJob, .ctx = @ptrCast(&contexts[i]) };
    }
    try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
    return true;
}

fn linearKPreparedQ8KActivationTripleDispatch(
    q6: bool,
    io: ?std.Io,
    q_input: []const u8,
    prepared_blocks_a: []const u8,
    panel_blocks_a: ?[]const u8,
    panel8_blocks_a: ?[]const u8,
    panel16_blocks_a: ?[]const u8,
    bias_a: ?[]const f32,
    output_a: []f32,
    prepared_blocks_b: []const u8,
    panel_blocks_b: ?[]const u8,
    panel8_blocks_b: ?[]const u8,
    panel16_blocks_b: ?[]const u8,
    bias_b: ?[]const f32,
    output_b: []f32,
    prepared_blocks_c: []const u8,
    panel_blocks_c: ?[]const u8,
    panel8_blocks_c: ?[]const u8,
    panel16_blocks_c: ?[]const u8,
    packed_qkv_panel16_blocks: ?[]const u8,
    packed_qkv_panel16_mr2: bool,
    bias_c: ?[]const f32,
    output_c: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    known: ?gguf_tensor_types.KnownTensorType,
) !void {
    if (try linearKPreparedQ8KActivationTripleParallel(q6, io, q_input, prepared_blocks_a, panel_blocks_a, panel8_blocks_a, panel16_blocks_a, bias_a, output_a, prepared_blocks_b, panel_blocks_b, panel8_blocks_b, panel16_blocks_b, bias_b, output_b, prepared_blocks_c, panel_blocks_c, panel8_blocks_c, panel16_blocks_c, packed_qkv_panel16_blocks, packed_qkv_panel16_mr2, bias_c, output_c, rows, in_dim, out_dim, known)) return;
    if (q6 and shouldUseQ6KGroupedTriple(rows)) {
        linearQ6KPreparedQ8KActivationGroupedRange(3, q_input, .{ prepared_blocks_a, prepared_blocks_b, prepared_blocks_c }, .{ panel_blocks_a, panel_blocks_b, panel_blocks_c }, .{ panel8_blocks_a, panel8_blocks_b, panel8_blocks_c }, .{ panel16_blocks_a, panel16_blocks_b, panel16_blocks_c }, .{ output_a, output_b, output_c }, rows, in_dim, out_dim, 0, out_dim);
        return;
    }
    if (!q6 and useQ4Q5Panel16DirectForShape(rows, out_dim, in_dim / 256, panel16_blocks_a != null and panel16_blocks_b != null and panel16_blocks_c != null)) {
        if (panel16_blocks_a) |panel16_a| {
            if (panel16_blocks_b) |panel16_b| {
                if (panel16_blocks_c) |panel16_c| {
                    if (q4q5FusedTripleDirectEnabled() or packed_qkv_panel16_blocks != null) {
                        const row_blocks = in_dim / 256;
                        const use_packed_qkv_panel16_mr8 = if (known) |value| packed_qkv_panel16_blocks != null and useQ4Q5Panel16MR8DirectForShape(rows, out_dim, row_blocks, value, true) and row_blocks <= q8_k_prepared_sum_stack_max_row_blocks else false;
                        linearQ4Q5KPreparedQ8KActivationTriplePanel16Range(q_input, prepared_blocks_a, panel16_a, bias_a, output_a, prepared_blocks_b, panel16_b, bias_b, output_b, prepared_blocks_c, panel16_c, bias_c, output_c, packed_qkv_panel16_blocks, packed_qkv_panel16_mr2, use_packed_qkv_panel16_mr8, rows, in_dim, out_dim, 0, out_dim);
                        return;
                    }
                    kPreparedQ8KActivationApply(false, q_input, prepared_blocks_a, panel_blocks_a, panel8_blocks_a, panel16_a, output_a, rows, in_dim, out_dim, 0, out_dim, known);
                    kPreparedQ8KActivationApply(false, q_input, prepared_blocks_b, panel_blocks_b, panel8_blocks_b, panel16_b, output_b, rows, in_dim, out_dim, 0, out_dim, known);
                    kPreparedQ8KActivationApply(false, q_input, prepared_blocks_c, panel_blocks_c, panel8_blocks_c, panel16_c, output_c, rows, in_dim, out_dim, 0, out_dim, known);
                    return;
                }
            }
        }
    }
    if (!q6) {
        if (panel8_blocks_a) |panel8_a| {
            if (panel8_blocks_b) |panel8_b| {
                if (panel8_blocks_c) |panel8_c| {
                    linearQ4Q5KPreparedQ8KActivationTriplePanel8Range(q_input, prepared_blocks_a, panel8_a, output_a, prepared_blocks_b, panel8_b, output_b, prepared_blocks_c, panel8_c, output_c, rows, in_dim, out_dim, 0, out_dim);
                    return;
                }
            }
        }
    }
    kPreparedQ8KActivationApply(q6, q_input, prepared_blocks_a, panel_blocks_a, panel8_blocks_a, panel16_blocks_a, output_a, rows, in_dim, out_dim, 0, out_dim, known);
    kPreparedQ8KActivationApply(q6, q_input, prepared_blocks_b, panel_blocks_b, panel8_blocks_b, panel16_blocks_b, output_b, rows, in_dim, out_dim, 0, out_dim, known);
    kPreparedQ8KActivationApply(q6, q_input, prepared_blocks_c, panel_blocks_c, panel8_blocks_c, panel16_blocks_c, output_c, rows, in_dim, out_dim, 0, out_dim, known);
}

fn validatePreparedQ8_1ActivationBlocks(
    prepared_blocks: []const u8,
    prepared_panel_blocks: ?[]const u8,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !usize {
    _ = rows;
    const values_per_block: usize = 32;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    if (prepared_blocks.len != out_dim * row_blocks * prepared_q8_0_block_bytes) return error.InvalidQuantizedDataSize;
    if (prepared_panel_blocks) |blocks| {
        if (blocks.len != preparedQ8_0PanelByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;
    }
    return row_blocks;
}

fn legacyActivationInputSums(q_values: []const u8, input_sums: []i32, rows: usize, row_blocks: usize) void {
    const values_per_block: usize = 32;
    std.debug.assert(q_values.len == rows * row_blocks * values_per_block);
    std.debug.assert(input_sums.len == rows * row_blocks);
    for (0..rows) |r| {
        for (0..row_blocks) |block_idx| {
            const qx = q_values[(r * row_blocks + block_idx) * values_per_block ..][0..values_per_block];
            var sum: i32 = 0;
            for (qx) |raw| {
                const q: i8 = @bitCast(raw);
                sum += q;
            }
            input_sums[r * row_blocks + block_idx] = sum;
        }
    }
}

inline fn preparedLegacyScale(block: []const u8) f32 {
    return readF32Le(block[prepared_legacy_scale_offset..][0..4]);
}

inline fn preparedLegacyMin(block: []const u8) f32 {
    return readF32Le(block[prepared_legacy_min_offset..][0..4]);
}

inline fn preparedLegacyValues(block: []const u8) *const [32]u8 {
    return block[prepared_legacy_values_offset..][0..prepared_legacy_values_bytes];
}

fn validatePreparedLegacyActivationBlocks(
    prepared_blocks: []const u8,
    prepared_panel_blocks: ?[]const u8,
    in_dim: usize,
    out_dim: usize,
) !usize {
    const values_per_block: usize = 32;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    if (prepared_blocks.len != out_dim * row_blocks * prepared_legacy_block_bytes) return error.InvalidQuantizedDataSize;
    if (prepared_panel_blocks) |blocks| {
        if (blocks.len != preparedLegacyPanelByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;
    }
    return row_blocks;
}

inline fn preparedLegacyPanelBlock(
    panel_blocks: ?[]const u8,
    prepared_blocks: []const u8,
    row_blocks: usize,
    row_stride: usize,
    out_col: usize,
    block_idx: usize,
    lane: usize,
) []const u8 {
    if (panel_blocks) |panel| {
        const panel_idx = out_col / prepared_q8_0_panel_nr;
        const panel_base = (panel_idx * row_blocks + block_idx) * prepared_q8_0_panel_nr * prepared_legacy_block_bytes;
        return panel[panel_base + lane * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
    }
    return prepared_blocks[(out_col + lane) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
}

inline fn dotLegacyPreparedQ8_0Block(
    qx: *const [32]u8,
    input_scale: f32,
    input_sum_f: f32,
    prepared_block: []const u8,
) f32 {
    const dot = dotI8I8Block(qx, preparedLegacyValues(prepared_block));
    return input_scale * (preparedLegacyScale(prepared_block) * @as(f32, @floatFromInt(dot)) + preparedLegacyMin(prepared_block) * input_sum_f);
}

inline fn addLegacyPreparedQ8_0Block4MR4(
    qx0: *const [32]u8,
    qx1: *const [32]u8,
    qx2: *const [32]u8,
    qx3: *const [32]u8,
    input_scales: *const [4]f32,
    input_sums: *const [4]f32,
    w0: []const u8,
    w1: []const u8,
    w2: []const u8,
    w3: []const u8,
    acc: *[4][4]f32,
) void {
    const dots = dotI8I8Block4MR4(qx0, qx1, qx2, qx3, preparedLegacyValues(w0), preparedLegacyValues(w1), preparedLegacyValues(w2), preparedLegacyValues(w3));
    const weight_scales = [_]f32{
        preparedLegacyScale(w0),
        preparedLegacyScale(w1),
        preparedLegacyScale(w2),
        preparedLegacyScale(w3),
    };
    const weight_mins = [_]f32{
        preparedLegacyMin(w0),
        preparedLegacyMin(w1),
        preparedLegacyMin(w2),
        preparedLegacyMin(w3),
    };
    inline for (0..4) |rr| {
        inline for (0..4) |cc| {
            acc.*[rr][cc] += input_scales[rr] * (weight_scales[cc] * @as(f32, @floatFromInt(dots[rr * 4 + cc])) + weight_mins[cc] * input_sums[rr]);
        }
    }
}

fn legacyPreparedActivationPairApply(
    q_values: []const u8,
    input_scales: []const f32,
    input_sums: []const i32,
    prepared_blocks_a: []const u8,
    prepared_panel_blocks_a: ?[]const u8,
    prepared_blocks_b: []const u8,
    prepared_panel_blocks_b: ?[]const u8,
    output_a: []f32,
    output_b: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    use_mr4: bool,
) void {
    const values_per_block: usize = 32;
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * prepared_legacy_block_bytes;

    var r: usize = 0;
    if (use_mr4 and out_start == 0 and out_end == out_dim and (out_dim % prepared_q8_0_panel_nr) == 0) {
        while (r + 4 <= rows) : (r += 4) {
            const out_row_a0 = output_a[r * out_dim ..][0..out_dim];
            const out_row_a1 = output_a[(r + 1) * out_dim ..][0..out_dim];
            const out_row_a2 = output_a[(r + 2) * out_dim ..][0..out_dim];
            const out_row_a3 = output_a[(r + 3) * out_dim ..][0..out_dim];
            const out_row_b0 = output_b[r * out_dim ..][0..out_dim];
            const out_row_b1 = output_b[(r + 1) * out_dim ..][0..out_dim];
            const out_row_b2 = output_b[(r + 2) * out_dim ..][0..out_dim];
            const out_row_b3 = output_b[(r + 3) * out_dim ..][0..out_dim];
            const input_q_row0 = q_values[r * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
            const input_q_row1 = q_values[(r + 1) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
            const input_q_row2 = q_values[(r + 2) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
            const input_q_row3 = q_values[(r + 3) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
            const input_scale_row0 = input_scales[r * row_blocks ..][0..row_blocks];
            const input_scale_row1 = input_scales[(r + 1) * row_blocks ..][0..row_blocks];
            const input_scale_row2 = input_scales[(r + 2) * row_blocks ..][0..row_blocks];
            const input_scale_row3 = input_scales[(r + 3) * row_blocks ..][0..row_blocks];
            const input_sum_row0 = input_sums[r * row_blocks ..][0..row_blocks];
            const input_sum_row1 = input_sums[(r + 1) * row_blocks ..][0..row_blocks];
            const input_sum_row2 = input_sums[(r + 2) * row_blocks ..][0..row_blocks];
            const input_sum_row3 = input_sums[(r + 3) * row_blocks ..][0..row_blocks];
            var o: usize = 0;
            while (o + prepared_q8_0_panel_nr <= out_dim) : (o += prepared_q8_0_panel_nr) {
                var acc_a = [_][4]f32{[_]f32{0.0} ** 4} ** 4;
                var acc_b = [_][4]f32{[_]f32{0.0} ** 4} ** 4;
                for (0..row_blocks) |block_idx| {
                    const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..values_per_block];
                    const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..values_per_block];
                    const qx2: *const [32]u8 = input_q_row2[block_idx * values_per_block ..][0..values_per_block];
                    const qx3: *const [32]u8 = input_q_row3[block_idx * values_per_block ..][0..values_per_block];
                    const input_scales_for_block = [_]f32{
                        input_scale_row0[block_idx],
                        input_scale_row1[block_idx],
                        input_scale_row2[block_idx],
                        input_scale_row3[block_idx],
                    };
                    const input_sums_for_block = [_]f32{
                        @as(f32, @floatFromInt(input_sum_row0[block_idx])),
                        @as(f32, @floatFromInt(input_sum_row1[block_idx])),
                        @as(f32, @floatFromInt(input_sum_row2[block_idx])),
                        @as(f32, @floatFromInt(input_sum_row3[block_idx])),
                    };
                    const a0 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 0);
                    const a1 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 1);
                    const a2 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 2);
                    const a3 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 3);
                    addLegacyPreparedQ8_0Block4MR4(qx0, qx1, qx2, qx3, &input_scales_for_block, &input_sums_for_block, a0, a1, a2, a3, &acc_a);
                    const b0 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 0);
                    const b1 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 1);
                    const b2 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 2);
                    const b3 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 3);
                    addLegacyPreparedQ8_0Block4MR4(qx0, qx1, qx2, qx3, &input_scales_for_block, &input_sums_for_block, b0, b1, b2, b3, &acc_b);
                }
                inline for (0..4) |lane| {
                    out_row_a0[o + lane] = acc_a[0][lane];
                    out_row_a1[o + lane] = acc_a[1][lane];
                    out_row_a2[o + lane] = acc_a[2][lane];
                    out_row_a3[o + lane] = acc_a[3][lane];
                    out_row_b0[o + lane] = acc_b[0][lane];
                    out_row_b1[o + lane] = acc_b[1][lane];
                    out_row_b2[o + lane] = acc_b[2][lane];
                    out_row_b3[o + lane] = acc_b[3][lane];
                }
            }
        }
    }

    while (r < rows) : (r += 1) {
        const out_row_a = output_a[r * out_dim ..][0..out_dim];
        const out_row_b = output_b[r * out_dim ..][0..out_dim];
        const input_q_row = q_values[r * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_scale_row = input_scales[r * row_blocks ..][0..row_blocks];
        const input_sum_row = input_sums[r * row_blocks ..][0..row_blocks];

        var o = out_start;
        while (o < out_end and (o % prepared_q8_0_panel_nr) != 0) : (o += 1) {
            var acc_a: f32 = 0.0;
            var acc_b: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..values_per_block];
                const input_scale = input_scale_row[block_idx];
                const input_sum_f = @as(f32, @floatFromInt(input_sum_row[block_idx]));
                acc_a += dotLegacyPreparedQ8_0Block(qx, input_scale, input_sum_f, prepared_blocks_a[o * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes]);
                acc_b += dotLegacyPreparedQ8_0Block(qx, input_scale, input_sum_f, prepared_blocks_b[o * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes]);
            }
            out_row_a[o] = acc_a;
            out_row_b[o] = acc_b;
        }

        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc_a0: f32 = 0.0;
            var acc_a1: f32 = 0.0;
            var acc_a2: f32 = 0.0;
            var acc_a3: f32 = 0.0;
            var acc_b0: f32 = 0.0;
            var acc_b1: f32 = 0.0;
            var acc_b2: f32 = 0.0;
            var acc_b3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..values_per_block];
                const input_scale = input_scale_row[block_idx];
                const input_sum_f = @as(f32, @floatFromInt(input_sum_row[block_idx]));
                const a0 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 0);
                const a1 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 1);
                const a2 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 2);
                const a3 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 3);
                const b0 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 0);
                const b1 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 1);
                const b2 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 2);
                const b3 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 3);
                const dots_a = dotI8I8Block4(qx, preparedLegacyValues(a0), preparedLegacyValues(a1), preparedLegacyValues(a2), preparedLegacyValues(a3));
                const dots_b = dotI8I8Block4(qx, preparedLegacyValues(b0), preparedLegacyValues(b1), preparedLegacyValues(b2), preparedLegacyValues(b3));
                acc_a0 += input_scale * (preparedLegacyScale(a0) * @as(f32, @floatFromInt(dots_a[0])) + preparedLegacyMin(a0) * input_sum_f);
                acc_a1 += input_scale * (preparedLegacyScale(a1) * @as(f32, @floatFromInt(dots_a[1])) + preparedLegacyMin(a1) * input_sum_f);
                acc_a2 += input_scale * (preparedLegacyScale(a2) * @as(f32, @floatFromInt(dots_a[2])) + preparedLegacyMin(a2) * input_sum_f);
                acc_a3 += input_scale * (preparedLegacyScale(a3) * @as(f32, @floatFromInt(dots_a[3])) + preparedLegacyMin(a3) * input_sum_f);
                acc_b0 += input_scale * (preparedLegacyScale(b0) * @as(f32, @floatFromInt(dots_b[0])) + preparedLegacyMin(b0) * input_sum_f);
                acc_b1 += input_scale * (preparedLegacyScale(b1) * @as(f32, @floatFromInt(dots_b[1])) + preparedLegacyMin(b1) * input_sum_f);
                acc_b2 += input_scale * (preparedLegacyScale(b2) * @as(f32, @floatFromInt(dots_b[2])) + preparedLegacyMin(b2) * input_sum_f);
                acc_b3 += input_scale * (preparedLegacyScale(b3) * @as(f32, @floatFromInt(dots_b[3])) + preparedLegacyMin(b3) * input_sum_f);
            }
            out_row_a[o] = acc_a0;
            out_row_a[o + 1] = acc_a1;
            out_row_a[o + 2] = acc_a2;
            out_row_a[o + 3] = acc_a3;
            out_row_b[o] = acc_b0;
            out_row_b[o + 1] = acc_b1;
            out_row_b[o + 2] = acc_b2;
            out_row_b[o + 3] = acc_b3;
        }

        while (o < out_end) : (o += 1) {
            var acc_a: f32 = 0.0;
            var acc_b: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..values_per_block];
                const input_scale = input_scale_row[block_idx];
                const input_sum_f = @as(f32, @floatFromInt(input_sum_row[block_idx]));
                acc_a += dotLegacyPreparedQ8_0Block(qx, input_scale, input_sum_f, prepared_blocks_a[o * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes]);
                acc_b += dotLegacyPreparedQ8_0Block(qx, input_scale, input_sum_f, prepared_blocks_b[o * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes]);
            }
            out_row_a[o] = acc_a;
            out_row_b[o] = acc_b;
        }
    }
}

fn legacyPreparedActivationTripleApply(
    q_values: []const u8,
    input_scales: []const f32,
    input_sums: []const i32,
    prepared_blocks_a: []const u8,
    prepared_panel_blocks_a: ?[]const u8,
    prepared_blocks_b: []const u8,
    prepared_panel_blocks_b: ?[]const u8,
    prepared_blocks_c: []const u8,
    prepared_panel_blocks_c: ?[]const u8,
    bias_a: ?[]const f32,
    bias_b: ?[]const f32,
    bias_c: ?[]const f32,
    output_a: []f32,
    output_b: []f32,
    output_c: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    use_mr4: bool,
) void {
    const values_per_block: usize = 32;
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * prepared_legacy_block_bytes;

    var r: usize = 0;
    if (use_mr4 and out_start == 0 and out_end == out_dim and (out_dim % prepared_q8_0_panel_nr) == 0) {
        while (r + 4 <= rows) : (r += 4) {
            const out_row_a0 = output_a[r * out_dim ..][0..out_dim];
            const out_row_a1 = output_a[(r + 1) * out_dim ..][0..out_dim];
            const out_row_a2 = output_a[(r + 2) * out_dim ..][0..out_dim];
            const out_row_a3 = output_a[(r + 3) * out_dim ..][0..out_dim];
            const out_row_b0 = output_b[r * out_dim ..][0..out_dim];
            const out_row_b1 = output_b[(r + 1) * out_dim ..][0..out_dim];
            const out_row_b2 = output_b[(r + 2) * out_dim ..][0..out_dim];
            const out_row_b3 = output_b[(r + 3) * out_dim ..][0..out_dim];
            const out_row_c0 = output_c[r * out_dim ..][0..out_dim];
            const out_row_c1 = output_c[(r + 1) * out_dim ..][0..out_dim];
            const out_row_c2 = output_c[(r + 2) * out_dim ..][0..out_dim];
            const out_row_c3 = output_c[(r + 3) * out_dim ..][0..out_dim];
            const input_q_row0 = q_values[r * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
            const input_q_row1 = q_values[(r + 1) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
            const input_q_row2 = q_values[(r + 2) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
            const input_q_row3 = q_values[(r + 3) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
            const input_scale_row0 = input_scales[r * row_blocks ..][0..row_blocks];
            const input_scale_row1 = input_scales[(r + 1) * row_blocks ..][0..row_blocks];
            const input_scale_row2 = input_scales[(r + 2) * row_blocks ..][0..row_blocks];
            const input_scale_row3 = input_scales[(r + 3) * row_blocks ..][0..row_blocks];
            const input_sum_row0 = input_sums[r * row_blocks ..][0..row_blocks];
            const input_sum_row1 = input_sums[(r + 1) * row_blocks ..][0..row_blocks];
            const input_sum_row2 = input_sums[(r + 2) * row_blocks ..][0..row_blocks];
            const input_sum_row3 = input_sums[(r + 3) * row_blocks ..][0..row_blocks];
            var o: usize = 0;
            while (o + prepared_q8_0_panel_nr <= out_dim) : (o += prepared_q8_0_panel_nr) {
                var acc_a: [4][4]f32 = undefined;
                var acc_b: [4][4]f32 = undefined;
                var acc_c: [4][4]f32 = undefined;
                inline for (0..4) |rr| {
                    inline for (0..4) |cc| {
                        acc_a[rr][cc] = optionalLinearBiasAt(bias_a, o + cc);
                        acc_b[rr][cc] = optionalLinearBiasAt(bias_b, o + cc);
                        acc_c[rr][cc] = optionalLinearBiasAt(bias_c, o + cc);
                    }
                }
                for (0..row_blocks) |block_idx| {
                    const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..values_per_block];
                    const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..values_per_block];
                    const qx2: *const [32]u8 = input_q_row2[block_idx * values_per_block ..][0..values_per_block];
                    const qx3: *const [32]u8 = input_q_row3[block_idx * values_per_block ..][0..values_per_block];
                    const input_scales_for_block = [_]f32{
                        input_scale_row0[block_idx],
                        input_scale_row1[block_idx],
                        input_scale_row2[block_idx],
                        input_scale_row3[block_idx],
                    };
                    const input_sums_for_block = [_]f32{
                        @as(f32, @floatFromInt(input_sum_row0[block_idx])),
                        @as(f32, @floatFromInt(input_sum_row1[block_idx])),
                        @as(f32, @floatFromInt(input_sum_row2[block_idx])),
                        @as(f32, @floatFromInt(input_sum_row3[block_idx])),
                    };
                    const a0 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 0);
                    const a1 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 1);
                    const a2 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 2);
                    const a3 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 3);
                    addLegacyPreparedQ8_0Block4MR4(qx0, qx1, qx2, qx3, &input_scales_for_block, &input_sums_for_block, a0, a1, a2, a3, &acc_a);
                    const b0 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 0);
                    const b1 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 1);
                    const b2 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 2);
                    const b3 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 3);
                    addLegacyPreparedQ8_0Block4MR4(qx0, qx1, qx2, qx3, &input_scales_for_block, &input_sums_for_block, b0, b1, b2, b3, &acc_b);
                    const c0 = preparedLegacyPanelBlock(prepared_panel_blocks_c, prepared_blocks_c, row_blocks, row_stride, o, block_idx, 0);
                    const c1 = preparedLegacyPanelBlock(prepared_panel_blocks_c, prepared_blocks_c, row_blocks, row_stride, o, block_idx, 1);
                    const c2 = preparedLegacyPanelBlock(prepared_panel_blocks_c, prepared_blocks_c, row_blocks, row_stride, o, block_idx, 2);
                    const c3 = preparedLegacyPanelBlock(prepared_panel_blocks_c, prepared_blocks_c, row_blocks, row_stride, o, block_idx, 3);
                    addLegacyPreparedQ8_0Block4MR4(qx0, qx1, qx2, qx3, &input_scales_for_block, &input_sums_for_block, c0, c1, c2, c3, &acc_c);
                }
                inline for (0..4) |lane| {
                    out_row_a0[o + lane] = acc_a[0][lane];
                    out_row_a1[o + lane] = acc_a[1][lane];
                    out_row_a2[o + lane] = acc_a[2][lane];
                    out_row_a3[o + lane] = acc_a[3][lane];
                    out_row_b0[o + lane] = acc_b[0][lane];
                    out_row_b1[o + lane] = acc_b[1][lane];
                    out_row_b2[o + lane] = acc_b[2][lane];
                    out_row_b3[o + lane] = acc_b[3][lane];
                    out_row_c0[o + lane] = acc_c[0][lane];
                    out_row_c1[o + lane] = acc_c[1][lane];
                    out_row_c2[o + lane] = acc_c[2][lane];
                    out_row_c3[o + lane] = acc_c[3][lane];
                }
            }
        }
    }

    while (r < rows) : (r += 1) {
        const out_row_a = output_a[r * out_dim ..][0..out_dim];
        const out_row_b = output_b[r * out_dim ..][0..out_dim];
        const out_row_c = output_c[r * out_dim ..][0..out_dim];
        const input_q_row = q_values[r * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_scale_row = input_scales[r * row_blocks ..][0..row_blocks];
        const input_sum_row = input_sums[r * row_blocks ..][0..row_blocks];

        var o = out_start;
        while (o < out_end and (o % prepared_q8_0_panel_nr) != 0) : (o += 1) {
            var acc_a = optionalLinearBiasAt(bias_a, o);
            var acc_b = optionalLinearBiasAt(bias_b, o);
            var acc_c = optionalLinearBiasAt(bias_c, o);
            for (0..row_blocks) |block_idx| {
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..values_per_block];
                const input_scale = input_scale_row[block_idx];
                const input_sum_f = @as(f32, @floatFromInt(input_sum_row[block_idx]));
                acc_a += dotLegacyPreparedQ8_0Block(qx, input_scale, input_sum_f, prepared_blocks_a[o * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes]);
                acc_b += dotLegacyPreparedQ8_0Block(qx, input_scale, input_sum_f, prepared_blocks_b[o * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes]);
                acc_c += dotLegacyPreparedQ8_0Block(qx, input_scale, input_sum_f, prepared_blocks_c[o * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes]);
            }
            out_row_a[o] = acc_a;
            out_row_b[o] = acc_b;
            out_row_c[o] = acc_c;
        }

        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc_a0 = optionalLinearBiasAt(bias_a, o);
            var acc_a1 = optionalLinearBiasAt(bias_a, o + 1);
            var acc_a2 = optionalLinearBiasAt(bias_a, o + 2);
            var acc_a3 = optionalLinearBiasAt(bias_a, o + 3);
            var acc_b0 = optionalLinearBiasAt(bias_b, o);
            var acc_b1 = optionalLinearBiasAt(bias_b, o + 1);
            var acc_b2 = optionalLinearBiasAt(bias_b, o + 2);
            var acc_b3 = optionalLinearBiasAt(bias_b, o + 3);
            var acc_c0 = optionalLinearBiasAt(bias_c, o);
            var acc_c1 = optionalLinearBiasAt(bias_c, o + 1);
            var acc_c2 = optionalLinearBiasAt(bias_c, o + 2);
            var acc_c3 = optionalLinearBiasAt(bias_c, o + 3);
            for (0..row_blocks) |block_idx| {
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..values_per_block];
                const input_scale = input_scale_row[block_idx];
                const input_sum_f = @as(f32, @floatFromInt(input_sum_row[block_idx]));
                const a0 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 0);
                const a1 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 1);
                const a2 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 2);
                const a3 = preparedLegacyPanelBlock(prepared_panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 3);
                const b0 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 0);
                const b1 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 1);
                const b2 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 2);
                const b3 = preparedLegacyPanelBlock(prepared_panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 3);
                const c0 = preparedLegacyPanelBlock(prepared_panel_blocks_c, prepared_blocks_c, row_blocks, row_stride, o, block_idx, 0);
                const c1 = preparedLegacyPanelBlock(prepared_panel_blocks_c, prepared_blocks_c, row_blocks, row_stride, o, block_idx, 1);
                const c2 = preparedLegacyPanelBlock(prepared_panel_blocks_c, prepared_blocks_c, row_blocks, row_stride, o, block_idx, 2);
                const c3 = preparedLegacyPanelBlock(prepared_panel_blocks_c, prepared_blocks_c, row_blocks, row_stride, o, block_idx, 3);
                const dots_a = dotI8I8Block4(qx, preparedLegacyValues(a0), preparedLegacyValues(a1), preparedLegacyValues(a2), preparedLegacyValues(a3));
                const dots_b = dotI8I8Block4(qx, preparedLegacyValues(b0), preparedLegacyValues(b1), preparedLegacyValues(b2), preparedLegacyValues(b3));
                const dots_c = dotI8I8Block4(qx, preparedLegacyValues(c0), preparedLegacyValues(c1), preparedLegacyValues(c2), preparedLegacyValues(c3));
                acc_a0 += input_scale * (preparedLegacyScale(a0) * @as(f32, @floatFromInt(dots_a[0])) + preparedLegacyMin(a0) * input_sum_f);
                acc_a1 += input_scale * (preparedLegacyScale(a1) * @as(f32, @floatFromInt(dots_a[1])) + preparedLegacyMin(a1) * input_sum_f);
                acc_a2 += input_scale * (preparedLegacyScale(a2) * @as(f32, @floatFromInt(dots_a[2])) + preparedLegacyMin(a2) * input_sum_f);
                acc_a3 += input_scale * (preparedLegacyScale(a3) * @as(f32, @floatFromInt(dots_a[3])) + preparedLegacyMin(a3) * input_sum_f);
                acc_b0 += input_scale * (preparedLegacyScale(b0) * @as(f32, @floatFromInt(dots_b[0])) + preparedLegacyMin(b0) * input_sum_f);
                acc_b1 += input_scale * (preparedLegacyScale(b1) * @as(f32, @floatFromInt(dots_b[1])) + preparedLegacyMin(b1) * input_sum_f);
                acc_b2 += input_scale * (preparedLegacyScale(b2) * @as(f32, @floatFromInt(dots_b[2])) + preparedLegacyMin(b2) * input_sum_f);
                acc_b3 += input_scale * (preparedLegacyScale(b3) * @as(f32, @floatFromInt(dots_b[3])) + preparedLegacyMin(b3) * input_sum_f);
                acc_c0 += input_scale * (preparedLegacyScale(c0) * @as(f32, @floatFromInt(dots_c[0])) + preparedLegacyMin(c0) * input_sum_f);
                acc_c1 += input_scale * (preparedLegacyScale(c1) * @as(f32, @floatFromInt(dots_c[1])) + preparedLegacyMin(c1) * input_sum_f);
                acc_c2 += input_scale * (preparedLegacyScale(c2) * @as(f32, @floatFromInt(dots_c[2])) + preparedLegacyMin(c2) * input_sum_f);
                acc_c3 += input_scale * (preparedLegacyScale(c3) * @as(f32, @floatFromInt(dots_c[3])) + preparedLegacyMin(c3) * input_sum_f);
            }
            out_row_a[o] = acc_a0;
            out_row_a[o + 1] = acc_a1;
            out_row_a[o + 2] = acc_a2;
            out_row_a[o + 3] = acc_a3;
            out_row_b[o] = acc_b0;
            out_row_b[o + 1] = acc_b1;
            out_row_b[o + 2] = acc_b2;
            out_row_b[o + 3] = acc_b3;
            out_row_c[o] = acc_c0;
            out_row_c[o + 1] = acc_c1;
            out_row_c[o + 2] = acc_c2;
            out_row_c[o + 3] = acc_c3;
        }

        while (o < out_end) : (o += 1) {
            var acc_a = optionalLinearBiasAt(bias_a, o);
            var acc_b = optionalLinearBiasAt(bias_b, o);
            var acc_c = optionalLinearBiasAt(bias_c, o);
            for (0..row_blocks) |block_idx| {
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..values_per_block];
                const input_scale = input_scale_row[block_idx];
                const input_sum_f = @as(f32, @floatFromInt(input_sum_row[block_idx]));
                acc_a += dotLegacyPreparedQ8_0Block(qx, input_scale, input_sum_f, prepared_blocks_a[o * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes]);
                acc_b += dotLegacyPreparedQ8_0Block(qx, input_scale, input_sum_f, prepared_blocks_b[o * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes]);
                acc_c += dotLegacyPreparedQ8_0Block(qx, input_scale, input_sum_f, prepared_blocks_c[o * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes]);
            }
            out_row_a[o] = acc_a;
            out_row_b[o] = acc_b;
            out_row_c[o] = acc_c;
        }
    }
}

fn legacyPreparedActivationApply(
    q_values: []const u8,
    input_scales: []const f32,
    input_sums: []const i32,
    prepared_blocks: []const u8,
    prepared_panel_blocks: ?[]const u8,
    bias: ?[]const f32,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
    use_mr4: bool,
) void {
    if (out_start == 0 and out_end == out_dim) {
        legacyPreparedActivationApplyFullMR2(q_values, input_scales, input_sums, prepared_blocks, prepared_panel_blocks, bias, output, rows, in_dim, out_dim, use_mr4);
        return;
    }

    const values_per_block: usize = 32;
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * prepared_legacy_block_bytes;

    for (0..rows) |r| {
        const out_row = output[r * out_dim ..][0..out_dim];
        const input_q_row = q_values[r * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_scale_row = input_scales[r * row_blocks ..][0..row_blocks];
        const input_sum_row = input_sums[r * row_blocks ..][0..row_blocks];
        var o = out_start;
        while (o < out_end and (o % prepared_q8_0_panel_nr) != 0) : (o += 1) {
            var acc = optionalLinearBiasAt(bias, o);
            const w_off = o * row_stride;
            for (0..row_blocks) |block_idx| {
                const block = prepared_blocks[w_off + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const input_scale = input_scale_row[block_idx];
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..values_per_block];
                const dot = dotI8I8Block(qx, preparedLegacyValues(block));
                acc += input_scale * (preparedLegacyScale(block) * @as(f32, @floatFromInt(dot)) + preparedLegacyMin(block) * @as(f32, @floatFromInt(input_sum_row[block_idx])));
            }
            out_row[o] = acc;
        }
        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc0 = optionalLinearBiasAt(bias, o);
            var acc1 = optionalLinearBiasAt(bias, o + 1);
            var acc2 = optionalLinearBiasAt(bias, o + 2);
            var acc3 = optionalLinearBiasAt(bias, o + 3);
            for (0..row_blocks) |block_idx| {
                const panel_blocks = if (prepared_panel_blocks) |panel| blk: {
                    const panel_off = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * prepared_legacy_block_bytes;
                    break :blk panel[panel_off..][0 .. prepared_q8_0_panel_nr * prepared_legacy_block_bytes];
                } else null;
                const w0 = if (panel_blocks) |panel| panel[0..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 0) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const w1 = if (panel_blocks) |panel| panel[prepared_legacy_block_bytes..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 1) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const w2 = if (panel_blocks) |panel| panel[2 * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 2) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const w3 = if (panel_blocks) |panel| panel[3 * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 3) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..values_per_block];
                const dots = dotI8I8Block4(qx, preparedLegacyValues(w0), preparedLegacyValues(w1), preparedLegacyValues(w2), preparedLegacyValues(w3));
                const input_scale = input_scale_row[block_idx];
                if (!use_mr4) {
                    acc0 += input_scale * preparedLegacyScale(w0) * @as(f32, @floatFromInt(dots[0]));
                    acc1 += input_scale * preparedLegacyScale(w1) * @as(f32, @floatFromInt(dots[1]));
                    acc2 += input_scale * preparedLegacyScale(w2) * @as(f32, @floatFromInt(dots[2]));
                    acc3 += input_scale * preparedLegacyScale(w3) * @as(f32, @floatFromInt(dots[3]));
                } else {
                    const input_sum_f = @as(f32, @floatFromInt(input_sum_row[block_idx]));
                    acc0 += input_scale * (preparedLegacyScale(w0) * @as(f32, @floatFromInt(dots[0])) + preparedLegacyMin(w0) * input_sum_f);
                    acc1 += input_scale * (preparedLegacyScale(w1) * @as(f32, @floatFromInt(dots[1])) + preparedLegacyMin(w1) * input_sum_f);
                    acc2 += input_scale * (preparedLegacyScale(w2) * @as(f32, @floatFromInt(dots[2])) + preparedLegacyMin(w2) * input_sum_f);
                    acc3 += input_scale * (preparedLegacyScale(w3) * @as(f32, @floatFromInt(dots[3])) + preparedLegacyMin(w3) * input_sum_f);
                }
            }
            out_row[o] = acc0;
            out_row[o + 1] = acc1;
            out_row[o + 2] = acc2;
            out_row[o + 3] = acc3;
        }
        while (o < out_end) : (o += 1) {
            var acc = optionalLinearBiasAt(bias, o);
            const w_off = o * row_stride;
            for (0..row_blocks) |block_idx| {
                const block = prepared_blocks[w_off + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const input_scale = input_scale_row[block_idx];
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..values_per_block];
                const dot = dotI8I8Block(qx, preparedLegacyValues(block));
                acc += input_scale * (preparedLegacyScale(block) * @as(f32, @floatFromInt(dot)) + preparedLegacyMin(block) * @as(f32, @floatFromInt(input_sum_row[block_idx])));
            }
            out_row[o] = acc;
        }
    }
}

fn legacyPreparedActivationApplyFullMR2(
    q_values: []const u8,
    input_scales: []const f32,
    input_sums: []const i32,
    prepared_blocks: []const u8,
    prepared_panel_blocks: ?[]const u8,
    bias: ?[]const f32,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    use_mr4: bool,
) void {
    const values_per_block: usize = 32;
    const row_blocks = in_dim / values_per_block;
    const row_stride = row_blocks * prepared_legacy_block_bytes;

    var r: usize = 0;
    if (use_mr4) {
        while (r + 4 <= rows) : (r += 4) {
            const out_row0 = output[r * out_dim ..][0..out_dim];
            const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
            const out_row2 = output[(r + 2) * out_dim ..][0..out_dim];
            const out_row3 = output[(r + 3) * out_dim ..][0..out_dim];
            const input_q_row0 = q_values[r * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
            const input_q_row1 = q_values[(r + 1) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
            const input_q_row2 = q_values[(r + 2) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
            const input_q_row3 = q_values[(r + 3) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
            const input_scale_row0 = input_scales[r * row_blocks ..][0..row_blocks];
            const input_scale_row1 = input_scales[(r + 1) * row_blocks ..][0..row_blocks];
            const input_scale_row2 = input_scales[(r + 2) * row_blocks ..][0..row_blocks];
            const input_scale_row3 = input_scales[(r + 3) * row_blocks ..][0..row_blocks];
            const input_sum_row0 = input_sums[r * row_blocks ..][0..row_blocks];
            const input_sum_row1 = input_sums[(r + 1) * row_blocks ..][0..row_blocks];
            const input_sum_row2 = input_sums[(r + 2) * row_blocks ..][0..row_blocks];
            const input_sum_row3 = input_sums[(r + 3) * row_blocks ..][0..row_blocks];
            var o: usize = 0;
            while (o + prepared_q8_0_panel_nr <= out_dim) : (o += prepared_q8_0_panel_nr) {
                var acc: [4][4]f32 = undefined;
                inline for (0..4) |lane| {
                    const value = optionalLinearBiasAt(bias, o + lane);
                    acc[0][lane] = value;
                    acc[1][lane] = value;
                    acc[2][lane] = value;
                    acc[3][lane] = value;
                }
                for (0..row_blocks) |block_idx| {
                    const panel_blocks = if (prepared_panel_blocks) |panel| blk: {
                        const panel_off = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * prepared_legacy_block_bytes;
                        break :blk panel[panel_off..][0 .. prepared_q8_0_panel_nr * prepared_legacy_block_bytes];
                    } else null;
                    const w0 = if (panel_blocks) |panel| panel[0..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 0) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                    const w1 = if (panel_blocks) |panel| panel[prepared_legacy_block_bytes..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 1) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                    const w2 = if (panel_blocks) |panel| panel[2 * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 2) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                    const w3 = if (panel_blocks) |panel| panel[3 * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 3) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                    const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..values_per_block];
                    const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..values_per_block];
                    const qx2: *const [32]u8 = input_q_row2[block_idx * values_per_block ..][0..values_per_block];
                    const qx3: *const [32]u8 = input_q_row3[block_idx * values_per_block ..][0..values_per_block];
                    const dots = dotI8I8Block4MR4(qx0, qx1, qx2, qx3, preparedLegacyValues(w0), preparedLegacyValues(w1), preparedLegacyValues(w2), preparedLegacyValues(w3));
                    const scales = [_]f32{ input_scale_row0[block_idx], input_scale_row1[block_idx], input_scale_row2[block_idx], input_scale_row3[block_idx] };
                    const sums = [_]f32{
                        @as(f32, @floatFromInt(input_sum_row0[block_idx])),
                        @as(f32, @floatFromInt(input_sum_row1[block_idx])),
                        @as(f32, @floatFromInt(input_sum_row2[block_idx])),
                        @as(f32, @floatFromInt(input_sum_row3[block_idx])),
                    };
                    const weight_scales = [_]f32{ preparedLegacyScale(w0), preparedLegacyScale(w1), preparedLegacyScale(w2), preparedLegacyScale(w3) };
                    const weight_mins = [_]f32{ preparedLegacyMin(w0), preparedLegacyMin(w1), preparedLegacyMin(w2), preparedLegacyMin(w3) };
                    inline for (0..4) |row_idx| {
                        inline for (0..4) |lane| {
                            acc[row_idx][lane] += scales[row_idx] * (weight_scales[lane] * @as(f32, @floatFromInt(dots[row_idx * 4 + lane])) + weight_mins[lane] * sums[row_idx]);
                        }
                    }
                }
                inline for (0..4) |lane| {
                    out_row0[o + lane] = acc[0][lane];
                    out_row1[o + lane] = acc[1][lane];
                    out_row2[o + lane] = acc[2][lane];
                    out_row3[o + lane] = acc[3][lane];
                }
            }
            while (o < out_dim) : (o += 1) {
                var acc0 = optionalLinearBiasAt(bias, o);
                var acc1 = acc0;
                var acc2 = acc0;
                var acc3 = acc0;
                const w_off = o * row_stride;
                for (0..row_blocks) |block_idx| {
                    const block = prepared_blocks[w_off + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                    const qw = preparedLegacyValues(block);
                    const weight_scale = preparedLegacyScale(block);
                    const weight_min = preparedLegacyMin(block);
                    const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..values_per_block];
                    const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..values_per_block];
                    const qx2: *const [32]u8 = input_q_row2[block_idx * values_per_block ..][0..values_per_block];
                    const qx3: *const [32]u8 = input_q_row3[block_idx * values_per_block ..][0..values_per_block];
                    acc0 += input_scale_row0[block_idx] * (weight_scale * @as(f32, @floatFromInt(dotI8I8Block(qx0, qw))) + weight_min * @as(f32, @floatFromInt(input_sum_row0[block_idx])));
                    acc1 += input_scale_row1[block_idx] * (weight_scale * @as(f32, @floatFromInt(dotI8I8Block(qx1, qw))) + weight_min * @as(f32, @floatFromInt(input_sum_row1[block_idx])));
                    acc2 += input_scale_row2[block_idx] * (weight_scale * @as(f32, @floatFromInt(dotI8I8Block(qx2, qw))) + weight_min * @as(f32, @floatFromInt(input_sum_row2[block_idx])));
                    acc3 += input_scale_row3[block_idx] * (weight_scale * @as(f32, @floatFromInt(dotI8I8Block(qx3, qw))) + weight_min * @as(f32, @floatFromInt(input_sum_row3[block_idx])));
                }
                out_row0[o] = acc0;
                out_row1[o] = acc1;
                out_row2[o] = acc2;
                out_row3[o] = acc3;
            }
        }
    }
    while (r + 1 < rows) : (r += 2) {
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
        const input_q_row0 = q_values[r * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_q_row1 = q_values[(r + 1) * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_scale_row0 = input_scales[r * row_blocks ..][0..row_blocks];
        const input_scale_row1 = input_scales[(r + 1) * row_blocks ..][0..row_blocks];
        const input_sum_row0 = input_sums[r * row_blocks ..][0..row_blocks];
        const input_sum_row1 = input_sums[(r + 1) * row_blocks ..][0..row_blocks];
        var o: usize = 0;
        while (o + prepared_q8_0_panel_nr <= out_dim) : (o += prepared_q8_0_panel_nr) {
            var acc00 = optionalLinearBiasAt(bias, o);
            var acc01 = optionalLinearBiasAt(bias, o + 1);
            var acc02 = optionalLinearBiasAt(bias, o + 2);
            var acc03 = optionalLinearBiasAt(bias, o + 3);
            var acc10 = acc00;
            var acc11 = acc01;
            var acc12 = acc02;
            var acc13 = acc03;
            for (0..row_blocks) |block_idx| {
                const panel_blocks = if (prepared_panel_blocks) |panel| blk: {
                    const panel_off = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * prepared_legacy_block_bytes;
                    break :blk panel[panel_off..][0 .. prepared_q8_0_panel_nr * prepared_legacy_block_bytes];
                } else null;
                const w0 = if (panel_blocks) |panel| panel[0..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 0) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const w1 = if (panel_blocks) |panel| panel[prepared_legacy_block_bytes..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 1) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const w2 = if (panel_blocks) |panel| panel[2 * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 2) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const w3 = if (panel_blocks) |panel| panel[3 * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 3) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..values_per_block];
                const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..values_per_block];
                const dots = dotI8I8Block4MR2(qx0, qx1, preparedLegacyValues(w0), preparedLegacyValues(w1), preparedLegacyValues(w2), preparedLegacyValues(w3));
                const scale0 = input_scale_row0[block_idx];
                const scale1 = input_scale_row1[block_idx];
                const ws0 = preparedLegacyScale(w0);
                const ws1 = preparedLegacyScale(w1);
                const ws2 = preparedLegacyScale(w2);
                const ws3 = preparedLegacyScale(w3);
                if (!use_mr4) {
                    acc00 += scale0 * ws0 * @as(f32, @floatFromInt(dots[0]));
                    acc01 += scale0 * ws1 * @as(f32, @floatFromInt(dots[1]));
                    acc02 += scale0 * ws2 * @as(f32, @floatFromInt(dots[2]));
                    acc03 += scale0 * ws3 * @as(f32, @floatFromInt(dots[3]));
                    acc10 += scale1 * ws0 * @as(f32, @floatFromInt(dots[4]));
                    acc11 += scale1 * ws1 * @as(f32, @floatFromInt(dots[5]));
                    acc12 += scale1 * ws2 * @as(f32, @floatFromInt(dots[6]));
                    acc13 += scale1 * ws3 * @as(f32, @floatFromInt(dots[7]));
                } else {
                    const sum0 = @as(f32, @floatFromInt(input_sum_row0[block_idx]));
                    const sum1 = @as(f32, @floatFromInt(input_sum_row1[block_idx]));
                    const wm0 = preparedLegacyMin(w0);
                    const wm1 = preparedLegacyMin(w1);
                    const wm2 = preparedLegacyMin(w2);
                    const wm3 = preparedLegacyMin(w3);
                    acc00 += scale0 * (ws0 * @as(f32, @floatFromInt(dots[0])) + wm0 * sum0);
                    acc01 += scale0 * (ws1 * @as(f32, @floatFromInt(dots[1])) + wm1 * sum0);
                    acc02 += scale0 * (ws2 * @as(f32, @floatFromInt(dots[2])) + wm2 * sum0);
                    acc03 += scale0 * (ws3 * @as(f32, @floatFromInt(dots[3])) + wm3 * sum0);
                    acc10 += scale1 * (ws0 * @as(f32, @floatFromInt(dots[4])) + wm0 * sum1);
                    acc11 += scale1 * (ws1 * @as(f32, @floatFromInt(dots[5])) + wm1 * sum1);
                    acc12 += scale1 * (ws2 * @as(f32, @floatFromInt(dots[6])) + wm2 * sum1);
                    acc13 += scale1 * (ws3 * @as(f32, @floatFromInt(dots[7])) + wm3 * sum1);
                }
            }
            out_row0[o] = acc00;
            out_row0[o + 1] = acc01;
            out_row0[o + 2] = acc02;
            out_row0[o + 3] = acc03;
            out_row1[o] = acc10;
            out_row1[o + 1] = acc11;
            out_row1[o + 2] = acc12;
            out_row1[o + 3] = acc13;
        }
        while (o < out_dim) : (o += 1) {
            var acc0 = optionalLinearBiasAt(bias, o);
            var acc1 = acc0;
            const w_off = o * row_stride;
            for (0..row_blocks) |block_idx| {
                const block = prepared_blocks[w_off + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const qx0: *const [32]u8 = input_q_row0[block_idx * values_per_block ..][0..values_per_block];
                const qx1: *const [32]u8 = input_q_row1[block_idx * values_per_block ..][0..values_per_block];
                const qw = preparedLegacyValues(block);
                const weight_scale = preparedLegacyScale(block);
                if (!use_mr4) {
                    acc0 += input_scale_row0[block_idx] * weight_scale * @as(f32, @floatFromInt(dotI8I8Block(qx0, qw)));
                    acc1 += input_scale_row1[block_idx] * weight_scale * @as(f32, @floatFromInt(dotI8I8Block(qx1, qw)));
                } else {
                    const weight_min = preparedLegacyMin(block);
                    acc0 += input_scale_row0[block_idx] * (weight_scale * @as(f32, @floatFromInt(dotI8I8Block(qx0, qw))) + weight_min * @as(f32, @floatFromInt(input_sum_row0[block_idx])));
                    acc1 += input_scale_row1[block_idx] * (weight_scale * @as(f32, @floatFromInt(dotI8I8Block(qx1, qw))) + weight_min * @as(f32, @floatFromInt(input_sum_row1[block_idx])));
                }
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
        }
    }

    if (r < rows) {
        const out_row = output[r * out_dim ..][0..out_dim];
        const input_q_row = q_values[r * row_blocks * values_per_block ..][0 .. row_blocks * values_per_block];
        const input_scale_row = input_scales[r * row_blocks ..][0..row_blocks];
        const input_sum_row = input_sums[r * row_blocks ..][0..row_blocks];
        var o: usize = 0;
        while (o + prepared_q8_0_panel_nr <= out_dim) : (o += prepared_q8_0_panel_nr) {
            var acc0 = optionalLinearBiasAt(bias, o);
            var acc1 = optionalLinearBiasAt(bias, o + 1);
            var acc2 = optionalLinearBiasAt(bias, o + 2);
            var acc3 = optionalLinearBiasAt(bias, o + 3);
            for (0..row_blocks) |block_idx| {
                const panel_blocks = if (prepared_panel_blocks) |panel| blk: {
                    const panel_off = ((o / prepared_q8_0_panel_nr) * row_blocks + block_idx) * prepared_q8_0_panel_nr * prepared_legacy_block_bytes;
                    break :blk panel[panel_off..][0 .. prepared_q8_0_panel_nr * prepared_legacy_block_bytes];
                } else null;
                const w0 = if (panel_blocks) |panel| panel[0..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 0) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const w1 = if (panel_blocks) |panel| panel[prepared_legacy_block_bytes..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 1) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const w2 = if (panel_blocks) |panel| panel[2 * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 2) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const w3 = if (panel_blocks) |panel| panel[3 * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes] else prepared_blocks[(o + 3) * row_stride + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..values_per_block];
                const dots = dotI8I8Block4(qx, preparedLegacyValues(w0), preparedLegacyValues(w1), preparedLegacyValues(w2), preparedLegacyValues(w3));
                const input_scale = input_scale_row[block_idx];
                const input_sum_f = @as(f32, @floatFromInt(input_sum_row[block_idx]));
                acc0 += input_scale * (preparedLegacyScale(w0) * @as(f32, @floatFromInt(dots[0])) + preparedLegacyMin(w0) * input_sum_f);
                acc1 += input_scale * (preparedLegacyScale(w1) * @as(f32, @floatFromInt(dots[1])) + preparedLegacyMin(w1) * input_sum_f);
                acc2 += input_scale * (preparedLegacyScale(w2) * @as(f32, @floatFromInt(dots[2])) + preparedLegacyMin(w2) * input_sum_f);
                acc3 += input_scale * (preparedLegacyScale(w3) * @as(f32, @floatFromInt(dots[3])) + preparedLegacyMin(w3) * input_sum_f);
            }
            out_row[o] = acc0;
            out_row[o + 1] = acc1;
            out_row[o + 2] = acc2;
            out_row[o + 3] = acc3;
        }
        while (o < out_dim) : (o += 1) {
            var acc = optionalLinearBiasAt(bias, o);
            const w_off = o * row_stride;
            for (0..row_blocks) |block_idx| {
                const block = prepared_blocks[w_off + block_idx * prepared_legacy_block_bytes ..][0..prepared_legacy_block_bytes];
                const input_scale = input_scale_row[block_idx];
                const qx: *const [32]u8 = input_q_row[block_idx * values_per_block ..][0..values_per_block];
                const dot = dotI8I8Block(qx, preparedLegacyValues(block));
                if (!use_mr4) {
                    acc += input_scale * preparedLegacyScale(block) * @as(f32, @floatFromInt(dot));
                } else {
                    acc += input_scale * (preparedLegacyScale(block) * @as(f32, @floatFromInt(dot)) + preparedLegacyMin(block) * @as(f32, @floatFromInt(input_sum_row[block_idx])));
                }
            }
            out_row[o] = acc;
        }
    }
}

fn quantizeLegacyActivation(
    allocator: std.mem.Allocator,
    input: []const f32,
    rows: usize,
    in_dim: usize,
    row_blocks: usize,
) !struct { q_values: []u8, input_scales: []f32, input_sums: []i32 } {
    const values_per_block: usize = 32;
    const alloc_start = nativeQuantPhaseStart();
    const q_values = try allocator.alloc(u8, rows * row_blocks * values_per_block);
    errdefer allocator.free(q_values);
    const input_scales = try allocator.alloc(f32, rows * row_blocks);
    errdefer allocator.free(input_scales);
    const input_sums = try allocator.alloc(i32, rows * row_blocks);
    errdefer allocator.free(input_sums);
    noteNativeQuantPhase(.legacy_activation_alloc, alloc_start);
    const quant_start = nativeQuantPhaseStart();
    quantizeLegacyActivationInto(input, q_values, input_scales, input_sums, rows, in_dim, row_blocks);
    noteNativeQuantPhase(.legacy_activation_quant, quant_start);
    return .{ .q_values = q_values, .input_scales = input_scales, .input_sums = input_sums };
}

fn quantizeLegacyActivationInto(
    input: []const f32,
    q_values: []u8,
    input_scales: []f32,
    input_sums: []i32,
    rows: usize,
    in_dim: usize,
    row_blocks: usize,
) void {
    const values_per_block: usize = 32;
    for (0..rows) |r| {
        const input_row = input[r * in_dim ..][0..in_dim];
        for (0..row_blocks) |block_idx| {
            const input_block = input_row[block_idx * values_per_block ..][0..values_per_block];
            var max_abs: f32 = 0.0;
            for (input_block) |value| max_abs = @max(max_abs, @abs(value));
            const scale = if (max_abs == 0.0) @as(f32, 1.0) else max_abs / 127.0;
            const inv_scale = if (max_abs == 0.0) 0.0 else 1.0 / scale;
            const q_off = (r * row_blocks + block_idx) * values_per_block;
            const block_out = q_values[q_off..][0..values_per_block];
            input_scales[r * row_blocks + block_idx] = scale;
            var sum: i32 = 0;
            for (input_block, 0..) |value, i| {
                const q = if (max_abs == 0.0)
                    @as(i8, 0)
                else
                    @as(i8, @intFromFloat(@min(@max(std.math.round(value * inv_scale), -127.0), 127.0)));
                block_out[i] = @bitCast(q);
                sum += q;
            }
            input_sums[r * row_blocks + block_idx] = sum;
        }
    }
}

fn linearNoBiasLegacyPreparedActivation(
    allocator: std.mem.Allocator,
    io: ?std.Io,
    input: []const f32,
    prepared_blocks: []const u8,
    prepared_panel_blocks: ?[]const u8,
    use_mr4: bool,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    const row_blocks = try validatePreparedLegacyActivationBlocks(prepared_blocks, prepared_panel_blocks, in_dim, out_dim);
    const values_per_block: usize = 32;
    if (rows == 1 and in_dim <= small_row_q8_0_stack_max_in_dim) {
        var q_values_buf: [small_row_q8_0_stack_max_in_dim]u8 = undefined;
        var input_scales_buf: [small_row_q8_0_stack_max_in_dim / values_per_block]f32 = undefined;
        var input_sums_buf: [small_row_q8_0_stack_max_in_dim / values_per_block]i32 = undefined;
        const q_values = q_values_buf[0 .. row_blocks * values_per_block];
        const input_scales = input_scales_buf[0..row_blocks];
        const input_sums = input_sums_buf[0..row_blocks];
        const quant_start = nativeQuantPhaseStart();
        quantizeLegacyActivationInto(input, q_values, input_scales, input_sums, rows, in_dim, row_blocks);
        noteNativeQuantPhase(.legacy_activation_quant, quant_start);
        const compute_start = nativeQuantPhaseStart();
        try linearLegacyPreparedActivationDispatch(io, q_values, input_scales, input_sums, prepared_blocks, prepared_panel_blocks, null, use_mr4, output, rows, in_dim, out_dim);
        noteNativeQuantPhase(.legacy_compute, compute_start);
        return;
    }
    const q = try quantizeLegacyActivation(allocator, input, rows, in_dim, row_blocks);
    defer allocator.free(q.q_values);
    defer allocator.free(q.input_scales);
    defer allocator.free(q.input_sums);
    const compute_start = nativeQuantPhaseStart();
    try linearLegacyPreparedActivationDispatch(io, q.q_values, q.input_scales, q.input_sums, prepared_blocks, prepared_panel_blocks, null, use_mr4, output, rows, in_dim, out_dim);
    noteNativeQuantPhase(.legacy_compute, compute_start);
}

fn linearLegacyPreparedActivationParallel(
    io: ?std.Io,
    q_values: []const u8,
    input_scales: []const f32,
    input_sums: []const i32,
    prepared_blocks: []const u8,
    prepared_panel_blocks: ?[]const u8,
    bias: ?[]const f32,
    use_mr4: bool,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !bool {
    const values_per_block: usize = 32;
    const row_blocks = in_dim / values_per_block;
    const col_plan = chooseQuantLinearColumnParallelPlan(quantParallelEnabled(), quantParallelDispatchAvailable(io), rows, out_dim, row_blocks, quantParallelMaxWorkers());
    if (col_plan.worker_count > 1) {
        if (quantParallelDebugRequested()) {
            std.debug.print("legacy_prepared_activation_parallel_cols workers={d} rows={d} out={d} row_blocks={d}\n", .{ col_plan.worker_count, rows, out_dim, row_blocks });
        }
        var chunks: [max_q4_k_parallel_workers]QuantColChunk = undefined;
        const num_chunks = chunkColsForWorkers(out_dim, col_plan, &chunks);
        var contexts: [max_q4_k_parallel_workers]LegacyPreparedActivationWorkerCtx = undefined;
        var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
        for (chunks[0..num_chunks], 0..) |chunk, i| {
            contexts[i] = .{
                .q_values = q_values,
                .input_scales = input_scales,
                .input_sums = input_sums,
                .prepared_blocks = prepared_blocks,
                .prepared_panel_blocks = prepared_panel_blocks,
                .bias = bias,
                .use_mr4 = use_mr4,
                .output = output,
                .rows = rows,
                .in_dim = in_dim,
                .out_dim = out_dim,
                .out_start = chunk.start,
                .out_end = chunk.end,
            };
            jobs[i] = .{ .fn_ptr = legacyPreparedActivationWorkerJob, .ctx = @ptrCast(&contexts[i]) };
        }
        try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
        return true;
    }

    const plan = chooseQuantLinearParallelPlan(quantParallelEnabled(), rows, out_dim, row_blocks, quantParallelMaxWorkers());
    if (plan.worker_count <= 1) return false;

    var chunks: [max_q4_k_parallel_workers]QuantRowChunk = undefined;
    const num_chunks = chunkRowsForWorkers(rows, plan, &chunks);
    var contexts: [max_q4_k_parallel_workers]LegacyPreparedActivationWorkerCtx = undefined;
    var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
    for (chunks[0..num_chunks], 0..) |chunk, i| {
        contexts[i] = .{
            .q_values = q_values[chunk.start * row_blocks * values_per_block .. chunk.end * row_blocks * values_per_block],
            .input_scales = input_scales[chunk.start * row_blocks .. chunk.end * row_blocks],
            .input_sums = input_sums[chunk.start * row_blocks .. chunk.end * row_blocks],
            .prepared_blocks = prepared_blocks,
            .prepared_panel_blocks = prepared_panel_blocks,
            .bias = bias,
            .use_mr4 = use_mr4,
            .output = output[chunk.start * out_dim .. chunk.end * out_dim],
            .rows = chunk.end - chunk.start,
            .in_dim = in_dim,
            .out_dim = out_dim,
            .out_start = 0,
            .out_end = out_dim,
        };
        jobs[i] = .{ .fn_ptr = legacyPreparedActivationWorkerJob, .ctx = @ptrCast(&contexts[i]) };
    }
    try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
    return true;
}

fn linearLegacyPreparedActivationDispatch(
    io: ?std.Io,
    q_values: []const u8,
    input_scales: []const f32,
    input_sums: []const i32,
    prepared_blocks: []const u8,
    prepared_panel_blocks: ?[]const u8,
    bias: ?[]const f32,
    use_mr4: bool,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    if (try linearLegacyPreparedActivationParallel(io, q_values, input_scales, input_sums, prepared_blocks, prepared_panel_blocks, bias, use_mr4, output, rows, in_dim, out_dim)) return;
    legacyPreparedActivationApply(q_values, input_scales, input_sums, prepared_blocks, prepared_panel_blocks, bias, output, rows, in_dim, out_dim, 0, out_dim, use_mr4);
}

