    defer allocator.free(q.input_scales);
    defer allocator.free(q.input_sums);
    try linearLegacyPreparedActivationTripleDispatch(io, q.q_values, q.input_scales, q.input_sums, prepared_blocks_a, prepared_panel_blocks_a, prepared_blocks_b, prepared_panel_blocks_b, prepared_blocks_c, prepared_panel_blocks_c, bias_a, bias_b, bias_c, output_a, output_b, output_c, rows, in_dim, out_dim, use_mr4);
}

inline fn preparedQ1_0Scale(block: []const u8) f32 {
    return readF32Le(block[prepared_q1_0_scale_offset..][0..4]);
}

inline fn preparedQ1_0Values(block: []const u8, sub32: usize) *const [32]u8 {
    return block[prepared_q1_0_values_offset + sub32 * 32 ..][0..32];
}

fn validatePreparedQ1_0ActivationBlocks(
    prepared_blocks: []const u8,
    panel_blocks: ?[]const u8,
    in_dim: usize,
    out_dim: usize,
) !usize {
    const values_per_block: usize = 128;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    if (prepared_blocks.len != out_dim * row_blocks * prepared_q1_0_block_bytes) return error.InvalidQuantizedDataSize;
    if (panel_blocks) |blocks| {
        if (blocks.len != preparedQ1_0PanelByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;
    }
    return row_blocks;
}

inline fn preparedQ1_0PanelBlock(
    panel_blocks: ?[]const u8,
    prepared_blocks: []const u8,
    row_blocks: usize,
    row_stride: usize,
    out_col: usize,
    block_idx: usize,
    lane: usize,
) []const u8 {
    if (panel_blocks) |panel| {
        const panel_idx = out_col / prepared_q8_0_panel_nr;
        const panel_base = (panel_idx * row_blocks + block_idx) * prepared_q8_0_panel_nr * prepared_q1_0_block_bytes;
        return panel[panel_base + lane * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes];
    }
    return prepared_blocks[(out_col + lane) * row_stride + block_idx * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes];
}

inline fn dotQ1_0PreparedQ8_0Block(
    q_values_row: []const u8,
    input_scales_row: []const f32,
    prepared_block: []const u8,
    block_idx: usize,
) f32 {
    const d = preparedQ1_0Scale(prepared_block);
    var acc: f32 = 0.0;
    inline for (0..4) |sub| {
        const input_block_idx = block_idx * 4 + sub;
        const qx: *const [32]u8 = q_values_row[input_block_idx * 32 ..][0..32];
        const dot = dotI8I8Block(qx, preparedQ1_0Values(prepared_block, sub));
        acc += (input_scales_row[input_block_idx] * d) * @as(f32, @floatFromInt(dot));
    }
    return acc;
}

inline fn dotQ1_0PreparedQ8_0Block4(
    q_values_row: []const u8,
    input_scales_row: []const f32,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
    block_idx: usize,
) struct { f32, f32, f32, f32 } {
    const d0 = preparedQ1_0Scale(prepared_block0);
    const d1 = preparedQ1_0Scale(prepared_block1);
    const d2 = preparedQ1_0Scale(prepared_block2);
    const d3 = preparedQ1_0Scale(prepared_block3);
    var acc0: f32 = 0.0;
    var acc1: f32 = 0.0;
    var acc2: f32 = 0.0;
    var acc3: f32 = 0.0;
    inline for (0..4) |sub| {
        const input_block_idx = block_idx * 4 + sub;
        const qx: *const [32]u8 = q_values_row[input_block_idx * 32 ..][0..32];
        const dots = dotI8I8Block4(
            qx,
            preparedQ1_0Values(prepared_block0, sub),
            preparedQ1_0Values(prepared_block1, sub),
            preparedQ1_0Values(prepared_block2, sub),
            preparedQ1_0Values(prepared_block3, sub),
        );
        const input_scale = input_scales_row[input_block_idx];
        acc0 += (input_scale * d0) * @as(f32, @floatFromInt(dots[0]));
        acc1 += (input_scale * d1) * @as(f32, @floatFromInt(dots[1]));
        acc2 += (input_scale * d2) * @as(f32, @floatFromInt(dots[2]));
        acc3 += (input_scale * d3) * @as(f32, @floatFromInt(dots[3]));
    }
    return .{ acc0, acc1, acc2, acc3 };
}

inline fn dotQ1_0PreparedQ8_0GroupedBlock(
    comptime projection_count: usize,
    q_values_row: []const u8,
    input_scales_row: []const f32,
    prepared_blocks: [projection_count][]const u8,
    block_idx: usize,
) [projection_count]f32 {
    var scales: [projection_count]f32 = undefined;
    inline for (0..projection_count) |projection_idx| {
        scales[projection_idx] = preparedQ1_0Scale(prepared_blocks[projection_idx]);
    }
    var acc: [projection_count]f32 = [_]f32{0.0} ** projection_count;
    inline for (0..4) |sub| {
        const input_block_idx = block_idx * 4 + sub;
        const qx: *const [32]u8 = q_values_row[input_block_idx * 32 ..][0..32];
        const input_scale = input_scales_row[input_block_idx];
        inline for (0..projection_count) |projection_idx| {
            const dot = dotI8I8Block(qx, preparedQ1_0Values(prepared_blocks[projection_idx], sub));
            acc[projection_idx] += (input_scale * scales[projection_idx]) * @as(f32, @floatFromInt(dot));
        }
    }
    return acc;
}

inline fn dotQ1_0PreparedQ8_0GroupedBlock4(
    comptime projection_count: usize,
    q_values_row: []const u8,
    input_scales_row: []const f32,
    prepared_blocks: [projection_count][4][]const u8,
    block_idx: usize,
) [projection_count][4]f32 {
    var scales: [projection_count][4]f32 = undefined;
    inline for (0..projection_count) |projection_idx| {
        inline for (0..4) |lane| {
            scales[projection_idx][lane] = preparedQ1_0Scale(prepared_blocks[projection_idx][lane]);
        }
    }
    var acc: [projection_count][4]f32 = [_][4]f32{[_]f32{0.0} ** 4} ** projection_count;
    inline for (0..4) |sub| {
        const input_block_idx = block_idx * 4 + sub;
        const qx: *const [32]u8 = q_values_row[input_block_idx * 32 ..][0..32];
        const input_scale = input_scales_row[input_block_idx];
        if (comptime projection_count == 2) {
            const dots = dotI8I8Block8(
                qx,
                preparedQ1_0Values(prepared_blocks[0][0], sub),
                preparedQ1_0Values(prepared_blocks[0][1], sub),
                preparedQ1_0Values(prepared_blocks[0][2], sub),
                preparedQ1_0Values(prepared_blocks[0][3], sub),
                preparedQ1_0Values(prepared_blocks[1][0], sub),
                preparedQ1_0Values(prepared_blocks[1][1], sub),
                preparedQ1_0Values(prepared_blocks[1][2], sub),
                preparedQ1_0Values(prepared_blocks[1][3], sub),
            );
            inline for (0..4) |lane| {
                acc[0][lane] += (input_scale * scales[0][lane]) * @as(f32, @floatFromInt(dots[lane]));
                acc[1][lane] += (input_scale * scales[1][lane]) * @as(f32, @floatFromInt(dots[4 + lane]));
            }
        } else if (comptime projection_count == 3) {
            const dots_ab = dotI8I8Block8(
                qx,
                preparedQ1_0Values(prepared_blocks[0][0], sub),
                preparedQ1_0Values(prepared_blocks[0][1], sub),
                preparedQ1_0Values(prepared_blocks[0][2], sub),
                preparedQ1_0Values(prepared_blocks[0][3], sub),
                preparedQ1_0Values(prepared_blocks[1][0], sub),
                preparedQ1_0Values(prepared_blocks[1][1], sub),
                preparedQ1_0Values(prepared_blocks[1][2], sub),
                preparedQ1_0Values(prepared_blocks[1][3], sub),
            );
            const dots_c = dotI8I8Block4(
                qx,
                preparedQ1_0Values(prepared_blocks[2][0], sub),
                preparedQ1_0Values(prepared_blocks[2][1], sub),
                preparedQ1_0Values(prepared_blocks[2][2], sub),
                preparedQ1_0Values(prepared_blocks[2][3], sub),
            );
            inline for (0..4) |lane| {
                acc[0][lane] += (input_scale * scales[0][lane]) * @as(f32, @floatFromInt(dots_ab[lane]));
                acc[1][lane] += (input_scale * scales[1][lane]) * @as(f32, @floatFromInt(dots_ab[4 + lane]));
                acc[2][lane] += (input_scale * scales[2][lane]) * @as(f32, @floatFromInt(dots_c[lane]));
            }
        } else {
            inline for (0..projection_count) |projection_idx| {
                const dots = dotI8I8Block4(
                    qx,
                    preparedQ1_0Values(prepared_blocks[projection_idx][0], sub),
                    preparedQ1_0Values(prepared_blocks[projection_idx][1], sub),
                    preparedQ1_0Values(prepared_blocks[projection_idx][2], sub),
                    preparedQ1_0Values(prepared_blocks[projection_idx][3], sub),
                );
                acc[projection_idx][0] += (input_scale * scales[projection_idx][0]) * @as(f32, @floatFromInt(dots[0]));
                acc[projection_idx][1] += (input_scale * scales[projection_idx][1]) * @as(f32, @floatFromInt(dots[1]));
                acc[projection_idx][2] += (input_scale * scales[projection_idx][2]) * @as(f32, @floatFromInt(dots[2]));
                acc[projection_idx][3] += (input_scale * scales[projection_idx][3]) * @as(f32, @floatFromInt(dots[3]));
            }
        }
    }
    return acc;
}

fn q1_0PreparedActivationApply(
    q_values: []const u8,
    input_scales: []const f32,
    prepared_blocks: []const u8,
    panel_blocks: ?[]const u8,
    bias: ?[]const f32,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    const row_blocks = in_dim / 128;
    const input_blocks = in_dim / 32;
    const row_stride = row_blocks * prepared_q1_0_block_bytes;
    for (0..rows) |r| {
        const q_values_row = q_values[r * in_dim ..][0..in_dim];
        const input_scales_row = input_scales[r * input_blocks ..][0..input_blocks];
        const out_row = output[r * out_dim ..][0..out_dim];
        var o: usize = out_start;
        while (o < out_end and (o % prepared_q8_0_panel_nr) != 0) : (o += 1) {
            var acc = optionalLinearBiasAt(bias, o);
            for (0..row_blocks) |block_idx| {
                acc += dotQ1_0PreparedQ8_0Block(
                    q_values_row,
                    input_scales_row,
                    prepared_blocks[o * row_stride + block_idx * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes],
                    block_idx,
                );
            }
            out_row[o] = acc;
        }
        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc0 = optionalLinearBiasAt(bias, o);
            var acc1 = optionalLinearBiasAt(bias, o + 1);
            var acc2 = optionalLinearBiasAt(bias, o + 2);
            var acc3 = optionalLinearBiasAt(bias, o + 3);
            for (0..row_blocks) |block_idx| {
                const sums = dotQ1_0PreparedQ8_0Block4(
                    q_values_row,
                    input_scales_row,
                    preparedQ1_0PanelBlock(panel_blocks, prepared_blocks, row_blocks, row_stride, o, block_idx, 0),
                    preparedQ1_0PanelBlock(panel_blocks, prepared_blocks, row_blocks, row_stride, o, block_idx, 1),
                    preparedQ1_0PanelBlock(panel_blocks, prepared_blocks, row_blocks, row_stride, o, block_idx, 2),
                    preparedQ1_0PanelBlock(panel_blocks, prepared_blocks, row_blocks, row_stride, o, block_idx, 3),
                    block_idx,
                );
                acc0 += sums[0];
                acc1 += sums[1];
                acc2 += sums[2];
                acc3 += sums[3];
            }
            out_row[o] = acc0;
            out_row[o + 1] = acc1;
            out_row[o + 2] = acc2;
            out_row[o + 3] = acc3;
        }
        while (o < out_end) : (o += 1) {
            var acc = optionalLinearBiasAt(bias, o);
            for (0..row_blocks) |block_idx| {
                acc += dotQ1_0PreparedQ8_0Block(
                    q_values_row,
                    input_scales_row,
                    prepared_blocks[o * row_stride + block_idx * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes],
                    block_idx,
                );
            }
            out_row[o] = acc;
        }
    }
}

fn q1_0PreparedActivationPairApply(
    q_values: []const u8,
    input_scales: []const f32,
    prepared_blocks_a: []const u8,
    panel_blocks_a: ?[]const u8,
    prepared_blocks_b: []const u8,
    panel_blocks_b: ?[]const u8,
    output_a: []f32,
    output_b: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    const row_blocks = in_dim / 128;
    const input_blocks = in_dim / 32;
    const row_stride = row_blocks * prepared_q1_0_block_bytes;
    for (0..rows) |r| {
        const q_values_row = q_values[r * in_dim ..][0..in_dim];
        const input_scales_row = input_scales[r * input_blocks ..][0..input_blocks];
        const out_row_a = output_a[r * out_dim ..][0..out_dim];
        const out_row_b = output_b[r * out_dim ..][0..out_dim];
        var o: usize = out_start;
        while (o < out_end and (o % prepared_q8_0_panel_nr) != 0) : (o += 1) {
            var acc_a: f32 = 0.0;
            var acc_b: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const sums = dotQ1_0PreparedQ8_0GroupedBlock(
                    2,
                    q_values_row,
                    input_scales_row,
                    .{
                        prepared_blocks_a[o * row_stride + block_idx * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes],
                        prepared_blocks_b[o * row_stride + block_idx * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes],
                    },
                    block_idx,
                );
                acc_a += sums[0];
                acc_b += sums[1];
            }
            out_row_a[o] = acc_a;
            out_row_b[o] = acc_b;
        }
        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc_a0: f32 = 0.0;
            var acc_a1: f32 = 0.0;
            var acc_a2: f32 = 0.0;
            var acc_a3: f32 = 0.0;
            var acc_b0: f32 = 0.0;
            var acc_b1: f32 = 0.0;
            var acc_b2: f32 = 0.0;
            var acc_b3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const sums = dotQ1_0PreparedQ8_0GroupedBlock4(
                    2,
                    q_values_row,
                    input_scales_row,
                    .{
                        .{
                            preparedQ1_0PanelBlock(panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 0),
                            preparedQ1_0PanelBlock(panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 1),
                            preparedQ1_0PanelBlock(panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 2),
                            preparedQ1_0PanelBlock(panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 3),
                        },
                        .{
                            preparedQ1_0PanelBlock(panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 0),
                            preparedQ1_0PanelBlock(panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 1),
                            preparedQ1_0PanelBlock(panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 2),
                            preparedQ1_0PanelBlock(panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 3),
                        },
                    },
                    block_idx,
                );
                acc_a0 += sums[0][0];
                acc_a1 += sums[0][1];
                acc_a2 += sums[0][2];
                acc_a3 += sums[0][3];
                acc_b0 += sums[1][0];
                acc_b1 += sums[1][1];
                acc_b2 += sums[1][2];
                acc_b3 += sums[1][3];
            }
            out_row_a[o] = acc_a0;
            out_row_a[o + 1] = acc_a1;
            out_row_a[o + 2] = acc_a2;
            out_row_a[o + 3] = acc_a3;
            out_row_b[o] = acc_b0;
            out_row_b[o + 1] = acc_b1;
            out_row_b[o + 2] = acc_b2;
            out_row_b[o + 3] = acc_b3;
        }
        while (o < out_end) : (o += 1) {
            var acc_a: f32 = 0.0;
            var acc_b: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const sums = dotQ1_0PreparedQ8_0GroupedBlock(
                    2,
                    q_values_row,
                    input_scales_row,
                    .{
                        prepared_blocks_a[o * row_stride + block_idx * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes],
                        prepared_blocks_b[o * row_stride + block_idx * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes],
                    },
                    block_idx,
                );
                acc_a += sums[0];
                acc_b += sums[1];
            }
            out_row_a[o] = acc_a;
            out_row_b[o] = acc_b;
        }
    }
}

fn q1_0PreparedActivationTripleApply(
    q_values: []const u8,
    input_scales: []const f32,
    prepared_blocks_a: []const u8,
    panel_blocks_a: ?[]const u8,
    prepared_blocks_b: []const u8,
    panel_blocks_b: ?[]const u8,
    prepared_blocks_c: []const u8,
    panel_blocks_c: ?[]const u8,
    bias_a: ?[]const f32,
    bias_b: ?[]const f32,
    bias_c: ?[]const f32,
    output_a: []f32,
    output_b: []f32,
    output_c: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    const row_blocks = in_dim / 128;
    const input_blocks = in_dim / 32;
    const row_stride = row_blocks * prepared_q1_0_block_bytes;
    for (0..rows) |r| {
        const q_values_row = q_values[r * in_dim ..][0..in_dim];
        const input_scales_row = input_scales[r * input_blocks ..][0..input_blocks];
        const out_row_a = output_a[r * out_dim ..][0..out_dim];
        const out_row_b = output_b[r * out_dim ..][0..out_dim];
        const out_row_c = output_c[r * out_dim ..][0..out_dim];
        var o: usize = out_start;
        while (o < out_end and (o % prepared_q8_0_panel_nr) != 0) : (o += 1) {
            var acc_a = optionalLinearBiasAt(bias_a, o);
            var acc_b = optionalLinearBiasAt(bias_b, o);
            var acc_c = optionalLinearBiasAt(bias_c, o);
            for (0..row_blocks) |block_idx| {
                const sums = dotQ1_0PreparedQ8_0GroupedBlock(
                    3,
                    q_values_row,
                    input_scales_row,
                    .{
                        prepared_blocks_a[o * row_stride + block_idx * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes],
                        prepared_blocks_b[o * row_stride + block_idx * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes],
                        prepared_blocks_c[o * row_stride + block_idx * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes],
                    },
                    block_idx,
                );
                acc_a += sums[0];
                acc_b += sums[1];
                acc_c += sums[2];
            }
            out_row_a[o] = acc_a;
            out_row_b[o] = acc_b;
            out_row_c[o] = acc_c;
        }
        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc_a0 = optionalLinearBiasAt(bias_a, o);
            var acc_a1 = optionalLinearBiasAt(bias_a, o + 1);
            var acc_a2 = optionalLinearBiasAt(bias_a, o + 2);
            var acc_a3 = optionalLinearBiasAt(bias_a, o + 3);
            var acc_b0 = optionalLinearBiasAt(bias_b, o);
            var acc_b1 = optionalLinearBiasAt(bias_b, o + 1);
            var acc_b2 = optionalLinearBiasAt(bias_b, o + 2);
            var acc_b3 = optionalLinearBiasAt(bias_b, o + 3);
            var acc_c0 = optionalLinearBiasAt(bias_c, o);
            var acc_c1 = optionalLinearBiasAt(bias_c, o + 1);
            var acc_c2 = optionalLinearBiasAt(bias_c, o + 2);
            var acc_c3 = optionalLinearBiasAt(bias_c, o + 3);
            for (0..row_blocks) |block_idx| {
                const sums = dotQ1_0PreparedQ8_0GroupedBlock4(
                    3,
                    q_values_row,
                    input_scales_row,
                    .{
                        .{
                            preparedQ1_0PanelBlock(panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 0),
                            preparedQ1_0PanelBlock(panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 1),
                            preparedQ1_0PanelBlock(panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 2),
                            preparedQ1_0PanelBlock(panel_blocks_a, prepared_blocks_a, row_blocks, row_stride, o, block_idx, 3),
                        },
                        .{
                            preparedQ1_0PanelBlock(panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 0),
                            preparedQ1_0PanelBlock(panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 1),
                            preparedQ1_0PanelBlock(panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 2),
                            preparedQ1_0PanelBlock(panel_blocks_b, prepared_blocks_b, row_blocks, row_stride, o, block_idx, 3),
                        },
                        .{
                            preparedQ1_0PanelBlock(panel_blocks_c, prepared_blocks_c, row_blocks, row_stride, o, block_idx, 0),
                            preparedQ1_0PanelBlock(panel_blocks_c, prepared_blocks_c, row_blocks, row_stride, o, block_idx, 1),
                            preparedQ1_0PanelBlock(panel_blocks_c, prepared_blocks_c, row_blocks, row_stride, o, block_idx, 2),
                            preparedQ1_0PanelBlock(panel_blocks_c, prepared_blocks_c, row_blocks, row_stride, o, block_idx, 3),
                        },
                    },
                    block_idx,
                );
                acc_a0 += sums[0][0];
                acc_a1 += sums[0][1];
                acc_a2 += sums[0][2];
                acc_a3 += sums[0][3];
                acc_b0 += sums[1][0];
                acc_b1 += sums[1][1];
                acc_b2 += sums[1][2];
                acc_b3 += sums[1][3];
                acc_c0 += sums[2][0];
                acc_c1 += sums[2][1];
                acc_c2 += sums[2][2];
                acc_c3 += sums[2][3];
            }
            out_row_a[o] = acc_a0;
            out_row_a[o + 1] = acc_a1;
            out_row_a[o + 2] = acc_a2;
            out_row_a[o + 3] = acc_a3;
            out_row_b[o] = acc_b0;
            out_row_b[o + 1] = acc_b1;
            out_row_b[o + 2] = acc_b2;
            out_row_b[o + 3] = acc_b3;
            out_row_c[o] = acc_c0;
            out_row_c[o + 1] = acc_c1;
            out_row_c[o + 2] = acc_c2;
            out_row_c[o + 3] = acc_c3;
        }
        while (o < out_end) : (o += 1) {
            var acc_a = optionalLinearBiasAt(bias_a, o);
            var acc_b = optionalLinearBiasAt(bias_b, o);
            var acc_c = optionalLinearBiasAt(bias_c, o);
            for (0..row_blocks) |block_idx| {
                const sums = dotQ1_0PreparedQ8_0GroupedBlock(
                    3,
                    q_values_row,
                    input_scales_row,
                    .{
                        prepared_blocks_a[o * row_stride + block_idx * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes],
                        prepared_blocks_b[o * row_stride + block_idx * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes],
                        prepared_blocks_c[o * row_stride + block_idx * prepared_q1_0_block_bytes ..][0..prepared_q1_0_block_bytes],
                    },
                    block_idx,
                );
                acc_a += sums[0];
                acc_b += sums[1];
                acc_c += sums[2];
            }
            out_row_a[o] = acc_a;
            out_row_b[o] = acc_b;
            out_row_c[o] = acc_c;
        }
    }
}

fn quantizeQ1_0Activation(
    allocator: std.mem.Allocator,
    input: []const f32,
    rows: usize,
    in_dim: usize,
) !struct { q_values: []u8, input_scales: []f32 } {
    const input_blocks = in_dim / 32;
    const q_values = try allocator.alloc(u8, rows * in_dim);
    errdefer allocator.free(q_values);
    const input_scales = try allocator.alloc(f32, rows * input_blocks);
    errdefer allocator.free(input_scales);
    quantizeQ8_0ActivationRows(input, q_values, input_scales, rows, in_dim, input_blocks);
    return .{ .q_values = q_values, .input_scales = input_scales };
}

fn linearNoBiasQ1_0PreparedActivation(
    allocator: std.mem.Allocator,
    io: ?std.Io,
    input: []const f32,
    prepared_blocks: []const u8,
    panel_blocks: ?[]const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    _ = try validatePreparedQ1_0ActivationBlocks(prepared_blocks, panel_blocks, in_dim, out_dim);
    const values_per_block: usize = 32;
    const input_blocks = in_dim / values_per_block;
    if (rows == 1 and in_dim <= small_row_q8_0_stack_max_in_dim) {
        var q_values_buf: [small_row_q8_0_stack_max_in_dim]u8 = undefined;
        var input_scales_buf: [small_row_q8_0_stack_max_in_dim / values_per_block]f32 = undefined;
        const q_values = q_values_buf[0..in_dim];
        const input_scales = input_scales_buf[0..input_blocks];
        quantizeQ8_0ActivationRows(input, q_values, input_scales, rows, in_dim, input_blocks);
        try linearQ1_0PreparedActivationDispatch(io, q_values, input_scales, prepared_blocks, panel_blocks, null, output, rows, in_dim, out_dim);
        return;
    }
    const q = try quantizeQ1_0Activation(allocator, input, rows, in_dim);
    defer allocator.free(q.q_values);
    defer allocator.free(q.input_scales);
    try linearQ1_0PreparedActivationDispatch(io, q.q_values, q.input_scales, prepared_blocks, panel_blocks, null, output, rows, in_dim, out_dim);
}

fn linearQ1_0PreparedActivationParallel(
    io: ?std.Io,
    q_values: []const u8,
    input_scales: []const f32,
    prepared_blocks: []const u8,
    panel_blocks: ?[]const u8,
    bias: ?[]const f32,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !bool {
    const row_blocks = in_dim / 128;
    const input_blocks = in_dim / 32;
    const col_plan = chooseQuantLinearColumnParallelPlan(quantParallelEnabled(), quantParallelDispatchAvailable(io), rows, out_dim, row_blocks, quantParallelMaxWorkers());
    if (col_plan.worker_count > 1) {
        if (quantParallelDebugRequested()) {
            std.debug.print("q1_0_prepared_activation_parallel_cols workers={d} rows={d} out={d} row_blocks={d}\n", .{ col_plan.worker_count, rows, out_dim, row_blocks });
        }
        var chunks: [max_q4_k_parallel_workers]QuantColChunk = undefined;
        const num_chunks = chunkColsForWorkers(out_dim, col_plan, &chunks);
        var contexts: [max_q4_k_parallel_workers]Q1_0PreparedActivationWorkerCtx = undefined;
        var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
        for (chunks[0..num_chunks], 0..) |chunk, i| {
            contexts[i] = .{
                .q_values = q_values,
                .input_scales = input_scales,
                .prepared_blocks = prepared_blocks,
                .panel_blocks = panel_blocks,
                .bias = bias,
                .output = output,
                .rows = rows,
                .in_dim = in_dim,
                .out_dim = out_dim,
                .out_start = chunk.start,
                .out_end = chunk.end,
            };
            jobs[i] = .{ .fn_ptr = q1_0PreparedActivationWorkerJob, .ctx = @ptrCast(&contexts[i]) };
        }
        try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
        return true;
    }

    const plan = chooseQuantLinearParallelPlan(quantParallelEnabled(), rows, out_dim, row_blocks, quantParallelMaxWorkers());
    if (plan.worker_count <= 1) return false;

    var chunks: [max_q4_k_parallel_workers]QuantRowChunk = undefined;
    const num_chunks = chunkRowsForWorkers(rows, plan, &chunks);
    var contexts: [max_q4_k_parallel_workers]Q1_0PreparedActivationWorkerCtx = undefined;
    var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
    for (chunks[0..num_chunks], 0..) |chunk, i| {
        contexts[i] = .{
            .q_values = q_values[chunk.start * in_dim .. chunk.end * in_dim],
            .input_scales = input_scales[chunk.start * input_blocks .. chunk.end * input_blocks],
            .prepared_blocks = prepared_blocks,
            .panel_blocks = panel_blocks,
            .bias = bias,
            .output = output[chunk.start * out_dim .. chunk.end * out_dim],
            .rows = chunk.end - chunk.start,
            .in_dim = in_dim,
            .out_dim = out_dim,
            .out_start = 0,
            .out_end = out_dim,
        };
        jobs[i] = .{ .fn_ptr = q1_0PreparedActivationWorkerJob, .ctx = @ptrCast(&contexts[i]) };
    }
    try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
    return true;
}

fn linearQ1_0PreparedActivationDispatch(
    io: ?std.Io,
    q_values: []const u8,
    input_scales: []const f32,
