inline fn preparedK16Dsc(prepared_block: []const u8, sub: usize) f32 {
    return readF32Le(prepared_block[prepared_k16_dsc_offset + sub * 4 ..][0..4]);
}

inline fn preparedK16Dmn(prepared_block: []const u8, sub: usize) f32 {
    return readF32Le(prepared_block[prepared_k16_dmn_offset + sub * 4 ..][0..4]);
}

inline fn preparedK16Values(prepared_block: []const u8, sub: usize) *const [16]u8 {
    return prepared_block[prepared_k16_values_offset + sub * 16 ..][0..16];
}

inline fn q8KBlockSum16(q8_block: []const u8, sub16: usize) i32 {
    return @intCast(std.mem.readInt(i16, q8_block[260 + sub16 * 2 ..][0..2], .little));
}

inline fn prepareQ8KActivationSums16(q8_block: []const u8, sums: *[16]f32) void {
    inline for (0..16) |sub| {
        sums[sub] = @as(f32, @floatFromInt(q8KBlockSum16(q8_block, sub)));
    }
}

inline fn q8KBlockSum16F(q8_block: []const u8, activation_sums: ?*const [16]f32, sub16: usize) f32 {
    return if (activation_sums) |sums| sums[sub16] else @as(f32, @floatFromInt(q8KBlockSum16(q8_block, sub16)));
}

inline fn dotQ2KRawQ8Sub16(q_input: *const [16]u8, raw_block: []const u8, sub: usize) i32 {
    std.debug.assert(raw_block.len == 84);
    const qs = raw_block[20..84];
    const chunk = sub / 8;
    const group = (sub % 8) / 2;
    const l_base = (sub % 2) * 16;
    const q_base = chunk * 32;
    const shift: @Vector(VEC_LEN, u3) = @splat(@as(u3, @intCast(group * 2)));
    const mask_03: U8xN = @splat(0x03);
    var acc: I32xN = @splat(0);
    comptime var i: usize = 0;
    inline while (i < 16) : (i += VEC_LEN) {
        const raw_x: U8xN = q_input[i..][0..VEC_LEN].*;
        const raw_q: U8xN = qs[q_base + l_base + i ..][0..VEC_LEN].*;
        const x: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw_x));
        const q: I32xN = (raw_q >> shift) & mask_03;
        acc += x * q;
    }
    return @reduce(.Add, acc);
}

inline fn dotQ3KRawQ8Sub16(q_input: *const [16]u8, raw_block: []const u8, sub: usize) i32 {
    std.debug.assert(raw_block.len == 110);
    const hmask = raw_block[0..32];
    const qs = raw_block[32..96];
    const chunk = sub / 8;
    const group = (sub % 8) / 2;
    const l_base = (sub % 2) * 16;
    const q_base = chunk * 32;
    const shift: @Vector(VEC_LEN, u3) = @splat(@as(u3, @intCast(group * 2)));
    const hm_shift: @Vector(VEC_LEN, u3) = @splat(@as(u3, @intCast(chunk * 4 + group)));
    const mask_03: U8xN = @splat(0x03);
    const mask_01: U8xN = @splat(0x01);
    const four: I32xN = @splat(4);
    var acc: I32xN = @splat(0);
    comptime var i: usize = 0;
    inline while (i < 16) : (i += VEC_LEN) {
        const l = l_base + i;
        const raw_x: U8xN = q_input[i..][0..VEC_LEN].*;
        const raw_q: U8xN = qs[q_base + l ..][0..VEC_LEN].*;
        const raw_h: U8xN = hmask[l..][0..VEC_LEN].*;
        const x: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw_x));
        const low2: I32xN = (raw_q >> shift) & mask_03;
        const high1: I32xN = (raw_h >> hm_shift) & mask_01;
        const q = low2 + high1 * four - four;
        acc += x * q;
    }
    return @reduce(.Add, acc);
}

inline fn q3KRawScale(raw_block: []const u8, sub: usize) i32 {
    const scale_data = raw_block[96..108];
    const group = sub % 4;
    return switch (sub / 4) {
        0 => @as(i32, scale_data[group] & 0x0F) | (@as(i32, scale_data[8 + group] & 0x03) << 4),
        1 => @as(i32, scale_data[4 + group] & 0x0F) | (@as(i32, (scale_data[8 + group] >> 2) & 0x03) << 4),
        2 => @as(i32, (scale_data[group] >> 4) & 0x0F) | (@as(i32, (scale_data[8 + group] >> 4) & 0x03) << 4),
        else => @as(i32, (scale_data[4 + group] >> 4) & 0x0F) | (@as(i32, (scale_data[8 + group] >> 6) & 0x03) << 4),
    };
}

inline fn dotK16RawQ8KBlock(comptime has_min: bool, q8_block: []const u8, raw_block: []const u8) f32 {
    std.debug.assert(q8_block.len == 292);
    const x_d = readF32Le(q8_block[0..4]);
    const qx = q8_block[4..260];
    var acc: f32 = 0.0;
    if (comptime has_min) {
        std.debug.assert(raw_block.len == 84);
        const scales_raw = raw_block[0..16];
        const d = decodeFp16Le(raw_block[16], raw_block[17]);
        const dmin = decodeFp16Le(raw_block[18], raw_block[19]);
        for (0..16) |sub| {
            const dot = dotQ2KRawQ8Sub16(qx[sub * 16 ..][0..16], raw_block, sub);
            const sc = @as(f32, @floatFromInt(scales_raw[sub] & 0x0F));
            const m = @as(f32, @floatFromInt(scales_raw[sub] >> 4));
            const activation_sum = @as(f32, @floatFromInt(q8KBlockSum16(q8_block, sub)));
            acc += (d * sc) * @as(f32, @floatFromInt(dot)) - (dmin * m) * activation_sum;
        }
    } else {
        std.debug.assert(raw_block.len == 110);
        const d = decodeFp16Le(raw_block[108], raw_block[109]);
        for (0..16) |sub| {
            const dot = dotQ3KRawQ8Sub16(qx[sub * 16 ..][0..16], raw_block, sub);
            const scale = d * @as(f32, @floatFromInt(q3KRawScale(raw_block, sub) - 32));
            acc += scale * @as(f32, @floatFromInt(dot));
        }
    }
    return x_d * acc;
}

inline fn dotK16RawQ8KBlock4(
    comptime has_min: bool,
    q8_block: []const u8,
    raw_block0: []const u8,
    raw_block1: []const u8,
    raw_block2: []const u8,
    raw_block3: []const u8,
) struct { f32, f32, f32, f32 } {
    return .{
        dotK16RawQ8KBlock(has_min, q8_block, raw_block0),
        dotK16RawQ8KBlock(has_min, q8_block, raw_block1),
        dotK16RawQ8KBlock(has_min, q8_block, raw_block2),
        dotK16RawQ8KBlock(has_min, q8_block, raw_block3),
    };
}

inline fn preparedK16PanelBlock(
    panel_blocks: ?[]const u8,
    prepared_blocks: []const u8,
    row_blocks: usize,
    row_stride: usize,
    out_col: usize,
    block_idx: usize,
    lane: usize,
) []const u8 {
    if (panel_blocks) |panel| {
        const panel_idx = out_col / prepared_q8_0_panel_nr;
        const panel_base = (panel_idx * row_blocks + block_idx) * prepared_q8_0_panel_nr * prepared_k16_block_bytes;
        return panel[panel_base + lane * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
    }
    return prepared_blocks[(out_col + lane) * row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
}

inline fn dotK16PreparedQ8KBlockWithSums(comptime has_min: bool, q8_block: []const u8, activation_sums: ?*const [16]f32, prepared_block: []const u8) f32 {
    std.debug.assert(q8_block.len == 292);
    std.debug.assert(prepared_block.len == prepared_k16_block_bytes);
    const x_d = readF32Le(q8_block[0..4]);
    const qx = q8_block[4..260];
    var acc: f32 = 0.0;
    for (0..16) |sub| {
        const dot = dotI8I8Block16(qx[sub * 16 ..][0..16], preparedK16Values(prepared_block, sub));
        const dot_f = @as(f32, @floatFromInt(dot));
        if (comptime has_min) {
            const activation_sum = q8KBlockSum16F(q8_block, activation_sums, sub);
            acc += preparedK16Dsc(prepared_block, sub) * dot_f - preparedK16Dmn(prepared_block, sub) * activation_sum;
        } else {
            acc += preparedK16Dsc(prepared_block, sub) * dot_f;
        }
    }
    return x_d * acc;
}

inline fn dotK16PreparedQ8KBlock(comptime has_min: bool, q8_block: []const u8, prepared_block: []const u8) f32 {
    return dotK16PreparedQ8KBlockWithSums(has_min, q8_block, null, prepared_block);
}

inline fn dotK16PreparedQ8KBlock4WithSums(
    comptime has_min: bool,
    q8_block: []const u8,
    activation_sums: ?*const [16]f32,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
) struct { f32, f32, f32, f32 } {
    const x_d = readF32Le(q8_block[0..4]);
    const qx = q8_block[4..260];
    var acc0: f32 = 0.0;
    var acc1: f32 = 0.0;
    var acc2: f32 = 0.0;
    var acc3: f32 = 0.0;
    for (0..16) |sub| {
        const dots = dotI8I8Block4_16(
            qx[sub * 16 ..][0..16],
            preparedK16Values(prepared_block0, sub),
            preparedK16Values(prepared_block1, sub),
            preparedK16Values(prepared_block2, sub),
            preparedK16Values(prepared_block3, sub),
        );
        if (comptime has_min) {
            const activation_sum = q8KBlockSum16F(q8_block, activation_sums, sub);
            acc0 += preparedK16Dsc(prepared_block0, sub) * @as(f32, @floatFromInt(dots[0])) - preparedK16Dmn(prepared_block0, sub) * activation_sum;
            acc1 += preparedK16Dsc(prepared_block1, sub) * @as(f32, @floatFromInt(dots[1])) - preparedK16Dmn(prepared_block1, sub) * activation_sum;
            acc2 += preparedK16Dsc(prepared_block2, sub) * @as(f32, @floatFromInt(dots[2])) - preparedK16Dmn(prepared_block2, sub) * activation_sum;
            acc3 += preparedK16Dsc(prepared_block3, sub) * @as(f32, @floatFromInt(dots[3])) - preparedK16Dmn(prepared_block3, sub) * activation_sum;
        } else {
            acc0 += preparedK16Dsc(prepared_block0, sub) * @as(f32, @floatFromInt(dots[0]));
            acc1 += preparedK16Dsc(prepared_block1, sub) * @as(f32, @floatFromInt(dots[1]));
            acc2 += preparedK16Dsc(prepared_block2, sub) * @as(f32, @floatFromInt(dots[2]));
            acc3 += preparedK16Dsc(prepared_block3, sub) * @as(f32, @floatFromInt(dots[3]));
        }
    }
    return .{ x_d * acc0, x_d * acc1, x_d * acc2, x_d * acc3 };
}

inline fn dotK16PreparedQ8KBlock4(
    comptime has_min: bool,
    q8_block: []const u8,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
) struct { f32, f32, f32, f32 } {
    return dotK16PreparedQ8KBlock4WithSums(has_min, q8_block, null, prepared_block0, prepared_block1, prepared_block2, prepared_block3);
}

inline fn dotK16PreparedQ8KBlock4MR2WithSums(
    comptime has_min: bool,
    q8_block_r0: []const u8,
    activation_sums_r0: ?*const [16]f32,
    q8_block_r1: []const u8,
    activation_sums_r1: ?*const [16]f32,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
) struct { f32, f32, f32, f32, f32, f32, f32, f32 } {
    const x_d0 = readF32Le(q8_block_r0[0..4]);
    const x_d1 = readF32Le(q8_block_r1[0..4]);
    const qx0 = q8_block_r0[4..260];
    const qx1 = q8_block_r1[4..260];
    var acc00: f32 = 0.0;
    var acc01: f32 = 0.0;
    var acc02: f32 = 0.0;
    var acc03: f32 = 0.0;
    var acc10: f32 = 0.0;
    var acc11: f32 = 0.0;
    var acc12: f32 = 0.0;
    var acc13: f32 = 0.0;
    for (0..16) |sub| {
        const q_off = sub * 16;
        const dots = dotI8I8Block4MR2_16(
            qx0[q_off..][0..16],
            qx1[q_off..][0..16],
            preparedK16Values(prepared_block0, sub),
            preparedK16Values(prepared_block1, sub),
            preparedK16Values(prepared_block2, sub),
            preparedK16Values(prepared_block3, sub),
        );
        const dsc0 = preparedK16Dsc(prepared_block0, sub);
        const dsc1 = preparedK16Dsc(prepared_block1, sub);
        const dsc2 = preparedK16Dsc(prepared_block2, sub);
        const dsc3 = preparedK16Dsc(prepared_block3, sub);
        if (comptime has_min) {
            const sum0 = q8KBlockSum16F(q8_block_r0, activation_sums_r0, sub);
            const sum1 = q8KBlockSum16F(q8_block_r1, activation_sums_r1, sub);
            const dmn0 = preparedK16Dmn(prepared_block0, sub);
            const dmn1 = preparedK16Dmn(prepared_block1, sub);
            const dmn2 = preparedK16Dmn(prepared_block2, sub);
            const dmn3 = preparedK16Dmn(prepared_block3, sub);
            acc00 += dsc0 * @as(f32, @floatFromInt(dots[0])) - dmn0 * sum0;
            acc01 += dsc1 * @as(f32, @floatFromInt(dots[1])) - dmn1 * sum0;
            acc02 += dsc2 * @as(f32, @floatFromInt(dots[2])) - dmn2 * sum0;
            acc03 += dsc3 * @as(f32, @floatFromInt(dots[3])) - dmn3 * sum0;
            acc10 += dsc0 * @as(f32, @floatFromInt(dots[4])) - dmn0 * sum1;
            acc11 += dsc1 * @as(f32, @floatFromInt(dots[5])) - dmn1 * sum1;
            acc12 += dsc2 * @as(f32, @floatFromInt(dots[6])) - dmn2 * sum1;
            acc13 += dsc3 * @as(f32, @floatFromInt(dots[7])) - dmn3 * sum1;
        } else {
            acc00 += dsc0 * @as(f32, @floatFromInt(dots[0]));
            acc01 += dsc1 * @as(f32, @floatFromInt(dots[1]));
            acc02 += dsc2 * @as(f32, @floatFromInt(dots[2]));
            acc03 += dsc3 * @as(f32, @floatFromInt(dots[3]));
            acc10 += dsc0 * @as(f32, @floatFromInt(dots[4]));
            acc11 += dsc1 * @as(f32, @floatFromInt(dots[5]));
            acc12 += dsc2 * @as(f32, @floatFromInt(dots[6]));
            acc13 += dsc3 * @as(f32, @floatFromInt(dots[7]));
        }
    }
    return .{
        x_d0 * acc00,
        x_d0 * acc01,
        x_d0 * acc02,
        x_d0 * acc03,
        x_d1 * acc10,
        x_d1 * acc11,
        x_d1 * acc12,
        x_d1 * acc13,
    };
}

inline fn dotK16PreparedQ8KBlock4MR2(
    comptime has_min: bool,
    q8_block_r0: []const u8,
    q8_block_r1: []const u8,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
) struct { f32, f32, f32, f32, f32, f32, f32, f32 } {
    return dotK16PreparedQ8KBlock4MR2WithSums(has_min, q8_block_r0, null, q8_block_r1, null, prepared_block0, prepared_block1, prepared_block2, prepared_block3);
}

inline fn dotK16PreparedQ8KBlock4MR4WithSums(
    comptime has_min: bool,
    q8_block_r0: []const u8,
    activation_sums_r0: ?*const [16]f32,
    q8_block_r1: []const u8,
    activation_sums_r1: ?*const [16]f32,
    q8_block_r2: []const u8,
    activation_sums_r2: ?*const [16]f32,
    q8_block_r3: []const u8,
    activation_sums_r3: ?*const [16]f32,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
) [16]f32 {
    const x_d0 = readF32Le(q8_block_r0[0..4]);
    const x_d1 = readF32Le(q8_block_r1[0..4]);
    const x_d2 = readF32Le(q8_block_r2[0..4]);
    const x_d3 = readF32Le(q8_block_r3[0..4]);
    const qx0 = q8_block_r0[4..260];
    const qx1 = q8_block_r1[4..260];
    const qx2 = q8_block_r2[4..260];
    const qx3 = q8_block_r3[4..260];
    var acc: [16]f32 = [_]f32{0.0} ** 16;
    for (0..16) |sub| {
        const q_off = sub * 16;
        const dots01 = dotI8I8Block4MR2_16(
            qx0[q_off..][0..16],
            qx1[q_off..][0..16],
            preparedK16Values(prepared_block0, sub),
            preparedK16Values(prepared_block1, sub),
            preparedK16Values(prepared_block2, sub),
            preparedK16Values(prepared_block3, sub),
        );
        const dots23 = dotI8I8Block4MR2_16(
            qx2[q_off..][0..16],
            qx3[q_off..][0..16],
            preparedK16Values(prepared_block0, sub),
            preparedK16Values(prepared_block1, sub),
            preparedK16Values(prepared_block2, sub),
            preparedK16Values(prepared_block3, sub),
        );
        const dsc0 = preparedK16Dsc(prepared_block0, sub);
        const dsc1 = preparedK16Dsc(prepared_block1, sub);
        const dsc2 = preparedK16Dsc(prepared_block2, sub);
        const dsc3 = preparedK16Dsc(prepared_block3, sub);
        if (comptime has_min) {
            const sum0 = q8KBlockSum16F(q8_block_r0, activation_sums_r0, sub);
            const sum1 = q8KBlockSum16F(q8_block_r1, activation_sums_r1, sub);
            const sum2 = q8KBlockSum16F(q8_block_r2, activation_sums_r2, sub);
            const sum3 = q8KBlockSum16F(q8_block_r3, activation_sums_r3, sub);
            const dmn0 = preparedK16Dmn(prepared_block0, sub);
            const dmn1 = preparedK16Dmn(prepared_block1, sub);
            const dmn2 = preparedK16Dmn(prepared_block2, sub);
            const dmn3 = preparedK16Dmn(prepared_block3, sub);
            acc[0] += dsc0 * @as(f32, @floatFromInt(dots01[0])) - dmn0 * sum0;
            acc[1] += dsc1 * @as(f32, @floatFromInt(dots01[1])) - dmn1 * sum0;
            acc[2] += dsc2 * @as(f32, @floatFromInt(dots01[2])) - dmn2 * sum0;
            acc[3] += dsc3 * @as(f32, @floatFromInt(dots01[3])) - dmn3 * sum0;
            acc[4] += dsc0 * @as(f32, @floatFromInt(dots01[4])) - dmn0 * sum1;
            acc[5] += dsc1 * @as(f32, @floatFromInt(dots01[5])) - dmn1 * sum1;
            acc[6] += dsc2 * @as(f32, @floatFromInt(dots01[6])) - dmn2 * sum1;
            acc[7] += dsc3 * @as(f32, @floatFromInt(dots01[7])) - dmn3 * sum1;
            acc[8] += dsc0 * @as(f32, @floatFromInt(dots23[0])) - dmn0 * sum2;
            acc[9] += dsc1 * @as(f32, @floatFromInt(dots23[1])) - dmn1 * sum2;
            acc[10] += dsc2 * @as(f32, @floatFromInt(dots23[2])) - dmn2 * sum2;
            acc[11] += dsc3 * @as(f32, @floatFromInt(dots23[3])) - dmn3 * sum2;
            acc[12] += dsc0 * @as(f32, @floatFromInt(dots23[4])) - dmn0 * sum3;
            acc[13] += dsc1 * @as(f32, @floatFromInt(dots23[5])) - dmn1 * sum3;
            acc[14] += dsc2 * @as(f32, @floatFromInt(dots23[6])) - dmn2 * sum3;
            acc[15] += dsc3 * @as(f32, @floatFromInt(dots23[7])) - dmn3 * sum3;
        } else {
            acc[0] += dsc0 * @as(f32, @floatFromInt(dots01[0]));
            acc[1] += dsc1 * @as(f32, @floatFromInt(dots01[1]));
            acc[2] += dsc2 * @as(f32, @floatFromInt(dots01[2]));
            acc[3] += dsc3 * @as(f32, @floatFromInt(dots01[3]));
            acc[4] += dsc0 * @as(f32, @floatFromInt(dots01[4]));
            acc[5] += dsc1 * @as(f32, @floatFromInt(dots01[5]));
            acc[6] += dsc2 * @as(f32, @floatFromInt(dots01[6]));
            acc[7] += dsc3 * @as(f32, @floatFromInt(dots01[7]));
            acc[8] += dsc0 * @as(f32, @floatFromInt(dots23[0]));
            acc[9] += dsc1 * @as(f32, @floatFromInt(dots23[1]));
            acc[10] += dsc2 * @as(f32, @floatFromInt(dots23[2]));
            acc[11] += dsc3 * @as(f32, @floatFromInt(dots23[3]));
            acc[12] += dsc0 * @as(f32, @floatFromInt(dots23[4]));
            acc[13] += dsc1 * @as(f32, @floatFromInt(dots23[5]));
            acc[14] += dsc2 * @as(f32, @floatFromInt(dots23[6]));
            acc[15] += dsc3 * @as(f32, @floatFromInt(dots23[7]));
        }
    }
    return .{
        x_d0 * acc[0],  x_d0 * acc[1],  x_d0 * acc[2],  x_d0 * acc[3],
        x_d1 * acc[4],  x_d1 * acc[5],  x_d1 * acc[6],  x_d1 * acc[7],
        x_d2 * acc[8],  x_d2 * acc[9],  x_d2 * acc[10], x_d2 * acc[11],
        x_d3 * acc[12], x_d3 * acc[13], x_d3 * acc[14], x_d3 * acc[15],
    };
}

inline fn dotK16PreparedQ8KBlock4MR4(
    comptime has_min: bool,
    q8_block_r0: []const u8,
    q8_block_r1: []const u8,
    q8_block_r2: []const u8,
    q8_block_r3: []const u8,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
) [16]f32 {
    return dotK16PreparedQ8KBlock4MR4WithSums(has_min, q8_block_r0, null, q8_block_r1, null, q8_block_r2, null, q8_block_r3, null, prepared_block0, prepared_block1, prepared_block2, prepared_block3);
}

inline fn q3KNoDmnPanelDsc(panel_block: []const u8, sub: usize) F32x4 {
    std.debug.assert(panel_block.len == prepared_q3_k_panel_block_bytes);
    return readF32x4Le(panel_block[prepared_q3_k_panel_dsc_offset + sub * prepared_q3_k_panel_nr * 4 ..][0..16]);
}

inline fn q3KNoDmnPanelValues(panel_block: []const u8, sub: usize) []const u8 {
    std.debug.assert(panel_block.len == prepared_q3_k_panel_block_bytes);
    return panel_block[prepared_q3_k_panel_values_offset + sub * prepared_q3_k_panel_nr * 16 ..][0 .. prepared_q3_k_panel_nr * 16];
}

inline fn dotQ3KNoDmnPanel4(
    q8_block: []const u8,
    panel_block: []const u8,
) struct { f32, f32, f32, f32 } {
    std.debug.assert(q8_block.len == 292);
    const qx = q8_block[4..260];
    const x_scale: F32x4 = @splat(readF32Le(q8_block[0..4]));
    var acc: F32x4 = @splat(0.0);
    inline for (0..16) |sub| {
        const q_off = sub * 16;
        const values = q3KNoDmnPanelValues(panel_block, sub);
        const dots = dotI8I8Block4_16(
            qx[q_off..][0..16],
            values[0..][0..16],
            values[16..][0..16],
            values[2 * 16 ..][0..16],
            values[3 * 16 ..][0..16],
        );
        const dots_vec: F32x4 = @floatFromInt(@as(I32x4, .{ dots[0], dots[1], dots[2], dots[3] }));
        acc += q3KNoDmnPanelDsc(panel_block, sub) * dots_vec;
    }
    const scaled = x_scale * acc;
    return .{ scaled[0], scaled[1], scaled[2], scaled[3] };
}

inline fn dotQ3KNoDmnPanel4MR2(
    q8_block_r0: []const u8,
    q8_block_r1: []const u8,
    panel_block: []const u8,
) struct { f32, f32, f32, f32, f32, f32, f32, f32 } {
    std.debug.assert(q8_block_r0.len == 292);
    std.debug.assert(q8_block_r1.len == 292);
    const qx0 = q8_block_r0[4..260];
    const qx1 = q8_block_r1[4..260];
    const x_scale0: F32x4 = @splat(readF32Le(q8_block_r0[0..4]));
    const x_scale1: F32x4 = @splat(readF32Le(q8_block_r1[0..4]));
    var acc0: F32x4 = @splat(0.0);
    var acc1: F32x4 = @splat(0.0);
    inline for (0..16) |sub| {
        const q_off = sub * 16;
        const values = q3KNoDmnPanelValues(panel_block, sub);
        const dots = dotI8I8Block4MR2_16(
            qx0[q_off..][0..16],
            qx1[q_off..][0..16],
            values[0..][0..16],
            values[16..][0..16],
            values[2 * 16 ..][0..16],
            values[3 * 16 ..][0..16],
        );
        const dsc = q3KNoDmnPanelDsc(panel_block, sub);
        const dots0: F32x4 = @floatFromInt(@as(I32x4, .{ dots[0], dots[1], dots[2], dots[3] }));
        const dots1: F32x4 = @floatFromInt(@as(I32x4, .{ dots[4], dots[5], dots[6], dots[7] }));
        acc0 += dsc * dots0;
        acc1 += dsc * dots1;
    }
    const r0 = x_scale0 * acc0;
    const r1 = x_scale1 * acc1;
    return .{ r0[0], r0[1], r0[2], r0[3], r1[0], r1[1], r1[2], r1[3] };
}

inline fn dotQ3KNoDmnPanel4MR4(
    q8_block_r0: []const u8,
    q8_block_r1: []const u8,
    q8_block_r2: []const u8,
    q8_block_r3: []const u8,
    panel_block: []const u8,
) [16]f32 {
    std.debug.assert(q8_block_r0.len == 292);
    std.debug.assert(q8_block_r1.len == 292);
    std.debug.assert(q8_block_r2.len == 292);
    std.debug.assert(q8_block_r3.len == 292);
    const qx0 = q8_block_r0[4..260];
    const qx1 = q8_block_r1[4..260];
    const qx2 = q8_block_r2[4..260];
    const qx3 = q8_block_r3[4..260];
    const x_scale0: F32x4 = @splat(readF32Le(q8_block_r0[0..4]));
    const x_scale1: F32x4 = @splat(readF32Le(q8_block_r1[0..4]));
    const x_scale2: F32x4 = @splat(readF32Le(q8_block_r2[0..4]));
    const x_scale3: F32x4 = @splat(readF32Le(q8_block_r3[0..4]));
    var acc0: F32x4 = @splat(0.0);
    var acc1: F32x4 = @splat(0.0);
    var acc2: F32x4 = @splat(0.0);
    var acc3: F32x4 = @splat(0.0);
    inline for (0..16) |sub| {
        const q_off = sub * 16;
        const values = q3KNoDmnPanelValues(panel_block, sub);
        const dots01 = dotI8I8Block4MR2_16(
            qx0[q_off..][0..16],
            qx1[q_off..][0..16],
            values[0..][0..16],
            values[16..][0..16],
            values[2 * 16 ..][0..16],
            values[3 * 16 ..][0..16],
        );
        const dots23 = dotI8I8Block4MR2_16(
            qx2[q_off..][0..16],
            qx3[q_off..][0..16],
            values[0..][0..16],
            values[16..][0..16],
            values[2 * 16 ..][0..16],
            values[3 * 16 ..][0..16],
        );
        const dsc = q3KNoDmnPanelDsc(panel_block, sub);
        const dots0: F32x4 = @floatFromInt(@as(I32x4, .{ dots01[0], dots01[1], dots01[2], dots01[3] }));
        const dots1: F32x4 = @floatFromInt(@as(I32x4, .{ dots01[4], dots01[5], dots01[6], dots01[7] }));
        const dots2: F32x4 = @floatFromInt(@as(I32x4, .{ dots23[0], dots23[1], dots23[2], dots23[3] }));
        const dots3: F32x4 = @floatFromInt(@as(I32x4, .{ dots23[4], dots23[5], dots23[6], dots23[7] }));
        acc0 += dsc * dots0;
        acc1 += dsc * dots1;
        acc2 += dsc * dots2;
        acc3 += dsc * dots3;
    }
    const r0 = x_scale0 * acc0;
    const r1 = x_scale1 * acc1;
    const r2 = x_scale2 * acc2;
    const r3 = x_scale3 * acc3;
    return .{
        r0[0], r0[1], r0[2], r0[3],
        r1[0], r1[1], r1[2], r1[3],
        r2[0], r2[1], r2[2], r2[3],
        r3[0], r3[1], r3[2], r3[3],
    };
}

inline fn k16Panel8Dsc(panel_block: []const u8, sub: usize) F32x8 {
    std.debug.assert(panel_block.len == prepared_k16_panel8_block_bytes);
    return readF32x8Le(panel_block[prepared_k16_panel8_dsc_offset + sub * prepared_k_panel8_nr * 4 ..][0..32]);
}

inline fn k16Panel8Dmn(panel_block: []const u8, sub: usize) F32x8 {
    std.debug.assert(panel_block.len == prepared_k16_panel8_block_bytes);
    return readF32x8Le(panel_block[prepared_k16_panel8_dmn_offset + sub * prepared_k_panel8_nr * 4 ..][0..32]);
}

inline fn k16Panel8Values(panel_block: []const u8, sub: usize) []const u8 {
    std.debug.assert(panel_block.len == prepared_k16_panel8_block_bytes);
    return panel_block[prepared_k16_panel8_values_offset + sub * prepared_k_panel8_nr * 16 ..][0 .. prepared_k_panel8_nr * 16];
}

inline fn dotK16PreparedQ8KPanel8Vec(comptime has_min: bool, q8_block: []const u8, panel_block: []const u8) F32x8 {
    @setEvalBranchQuota(20_000);
    std.debug.assert(q8_block.len == 292);
    std.debug.assert(panel_block.len == prepared_k16_panel8_block_bytes);
    const qx = q8_block[4..260];
    const x_scale: F32x8 = @splat(readF32Le(q8_block[0..4]));
    var acc: F32x8 = @splat(0.0);
    inline for (0..16) |sub| {
        const q_off = sub * 16;
        const dots = @as(F32x8, @floatFromInt(dotI8I8Block8ContiguousVec16(qx[q_off..][0..16], k16Panel8Values(panel_block, sub))));
        const dsc = k16Panel8Dsc(panel_block, sub);
        if (comptime has_min) {
            const dmn = k16Panel8Dmn(panel_block, sub);
            const activation_sum: F32x8 = @splat(@as(f32, @floatFromInt(q8KBlockSum16(q8_block, sub))));
            acc += dsc * dots - dmn * activation_sum;
        } else {
            acc += dsc * dots;
        }
    }
    return x_scale * acc;
}

inline fn dotK16PreparedQ8KPanel8(comptime has_min: bool, q8_block: []const u8, panel_block: []const u8) [8]f32 {
    return f32x8ToArray(dotK16PreparedQ8KPanel8Vec(has_min, q8_block, panel_block));
}

inline fn dotK16PreparedQ8KPanel8MR2Vec(
    comptime has_min: bool,
    q8_block_r0: []const u8,
    q8_block_r1: []const u8,
    panel_block: []const u8,
) Panel8MR2VecSums {
    @setEvalBranchQuota(20_000);
    std.debug.assert(q8_block_r0.len == 292);
    std.debug.assert(q8_block_r1.len == 292);
    std.debug.assert(panel_block.len == prepared_k16_panel8_block_bytes);
    const qx0 = q8_block_r0[4..260];
    const qx1 = q8_block_r1[4..260];
    const x_scale0: F32x8 = @splat(readF32Le(q8_block_r0[0..4]));
    const x_scale1: F32x8 = @splat(readF32Le(q8_block_r1[0..4]));
    var acc0: F32x8 = @splat(0.0);
    var acc1: F32x8 = @splat(0.0);
    inline for (0..16) |sub| {
        const q_off = sub * 16;
        const dots = dotI8I8Block8MR2RowsContiguousVec16(qx0[q_off..][0..16], qx1[q_off..][0..16], k16Panel8Values(panel_block, sub));
        const dsc = k16Panel8Dsc(panel_block, sub);
        const dots0: F32x8 = @floatFromInt(dots.r0);
        const dots1: F32x8 = @floatFromInt(dots.r1);
        if (comptime has_min) {
            const dmn = k16Panel8Dmn(panel_block, sub);
            const activation_sum0: F32x8 = @splat(@as(f32, @floatFromInt(q8KBlockSum16(q8_block_r0, sub))));
            const activation_sum1: F32x8 = @splat(@as(f32, @floatFromInt(q8KBlockSum16(q8_block_r1, sub))));
            acc0 += dsc * dots0 - dmn * activation_sum0;
            acc1 += dsc * dots1 - dmn * activation_sum1;
        } else {
            acc0 += dsc * dots0;
            acc1 += dsc * dots1;
        }
    }
    return .{ .r0 = x_scale0 * acc0, .r1 = x_scale1 * acc1 };
}

inline fn dotK16PreparedQ8KPanel8MR2(
