            qx2[q_off..][0..16],
            qx3[q_off..][0..16],
            k16Panel8Values(panel_block, sub),
        );
        const dsc = k16Panel8Dsc(panel_block, sub);
        const dots0: F32x8 = @floatFromInt(dots.r0);
        const dots1: F32x8 = @floatFromInt(dots.r1);
