fn validatePreparedK16ActivationBlocks(
    prepared_blocks: []const u8,
    panel_blocks: ?[]const u8,
    panel8_blocks: ?[]const u8,
    in_dim: usize,
    out_dim: usize,
) !usize {
    const values_per_block: usize = 256;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    if (prepared_blocks.len != out_dim * row_blocks * prepared_k16_block_bytes) return error.InvalidQuantizedDataSize;
    if (panel_blocks) |blocks| {
        if (blocks.len != preparedK16PanelByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;
    }
    if (panel8_blocks) |blocks| {
        if (blocks.len != preparedK16Panel8ByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;
    }
    return row_blocks;
}

fn validatePreparedK16Panel16ActivationBlocks(
    prepared_blocks: []const u8,
    panel16_blocks: []const u8,
    in_dim: usize,
    out_dim: usize,
) !usize {
    const row_blocks = try validatePreparedK16ActivationBlocks(prepared_blocks, null, null, in_dim, out_dim);
    if (panel16_blocks.len != preparedK16Panel16ByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;
    return row_blocks;
}

fn validatePreparedQ3KNoDmnPanelBlocks(
    prepared_blocks: []const u8,
    panel_blocks: []const u8,
    in_dim: usize,
    out_dim: usize,
) !usize {
    const row_blocks = try validatePreparedK16ActivationBlocks(prepared_blocks, null, null, in_dim, out_dim);
    if (panel_blocks.len != preparedQ3KNoDmnPanelByteSize(out_dim, row_blocks)) return error.InvalidQuantizedDataSize;
    return row_blocks;
}

fn k16PreparedQ8KActivationQ3NoDmnPanelApply(
    q_input: []const u8,
    prepared_blocks: []const u8,
    q3_panel_blocks: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    const row_blocks = in_dim / values_per_block;
    const prepared_row_stride = row_blocks * prepared_k16_block_bytes;
    const input_row_stride = row_blocks * q8_block_size;
    var r: usize = 0;
    while (r + 4 <= rows) : (r += 4) {
        const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
        const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
        const q_input_row2 = q_input[(r + 2) * input_row_stride ..][0..input_row_stride];
        const q_input_row3 = q_input[(r + 3) * input_row_stride ..][0..input_row_stride];
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
        const out_row2 = output[(r + 2) * out_dim ..][0..out_dim];
        const out_row3 = output[(r + 3) * out_dim ..][0..out_dim];
        var o: usize = out_start;
        while (o < out_end and (o % prepared_q3_k_panel_nr) != 0) : (o += 1) {
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            var acc2: f32 = 0.0;
            var acc3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q_off = block_idx * q8_block_size;
                const prepared_block = prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                acc0 += dotK16PreparedQ8KBlock(false, q_input_row0[q_off..][0..q8_block_size], prepared_block);
                acc1 += dotK16PreparedQ8KBlock(false, q_input_row1[q_off..][0..q8_block_size], prepared_block);
                acc2 += dotK16PreparedQ8KBlock(false, q_input_row2[q_off..][0..q8_block_size], prepared_block);
                acc3 += dotK16PreparedQ8KBlock(false, q_input_row3[q_off..][0..q8_block_size], prepared_block);
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
            out_row2[o] = acc2;
            out_row3[o] = acc3;
        }
        while (o + prepared_q3_k_panel_nr <= out_end) : (o += prepared_q3_k_panel_nr) {
            var acc: [16]f32 = [_]f32{0.0} ** 16;
            for (0..row_blocks) |block_idx| {
                const q_off = block_idx * q8_block_size;
                const panel_off = ((o / prepared_q3_k_panel_nr) * row_blocks + block_idx) * prepared_q3_k_panel_block_bytes;
                const sums = dotQ3KNoDmnPanel4MR4(
                    q_input_row0[q_off..][0..q8_block_size],
                    q_input_row1[q_off..][0..q8_block_size],
                    q_input_row2[q_off..][0..q8_block_size],
                    q_input_row3[q_off..][0..q8_block_size],
                    q3_panel_blocks[panel_off..][0..prepared_q3_k_panel_block_bytes],
                );
                inline for (0..16) |idx| acc[idx] += sums[idx];
            }
            inline for (0..prepared_q3_k_panel_nr) |lane| {
                out_row0[o + lane] = acc[lane];
                out_row1[o + lane] = acc[prepared_q3_k_panel_nr + lane];
                out_row2[o + lane] = acc[2 * prepared_q3_k_panel_nr + lane];
                out_row3[o + lane] = acc[3 * prepared_q3_k_panel_nr + lane];
            }
        }
        while (o < out_end) : (o += 1) {
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            var acc2: f32 = 0.0;
            var acc3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q_off = block_idx * q8_block_size;
                const prepared_block = prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                acc0 += dotK16PreparedQ8KBlock(false, q_input_row0[q_off..][0..q8_block_size], prepared_block);
                acc1 += dotK16PreparedQ8KBlock(false, q_input_row1[q_off..][0..q8_block_size], prepared_block);
                acc2 += dotK16PreparedQ8KBlock(false, q_input_row2[q_off..][0..q8_block_size], prepared_block);
                acc3 += dotK16PreparedQ8KBlock(false, q_input_row3[q_off..][0..q8_block_size], prepared_block);
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
            out_row2[o] = acc2;
            out_row3[o] = acc3;
        }
    }
    while (r + 2 <= rows) : (r += 2) {
        const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
        const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
        var o: usize = out_start;
        while (o < out_end and (o % prepared_q3_k_panel_nr) != 0) : (o += 1) {
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const prepared_block = prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                acc0 += dotK16PreparedQ8KBlock(false, q_input_row0[block_idx * q8_block_size ..][0..q8_block_size], prepared_block);
                acc1 += dotK16PreparedQ8KBlock(false, q_input_row1[block_idx * q8_block_size ..][0..q8_block_size], prepared_block);
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
        }
        while (o + prepared_q3_k_panel_nr <= out_end) : (o += prepared_q3_k_panel_nr) {
            var acc: [8]f32 = [_]f32{0.0} ** 8;
            for (0..row_blocks) |block_idx| {
                const panel_off = ((o / prepared_q3_k_panel_nr) * row_blocks + block_idx) * prepared_q3_k_panel_block_bytes;
                const sums = dotQ3KNoDmnPanel4MR2(
                    q_input_row0[block_idx * q8_block_size ..][0..q8_block_size],
                    q_input_row1[block_idx * q8_block_size ..][0..q8_block_size],
