                acc0 += dotK16PreparedQ8KBlock(false, q_input_row0[q_off..][0..q8_block_size], prepared_block);
                acc1 += dotK16PreparedQ8KBlock(false, q_input_row1[q_off..][0..q8_block_size], prepared_block);
