                acc12 += sums[6];
                acc13 += sums[7];
            }
            out_row0[o] = acc00;
            out_row0[o + 1] = acc01;
            out_row0[o + 2] = acc02;
            out_row0[o + 3] = acc03;
            out_row1[o] = acc10;
            out_row1[o + 1] = acc11;
            out_row1[o + 2] = acc12;
