                const q_off = block_idx * q8_block_size;
                const prepared_block = prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                acc0 += dotK16PreparedQ8KBlock(has_min, q_input_row0[q_off..][0..q8_block_size], prepared_block);
                acc1 += dotK16PreparedQ8KBlock(has_min, q_input_row1[q_off..][0..q8_block_size], prepared_block);
