                const q2 = q_input_row2[q_off..][0..q8_block_size];
                const q3 = q_input_row3[q_off..][0..q8_block_size];
                const sums_lo = dotK16PreparedQ8KPanel8MR4Vec(has_min, q0, q1, q2, q3, panel_lo);
                const sums_hi = dotK16PreparedQ8KPanel8MR4Vec(has_min, q0, q1, q2, q3, panel_hi);
                acc0_lo += sums_lo.r0;
                acc0_hi += sums_hi.r0;
                acc1_lo += sums_lo.r1;
                acc1_hi += sums_hi.r1;
                acc2_lo += sums_lo.r2;
                acc2_hi += sums_hi.r2;
                acc3_lo += sums_lo.r3;
                acc3_hi += sums_hi.r3;
            }
            storeF32x8(out_row0, o, acc0_lo);
            storeF32x8(out_row0, o + prepared_k_panel8_nr, acc0_hi);
            storeF32x8(out_row1, o, acc1_lo);
            storeF32x8(out_row1, o + prepared_k_panel8_nr, acc1_hi);
            storeF32x8(out_row2, o, acc2_lo);
            storeF32x8(out_row2, o + prepared_k_panel8_nr, acc2_hi);
            storeF32x8(out_row3, o, acc3_lo);
            storeF32x8(out_row3, o + prepared_k_panel8_nr, acc3_hi);
        }
        while (o < out_end) : (o += 1) {
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            var acc2: f32 = 0.0;
            var acc3: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const q_off = block_idx * q8_block_size;
                const prepared_block = prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                acc0 += dotK16PreparedQ8KBlock(has_min, q_input_row0[q_off..][0..q8_block_size], prepared_block);
                acc1 += dotK16PreparedQ8KBlock(has_min, q_input_row1[q_off..][0..q8_block_size], prepared_block);
                acc2 += dotK16PreparedQ8KBlock(has_min, q_input_row2[q_off..][0..q8_block_size], prepared_block);
                acc3 += dotK16PreparedQ8KBlock(has_min, q_input_row3[q_off..][0..q8_block_size], prepared_block);
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
            out_row2[o] = acc2;
            out_row3[o] = acc3;
        }
    }
    while (r + 2 <= rows) : (r += 2) {
        const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
        const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
        var o: usize = out_start;
