                acc0 += dotK16PreparedQ8KBlock(has_min, q_input_row0[block_idx * q8_block_size ..][0..q8_block_size], prepared_block);
                acc1 += dotK16PreparedQ8KBlock(has_min, q_input_row1[block_idx * q8_block_size ..][0..q8_block_size], prepared_block);
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
        }
        while (o + prepared_k_panel16_nr <= out_end) : (o += prepared_k_panel16_nr) {
            var acc0_lo: F32x8 = @splat(0.0);
            var acc0_hi: F32x8 = @splat(0.0);
            var acc1_lo: F32x8 = @splat(0.0);
            var acc1_hi: F32x8 = @splat(0.0);
            for (0..row_blocks) |block_idx| {
                const q_off = block_idx * q8_block_size;
                const panel_off = ((o / prepared_k_panel16_nr) * row_blocks + block_idx) * prepared_k16_panel16_block_bytes;
                const panel_lo = panel16_blocks[panel_off..][0..prepared_k16_panel8_block_bytes];
                const panel_hi = panel16_blocks[panel_off + prepared_k16_panel8_block_bytes ..][0..prepared_k16_panel8_block_bytes];
                const q0 = q_input_row0[q_off..][0..q8_block_size];
                const q1 = q_input_row1[q_off..][0..q8_block_size];
                const sums_lo = dotK16PreparedQ8KPanel8MR2Vec(has_min, q0, q1, panel_lo);
                const sums_hi = dotK16PreparedQ8KPanel8MR2Vec(has_min, q0, q1, panel_hi);
                acc0_lo += sums_lo.r0;
                acc0_hi += sums_hi.r0;
                acc1_lo += sums_lo.r1;
                acc1_hi += sums_hi.r1;
            }
            storeF32x8(out_row0, o, acc0_lo);
            storeF32x8(out_row0, o + prepared_k_panel8_nr, acc0_hi);
            storeF32x8(out_row1, o, acc1_lo);
            storeF32x8(out_row1, o + prepared_k_panel8_nr, acc1_hi);
        }
        while (o < out_end) : (o += 1) {
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            for (0..row_blocks) |block_idx| {
                const prepared_block = prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
