}

fn k16PreparedQ8KActivationApply(
    comptime has_min: bool,
    q_input: []const u8,
    prepared_blocks: []const u8,
    panel_blocks: ?[]const u8,
    panel8_blocks: ?[]const u8,
    bias: ?[]const f32,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    const row_blocks = in_dim / values_per_block;
    const prepared_row_stride = row_blocks * prepared_k16_block_bytes;
    const input_row_stride = row_blocks * q8_block_size;
    if (comptime !has_min) {
        if (k16Rows3DirectEnabled() and row_blocks == 3 and panel8_blocks == null and bias == null) {
            k16PreparedQ8KActivationRows3NoMinApply(q_input, prepared_blocks, panel_blocks, output, rows, out_dim, out_start, out_end);
            return;
        }
    }
    var r: usize = 0;
    if (panel8_blocks == null) {
        while (r + 4 <= rows) : (r += 4) {
            const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
            const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
            const q_input_row2 = q_input[(r + 2) * input_row_stride ..][0..input_row_stride];
            const q_input_row3 = q_input[(r + 3) * input_row_stride ..][0..input_row_stride];
            const out_row0 = output[r * out_dim ..][0..out_dim];
            const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
            const out_row2 = output[(r + 2) * out_dim ..][0..out_dim];
            const out_row3 = output[(r + 3) * out_dim ..][0..out_dim];
            const use_prepared_sums = has_min and k16PreparedQ8SumsEnabledFor(rows, out_dim, row_blocks) and row_blocks <= q8_k_prepared_sum_stack_max_row_blocks;
            var activation_sums0: [q8_k_prepared_sum_stack_max_row_blocks][16]f32 = undefined;
            var activation_sums1: [q8_k_prepared_sum_stack_max_row_blocks][16]f32 = undefined;
            var activation_sums2: [q8_k_prepared_sum_stack_max_row_blocks][16]f32 = undefined;
            var activation_sums3: [q8_k_prepared_sum_stack_max_row_blocks][16]f32 = undefined;
            if (comptime has_min) {
                if (use_prepared_sums) {
                    for (0..row_blocks) |block_idx| {
                        const off = block_idx * q8_block_size;
                        prepareQ8KActivationSums16(q_input_row0[off..][0..q8_block_size], &activation_sums0[block_idx]);
                        prepareQ8KActivationSums16(q_input_row1[off..][0..q8_block_size], &activation_sums1[block_idx]);
                        prepareQ8KActivationSums16(q_input_row2[off..][0..q8_block_size], &activation_sums2[block_idx]);
                        prepareQ8KActivationSums16(q_input_row3[off..][0..q8_block_size], &activation_sums3[block_idx]);
                    }
                }
            }
            var o: usize = out_start;
            while (o < out_end and (o % prepared_q8_0_panel_nr) != 0) : (o += 1) {
                var acc0 = optionalLinearBiasAt(bias, o);
                var acc1 = acc0;
                var acc2 = acc0;
                var acc3 = acc0;
                for (0..row_blocks) |block_idx| {
                    const prepared_block = prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                    const off = block_idx * q8_block_size;
                    acc0 += dotK16PreparedQ8KBlock(has_min, q_input_row0[off..][0..q8_block_size], prepared_block);
                    acc1 += dotK16PreparedQ8KBlock(has_min, q_input_row1[off..][0..q8_block_size], prepared_block);
                    acc2 += dotK16PreparedQ8KBlock(has_min, q_input_row2[off..][0..q8_block_size], prepared_block);
                    acc3 += dotK16PreparedQ8KBlock(has_min, q_input_row3[off..][0..q8_block_size], prepared_block);
                }
                out_row0[o] = acc0;
                out_row1[o] = acc1;
                out_row2[o] = acc2;
                out_row3[o] = acc3;
            }
            while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
                var acc00 = optionalLinearBiasAt(bias, o);
                var acc01 = optionalLinearBiasAt(bias, o + 1);
                var acc02 = optionalLinearBiasAt(bias, o + 2);
                var acc03 = optionalLinearBiasAt(bias, o + 3);
                var acc10 = acc00;
                var acc11 = acc01;
                var acc12 = acc02;
                var acc13 = acc03;
                var acc20 = acc00;
                var acc21 = acc01;
                var acc22 = acc02;
                var acc23 = acc03;
                var acc30 = acc00;
                var acc31 = acc01;
                var acc32 = acc02;
                var acc33 = acc03;
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * q8_block_size;
                    const sums0 = if (use_prepared_sums) &activation_sums0[block_idx] else null;
                    const sums1 = if (use_prepared_sums) &activation_sums1[block_idx] else null;
                    const sums2 = if (use_prepared_sums) &activation_sums2[block_idx] else null;
                    const sums3 = if (use_prepared_sums) &activation_sums3[block_idx] else null;
                    const sums = dotK16PreparedQ8KBlock4MR4WithSums(
                        has_min,
                        q_input_row0[off..][0..q8_block_size],
                        sums0,
                        q_input_row1[off..][0..q8_block_size],
                        sums1,
                        q_input_row2[off..][0..q8_block_size],
                        sums2,
                        q_input_row3[off..][0..q8_block_size],
                        sums3,
                        preparedK16PanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 0),
                        preparedK16PanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 1),
                        preparedK16PanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 2),
                        preparedK16PanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 3),
                    );
                    acc00 += sums[0];
                    acc01 += sums[1];
                    acc02 += sums[2];
                    acc03 += sums[3];
                    acc10 += sums[4];
                    acc11 += sums[5];
                    acc12 += sums[6];
                    acc13 += sums[7];
                    acc20 += sums[8];
                    acc21 += sums[9];
                    acc22 += sums[10];
                    acc23 += sums[11];
                    acc30 += sums[12];
                    acc31 += sums[13];
                    acc32 += sums[14];
                    acc33 += sums[15];
                }
                out_row0[o] = acc00;
                out_row0[o + 1] = acc01;
                out_row0[o + 2] = acc02;
                out_row0[o + 3] = acc03;
                out_row1[o] = acc10;
                out_row1[o + 1] = acc11;
                out_row1[o + 2] = acc12;
                out_row1[o + 3] = acc13;
                out_row2[o] = acc20;
                out_row2[o + 1] = acc21;
                out_row2[o + 2] = acc22;
                out_row2[o + 3] = acc23;
                out_row3[o] = acc30;
                out_row3[o + 1] = acc31;
                out_row3[o + 2] = acc32;
                out_row3[o + 3] = acc33;
            }
            while (o < out_end) : (o += 1) {
                var acc0 = optionalLinearBiasAt(bias, o);
                var acc1 = acc0;
                var acc2 = acc0;
                var acc3 = acc0;
                for (0..row_blocks) |block_idx| {
                    const prepared_block = prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                    const off = block_idx * q8_block_size;
                    acc0 += dotK16PreparedQ8KBlock(has_min, q_input_row0[off..][0..q8_block_size], prepared_block);
                    acc1 += dotK16PreparedQ8KBlock(has_min, q_input_row1[off..][0..q8_block_size], prepared_block);
                    acc2 += dotK16PreparedQ8KBlock(has_min, q_input_row2[off..][0..q8_block_size], prepared_block);
                    acc3 += dotK16PreparedQ8KBlock(has_min, q_input_row3[off..][0..q8_block_size], prepared_block);
                }
                out_row0[o] = acc0;
                out_row1[o] = acc1;
                out_row2[o] = acc2;
                out_row3[o] = acc3;
            }
        }
    }
    if (panel8_blocks) |panel8| {
        while (r + 4 <= rows) : (r += 4) {
            const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
            const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
            const q_input_row2 = q_input[(r + 2) * input_row_stride ..][0..input_row_stride];
            const q_input_row3 = q_input[(r + 3) * input_row_stride ..][0..input_row_stride];
            const out_row0 = output[r * out_dim ..][0..out_dim];
            const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
            const out_row2 = output[(r + 2) * out_dim ..][0..out_dim];
            const out_row3 = output[(r + 3) * out_dim ..][0..out_dim];
            var o: usize = out_start;
            while (o < out_end and (o % prepared_k_panel8_nr) != 0) : (o += 1) {
                var acc0 = optionalLinearBiasAt(bias, o);
                var acc1 = acc0;
                var acc2 = acc0;
                var acc3 = acc0;
                for (0..row_blocks) |block_idx| {
                    const prepared_block = prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                    const off = block_idx * q8_block_size;
                    acc0 += dotK16PreparedQ8KBlock(has_min, q_input_row0[off..][0..q8_block_size], prepared_block);
                    acc1 += dotK16PreparedQ8KBlock(has_min, q_input_row1[off..][0..q8_block_size], prepared_block);
                    acc2 += dotK16PreparedQ8KBlock(has_min, q_input_row2[off..][0..q8_block_size], prepared_block);
                    acc3 += dotK16PreparedQ8KBlock(has_min, q_input_row3[off..][0..q8_block_size], prepared_block);
                }
                out_row0[o] = acc0;
                out_row1[o] = acc1;
                out_row2[o] = acc2;
                out_row3[o] = acc3;
            }
            while (o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc0 = optionalLinearBiasVec8(bias, o);
                var acc1 = acc0;
                var acc2 = acc0;
                var acc3 = acc0;
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * q8_block_size;
                    const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_k16_panel8_block_bytes;
                    const sums = dotK16PreparedQ8KPanel8MR4Vec(
                        has_min,
                        q_input_row0[off..][0..q8_block_size],
                        q_input_row1[off..][0..q8_block_size],
                        q_input_row2[off..][0..q8_block_size],
                        q_input_row3[off..][0..q8_block_size],
                        panel8[panel_off..][0..prepared_k16_panel8_block_bytes],
                    );
                    acc0 += sums.r0;
                    acc1 += sums.r1;
                    acc2 += sums.r2;
                    acc3 += sums.r3;
                }
                storeF32x8(out_row0, o, acc0);
                storeF32x8(out_row1, o, acc1);
                storeF32x8(out_row2, o, acc2);
                storeF32x8(out_row3, o, acc3);
            }
            while (o < out_end) : (o += 1) {
                var acc0 = optionalLinearBiasAt(bias, o);
                var acc1 = acc0;
                var acc2 = acc0;
                var acc3 = acc0;
                for (0..row_blocks) |block_idx| {
                    const prepared_block = prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                    const off = block_idx * q8_block_size;
                    acc0 += dotK16PreparedQ8KBlock(has_min, q_input_row0[off..][0..q8_block_size], prepared_block);
                    acc1 += dotK16PreparedQ8KBlock(has_min, q_input_row1[off..][0..q8_block_size], prepared_block);
                    acc2 += dotK16PreparedQ8KBlock(has_min, q_input_row2[off..][0..q8_block_size], prepared_block);
                    acc3 += dotK16PreparedQ8KBlock(has_min, q_input_row3[off..][0..q8_block_size], prepared_block);
                }
                out_row0[o] = acc0;
                out_row1[o] = acc1;
                out_row2[o] = acc2;
                out_row3[o] = acc3;
            }
        }
    }
    while (r + 1 < rows) : (r += 2) {
        const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
        const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
        const out_row0 = output[r * out_dim ..][0..out_dim];
        const out_row1 = output[(r + 1) * out_dim ..][0..out_dim];
        var o: usize = out_start;
        const panel_align: usize = if (panel8_blocks != null) prepared_k_panel8_nr else prepared_q8_0_panel_nr;
        while (o < out_end and (o % panel_align) != 0) : (o += 1) {
            var acc0 = optionalLinearBiasAt(bias, o);
            var acc1 = acc0;
            for (0..row_blocks) |block_idx| {
                const prepared_block = prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                acc0 += dotK16PreparedQ8KBlock(has_min, q_input_row0[block_idx * q8_block_size ..][0..q8_block_size], prepared_block);
                acc1 += dotK16PreparedQ8KBlock(has_min, q_input_row1[block_idx * q8_block_size ..][0..q8_block_size], prepared_block);
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
        }
        if (panel8_blocks) |panel8| {
            while (o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc0 = optionalLinearBiasVec8(bias, o);
                var acc1 = acc0;
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * q8_block_size;
                    const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_k16_panel8_block_bytes;
                    const sums = dotK16PreparedQ8KPanel8MR2Vec(
                        has_min,
                        q_input_row0[off..][0..q8_block_size],
                        q_input_row1[off..][0..q8_block_size],
                        panel8[panel_off..][0..prepared_k16_panel8_block_bytes],
                    );
                    acc0 += sums.r0;
                    acc1 += sums.r1;
                }
                storeF32x8(out_row0, o, acc0);
                storeF32x8(out_row1, o, acc1);
            }
        }
        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc00 = optionalLinearBiasAt(bias, o);
            var acc01 = optionalLinearBiasAt(bias, o + 1);
            var acc02 = optionalLinearBiasAt(bias, o + 2);
            var acc03 = optionalLinearBiasAt(bias, o + 3);
            var acc10 = acc00;
            var acc11 = acc01;
            var acc12 = acc02;
            var acc13 = acc03;
            for (0..row_blocks) |block_idx| {
                const sums = dotK16PreparedQ8KBlock4MR2(
                    has_min,
                    q_input_row0[block_idx * q8_block_size ..][0..q8_block_size],
                    q_input_row1[block_idx * q8_block_size ..][0..q8_block_size],
                    preparedK16PanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 0),
                    preparedK16PanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 1),
                    preparedK16PanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 2),
                    preparedK16PanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 3),
                );
                acc00 += sums[0];
                acc01 += sums[1];
                acc02 += sums[2];
                acc03 += sums[3];
                acc10 += sums[4];
                acc11 += sums[5];
                acc12 += sums[6];
                acc13 += sums[7];
            }
            out_row0[o] = acc00;
            out_row0[o + 1] = acc01;
            out_row0[o + 2] = acc02;
            out_row0[o + 3] = acc03;
            out_row1[o] = acc10;
            out_row1[o + 1] = acc11;
            out_row1[o + 2] = acc12;
            out_row1[o + 3] = acc13;
        }
        while (o < out_end) : (o += 1) {
            var acc0 = optionalLinearBiasAt(bias, o);
            var acc1 = acc0;
            for (0..row_blocks) |block_idx| {
                const prepared_block = prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                acc0 += dotK16PreparedQ8KBlock(has_min, q_input_row0[block_idx * q8_block_size ..][0..q8_block_size], prepared_block);
                acc1 += dotK16PreparedQ8KBlock(has_min, q_input_row1[block_idx * q8_block_size ..][0..q8_block_size], prepared_block);
            }
            out_row0[o] = acc0;
            out_row1[o] = acc1;
        }
    }

    while (r < rows) : (r += 1) {
        const q_input_row = q_input[r * input_row_stride ..][0..input_row_stride];
        const out_row = output[r * out_dim ..][0..out_dim];
        var o: usize = out_start;
        const panel_align: usize = if (panel8_blocks != null) prepared_k_panel8_nr else prepared_q8_0_panel_nr;
        while (o < out_end and (o % panel_align) != 0) : (o += 1) {
            var acc = optionalLinearBiasAt(bias, o);
            for (0..row_blocks) |block_idx| {
                acc += dotK16PreparedQ8KBlock(
                    has_min,
                    q_input_row[block_idx * q8_block_size ..][0..q8_block_size],
                    prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes],
                );
            }
            out_row[o] = acc;
        }
        if (panel8_blocks) |panel8| {
            while (o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc = optionalLinearBiasVec8(bias, o);
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * q8_block_size;
                    const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_k16_panel8_block_bytes;
                    const sums = dotK16PreparedQ8KPanel8Vec(
                        has_min,
                        q_input_row[off..][0..q8_block_size],
                        panel8[panel_off..][0..prepared_k16_panel8_block_bytes],
                    );
                    acc += sums;
                }
                storeF32x8(out_row, o, acc);
            }
        }
        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc0 = optionalLinearBiasAt(bias, o);
            var acc1 = optionalLinearBiasAt(bias, o + 1);
            var acc2 = optionalLinearBiasAt(bias, o + 2);
            var acc3 = optionalLinearBiasAt(bias, o + 3);
            for (0..row_blocks) |block_idx| {
                const sums = dotK16PreparedQ8KBlock4(
                    has_min,
                    q_input_row[block_idx * q8_block_size ..][0..q8_block_size],
                    preparedK16PanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 0),
                    preparedK16PanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 1),
                    preparedK16PanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 2),
                    preparedK16PanelBlock(panel_blocks, prepared_blocks, row_blocks, prepared_row_stride, o, block_idx, 3),
                );
                acc0 += sums[0];
                acc1 += sums[1];
                acc2 += sums[2];
                acc3 += sums[3];
            }
            out_row[o] = acc0;
            out_row[o + 1] = acc1;
            out_row[o + 2] = acc2;
            out_row[o + 3] = acc3;
        }
        while (o < out_end) : (o += 1) {
            var acc = optionalLinearBiasAt(bias, o);
            for (0..row_blocks) |block_idx| {
                acc += dotK16PreparedQ8KBlock(
                    has_min,
                    q_input_row[block_idx * q8_block_size ..][0..q8_block_size],
                    prepared_blocks[o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes],
                );
            }
            out_row[o] = acc;
        }
    }
}

fn k16PreparedQ8KActivationGroupedApply(
    comptime has_min: bool,
    comptime projection_count: usize,
    q_input: []const u8,
    prepared_blocks: [projection_count][]const u8,
    panel_blocks: [projection_count]?[]const u8,
    panel8_blocks: [projection_count]?[]const u8,
    biases: [projection_count]?[]const f32,
    outputs: [projection_count][]f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    const row_blocks = in_dim / values_per_block;
    const prepared_row_stride = row_blocks * prepared_k16_block_bytes;
    const input_row_stride = row_blocks * q8_block_size;
    var r: usize = 0;
    if (panel8_blocks[0] == null) {
        while (r + 3 < rows) : (r += 4) {
            const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
            const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
            const q_input_row2 = q_input[(r + 2) * input_row_stride ..][0..input_row_stride];
            const q_input_row3 = q_input[(r + 3) * input_row_stride ..][0..input_row_stride];
            const use_prepared_sums = has_min and k16PreparedQ8SumsEnabledFor(rows, out_dim, row_blocks) and row_blocks <= q8_k_prepared_sum_stack_max_row_blocks;
            var activation_sums0: [q8_k_prepared_sum_stack_max_row_blocks][16]f32 = undefined;
            var activation_sums1: [q8_k_prepared_sum_stack_max_row_blocks][16]f32 = undefined;
            var activation_sums2: [q8_k_prepared_sum_stack_max_row_blocks][16]f32 = undefined;
            var activation_sums3: [q8_k_prepared_sum_stack_max_row_blocks][16]f32 = undefined;
            if (comptime has_min) {
                if (use_prepared_sums) {
                    for (0..row_blocks) |block_idx| {
                        const off = block_idx * q8_block_size;
                        prepareQ8KActivationSums16(q_input_row0[off..][0..q8_block_size], &activation_sums0[block_idx]);
                        prepareQ8KActivationSums16(q_input_row1[off..][0..q8_block_size], &activation_sums1[block_idx]);
                        prepareQ8KActivationSums16(q_input_row2[off..][0..q8_block_size], &activation_sums2[block_idx]);
                        prepareQ8KActivationSums16(q_input_row3[off..][0..q8_block_size], &activation_sums3[block_idx]);
                    }
                }
            }
            var o: usize = out_start;
            while (o < out_end and (o % prepared_q8_0_panel_nr) != 0) : (o += 1) {
                var acc0: [projection_count]f32 = undefined;
                var acc1: [projection_count]f32 = undefined;
                var acc2: [projection_count]f32 = undefined;
                var acc3: [projection_count]f32 = undefined;
                inline for (0..projection_count) |projection_idx| {
                    const bias_value = optionalLinearBiasAt(biases[projection_idx], o);
                    acc0[projection_idx] = bias_value;
                    acc1[projection_idx] = bias_value;
                    acc2[projection_idx] = bias_value;
                    acc3[projection_idx] = bias_value;
                }
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * q8_block_size;
                    inline for (0..projection_count) |projection_idx| {
                        const prepared_block = prepared_blocks[projection_idx][o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                        acc0[projection_idx] += dotK16PreparedQ8KBlock(has_min, q_input_row0[off..][0..q8_block_size], prepared_block);
                        acc1[projection_idx] += dotK16PreparedQ8KBlock(has_min, q_input_row1[off..][0..q8_block_size], prepared_block);
                        acc2[projection_idx] += dotK16PreparedQ8KBlock(has_min, q_input_row2[off..][0..q8_block_size], prepared_block);
                        acc3[projection_idx] += dotK16PreparedQ8KBlock(has_min, q_input_row3[off..][0..q8_block_size], prepared_block);
                    }
                }
                inline for (0..projection_count) |projection_idx| {
                    outputs[projection_idx][r * out_dim + o] = acc0[projection_idx];
                    outputs[projection_idx][(r + 1) * out_dim + o] = acc1[projection_idx];
                    outputs[projection_idx][(r + 2) * out_dim + o] = acc2[projection_idx];
                    outputs[projection_idx][(r + 3) * out_dim + o] = acc3[projection_idx];
                }
            }
            while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
                var acc0: [projection_count][prepared_q8_0_panel_nr]f32 = undefined;
                var acc1: [projection_count][prepared_q8_0_panel_nr]f32 = undefined;
                var acc2: [projection_count][prepared_q8_0_panel_nr]f32 = undefined;
                var acc3: [projection_count][prepared_q8_0_panel_nr]f32 = undefined;
                inline for (0..projection_count) |projection_idx| {
                    inline for (0..prepared_q8_0_panel_nr) |lane| {
                        const bias_value = optionalLinearBiasAt(biases[projection_idx], o + lane);
                        acc0[projection_idx][lane] = bias_value;
                        acc1[projection_idx][lane] = bias_value;
                        acc2[projection_idx][lane] = bias_value;
                        acc3[projection_idx][lane] = bias_value;
                    }
                }
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * q8_block_size;
                    const sums0 = if (use_prepared_sums) &activation_sums0[block_idx] else null;
                    const sums1 = if (use_prepared_sums) &activation_sums1[block_idx] else null;
                    const sums2 = if (use_prepared_sums) &activation_sums2[block_idx] else null;
                    const sums3 = if (use_prepared_sums) &activation_sums3[block_idx] else null;
                    inline for (0..projection_count) |projection_idx| {
                        const sums = dotK16PreparedQ8KBlock4MR4WithSums(
                            has_min,
                            q_input_row0[off..][0..q8_block_size],
                            sums0,
                            q_input_row1[off..][0..q8_block_size],
                            sums1,
                            q_input_row2[off..][0..q8_block_size],
                            sums2,
                            q_input_row3[off..][0..q8_block_size],
                            sums3,
                            preparedK16PanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 0),
                            preparedK16PanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 1),
                            preparedK16PanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 2),
                            preparedK16PanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 3),
                        );
                        inline for (0..prepared_q8_0_panel_nr) |lane| {
                            acc0[projection_idx][lane] += sums[lane];
                            acc1[projection_idx][lane] += sums[prepared_q8_0_panel_nr + lane];
                            acc2[projection_idx][lane] += sums[2 * prepared_q8_0_panel_nr + lane];
                            acc3[projection_idx][lane] += sums[3 * prepared_q8_0_panel_nr + lane];
                        }
                    }
                }
                inline for (0..projection_count) |projection_idx| {
                    const out_row0 = outputs[projection_idx][r * out_dim ..][0..out_dim];
                    const out_row1 = outputs[projection_idx][(r + 1) * out_dim ..][0..out_dim];
                    const out_row2 = outputs[projection_idx][(r + 2) * out_dim ..][0..out_dim];
                    const out_row3 = outputs[projection_idx][(r + 3) * out_dim ..][0..out_dim];
                    inline for (0..prepared_q8_0_panel_nr) |lane| {
                        out_row0[o + lane] = acc0[projection_idx][lane];
                        out_row1[o + lane] = acc1[projection_idx][lane];
                        out_row2[o + lane] = acc2[projection_idx][lane];
                        out_row3[o + lane] = acc3[projection_idx][lane];
                    }
                }
            }
            while (o < out_end) : (o += 1) {
                var acc0: [projection_count]f32 = undefined;
                var acc1: [projection_count]f32 = undefined;
                var acc2: [projection_count]f32 = undefined;
                var acc3: [projection_count]f32 = undefined;
                inline for (0..projection_count) |projection_idx| {
                    const bias_value = optionalLinearBiasAt(biases[projection_idx], o);
                    acc0[projection_idx] = bias_value;
                    acc1[projection_idx] = bias_value;
                    acc2[projection_idx] = bias_value;
                    acc3[projection_idx] = bias_value;
                }
                for (0..row_blocks) |block_idx| {
                    const off = block_idx * q8_block_size;
                    inline for (0..projection_count) |projection_idx| {
                        const prepared_block = prepared_blocks[projection_idx][o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                        acc0[projection_idx] += dotK16PreparedQ8KBlock(has_min, q_input_row0[off..][0..q8_block_size], prepared_block);
                        acc1[projection_idx] += dotK16PreparedQ8KBlock(has_min, q_input_row1[off..][0..q8_block_size], prepared_block);
                        acc2[projection_idx] += dotK16PreparedQ8KBlock(has_min, q_input_row2[off..][0..q8_block_size], prepared_block);
                        acc3[projection_idx] += dotK16PreparedQ8KBlock(has_min, q_input_row3[off..][0..q8_block_size], prepared_block);
                    }
                }
                inline for (0..projection_count) |projection_idx| {
                    outputs[projection_idx][r * out_dim + o] = acc0[projection_idx];
                    outputs[projection_idx][(r + 1) * out_dim + o] = acc1[projection_idx];
                    outputs[projection_idx][(r + 2) * out_dim + o] = acc2[projection_idx];
                    outputs[projection_idx][(r + 3) * out_dim + o] = acc3[projection_idx];
                }
            }
        }
    }
    while (r + 1 < rows) : (r += 2) {
        const q_input_row0 = q_input[r * input_row_stride ..][0..input_row_stride];
        const q_input_row1 = q_input[(r + 1) * input_row_stride ..][0..input_row_stride];
        var o: usize = out_start;
        const panel_align: usize = if (panel8_blocks[0] != null) prepared_k_panel8_nr else prepared_q8_0_panel_nr;
        while (o < out_end and (o % panel_align) != 0) : (o += 1) {
            var acc0: [projection_count]f32 = undefined;
            var acc1: [projection_count]f32 = undefined;
            inline for (0..projection_count) |projection_idx| {
                acc0[projection_idx] = optionalLinearBiasAt(biases[projection_idx], o);
                acc1[projection_idx] = acc0[projection_idx];
            }
            for (0..row_blocks) |block_idx| {
                const q0 = q_input_row0[block_idx * q8_block_size ..][0..q8_block_size];
                const q1 = q_input_row1[block_idx * q8_block_size ..][0..q8_block_size];
                inline for (0..projection_count) |projection_idx| {
                    const prepared_block = prepared_blocks[projection_idx][o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                    acc0[projection_idx] += dotK16PreparedQ8KBlock(has_min, q0, prepared_block);
                    acc1[projection_idx] += dotK16PreparedQ8KBlock(has_min, q1, prepared_block);
                }
            }
            inline for (0..projection_count) |projection_idx| {
                outputs[projection_idx][r * out_dim + o] = acc0[projection_idx];
                outputs[projection_idx][(r + 1) * out_dim + o] = acc1[projection_idx];
            }
        }
        if (panel8_blocks[0] != null) {
            while (o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc0: [projection_count]F32x8 = undefined;
                var acc1: [projection_count]F32x8 = undefined;
                inline for (0..projection_count) |projection_idx| {
                    acc0[projection_idx] = optionalLinearBiasVec8(biases[projection_idx], o);
                    acc1[projection_idx] = acc0[projection_idx];
                }
                for (0..row_blocks) |block_idx| {
                    const q0 = q_input_row0[block_idx * q8_block_size ..][0..q8_block_size];
                    const q1 = q_input_row1[block_idx * q8_block_size ..][0..q8_block_size];
                    inline for (0..projection_count) |projection_idx| {
                        if (panel8_blocks[projection_idx]) |panel8| {
                            const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_k16_panel8_block_bytes;
                            const sums = dotK16PreparedQ8KPanel8MR2Vec(has_min, q0, q1, panel8[panel_off..][0..prepared_k16_panel8_block_bytes]);
                            acc0[projection_idx] += sums.r0;
                            acc1[projection_idx] += sums.r1;
                        }
                    }
                }
                inline for (0..projection_count) |projection_idx| {
                    const out_row0 = outputs[projection_idx][r * out_dim ..][0..out_dim];
                    const out_row1 = outputs[projection_idx][(r + 1) * out_dim ..][0..out_dim];
                    storeF32x8(out_row0, o, acc0[projection_idx]);
                    storeF32x8(out_row1, o, acc1[projection_idx]);
                }
            }
        }
        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc0: [projection_count][4]f32 = undefined;
            var acc1: [projection_count][4]f32 = undefined;
            inline for (0..projection_count) |projection_idx| {
                acc0[projection_idx] = .{
                    optionalLinearBiasAt(biases[projection_idx], o),
                    optionalLinearBiasAt(biases[projection_idx], o + 1),
                    optionalLinearBiasAt(biases[projection_idx], o + 2),
                    optionalLinearBiasAt(biases[projection_idx], o + 3),
                };
                acc1[projection_idx] = acc0[projection_idx];
            }
            for (0..row_blocks) |block_idx| {
                const q0 = q_input_row0[block_idx * q8_block_size ..][0..q8_block_size];
                const q1 = q_input_row1[block_idx * q8_block_size ..][0..q8_block_size];
                inline for (0..projection_count) |projection_idx| {
                    const sums = dotK16PreparedQ8KBlock4MR2(
                        has_min,
                        q0,
                        q1,
                        preparedK16PanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 0),
                        preparedK16PanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 1),
                        preparedK16PanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 2),
                        preparedK16PanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 3),
                    );
                    inline for (0..4) |lane| {
                        acc0[projection_idx][lane] += sums[lane];
                        acc1[projection_idx][lane] += sums[lane + 4];
                    }
                }
            }
            inline for (0..projection_count) |projection_idx| {
                const out_row0 = outputs[projection_idx][r * out_dim ..][0..out_dim];
                const out_row1 = outputs[projection_idx][(r + 1) * out_dim ..][0..out_dim];
                inline for (0..4) |lane| {
                    out_row0[o + lane] = acc0[projection_idx][lane];
                    out_row1[o + lane] = acc1[projection_idx][lane];
                }
            }
        }
        while (o < out_end) : (o += 1) {
            var acc0: [projection_count]f32 = undefined;
            var acc1: [projection_count]f32 = undefined;
            inline for (0..projection_count) |projection_idx| {
                acc0[projection_idx] = optionalLinearBiasAt(biases[projection_idx], o);
                acc1[projection_idx] = acc0[projection_idx];
            }
            for (0..row_blocks) |block_idx| {
                const q0 = q_input_row0[block_idx * q8_block_size ..][0..q8_block_size];
                const q1 = q_input_row1[block_idx * q8_block_size ..][0..q8_block_size];
                inline for (0..projection_count) |projection_idx| {
                    const prepared_block = prepared_blocks[projection_idx][o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                    acc0[projection_idx] += dotK16PreparedQ8KBlock(has_min, q0, prepared_block);
                    acc1[projection_idx] += dotK16PreparedQ8KBlock(has_min, q1, prepared_block);
                }
            }
            inline for (0..projection_count) |projection_idx| {
                outputs[projection_idx][r * out_dim + o] = acc0[projection_idx];
                outputs[projection_idx][(r + 1) * out_dim + o] = acc1[projection_idx];
            }
        }
    }

    while (r < rows) : (r += 1) {
        const q_input_row = q_input[r * input_row_stride ..][0..input_row_stride];
        var o: usize = out_start;
        const panel_align: usize = if (panel8_blocks[0] != null) prepared_k_panel8_nr else prepared_q8_0_panel_nr;
        while (o < out_end and (o % panel_align) != 0) : (o += 1) {
            var acc: [projection_count]f32 = undefined;
            inline for (0..projection_count) |projection_idx| {
                acc[projection_idx] = optionalLinearBiasAt(biases[projection_idx], o);
            }
            for (0..row_blocks) |block_idx| {
                const q = q_input_row[block_idx * q8_block_size ..][0..q8_block_size];
                inline for (0..projection_count) |projection_idx| {
                    const prepared_block = prepared_blocks[projection_idx][o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                    acc[projection_idx] += dotK16PreparedQ8KBlock(has_min, q, prepared_block);
                }
            }
            inline for (0..projection_count) |projection_idx| {
                outputs[projection_idx][r * out_dim + o] = acc[projection_idx];
            }
        }
        if (panel8_blocks[0] != null) {
            while (o + prepared_k_panel8_nr <= out_end) : (o += prepared_k_panel8_nr) {
                var acc: [projection_count]F32x8 = undefined;
                inline for (0..projection_count) |projection_idx| {
                    acc[projection_idx] = optionalLinearBiasVec8(biases[projection_idx], o);
                }
                for (0..row_blocks) |block_idx| {
                    const q = q_input_row[block_idx * q8_block_size ..][0..q8_block_size];
                    inline for (0..projection_count) |projection_idx| {
                        if (panel8_blocks[projection_idx]) |panel8| {
                            const panel_off = ((o / prepared_k_panel8_nr) * row_blocks + block_idx) * prepared_k16_panel8_block_bytes;
                            acc[projection_idx] += dotK16PreparedQ8KPanel8Vec(has_min, q, panel8[panel_off..][0..prepared_k16_panel8_block_bytes]);
                        }
                    }
                }
                inline for (0..projection_count) |projection_idx| {
                    const out_row = outputs[projection_idx][r * out_dim ..][0..out_dim];
                    storeF32x8(out_row, o, acc[projection_idx]);
                }
            }
        }
        while (o + prepared_q8_0_panel_nr <= out_end) : (o += prepared_q8_0_panel_nr) {
            var acc: [projection_count][4]f32 = undefined;
            inline for (0..projection_count) |projection_idx| {
                acc[projection_idx] = .{
                    optionalLinearBiasAt(biases[projection_idx], o),
                    optionalLinearBiasAt(biases[projection_idx], o + 1),
                    optionalLinearBiasAt(biases[projection_idx], o + 2),
                    optionalLinearBiasAt(biases[projection_idx], o + 3),
                };
            }
            for (0..row_blocks) |block_idx| {
                const q = q_input_row[block_idx * q8_block_size ..][0..q8_block_size];
                inline for (0..projection_count) |projection_idx| {
                    const sums = dotK16PreparedQ8KBlock4(
                        has_min,
                        q,
                        preparedK16PanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 0),
                        preparedK16PanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 1),
                        preparedK16PanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 2),
                        preparedK16PanelBlock(panel_blocks[projection_idx], prepared_blocks[projection_idx], row_blocks, prepared_row_stride, o, block_idx, 3),
                    );
                    inline for (0..4) |lane| {
                        acc[projection_idx][lane] += sums[lane];
                    }
                }
            }
            inline for (0..projection_count) |projection_idx| {
                const out_row = outputs[projection_idx][r * out_dim ..][0..out_dim];
                inline for (0..4) |lane| {
                    out_row[o + lane] = acc[projection_idx][lane];
                }
            }
        }
        while (o < out_end) : (o += 1) {
            var acc: [projection_count]f32 = undefined;
            inline for (0..projection_count) |projection_idx| {
                acc[projection_idx] = optionalLinearBiasAt(biases[projection_idx], o);
            }
            for (0..row_blocks) |block_idx| {
                const q = q_input_row[block_idx * q8_block_size ..][0..q8_block_size];
                inline for (0..projection_count) |projection_idx| {
                    const prepared_block = prepared_blocks[projection_idx][o * prepared_row_stride + block_idx * prepared_k16_block_bytes ..][0..prepared_k16_block_bytes];
                    acc[projection_idx] += dotK16PreparedQ8KBlock(has_min, q, prepared_block);
                }
            }
            inline for (0..projection_count) |projection_idx| {
                outputs[projection_idx][r * out_dim + o] = acc[projection_idx];
