        }
    }
}

fn k16PreparedQ8KActivationPairApply(
    comptime has_min: bool,
    q_input: []const u8,
    prepared_blocks_a: []const u8,
    panel_blocks_a: ?[]const u8,
    panel8_blocks_a: ?[]const u8,
    prepared_blocks_b: []const u8,
    panel_blocks_b: ?[]const u8,
    panel8_blocks_b: ?[]const u8,
    output_a: []f32,
    output_b: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    k16PreparedQ8KActivationGroupedApply(
        has_min,
        2,
        q_input,
        .{ prepared_blocks_a, prepared_blocks_b },
        .{ panel_blocks_a, panel_blocks_b },
        .{ panel8_blocks_a, panel8_blocks_b },
        .{ null, null },
        .{ output_a, output_b },
        rows,
        in_dim,
        out_dim,
        out_start,
        out_end,
    );
}

fn k16PreparedQ8KActivationTripleApply(
    comptime has_min: bool,
    q_input: []const u8,
    prepared_blocks_a: []const u8,
    panel_blocks_a: ?[]const u8,
    panel8_blocks_a: ?[]const u8,
    prepared_blocks_b: []const u8,
    panel_blocks_b: ?[]const u8,
    panel8_blocks_b: ?[]const u8,
    prepared_blocks_c: []const u8,
    panel_blocks_c: ?[]const u8,
    panel8_blocks_c: ?[]const u8,
    bias_a: ?[]const f32,
    bias_b: ?[]const f32,
    bias_c: ?[]const f32,
    output_a: []f32,
    output_b: []f32,
    output_c: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    k16PreparedQ8KActivationGroupedApply(
        has_min,
        3,
        q_input,
        .{ prepared_blocks_a, prepared_blocks_b, prepared_blocks_c },
        .{ panel_blocks_a, panel_blocks_b, panel_blocks_c },
        .{ panel8_blocks_a, panel8_blocks_b, panel8_blocks_c },
        .{ bias_a, bias_b, bias_c },
        .{ output_a, output_b, output_c },
        rows,
        in_dim,
        out_dim,
        out_start,
        out_end,
    );
}

fn quantizeK16Activation(
    allocator: std.mem.Allocator,
    io: ?std.Io,
    input: []const f32,
    rows: usize,
    in_dim: usize,
    row_blocks: usize,
) ![]u8 {
    const q8_block_size: usize = 292;
    const q_input = try allocator.alloc(u8, rows * row_blocks * q8_block_size);
    try quantizeQ8_KActivationRowsDispatch(io, input, q_input, rows, in_dim, row_blocks);
    return q_input;
}

fn k16RawQ8KActivationApply(
    comptime has_min: bool,
    q_input: []const u8,
    weight_raw: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    out_start: usize,
    out_end: usize,
) void {
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    const block_size: usize = if (has_min) 84 else 110;
    const row_blocks = in_dim / values_per_block;
    const input_row_stride = row_blocks * q8_block_size;
    const weight_row_stride = row_blocks * block_size;
    var r: usize = 0;
    while (r < rows) : (r += 1) {
        const q_input_row = q_input[r * input_row_stride ..][0..input_row_stride];
        const out_row = output[r * out_dim ..][0..out_dim];
        var o: usize = out_start;
        while (o + 4 <= out_end) : (o += 4) {
            var acc0: f32 = 0.0;
            var acc1: f32 = 0.0;
            var acc2: f32 = 0.0;
            var acc3: f32 = 0.0;
            const w0_off = o * weight_row_stride;
            const w1_off = (o + 1) * weight_row_stride;
            const w2_off = (o + 2) * weight_row_stride;
            const w3_off = (o + 3) * weight_row_stride;
            for (0..row_blocks) |block_idx| {
                const q_off = block_idx * q8_block_size;
                const w_off = block_idx * block_size;
                const sums = dotK16RawQ8KBlock4(
                    has_min,
                    q_input_row[q_off..][0..q8_block_size],
                    weight_raw[w0_off + w_off ..][0..block_size],
                    weight_raw[w1_off + w_off ..][0..block_size],
                    weight_raw[w2_off + w_off ..][0..block_size],
                    weight_raw[w3_off + w_off ..][0..block_size],
                );
                acc0 += sums[0];
                acc1 += sums[1];
                acc2 += sums[2];
                acc3 += sums[3];
            }
            out_row[o] = acc0;
            out_row[o + 1] = acc1;
            out_row[o + 2] = acc2;
            out_row[o + 3] = acc3;
        }
        while (o < out_end) : (o += 1) {
            var acc: f32 = 0.0;
            const weight_row = weight_raw[o * weight_row_stride ..][0..weight_row_stride];
            for (0..row_blocks) |block_idx| {
                const q_off = block_idx * q8_block_size;
                const w_off = block_idx * block_size;
                acc += dotK16RawQ8KBlock(
                    has_min,
                    q_input_row[q_off..][0..q8_block_size],
                    weight_row[w_off..][0..block_size],
                );
            }
            out_row[o] = acc;
        }
    }
}

fn linearK16RawQ8KActivationParallel(
    comptime has_min: bool,
    io: ?std.Io,
    q_input: []const u8,
    weight_raw: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !bool {
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    const row_blocks = in_dim / values_per_block;
    const col_plan = chooseQuantLinearColumnParallelPlan(quantParallelEnabled(), quantParallelDispatchAvailable(io), rows, out_dim, row_blocks, quantParallelMaxWorkers());
    if (col_plan.worker_count > 1) {
        if (quantParallelDebugRequested()) {
            std.debug.print("k16_raw_q8_k_activation_parallel_cols has_min={} workers={d} rows={d} out={d} row_blocks={d}\n", .{ has_min, col_plan.worker_count, rows, out_dim, row_blocks });
        }
        var chunks: [max_q4_k_parallel_workers]QuantColChunk = undefined;
        const num_chunks = chunkColsForWorkers(out_dim, col_plan, &chunks);
        var contexts: [max_q4_k_parallel_workers]K16RawQ8KActivationWorkerCtx = undefined;
        var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
        for (chunks[0..num_chunks], 0..) |chunk, i| {
            contexts[i] = .{
                .q_input = q_input,
                .weight_raw = weight_raw,
                .output = output,
                .rows = rows,
                .in_dim = in_dim,
                .out_dim = out_dim,
                .out_start = chunk.start,
                .out_end = chunk.end,
                .has_min = has_min,
            };
            jobs[i] = .{ .fn_ptr = k16RawQ8KActivationWorkerJob, .ctx = @ptrCast(&contexts[i]) };
        }
        try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
        return true;
    }

    const plan = chooseQuantLinearParallelPlan(quantParallelEnabled(), rows, out_dim, row_blocks, quantParallelMaxWorkers());
    if (plan.worker_count <= 1) return false;

    var chunks: [max_q4_k_parallel_workers]QuantRowChunk = undefined;
    const num_chunks = chunkRowsForWorkers(rows, plan, &chunks);
    var contexts: [max_q4_k_parallel_workers]K16RawQ8KActivationWorkerCtx = undefined;
    var jobs: [max_q4_k_parallel_workers]linalg.pool.Job = undefined;
    for (chunks[0..num_chunks], 0..) |chunk, i| {
        contexts[i] = .{
            .q_input = q_input[chunk.start * row_blocks * q8_block_size .. chunk.end * row_blocks * q8_block_size],
            .weight_raw = weight_raw,
            .output = output[chunk.start * out_dim .. chunk.end * out_dim],
            .rows = chunk.end - chunk.start,
            .in_dim = in_dim,
            .out_dim = out_dim,
            .out_start = 0,
            .out_end = out_dim,
            .has_min = has_min,
        };
        jobs[i] = .{ .fn_ptr = k16RawQ8KActivationWorkerJob, .ctx = @ptrCast(&contexts[i]) };
    }
    try dispatchAndCheckQuantWorkers(io, jobs[0..num_chunks], contexts[0..num_chunks]);
    return true;
}

fn linearK16RawQ8KActivationDispatch(
    comptime has_min: bool,
    io: ?std.Io,
    q_input: []const u8,
    weight_raw: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    if (try linearK16RawQ8KActivationParallel(has_min, io, q_input, weight_raw, output, rows, in_dim, out_dim)) return;
    k16RawQ8KActivationApply(has_min, q_input, weight_raw, output, rows, in_dim, out_dim, 0, out_dim);
}

fn linearNoBiasK16RawQ8KActivation(
    comptime has_min: bool,
    allocator: std.mem.Allocator,
    io: ?std.Io,
    input: []const f32,
    weight_raw: []const u8,
    output: []f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
) !void {
    const values_per_block: usize = 256;
    const q8_block_size: usize = 292;
    const block_size: usize = if (has_min) 84 else 110;
    if (in_dim % values_per_block != 0) return error.InvalidQuantizedLinearShape;
    const row_blocks = in_dim / values_per_block;
    if (weight_raw.len != out_dim * row_blocks * block_size) return error.InvalidQuantizedDataSize;
    if (rows == 1 and in_dim <= small_row_q8_k_stack_max_in_dim) {
        var q_input_buf: [small_row_q8_k_stack_max_in_dim / values_per_block * q8_block_size]u8 = undefined;
        const q_input = q_input_buf[0 .. row_blocks * q8_block_size];
        try quantizeQ8_KActivationRowsDispatch(io, input, q_input, rows, in_dim, row_blocks);
        try linearK16RawQ8KActivationDispatch(has_min, io, q_input, weight_raw, output, rows, in_dim, out_dim);
        return;
    }
    const q_input = try quantizeK16Activation(allocator, io, input, rows, in_dim, row_blocks);
    defer allocator.free(q_input);
    try linearK16RawQ8KActivationDispatch(has_min, io, q_input, weight_raw, output, rows, in_dim, out_dim);
}

