const bitnet_tl_pair_lut_entries = 16;
const bitnet_tl_three_lut_entries = 32;
const bitnet_tl_simd_lanes = 8;

fn fillTL1ActivationPairLut(input_row: []const f32, scale: f32, weight_scale: f32, pair_lut: []f32) void {
    std.debug.assert(input_row.len % 2 == 0);
    std.debug.assert(pair_lut.len == (input_row.len / 2) * bitnet_tl_pair_lut_entries);

    for (0..input_row.len / 2) |pair_col| {
        const a0 = quantizeBitnetActivation(input_row[pair_col * 2 + 0], scale);
        const a1 = quantizeBitnetActivation(input_row[pair_col * 2 + 1], scale);
        const base = pair_col * bitnet_tl_pair_lut_entries;
        inline for (0..bitnet_tl_pair_lut_entries) |code| {
            const pair = quant_codec.bitnetTLPair(@intCast(code));
            pair_lut[base + code] = (a0 * @as(f32, @floatFromInt(pair[0])) + a1 * @as(f32, @floatFromInt(pair[1]))) * weight_scale;
        }
    }
}

fn fillTL2ActivationLuts(
    input_row: []const f32,
    scale: f32,
    view: quant_codec.BitnetTL2View,
    three_lut: []f32,
    two_lut: []f32,
) void {
    std.debug.assert(three_lut.len == view.threeCount() * bitnet_tl_three_lut_entries);
    std.debug.assert(two_lut.len == view.twoPairCount() * bitnet_tl_pair_lut_entries);

    for (0..view.threeCount()) |triple_col| {
        const col = triple_col * 3;
        const a0 = quantizeBitnetActivation(input_row[col + 0], scale);
        const a1 = quantizeBitnetActivation(input_row[col + 1], scale);
        const a2 = quantizeBitnetActivation(input_row[col + 2], scale);
        const base = triple_col * bitnet_tl_three_lut_entries;
        inline for (0..16) |code| {
            inline for (0..2) |negative_bit| {
                const triple = quant_codec.bitnetTL2Three(@intCast(code), negative_bit != 0);
                three_lut[base + code * 2 + negative_bit] =
                    (a0 * @as(f32, @floatFromInt(triple[0])) +
                        a1 * @as(f32, @floatFromInt(triple[1])) +
                        a2 * @as(f32, @floatFromInt(triple[2]))) * view.weight_scale;
            }
        }
    }

    for (0..view.twoPairCount()) |pair_col| {
        const col = view.three_cols + pair_col * 2;
        const a0 = quantizeBitnetActivation(input_row[col + 0], scale);
        const a1 = quantizeBitnetActivation(input_row[col + 1], scale);
        const base = pair_col * bitnet_tl_pair_lut_entries;
        inline for (0..bitnet_tl_pair_lut_entries) |code| {
            const pair = quant_codec.bitnetTLPair(@intCast(code));
            two_lut[base + code] = (a0 * @as(f32, @floatFromInt(pair[0])) + a1 * @as(f32, @floatFromInt(pair[1]))) * view.weight_scale;
        }
    }
}

fn dotTL1LutRow(view: quant_codec.BitnetTL1View, row: usize, pair_lut: []const f32) !f32 {
    const pair_count = view.pairCount();
    std.debug.assert(pair_lut.len == pair_count * bitnet_tl_pair_lut_entries);

    var vec_acc: @Vector(bitnet_tl_simd_lanes, f32) = @splat(0.0);
    var pair_col: usize = 0;
    while (pair_col + bitnet_tl_simd_lanes <= pair_count) : (pair_col += bitnet_tl_simd_lanes) {
        var lanes: @Vector(bitnet_tl_simd_lanes, f32) = @splat(0.0);
        inline for (0..bitnet_tl_simd_lanes) |lane| {
            const code = try view.pairCode(row, pair_col + lane);
            lanes[lane] = pair_lut[(pair_col + lane) * bitnet_tl_pair_lut_entries + @as(usize, @intCast(code))];
        }
        vec_acc += lanes;
    }

    var acc = @reduce(.Add, vec_acc);
    while (pair_col < pair_count) : (pair_col += 1) {
        const code = try view.pairCode(row, pair_col);
        acc += pair_lut[pair_col * bitnet_tl_pair_lut_entries + @as(usize, @intCast(code))];
    }
    return acc;
}

fn dotTL2LutRow(
    view: quant_codec.BitnetTL2View,
    row: usize,
    three_lut: []const f32,
    two_lut: []const f32,
) !f32 {
    const three_count = view.threeCount();
    const two_count = view.twoPairCount();
    std.debug.assert(three_lut.len == three_count * bitnet_tl_three_lut_entries);
    std.debug.assert(two_lut.len == two_count * bitnet_tl_pair_lut_entries);

    var vec_acc: @Vector(bitnet_tl_simd_lanes, f32) = @splat(0.0);
    var triple_col: usize = 0;
    while (triple_col + bitnet_tl_simd_lanes <= three_count) : (triple_col += bitnet_tl_simd_lanes) {
        var lanes: @Vector(bitnet_tl_simd_lanes, f32) = @splat(0.0);
        inline for (0..bitnet_tl_simd_lanes) |lane| {
            const code = try view.threeCode(row, triple_col + lane);
            const negative = try view.threeNegative(row, triple_col + lane);
            lanes[lane] = three_lut[(triple_col + lane) * bitnet_tl_three_lut_entries + @as(usize, @intCast(code)) * 2 + @intFromBool(negative)];
        }
        vec_acc += lanes;
    }

    var acc = @reduce(.Add, vec_acc);
    while (triple_col < three_count) : (triple_col += 1) {
        const code = try view.threeCode(row, triple_col);
        const negative = try view.threeNegative(row, triple_col);
        acc += three_lut[triple_col * bitnet_tl_three_lut_entries + @as(usize, @intCast(code)) * 2 + @intFromBool(negative)];
    }

    var pair_vec_acc: @Vector(bitnet_tl_simd_lanes, f32) = @splat(0.0);
    var pair_col: usize = 0;
    while (pair_col + bitnet_tl_simd_lanes <= two_count) : (pair_col += bitnet_tl_simd_lanes) {
        var lanes: @Vector(bitnet_tl_simd_lanes, f32) = @splat(0.0);
        inline for (0..bitnet_tl_simd_lanes) |lane| {
            const code = try view.twoPairCode(row, pair_col + lane);
            lanes[lane] = two_lut[(pair_col + lane) * bitnet_tl_pair_lut_entries + @as(usize, @intCast(code))];
        }
        pair_vec_acc += lanes;
    }
    acc += @reduce(.Add, pair_vec_acc);

    while (pair_col < two_count) : (pair_col += 1) {
        const code = try view.twoPairCode(row, pair_col);
        acc += two_lut[pair_col * bitnet_tl_pair_lut_entries + @as(usize, @intCast(code))];
    }
    return acc;
}

fn bitnetActivationScale(input_row: []const f32) f32 {
    var abs_max: f32 = 0.0;
    for (input_row) |value| {
        abs_max = @max(abs_max, @abs(value));
    }
    if (abs_max == 0.0) return 1.0;
    return abs_max / 127.0;
}

fn quantizeBitnetActivation(value: f32, scale: f32) f32 {
    if (scale == 0.0) return 0.0;
    const quantized = @min(@max(std.math.round(value / scale), -127.0), 127.0);
    return quantized * scale;
}

fn quantizeBitnetActivationInt8(value: f32, scale: f32) i8 {
    if (scale == 0.0) return 0;
    const quantized = @min(@max(std.math.round(value / scale), -127.0), 127.0);
    return @intCast(@as(i32, @intFromFloat(quantized)));
}

fn quantizeBitnetActivationRow(input_row: []const f32, scale: f32, quantized_row: []i8) void {
    std.debug.assert(input_row.len == quantized_row.len);
    for (input_row, quantized_row) |value, *out| {
        out.* = quantizeBitnetActivationInt8(value, scale);
    }
}

fn dotI2SBlock(input_block: []const f32, block: []const u8) f32 {
    const map2bit = [_]f32{ -1.0, 0.0, 1.0, 0.0 };
    var acc: f32 = 0.0;
    for (0..32) |group| {
        const packed_value = block[group];
        const codes = [_]u2{
            @intCast((packed_value >> 6) & 0x03),
            @intCast((packed_value >> 4) & 0x03),
            @intCast((packed_value >> 2) & 0x03),
            @intCast(packed_value & 0x03),
        };
        inline for (0..4) |lane| {
            acc += input_block[lane * 32 + group] * map2bit[codes[lane]];
        }
    }
    return acc;
}

fn dotI8SBlock(input_block: []const f32, block: []const u8) f32 {
    const value: i8 = @bitCast(block[0]);
    return input_block[0] * @as(f32, @floatFromInt(value));
}

fn dotI2SBlockActivationQuantized(input_block: []const i8, block: []const u8, activation_scale: f32) f32 {
    std.debug.assert(input_block.len == 128);
    std.debug.assert(block.len == 32);

    const zero_i32: I32xN = @splat(0);
    const code_mask: U8xN = @splat(0x03);
    var acc: i32 = 0;
    inline for (0..4) |lane| {
        const shift: u3 = @intCast((3 - lane) * 2);
        const shift_vec: @Vector(VEC_LEN, u3) = @splat(shift);
        var vec_acc: I32xN = @splat(0);
        var group: usize = 0;
        while (group + VEC_LEN <= 32) : (group += VEC_LEN) {
            const packed_bytes: U8xN = block[group..][0..VEC_LEN].*;
            const codes: U8xN = (packed_bytes >> shift_vec) & code_mask;
            const activations_i8: I8xN = input_block[lane * 32 + group ..][0..VEC_LEN].*;
            const activations: I32xN = activations_i8;
            const pos_mask = codes == @as(U8xN, @splat(2));
            const neg_mask = codes == @as(U8xN, @splat(0));
            vec_acc += @select(i32, pos_mask, activations, zero_i32);
            vec_acc -= @select(i32, neg_mask, activations, zero_i32);
        }
        acc += @reduce(.Add, vec_acc);
        while (group < 32) : (group += 1) {
            const code: u2 = @intCast((block[group] >> shift) & 0x03);
            const activation: i32 = input_block[lane * 32 + group];
            switch (code) {
                0 => acc -= activation,
                2 => acc += activation,
                else => {},
            }
        }
    }
    return activation_scale * @as(f32, @floatFromInt(acc));
}

fn dotQ5_0Block(input_block: []const f32, block: []const u8) f32 {
    const d = decodeFp16Le(block[0], block[1]);
    const qh = std.mem.readInt(u32, block[2..6], .little);
    const qs = block[6..22];
    var acc: f32 = 0.0;
    for (qs, 0..) |packed_byte, i| {
        const lo4: i32 = packed_byte & 0x0F;
        const hi1: i32 = @intCast((qh >> @as(u5, @intCast(i))) & 1);
        acc += input_block[i] * @as(f32, @floatFromInt((lo4 | (hi1 << 4)) - 16));
    }
    for (qs, 0..) |packed_byte, i| {
        const lo4: i32 = packed_byte >> 4;
        const hi1: i32 = @intCast((qh >> @as(u5, @intCast(i + 16))) & 1);
        acc += input_block[16 + i] * @as(f32, @floatFromInt((lo4 | (hi1 << 4)) - 16));
    }
    return d * acc;
}

fn dotQ5_1Block(input_block: []const f32, block: []const u8) f32 {
    const d = decodeFp16Le(block[0], block[1]);
    const m = decodeFp16Le(block[2], block[3]);
    const qh = std.mem.readInt(u32, block[4..8], .little);
    const qs = block[8..24];
    var acc: f32 = 0.0;
    for (qs, 0..) |packed_byte, i| {
        const lo4: i32 = packed_byte & 0x0F;
        const hi1: i32 = @intCast((qh >> @as(u5, @intCast(i))) & 1);
        acc += input_block[i] * (d * @as(f32, @floatFromInt(lo4 | (hi1 << 4))) + m);
    }
    for (qs, 0..) |packed_byte, i| {
        const lo4: i32 = packed_byte >> 4;
        const hi1: i32 = @intCast((qh >> @as(u5, @intCast(i + 16))) & 1);
        acc += input_block[16 + i] * (d * @as(f32, @floatFromInt(lo4 | (hi1 << 4))) + m);
    }
    return acc;
}

fn dotQ1_0Block(input_block: []const f32, block: []const u8) f32 {
    // Q1_0: 2-byte fp16 scale, then 16 bytes = 128 sign bits (LSB-first within each byte).
    // bit == 1 → weight = +d, bit == 0 → weight = -d (matches dequantizeQ1_0).
    const d = decodeFp16Le(block[0], block[1]);
    const qs = block[2..18];
    const Vec8 = @Vector(8, f32);
    var acc: Vec8 = @splat(0.0);
    inline for (0..16) |byte_idx| {
        const b = qs[byte_idx];
        const signs: Vec8 = .{
            if ((b & 0x01) != 0) 1.0 else -1.0,
            if ((b & 0x02) != 0) 1.0 else -1.0,
            if ((b & 0x04) != 0) 1.0 else -1.0,
            if ((b & 0x08) != 0) 1.0 else -1.0,
            if ((b & 0x10) != 0) 1.0 else -1.0,
            if ((b & 0x20) != 0) 1.0 else -1.0,
            if ((b & 0x40) != 0) 1.0 else -1.0,
            if ((b & 0x80) != 0) 1.0 else -1.0,
        };
        const inp: Vec8 = input_block[byte_idx * 8 ..][0..8].*;
        acc += inp * signs;
    }
    return d * @reduce(.Add, acc);
}

fn dotQ4_0Block(input_block: []const f32, block: []const u8) f32 {
    const d = decodeFp16Le(block[0], block[1]);
    const qs = block[2..18];
    var acc: f32 = 0.0;
    for (qs, 0..) |packed_byte, i| {
        const lo = @as(f32, @floatFromInt(@as(i32, packed_byte & 0x0F) - 8));
        acc += input_block[i] * lo;
    }
    for (qs, 0..) |packed_byte, i| {
        const hi = @as(f32, @floatFromInt(@as(i32, packed_byte >> 4) - 8));
        acc += input_block[16 + i] * hi;
    }
    return d * acc;
}

fn dotQ4_1Block(input_block: []const f32, block: []const u8) f32 {
    const d = decodeFp16Le(block[0], block[1]);
    const m = decodeFp16Le(block[2], block[3]);
    const qs = block[4..20];
    var acc: f32 = 0.0;
    for (qs, 0..) |packed_byte, i| {
        const lo = @as(f32, @floatFromInt(packed_byte & 0x0F));
        acc += input_block[i] * (d * lo + m);
    }
    for (qs, 0..) |packed_byte, i| {
        const hi = @as(f32, @floatFromInt(packed_byte >> 4));
        acc += input_block[16 + i] * (d * hi + m);
    }
    return acc;
}

fn dotQ8_0Block(input_block: []const f32, block: []const u8) f32 {
    const d = decodeFp16Le(block[0], block[1]);
    const qs = block[2..34];
    var acc: F32xN = @splat(0.0);
    comptime var i: usize = 0;
    inline while (i < 32) : (i += VEC_LEN) {
        const raw: U8xN = qs[i..][0..VEC_LEN].*;
        const qi: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw));
        const qf: F32xN = @floatFromInt(qi);
        const inp: F32xN = input_block[i..][0..VEC_LEN].*;
        acc += inp * qf;
    }
    return d * @reduce(.Add, acc);
}

fn dotQ8_1Block(input_block: []const f32, block: []const u8) f32 {
    const d = decodeFp16Le(block[0], block[1]);
    // block[2..4] stores d * sum(qs) for optimized dot products.
    const qs = block[4..36];
    var acc: F32xN = @splat(0.0);
    comptime var i: usize = 0;
    inline while (i < 32) : (i += VEC_LEN) {
        const raw: U8xN = qs[i..][0..VEC_LEN].*;
        const qi: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw));
        const qf: F32xN = @floatFromInt(qi);
        const inp: F32xN = input_block[i..][0..VEC_LEN].*;
        acc += inp * qf;
    }
    return d * @reduce(.Add, acc);
}

fn dotQ8_KBlock(input_block: []const f32, block: []const u8) f32 {
    const d = decodeF32Le(block[0], block[1], block[2], block[3]);
    const qs = block[4..260];
    var acc: F32xN = @splat(0.0);
    var i: usize = 0;
    while (i < 256) : (i += VEC_LEN) {
        const raw: U8xN = qs[i..][0..VEC_LEN].*;
        const qi: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw));
        const qf: F32xN = @floatFromInt(qi);
        const inp: F32xN = input_block[i..][0..VEC_LEN].*;
        acc += inp * qf;
    }
    return d * @reduce(.Add, acc);
}

fn dotQ8KQ8KBlock(q8_input: []const u8, q8_weight: []const u8) f32 {
    std.debug.assert(q8_input.len == 292);
    std.debug.assert(q8_weight.len == 292);
    const scale = readF32Le(q8_input[0..4]) * readF32Le(q8_weight[0..4]);
    const qx = q8_input[4..260];
    const qw = q8_weight[4..260];
    var dot: i32 = 0;
    inline for (0..8) |chunk| {
        const off = chunk * 32;
        dot += dotI8I8Block(qx[off..][0..32], qw[off..][0..32]);
    }
    return scale * @as(f32, @floatFromInt(dot));
}

inline fn dotQ8KQ8KBlock4FusedSdot(
    q8_input: []const u8,
    q8_weight0: []const u8,
    q8_weight1: []const u8,
    q8_weight2: []const u8,
    q8_weight3: []const u8,
) struct { f32, f32, f32, f32 } {
    if (comptime !native_aarch64_dotprod) {
        return dotQ8KQ8KBlock4(q8_input, q8_weight0, q8_weight1, q8_weight2, q8_weight3);
    }

    std.debug.assert(q8_input.len == 292);
    std.debug.assert(q8_weight0.len == 292);
    std.debug.assert(q8_weight1.len == 292);
    std.debug.assert(q8_weight2.len == 292);
    std.debug.assert(q8_weight3.len == 292);

    const qx = q8_input[4..260];
    const qw0 = q8_weight0[4..260];
    const qw1 = q8_weight1[4..260];
    const qw2 = q8_weight2[4..260];
    const qw3 = q8_weight3[4..260];
    var acc0: I32x4 = @splat(0);
    var acc1: I32x4 = @splat(0);
    var acc2: I32x4 = @splat(0);
    var acc3: I32x4 = @splat(0);
    comptime var off: usize = 0;
    inline while (off < 256) : (off += 16) {
        const raw_x: U8x16 = qx[off..][0..16].*;
        acc0 = aarch64Sdot16(acc0, raw_x, qw0[off..][0..16].*);
        acc1 = aarch64Sdot16(acc1, raw_x, qw1[off..][0..16].*);
        acc2 = aarch64Sdot16(acc2, raw_x, qw2[off..][0..16].*);
        acc3 = aarch64Sdot16(acc3, raw_x, qw3[off..][0..16].*);
    }
    const input_scale = readF32Le(q8_input[0..4]);
    return .{
        input_scale * readF32Le(q8_weight0[0..4]) * @as(f32, @floatFromInt(@reduce(.Add, acc0))),
        input_scale * readF32Le(q8_weight1[0..4]) * @as(f32, @floatFromInt(@reduce(.Add, acc1))),
        input_scale * readF32Le(q8_weight2[0..4]) * @as(f32, @floatFromInt(@reduce(.Add, acc2))),
        input_scale * readF32Le(q8_weight3[0..4]) * @as(f32, @floatFromInt(@reduce(.Add, acc3))),
    };
}

fn dotQ8KQ8KBlock4(
    q8_input: []const u8,
    q8_weight0: []const u8,
    q8_weight1: []const u8,
    q8_weight2: []const u8,
    q8_weight3: []const u8,
) struct { f32, f32, f32, f32 } {
    std.debug.assert(q8_input.len == 292);
    std.debug.assert(q8_weight0.len == 292);
    std.debug.assert(q8_weight1.len == 292);
    std.debug.assert(q8_weight2.len == 292);
    std.debug.assert(q8_weight3.len == 292);
    const input_scale = readF32Le(q8_input[0..4]);
    const qx = q8_input[4..260];
    const qw0 = q8_weight0[4..260];
    const qw1 = q8_weight1[4..260];
    const qw2 = q8_weight2[4..260];
    const qw3 = q8_weight3[4..260];
    var dot0: i32 = 0;
    var dot1: i32 = 0;
    var dot2: i32 = 0;
    var dot3: i32 = 0;
    inline for (0..8) |chunk| {
        const off = chunk * 32;
        const dots = dotI8I8Block4(qx[off..][0..32], qw0[off..][0..32], qw1[off..][0..32], qw2[off..][0..32], qw3[off..][0..32]);
        dot0 += dots[0];
        dot1 += dots[1];
        dot2 += dots[2];
        dot3 += dots[3];
    }
    return .{
        input_scale * readF32Le(q8_weight0[0..4]) * @as(f32, @floatFromInt(dot0)),
        input_scale * readF32Le(q8_weight1[0..4]) * @as(f32, @floatFromInt(dot1)),
        input_scale * readF32Le(q8_weight2[0..4]) * @as(f32, @floatFromInt(dot2)),
        input_scale * readF32Le(q8_weight3[0..4]) * @as(f32, @floatFromInt(dot3)),
    };
}

inline fn dotQ8KQ8KBlock4MR2FusedSdot(
    q8_input0: []const u8,
