fn dotIQ4NLBlock(input_block: []const f32, block: []const u8) f32 {
    const d = decodeFp16Le(block[0], block[1]);
    const qs = block[2..18];
    var acc: f32 = 0.0;
    for (qs, 0..) |packed_byte, i| {
        const q = quant_codec.iq4_nl_values[packed_byte & 0x0F];
        acc += input_block[i] * @as(f32, @floatFromInt(q));
    }
    for (qs, 0..) |packed_byte, i| {
        const q = quant_codec.iq4_nl_values[packed_byte >> 4];
        acc += input_block[16 + i] * @as(f32, @floatFromInt(q));
    }
    return d * acc;
}

fn dotIQ4XSBlock(input_block: []const f32, block: []const u8) f32 {
    const d = decodeFp16Le(block[0], block[1]);
    const scales_h = std.mem.readInt(u16, block[2..4], .little);
    const scales_l = block[4..8];
    const qs = block[8..136];
    var acc: f32 = 0.0;
    for (0..8) |ib| {
        const low: u16 = (scales_l[ib / 2] >> @as(u3, @intCast(4 * (ib % 2)))) & 0x0F;
        const high: u16 = (scales_h >> @as(u4, @intCast(2 * ib))) & 0x03;
        const ls = @as(i32, @intCast(low | (high << 4)));
        const dl = d * @as(f32, @floatFromInt(ls - 32));
        const q_base = ib * 16;
        const input_base = ib * 32;
        for (0..16) |j| {
            const q = quant_codec.iq4_nl_values[qs[q_base + j] & 0x0F];
            acc += input_block[input_base + j] * (dl * @as(f32, @floatFromInt(q)));
        }
        for (0..16) |j| {
            const q = quant_codec.iq4_nl_values[qs[q_base + j] >> 4];
            acc += input_block[input_base + 16 + j] * (dl * @as(f32, @floatFromInt(q)));
        }
    }
    return acc;
}

fn dotQ2_KBlock(input_block: []const f32, block: []const u8) f32 {
    const scales_raw = block[0..16];
    const d = decodeFp16Le(block[16], block[17]);
    const dmin = decodeFp16Le(block[18], block[19]);
    const qs = block[20..84];

    const mask_03: U8xN = @splat(0x03);
    var acc: F32xN = @splat(0.0);
    for (0..16) |sub| {
        const sc = @as(f32, @floatFromInt(scales_raw[sub] & 0x0F));
        const m = @as(f32, @floatFromInt(scales_raw[sub] >> 4));
        const dsc: F32xN = @splat(d * sc);
        const dmn: F32xN = @splat(dmin * m);
        const chunk = sub / 8;
        const group = (sub % 8) / 2;
        const l_base = (sub % 2) * 16;
        const q_base = chunk * 32;
        const shift: @Vector(VEC_LEN, u3) = @splat(@as(u3, @intCast(group * 2)));
        const input_off = sub * 16;

        comptime var i: usize = 0;
        inline while (i < 16) : (i += VEC_LEN) {
            const raw: U8xN = qs[q_base + l_base + i ..][0..VEC_LEN].*;
            const q: I32xN = (raw >> shift) & mask_03;
            const inp: F32xN = input_block[input_off + i ..][0..VEC_LEN].*;
            acc += inp * (dsc * @as(F32xN, @floatFromInt(q)) - dmn);
        }
    }
    return @reduce(.Add, acc);
}

fn dotQ3_KBlock(input_block: []const f32, block: []const u8) f32 {
    const hmask = block[0..32];
    const qs = block[32..96];
    const scale_data = block[96..108];
    const d = decodeFp16Le(block[108], block[109]);

    var raw_scales: [16]i32 = undefined;
    for (0..4) |i| {
        raw_scales[i] = @as(i32, scale_data[i] & 0x0F) | (@as(i32, scale_data[8 + i] & 0x03) << 4);
        raw_scales[i + 4] = @as(i32, scale_data[4 + i] & 0x0F) | (@as(i32, (scale_data[8 + i] >> 2) & 0x03) << 4);
        raw_scales[i + 8] = @as(i32, (scale_data[i] >> 4) & 0x0F) | (@as(i32, (scale_data[8 + i] >> 4) & 0x03) << 4);
        raw_scales[i + 12] = @as(i32, (scale_data[4 + i] >> 4) & 0x0F) | (@as(i32, (scale_data[8 + i] >> 6) & 0x03) << 4);
    }

    const mask_03: U8xN = @splat(0x03);
    const mask_01: U8xN = @splat(0x01);
    const four: I32xN = @splat(4);
    var acc: F32xN = @splat(0.0);
    for (0..16) |sub| {
        const scale: F32xN = @splat(d * @as(f32, @floatFromInt(raw_scales[sub] - 32)));
        const chunk = sub / 8;
        const group = (sub % 8) / 2;
        const l_base = (sub % 2) * 16;
        const q_base = chunk * 32;
        const shift: @Vector(VEC_LEN, u3) = @splat(@as(u3, @intCast(group * 2)));
        const hm_shift: @Vector(VEC_LEN, u3) = @splat(@as(u3, @intCast(chunk * 4 + group)));
        const input_off = sub * 16;

        comptime var i: usize = 0;
        inline while (i < 16) : (i += VEC_LEN) {
            const l = l_base + i;
            const qs_raw: U8xN = qs[q_base + l ..][0..VEC_LEN].*;
            const hm_raw: U8xN = hmask[l..][0..VEC_LEN].*;
            const low2: I32xN = (qs_raw >> shift) & mask_03;
            const high1: I32xN = (hm_raw >> hm_shift) & mask_01;
            const q: I32xN = low2 + high1 * four - four;
            const inp: F32xN = input_block[input_off + i ..][0..VEC_LEN].*;
            acc += inp * (scale * @as(F32xN, @floatFromInt(q)));
        }
    }
    return @reduce(.Add, acc);
}

fn dotQ5_KBlock(input_block: []const f32, block: []const u8) f32 {
    const d = decodeFp16Le(block[0], block[1]);
    const dmin = decodeFp16Le(block[2], block[3]);
    const scales = block[4..16];
    const qh = block[16..48];
    const ql = block[48..176];

    var scs: [8]f32 = undefined;
    var mins: [8]f32 = undefined;
    unpackQ4KScaleMins(scales, &scs, &mins);

    const mask_0f: U8xN = @splat(0x0F);
    const mask_01: U8xN = @splat(0x01);
    const sixteen: I32xN = @splat(16);
    var acc: F32xN = @splat(0.0);
    for (0..8) |sub| {
        const dsc: F32xN = @splat(d * scs[sub]);
        const dmn: F32xN = @splat(dmin * mins[sub]);
        const chunk = sub / 2;
        const is_high = sub % 2 == 1;
        const ql_off = chunk * 32;
        const hb_shift: @Vector(VEC_LEN, u3) = @splat(@as(u3, @intCast(sub)));
        const input_off = sub * 32;

        var i: usize = 0;
        while (i < 32) : (i += VEC_LEN) {
            const ql_raw: U8xN = ql[ql_off + i ..][0..VEC_LEN].*;
            const qh_raw: U8xN = qh[i..][0..VEC_LEN].*;
            const low: I32xN = if (is_high) ql_raw >> @as(@Vector(VEC_LEN, u3), @splat(4)) else ql_raw & mask_0f;
            const high: I32xN = (qh_raw >> hb_shift) & mask_01;
            const q: I32xN = low + high * sixteen;
            const inp: F32xN = input_block[input_off + i ..][0..VEC_LEN].*;
            acc += inp * (dsc * @as(F32xN, @floatFromInt(q)) - dmn);
        }
    }
    return @reduce(.Add, acc);
}

fn dotQ4_KBlock(input_block: []const f32, block: []const u8) f32 {
    const d = decodeFp16Le(block[0], block[1]);
    const dmin = decodeFp16Le(block[2], block[3]);
    const scales = block[4..16];
    const qs = block[16..144];

    var scs: [8]f32 = undefined;
    var mins: [8]f32 = undefined;
    unpackQ4KScaleMins(scales, &scs, &mins);

    const mask_0f: U8xN = @splat(0x0F);
    var acc: F32xN = @splat(0.0);
    var q_off: usize = 0;
    for (0..4) |chunk| {
        const sub = chunk * 2;
        const dsc0: F32xN = @splat(d * scs[sub]);
        const dmn0: F32xN = @splat(dmin * mins[sub]);
        const dsc1: F32xN = @splat(d * scs[sub + 1]);
        const dmn1: F32xN = @splat(dmin * mins[sub + 1]);
        const input_off = chunk * 64;

        var i: usize = 0;
        while (i < 32) : (i += VEC_LEN) {
            const raw: U8xN = qs[q_off + i ..][0..VEC_LEN].*;
            const lo: I32xN = raw & mask_0f;
            const inp: F32xN = input_block[input_off + i ..][0..VEC_LEN].*;
            acc += inp * (dsc0 * @as(F32xN, @floatFromInt(lo)) - dmn0);
        }
        i = 0;
        while (i < 32) : (i += VEC_LEN) {
            const raw: U8xN = qs[q_off + i ..][0..VEC_LEN].*;
            const hi: I32xN = raw >> @splat(4);
            const inp: F32xN = input_block[input_off + 32 + i ..][0..VEC_LEN].*;
            acc += inp * (dsc1 * @as(F32xN, @floatFromInt(hi)) - dmn1);
        }
        q_off += 32;
    }
    return @reduce(.Add, acc);
}

inline fn dotQ4KPreparedBlock(input_block: []const f32, prepared_block: []const u8) f32 {
    std.debug.assert(prepared_block.len == prepared_q4_k_block_bytes);

    const q_values = prepared_block[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    var acc: F32xN = @splat(0.0);
    for (0..4) |chunk| {
        const sub = chunk * 2;
        const dsc0: F32xN = @splat(preparedQ4KDsc(prepared_block, sub));
        const dmn0: F32xN = @splat(preparedQ4KDmn(prepared_block, sub));
        const dsc1: F32xN = @splat(preparedQ4KDsc(prepared_block, sub + 1));
        const dmn1: F32xN = @splat(preparedQ4KDmn(prepared_block, sub + 1));
        const input_off = chunk * 64;
        const q_off = chunk * 64;

        var i: usize = 0;
        while (i < 32) : (i += VEC_LEN) {
            const q: U8xN = q_values[q_off + i ..][0..VEC_LEN].*;
            const inp: F32xN = input_block[input_off + i ..][0..VEC_LEN].*;
            acc += inp * (dsc0 * @as(F32xN, @floatFromInt(q)) - dmn0);
        }
        i = 0;
        while (i < 32) : (i += VEC_LEN) {
            const q: U8xN = q_values[q_off + 32 + i ..][0..VEC_LEN].*;
            const inp: F32xN = input_block[input_off + 32 + i ..][0..VEC_LEN].*;
            acc += inp * (dsc1 * @as(F32xN, @floatFromInt(q)) - dmn1);
        }
    }
    return @reduce(.Add, acc);
}

inline fn dotQ4KPreparedBlockMR2NR1(
    input_block_r0: []const f32,
    input_block_r1: []const f32,
    prepared_block: []const u8,
) struct { f32, f32 } {
    std.debug.assert(prepared_block.len == prepared_q4_k_block_bytes);

    const q_values = prepared_block[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    var acc_r0: F32xN = @splat(0.0);
    var acc_r1: F32xN = @splat(0.0);
    for (0..4) |chunk| {
        const sub = chunk * 2;
        const dsc0: F32xN = @splat(preparedQ4KDsc(prepared_block, sub));
        const dmn0: F32xN = @splat(preparedQ4KDmn(prepared_block, sub));
        const dsc1: F32xN = @splat(preparedQ4KDsc(prepared_block, sub + 1));
        const dmn1: F32xN = @splat(preparedQ4KDmn(prepared_block, sub + 1));
        const input_off = chunk * 64;
        const q_off = chunk * 64;

        var i: usize = 0;
        while (i < 32) : (i += VEC_LEN) {
            const q: U8xN = q_values[q_off + i ..][0..VEC_LEN].*;
            const w = dsc0 * @as(F32xN, @floatFromInt(q)) - dmn0;
            const inp_r0: F32xN = input_block_r0[input_off + i ..][0..VEC_LEN].*;
            const inp_r1: F32xN = input_block_r1[input_off + i ..][0..VEC_LEN].*;
            acc_r0 += inp_r0 * w;
            acc_r1 += inp_r1 * w;
        }
        i = 0;
        while (i < 32) : (i += VEC_LEN) {
            const q: U8xN = q_values[q_off + 32 + i ..][0..VEC_LEN].*;
            const w = dsc1 * @as(F32xN, @floatFromInt(q)) - dmn1;
            const inp_r0: F32xN = input_block_r0[input_off + 32 + i ..][0..VEC_LEN].*;
            const inp_r1: F32xN = input_block_r1[input_off + 32 + i ..][0..VEC_LEN].*;
            acc_r0 += inp_r0 * w;
            acc_r1 += inp_r1 * w;
        }
    }
    return .{ @reduce(.Add, acc_r0), @reduce(.Add, acc_r1) };
}

fn accumulateQ4KPreparedBlock4(
    input_block: []const f32,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
    acc0: *F32xN,
    acc1: *F32xN,
    acc2: *F32xN,
    acc3: *F32xN,
) void {
    accumulateQ4KPreparedBlock4MR1(
        input_block,
        prepared_block0,
        prepared_block1,
        prepared_block2,
        prepared_block3,
        acc0,
        acc1,
        acc2,
        acc3,
    );
}

// MR=1 NR=4: one input row × four prepared cols.  Used directly by the
// M-tail (when `rows` is odd) and as a building block for the 4-col single-
// row path in `linearNoBiasQ4KPreparedTiledRange`.
inline fn accumulateQ4KPreparedBlock4MR1(
    input_block: []const f32,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
    acc0: *F32xN,
    acc1: *F32xN,
    acc2: *F32xN,
    acc3: *F32xN,
) void {
    std.debug.assert(prepared_block0.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block1.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block2.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block3.len == prepared_q4_k_block_bytes);

    const q_values0 = prepared_block0[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    const q_values1 = prepared_block1[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    const q_values2 = prepared_block2[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    const q_values3 = prepared_block3[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    for (0..4) |chunk| {
        const sub = chunk * 2;
        const dsc00: F32xN = @splat(preparedQ4KDsc(prepared_block0, sub));
        const dmn00: F32xN = @splat(preparedQ4KDmn(prepared_block0, sub));
        const dsc01: F32xN = @splat(preparedQ4KDsc(prepared_block0, sub + 1));
        const dmn01: F32xN = @splat(preparedQ4KDmn(prepared_block0, sub + 1));

        const dsc10: F32xN = @splat(preparedQ4KDsc(prepared_block1, sub));
        const dmn10: F32xN = @splat(preparedQ4KDmn(prepared_block1, sub));
        const dsc11: F32xN = @splat(preparedQ4KDsc(prepared_block1, sub + 1));
        const dmn11: F32xN = @splat(preparedQ4KDmn(prepared_block1, sub + 1));

        const dsc20: F32xN = @splat(preparedQ4KDsc(prepared_block2, sub));
        const dmn20: F32xN = @splat(preparedQ4KDmn(prepared_block2, sub));
        const dsc21: F32xN = @splat(preparedQ4KDsc(prepared_block2, sub + 1));
        const dmn21: F32xN = @splat(preparedQ4KDmn(prepared_block2, sub + 1));

        const dsc30: F32xN = @splat(preparedQ4KDsc(prepared_block3, sub));
        const dmn30: F32xN = @splat(preparedQ4KDmn(prepared_block3, sub));
        const dsc31: F32xN = @splat(preparedQ4KDsc(prepared_block3, sub + 1));
        const dmn31: F32xN = @splat(preparedQ4KDmn(prepared_block3, sub + 1));

        const input_off = chunk * 64;
        const q_off = chunk * 64;

        var i: usize = 0;
        while (i < 32) : (i += VEC_LEN) {
            const inp: F32xN = input_block[input_off + i ..][0..VEC_LEN].*;
            const q0: U8xN = q_values0[q_off + i ..][0..VEC_LEN].*;
            const q1: U8xN = q_values1[q_off + i ..][0..VEC_LEN].*;
            const q2: U8xN = q_values2[q_off + i ..][0..VEC_LEN].*;
            const q3: U8xN = q_values3[q_off + i ..][0..VEC_LEN].*;
            acc0.* += inp * (dsc00 * @as(F32xN, @floatFromInt(q0)) - dmn00);
            acc1.* += inp * (dsc10 * @as(F32xN, @floatFromInt(q1)) - dmn10);
            acc2.* += inp * (dsc20 * @as(F32xN, @floatFromInt(q2)) - dmn20);
            acc3.* += inp * (dsc30 * @as(F32xN, @floatFromInt(q3)) - dmn30);
        }
        i = 0;
        while (i < 32) : (i += VEC_LEN) {
            const inp: F32xN = input_block[input_off + 32 + i ..][0..VEC_LEN].*;
            const q0: U8xN = q_values0[q_off + 32 + i ..][0..VEC_LEN].*;
            const q1: U8xN = q_values1[q_off + 32 + i ..][0..VEC_LEN].*;
            const q2: U8xN = q_values2[q_off + 32 + i ..][0..VEC_LEN].*;
            const q3: U8xN = q_values3[q_off + 32 + i ..][0..VEC_LEN].*;
            acc0.* += inp * (dsc01 * @as(F32xN, @floatFromInt(q0)) - dmn01);
            acc1.* += inp * (dsc11 * @as(F32xN, @floatFromInt(q1)) - dmn11);
            acc2.* += inp * (dsc21 * @as(F32xN, @floatFromInt(q2)) - dmn21);
            acc3.* += inp * (dsc31 * @as(F32xN, @floatFromInt(q3)) - dmn31);
        }
    }
}

// MR=2 NR=4: two input rows × four prepared cols, eight accumulators.
//
// The whole reason this exists: dequantising a Q4_K block (computing
// `dsc * f32(q) - dmn` per lane) is the dominant compute in the kernel.
// MR=1 reloads the dequantised weight per row.  MR=2 computes the
// dequantised lane *once* and applies it to two input rows, halving the
// dequant work for the same total FMAs.
//
// 8 F32xN accumulators (8 ymm registers) leave half the AVX2 register
// file free for the splat constants and per-block scratch.  Going to
// MR=4/NR=4 (16 acc) spills on AVX2 and is left as a follow-up.
inline fn accumulateQ4KPreparedBlock4MR2(
    input_block_r0: []const f32,
    input_block_r1: []const f32,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
    acc_r0_0: *F32xN,
    acc_r0_1: *F32xN,
    acc_r0_2: *F32xN,
    acc_r0_3: *F32xN,
    acc_r1_0: *F32xN,
    acc_r1_1: *F32xN,
    acc_r1_2: *F32xN,
    acc_r1_3: *F32xN,
) void {
    std.debug.assert(prepared_block0.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block1.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block2.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block3.len == prepared_q4_k_block_bytes);

    const q_values0 = prepared_block0[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    const q_values1 = prepared_block1[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    const q_values2 = prepared_block2[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    const q_values3 = prepared_block3[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    for (0..4) |chunk| {
        const sub = chunk * 2;
        const dsc00: F32xN = @splat(preparedQ4KDsc(prepared_block0, sub));
        const dmn00: F32xN = @splat(preparedQ4KDmn(prepared_block0, sub));
        const dsc01: F32xN = @splat(preparedQ4KDsc(prepared_block0, sub + 1));
        const dmn01: F32xN = @splat(preparedQ4KDmn(prepared_block0, sub + 1));

        const dsc10: F32xN = @splat(preparedQ4KDsc(prepared_block1, sub));
        const dmn10: F32xN = @splat(preparedQ4KDmn(prepared_block1, sub));
        const dsc11: F32xN = @splat(preparedQ4KDsc(prepared_block1, sub + 1));
        const dmn11: F32xN = @splat(preparedQ4KDmn(prepared_block1, sub + 1));

        const dsc20: F32xN = @splat(preparedQ4KDsc(prepared_block2, sub));
        const dmn20: F32xN = @splat(preparedQ4KDmn(prepared_block2, sub));
        const dsc21: F32xN = @splat(preparedQ4KDsc(prepared_block2, sub + 1));
        const dmn21: F32xN = @splat(preparedQ4KDmn(prepared_block2, sub + 1));

        const dsc30: F32xN = @splat(preparedQ4KDsc(prepared_block3, sub));
        const dmn30: F32xN = @splat(preparedQ4KDmn(prepared_block3, sub));
        const dsc31: F32xN = @splat(preparedQ4KDsc(prepared_block3, sub + 1));
        const dmn31: F32xN = @splat(preparedQ4KDmn(prepared_block3, sub + 1));

        const input_off = chunk * 64;
        const q_off = chunk * 64;

        // First sub-block (sub).  Compute each col's dequantised weight
        // lane once and apply to both input rows.
        var i: usize = 0;
        while (i < 32) : (i += VEC_LEN) {
            const inp_r0: F32xN = input_block_r0[input_off + i ..][0..VEC_LEN].*;
            const inp_r1: F32xN = input_block_r1[input_off + i ..][0..VEC_LEN].*;
            const q0: U8xN = q_values0[q_off + i ..][0..VEC_LEN].*;
            const q1: U8xN = q_values1[q_off + i ..][0..VEC_LEN].*;
            const q2: U8xN = q_values2[q_off + i ..][0..VEC_LEN].*;
            const q3: U8xN = q_values3[q_off + i ..][0..VEC_LEN].*;
            const w0 = dsc00 * @as(F32xN, @floatFromInt(q0)) - dmn00;
            const w1 = dsc10 * @as(F32xN, @floatFromInt(q1)) - dmn10;
            const w2 = dsc20 * @as(F32xN, @floatFromInt(q2)) - dmn20;
            const w3 = dsc30 * @as(F32xN, @floatFromInt(q3)) - dmn30;
            acc_r0_0.* += inp_r0 * w0;
            acc_r0_1.* += inp_r0 * w1;
            acc_r0_2.* += inp_r0 * w2;
            acc_r0_3.* += inp_r0 * w3;
            acc_r1_0.* += inp_r1 * w0;
            acc_r1_1.* += inp_r1 * w1;
            acc_r1_2.* += inp_r1 * w2;
            acc_r1_3.* += inp_r1 * w3;
        }
        // Second sub-block (sub + 1).
        i = 0;
        while (i < 32) : (i += VEC_LEN) {
            const inp_r0: F32xN = input_block_r0[input_off + 32 + i ..][0..VEC_LEN].*;
            const inp_r1: F32xN = input_block_r1[input_off + 32 + i ..][0..VEC_LEN].*;
            const q0: U8xN = q_values0[q_off + 32 + i ..][0..VEC_LEN].*;
            const q1: U8xN = q_values1[q_off + 32 + i ..][0..VEC_LEN].*;
            const q2: U8xN = q_values2[q_off + 32 + i ..][0..VEC_LEN].*;
            const q3: U8xN = q_values3[q_off + 32 + i ..][0..VEC_LEN].*;
            const w0 = dsc01 * @as(F32xN, @floatFromInt(q0)) - dmn01;
            const w1 = dsc11 * @as(F32xN, @floatFromInt(q1)) - dmn11;
            const w2 = dsc21 * @as(F32xN, @floatFromInt(q2)) - dmn21;
            const w3 = dsc31 * @as(F32xN, @floatFromInt(q3)) - dmn31;
            acc_r0_0.* += inp_r0 * w0;
            acc_r0_1.* += inp_r0 * w1;
            acc_r0_2.* += inp_r0 * w2;
            acc_r0_3.* += inp_r0 * w3;
            acc_r1_0.* += inp_r1 * w0;
            acc_r1_1.* += inp_r1 * w1;
            acc_r1_2.* += inp_r1 * w2;
            acc_r1_3.* += inp_r1 * w3;
        }
    }
}

fn preparedQ6KDsc(prepared_block: []const u8, sub: usize) f32 {
    return readF32Le(prepared_block[sub * 4 ..][0..4]);
}

inline fn dotQ6KPreparedBlock(input_block: []const f32, prepared_block: []const u8) f32 {
    std.debug.assert(prepared_block.len == prepared_q4_k_block_bytes);
    const q_values = prepared_block[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    var acc: F32xN = @splat(0.0);
    for (0..16) |sub| {
        const scale: F32xN = @splat(preparedQ6KDsc(prepared_block, sub));
        const q_off = sub * 16;
        const input_off = sub * 16;
        comptime var i: usize = 0;
        inline while (i < 16) : (i += VEC_LEN) {
            const raw: U8xN = q_values[q_off + i ..][0..VEC_LEN].*;
            const q: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw));
            const inp: F32xN = input_block[input_off + i ..][0..VEC_LEN].*;
            acc += inp * (scale * @as(F32xN, @floatFromInt(q)));
        }
    }
    return @reduce(.Add, acc);
}

inline fn dotQ6KPreparedQ8KBlock(q8_block: []const u8, prepared_block: []const u8) f32 {
    std.debug.assert(q8_block.len == 292);
    std.debug.assert(prepared_block.len == prepared_q4_k_block_bytes);

    const qx = q8_block[4..260];
    const x_d = readF32Le(q8_block[0..4]);
    const q_values = prepared_block[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    var acc: f32 = 0.0;
    for (0..16) |sub| {
        const scale = x_d * preparedQ6KDsc(prepared_block, sub);
        const q_off = sub * 16;
        const dot = dotI8I8Block16(qx[q_off..][0..16], q_values[q_off..][0..16]);
        acc += scale * @as(f32, @floatFromInt(dot));
    }
    return acc;
}

inline fn dotQ6KPreparedQ8KBlock4(
    q8_block: []const u8,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
) struct { f32, f32, f32, f32 } {
    std.debug.assert(q8_block.len == 292);
    std.debug.assert(prepared_block0.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block1.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block2.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block3.len == prepared_q4_k_block_bytes);

    const qx = q8_block[4..260];
    const x_d = readF32Le(q8_block[0..4]);
    const q_values0 = prepared_block0[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values1 = prepared_block1[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values2 = prepared_block2[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values3 = prepared_block3[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    var acc0: f32 = 0.0;
    var acc1: f32 = 0.0;
    var acc2: f32 = 0.0;
    var acc3: f32 = 0.0;
    for (0..16) |sub| {
        const q_off = sub * 16;
        const dots = dotI8I8Block4_16(
            qx[q_off..][0..16],
            q_values0[q_off..][0..16],
            q_values1[q_off..][0..16],
            q_values2[q_off..][0..16],
            q_values3[q_off..][0..16],
        );
        acc0 += (x_d * preparedQ6KDsc(prepared_block0, sub)) * @as(f32, @floatFromInt(dots[0]));
        acc1 += (x_d * preparedQ6KDsc(prepared_block1, sub)) * @as(f32, @floatFromInt(dots[1]));
        acc2 += (x_d * preparedQ6KDsc(prepared_block2, sub)) * @as(f32, @floatFromInt(dots[2]));
        acc3 += (x_d * preparedQ6KDsc(prepared_block3, sub)) * @as(f32, @floatFromInt(dots[3]));
    }
    return .{ acc0, acc1, acc2, acc3 };
}

inline fn dotQ6KPreparedQ8KBlock8(
    q8_block: []const u8,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
    prepared_block4: []const u8,
    prepared_block5: []const u8,
    prepared_block6: []const u8,
    prepared_block7: []const u8,
) [8]f32 {
    std.debug.assert(q8_block.len == 292);
    std.debug.assert(prepared_block0.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block1.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block2.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block3.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block4.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block5.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block6.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block7.len == prepared_q4_k_block_bytes);

    const qx = q8_block[4..260];
    const x_d = readF32Le(q8_block[0..4]);
    const q_values0 = prepared_block0[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values1 = prepared_block1[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values2 = prepared_block2[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values3 = prepared_block3[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values4 = prepared_block4[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values5 = prepared_block5[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values6 = prepared_block6[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values7 = prepared_block7[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    var acc: [8]f32 = @splat(0.0);
    for (0..16) |sub| {
        const q_off = sub * 16;
        const dots = dotI8I8Block8_16(
            qx[q_off..][0..16],
            q_values0[q_off..][0..16],
            q_values1[q_off..][0..16],
            q_values2[q_off..][0..16],
            q_values3[q_off..][0..16],
            q_values4[q_off..][0..16],
            q_values5[q_off..][0..16],
            q_values6[q_off..][0..16],
            q_values7[q_off..][0..16],
        );
        acc[0] += (x_d * preparedQ6KDsc(prepared_block0, sub)) * @as(f32, @floatFromInt(dots[0]));
        acc[1] += (x_d * preparedQ6KDsc(prepared_block1, sub)) * @as(f32, @floatFromInt(dots[1]));
        acc[2] += (x_d * preparedQ6KDsc(prepared_block2, sub)) * @as(f32, @floatFromInt(dots[2]));
        acc[3] += (x_d * preparedQ6KDsc(prepared_block3, sub)) * @as(f32, @floatFromInt(dots[3]));
        acc[4] += (x_d * preparedQ6KDsc(prepared_block4, sub)) * @as(f32, @floatFromInt(dots[4]));
        acc[5] += (x_d * preparedQ6KDsc(prepared_block5, sub)) * @as(f32, @floatFromInt(dots[5]));
        acc[6] += (x_d * preparedQ6KDsc(prepared_block6, sub)) * @as(f32, @floatFromInt(dots[6]));
        acc[7] += (x_d * preparedQ6KDsc(prepared_block7, sub)) * @as(f32, @floatFromInt(dots[7]));
    }
    return acc;
}

inline fn q6KPanel8ScaleI32(panel_block: []const u8, sub: usize) I32x8 {
    const raw: U8x8 = panel_block[prepared_q6_k_panel8_scales_offset + sub * prepared_k_panel8_nr ..][0..prepared_k_panel8_nr].*;
    const signed: I8x8 = @bitCast(raw);
    return @intCast(signed);
}

inline fn q6KPanel8ValuesBase(sub: usize) usize {
    return prepared_q6_k_panel8_values_offset + sub * prepared_k_panel8_nr * 16;
}

inline fn q6KPanel8WeightScale(panel_block: []const u8) F32x8 {
    return readF32x8Le(panel_block[prepared_q6_k_panel8_d_offset..][0..32]);
}

inline fn q6KPanel8ScaledSdot16(acc: I32x4, raw_x: U8x16, raw_w: U8x16, scale: i32) I32x4 {
    return acc + aarch64Sdot16(@splat(0), raw_x, raw_w) * @as(I32x4, @splat(scale));
}

inline fn q6KPanel8ReduceWeighted8(acc: [8]I32x4) I32x8 {
    return .{
        @reduce(.Add, acc[0]),
        @reduce(.Add, acc[1]),
        @reduce(.Add, acc[2]),
        @reduce(.Add, acc[3]),
        @reduce(.Add, acc[4]),
        @reduce(.Add, acc[5]),
        @reduce(.Add, acc[6]),
        @reduce(.Add, acc[7]),
    };
}

inline fn dotQ6KPreparedQ8KPanel8VecFusedSdot(q8_block: []const u8, panel_block: []const u8) F32x8 {
    std.debug.assert(q8_block.len == 292);
    std.debug.assert(panel_block.len == prepared_q6_k_panel8_block_bytes);

    const qx = q8_block[4..260];
    const final_scale = @as(F32x8, @splat(readF32Le(q8_block[0..4]))) * q6KPanel8WeightScale(panel_block);
    var weighted: [8]I32x4 = [_]I32x4{@splat(0)} ** 8;
    inline for (0..16) |sub| {
        const raw_x: U8x16 = qx[sub * 16 ..][0..16].*;
        const values_base = q6KPanel8ValuesBase(sub);
        const scales = q6KPanel8ScaleI32(panel_block, sub);
        inline for (0..prepared_k_panel8_nr) |lane| {
            const raw_w: U8x16 = panel_block[values_base + lane * 16 ..][0..16].*;
            weighted[lane] = q6KPanel8ScaledSdot16(weighted[lane], raw_x, raw_w, scales[lane]);
        }
    }
    return final_scale * @as(F32x8, @floatFromInt(q6KPanel8ReduceWeighted8(weighted)));
