inline fn panel16FromAcc(acc_lo: F32x8, acc_hi: F32x8) [16]f32 {
    var out: [16]f32 = undefined;
    const lo = f32x8ToArray(acc_lo);
    const hi = f32x8ToArray(acc_hi);
    for (0..8) |idx| {
        out[idx] = lo[idx];
        out[idx + 8] = hi[idx];
    }
    return out;
}

inline fn dotQ6KPreparedQ8KPanel16(q8_block: []const u8, panel_block: []const u8) [16]f32 {
