    const qx1 = q8_block_r1[4..260];
    const x_d0 = readF32Le(q8_block_r0[0..4]);
    const x_d1 = readF32Le(q8_block_r1[0..4]);
    const q_values0 = prepared_block0[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values1 = prepared_block1[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values2 = prepared_block2[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values3 = prepared_block3[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    var acc_r0_0: f32 = 0.0;
    var acc_r0_1: f32 = 0.0;
    var acc_r0_2: f32 = 0.0;
    var acc_r0_3: f32 = 0.0;
    var acc_r1_0: f32 = 0.0;
    var acc_r1_1: f32 = 0.0;
    var acc_r1_2: f32 = 0.0;
    var acc_r1_3: f32 = 0.0;
    for (0..16) |sub| {
        const q_off = sub * 16;
        const dots = dotI8I8Block4MR2_16(
            qx0[q_off..][0..16],
            qx1[q_off..][0..16],
            q_values0[q_off..][0..16],
            q_values1[q_off..][0..16],
            q_values2[q_off..][0..16],
            q_values3[q_off..][0..16],
        );
        const dsc0 = preparedQ6KDsc(prepared_block0, sub);
        const dsc1 = preparedQ6KDsc(prepared_block1, sub);
        const dsc2 = preparedQ6KDsc(prepared_block2, sub);
        const dsc3 = preparedQ6KDsc(prepared_block3, sub);
        acc_r0_0 += (x_d0 * dsc0) * @as(f32, @floatFromInt(dots[0]));
        acc_r0_1 += (x_d0 * dsc1) * @as(f32, @floatFromInt(dots[1]));
        acc_r0_2 += (x_d0 * dsc2) * @as(f32, @floatFromInt(dots[2]));
        acc_r0_3 += (x_d0 * dsc3) * @as(f32, @floatFromInt(dots[3]));
        acc_r1_0 += (x_d1 * dsc0) * @as(f32, @floatFromInt(dots[4]));
        acc_r1_1 += (x_d1 * dsc1) * @as(f32, @floatFromInt(dots[5]));
        acc_r1_2 += (x_d1 * dsc2) * @as(f32, @floatFromInt(dots[6]));
        acc_r1_3 += (x_d1 * dsc3) * @as(f32, @floatFromInt(dots[7]));
    }
    return .{ acc_r0_0, acc_r0_1, acc_r0_2, acc_r0_3, acc_r1_0, acc_r1_1, acc_r1_2, acc_r1_3 };
}

inline fn q8KBlockSum(q8_block: []const u8, sub32: usize) i32 {
    const sum0 = std.mem.readInt(i16, q8_block[260 + sub32 * 4 ..][0..2], .little);
    const sum1 = std.mem.readInt(i16, q8_block[260 + sub32 * 4 + 2 ..][0..2], .little);
    return @as(i32, @intCast(sum0)) + @as(i32, @intCast(sum1));
}

inline fn prepareQ8KActivationSums(q8_block: []const u8, out: *[8]F32x8) void {
    std.debug.assert(q8_block.len == 292);
    inline for (0..8) |sub| {
        out[sub] = @splat(@as(f32, @floatFromInt(q8KBlockSum(q8_block, sub))));
    }
}

fn dotQ4Q5KPreparedQ8KBlock(q8_block: []const u8, prepared_block: []const u8) f32 {
    std.debug.assert(q8_block.len == 292);
    std.debug.assert(prepared_block.len == prepared_q4_k_block_bytes);

    const qx = q8_block[4..260];
    const x_d = readF32Le(q8_block[0..4]);
    const q_values = prepared_block[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    var acc: f32 = 0.0;
    for (0..8) |sub| {
        const q_off = sub * 32;
        const dot = dotI8I8Block(qx[q_off..][0..32], q_values[q_off..][0..32]);
        const activation_sum = q8KBlockSum(q8_block, sub);
        const dsc = preparedQ4KDsc(prepared_block, sub);
        const dmn = preparedQ4KDmn(prepared_block, sub);
        acc += x_d * (dsc * @as(f32, @floatFromInt(dot)) - dmn * @as(f32, @floatFromInt(activation_sum)));
    }
    return acc;
}

inline fn dotQ4Q5KPreparedQ8KBlock4(
    q8_block: []const u8,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
) struct { f32, f32, f32, f32 } {
    std.debug.assert(q8_block.len == 292);
    std.debug.assert(prepared_block0.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block1.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block2.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block3.len == prepared_q4_k_block_bytes);

    const qx = q8_block[4..260];
    const x_d = readF32Le(q8_block[0..4]);
    const q_values0 = prepared_block0[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values1 = prepared_block1[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values2 = prepared_block2[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values3 = prepared_block3[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    var acc0: f32 = 0.0;
    var acc1: f32 = 0.0;
    var acc2: f32 = 0.0;
    var acc3: f32 = 0.0;
    for (0..8) |sub| {
        const q_off = sub * 32;
        const dots = dotI8I8Block4(
            qx[q_off..][0..32],
            q_values0[q_off..][0..32],
            q_values1[q_off..][0..32],
            q_values2[q_off..][0..32],
            q_values3[q_off..][0..32],
        );
        const activation_sum_f = @as(f32, @floatFromInt(q8KBlockSum(q8_block, sub)));
        const dot0_f = @as(f32, @floatFromInt(dots[0]));
        const dot1_f = @as(f32, @floatFromInt(dots[1]));
        const dot2_f = @as(f32, @floatFromInt(dots[2]));
        const dot3_f = @as(f32, @floatFromInt(dots[3]));
        acc0 += x_d * (preparedQ4KDsc(prepared_block0, sub) * dot0_f - preparedQ4KDmn(prepared_block0, sub) * activation_sum_f);
        acc1 += x_d * (preparedQ4KDsc(prepared_block1, sub) * dot1_f - preparedQ4KDmn(prepared_block1, sub) * activation_sum_f);
        acc2 += x_d * (preparedQ4KDsc(prepared_block2, sub) * dot2_f - preparedQ4KDmn(prepared_block2, sub) * activation_sum_f);
        acc3 += x_d * (preparedQ4KDsc(prepared_block3, sub) * dot3_f - preparedQ4KDmn(prepared_block3, sub) * activation_sum_f);
    }
    return .{ acc0, acc1, acc2, acc3 };
}

inline fn dotQ4Q5KPreparedQ8KBlock8(
    q8_block: []const u8,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
