) Panel16MR4Sums {
    std.debug.assert(q8_block_r0.len == 292);
    std.debug.assert(q8_block_r1.len == 292);
    std.debug.assert(q8_block_r2.len == 292);
    std.debug.assert(q8_block_r3.len == 292);
    std.debug.assert(panel_block.len == prepared_k_panel16_block_bytes);

    var acc0_lo: F32x8 = @splat(0.0);
    var acc0_hi: F32x8 = @splat(0.0);
    var acc1_lo: F32x8 = @splat(0.0);
    var acc1_hi: F32x8 = @splat(0.0);
    var acc2_lo: F32x8 = @splat(0.0);
    var acc2_hi: F32x8 = @splat(0.0);
    var acc3_lo: F32x8 = @splat(0.0);
    var acc3_hi: F32x8 = @splat(0.0);
    accumulateQ4Q5KPreparedQ8KPanel16MR4Block(q8_block_r0, q8_block_r1, q8_block_r2, q8_block_r3, panel_block, &acc0_lo, &acc0_hi, &acc1_lo, &acc1_hi, &acc2_lo, &acc2_hi, &acc3_lo, &acc3_hi);
    return panel16MR4FromAcc(acc0_lo, acc0_hi, acc1_lo, acc1_hi, acc2_lo, acc2_hi, acc3_lo, acc3_hi);
}

inline fn dotQ4Q5KPreparedQ8KPanel16MR2PreparedSums(
    q8_block_r0: []const u8,
    q8_block_r1: []const u8,
    activation_sum0: *const [8]F32x8,
    activation_sum1: *const [8]F32x8,
    panel_block: []const u8,
) Panel16MR2Sums {
    std.debug.assert(q8_block_r0.len == 292);
    std.debug.assert(q8_block_r1.len == 292);
    std.debug.assert(panel_block.len == prepared_k_panel16_block_bytes);

    const qx0 = q8_block_r0[4..260];
    const qx1 = q8_block_r1[4..260];
    const x_scale0: F32x8 = @splat(readF32Le(q8_block_r0[0..4]));
    const x_scale1: F32x8 = @splat(readF32Le(q8_block_r1[0..4]));
    var acc0_lo: F32x8 = @splat(0.0);
    var acc0_hi: F32x8 = @splat(0.0);
    var acc1_lo: F32x8 = @splat(0.0);
    var acc1_hi: F32x8 = @splat(0.0);
    for (0..8) |sub| {
        const q_off = sub * 32;
        const values_base = prepared_k_panel16_values_offset + sub * prepared_k_panel16_nr * 32;
        const w0 = panel_block[values_base..][0..32];
        const w1 = panel_block[values_base + 32 ..][0..32];
        const w2 = panel_block[values_base + 2 * 32 ..][0..32];
        const w3 = panel_block[values_base + 3 * 32 ..][0..32];
        const w4 = panel_block[values_base + 4 * 32 ..][0..32];
        const w5 = panel_block[values_base + 5 * 32 ..][0..32];
        const w6 = panel_block[values_base + 6 * 32 ..][0..32];
        const w7 = panel_block[values_base + 7 * 32 ..][0..32];
        const w8 = panel_block[values_base + 8 * 32 ..][0..32];
        const w9 = panel_block[values_base + 9 * 32 ..][0..32];
        const w10 = panel_block[values_base + 10 * 32 ..][0..32];
        const w11 = panel_block[values_base + 11 * 32 ..][0..32];
        const w12 = panel_block[values_base + 12 * 32 ..][0..32];
        const w13 = panel_block[values_base + 13 * 32 ..][0..32];
        const w14 = panel_block[values_base + 14 * 32 ..][0..32];
        const w15 = panel_block[values_base + 15 * 32 ..][0..32];
        const dots_lo = dotI8I8Block8MR2RowsVec(qx0[q_off..][0..32], qx1[q_off..][0..32], w0, w1, w2, w3, w4, w5, w6, w7);
        const dots_hi = dotI8I8Block8MR2RowsVec(qx0[q_off..][0..32], qx1[q_off..][0..32], w8, w9, w10, w11, w12, w13, w14, w15);
        const dsc_lo = readF32x8Le(panel_block[prepared_k_panel16_dsc_offset + sub * prepared_k_panel16_nr * 4 ..][0..32]);
        const dsc_hi = readF32x8Le(panel_block[prepared_k_panel16_dsc_offset + (sub * prepared_k_panel16_nr + 8) * 4 ..][0..32]);
        const dmn_lo = readF32x8Le(panel_block[prepared_k_panel16_dmn_offset + sub * prepared_k_panel16_nr * 4 ..][0..32]);
        const dmn_hi = readF32x8Le(panel_block[prepared_k_panel16_dmn_offset + (sub * prepared_k_panel16_nr + 8) * 4 ..][0..32]);
        acc0_lo += x_scale0 * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo.r0)) - dmn_lo * activation_sum0[sub]);
        acc1_lo += x_scale1 * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo.r1)) - dmn_lo * activation_sum1[sub]);
        acc0_hi += x_scale0 * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi.r0)) - dmn_hi * activation_sum0[sub]);
        acc1_hi += x_scale1 * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi.r1)) - dmn_hi * activation_sum1[sub]);
    }
    var r0: [16]f32 = undefined;
    var r1: [16]f32 = undefined;
    const r0_lo = f32x8ToArray(acc0_lo);
    const r0_hi = f32x8ToArray(acc0_hi);
    const r1_lo = f32x8ToArray(acc1_lo);
    const r1_hi = f32x8ToArray(acc1_hi);
    inline for (0..8) |idx| {
        r0[idx] = r0_lo[idx];
        r0[idx + 8] = r0_hi[idx];
        r1[idx] = r1_lo[idx];
        r1[idx + 8] = r1_hi[idx];
    }
    return .{ .r0 = r0, .r1 = r1 };
}

inline fn dotQ4Q5KPreparedQ8KPanel16MR4PreparedSums(
    q8_block_r0: []const u8,
    q8_block_r1: []const u8,
    q8_block_r2: []const u8,
    q8_block_r3: []const u8,
    activation_sum0: *const [8]F32x8,
    activation_sum1: *const [8]F32x8,
    activation_sum2: *const [8]F32x8,
    activation_sum3: *const [8]F32x8,
    panel_block: []const u8,
) Panel16MR4Sums {
    std.debug.assert(q8_block_r0.len == 292);
    std.debug.assert(q8_block_r1.len == 292);
    std.debug.assert(q8_block_r2.len == 292);
    std.debug.assert(q8_block_r3.len == 292);
    std.debug.assert(panel_block.len == prepared_k_panel16_block_bytes);

    const qx0 = q8_block_r0[4..260];
    const qx1 = q8_block_r1[4..260];
    const qx2 = q8_block_r2[4..260];
    const qx3 = q8_block_r3[4..260];
    const x_scale0: F32x8 = @splat(readF32Le(q8_block_r0[0..4]));
    const x_scale1: F32x8 = @splat(readF32Le(q8_block_r1[0..4]));
    const x_scale2: F32x8 = @splat(readF32Le(q8_block_r2[0..4]));
    const x_scale3: F32x8 = @splat(readF32Le(q8_block_r3[0..4]));
    var acc0_lo: F32x8 = @splat(0.0);
    var acc0_hi: F32x8 = @splat(0.0);
    var acc1_lo: F32x8 = @splat(0.0);
    var acc1_hi: F32x8 = @splat(0.0);
    var acc2_lo: F32x8 = @splat(0.0);
    var acc2_hi: F32x8 = @splat(0.0);
    var acc3_lo: F32x8 = @splat(0.0);
    var acc3_hi: F32x8 = @splat(0.0);
    for (0..8) |sub| {
        const q_off = sub * 32;
        const values_base = prepared_k_panel16_values_offset + sub * prepared_k_panel16_nr * 32;
        const w0 = panel_block[values_base..][0..32];
        const w1 = panel_block[values_base + 32 ..][0..32];
        const w2 = panel_block[values_base + 2 * 32 ..][0..32];
        const w3 = panel_block[values_base + 3 * 32 ..][0..32];
        const w4 = panel_block[values_base + 4 * 32 ..][0..32];
        const w5 = panel_block[values_base + 5 * 32 ..][0..32];
        const w6 = panel_block[values_base + 6 * 32 ..][0..32];
        const w7 = panel_block[values_base + 7 * 32 ..][0..32];
        const w8 = panel_block[values_base + 8 * 32 ..][0..32];
        const w9 = panel_block[values_base + 9 * 32 ..][0..32];
        const w10 = panel_block[values_base + 10 * 32 ..][0..32];
        const w11 = panel_block[values_base + 11 * 32 ..][0..32];
        const w12 = panel_block[values_base + 12 * 32 ..][0..32];
        const w13 = panel_block[values_base + 13 * 32 ..][0..32];
        const w14 = panel_block[values_base + 14 * 32 ..][0..32];
        const w15 = panel_block[values_base + 15 * 32 ..][0..32];
        const dots_lo = dotI8I8Block8MR4RowsVec(qx0[q_off..][0..32], qx1[q_off..][0..32], qx2[q_off..][0..32], qx3[q_off..][0..32], w0, w1, w2, w3, w4, w5, w6, w7);
        const dots_hi = dotI8I8Block8MR4RowsVec(qx0[q_off..][0..32], qx1[q_off..][0..32], qx2[q_off..][0..32], qx3[q_off..][0..32], w8, w9, w10, w11, w12, w13, w14, w15);
        const dsc_lo = readF32x8Le(panel_block[prepared_k_panel16_dsc_offset + sub * prepared_k_panel16_nr * 4 ..][0..32]);
        const dsc_hi = readF32x8Le(panel_block[prepared_k_panel16_dsc_offset + (sub * prepared_k_panel16_nr + 8) * 4 ..][0..32]);
        const dmn_lo = readF32x8Le(panel_block[prepared_k_panel16_dmn_offset + sub * prepared_k_panel16_nr * 4 ..][0..32]);
        const dmn_hi = readF32x8Le(panel_block[prepared_k_panel16_dmn_offset + (sub * prepared_k_panel16_nr + 8) * 4 ..][0..32]);
        acc0_lo += x_scale0 * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo.r0)) - dmn_lo * activation_sum0[sub]);
        acc1_lo += x_scale1 * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo.r1)) - dmn_lo * activation_sum1[sub]);
        acc2_lo += x_scale2 * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo.r2)) - dmn_lo * activation_sum2[sub]);
        acc3_lo += x_scale3 * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo.r3)) - dmn_lo * activation_sum3[sub]);
        acc0_hi += x_scale0 * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi.r0)) - dmn_hi * activation_sum0[sub]);
        acc1_hi += x_scale1 * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi.r1)) - dmn_hi * activation_sum1[sub]);
        acc2_hi += x_scale2 * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi.r2)) - dmn_hi * activation_sum2[sub]);
        acc3_hi += x_scale3 * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi.r3)) - dmn_hi * activation_sum3[sub]);
    }
    var r0: [16]f32 = undefined;
    var r1: [16]f32 = undefined;
    var r2: [16]f32 = undefined;
    var r3: [16]f32 = undefined;
    const r0_lo = f32x8ToArray(acc0_lo);
    const r0_hi = f32x8ToArray(acc0_hi);
    const r1_lo = f32x8ToArray(acc1_lo);
    const r1_hi = f32x8ToArray(acc1_hi);
    const r2_lo = f32x8ToArray(acc2_lo);
    const r2_hi = f32x8ToArray(acc2_hi);
    const r3_lo = f32x8ToArray(acc3_lo);
    const r3_hi = f32x8ToArray(acc3_hi);
    inline for (0..8) |idx| {
        r0[idx] = r0_lo[idx];
        r0[idx + 8] = r0_hi[idx];
        r1[idx] = r1_lo[idx];
        r1[idx + 8] = r1_hi[idx];
        r2[idx] = r2_lo[idx];
        r2[idx + 8] = r2_hi[idx];
        r3[idx] = r3_lo[idx];
        r3[idx + 8] = r3_hi[idx];
    }
    return .{ .r0 = r0, .r1 = r1, .r2 = r2, .r3 = r3 };
}

inline fn q4q5KTriplePanel16Block(panel_a: []const u8, panel_b: []const u8, panel_c: []const u8, panel_off: usize) Q4Q5KTriplePanel16Block {
    return .{
        .a = panel_a[panel_off..][0..prepared_k_panel16_block_bytes],
        .b = panel_b[panel_off..][0..prepared_k_panel16_block_bytes],
        .c = panel_c[panel_off..][0..prepared_k_panel16_block_bytes],
    };
}

inline fn q4q5KPhysicalQKVPanel16Block(packed_qkv: []const u8, panel_off: usize) []const u8 {
    const packed_off = (panel_off / prepared_k_panel16_block_bytes) * prepared_k_qkv_panel16_block_bytes;
    return packed_qkv[packed_off..][0..prepared_k_qkv_panel16_block_bytes];
}

inline fn packedQKVPanel16Dsc(block: []const u8, sub: usize, comptime proj: usize, comptime lane_base: usize) F32x8 {
    const off = prepared_k_qkv_panel16_dsc_offset + ((sub * prepared_k_qkv_panel16_proj + proj) * prepared_k_panel16_nr + lane_base) * 4;
    return readF32x8Le(block[off..][0..32]);
}

inline fn packedQKVPanel16Dmn(block: []const u8, sub: usize, comptime proj: usize, comptime lane_base: usize) F32x8 {
    const off = prepared_k_qkv_panel16_dmn_offset + ((sub * prepared_k_qkv_panel16_proj + proj) * prepared_k_panel16_nr + lane_base) * 4;
    return readF32x8Le(block[off..][0..32]);
}

inline fn packedQKVPanel16Values(block: []const u8, sub: usize, comptime proj: usize, comptime lane: usize) *const [32]u8 {
    const off = prepared_k_qkv_panel16_values_offset + ((sub * prepared_k_qkv_panel16_proj + proj) * prepared_k_panel16_nr + lane) * 32;
    return block[off..][0..32];
}

inline fn packedQKVPanel16Values8Base(block: []const u8, sub: usize, comptime proj: usize, comptime lane_base: usize) []const u8 {
    const off = prepared_k_qkv_panel16_values_offset + ((sub * prepared_k_qkv_panel16_proj + proj) * prepared_k_panel16_nr + lane_base) * 32;
    return block[off..][0 .. 8 * 32];
}

const PackedQKVPanel16SubProjectionView = struct {
    dsc_lo: []const u8,
    dsc_hi: []const u8,
    dmn_lo: []const u8,
    dmn_hi: []const u8,
    values_lo: []const u8,
    values_hi: []const u8,
};

inline fn packedQKVPanel16SubProjectionViewFromLaneBase(block: []const u8, lane_base: usize) PackedQKVPanel16SubProjectionView {
    const meta_base = lane_base * 4;
    const values_base = lane_base * 32;
    return .{
        .dsc_lo = block[prepared_k_qkv_panel16_dsc_offset + meta_base ..][0..32],
        .dsc_hi = block[prepared_k_qkv_panel16_dsc_offset + meta_base + 8 * 4 ..][0..32],
        .dmn_lo = block[prepared_k_qkv_panel16_dmn_offset + meta_base ..][0..32],
        .dmn_hi = block[prepared_k_qkv_panel16_dmn_offset + meta_base + 8 * 4 ..][0..32],
        .values_lo = block[prepared_k_qkv_panel16_values_offset + values_base ..][0 .. 8 * 32],
        .values_hi = block[prepared_k_qkv_panel16_values_offset + values_base + 8 * 32 ..][0 .. 8 * 32],
    };
}

inline fn packedQKVPanel16SubProjectionView(block: []const u8, sub: usize, comptime proj: usize) PackedQKVPanel16SubProjectionView {
    const lane_base = (sub * prepared_k_qkv_panel16_proj + proj) * prepared_k_panel16_nr;
    return packedQKVPanel16SubProjectionViewFromLaneBase(block, lane_base);
}

inline fn accumulateQ4Q5KPackedQKVPanel16NR16MR1(
    qx: []const u8,
    q_off: usize,
    x_scale: F32x8,
    activation_sum: F32x8,
    block: []const u8,
    sub: usize,
    comptime proj: usize,
    acc_lo: *F32x8,
    acc_hi: *F32x8,
) void {
    const view = packedQKVPanel16SubProjectionView(block, sub, proj);
    const dots_lo = dotI8I8Block8ContiguousVec(qx[q_off..][0..32], view.values_lo);
    const dots_hi = dotI8I8Block8ContiguousVec(qx[q_off..][0..32], view.values_hi);
    const dsc_lo = readF32x8Le(view.dsc_lo);
    const dsc_hi = readF32x8Le(view.dsc_hi);
    const dmn_lo = readF32x8Le(view.dmn_lo);
    const dmn_hi = readF32x8Le(view.dmn_hi);
    acc_lo.* += x_scale * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo)) - dmn_lo * activation_sum);
    acc_hi.* += x_scale * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi)) - dmn_hi * activation_sum);
}

inline fn accumulateQ4Q5KPackedQKVPanel16NR8MR2(
    qx0: []const u8,
    qx1: []const u8,
    q_off: usize,
    x_scale0: F32x8,
    x_scale1: F32x8,
    activation_sum0: F32x8,
    activation_sum1: F32x8,
    block: []const u8,
    sub: usize,
    comptime proj: usize,
    comptime lane_base: usize,
    acc0: *F32x8,
    acc1: *F32x8,
) void {
    const view = packedQKVPanel16SubProjectionView(block, sub, proj);
    const values = if (lane_base == 0) view.values_lo else view.values_hi;
    const dots = dotI8I8Block8MR2RowsContiguousVec(qx0[q_off..][0..32], qx1[q_off..][0..32], values);
    const dsc = readF32x8Le(if (lane_base == 0) view.dsc_lo else view.dsc_hi);
    const dmn = readF32x8Le(if (lane_base == 0) view.dmn_lo else view.dmn_hi);
    acc0.* += x_scale0 * (dsc * @as(F32x8, @floatFromInt(dots.r0)) - dmn * activation_sum0);
    acc1.* += x_scale1 * (dsc * @as(F32x8, @floatFromInt(dots.r1)) - dmn * activation_sum1);
}

inline fn accumulateQ4Q5KPackedQKVPanel16NR16MR2(
    qx0: []const u8,
    qx1: []const u8,
    q_off: usize,
    x_scale0: F32x8,
    x_scale1: F32x8,
    activation_sum0: F32x8,
    activation_sum1: F32x8,
    block: []const u8,
    sub: usize,
    comptime proj: usize,
    acc0_lo: *F32x8,
    acc0_hi: *F32x8,
    acc1_lo: *F32x8,
    acc1_hi: *F32x8,
) void {
    const view = packedQKVPanel16SubProjectionView(block, sub, proj);
    const dots_lo = dotI8I8Block8MR2RowsContiguousVec(qx0[q_off..][0..32], qx1[q_off..][0..32], view.values_lo);
    const dots_hi = dotI8I8Block8MR2RowsContiguousVec(qx0[q_off..][0..32], qx1[q_off..][0..32], view.values_hi);
    const dsc_lo = readF32x8Le(view.dsc_lo);
    const dsc_hi = readF32x8Le(view.dsc_hi);
    const dmn_lo = readF32x8Le(view.dmn_lo);
    const dmn_hi = readF32x8Le(view.dmn_hi);
    acc0_lo.* += x_scale0 * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo.r0)) - dmn_lo * activation_sum0);
    acc1_lo.* += x_scale1 * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo.r1)) - dmn_lo * activation_sum1);
    acc0_hi.* += x_scale0 * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi.r0)) - dmn_hi * activation_sum0);
    acc1_hi.* += x_scale1 * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi.r1)) - dmn_hi * activation_sum1);
}

inline fn accumulateQ4Q5KPackedQKVPanel16NR8MR4(
    qsub0: *const [32]u8,
    qsub1: *const [32]u8,
    qsub2: *const [32]u8,
    qsub3: *const [32]u8,
    x_scale0: F32x8,
    x_scale1: F32x8,
    x_scale2: F32x8,
    x_scale3: F32x8,
    activation_sum0: F32x8,
    activation_sum1: F32x8,
    activation_sum2: F32x8,
    activation_sum3: F32x8,
    block: []const u8,
    sub: usize,
    comptime proj: usize,
    comptime lane_base: usize,
    acc0: *F32x8,
    acc1: *F32x8,
    acc2: *F32x8,
    acc3: *F32x8,
) void {
    const view = packedQKVPanel16SubProjectionView(block, sub, proj);
    const values = if (lane_base == 0) view.values_lo else view.values_hi;
    const dots = dotI8I8Block8MR4RowsContiguousVec(
        qsub0,
        qsub1,
        qsub2,
        qsub3,
        values,
    );
    const dsc = readF32x8Le(if (lane_base == 0) view.dsc_lo else view.dsc_hi);
    const dmn = readF32x8Le(if (lane_base == 0) view.dmn_lo else view.dmn_hi);
    acc0.* += x_scale0 * (dsc * @as(F32x8, @floatFromInt(dots.r0)) - dmn * activation_sum0);
    acc1.* += x_scale1 * (dsc * @as(F32x8, @floatFromInt(dots.r1)) - dmn * activation_sum1);
    acc2.* += x_scale2 * (dsc * @as(F32x8, @floatFromInt(dots.r2)) - dmn * activation_sum2);
    acc3.* += x_scale3 * (dsc * @as(F32x8, @floatFromInt(dots.r3)) - dmn * activation_sum3);
}

inline fn accumulateQ4Q5KPackedQKVPanel16NR16MR4ProjectionView(
    qsub0: *const [32]u8,
    qsub1: *const [32]u8,
    qsub2: *const [32]u8,
    qsub3: *const [32]u8,
    x_scale0: F32x8,
    x_scale1: F32x8,
    x_scale2: F32x8,
    x_scale3: F32x8,
    activation_sum0: F32x8,
    activation_sum1: F32x8,
    activation_sum2: F32x8,
    activation_sum3: F32x8,
    view: PackedQKVPanel16SubProjectionView,
    acc0_lo: *F32x8,
    acc0_hi: *F32x8,
    acc1_lo: *F32x8,
    acc1_hi: *F32x8,
    acc2_lo: *F32x8,
    acc2_hi: *F32x8,
    acc3_lo: *F32x8,
    acc3_hi: *F32x8,
) void {
    const dots_lo = dotI8I8Block8MR4RowsContiguousVec(
        qsub0,
        qsub1,
        qsub2,
        qsub3,
        view.values_lo,
    );
    const dots_hi = dotI8I8Block8MR4RowsContiguousVec(
        qsub0,
        qsub1,
        qsub2,
        qsub3,
        view.values_hi,
    );
    const dsc_lo = readF32x8Le(view.dsc_lo);
    const dsc_hi = readF32x8Le(view.dsc_hi);
    const dmn_lo = readF32x8Le(view.dmn_lo);
    const dmn_hi = readF32x8Le(view.dmn_hi);
    acc0_lo.* += x_scale0 * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo.r0)) - dmn_lo * activation_sum0);
    acc1_lo.* += x_scale1 * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo.r1)) - dmn_lo * activation_sum1);
    acc2_lo.* += x_scale2 * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo.r2)) - dmn_lo * activation_sum2);
    acc3_lo.* += x_scale3 * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo.r3)) - dmn_lo * activation_sum3);
    acc0_hi.* += x_scale0 * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi.r0)) - dmn_hi * activation_sum0);
    acc1_hi.* += x_scale1 * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi.r1)) - dmn_hi * activation_sum1);
    acc2_hi.* += x_scale2 * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi.r2)) - dmn_hi * activation_sum2);
    acc3_hi.* += x_scale3 * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi.r3)) - dmn_hi * activation_sum3);
}

inline fn accumulateQ4Q5KPackedQKVPanel16NR16MR8ProjectionView(
    qsubs: [8]*const [32]u8,
    x_scales: [8]F32x8,
    activation_sums: [8]F32x8,
    view: PackedQKVPanel16SubProjectionView,
    acc_lo: *[8]F32x8,
    acc_hi: *[8]F32x8,
) void {
    const dots_lo_0123 = dotI8I8Block8MR4RowsContiguousVec(
        qsubs[0],
        qsubs[1],
        qsubs[2],
        qsubs[3],
        view.values_lo,
    );
    const dots_hi_0123 = dotI8I8Block8MR4RowsContiguousVec(
        qsubs[0],
        qsubs[1],
        qsubs[2],
        qsubs[3],
        view.values_hi,
    );
    const dots_lo_4567 = dotI8I8Block8MR4RowsContiguousVec(
        qsubs[4],
        qsubs[5],
        qsubs[6],
        qsubs[7],
        view.values_lo,
    );
    const dots_hi_4567 = dotI8I8Block8MR4RowsContiguousVec(
        qsubs[4],
        qsubs[5],
        qsubs[6],
        qsubs[7],
        view.values_hi,
    );
    const dsc_lo = readF32x8Le(view.dsc_lo);
    const dsc_hi = readF32x8Le(view.dsc_hi);
    const dmn_lo = readF32x8Le(view.dmn_lo);
    const dmn_hi = readF32x8Le(view.dmn_hi);
    acc_lo.*[0] += x_scales[0] * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo_0123.r0)) - dmn_lo * activation_sums[0]);
    acc_lo.*[1] += x_scales[1] * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo_0123.r1)) - dmn_lo * activation_sums[1]);
    acc_lo.*[2] += x_scales[2] * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo_0123.r2)) - dmn_lo * activation_sums[2]);
    acc_lo.*[3] += x_scales[3] * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo_0123.r3)) - dmn_lo * activation_sums[3]);
    acc_lo.*[4] += x_scales[4] * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo_4567.r0)) - dmn_lo * activation_sums[4]);
    acc_lo.*[5] += x_scales[5] * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo_4567.r1)) - dmn_lo * activation_sums[5]);
    acc_lo.*[6] += x_scales[6] * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo_4567.r2)) - dmn_lo * activation_sums[6]);
    acc_lo.*[7] += x_scales[7] * (dsc_lo * @as(F32x8, @floatFromInt(dots_lo_4567.r3)) - dmn_lo * activation_sums[7]);
    acc_hi.*[0] += x_scales[0] * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi_0123.r0)) - dmn_hi * activation_sums[0]);
    acc_hi.*[1] += x_scales[1] * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi_0123.r1)) - dmn_hi * activation_sums[1]);
    acc_hi.*[2] += x_scales[2] * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi_0123.r2)) - dmn_hi * activation_sums[2]);
    acc_hi.*[3] += x_scales[3] * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi_0123.r3)) - dmn_hi * activation_sums[3]);
    acc_hi.*[4] += x_scales[4] * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi_4567.r0)) - dmn_hi * activation_sums[4]);
    acc_hi.*[5] += x_scales[5] * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi_4567.r1)) - dmn_hi * activation_sums[5]);
    acc_hi.*[6] += x_scales[6] * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi_4567.r2)) - dmn_hi * activation_sums[6]);
    acc_hi.*[7] += x_scales[7] * (dsc_hi * @as(F32x8, @floatFromInt(dots_hi_4567.r3)) - dmn_hi * activation_sums[7]);
}

