inline fn dotQ4Q5KPreparedQ8KPanel8MR4(
    q8_block_r0: []const u8,
    q8_block_r1: []const u8,
    q8_block_r2: []const u8,
    q8_block_r3: []const u8,
    panel_block: []const u8,
) Panel8MR4Sums {
    std.debug.assert(q8_block_r0.len == 292);
    std.debug.assert(q8_block_r1.len == 292);
    std.debug.assert(q8_block_r2.len == 292);
    std.debug.assert(q8_block_r3.len == 292);
    std.debug.assert(panel_block.len == prepared_k_panel8_block_bytes);

    const qx0 = q8_block_r0[4..260];
    const qx1 = q8_block_r1[4..260];
    const qx2 = q8_block_r2[4..260];
    const qx3 = q8_block_r3[4..260];
    const x_scale0: F32x8 = @splat(readF32Le(q8_block_r0[0..4]));
    const x_scale1: F32x8 = @splat(readF32Le(q8_block_r1[0..4]));
    const x_scale2: F32x8 = @splat(readF32Le(q8_block_r2[0..4]));
    const x_scale3: F32x8 = @splat(readF32Le(q8_block_r3[0..4]));
    var acc0: F32x8 = @splat(0.0);
    var acc1: F32x8 = @splat(0.0);
    var acc2: F32x8 = @splat(0.0);
    var acc3: F32x8 = @splat(0.0);
    for (0..8) |sub| {
        const q_off = sub * 32;
        const values_base = prepared_k_panel8_values_offset + sub * prepared_k_panel8_nr * 32;
        const w0 = panel_block[values_base..][0..32];
        const w1 = panel_block[values_base + 32 ..][0..32];
        const w2 = panel_block[values_base + 2 * 32 ..][0..32];
        const w3 = panel_block[values_base + 3 * 32 ..][0..32];
        const w4 = panel_block[values_base + 4 * 32 ..][0..32];
        const w5 = panel_block[values_base + 5 * 32 ..][0..32];
        const w6 = panel_block[values_base + 6 * 32 ..][0..32];
        const w7 = panel_block[values_base + 7 * 32 ..][0..32];
        const dots01 = dotI8I8Block8MR2(qx0[q_off..][0..32], qx1[q_off..][0..32], w0, w1, w2, w3, w4, w5, w6, w7);
        const dots23 = dotI8I8Block8MR2(qx2[q_off..][0..32], qx3[q_off..][0..32], w0, w1, w2, w3, w4, w5, w6, w7);
        const dsc = readF32x8Le(panel_block[prepared_k_panel8_dsc_offset + sub * prepared_k_panel8_nr * 4 ..][0..32]);
        const dmn = readF32x8Le(panel_block[prepared_k_panel8_dmn_offset + sub * prepared_k_panel8_nr * 4 ..][0..32]);
        const activation_sum0: F32x8 = @splat(@as(f32, @floatFromInt(q8KBlockSum(q8_block_r0, sub))));
        const activation_sum1: F32x8 = @splat(@as(f32, @floatFromInt(q8KBlockSum(q8_block_r1, sub))));
        const activation_sum2: F32x8 = @splat(@as(f32, @floatFromInt(q8KBlockSum(q8_block_r2, sub))));
        const activation_sum3: F32x8 = @splat(@as(f32, @floatFromInt(q8KBlockSum(q8_block_r3, sub))));
        const dots0: F32x8 = @floatFromInt(i32ArrayToVec8(dots01[0..8].*));
        const dots1: F32x8 = @floatFromInt(i32ArrayToVec8(dots01[8..16].*));
        const dots2: F32x8 = @floatFromInt(i32ArrayToVec8(dots23[0..8].*));
        const dots3: F32x8 = @floatFromInt(i32ArrayToVec8(dots23[8..16].*));
        acc0 += x_scale0 * (dsc * dots0 - dmn * activation_sum0);
        acc1 += x_scale1 * (dsc * dots1 - dmn * activation_sum1);
        acc2 += x_scale2 * (dsc * dots2 - dmn * activation_sum2);
        acc3 += x_scale3 * (dsc * dots3 - dmn * activation_sum3);
    }
    return .{
        .r0 = f32x8ToArray(acc0),
        .r1 = f32x8ToArray(acc1),
        .r2 = f32x8ToArray(acc2),
        .r3 = f32x8ToArray(acc3),
    };
}

inline fn dotQ4Q5KPreparedQ8KBlock4MR4(
    q8_block_r0: []const u8,
    q8_block_r1: []const u8,
    q8_block_r2: []const u8,
    q8_block_r3: []const u8,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
) [16]f32 {
    std.debug.assert(q8_block_r0.len == 292);
    std.debug.assert(q8_block_r1.len == 292);
    std.debug.assert(q8_block_r2.len == 292);
    std.debug.assert(q8_block_r3.len == 292);
    std.debug.assert(prepared_block0.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block1.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block2.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block3.len == prepared_q4_k_block_bytes);

    const qx0 = q8_block_r0[4..260];
    const qx1 = q8_block_r1[4..260];
    const qx2 = q8_block_r2[4..260];
    const qx3 = q8_block_r3[4..260];
    const x_d0 = readF32Le(q8_block_r0[0..4]);
    const x_d1 = readF32Le(q8_block_r1[0..4]);
    const x_d2 = readF32Le(q8_block_r2[0..4]);
    const x_d3 = readF32Le(q8_block_r3[0..4]);
    const q_values0 = prepared_block0[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values1 = prepared_block1[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values2 = prepared_block2[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values3 = prepared_block3[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    var acc: [16]f32 = [_]f32{0.0} ** 16;
    for (0..8) |sub| {
        const q_off = sub * 32;
        const dots = dotI8I8Block4MR4(
            qx0[q_off..][0..32],
            qx1[q_off..][0..32],
            qx2[q_off..][0..32],
            qx3[q_off..][0..32],
            q_values0[q_off..][0..32],
            q_values1[q_off..][0..32],
            q_values2[q_off..][0..32],
            q_values3[q_off..][0..32],
        );
        const dsc0 = preparedQ4KDsc(prepared_block0, sub);
        const dsc1 = preparedQ4KDsc(prepared_block1, sub);
        const dsc2 = preparedQ4KDsc(prepared_block2, sub);
        const dsc3 = preparedQ4KDsc(prepared_block3, sub);
        const dmn0 = preparedQ4KDmn(prepared_block0, sub);
        const dmn1 = preparedQ4KDmn(prepared_block1, sub);
        const dmn2 = preparedQ4KDmn(prepared_block2, sub);
        const dmn3 = preparedQ4KDmn(prepared_block3, sub);
        const activation_sum_r0 = @as(f32, @floatFromInt(q8KBlockSum(q8_block_r0, sub)));
        const activation_sum_r1 = @as(f32, @floatFromInt(q8KBlockSum(q8_block_r1, sub)));
        const activation_sum_r2 = @as(f32, @floatFromInt(q8KBlockSum(q8_block_r2, sub)));
        const activation_sum_r3 = @as(f32, @floatFromInt(q8KBlockSum(q8_block_r3, sub)));
        acc[0] += x_d0 * (dsc0 * @as(f32, @floatFromInt(dots[0])) - dmn0 * activation_sum_r0);
        acc[1] += x_d0 * (dsc1 * @as(f32, @floatFromInt(dots[1])) - dmn1 * activation_sum_r0);
        acc[2] += x_d0 * (dsc2 * @as(f32, @floatFromInt(dots[2])) - dmn2 * activation_sum_r0);
        acc[3] += x_d0 * (dsc3 * @as(f32, @floatFromInt(dots[3])) - dmn3 * activation_sum_r0);
        acc[4] += x_d1 * (dsc0 * @as(f32, @floatFromInt(dots[4])) - dmn0 * activation_sum_r1);
        acc[5] += x_d1 * (dsc1 * @as(f32, @floatFromInt(dots[5])) - dmn1 * activation_sum_r1);
        acc[6] += x_d1 * (dsc2 * @as(f32, @floatFromInt(dots[6])) - dmn2 * activation_sum_r1);
        acc[7] += x_d1 * (dsc3 * @as(f32, @floatFromInt(dots[7])) - dmn3 * activation_sum_r1);
        acc[8] += x_d2 * (dsc0 * @as(f32, @floatFromInt(dots[8])) - dmn0 * activation_sum_r2);
        acc[9] += x_d2 * (dsc1 * @as(f32, @floatFromInt(dots[9])) - dmn1 * activation_sum_r2);
        acc[10] += x_d2 * (dsc2 * @as(f32, @floatFromInt(dots[10])) - dmn2 * activation_sum_r2);
        acc[11] += x_d2 * (dsc3 * @as(f32, @floatFromInt(dots[11])) - dmn3 * activation_sum_r2);
        acc[12] += x_d3 * (dsc0 * @as(f32, @floatFromInt(dots[12])) - dmn0 * activation_sum_r3);
        acc[13] += x_d3 * (dsc1 * @as(f32, @floatFromInt(dots[13])) - dmn1 * activation_sum_r3);
        acc[14] += x_d3 * (dsc2 * @as(f32, @floatFromInt(dots[14])) - dmn2 * activation_sum_r3);
        acc[15] += x_d3 * (dsc3 * @as(f32, @floatFromInt(dots[15])) - dmn3 * activation_sum_r3);
    }
    return acc;
}

inline fn dotQ4Q5KPreparedQ8KBlock4MR2(
    q8_block_r0: []const u8,
    q8_block_r1: []const u8,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
) struct { f32, f32, f32, f32, f32, f32, f32, f32 } {
    std.debug.assert(q8_block_r0.len == 292);
    std.debug.assert(q8_block_r1.len == 292);
    std.debug.assert(prepared_block0.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block1.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block2.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block3.len == prepared_q4_k_block_bytes);

    const qx0 = q8_block_r0[4..260];
    const qx1 = q8_block_r1[4..260];
    const x_d0 = readF32Le(q8_block_r0[0..4]);
    const x_d1 = readF32Le(q8_block_r1[0..4]);
    const q_values0 = prepared_block0[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values1 = prepared_block1[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values2 = prepared_block2[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values3 = prepared_block3[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    var acc_r0_0: f32 = 0.0;
    var acc_r0_1: f32 = 0.0;
    var acc_r0_2: f32 = 0.0;
    var acc_r0_3: f32 = 0.0;
    var acc_r1_0: f32 = 0.0;
    var acc_r1_1: f32 = 0.0;
    var acc_r1_2: f32 = 0.0;
    var acc_r1_3: f32 = 0.0;
    for (0..8) |sub| {
        const q_off = sub * 32;
        const dots = dotI8I8Block4MR2(
            qx0[q_off..][0..32],
            qx1[q_off..][0..32],
            q_values0[q_off..][0..32],
            q_values1[q_off..][0..32],
            q_values2[q_off..][0..32],
            q_values3[q_off..][0..32],
        );
        const activation_sum_r0 = @as(f32, @floatFromInt(q8KBlockSum(q8_block_r0, sub)));
        const activation_sum_r1 = @as(f32, @floatFromInt(q8KBlockSum(q8_block_r1, sub)));
        const dsc0 = preparedQ4KDsc(prepared_block0, sub);
        const dsc1 = preparedQ4KDsc(prepared_block1, sub);
        const dsc2 = preparedQ4KDsc(prepared_block2, sub);
        const dsc3 = preparedQ4KDsc(prepared_block3, sub);
        const dmn0 = preparedQ4KDmn(prepared_block0, sub);
        const dmn1 = preparedQ4KDmn(prepared_block1, sub);
        const dmn2 = preparedQ4KDmn(prepared_block2, sub);
        const dmn3 = preparedQ4KDmn(prepared_block3, sub);
        acc_r0_0 += x_d0 * (dsc0 * @as(f32, @floatFromInt(dots[0])) - dmn0 * activation_sum_r0);
        acc_r0_1 += x_d0 * (dsc1 * @as(f32, @floatFromInt(dots[1])) - dmn1 * activation_sum_r0);
        acc_r0_2 += x_d0 * (dsc2 * @as(f32, @floatFromInt(dots[2])) - dmn2 * activation_sum_r0);
        acc_r0_3 += x_d0 * (dsc3 * @as(f32, @floatFromInt(dots[3])) - dmn3 * activation_sum_r0);
        acc_r1_0 += x_d1 * (dsc0 * @as(f32, @floatFromInt(dots[4])) - dmn0 * activation_sum_r1);
        acc_r1_1 += x_d1 * (dsc1 * @as(f32, @floatFromInt(dots[5])) - dmn1 * activation_sum_r1);
        acc_r1_2 += x_d1 * (dsc2 * @as(f32, @floatFromInt(dots[6])) - dmn2 * activation_sum_r1);
        acc_r1_3 += x_d1 * (dsc3 * @as(f32, @floatFromInt(dots[7])) - dmn3 * activation_sum_r1);
    }
    return .{ acc_r0_0, acc_r0_1, acc_r0_2, acc_r0_3, acc_r1_0, acc_r1_1, acc_r1_2, acc_r1_3 };
}

inline fn dotQ6KPreparedBlockMR2NR1(
    input_block_r0: []const f32,
    input_block_r1: []const f32,
    prepared_block: []const u8,
) struct { f32, f32 } {
    std.debug.assert(prepared_block.len == prepared_q4_k_block_bytes);
    const q_values = prepared_block[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    var acc_r0: F32xN = @splat(0.0);
    var acc_r1: F32xN = @splat(0.0);
    for (0..16) |sub| {
        const scale: F32xN = @splat(preparedQ6KDsc(prepared_block, sub));
        const q_off = sub * 16;
        const input_off = sub * 16;
        comptime var i: usize = 0;
        inline while (i < 16) : (i += VEC_LEN) {
            const raw: U8xN = q_values[q_off + i ..][0..VEC_LEN].*;
            const q: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw));
            const w = scale * @as(F32xN, @floatFromInt(q));
            const inp_r0: F32xN = input_block_r0[input_off + i ..][0..VEC_LEN].*;
            const inp_r1: F32xN = input_block_r1[input_off + i ..][0..VEC_LEN].*;
            acc_r0 += inp_r0 * w;
            acc_r1 += inp_r1 * w;
        }
    }
    return .{ @reduce(.Add, acc_r0), @reduce(.Add, acc_r1) };
}

inline fn accumulateQ6KPreparedBlock4MR1(
    input_block: []const f32,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
    acc0: *F32xN,
    acc1: *F32xN,
    acc2: *F32xN,
    acc3: *F32xN,
) void {
    std.debug.assert(prepared_block0.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block1.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block2.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block3.len == prepared_q4_k_block_bytes);

    const q_values0 = prepared_block0[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values1 = prepared_block1[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values2 = prepared_block2[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values3 = prepared_block3[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    for (0..16) |sub| {
        const scale0: F32xN = @splat(preparedQ6KDsc(prepared_block0, sub));
        const scale1: F32xN = @splat(preparedQ6KDsc(prepared_block1, sub));
        const scale2: F32xN = @splat(preparedQ6KDsc(prepared_block2, sub));
        const scale3: F32xN = @splat(preparedQ6KDsc(prepared_block3, sub));
        const q_off = sub * 16;
        const input_off = sub * 16;
        comptime var i: usize = 0;
        inline while (i < 16) : (i += VEC_LEN) {
            const inp: F32xN = input_block[input_off + i ..][0..VEC_LEN].*;
            const raw0: U8xN = q_values0[q_off + i ..][0..VEC_LEN].*;
            const raw1: U8xN = q_values1[q_off + i ..][0..VEC_LEN].*;
            const raw2: U8xN = q_values2[q_off + i ..][0..VEC_LEN].*;
            const raw3: U8xN = q_values3[q_off + i ..][0..VEC_LEN].*;
            const q0: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw0));
            const q1: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw1));
            const q2: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw2));
            const q3: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw3));
            acc0.* += inp * (scale0 * @as(F32xN, @floatFromInt(q0)));
            acc1.* += inp * (scale1 * @as(F32xN, @floatFromInt(q1)));
            acc2.* += inp * (scale2 * @as(F32xN, @floatFromInt(q2)));
            acc3.* += inp * (scale3 * @as(F32xN, @floatFromInt(q3)));
        }
    }
}

inline fn accumulateQ6KPreparedBlock4MR2(
    input_block_r0: []const f32,
    input_block_r1: []const f32,
    prepared_block0: []const u8,
    prepared_block1: []const u8,
    prepared_block2: []const u8,
    prepared_block3: []const u8,
    acc_r0_0: *F32xN,
    acc_r0_1: *F32xN,
    acc_r0_2: *F32xN,
    acc_r0_3: *F32xN,
    acc_r1_0: *F32xN,
    acc_r1_1: *F32xN,
    acc_r1_2: *F32xN,
    acc_r1_3: *F32xN,
) void {
    std.debug.assert(prepared_block0.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block1.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block2.len == prepared_q4_k_block_bytes);
    std.debug.assert(prepared_block3.len == prepared_q4_k_block_bytes);

    const q_values0 = prepared_block0[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values1 = prepared_block1[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values2 = prepared_block2[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];
    const q_values3 = prepared_block3[prepared_q4_k_header_bytes..prepared_q4_k_block_bytes];

    for (0..16) |sub| {
        const scale0: F32xN = @splat(preparedQ6KDsc(prepared_block0, sub));
        const scale1: F32xN = @splat(preparedQ6KDsc(prepared_block1, sub));
        const scale2: F32xN = @splat(preparedQ6KDsc(prepared_block2, sub));
        const scale3: F32xN = @splat(preparedQ6KDsc(prepared_block3, sub));
        const q_off = sub * 16;
        const input_off = sub * 16;
        comptime var i: usize = 0;
        inline while (i < 16) : (i += VEC_LEN) {
            const inp_r0: F32xN = input_block_r0[input_off + i ..][0..VEC_LEN].*;
            const inp_r1: F32xN = input_block_r1[input_off + i ..][0..VEC_LEN].*;
            const raw0: U8xN = q_values0[q_off + i ..][0..VEC_LEN].*;
            const raw1: U8xN = q_values1[q_off + i ..][0..VEC_LEN].*;
            const raw2: U8xN = q_values2[q_off + i ..][0..VEC_LEN].*;
            const raw3: U8xN = q_values3[q_off + i ..][0..VEC_LEN].*;
            const q0: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw0));
            const q1: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw1));
            const q2: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw2));
            const q3: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(raw3));
            const w0 = scale0 * @as(F32xN, @floatFromInt(q0));
            const w1 = scale1 * @as(F32xN, @floatFromInt(q1));
            const w2 = scale2 * @as(F32xN, @floatFromInt(q2));
            const w3 = scale3 * @as(F32xN, @floatFromInt(q3));
            acc_r0_0.* += inp_r0 * w0;
            acc_r0_1.* += inp_r0 * w1;
            acc_r0_2.* += inp_r0 * w2;
            acc_r0_3.* += inp_r0 * w3;
            acc_r1_0.* += inp_r1 * w0;
            acc_r1_1.* += inp_r1 * w1;
            acc_r1_2.* += inp_r1 * w2;
            acc_r1_3.* += inp_r1 * w3;
        }
    }
}

fn dotQ6_KBlock(input_block: []const f32, block: []const u8) f32 {
    const ql = block[0..128];
    const qh = block[128..192];
    const scales = block[192..208];
    const d = decodeFp16Le(block[208], block[209]);

    const mask_0f: U8xN = @splat(0x0F);
    const mask_03: U8xN = @splat(0x03);
    const offset_32: I32xN = @splat(32);
    var acc: F32xN = @splat(0.0);
    for (0..16) |sub| {
        const scale: F32xN = @splat(d * @as(f32, @floatFromInt(@as(i8, @bitCast(scales[sub])))));
        const half = sub / 8;
        const group = (sub % 8) / 2;
        const l_base = (sub % 2) * 16;
        const ql_off = half * 64 + (group & 1) * 32;
        const qh_off = half * 32;
        const qh_shift: @Vector(VEC_LEN, u3) = @splat(@as(u3, @intCast(group * 2)));
        const nibble_shift: @Vector(VEC_LEN, u3) = @splat(@as(u3, @intCast((group / 2) * 4)));
        const input_off = sub * 16;

        // 16 elements in two SIMD passes of 8
        comptime var i: usize = 0;
        inline while (i < 16) : (i += VEC_LEN) {
            const l = l_base + i;
            const ql_raw: U8xN = ql[ql_off + l ..][0..VEC_LEN].*;
            const qh_raw: U8xN = qh[qh_off + l ..][0..VEC_LEN].*;
            const low4: I32xN = (ql_raw >> nibble_shift) & mask_0f;
            const high2: I32xN = (qh_raw >> qh_shift) & mask_03;
            const q: I32xN = (low4 | (high2 << @splat(4))) - offset_32;
            const inp: F32xN = input_block[input_off + i ..][0..VEC_LEN].*;
            acc += inp * (scale * @as(F32xN, @floatFromInt(q)));
        }
    }
    return @reduce(.Add, acc);
}

fn dotQ6_KQ8_KBlock(q8_block: []const u8, q6_block: []const u8) f32 {
    std.debug.assert(q8_block.len == 292);
    std.debug.assert(q6_block.len == 210);

    const qx = q8_block[4..260];
    const x_d = readF32Le(q8_block[0..4]);
    const ql = q6_block[0..128];
    const qh = q6_block[128..192];
    const scales = q6_block[192..208];
    const d = decodeFp16Le(q6_block[208], q6_block[209]);

    const mask_0f: U8xN = @splat(0x0F);
    const mask_03: U8xN = @splat(0x03);
    var acc: f32 = 0.0;
    for (0..16) |sub| {
        const half = sub / 8;
        const group = (sub % 8) / 2;
        const l_base = (sub % 2) * 16;
        const ql_off = half * 64 + (group & 1) * 32;
        const qh_off = half * 32;
        const qh_shift: @Vector(VEC_LEN, u3) = @splat(@as(u3, @intCast(group * 2)));
        const nibble_shift: @Vector(VEC_LEN, u3) = @splat(@as(u3, @intCast((group / 2) * 4)));
        const input_off = sub * 16;

        var dot: I32xN = @splat(0);
        comptime var i: usize = 0;
        inline while (i < 16) : (i += VEC_LEN) {
            const l = l_base + i;
            const ql_raw: U8xN = ql[ql_off + l ..][0..VEC_LEN].*;
            const qh_raw: U8xN = qh[qh_off + l ..][0..VEC_LEN].*;
            const low4: I32xN = (ql_raw >> nibble_shift) & mask_0f;
            const high2: I32xN = (qh_raw >> qh_shift) & mask_03;
            const q_raw = low4 | (high2 << @splat(4));
            const x_raw: U8xN = qx[input_off + i ..][0..VEC_LEN].*;
            const x: I32xN = @as(@Vector(VEC_LEN, i8), @bitCast(x_raw));
            dot += q_raw * x;
        }
        const bsums = std.mem.readInt(i16, q8_block[260 + sub * 2 ..][0..2], .little);
        const centered_dot = @reduce(.Add, dot) - 32 * @as(i32, @intCast(bsums));
        const scale = d * @as(f32, @floatFromInt(@as(i8, @bitCast(scales[sub]))));
        acc += (x_d * scale) * @as(f32, @floatFromInt(centered_dot));
    }
    return acc;
}

fn unpackQ4KScaleMins(scales: []const u8, scs: *[8]f32, mins: *[8]f32) void {
    for (0..4) |j| {
        scs[j] = @floatFromInt(scales[j] & 63);
        mins[j] = @floatFromInt(scales[j + 4] & 63);
    }
    for (4..8) |j| {
        scs[j] = @floatFromInt((scales[j + 4] & 0x0F) | ((scales[j - 4] >> 6) << 4));
        mins[j] = @floatFromInt((scales[j + 4] >> 4) | ((scales[j] >> 6) << 4));
    }
}

fn unpackQ4KScaleMinsU8(scales: []const u8, scs: *[8]u8, mins: *[8]u8) void {
    for (0..4) |j| {
        scs[j] = scales[j] & 63;
        mins[j] = scales[j + 4] & 63;
    }
    for (4..8) |j| {
        scs[j] = (scales[j + 4] & 0x0F) | ((scales[j - 4] >> 6) << 4);
        mins[j] = (scales[j + 4] >> 4) | ((scales[j] >> 6) << 4);
    }
}

fn unpackQ4KValues(qs: []const u8, out: []u8) void {
    std.debug.assert(qs.len == 128);
    std.debug.assert(out.len == prepared_q4_k_values_bytes);
    for (0..4) |chunk| {
        const src_off = chunk * 32;
        const dst_off = chunk * 64;
        for (0..32) |i| {
            const packed_byte = qs[src_off + i];
            out[dst_off + i] = packed_byte & 0x0F;
            out[dst_off + 32 + i] = packed_byte >> 4;
        }
    }
}

const PackedQuantizedMatrixMeta = struct {
    layout: quant_codec.PackedExpertLinearMeta,
    row_blocks: usize,
    values_per_block: usize,
    block_size: usize,
};

fn packedQuantizedMatrixMeta(
    shape: []const i64,
    packed_view: QuantizedStorage.PackedExpertView,
    in_dim: usize,
    out_dim: usize,
    tensor_type: gguf_tensor_types.TensorType,
) !PackedQuantizedMatrixMeta {
    const expert_axis: usize = @intCast(packed_view.expert_axis);
    const layout = try quant_codec.packedExpertLinearMeta(
        shape,
        expert_axis,
        packed_view.expert_index,
        in_dim,
        out_dim,
        tensor_type,
    );
    return .{
        .layout = layout,
        .row_blocks = layout.row_blocks,
        .values_per_block = layout.values_per_block,
        .block_size = layout.block_size,
    };
}

fn packedExpertRowBlockBase(
    meta: PackedQuantizedMatrixMeta,
    packed_view: QuantizedStorage.PackedExpertView,
    row_index: usize,
) !usize {
    return quant_codec.packedExpertLinearRowBlockBase(
        meta.layout,
        packed_view.expert_index,
        row_index,
        packed_view.row_offset,
    );
}

const decodeFp16Le = quant_codec.decodeFp16Le;

fn decodeF32Le(b0: u8, b1: u8, b2: u8, b3: u8) f32 {
    const bits: u32 = @as(u32, b0) |
        (@as(u32, b1) << 8) |
        (@as(u32, b2) << 16) |
        (@as(u32, b3) << 24);
    return @bitCast(bits);
}

fn rmsNormOp(ctx: *anyopaque, input: CT, weight: CT, dim: usize, eps: f32) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const output = try self.allocator.dupe(f32, getData(input));
    activations_mod.rmsNorm(output, getData(weight), dim, eps);
    const result = try self.makeOwnedBuf(output);
    errdefer freeTensor(self, result);
    return propagateLogicalShapeLike(self, result, input);
}

fn rmsNormConsumeInputOp(_: *anyopaque, input: CT, weight: CT, dim: usize, eps: f32) anyerror!?CT {
    const buf = uniqueOwnedDenseBuf(input) orelse return null;
    activations_mod.rmsNorm(buf.data, getData(weight), dim, eps);
    return input;
}

fn reluOp(ctx: *anyopaque, input: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const output = try self.allocator.dupe(f32, getData(input));
    activations_mod.relu(output);
    const result = try self.makeBuf(output, true);
    return propagateLogicalShapeLike(self, result, input);
}

fn siluOp(ctx: *anyopaque, input: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const output = try self.allocator.dupe(f32, getData(input));
    activations_mod.silu(output);
    const result = try self.makeBuf(output, true);
