fn sigmoidOp(ctx: *anyopaque, input: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const output = try self.allocator.dupe(f32, getData(input));
    activations_mod.sigmoid(output);
    return self.makeBuf(output, true);
}

fn tanhOp(ctx: *anyopaque, input: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const data = getData(input);
    const output = try self.allocator.alloc(f32, data.len);
    for (data, 0..) |v, i| {
        output[i] = std.math.tanh(v);
    }
    return self.makeBuf(output, true);
}

fn concatOp(ctx: *anyopaque, a: CT, b: CT, total: usize, dim_a: usize, dim_b: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const a_data = getData(a);
    const b_data = getData(b);
    const out_dim = dim_a + dim_b;
    const output = try self.allocator.alloc(f32, total * out_dim);
    for (0..total) |i| {
        @memcpy(output[i * out_dim ..][0..dim_a], a_data[i * dim_a ..][0..dim_a]);
        @memcpy(output[i * out_dim + dim_a ..][0..dim_b], b_data[i * dim_b ..][0..dim_b]);
    }
    return self.makeBuf(output, true);
}

fn linearRowsNative(
    self: *NativeCompute,
    input: []const f32,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    weight: CT,
    bias: CT,
) ![]f32 {
    const weight_view = try denseWeightView(self, weight);
    defer if (weight_view.owned) |owned| self.allocator.free(owned);
    const bias_view = try denseWeightView(self, bias);
    defer if (bias_view.owned) |owned| self.allocator.free(owned);

    const output = try self.allocator.alloc(f32, rows * out_dim);
    errdefer self.allocator.free(output);
    for (0..rows) |r| {
        @memcpy(output[r * out_dim ..][0..out_dim], bias_view.data[0..out_dim]);
    }
    try self.dispatchSgemmTransB(rows, out_dim, in_dim, 1.0, input, weight_view.data, 1.0, output);
    return output;
}

fn splitQkvNative(qkv: []const f32, q: []f32, k: []f32, v: []f32, dim: usize) void {
    const rows = q.len / dim;
    for (0..rows) |row| {
        const src = row * dim * 3;
        const dst = row * dim;
        @memcpy(q[dst..][0..dim], qkv[src..][0..dim]);
        @memcpy(k[dst..][0..dim], qkv[src + dim ..][0..dim]);
        @memcpy(v[dst..][0..dim], qkv[src + 2 * dim ..][0..dim]);
    }
}

fn windowedSelfAttentionOp(
    ctx: *anyopaque,
    input: CT,
    norm_weight: CT,
    norm_bias: CT,
    qkv_weight: CT,
    qkv_bias: CT,
    proj_weight: CT,
    proj_bias: CT,
    batch: usize,
    height: usize,
    width: usize,
    dim: usize,
    num_heads: usize,
    window_size: usize,
) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const head_dim = dim / num_heads;

    const normed_ct = try layerNormOp(ctx, input, norm_weight, norm_bias, dim, 1e-5);
    defer freeTensor(ctx, normed_ct);
    const normed = getData(normed_ct);

    const window_pack = try linalg.padTokensToWindows(self.allocator, normed, batch, height, width, dim, window_size);
    defer self.allocator.free(window_pack.data);

    const rows = window_pack.window_count * window_pack.window_area;
    const qkv = try linearRowsNative(self, window_pack.data, rows, dim, dim * 3, qkv_weight, qkv_bias);
    defer self.allocator.free(qkv);
    const attn = try self.allocator.alloc(f32, rows * dim);
    defer self.allocator.free(attn);
    @memset(attn, 0.0);

    const q_buf = try self.allocator.alloc(f32, window_pack.window_area * head_dim);
    defer self.allocator.free(q_buf);
    const k_buf = try self.allocator.alloc(f32, window_pack.window_area * head_dim);
    defer self.allocator.free(k_buf);
    const v_buf = try self.allocator.alloc(f32, window_pack.window_area * head_dim);
    defer self.allocator.free(v_buf);
    const scores = try self.allocator.alloc(f32, window_pack.window_area * window_pack.window_area);
    defer self.allocator.free(scores);
    const out_buf = try self.allocator.alloc(f32, window_pack.window_area * head_dim);
    defer self.allocator.free(out_buf);
    const scale: f32 = 1.0 / @sqrt(@as(f32, @floatFromInt(head_dim)));

    for (0..window_pack.window_count) |window_idx| {
        const window_base = window_idx * window_pack.window_area;
        for (0..num_heads) |head| {
            const head_offset = head * head_dim;
            for (0..window_pack.window_area) |token| {
                const src_base = (window_base + token) * dim * 3;
                const dst_base = token * head_dim;
                @memcpy(q_buf[dst_base..][0..head_dim], qkv[src_base + head_offset ..][0..head_dim]);
                @memcpy(k_buf[dst_base..][0..head_dim], qkv[src_base + dim + head_offset ..][0..head_dim]);
                @memcpy(v_buf[dst_base..][0..head_dim], qkv[src_base + 2 * dim + head_offset ..][0..head_dim]);
            }

            @memset(scores, 0.0);
            try self.dispatchSgemmTransB(window_pack.window_area, window_pack.window_area, head_dim, scale, q_buf, k_buf, 0.0, scores);
            activations_mod.softmax(scores, window_pack.window_area);
            @memset(out_buf, 0.0);
            try self.dispatchSgemm(window_pack.window_area, head_dim, window_pack.window_area, 1.0, scores, v_buf, 0.0, out_buf);

            for (0..window_pack.window_area) |token| {
                const dst_base = (window_base + token) * dim + head_offset;
                const src_base = token * head_dim;
                @memcpy(attn[dst_base..][0..head_dim], out_buf[src_base..][0..head_dim]);
            }
        }
    }

    const projected = try linearRowsNative(self, attn, rows, dim, dim, proj_weight, proj_bias);
    defer self.allocator.free(projected);

    const unpadded = try linalg.unpadWindowTokens(self.allocator, projected, window_pack, batch, height, width, dim);
    return self.makeBuf(unpadded, true);
}

fn channelSelfAttentionOp(
    ctx: *anyopaque,
    input: CT,
    norm_weight: CT,
    norm_bias: CT,
    qkv_weight: CT,
    qkv_bias: CT,
    proj_weight: CT,
    proj_bias: CT,
    batch: usize,
    seq_len: usize,
    dim: usize,
    groups: usize,
) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));

    const normed_ct = try layerNormOp(ctx, input, norm_weight, norm_bias, dim, 1e-5);
    defer freeTensor(ctx, normed_ct);
    const qkv = try linearRowsNative(self, getData(normed_ct), batch * seq_len, dim, dim * 3, qkv_weight, qkv_bias);
    defer self.allocator.free(qkv);

    const attended = try self.allocator.alloc(f32, batch * seq_len * dim);
    defer self.allocator.free(attended);
    try linalg.channelAttention(self.allocator, attended, qkv, batch, seq_len, dim, groups);

    const projected = try linearRowsNative(self, attended, batch * seq_len, dim, dim, proj_weight, proj_bias);
    return self.makeBuf(projected, true);
}

fn tokenGridConv2dOp(
    ctx: *anyopaque,
    input: CT,
    weight: CT,
    bias: CT,
    batch: usize,
    in_channels: usize,
    out_channels: usize,
    height: usize,
    width: usize,
    kernel_h: usize,
    kernel_w: usize,
    stride_h: usize,
    stride_w: usize,
    padding_h: usize,
    padding_w: usize,
    groups: usize,
) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const input_tokens = getData(input);
    const out_h = (height + 2 * padding_h - kernel_h) / stride_h + 1;
    const out_w = (width + 2 * padding_w - kernel_w) / stride_w + 1;

    if (groups == in_channels and groups == out_channels) {
        const kernel_size = kernel_h * kernel_w;
        const weight_data = getData(weight);
        const bias_data = getData(bias);
        const out_tokens = try self.allocator.alloc(f32, batch * out_h * out_w * out_channels);
        errdefer self.allocator.free(out_tokens);

        for (0..batch) |b| {
            for (0..out_h) |oy| {
                const in_y_origin = oy * stride_h;
                for (0..out_w) |ox| {
                    const in_x_origin = ox * stride_w;
                    const out_base = ((b * out_h + oy) * out_w + ox) * out_channels;
                    for (0..out_channels) |c| {
                        const weight_channel = weight_data[c * kernel_size ..][0..kernel_size];
                        var acc = bias_data[c];
                        for (0..kernel_h) |ky| {
                            const in_y_signed: i64 = @as(i64, @intCast(in_y_origin + ky)) - @as(i64, @intCast(padding_h));
                            if (in_y_signed < 0 or in_y_signed >= @as(i64, @intCast(height))) continue;
                            const in_y: usize = @intCast(in_y_signed);
                            const row_base = ((b * height + in_y) * width) * in_channels;
                            const weight_row_base = ky * kernel_w;
                            for (0..kernel_w) |kx| {
                                const in_x_signed: i64 = @as(i64, @intCast(in_x_origin + kx)) - @as(i64, @intCast(padding_w));
                                if (in_x_signed < 0 or in_x_signed >= @as(i64, @intCast(width))) continue;
                                const in_x: usize = @intCast(in_x_signed);
                                const token_idx = row_base + in_x * in_channels + c;
                                acc += input_tokens[token_idx] * weight_channel[weight_row_base + kx];
                            }
                        }
                        out_tokens[out_base + c] = acc;
                    }
                }
            }
        }

        return self.makeBuf(out_tokens, true);
    }

    const image = try self.allocator.alloc(f32, batch * in_channels * height * width);
    defer self.allocator.free(image);

    for (0..batch) |b| {
        for (0..height) |y| {
            for (0..width) |x| {
                const token_idx = (b * height * width + y * width + x) * in_channels;
                for (0..in_channels) |c| {
                    const image_idx = ((b * in_channels + c) * height + y) * width + x;
                    image[image_idx] = input_tokens[token_idx + c];
                }
            }
        }
    }

    const image_ct = try self.makeBuf(image, false);
    defer freeTensor(ctx, image_ct);
    const out_ct = try conv2dOp(ctx, image_ct, weight, bias, batch, in_channels, out_channels, height, width, kernel_h, kernel_w, stride_h, stride_w, padding_h, padding_w, groups);
    defer freeTensor(ctx, out_ct);
    const out_image = getData(out_ct);
    const out_tokens = try self.allocator.alloc(f32, batch * out_h * out_w * out_channels);
    errdefer self.allocator.free(out_tokens);

    for (0..batch) |b| {
        for (0..out_h) |y| {
            for (0..out_w) |x| {
                const token_idx = (b * out_h * out_w + y * out_w + x) * out_channels;
                for (0..out_channels) |c| {
                    const image_idx = ((b * out_channels + c) * out_h + y) * out_w + x;
                    out_tokens[token_idx + c] = out_image[image_idx];
                }
            }
        }
    }

    return self.makeBuf(out_tokens, true);
}

fn causalSelfAttentionOp(ctx: *anyopaque, q_ct: CT, k_ct: CT, v_ct: CT, attn_bias_ct: ?CT, batch: usize, seq_len: usize, num_heads: usize, head_dim: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const Q = getData(q_ct);
    const K = getData(k_ct);
    const V = getData(v_ct);
    const bias: ?[]f32 = if (attn_bias_ct) |b| getData(b) else null;

    const output = try flashCausalAttentionHost(self.allocator, Q, K, V, bias, null, 0, batch, seq_len, seq_len, 0, 0, num_heads, num_heads, head_dim);
    return self.makeBuf(output, true);
}

fn crossAttentionOp(ctx: *anyopaque, q_ct: CT, k_ct: CT, v_ct: CT, enc_mask: []const i64, batch: usize, dec_seq: usize, enc_seq: usize, num_heads: usize, head_dim: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const Q = getData(q_ct);
    const K = getData(k_ct);
    const V = getData(v_ct);
    const output = try linalg.crossAttentionHost(self.allocator, Q, K, V, enc_mask, batch, dec_seq, enc_seq, num_heads, head_dim);
    return self.makeBuf(output, true);
}

fn relativePositionBiasOp(ctx: *anyopaque, weight: CT, q_len: usize, k_len: usize, num_heads: usize, num_buckets: usize, max_distance: usize, bidirectional: bool) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const table = getData(weight); // [num_heads, num_buckets]

    // Output: [num_heads, q_len, k_len]
    const output = try self.allocator.alloc(f32, num_heads * q_len * k_len);
    errdefer self.allocator.free(output);

    for (0..q_len) |qi| {
        for (0..k_len) |ki| {
            const bucket = t5RelativePositionBucket(@as(i64, @intCast(ki)) - @as(i64, @intCast(qi)), num_buckets, max_distance, bidirectional);
            for (0..num_heads) |h| {
                output[h * q_len * k_len + qi * k_len + ki] = table[h * num_buckets + bucket];
            }
        }
    }

    return self.makeBuf(output, true);
}

fn disentangledRelativeAttentionOp(ctx: *anyopaque, q_ct: CT, k_ct: CT, v_ct: CT, q_r_ct: CT, k_r_ct: CT, mask: []const i64, batch: usize, seq_len: usize, num_heads: usize, head_dim: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const Q = getData(q_ct);
    const K = getData(k_ct);
    const V = getData(v_ct);
    const Q_r = getData(q_r_ct);
    const K_r = getData(k_r_ct);
    const output = try linalg.debertaDisentangledAttentionHost(self.allocator, Q, K, V, Q_r, K_r, mask, batch, seq_len, num_heads, head_dim);
    return self.makeBuf(output, true);
}

/// T5 relative position bucket computation.
/// Maps a relative position (key_pos - query_pos) to a bucket index.
pub fn t5RelativePositionBucket(relative_position: i64, num_buckets_: usize, max_distance_: usize, bidirectional: bool) usize {
    return linalg.t5RelativePositionBucket(relative_position, num_buckets_, max_distance_, bidirectional);
}

fn multiplyOp(ctx: *anyopaque, a: CT, b: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    if (try applyShapeAwareBinaryOp(self, a, b, .mul)) |result| {
        return result;
    }
    const a_view = try denseTensorView(self, a);
    defer if (a_view.owned) |owned| self.allocator.free(owned);
    const b_view = try denseTensorView(self, b);
    defer if (b_view.owned) |owned| self.allocator.free(owned);
    const a_data = a_view.data;
    const b_data = b_view.data;
    if (a_data.len != b_data.len) {
        const output = try primBinaryBroadcast(self.allocator, a_data, b_data, .mul_prim);
        const result = try self.makeOwnedBuf(output);
        errdefer freeTensor(self, result);
        return propagateLogicalShapeFromBinaryOperands(self, result, a, b);
    }
    const output = try self.allocator.alloc(f32, a_data.len);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    var i: usize = 0;
    while (i + VEC_LEN <= a_data.len) : (i += VEC_LEN) {
        const va: F32xN = a_data[i..][0..VEC_LEN].*;
        const vb: F32xN = b_data[i..][0..VEC_LEN].*;
        output[i..][0..VEC_LEN].* = va * vb;
    }
    while (i < a_data.len) : (i += 1) {
        output[i] = a_data[i] * b_data[i];
    }
    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    return propagateLogicalShapeFromBinaryOperands(self, result, a, b);
}

fn conv1dOp(ctx: *anyopaque, input: CT, weight: CT, bias: CT, batch: usize, in_channels: usize, out_channels: usize, time_steps: usize, kernel_size: usize, stride: usize, padding: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const in_data = getData(input);
    const w_data = getData(weight);
    const b_data = getData(bias);

    const out_time = (time_steps + 2 * padding - kernel_size) / stride + 1;
    const output = try self.allocator.alloc(f32, batch * out_channels * out_time);
    errdefer self.allocator.free(output);

    // Initialize with bias
    for (0..batch) |b| {
        for (0..out_channels) |oc| {
            const bias_val = b_data[oc];
            const out_base = (b * out_channels + oc) * out_time;
            for (0..out_time) |t| {
                output[out_base + t] = bias_val;
            }
        }
    }

    // Conv1d: output[b, oc, t] += sum over ic, k of input[b, ic, t*stride + k - padding] * weight[oc, ic, k]
    for (0..batch) |b| {
        for (0..out_channels) |oc| {
            for (0..out_time) |t| {
                var sum: f32 = 0.0;
                for (0..in_channels) |ic| {
                    for (0..kernel_size) |k| {
                        const in_t_signed: i64 = @as(i64, @intCast(t * stride + k)) - @as(i64, @intCast(padding));
                        if (in_t_signed >= 0 and in_t_signed < @as(i64, @intCast(time_steps))) {
                            const in_t: usize = @intCast(in_t_signed);
                            const in_idx = (b * in_channels + ic) * time_steps + in_t;
                            const w_idx = (oc * in_channels + ic) * kernel_size + k;
                            sum += in_data[in_idx] * w_data[w_idx];
                        }
                    }
                }
                output[(b * out_channels + oc) * out_time + t] += sum;
            }
        }
    }

    const result = try self.makeBuf(output, true);
    return self.withLogicalShape(result, &.{ @intCast(batch), @intCast(out_channels), @intCast(out_time) });
}

fn conv2dOp(ctx: *anyopaque, input: CT, weight: CT, bias: CT, batch: usize, in_channels: usize, out_channels: usize, height: usize, width: usize, kernel_h: usize, kernel_w: usize, stride_h: usize, stride_w: usize, padding_h: usize, padding_w: usize, groups: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    if (groups == 0 or in_channels % groups != 0 or out_channels % groups != 0) return error.InvalidInputShape;

    const out_h = (height + 2 * padding_h - kernel_h) / stride_h + 1;
    const out_w = (width + 2 * padding_w - kernel_w) / stride_w + 1;
    const output_elems = try std.math.mul(usize, batch * out_channels, out_h * out_w);
    const conv_temp_limit_elems: usize = 64 * 1024 * 1024;
    if (output_elems > conv_temp_limit_elems) {
        std.log.warn("conv2d refusing oversized output batch={d} in_channels={d} out_channels={d} height={d} width={d} kernel={d}x{d} stride={d}x{d} padding={d}x{d} groups={d} out={d}x{d} output_elems={d}", .{
            batch,
            in_channels,
            out_channels,
            height,
            width,
            kernel_h,
            kernel_w,
            stride_h,
            stride_w,
            padding_h,
            padding_w,
            groups,
            out_h,
            out_w,
            output_elems,
        });
        return error.UnsupportedShape;
    }
    const output = try self.allocator.alloc(f32, output_elems);
    errdefer self.allocator.free(output);

    const input_data = getData(input);
    const weight_data = getData(weight);
    const bias_data = getData(bias);
    if (groups == 1) {
        const rows = out_h * out_w;
        const k_dim = in_channels * kernel_h * kernel_w;
        const cols_elems = try std.math.mul(usize, rows, k_dim);
        if (cols_elems > conv_temp_limit_elems) {
            std.log.warn("conv2d refusing oversized im2col rows={d} k_dim={d} cols_elems={d} batch={d} in_channels={d} out_channels={d} height={d} width={d} kernel={d}x{d} stride={d}x{d} padding={d}x{d}", .{
                rows,
                k_dim,
                cols_elems,
                batch,
                in_channels,
                out_channels,
                height,
                width,
                kernel_h,
                kernel_w,
                stride_h,
                stride_w,
                padding_h,
                padding_w,
            });
            return error.UnsupportedShape;
        }
        const cols = try self.allocator.alloc(f32, cols_elems);
        defer self.allocator.free(cols);

        for (0..batch) |b| {
            for (0..out_h) |oy| {
                for (0..out_w) |ox| {
                    const row = oy * out_w + ox;
                    const row_base = row * k_dim;
                    for (0..in_channels) |ic| {
                        for (0..kernel_h) |ky| {
                            for (0..kernel_w) |kx| {
                                const col_idx = ((ic * kernel_h + ky) * kernel_w) + kx;
                                const in_y_signed: i64 = @as(i64, @intCast(oy * stride_h + ky)) - @as(i64, @intCast(padding_h));
                                const in_x_signed: i64 = @as(i64, @intCast(ox * stride_w + kx)) - @as(i64, @intCast(padding_w));
                                cols[row_base + col_idx] = if (in_y_signed < 0 or in_x_signed < 0 or in_y_signed >= @as(i64, @intCast(height)) or in_x_signed >= @as(i64, @intCast(width))) 0.0 else blk: {
                                    const in_y: usize = @intCast(in_y_signed);
                                    const in_x: usize = @intCast(in_x_signed);
                                    const in_idx = ((b * in_channels + ic) * height + in_y) * width + in_x;
                                    break :blk input_data[in_idx];
                                };
                            }
                        }
                    }
                }
            }

            const batch_out = output[b * out_channels * rows ..][0 .. out_channels * rows];
            for (0..rows) |row| {
                const dst = batch_out[row * out_channels ..][0..out_channels];
                @memcpy(dst, bias_data[0..out_channels]);
            }
            try self.dispatchSgemmTransB(rows, out_channels, k_dim, 1.0, cols, weight_data, 1.0, batch_out);
        }

        const transposed = try self.allocator.alloc(f32, output.len);
        defer self.allocator.free(transposed);
        for (0..batch) |b| {
            const src_batch = output[b * out_channels * rows ..][0 .. out_channels * rows];
            const dst_batch = transposed[b * out_channels * rows ..][0 .. out_channels * rows];
            for (0..rows) |row| {
                for (0..out_channels) |oc| {
                    dst_batch[(oc * rows) + row] = src_batch[row * out_channels + oc];
                }
            }
        }
        @memcpy(output, transposed);
        const result = try self.makeBuf(output, true);
        return self.withLogicalShape(result, &.{ @intCast(batch), @intCast(out_channels), @intCast(out_h), @intCast(out_w) });
    }

    if (groups == in_channels and groups == out_channels) {
        const kernel_size = kernel_h * kernel_w;
        for (0..batch) |b| {
            for (0..out_channels) |c| {
                const weight_channel = weight_data[c * kernel_size ..][0..kernel_size];
                const input_base = (b * in_channels + c) * height * width;
                const output_base = (b * out_channels + c) * out_h * out_w;
                for (0..out_h) |oy| {
                    const in_y_origin = oy * stride_h;
                    for (0..out_w) |ox| {
                        const in_x_origin = ox * stride_w;
                        var acc = bias_data[c];
                        for (0..kernel_h) |ky| {
                            const in_y_signed: i64 = @as(i64, @intCast(in_y_origin + ky)) - @as(i64, @intCast(padding_h));
                            if (in_y_signed < 0 or in_y_signed >= @as(i64, @intCast(height))) continue;
                            const in_y: usize = @intCast(in_y_signed);
                            const row_base = input_base + in_y * width;
                            const weight_row_base = ky * kernel_w;
                            for (0..kernel_w) |kx| {
                                const in_x_signed: i64 = @as(i64, @intCast(in_x_origin + kx)) - @as(i64, @intCast(padding_w));
                                if (in_x_signed < 0 or in_x_signed >= @as(i64, @intCast(width))) continue;
                                const in_x: usize = @intCast(in_x_signed);
                                acc += input_data[row_base + in_x] * weight_channel[weight_row_base + kx];
                            }
                        }
                        output[output_base + oy * out_w + ox] = acc;
                    }
                }
            }
        }

        const result = try self.makeBuf(output, true);
        return self.withLogicalShape(result, &.{ @intCast(batch), @intCast(out_channels), @intCast(out_h), @intCast(out_w) });
    }

    const in_per_group = in_channels / groups;
    const out_per_group = out_channels / groups;
    const rows = out_h * out_w;
    const k_dim = in_per_group * kernel_h * kernel_w;
    const cols_elems = try std.math.mul(usize, rows, k_dim);
    if (cols_elems > conv_temp_limit_elems) {
        std.log.warn("conv2d refusing oversized grouped im2col rows={d} k_dim={d} cols_elems={d} batch={d} in_channels={d} out_channels={d} height={d} width={d} kernel={d}x{d} stride={d}x{d} padding={d}x{d} groups={d}", .{
            rows,
            k_dim,
            cols_elems,
            batch,
            in_channels,
            out_channels,
            height,
            width,
            kernel_h,
            kernel_w,
            stride_h,
            stride_w,
            padding_h,
            padding_w,
            groups,
        });
        return error.UnsupportedShape;
    }
    const cols = try self.allocator.alloc(f32, cols_elems);
    defer self.allocator.free(cols);
    const group_out = try self.allocator.alloc(f32, rows * out_per_group);
    defer self.allocator.free(group_out);
    const transposed = try self.allocator.alloc(f32, rows * out_per_group);
    defer self.allocator.free(transposed);

    for (0..batch) |b| {
        for (0..groups) |group| {
            const ic_base = group * in_per_group;
            const oc_base = group * out_per_group;

            for (0..out_h) |oy| {
                for (0..out_w) |ox| {
                    const row = oy * out_w + ox;
                    const row_base = row * k_dim;
                    for (0..in_per_group) |ic_group| {
                        const ic = ic_base + ic_group;
                        for (0..kernel_h) |ky| {
                            for (0..kernel_w) |kx| {
                                const col_idx = ((ic_group * kernel_h + ky) * kernel_w) + kx;
                                const in_y_signed: i64 = @as(i64, @intCast(oy * stride_h + ky)) - @as(i64, @intCast(padding_h));
                                const in_x_signed: i64 = @as(i64, @intCast(ox * stride_w + kx)) - @as(i64, @intCast(padding_w));
                                cols[row_base + col_idx] = if (in_y_signed < 0 or in_x_signed < 0 or in_y_signed >= @as(i64, @intCast(height)) or in_x_signed >= @as(i64, @intCast(width))) 0.0 else blk: {
                                    const in_y: usize = @intCast(in_y_signed);
                                    const in_x: usize = @intCast(in_x_signed);
                                    const in_idx = ((b * in_channels + ic) * height + in_y) * width + in_x;
                                    break :blk input_data[in_idx];
                                };
                            }
                        }
                    }
                }
            }

            for (0..rows) |row| {
                const dst = group_out[row * out_per_group ..][0..out_per_group];
                @memcpy(dst, bias_data[oc_base..][0..out_per_group]);
            }
            const weight_group = weight_data[oc_base * k_dim ..][0 .. out_per_group * k_dim];
            try self.dispatchSgemmTransB(rows, out_per_group, k_dim, 1.0, cols, weight_group, 1.0, group_out);

            for (0..rows) |row| {
                for (0..out_per_group) |oc_group| {
                    transposed[oc_group * rows + row] = group_out[row * out_per_group + oc_group];
                }
            }
            const batch_base = b * out_channels * rows;
            for (0..out_per_group) |oc_group| {
                const dst = output[batch_base + (oc_base + oc_group) * rows ..][0..rows];
                const src = transposed[oc_group * rows ..][0..rows];
                @memcpy(dst, src);
            }
        }
    }

    const result = try self.makeBuf(output, true);
    return self.withLogicalShape(result, &.{ @intCast(batch), @intCast(out_channels), @intCast(out_h), @intCast(out_w) });
}

/// Shared RoPE rotation core. Rotates `output` in-place using one position
/// value per head-sized chunk. `positions[tok]` gives the absolute position
/// for token index `tok`. Tokens with position 0 are identity (cos 0 = 1,
/// sin 0 = 0) so padded slots are left unchanged.
pub fn ropeCore(output: []f32, positions: []const usize, head_dim: usize, rope_dim: usize, theta: f32, freq_scale: f32, consecutive_pairs: bool) void {
    linalg.ropeCore(output, positions, head_dim, rope_dim, theta, freq_scale, consecutive_pairs);
}

fn ropeOp(ctx: *anyopaque, input: CT, seq_len: usize, head_dim: usize, rope_dim: usize, theta: f32, freq_scale: f32, position_offset: usize, consecutive_pairs: bool) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const data = getData(input);
    const total_chunks = data.len / head_dim;
    if (seq_len == 0) return error.InvalidRoPEInput;
    if (total_chunks % seq_len != 0) return error.InvalidRoPEInput;
    const chunks_per_position = total_chunks / seq_len;
    if (chunks_per_position == 0) return error.InvalidRoPEInput;
    const output = try self.allocator.dupe(f32, data);
    errdefer self.allocator.free(output);

    // Build flat position array: one position per head-sized chunk.
    // Layout is [batch * seq_len, num_heads], flattened by rows, so each token
    // position must repeat for all heads in that row.
    const positions = try self.allocator.alloc(usize, total_chunks);
    defer self.allocator.free(positions);
    for (0..total_chunks) |tok| {
        positions[tok] = position_offset + ((tok / chunks_per_position) % seq_len);
    }

    ropeCore(output, positions, head_dim, rope_dim, theta, freq_scale, consecutive_pairs);
    const result = try self.makeBuf(output, true);
    return propagateLogicalShapeLike(self, result, input);
}

fn ropePerItemOp(
    ctx: *anyopaque,
    input: CT,
    batch: usize,
    max_seq_len: usize,
    head_dim: usize,
    rope_dim: usize,
    theta: f32,
    freq_scale: f32,
    query_lengths: []const usize,
    position_offsets: []const usize,
    consecutive_pairs: bool,
) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    if (query_lengths.len != batch or position_offsets.len != batch) return error.InvalidRoPEInput;

    const data = getData(input);
    const row_count = batch * max_seq_len;
    if (row_count == 0) return self.makeBuf(try self.allocator.dupe(f32, data), true);
    if (data.len % row_count != 0) return error.InvalidRoPEInput;

    const row_dim = data.len / row_count;
    if (row_dim % head_dim != 0) return error.InvalidRoPEInput;
    const num_heads = row_dim / head_dim;
    const output = try self.allocator.dupe(f32, data);
    errdefer self.allocator.free(output);

    // Build flat position array: one entry per head-sized chunk.
    // Layout is [batch][max_seq_len][num_heads], each chunk is head_dim floats.
    // Padded positions (pos >= query_lengths[b]) get 0, which is identity rotation.
    const total_tokens = row_count * num_heads;
    const positions = try self.allocator.alloc(usize, total_tokens);
    defer self.allocator.free(positions);
    @memset(positions, 0);

    for (0..batch) |b| {
        if (query_lengths[b] > max_seq_len) {
            return error.InvalidRoPEInput;
        }
        for (0..query_lengths[b]) |pos| {
            const absolute_pos = position_offsets[b] + pos;
            const row_base = (b * max_seq_len + pos) * num_heads;
            for (0..num_heads) |h| {
                positions[row_base + h] = absolute_pos;
            }
        }
    }

    ropeCore(output, positions, head_dim, rope_dim, theta, freq_scale, consecutive_pairs);
    return self.makeBuf(output, true);
}

fn gqaCausalAttentionOp(ctx: *anyopaque, q_ct: CT, k_ct: CT, v_ct: CT, attn_bias_ct: ?CT, batch: usize, seq_len: usize, num_heads: usize, num_kv_heads: usize, head_dim: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const Q = getData(q_ct);
    const K = getData(k_ct);
    const V = getData(v_ct);
    const bias: ?[]f32 = if (attn_bias_ct) |b| getData(b) else null;

    return gqaAttentionSlices(self, Q, K, V, bias, null, 0, null, seq_len, batch, seq_len, seq_len, 0, 0, num_heads, num_kv_heads, head_dim);
}

fn attentionSinkScores(sink: AttentionSinkMetadata, num_heads: usize) !?[]const f32 {
    if (sink.per_head_tensor) |tensor| {
        const scores = getData(tensor);
        if (scores.len < num_heads) return error.InvalidAttentionSinkShape;
        return scores[0..num_heads];
    }
    if (sink.slot != null) return error.UnsupportedAttentionSink;
    return null;
}

fn gqaAttentionSlices(
    self: *NativeCompute,
    Q: []const f32,
    K: []const f32,
    V: []const f32,
    bias: ?[]const f32,
    attn_or_mask: ?[]const u8,
    sliding_window: usize,
    sink_scores: ?[]const f32,
    total_sequence_len: usize,
    batch: usize,
    q_seq_len: usize,
    kv_seq_len: usize,
    query_position_offset: usize,
    kv_position_offset: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
) !CT {
    const output = if (sink_scores) |scores|
        try gqaAttentionSlicesSinkHost(self.allocator, Q, K, V, bias, attn_or_mask, sliding_window, scores, total_sequence_len, batch, q_seq_len, kv_seq_len, query_position_offset, kv_position_offset, num_heads, num_kv_heads, head_dim)
    else
        try flashCausalAttentionHost(self.allocator, Q, K, V, bias, attn_or_mask, sliding_window, batch, q_seq_len, kv_seq_len, query_position_offset, kv_position_offset, num_heads, num_kv_heads, head_dim);
    return self.makeBuf(output, true);
}

pub fn gqaAttentionSlicesSinkHost(
    allocator: std.mem.Allocator,
    Q: []const f32,
    K: []const f32,
    V: []const f32,
    bias: ?[]const f32,
    attn_or_mask: ?[]const u8,
    sliding_window: usize,
    sink_scores: []const f32,
    total_sequence_len: usize,
    batch: usize,
    q_seq_len: usize,
    kv_seq_len: usize,
    query_position_offset: usize,
    kv_position_offset: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
) ![]f32 {
    if (num_kv_heads == 0 or num_heads % num_kv_heads != 0) return error.InvalidAttentionShape;
    if (sink_scores.len < num_heads) return error.InvalidAttentionSinkShape;
    const H_q = num_heads * head_dim;
    const H_kv = num_kv_heads * head_dim;
    if (Q.len != batch * q_seq_len * H_q) return error.InvalidAttentionShape;
    if (K.len != batch * kv_seq_len * H_kv) return error.InvalidAttentionShape;
    if (V.len != batch * kv_seq_len * H_kv) return error.InvalidAttentionShape;

    const output = try allocator.alloc(f32, batch * q_seq_len * H_q);
    errdefer allocator.free(output);
    @memset(output, 0.0);

    const heads_per_group = num_heads / num_kv_heads;
    const scale: f32 = 1.0 / @sqrt(@as(f32, @floatFromInt(head_dim)));
    for (0..batch) |b| {
        for (0..num_heads) |h| {
            const kv_h = h / heads_per_group;
            const sink_score = sink_scores[h];
            for (0..q_seq_len) |qi| {
                const q_ptr = Q[(b * q_seq_len + qi) * H_q + h * head_dim ..][0..head_dim];
                const out_ptr = output[(b * q_seq_len + qi) * H_q + h * head_dim ..][0..head_dim];
                var running_max = sink_score;
                var running_sum: f32 = 1.0;

                for (0..kv_seq_len) |ki| {
                    const query_pos = query_position_offset + qi;
                    const key_pos = kv_position_offset + ki;
                    if ((key_pos > query_pos and !allowsFutureAttention(attn_or_mask, total_sequence_len, query_pos, key_pos)) or !allowsPastAttention(sliding_window, query_pos, key_pos)) continue;

                    const k_ptr = K[(b * kv_seq_len + ki) * H_kv + kv_h * head_dim ..][0..head_dim];
                    const v_ptr = V[(b * kv_seq_len + ki) * H_kv + kv_h * head_dim ..][0..head_dim];
                    var score = linalg.dot(q_ptr, k_ptr) * scale;
                    if (bias) |bias_data| score += bias_data[h * q_seq_len * kv_seq_len + qi * kv_seq_len + ki];

                    const new_max = @max(running_max, score);
                    const prev_scale = @exp(running_max - new_max);
                    const score_scale = @exp(score - new_max);
                    if (prev_scale != 1.0) {
                        for (0..head_dim) |d| out_ptr[d] *= prev_scale;
                    }
                    linalg.axpy(score_scale, v_ptr, out_ptr);
                    running_sum = running_sum * prev_scale + score_scale;
                    running_max = new_max;
                }

                const inv_sum = 1.0 / running_sum;
                for (0..head_dim) |d| out_ptr[d] *= inv_sum;
            }
        }
    }
    return output;
}

// --- Flash Attention with tiled online softmax ---
//
// Instead of materializing the full [q_seq, kv_seq] score matrix, we tile Q
// into blocks of BLOCK_Q rows and stream over K/V in blocks of BLOCK_KV.
// For each Q-tile we maintain per-row running max and sum_exp accumulators
// (online softmax / Welford-style) and incrementally accumulate the output
// O_tile = softmax(Q_tile @ K^T / sqrt(d)) @ V without ever allocating more
// than [BLOCK_Q, BLOCK_KV] floats for the score tile.
//
// Memory: O(BLOCK_Q * BLOCK_KV + BLOCK_Q * head_dim) instead of O(seq^2).

/// Tiled flash causal attention supporting both MHA (num_heads == num_kv_heads)
/// and GQA (num_heads > num_kv_heads, evenly divisible).
pub fn flashCausalAttentionHost(
    allocator: std.mem.Allocator,
    Q: []const f32,
    K: []const f32,
    V: []const f32,
    bias: ?[]const f32,
    attn_or_mask: ?[]const u8,
    sliding_window: usize,
    batch: usize,
    q_seq_len: usize,
    kv_seq_len: usize,
    query_position_offset: usize,
    kv_position_offset: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
) ![]f32 {
    return linalg.flashCausalAttentionHost(
        allocator,
        Q,
        K,
        V,
        bias,
        attn_or_mask,
        sliding_window,
        batch,
        q_seq_len,
        kv_seq_len,
        query_position_offset,
        kv_position_offset,
        num_heads,
        num_kv_heads,
        head_dim,
    );
}

fn allowsFutureAttention(attn_or_mask: ?[]const u8, total_sequence_len: usize, query_pos: usize, key_pos: usize) bool {
    const mask = attn_or_mask orelse return false;
    if (query_pos >= total_sequence_len or key_pos >= total_sequence_len) return false;
    const idx = query_pos * total_sequence_len + key_pos;
    if (idx >= mask.len) return false;
    return mask[idx] != 0;
}

fn allowsPastAttention(sliding_window: usize, query_pos: usize, key_pos: usize) bool {
    if (key_pos > query_pos) return false;
    if (sliding_window == 0) return true;
    return query_pos - key_pos < sliding_window;
}

pub fn gqaCausalAttentionNaiveHost(
    allocator: std.mem.Allocator,
    Q: []const f32,
    K: []const f32,
    V: []const f32,
    batch: usize,
    seq_len: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
) ![]f32 {
    const H_q = std.math.mul(usize, num_heads, head_dim) catch return error.InvalidAttentionShape;
    const H_kv = std.math.mul(usize, num_kv_heads, head_dim) catch return error.InvalidAttentionShape;
    if (Q.len != batch * seq_len * H_q) return error.InvalidAttentionShape;
    if (K.len != batch * seq_len * H_kv) return error.InvalidAttentionShape;
    if (V.len != batch * seq_len * H_kv) return error.InvalidAttentionShape;
    if (num_heads % num_kv_heads != 0) return error.InvalidAttentionShape;

    const output = try allocator.alloc(f32, Q.len);
    errdefer allocator.free(output);
    @memset(output, 0.0);

    const scale: f32 = 1.0 / @sqrt(@as(f32, @floatFromInt(head_dim)));
    const heads_per_group = num_heads / num_kv_heads;
    var score_row = try allocator.alloc(f32, seq_len);
    defer allocator.free(score_row);

    for (0..batch) |b| {
        for (0..num_heads) |h| {
            const kv_h = h / heads_per_group;
            for (0..seq_len) |qi| {
                const q_base = (b * seq_len + qi) * H_q + h * head_dim;

                var row_max: f32 = -std.math.inf(f32);
                for (0..seq_len) |ki| {
                    if (ki > qi) {
                        score_row[ki] = -std.math.inf(f32);
                    } else {
                        const k_base = (b * seq_len + ki) * H_kv + kv_h * head_dim;
                        var d: f32 = 0.0;
                        for (0..head_dim) |dd| d += Q[q_base + dd] * K[k_base + dd];
                        score_row[ki] = d * scale;
                        if (score_row[ki] > row_max) row_max = score_row[ki];
                    }
                }

                var sum_exp: f32 = 0.0;
                for (0..seq_len) |ki| {
                    if (score_row[ki] == -std.math.inf(f32)) {
                        score_row[ki] = 0.0;
                    } else {
                        score_row[ki] = @exp(score_row[ki] - row_max);
                        sum_exp += score_row[ki];
                    }
                }
                if (sum_exp > 0.0) {
                    const inv_sum = 1.0 / sum_exp;
                    for (0..seq_len) |ki| score_row[ki] *= inv_sum;
                }

                const out_base = (b * seq_len + qi) * H_q + h * head_dim;
                for (0..seq_len) |vi| {
                    const w = score_row[vi];
                    if (w == 0.0) continue;
                    const v_base = (b * seq_len + vi) * H_kv + kv_h * head_dim;
                    for (0..head_dim) |dd| {
                        output[out_base + dd] += w * V[v_base + dd];
                    }
                }
            }
        }
    }

    return output;
}

fn gqaPagedAttentionOp(ctx: *anyopaque, q_ct: CT, k_ct: CT, v_ct: CT, attn_bias_ct: ?CT, attention: AttentionContext, batch: usize, num_heads: usize, num_kv_heads: usize, head_dim: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const Q = getData(q_ct);
    const K = getData(k_ct);
    const V = getData(v_ct);
    const bias: ?[]f32 = if (attn_bias_ct) |b| getData(b) else null;

    if (attention.kv_batch) |kv_batch| {
        if (attention.attn_or_mask != null) return error.AttentionOrMaskBatchUnsupported;
        if (kv_batch.len != batch) return error.InvalidPagedKvBatch;

        // Check if this is a mixed batch (per-item overrides present).
        const is_mixed = kv_batch[0].per_item_query_len != null;

        if (is_mixed) {
            // Mixed prefill+decode batch: each item has its own query_sequence_len.
            // Tokens are packed with padding to attention.query_sequence_len (the max).
            const max_q_rows = attention.query_sequence_len;
            const H_q = num_heads * head_dim;
            const H_kv = num_kv_heads * head_dim;
            const q_span = max_q_rows * H_q;
            const kv_span = max_q_rows * H_kv;
            const output = try self.allocator.alloc(f32, batch * q_span);
            errdefer self.allocator.free(output);
            @memset(output, 0.0);

            for (0..batch) |b| {
                const view = kv_batch[b];
                const item_q_len = view.per_item_query_len orelse attention.query_sequence_len;
                const item_total_len = view.per_item_total_len orelse attention.total_sequence_len;
                const item_kv_len = view.per_item_kv_len orelse attention.kv_sequence_len;
                const item_kv_pos_offset = view.per_item_kv_position_offset orelse attention.kv_position_offset;

                const item_attention: AttentionContext = .{
                    .mode = view.per_item_mode orelse attention.mode,
                    .total_sequence_len = item_total_len,
                    .query_sequence_len = item_q_len,
                    .kv_sequence_len = item_kv_len,
                    .kv_position_offset = item_kv_pos_offset,
                    .sliding_window = attention.sliding_window,
                    .kv_cache = view.kv_cache,
                    .kv_manager = view.kv_manager,
                    .kv_storage = view.kv_storage,
                    .kv_batch = null,
                    .layer_index = attention.layer_index,
                    .skip_kv_write = attention.skip_kv_write,
                    .attention_sink = attention.attention_sink,
                };

                // Slice this item's Q/K/V from the padded layout.
                const item_q_span = item_q_len * H_q;
                const item_kv_span = item_q_len * H_kv;
                const q_slice = Q[b * q_span ..][0..item_q_span];
                const k_slice = K[b * kv_span ..][0..item_kv_span];
                const v_slice = V[b * kv_span ..][0..item_kv_span];

                if (!attention.skip_kv_write)
                    try view.kv_manager.writeLayerKvSuffix(view.kv_cache.sequence_id, attention.layer_index, item_kv_len, item_q_len, k_slice, v_slice);
                const item_ct = try gqaPagedAttentionDirect(self, view.kv_manager, attention.layer_index, q_slice, bias, item_attention, num_heads, num_kv_heads, head_dim);
                defer freeTensor(undefined, item_ct);
                const item = getData(item_ct);
                @memcpy(output[b * q_span ..][0..item_q_span], item);
            }

            return self.makeBuf(output, true);
        }

        // Uniform batch: all items share the same sequence dimensions.
        const q_rows = attention.query_sequence_len;
        const H_q = num_heads * head_dim;
        const H_kv = num_kv_heads * head_dim;
        const q_span = q_rows * H_q;
        const kv_span = q_rows * H_kv;
        const output = try self.allocator.alloc(f32, batch * q_span);
        errdefer self.allocator.free(output);

        for (0..batch) |b| {
            const view = kv_batch[b];
            var item_attention = attention;
            item_attention.kv_batch = null;
            item_attention.kv_cache = view.kv_cache;
            item_attention.kv_manager = view.kv_manager;

            const q_slice = Q[b * q_span ..][0..q_span];
            const k_slice = K[b * kv_span ..][0..kv_span];
            const v_slice = V[b * kv_span ..][0..kv_span];

            if (!attention.skip_kv_write)
                try view.kv_manager.writeLayerKvSuffix(view.kv_cache.sequence_id, attention.layer_index, attention.kv_sequence_len, attention.query_sequence_len, k_slice, v_slice);
            const item_ct = try gqaPagedAttentionDirect(self, view.kv_manager, attention.layer_index, q_slice, bias, item_attention, num_heads, num_kv_heads, head_dim);
            defer freeTensor(undefined, item_ct);
            const item = getData(item_ct);
            @memcpy(output[b * q_span ..][0..q_span], item);
        }

        return self.makeBuf(output, true);
    }

    const sink_scores = try attentionSinkScores(attention.attention_sink, num_heads);
    if (batch > 1) {
        return gqaAttentionSlices(self, Q, K, V, bias, attention.attn_or_mask, attention.sliding_window, sink_scores, attention.total_sequence_len, batch, attention.query_sequence_len, attention.kv_sequence_len, attention.total_sequence_len - attention.query_sequence_len, attention.kv_position_offset, num_heads, num_kv_heads, head_dim);
    }

    const manager = attention.kv_manager orelse return gqaAttentionSlices(self, Q, K, V, bias, attention.attn_or_mask, attention.sliding_window, sink_scores, attention.total_sequence_len, batch, attention.query_sequence_len, attention.kv_sequence_len, attention.total_sequence_len - attention.query_sequence_len, attention.kv_position_offset, num_heads, num_kv_heads, head_dim);
    const kv = attention.kv_cache orelse return gqaAttentionSlices(self, Q, K, V, bias, attention.attn_or_mask, attention.sliding_window, sink_scores, attention.total_sequence_len, batch, attention.query_sequence_len, attention.kv_sequence_len, attention.total_sequence_len - attention.query_sequence_len, attention.kv_position_offset, num_heads, num_kv_heads, head_dim);

    if (!attention.skip_kv_write)
        try manager.writeLayerKvSuffix(kv.sequence_id, attention.layer_index, attention.kv_sequence_len, attention.query_sequence_len, K, V);
    _ = attention.mode;
    return gqaPagedAttentionDirect(self, manager, attention.layer_index, Q, bias, attention, num_heads, num_kv_heads, head_dim);
}

fn gqaPagedAttentionDirect(
    self: *NativeCompute,
    manager: *runtime.kv.manager.KvManager,
    layer_index: usize,
    Q: []const f32,
    bias: ?[]const f32,
    attention: AttentionContext,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
) !CT {
    const kv = attention.kv_cache orelse return error.InvalidPagedKvState;
    const block_ids = if (kv.logical_blocks) |blocks|
        blocks
    else blk: {
        const table = manager.blockTable(kv.sequence_id) orelse return error.InvalidSequenceId;
        break :blk table.blocks.items;
    };
    const pool = manager.getPoolMut(kv.pool_id) orelse return error.InvalidPoolId;
    if (pool.config.dtype == .polar4 or pool.config.dtype == .turbo3) {
        return gqaPagedAttentionDirectTurboQuant(self, pool, block_ids, layer_index, Q, bias, attention, num_heads, num_kv_heads, head_dim);
    }

    const q_seq_len = attention.query_sequence_len;
    const kv_seq_len = attention.kv_sequence_len;
    const query_position_offset = attention.total_sequence_len - q_seq_len;
    const kv_position_offset = attention.kv_position_offset;
    const H_q = num_heads * head_dim;
    const heads_per_group = num_heads / num_kv_heads;
    const scale: f32 = 1.0 / @sqrt(@as(f32, @floatFromInt(head_dim)));
    const sink_scores = try attentionSinkScores(attention.attention_sink, num_heads);
    const output = try self.allocator.alloc(f32, q_seq_len * H_q);
    errdefer self.allocator.free(output);
    @memset(output, 0.0);

    for (0..num_heads) |h| {
        const kv_h = h / heads_per_group;
        for (0..q_seq_len) |qi| {
            const q_ptr = Q[qi * H_q + h * head_dim ..].ptr;
            const out_ptr = output[qi * H_q + h * head_dim ..].ptr;
            var running_max = if (sink_scores) |scores| scores[h] else -std.math.inf(f32);
            var running_sum: f32 = if (sink_scores != null) 1.0 else 0.0;

            for (0..kv_seq_len) |token_idx| {
                const block_idx = token_idx / pool.config.page_size_tokens;
                const token_offset = token_idx % pool.config.page_size_tokens;
                if (block_idx >= block_ids.len) return error.InvalidPagedKvState;
                const block_id = block_ids[block_idx];
                const row = try pool.readToken(block_id, layer_index, token_offset);
                const k_ptr = row.k[kv_h * head_dim ..].ptr;
                const v_ptr = row.v[kv_h * head_dim ..].ptr;

                const query_pos = query_position_offset + qi;
                const key_pos = kv_position_offset + token_idx;
                if ((key_pos > query_pos and !allowsFutureAttention(attention.attn_or_mask, attention.total_sequence_len, query_pos, key_pos)) or !allowsPastAttention(attention.sliding_window, query_pos, key_pos)) continue;

                var score = linalg.dot(q_ptr[0..head_dim], k_ptr[0..head_dim]) * scale;
                if (bias) |bias_data| {
                    score += bias_data[h * q_seq_len * kv_seq_len + qi * kv_seq_len + key_pos];
                }

                const new_max = @max(running_max, score);
                const prev_scale: f32 = if (running_sum == 0.0) 0.0 else @exp(running_max - new_max);
                const score_scale = @exp(score - new_max);
                if (prev_scale != 1.0) {
                    for (0..head_dim) |d| out_ptr[d] *= prev_scale;
                }
                linalg.axpy(score_scale, v_ptr[0..head_dim], out_ptr[0..head_dim]);
                running_sum = running_sum * prev_scale + score_scale;
                running_max = new_max;
            }

            if (running_sum != 0.0) {
                const inv_sum = 1.0 / running_sum;
                for (0..head_dim) |d| out_ptr[d] *= inv_sum;
            }
        }
    }

    return self.makeBuf(output, true);
}

fn gqaPagedAttentionDirectTurboQuant(
    self: *NativeCompute,
    pool: *runtime.kv.storage.KvStorage,
    block_ids: []const runtime.kv.block.KvBlockId,
    layer_index: usize,
    Q: []const f32,
    bias: ?[]const f32,
    attention: AttentionContext,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
) !CT {
    if (pool.config.num_kv_heads != num_kv_heads or pool.config.head_dim != head_dim) return error.InvalidPagedKvState;

    const q_seq_len = attention.query_sequence_len;
    const kv_seq_len = attention.kv_sequence_len;
    const query_position_offset = attention.total_sequence_len - q_seq_len;
    const kv_position_offset = attention.kv_position_offset;
    const H_q = num_heads * head_dim;
    const heads_per_group = num_heads / num_kv_heads;
    const scale: f32 = 1.0 / @sqrt(@as(f32, @floatFromInt(head_dim)));
    const sink_scores = try attentionSinkScores(attention.attention_sink, num_heads);
    const output = try self.allocator.alloc(f32, q_seq_len * H_q);
    errdefer self.allocator.free(output);
    @memset(output, 0.0);

    for (0..num_heads) |h| {
        const kv_h = h / heads_per_group;
        for (0..q_seq_len) |qi| {
            const q_slice = Q[qi * H_q + h * head_dim ..][0..head_dim];
            var turbo3_projected_query: [runtime.kv.turboquant.turbo3_residual_bits_per_head]f32 = undefined;
            if (pool.config.dtype == .turbo3) {
                try runtime.kv.turboquant.projectTurbo3ResidualQuery(q_slice, &turbo3_projected_query, @intCast(head_dim), kv_h);
            }
            const out_ptr = output[qi * H_q + h * head_dim ..].ptr;
            var running_max = if (sink_scores) |scores| scores[h] else -std.math.inf(f32);
            var running_sum: f32 = if (sink_scores != null) 1.0 else 0.0;

            for (0..kv_seq_len) |token_idx| {
                const block_idx = token_idx / pool.config.page_size_tokens;
                const token_offset = token_idx % pool.config.page_size_tokens;
                if (block_idx >= block_ids.len) return error.InvalidPagedKvState;
                const block_id = block_ids[block_idx];

                const query_pos = query_position_offset + qi;
                const key_pos = kv_position_offset + token_idx;
                if ((key_pos > query_pos and !allowsFutureAttention(attention.attn_or_mask, attention.total_sequence_len, query_pos, key_pos)) or !allowsPastAttention(attention.sliding_window, query_pos, key_pos)) continue;

                const encoded = try pool.readEncodedToken(block_id, layer_index, token_offset);
                const v_row = try pool.readValueToken(block_id, layer_index, token_offset);
                const v_ptr = v_row[kv_h * head_dim ..].ptr;

                var score = switch (pool.config.dtype) {
                    .polar4 => try runtime.kv.turboquant.dotPolar4KeyFast(q_slice, encoded.k_bytes, @intCast(num_kv_heads), @intCast(head_dim), kv_h),
                    .turbo3 => blk: {
                        const base_bytes = runtime.kv.turboquant.turbo3KeyBytes(@intCast(num_kv_heads), @intCast(head_dim));
                        const residual_bytes = runtime.kv.turboquant.turbo3ResidualBytes(@intCast(num_kv_heads), @intCast(head_dim));
                        const base_score = try runtime.kv.turboquant.dotTurbo3KeyFast(q_slice, encoded.k_bytes[0..base_bytes], @intCast(num_kv_heads), @intCast(head_dim), kv_h);
                        const residual_score = try runtime.kv.turboquant.dotTurbo3ProjectedResidualSketch(&turbo3_projected_query, encoded.k_bytes[base_bytes..][0..residual_bytes], @intCast(num_kv_heads), @intCast(head_dim), kv_h);
                        break :blk base_score + runtime.kv.turboquant.turbo3_residual_default_scale * residual_score;
                    },
                    else => unreachable,
                };
                score *= scale;
                if (bias) |bias_data| {
                    score += bias_data[h * q_seq_len * kv_seq_len + qi * kv_seq_len + key_pos];
                }

                const new_max = @max(running_max, score);
                const prev_scale: f32 = if (running_sum == 0.0) 0.0 else @exp(running_max - new_max);
                const score_scale = @exp(score - new_max);
                if (prev_scale != 1.0) {
                    for (0..head_dim) |d| out_ptr[d] *= prev_scale;
                }
                linalg.axpy(score_scale, v_ptr[0..head_dim], out_ptr[0..head_dim]);
                running_sum = running_sum * prev_scale + score_scale;
                running_max = new_max;
            }

            if (running_sum != 0.0) {
                const inv_sum = 1.0 / running_sum;
                for (0..head_dim) |d| out_ptr[d] *= inv_sum;
            }
        }
    }

    return self.makeBuf(output, true);
}

// ── Primitive ops for training ─────────────────────────────────────────

/// Binary op helper that handles implicit trailing-dimension broadcasting.
/// When one operand is shorter and evenly divides the longer, it repeats cyclically.
fn primBinaryBroadcast(allocator: std.mem.Allocator, a_data: []const f32, b_data: []const f32, comptime op: enum { sub, div, add_prim, mul_prim, lt }) ![]f32 {
    const big = if (a_data.len >= b_data.len) a_data else b_data;
    const small = if (a_data.len >= b_data.len) b_data else a_data;
    const a_is_big = a_data.len >= b_data.len;
    if (small.len == 0 and big.len != 0) return error.ShapeMismatch;
    const output = try allocator.alloc(f32, big.len);

    if (small.len == big.len) {
        // Same size — fast path.
        for (big, small, 0..) |va, vb, i| {
            const a_val = if (a_is_big) va else vb;
            const b_val = if (a_is_big) vb else va;
            output[i] = switch (op) {
                .sub => a_val - b_val,
                .div => a_val / b_val,
                .add_prim => a_val + b_val,
                .mul_prim => a_val * b_val,
                .lt => if (a_val < b_val) @as(f32, 1.0) else @as(f32, 0.0),
            };
        }
    } else {
        // Broadcast: small repeats over trailing dim.
        for (0..big.len) |i| {
            const bi = i % small.len;
            const a_val = if (a_is_big) big[i] else small[bi];
            const b_val = if (a_is_big) small[bi] else big[i];
            output[i] = switch (op) {
                .sub => a_val - b_val,
                .div => a_val / b_val,
                .add_prim => a_val + b_val,
                .mul_prim => a_val * b_val,
                .lt => if (a_val < b_val) @as(f32, 1.0) else @as(f32, 0.0),
            };
        }
    }
    return output;
}

fn subtractOp(ctx: *anyopaque, a: CT, b: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    if (try applyShapeAwareBinaryOp(self, a, b, .sub)) |result| {
        return result;
    }
    const a_view = try denseTensorView(self, a);
    defer if (a_view.owned) |owned| self.allocator.free(owned);
    const b_view = try denseTensorView(self, b);
    defer if (b_view.owned) |owned| self.allocator.free(owned);
    const output = try primBinaryBroadcast(self.allocator, a_view.data, b_view.data, .sub);
    const result = try self.makeOwnedBuf(output);
    errdefer freeTensor(self, result);
    return propagateLogicalShapeFromBinaryOperands(self, result, a, b);
}

fn divideOp(ctx: *anyopaque, a: CT, b: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    if (try applyShapeAwareBinaryOp(self, a, b, .div)) |result| {
        return result;
    }
    const a_view = try denseTensorView(self, a);
    defer if (a_view.owned) |owned| self.allocator.free(owned);
    const b_view = try denseTensorView(self, b);
    defer if (b_view.owned) |owned| self.allocator.free(owned);
    const output = try primBinaryBroadcast(self.allocator, a_view.data, b_view.data, .div);
    const result = try self.makeOwnedBuf(output);
    errdefer freeTensor(self, result);
    return propagateLogicalShapeFromBinaryOperands(self, result, a, b);
}

fn negateOp(ctx: *anyopaque, a: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const a_data = getData(a);
    const output = try self.allocator.alloc(f32, a_data.len);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    var i: usize = 0;
    while (i + VEC_LEN <= a_data.len) : (i += VEC_LEN) {
        const va: F32xN = a_data[i..][0..VEC_LEN].*;
        output[i..][0..VEC_LEN].* = -va;
    }
    while (i < a_data.len) : (i += 1) output[i] = -a_data[i];
    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    return propagateLogicalShapeLike(self, result, a);
}

fn primUnaryOp(comptime op: enum { sqrt, rsqrt, exp, log, sin, cos, tanh_prim, abs }, ctx: *anyopaque, a: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const a_data = getData(a);
    const output = try self.allocator.alloc(f32, a_data.len);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    for (a_data, 0..) |v, i| {
        output[i] = switch (op) {
            .sqrt => @sqrt(v),
            .rsqrt => 1.0 / @sqrt(v),
            .exp => @exp(v),
            .log => @log(v),
            .sin => @sin(v),
            .cos => @cos(v),
            .tanh_prim => std.math.tanh(v),
            .abs => @abs(v),
        };
    }
    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    return propagateLogicalShapeLike(self, result, a);
}

fn primSqrtOp(ctx: *anyopaque, a: CT) anyerror!CT {
    return primUnaryOp(.sqrt, ctx, a);
}
fn primRsqrtOp(ctx: *anyopaque, a: CT) anyerror!CT {
    return primUnaryOp(.rsqrt, ctx, a);
}
fn primExpOp(ctx: *anyopaque, a: CT) anyerror!CT {
    return primUnaryOp(.exp, ctx, a);
}
fn primLogOp(ctx: *anyopaque, a: CT) anyerror!CT {
    return primUnaryOp(.log, ctx, a);
}
fn primSinOp(ctx: *anyopaque, a: CT) anyerror!CT {
    return primUnaryOp(.sin, ctx, a);
}
fn primCosOp(ctx: *anyopaque, a: CT) anyerror!CT {
    return primUnaryOp(.cos, ctx, a);
}
fn primTanhOp(ctx: *anyopaque, a: CT) anyerror!CT {
    return primUnaryOp(.tanh_prim, ctx, a);
}
fn primAbsOp(ctx: *anyopaque, a: CT) anyerror!CT {
    return primUnaryOp(.abs, ctx, a);
}

fn primErfOp(ctx: *anyopaque, a: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const a_data = getData(a);
    const output = try self.allocator.alloc(f32, a_data.len);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    // Abramowitz & Stegun approximation (max error ~1.5e-7)
    for (a_data, 0..) |v, i| {
        const x = @abs(v);
        const t = 1.0 / (1.0 + 0.3275911 * x);
        const poly = t * (0.254829592 + t * (-0.284496736 + t * (1.421413741 + t * (-1.453152027 + t * 1.061405429))));
        const result = 1.0 - poly * @exp(-x * x);
        output[i] = if (v >= 0) result else -result;
    }
    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    return propagateLogicalShapeLike(self, result, a);
}

fn lessThanOp(ctx: *anyopaque, a: CT, b: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    if (try applyShapeAwareBinaryOp(self, a, b, .lt)) |result| {
        return result;
    }
    const a_view = try denseTensorView(self, a);
    defer if (a_view.owned) |owned| self.allocator.free(owned);
    const b_view = try denseTensorView(self, b);
    defer if (b_view.owned) |owned| self.allocator.free(owned);
    const a_data = a_view.data;
    const b_data = b_view.data;
    const output = try primBinaryBroadcast(self.allocator, a_data, b_data, .lt);
    const result = try self.makeOwnedBuf(output);
    errdefer freeTensor(self, result);
    return propagateLogicalShapeFromBinaryOperands(self, result, a, b);
}

fn whereSelectOp(ctx: *anyopaque, cond: CT, on_true: CT, on_false: CT) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    var c_shape_symbolic_buf: [8]i64 = undefined;
    var t_shape_symbolic_buf: [8]i64 = undefined;
    var f_shape_symbolic_buf: [8]i64 = undefined;
    const c_shape_symbolic = symbolicShapeForBroadcast(cond, &c_shape_symbolic_buf);
    const t_shape_symbolic = symbolicShapeForBroadcast(on_true, &t_shape_symbolic_buf);
    const f_shape_symbolic = symbolicShapeForBroadcast(on_false, &f_shape_symbolic_buf);
    const c_len = toBuf(cond).data.len;
    const t_len = toBuf(on_true).data.len;
    const f_len = toBuf(on_false).data.len;

    var loose_out_shape_buf: [8]i64 = undefined;
    const loose_out_rank = computeBroadcastShape3Loose(c_shape_symbolic, t_shape_symbolic, f_shape_symbolic, &loose_out_shape_buf) orelse blk: {
        break :blk importedFlattenedBroadcastFallbackShape(
            c_shape_symbolic,
            t_shape_symbolic,
            f_shape_symbolic,
            c_len,
            t_len,
            f_len,
            &loose_out_shape_buf,
        ) orelse {
            std.log.warn("where_select broadcast mismatch cond_shape={any} true_shape={any} false_shape={any} cond_len={d} true_len={d} false_len={d}", .{
                c_shape_symbolic,
                t_shape_symbolic,
                f_shape_symbolic,
                c_len,
                t_len,
                f_len,
            });
            return error.ShapeMismatch;
        };
    };
    const loose_out_shape = loose_out_shape_buf[0..loose_out_rank];

    var c_shape_buf: [8]i64 = undefined;
    var t_shape_buf: [8]i64 = undefined;
    var f_shape_buf: [8]i64 = undefined;
    var c_shape = concretizeBroadcastOperandShape(c_shape_symbolic, c_len, loose_out_shape, &c_shape_buf);
    var t_shape = concretizeBroadcastOperandShape(t_shape_symbolic, t_len, loose_out_shape, &t_shape_buf);
    var f_shape = concretizeBroadcastOperandShape(f_shape_symbolic, f_len, loose_out_shape, &f_shape_buf);
    var c_coerced_shape_buf: [8]i64 = undefined;
    var t_coerced_shape_buf: [8]i64 = undefined;
    var f_coerced_shape_buf: [8]i64 = undefined;
    c_shape = coerceImportedFlattenedBroadcastOperandShape(c_shape_symbolic, c_shape, c_len, loose_out_shape, &c_coerced_shape_buf);
    t_shape = coerceImportedFlattenedBroadcastOperandShape(t_shape_symbolic, t_shape, t_len, loose_out_shape, &t_coerced_shape_buf);
    f_shape = coerceImportedFlattenedBroadcastOperandShape(f_shape_symbolic, f_shape, f_len, loose_out_shape, &f_coerced_shape_buf);

    var out_shape_buf: [8]i64 = undefined;
    const out_rank = computeBroadcastShape3(c_shape, t_shape, f_shape, &out_shape_buf) orelse {
        std.log.warn("where_select broadcast mismatch cond_shape={any} true_shape={any} false_shape={any} cond_len={d} true_len={d} false_len={d}", .{
            c_shape,
            t_shape,
            f_shape,
            toBuf(cond).data.len,
            toBuf(on_true).data.len,
            toBuf(on_false).data.len,
        });
        return error.ShapeMismatch;
    };
    const out_shape = out_shape_buf[0..out_rank];
    const out_len = if (out_rank == 0) @as(usize, 1) else shapeNumel(out_shape);
    var c_strides_scratch: [8]usize = undefined;
    var t_strides_scratch: [8]usize = undefined;
    var f_strides_scratch: [8]usize = undefined;
    const c_plan = denseReadPlanForResolvedShape(cond, c_shape, c_strides_scratch[0..c_shape.len]);
    const t_plan = denseReadPlanForResolvedShape(on_true, t_shape, t_strides_scratch[0..t_shape.len]);
    const f_plan = denseReadPlanForResolvedShape(on_false, f_shape, f_strides_scratch[0..f_shape.len]);
    const c_access = classifyBroadcastReadAccess(c_plan, c_shape, out_shape);
    const t_access = classifyBroadcastReadAccess(t_plan, t_shape, out_shape);
    const f_access = classifyBroadcastReadAccess(f_plan, f_shape, out_shape);
    const c_repeat = if (c_access.mode == .general) detectBroadcastBlockRepeatPlan(c_plan, c_shape, out_shape) else null;
    const t_repeat = if (t_access.mode == .general) detectBroadcastBlockRepeatPlan(t_plan, t_shape, out_shape) else null;
    const f_repeat = if (f_access.mode == .general) detectBroadcastBlockRepeatPlan(f_plan, f_shape, out_shape) else null;
    const loop_repeat = c_repeat orelse t_repeat orelse f_repeat;
    if (loop_repeat) |repeat_plan| {
        if ((c_access.mode != .general or (c_repeat != null and sameBroadcastBlockRepeatLoop(repeat_plan, c_repeat.?))) and
            (t_access.mode != .general or (t_repeat != null and sameBroadcastBlockRepeatLoop(repeat_plan, t_repeat.?))) and
            (f_access.mode != .general or (f_repeat != null and sameBroadcastBlockRepeatLoop(repeat_plan, f_repeat.?))))
        {
            maybeLogLargeTensor("where_select", out_len, out_shape);
            const output = try self.allocator.alloc(f32, out_len);
            var raw_output: ?[]f32 = output;
            errdefer if (raw_output) |raw| self.allocator.free(raw);
            var out_offset: usize = 0;
            for (0..repeat_plan.prefix_count) |prefix_idx| {
                const cond_block = if (c_repeat) |plan|
                    c_plan.data[plan.base_offset + prefix_idx * plan.block_len ..][0..plan.block_len]
                else
                    empty_f32[0..];
                const true_block = if (t_repeat) |plan|
                    t_plan.data[plan.base_offset + prefix_idx * plan.block_len ..][0..plan.block_len]
                else
                    empty_f32[0..];
                const false_block = if (f_repeat) |plan|
                    f_plan.data[plan.base_offset + prefix_idx * plan.block_len ..][0..plan.block_len]
                else
                    empty_f32[0..];
                for (0..repeat_plan.repeat_count) |_| {
                    for (0..repeat_plan.block_len) |j| {
                        const i = out_offset + j;
                        const c_val = switch (c_access.mode) {
                            .scalar => c_plan.data[c_plan.base_offset],
                            .linear => c_plan.data[c_plan.base_offset + i],
                            .general => cond_block[j],
                        };
                        const t_val = switch (t_access.mode) {
                            .scalar => t_plan.data[t_plan.base_offset],
                            .linear => t_plan.data[t_plan.base_offset + i],
                            .general => true_block[j],
                        };
                        const f_val = switch (f_access.mode) {
                            .scalar => f_plan.data[f_plan.base_offset],
                            .linear => f_plan.data[f_plan.base_offset + i],
                            .general => false_block[j],
                        };
                        output[i] = if (c_val != 0.0) t_val else f_val;
                    }
                    out_offset += repeat_plan.block_len;
                }
            }
            if (out_offset != out_len) return error.ShapeMismatch;
            const result = try self.makeBuf(output, true);
            raw_output = null;
            errdefer freeTensor(self, result);
            return self.withLogicalShape(result, out_shape);
        }
    }
    if (c_access.mode == .general and t_access.mode != .general and f_access.mode != .general) {
        if (detectBroadcastBlockRepeatPlan(c_plan, c_shape, out_shape)) |repeat_plan| {
            maybeLogLargeTensor("where_select", out_len, out_shape);
            const output = try self.allocator.alloc(f32, out_len);
            var raw_output: ?[]f32 = output;
            errdefer if (raw_output) |raw| self.allocator.free(raw);
            var out_offset: usize = 0;
            for (0..repeat_plan.prefix_count) |prefix_idx| {
                const cond_base = repeat_plan.base_offset + prefix_idx * repeat_plan.block_len;
                const cond_block = c_plan.data[cond_base .. cond_base + repeat_plan.block_len];
                for (0..repeat_plan.repeat_count) |_| {
                    for (cond_block, 0..) |cond_val, j| {
                        const i = out_offset + j;
                        const t_offset = switch (t_access.mode) {
                            .scalar => t_plan.base_offset,
                            .linear => t_plan.base_offset + i,
                            .general => unreachable,
                        };
                        const f_offset = switch (f_access.mode) {
                            .scalar => f_plan.base_offset,
                            .linear => f_plan.base_offset + i,
                            .general => unreachable,
                        };
                        if (t_offset >= t_plan.data.len or f_offset >= f_plan.data.len) return error.ShapeMismatch;
                        output[i] = if (cond_val != 0.0) t_plan.data[t_offset] else f_plan.data[f_offset];
                    }
                    out_offset += repeat_plan.block_len;
                }
            }
            if (out_offset != out_len) return error.ShapeMismatch;
            const result = try self.makeBuf(output, true);
            raw_output = null;
            errdefer freeTensor(self, result);
            return self.withLogicalShape(result, out_shape);
        }
    }
    var c_stepper = if (c_access.mode == .general) BroadcastStepper.init(out_shape, c_shape, c_plan.strides) else null;
    var t_stepper = if (t_access.mode == .general) BroadcastStepper.init(out_shape, t_shape, t_plan.strides) else null;
    var f_stepper = if (f_access.mode == .general) BroadcastStepper.init(out_shape, f_shape, f_plan.strides) else null;

    maybeLogLargeTensor("where_select", out_len, out_shape);
    const output = try self.allocator.alloc(f32, out_len);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    for (0..out_len) |i| {
        const c_offset = switch (c_access.mode) {
            .scalar => c_plan.base_offset,
            .linear => c_plan.base_offset + i,
            .general => c_plan.base_offset + c_stepper.?.currentOffset(),
        };
        const t_offset = switch (t_access.mode) {
            .scalar => t_plan.base_offset,
            .linear => t_plan.base_offset + i,
            .general => t_plan.base_offset + t_stepper.?.currentOffset(),
        };
        const f_offset = switch (f_access.mode) {
            .scalar => f_plan.base_offset,
            .linear => f_plan.base_offset + i,
            .general => f_plan.base_offset + f_stepper.?.currentOffset(),
        };
        if (c_offset >= c_plan.data.len or t_offset >= t_plan.data.len or f_offset >= f_plan.data.len) {
            std.log.warn("where_select offset mismatch i={d} out_shape={any} cond_shape={any} true_shape={any} false_shape={any} offsets={d}/{d}/{d} lens={d}/{d}/{d} modes={s}/{s}/{s}", .{
                i,
                out_shape,
                c_shape,
                t_shape,
                f_shape,
                c_offset,
                t_offset,
                f_offset,
                c_plan.data.len,
                t_plan.data.len,
                f_plan.data.len,
                @tagName(c_access.mode),
                @tagName(t_access.mode),
                @tagName(f_access.mode),
            });
            return error.ShapeMismatch;
        }
        output[i] = if (c_plan.data[c_offset] != 0.0) t_plan.data[t_offset] else f_plan.data[f_offset];
        if (c_stepper) |*stepper| stepper.advance();
        if (t_stepper) |*stepper| stepper.advance();
        if (f_stepper) |*stepper| stepper.advance();
    }
    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    return self.withLogicalShape(result, out_shape);
}

/// Compute strides for a given shape (row-major).
fn computeStrides(shape: []const i64, out: []usize) void {
    if (shape.len == 0) return;
    out[shape.len - 1] = 1;
    var j: usize = shape.len - 1;
    while (j > 0) {
        j -= 1;
        out[j] = out[j + 1] * @as(usize, @intCast(shape[j + 1]));
    }
}

/// Compute total number of elements from shape.
fn shapeNumel(shape: []const i64) usize {
    var n: usize = 1;
    for (shape) |d| n *= @as(usize, @intCast(d));
    return n;
}

fn safeShapeNumel(shape: []const i64) ?usize {
    var n: usize = 1;
    for (shape) |d| {
        if (d <= 0) return null;
        n = std.math.mul(usize, n, @intCast(d)) catch return null;
    }
    return n;
}

fn allShapeDimsPositive(shape: []const i64) bool {
    for (shape) |d| {
        if (d <= 0) return false;
    }
    return true;
}

fn allRepeatedBlocksEqual(data: []const f32, block_len: usize) bool {
    if (block_len == 0 or data.len == 0 or data.len % block_len != 0) return false;
    const repeats = data.len / block_len;
    if (repeats <= 1) return false;
    for (1..repeats) |repeat_idx| {
        const start = repeat_idx * block_len;
        if (!std.mem.eql(f32, data[0..block_len], data[start..][0..block_len])) {
            return false;
        }
    }
    return true;
}

fn resolveDeclaredBatchShape(shape: []const i64, batch_axes: []const u8, batch_size: usize) ?[8]i64 {
    if (batch_axes.len == 0 or batch_axes.len > 8) return null;

    var resolved: [8]i64 = undefined;
    var known_product: usize = 1;
    var unknown_index: ?usize = null;

    for (batch_axes, 0..) |axis, out_i| {
        if (axis >= shape.len) return null;
        const dim = shape[axis];
        if (dim > 0) {
            resolved[out_i] = dim;
            known_product = std.math.mul(usize, known_product, @intCast(dim)) catch return null;
            continue;
        }
        if (unknown_index != null) return null;
        unknown_index = out_i;
        resolved[out_i] = dim;
    }

    if (unknown_index) |idx| {
        if (known_product == 0 or batch_size % known_product != 0) return null;
        const inferred = batch_size / known_product;
        if (inferred == 0) return null;
        resolved[idx] = @intCast(inferred);
        return resolved;
    }

    if (known_product != batch_size) return null;
    return resolved;
}

fn primReduceSumOp(ctx: *anyopaque, input: CT, axes: []const u8, input_shape: []const i64) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    return primReduceOp(self, input, axes, input_shape, .sum);
}

fn primReduceMaxOp(ctx: *anyopaque, input: CT, axes: []const u8, input_shape: []const i64) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    return primReduceOp(self, input, axes, input_shape, .max);
}

fn primReduceMeanOp(ctx: *anyopaque, input: CT, axes: []const u8, input_shape: []const i64) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    return primReduceOp(self, input, axes, input_shape, .mean);
}

fn primArgMaxOp(ctx: *anyopaque, input: CT, axis: u8, keepdims: bool, input_shape: []const i64) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const in_data = getData(input);
    const effective_input_shape = storedOrDeclaredShape(input, input_shape);
    if (axis >= effective_input_shape.len) return error.ShapeMismatch;

    var resolved_input_shape_buf: [8]i64 = undefined;
    const resolved_input_shape = if (resolveShapeFromDataLen(effective_input_shape, in_data.len)) |resolved| blk: {
        resolved_input_shape_buf = resolved;
        break :blk resolved_input_shape_buf[0..effective_input_shape.len];
    } else blk: {
        for (0..effective_input_shape.len) |i| {
            resolved_input_shape_buf[i] = if (effective_input_shape[i] > 0) effective_input_shape[i] else 1;
        }
        break :blk resolved_input_shape_buf[0..effective_input_shape.len];
    };

    const rank = resolved_input_shape.len;
    const axis_dim_i64 = resolved_input_shape[axis];
    if (axis_dim_i64 <= 0) return error.ShapeMismatch;
    const axis_dim: usize = @intCast(axis_dim_i64);

    var outer: usize = 1;
    for (resolved_input_shape[0..axis]) |dim| outer *= @intCast(dim);
    var inner: usize = 1;
    for (resolved_input_shape[axis + 1 ..]) |dim| inner *= @intCast(dim);

    const out_numel = if (rank == 0) @as(usize, 1) else outer * inner;
    const output = try self.allocator.alloc(f32, out_numel);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);

    for (0..outer) |outer_idx| {
        for (0..inner) |inner_idx| {
            const base = outer_idx * axis_dim * inner + inner_idx;
            var best_idx: usize = 0;
            var best_val = in_data[base];
            for (1..axis_dim) |axis_idx| {
                const candidate = in_data[base + axis_idx * inner];
                if (candidate > best_val) {
                    best_val = candidate;
                    best_idx = axis_idx;
                }
            }
            output[outer_idx * inner + inner_idx] = @floatFromInt(best_idx);
        }
    }

    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    var out_shape_buf: [8]i64 = undefined;
    var out_rank: usize = 0;
    if (keepdims) {
        out_rank = rank;
        for (0..rank) |i| out_shape_buf[i] = if (i == axis) 1 else resolved_input_shape[i];
    } else {
        for (0..rank) |i| {
            if (i == axis) continue;
            out_shape_buf[out_rank] = resolved_input_shape[i];
            out_rank += 1;
        }
    }
    return self.withLogicalShape(result, out_shape_buf[0..out_rank]);
}

fn primReduceOp(self: *NativeCompute, input: CT, axes: []const u8, input_shape: []const i64, mode: enum { sum, max, mean }) anyerror!CT {
    const buf = toBuf(input);
    var materialized_input: ?[]f32 = null;
    defer if (materialized_input) |owned| self.allocator.free(owned);

    const in_data = blk: {
        if (buf.data.len != 0) break :blk getData(input);
        if (buf.source_tensor != null or buf.quantized_storage != null or buf.lazy_entry != null) {
            const dense = try toFloat32Op(self, input, self.allocator);
            materialized_input = dense;
            break :blk dense;
        }
        break :blk getData(input);
    };
    const effective_input_shape = storedOrDeclaredShape(input, input_shape);
    var resolved_input_shape_buf: [8]i64 = undefined;
    const resolved_input_shape = if (resolveShapeFromDataLen(effective_input_shape, in_data.len)) |resolved| blk: {
        resolved_input_shape_buf = resolved;
        break :blk resolved_input_shape_buf[0..effective_input_shape.len];
    } else blk: {
        for (0..effective_input_shape.len) |i| {
            resolved_input_shape_buf[i] = if (effective_input_shape[i] > 0) effective_input_shape[i] else 1;
        }
        break :blk resolved_input_shape_buf[0..effective_input_shape.len];
    };
    const rank = resolved_input_shape.len;

    // Compute output shape with keepdims semantics.
    var out_shape_buf: [8]i64 = resolved_input_shape_buf;
    var is_reduced = [_]bool{false} ** 8;
    for (axes) |ax| is_reduced[ax] = true;
    for (0..rank) |d| {
        out_shape_buf[d] = if (is_reduced[d]) 1 else resolved_input_shape[d];
    }
    const out_numel = if (rank == 0) @as(usize, 1) else shapeNumel(out_shape_buf[0..rank]);

    const output = try self.allocator.alloc(f32, out_numel);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    switch (mode) {
        .sum, .mean => @memset(output, 0.0),
        .max => @memset(output, -std.math.inf(f32)),
    }

    // Compute input strides.
    var in_strides: [8]usize = undefined;
    computeStrides(resolved_input_shape, in_strides[0..rank]);
    var out_strides: [8]usize = undefined;
    if (rank > 0) computeStrides(out_shape_buf[0..rank], out_strides[0..rank]);

    // For each input element, compute its output index by dropping reduced dims.
    const in_numel = shapeNumel(resolved_input_shape);
    for (0..in_numel) |flat_in| {
        // Decompose flat index into multi-index.
        var remaining = flat_in;

        // Compute output flat index by zeroing reduced dims.
        var out_flat: usize = 0;
        for (0..rank) |d| {
            const coord = remaining / in_strides[d];
            remaining %= in_strides[d];
            const out_coord = if (is_reduced[d]) @as(usize, 0) else coord;
            out_flat += out_coord * out_strides[d];
        }

        switch (mode) {
            .sum, .mean => output[out_flat] += in_data[flat_in],
            .max => output[out_flat] = @max(output[out_flat], in_data[flat_in]),
        }
    }

    if (mode == .mean) {
        var reduce_count: usize = 1;
        for (axes) |ax| reduce_count *= @as(usize, @intCast(resolved_input_shape[ax]));
        const scale: f32 = 1.0 / @as(f32, @floatFromInt(reduce_count));
        for (output) |*v| v.* *= scale;
    }

    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    return self.withLogicalShape(result, out_shape_buf[0..rank]);
}

fn primReshapeOp(ctx: *anyopaque, input: CT, new_shape: []const i64) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const in_data = getData(input);
    if (tensorStoredShape(input)) |shape| {
        if (inferReshapeShapeWithNumel(shape, new_shape, in_data.len)) |resolved| {
            return aliasDenseBufWithShape(self, input, resolved[0..new_shape.len]) catch blk: {
                const in_view = try denseWeightView(self, input);
                defer if (in_view.owned) |owned| self.allocator.free(owned);
                const output = try self.allocator.dupe(f32, in_view.data);
                const result = try self.makeOwnedBuf(output);
                errdefer freeTensor(self, result);
                break :blk self.withLogicalShape(result, resolved[0..new_shape.len]);
            };
        }
    }
    if (tensorShapeOp(ctx, input, self.allocator)) |runtime_shape| {
        defer self.allocator.free(runtime_shape);
        if (inferReshapeShapeWithNumel(runtime_shape, new_shape, in_data.len)) |resolved| {
            return aliasDenseBufWithShape(self, input, resolved[0..new_shape.len]) catch blk: {
                const in_view = try denseWeightView(self, input);
                defer if (in_view.owned) |owned| self.allocator.free(owned);
                const output = try self.allocator.dupe(f32, in_view.data);
                const result = try self.makeOwnedBuf(output);
                errdefer freeTensor(self, result);
                break :blk self.withLogicalShape(result, resolved[0..new_shape.len]);
            };
        }
    } else |_| {}
    if (resolveShapeFromDataLen(new_shape, in_data.len)) |resolved| {
        return aliasDenseBufWithShape(self, input, resolved[0..new_shape.len]) catch blk: {
            const dense_view = try denseWeightView(self, input);
            defer if (dense_view.owned) |owned| self.allocator.free(owned);
            const output = try self.allocator.dupe(f32, dense_view.data);
            const result = try self.makeOwnedBuf(output);
            errdefer freeTensor(self, result);
            break :blk self.withLogicalShape(result, resolved[0..new_shape.len]);
        };
    }
    const stored_input_shape = tensorStoredShape(input);
    var symbolic_shape: [8]i64 = undefined;
    for (new_shape, 0..) |dim, i| {
        if (dim != 0) {
            symbolic_shape[i] = dim;
            continue;
        }
        if (stored_input_shape) |shape| {
            if (i < shape.len and shape[i] > 0) {
                symbolic_shape[i] = shape[i];
                continue;
            }
        }
        symbolic_shape[i] = -1;
    }
    return aliasDenseBufWithShape(self, input, symbolic_shape[0..new_shape.len]) catch blk: {
        const dense_view = try denseWeightView(self, input);
        defer if (dense_view.owned) |owned| self.allocator.free(owned);
        const output = try self.allocator.dupe(f32, dense_view.data);
        const result = try self.makeOwnedBuf(output);
        errdefer freeTensor(self, result);
        break :blk self.withLogicalShape(result, symbolic_shape[0..new_shape.len]);
    };
}

fn primTransposeOp(ctx: *anyopaque, input: CT, perm: []const u8, input_shape: []const i64) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const input_buf = toBuf(input);
    const effective_input_shape = storedOrDeclaredShape(input, input_shape);
    var resolved_shape_buf: [8]i64 = undefined;
    var resolved_perm_buf: [8]u8 = undefined;
    var should_attach_shape = true;
    const resolved_shape: []const i64, const resolved_perm: []const u8, const rank: usize = blk: {
        if (safeShapeNumel(effective_input_shape)) |numel| {
            _ = numel;
            break :blk .{ effective_input_shape, perm, effective_input_shape.len };
        }
        if (resolveShapeFromDataLen(effective_input_shape, input_buf.data.len)) |resolved| {
            for (0..effective_input_shape.len) |i| resolved_shape_buf[i] = resolved[i];
            break :blk .{ resolved_shape_buf[0..effective_input_shape.len], perm, effective_input_shape.len };
        }
        const plan = collapseLeadingDynamicDimsForTranspose(effective_input_shape, perm, input_buf.data.len) orelse {
            std.log.warn("transpose symbolic shape unsupported shape={any} perm={any} len={d}", .{
                effective_input_shape,
                perm,
                input_buf.data.len,
            });
            return error.UnsupportedShape;
        };
        should_attach_shape = false;
        for (0..plan.rank) |i| {
            resolved_shape_buf[i] = plan.shape[i];
            resolved_perm_buf[i] = plan.perm[i];
        }
        break :blk .{ resolved_shape_buf[0..plan.rank], resolved_perm_buf[0..plan.rank], plan.rank };
    };
    // Compute output shape and strides.
    var out_shape: [8]i64 = undefined;
    for (0..rank) |d| out_shape[d] = resolved_shape[resolved_perm[d]];
    const numel = if (safeShapeNumel(out_shape[0..rank])) |resolved_numel| resolved_numel else input_buf.data.len;

    var in_strides: [8]usize = undefined;
    const logical_in_strides = logicalStridesOrContiguous(input, resolved_shape, in_strides[0..rank]);
    var out_strides: [8]usize = undefined;
    computeStrides(out_shape[0..rank], out_strides[0..rank]);

    if (canAliasTranspose(resolved_shape, resolved_perm)) {
        const result = try aliasDenseBufWithShape(self, input, out_shape[0..rank]);
        if (!should_attach_shape) return result;
        return result;
    }

    var view_strides: [8]usize = undefined;
    for (0..rank) |d| view_strides[d] = logical_in_strides[resolved_perm[d]];
    if (makeDenseViewAlias(self, input, out_shape[0..rank], view_strides[0..rank], 0)) |view| {
        if (!should_attach_shape) return view;
        return view;
    } else |_| {}

    const in_view = try denseWeightView(self, input);
    defer if (in_view.owned) |owned| self.allocator.free(owned);
    const in_data = in_view.data;
    const output = try self.allocator.alloc(f32, numel);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    for (0..numel) |flat_out| {
        // Decompose output flat index.
        var remaining = flat_out;
        var flat_in: usize = 0;
        for (0..rank) |d| {
            const coord = remaining / out_strides[d];
            remaining %= out_strides[d];
            flat_in += coord * logical_in_strides[resolved_perm[d]];
        }
        output[flat_out] = in_data[flat_in];
    }
    const result = try self.makeBuf(output, true);
    raw_output = null;
    if (!should_attach_shape) return result;
    errdefer freeTensor(self, result);
    return self.withLogicalShape(result, out_shape[0..rank]);
}

fn primBroadcastInDimOp(ctx: *anyopaque, input: CT, target_shape: []const i64, broadcast_axes: []const u8, input_shape: []const i64) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const input_buf = toBuf(input);
    const out_rank = target_shape.len;
    const effective_input_shape = storedOrDeclaredShape(input, input_shape);
    const in_rank = effective_input_shape.len;
    const axis_count = @min(broadcast_axes.len, in_rank);
    var resolved_input_shape_buf: [8]i64 = undefined;
    const resolved_input_shape = if (resolveShapeFromDataLen(effective_input_shape, input_buf.data.len)) |resolved| blk: {
        resolved_input_shape_buf = resolved;
        break :blk resolved_input_shape_buf[0..in_rank];
    } else blk: {
        for (0..in_rank) |i| {
            resolved_input_shape_buf[i] = if (effective_input_shape[i] > 0) effective_input_shape[i] else 1;
        }
        break :blk resolved_input_shape_buf[0..in_rank];
    };
    var resolved_target_shape: [8]i64 = undefined;
    for (0..out_rank) |d| {
        var resolved_dim = target_shape[d];
        if (resolved_dim <= 0) {
            for (broadcast_axes[0..axis_count], 0..) |ax, in_d| {
                if (ax == d and resolved_input_shape[in_d] >= 0) {
                    resolved_dim = resolved_input_shape[in_d];
                    break;
                }
            }
        }
        if (resolved_dim <= 0) resolved_dim = 1;
        resolved_target_shape[d] = resolved_dim;
    }
    const out_numel = shapeNumel(resolved_target_shape[0..out_rank]);
    if (axis_count == in_rank and out_numel == shapeNumel(resolved_input_shape)) {
        var can_alias = true;
        for (0..out_rank) |d| {
            var mapped_input_dim: ?usize = null;
            for (broadcast_axes[0..axis_count], 0..) |ax, in_d| {
                if (ax == d) {
                    mapped_input_dim = in_d;
                    break;
                }
            }
            if (mapped_input_dim) |in_d| {
                if (resolved_target_shape[d] != resolved_input_shape[in_d]) {
                    can_alias = false;
                    break;
                }
            } else if (resolved_target_shape[d] != 1) {
                can_alias = false;
                break;
            }
        }
        if (can_alias) {
            if (aliasDenseBufWithShape(self, input, resolved_target_shape[0..out_rank])) |aliased| {
                return aliased;
            } else |_| {}
        }
    }
    if (axis_count == 0) {
        if (input_buf.data.len > 0) {
            const in_data = getData(input);
            const output = try self.allocator.alloc(f32, out_numel);
            var raw_output: ?[]f32 = output;
            errdefer if (raw_output) |raw| self.allocator.free(raw);
            @memset(output, in_data[0]);
            const result = try self.makeBuf(output, true);
            raw_output = null;
            errdefer freeTensor(self, result);
            return self.withLogicalShape(result, resolved_target_shape[0..out_rank]);
        }
        return error.UnsupportedShape;
    }

    var out_strides: [8]usize = undefined;
    computeStrides(resolved_target_shape[0..out_rank], out_strides[0..out_rank]);

    // Build input strides in the output coordinate system.
    var in_strides: [8]usize = undefined;
    const logical_in_strides = logicalStridesOrContiguous(input, resolved_input_shape, in_strides[0..in_rank]);

    if (toBuf(input).lazy_entry == null and toBuf(input).quantized_storage == null and toBuf(input).source_tensor == null and toBuf(input).owned_quantized_storage == null and toBuf(input).owned_source_tensor == null) {
        var view_strides: [8]usize = undefined;
        var can_view = true;
        for (0..out_rank) |d| {
            view_strides[d] = 0;
            for (broadcast_axes[0..axis_count], 0..) |ax, in_d| {
                if (ax == d) {
                    if (resolved_input_shape[in_d] > 1 and resolved_input_shape[in_d] != resolved_target_shape[d]) {
                        can_view = false;
                    }
                    view_strides[d] = if (resolved_input_shape[in_d] > 1) logical_in_strides[in_d] else 0;
                    break;
                }
            }
        }
        if (can_view) {
            if (makeDenseViewAlias(self, input, resolved_target_shape[0..out_rank], view_strides[0..out_rank], 0)) |view| {
                return view;
            } else |_| {}
        }
    }

    const in_data = getData(input);
    const output = try self.allocator.alloc(f32, out_numel);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    for (0..out_numel) |flat_out| {
        var remaining = flat_out;
        var flat_in: usize = 0;
        for (0..out_rank) |d| {
            const coord = remaining / out_strides[d];
            remaining %= out_strides[d];
            // Check if this output dim corresponds to an input dim.
            for (broadcast_axes[0..axis_count], 0..) |ax, in_d| {
                if (ax == d) {
                    // If the input dim is 1, broadcast (coord stays 0).
                    if (resolved_input_shape[in_d] > 1) {
                        const input_extent = @as(usize, @intCast(resolved_input_shape[in_d]));
                        const target_extent = @as(usize, @intCast(resolved_target_shape[d]));
                        const input_coord = if (target_extent == input_extent)
                            coord
                        else if (target_extent > input_extent and target_extent % input_extent == 0)
                            coord % input_extent
                        else
                            return error.ShapeMismatch;
                        flat_in += input_coord * logical_in_strides[in_d];
                    }
                    break;
                }
            }
        }
        output[flat_out] = in_data[flat_in];
    }
    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    return self.withLogicalShape(result, resolved_target_shape[0..out_rank]);
}

fn primDotGeneralOp(ctx: *anyopaque, lhs: CT, rhs: CT, lhs_shape: []const i64, rhs_shape: []const i64, lhs_contracting: []const u8, rhs_contracting: []const u8, lhs_batch: []const u8, rhs_batch: []const u8) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const lhs_buf = toBuf(lhs);
    const lhs_len = tensorLogicalElementCount(lhs, lhs_shape) orelse lhs_buf.data.len;
    var rhs_resolved_shape_buf: [8]i64 = undefined;
    var rhs_effective_shape = storedOrDeclaredShape(rhs, rhs_shape);
    var lhs_resolved_shape_buf: [8]i64 = undefined;
    var lhs_effective_shape = storedOrDeclaredShape(lhs, lhs_shape);
    if (lhs_contracting.len == 1 and rhs_contracting.len == 1) {
        if (resolveDotOperandShapeFromPeer(
            lhs_len,
            lhs_shape,
            tensorStoredShape(lhs),
            rhs_effective_shape,
            lhs_contracting[0],
            lhs_batch,
            rhs_contracting[0],
            rhs_batch,
        )) |resolved| {
            lhs_resolved_shape_buf = resolved;
            lhs_effective_shape = lhs_resolved_shape_buf[0..lhs_shape.len];
        }

        const rhs_len = if (toBuf(rhs).source_tensor) |tensor| tensor.elementCount() else toBuf(rhs).data.len;
        if (resolveDotOperandShapeFromPeer(
            rhs_len,
            rhs_shape,
            tensorStoredShape(rhs),
            lhs_effective_shape,
            rhs_contracting[0],
            rhs_batch,
            lhs_contracting[0],
            lhs_batch,
        )) |resolved| {
            rhs_resolved_shape_buf = resolved;
            rhs_effective_shape = rhs_resolved_shape_buf[0..rhs_shape.len];
        }
    }

    // Handle common case: 2D matmul (no batch dims, one contracting dim each).
    if (lhs_batch.len == 0 and lhs_contracting.len == 1 and rhs_contracting.len == 1) {
        const lhs_rank = lhs_effective_shape.len;
        const rhs_rank = rhs_effective_shape.len;

        if (lhs_rank == 2 and rhs_rank == 2) {
            const lc = lhs_contracting[0];
            const rc = rhs_contracting[0];
            const k = positiveShapeDim(lhs_effective_shape, lc) catch try positiveShapeDim(rhs_effective_shape, rc);

            // Determine M, N based on which dims are contracting.
            const m = positiveShapeDim(lhs_effective_shape, 1 - lc) catch try resolveSymbolicDimFromElementCount(lhs_len, k);
            const rhs_buf = toBuf(rhs);
            const rhs_len = if (rhs_buf.source_tensor != null) 0 else rhs_buf.data.len;
            const n = positiveShapeDim(rhs_effective_shape, 1 - rc) catch try resolveSymbolicDimFromElementCount(rhs_len, k);

            const output = try self.allocator.alloc(f32, m * n);
            var raw_output: ?[]f32 = output;
            errdefer if (raw_output) |raw| self.allocator.free(raw);
            @memset(output, 0.0);

            if (lc == 1 and rc == 0) {
                if (lhs_buf.view_strides == null and rhs_buf.view_strides == null) {
                    const lhs_data = getData(lhs);
                    if (toBuf(rhs).source_tensor) |rhs_tensor| {
                        try matmulRhsSourceTensorChunked(self, lhs_data, rhs_tensor, output, m, k, n);
                        const result = try self.makeBuf(output, true);
                        raw_output = null;
                        errdefer freeTensor(self, result);
                        return self.withLogicalShape(result, &.{ @intCast(m), @intCast(n) });
                    }
                }
            }

            if (lhs_buf.view_strides == null and rhs_buf.view_strides == null and rhs_buf.source_tensor == null) {
                const lhs_data = getData(lhs);
                const rhs_dense = getData(rhs);
                // General 2D dot: C[i,j] = sum_k A[..] * B[..]
                for (0..m) |i| {
                    for (0..n) |j| {
                        var acc: f64 = 0.0;
                        for (0..k) |ki| {
                            const a_idx = if (lc == 1) i * k + ki else ki * m + i;
                            const b_idx = if (rc == 0) ki * n + j else j * k + ki;
                            acc += @as(f64, lhs_data[a_idx]) * @as(f64, rhs_dense[b_idx]);
                        }
                        output[i * n + j] = @floatCast(acc);
                    }
                }
                const result = try self.makeBuf(output, true);
                raw_output = null;
                errdefer freeTensor(self, result);
                const out_shape = [_]i64{ @intCast(m), @intCast(n) };
                return self.withLogicalShape(result, &out_shape);
            }

            const lhs_base = lhs_buf.data;
            const rhs_base = if (rhs_buf.source_tensor == null) rhs_buf.data else &.{};
            var lhs_stride_scratch: [8]usize = undefined;
            var rhs_stride_scratch: [8]usize = undefined;
            const lhs_strides = logicalStridesOrContiguous(lhs, lhs_effective_shape, lhs_stride_scratch[0..lhs_effective_shape.len]);
            const rhs_strides = if (rhs_buf.source_tensor == null) logicalStridesOrContiguous(rhs, rhs_effective_shape, rhs_stride_scratch[0..rhs_effective_shape.len]) else &.{};

            if (rhs_buf.source_tensor) |rhs_tensor| {
                const rhs_view = try tensorF32View(self, rhs_tensor);
                defer if (rhs_view.owned) |owned| self.allocator.free(owned);
                for (0..m) |i| {
                    for (0..n) |j| {
                        var acc: f64 = 0.0;
                        for (0..k) |ki| {
                            const lhs_val = rank2TensorRead(lhs_base, lhs_strides, 1 - lc, lc, i, ki);
                            const rhs_val = if (rc == 0) rhs_view.data[ki * n + j] else rhs_view.data[j * k + ki];
                            acc += @as(f64, lhs_val) * @as(f64, rhs_val);
                        }
                        output[i * n + j] = @floatCast(acc);
                    }
                }
            } else {
                for (0..m) |i| {
                    for (0..n) |j| {
                        var acc: f64 = 0.0;
                        for (0..k) |ki| {
                            const lhs_val = rank2TensorRead(lhs_base, lhs_strides, 1 - lc, lc, i, ki);
                            const rhs_val = rank2TensorRead(rhs_base, rhs_strides, rc, 1 - rc, ki, j);
                            acc += @as(f64, lhs_val) * @as(f64, rhs_val);
                        }
                        output[i * n + j] = @floatCast(acc);
                    }
                }
            }

            const result = try self.makeBuf(output, true);
            raw_output = null;
            errdefer freeTensor(self, result);
            const out_shape = [_]i64{ @intCast(m), @intCast(n) };
            return self.withLogicalShape(result, &out_shape);
        }
    }

    // Batched case: lhs_batch.len >= 1, 1 contracting dim.
    if (lhs_batch.len >= 1 and lhs_contracting.len == 1 and rhs_contracting.len == 1) {
        const lc = lhs_contracting[0];
        const rc = rhs_contracting[0];
        const k = positiveShapeDim(lhs_effective_shape, lc) catch try positiveShapeDim(rhs_effective_shape, rc);
        const lhs_has_batch = lhs_batch.len > 0;
        const rhs_has_batch = rhs_batch.len > 0;

        // Common ONNX linear case: lhs is rank>2 with batch attrs, rhs is a shared
        // rank-2 weight matrix. Flatten lhs leading rows and apply one GEMM.
        if (rhs_effective_shape.len == 2 and lc == lhs_effective_shape.len - 1 and rc == 0 and lhs_len % k == 0) {
            const rhs_k = positiveShapeDim(rhs_effective_shape, 0) catch return error.UnsupportedShape;
            const n = positiveShapeDim(rhs_effective_shape, 1) catch return error.UnsupportedShape;
            var effective_rows = lhs_len / k;
            var effective_k = k;
            var output_rank = lhs_effective_shape.len;
            var output_shape = copyShape(lhs_effective_shape);
            output_shape[output_rank - 1] = @intCast(n);
            if (lhs_shape.len == output_rank) {
                for (0..output_rank - 1) |i| {
                    if (lhs_shape[i] <= 0) output_shape[i] = lhs_shape[i];
                }
            }

            if (rhs_k != k and lhs_effective_shape.len >= 2 and lhs_len % rhs_k == 0) {
                var suffix_product: usize = 1;
                var suffix_start: ?usize = null;
                var idx = lhs_effective_shape.len;
                while (idx > 0) {
                    idx -= 1;
                    const dim = positiveShapeDim(lhs_effective_shape, idx) catch break;
                    suffix_product = std.math.mul(usize, suffix_product, dim) catch break;
                    if (suffix_product == rhs_k) {
                        suffix_start = idx;
                        break;
                    }
                    if (suffix_product > rhs_k) break;
                }
                if (suffix_start) |start| {
                    effective_k = rhs_k;
                    effective_rows = lhs_len / effective_k;
                    output_rank = start + 1;
                    for (0..start) |i| {
                        output_shape[i] = if (i < lhs_shape.len and lhs_shape[i] <= 0) lhs_shape[i] else lhs_effective_shape[i];
                    }
                    output_shape[start] = @intCast(n);
                }
            }

            const output = try self.allocator.alloc(f32, effective_rows * n);
            var raw_output: ?[]f32 = output;
            errdefer if (raw_output) |raw| self.allocator.free(raw);
            @memset(output, 0.0);
            const lhs_buf2 = toBuf(lhs);
            const rhs_buf2 = toBuf(rhs);
            if (lhs_buf2.view_strides == null and rhs_buf2.view_strides == null and rhs_buf2.source_tensor != null) {
                const lhs_data = getData(lhs);
                matmulRhsSourceTensorChunked(self, lhs_data, rhs_buf2.source_tensor.?, output, effective_rows, effective_k, n) catch |err| switch (err) {
                    error.ShapeMismatch => {
                        const rhs_view = try tensorF32View(self, rhs_buf2.source_tensor.?);
                        defer if (rhs_view.owned) |owned| self.allocator.free(owned);
                        if (rhs_buf2.source_tensor.?.shape.len != 2) return err;

                        const rhs_rows: usize = @intCast(rhs_buf2.source_tensor.?.shape[0]);
                        const rhs_cols: usize = @intCast(rhs_buf2.source_tensor.?.shape[1]);
                        if (rhs_rows == n and rhs_cols == effective_k and rhs_view.data.len == n * effective_k) {
                            try self.dispatchSgemmTransB(effective_rows, n, effective_k, 1.0, lhs_data, rhs_view.data, 0.0, output);
                        } else if (rhs_rows == effective_k and rhs_cols == n and rhs_view.data.len == effective_k * n) {
                            try self.dispatchSgemm(effective_rows, n, effective_k, 1.0, lhs_data, rhs_view.data, 0.0, output);
                        } else {
                            return err;
                        }
                    },
                    else => return err,
                };
            } else if (lhs_buf2.view_strides == null and rhs_buf2.view_strides == null) {
                const lhs_data = getData(lhs);
                const rhs_data = getData(rhs);
                if (rhs_data.len != effective_k * n) return error.UnsupportedShape;
                try self.dispatchSgemm(effective_rows, n, effective_k, 1.0, lhs_data, rhs_data, 0.0, output);
            } else {
                var lhs_stride_scratch: [8]usize = undefined;
                const lhs_strides = logicalStridesOrContiguous(lhs, lhs_effective_shape, lhs_stride_scratch[0..lhs_effective_shape.len]);
                if (rhs_buf2.source_tensor) |rhs_tensor| {
                    const rhs_view = try tensorF32View(self, rhs_tensor);
                    defer if (rhs_view.owned) |owned| self.allocator.free(owned);
                    for (0..effective_rows) |row| {
                        for (0..n) |col| {
                            var acc: f64 = 0.0;
                            for (0..effective_k) |ki| {
                                const lhs_val = try flattenedPrefixLastDimRead(lhs_effective_shape, lhs_strides, lhs_buf2.data, row, ki);
                                acc += @as(f64, lhs_val) * @as(f64, rhs_view.data[ki * n + col]);
                            }
                            output[row * n + col] = @floatCast(acc);
                        }
                    }
                } else {
                    const rhs_data = getData(rhs);
                    for (0..effective_rows) |row| {
                        for (0..n) |col| {
                            var acc: f64 = 0.0;
                            for (0..effective_k) |ki| {
                                const lhs_val = try flattenedPrefixLastDimRead(lhs_effective_shape, lhs_strides, lhs_buf2.data, row, ki);
                                acc += @as(f64, lhs_val) * @as(f64, rhs_data[ki * n + col]);
                            }
                            output[row * n + col] = @floatCast(acc);
                        }
                    }
                }
            }
            const result = try self.makeBuf(output, true);
            raw_output = null;
            errdefer freeTensor(self, result);
            return self.withLogicalShape(result, output_shape[0..output_rank]);
        }

        const rhs_buf2 = toBuf(rhs);
        const rhs_view = if (rhs_buf2.view_strides != null or rhs_buf2.source_tensor != null) try denseWeightView(self, rhs) else null;
        defer if (rhs_view) |view| if (view.owned) |owned| self.allocator.free(owned);
        const rhs_raw_data = if (rhs_view) |view| view.data else rhs_buf2.data;

        // Find the non-batch, non-contracting dims.
        var lhs_free: ?usize = null;
        var lhs_free_axis: ?u8 = null;
        for (0..lhs_effective_shape.len) |d| {
            var is_batch = false;
            for (lhs_batch) |bd| {
                if (bd == d) {
                    is_batch = true;
                    break;
                }
            }
            if (!is_batch and d != lc) {
                lhs_free = positiveShapeDim(lhs_effective_shape, d) catch null;
                lhs_free_axis = @intCast(d);
                break;
            }
        }
        var rhs_free: ?usize = null;
        var rhs_free_axis: ?u8 = null;
        for (0..rhs_effective_shape.len) |d| {
            var is_batch = false;
            for (rhs_batch) |bd| {
                if (bd == d) {
                    is_batch = true;
                    break;
                }
            }
            if (!is_batch and d != rc) {
                rhs_free = positiveShapeDim(rhs_effective_shape, d) catch null;
                rhs_free_axis = @intCast(d);
                break;
            }
        }

        var lhs_batch_shape_buf: [8]i64 = undefined;
        var rhs_batch_shape_buf: [8]i64 = undefined;
        var out_batch_shape_buf: [8]i64 = undefined;
        const lhs_batch_shape = blk: {
            for (lhs_batch, 0..) |bd, i| lhs_batch_shape_buf[i] = lhs_effective_shape[bd];
            break :blk lhs_batch_shape_buf[0..lhs_batch.len];
        };
        const rhs_batch_shape = blk: {
            for (rhs_batch, 0..) |bd, i| rhs_batch_shape_buf[i] = rhs_effective_shape[bd];
            break :blk rhs_batch_shape_buf[0..rhs_batch.len];
        };
        const symbolic_batch_dims =
            (lhs_has_batch and !allShapeDimsPositive(lhs_batch_shape)) or
            (rhs_has_batch and !allShapeDimsPositive(rhs_batch_shape));
        var flattened_batch_broadcast = false;
        const out_batch_shape = blk: {
            if (symbolic_batch_dims) break :blk &.{};
            if (lhs_has_batch and rhs_has_batch) {
                if (lhs_batch_shape.len != rhs_batch_shape.len) return error.UnsupportedShape;
                const lhs_batch_numel = safeShapeNumel(lhs_batch_shape) orelse return error.UnsupportedShape;
                const rhs_batch_numel = safeShapeNumel(rhs_batch_shape) orelse return error.UnsupportedShape;
                for (lhs_batch_shape, rhs_batch_shape, 0..) |ld, rd, i| {
                    if (ld == rd or ld == 1) {
                        out_batch_shape_buf[i] = rd;
                    } else if (rd == 1) {
                        out_batch_shape_buf[i] = ld;
                    } else if (lhs_batch_numel > rhs_batch_numel and lhs_batch_numel % rhs_batch_numel == 0) {
                        flattened_batch_broadcast = true;
                        for (lhs_batch_shape, 0..) |dim, j| out_batch_shape_buf[j] = dim;
                        break :blk out_batch_shape_buf[0..lhs_batch_shape.len];
                    } else if (rhs_batch_numel > lhs_batch_numel and rhs_batch_numel % lhs_batch_numel == 0) {
                        flattened_batch_broadcast = true;
                        for (rhs_batch_shape, 0..) |dim, j| out_batch_shape_buf[j] = dim;
                        break :blk out_batch_shape_buf[0..rhs_batch_shape.len];
                    } else {
                        return error.UnsupportedShape;
                    }
                }
                break :blk out_batch_shape_buf[0..lhs_batch_shape.len];
            }
            if (lhs_has_batch) {
                for (lhs_batch_shape, 0..) |dim, i| {
                    if (dim <= 0) return error.UnsupportedShape;
                    out_batch_shape_buf[i] = dim;
                }
                break :blk out_batch_shape_buf[0..lhs_batch_shape.len];
            }
            for (rhs_batch_shape, 0..) |dim, i| {
                if (dim <= 0) return error.UnsupportedShape;
                out_batch_shape_buf[i] = dim;
            }
            break :blk out_batch_shape_buf[0..rhs_batch_shape.len];
        };

        const lhs_symbolic_batch_factor: ?usize = blk: {
            if (!lhs_has_batch) break :blk 1;
            if (allShapeDimsPositive(lhs_batch_shape)) break :blk safeShapeNumel(lhs_batch_shape) orelse return error.UnsupportedShape;
            if (rhs_has_batch and rhs_batch_shape.len == lhs_batch_shape.len and allShapeDimsPositive(rhs_batch_shape)) {
                break :blk safeShapeNumel(rhs_batch_shape) orelse return error.UnsupportedShape;
            }
            break :blk null;
        };
        const rhs_symbolic_batch_factor: ?usize = blk: {
            if (!rhs_has_batch) break :blk 1;
            if (allShapeDimsPositive(rhs_batch_shape)) break :blk safeShapeNumel(rhs_batch_shape) orelse return error.UnsupportedShape;
            if (lhs_has_batch and lhs_batch_shape.len == rhs_batch_shape.len and allShapeDimsPositive(lhs_batch_shape)) {
                break :blk safeShapeNumel(lhs_batch_shape) orelse return error.UnsupportedShape;
            }
            break :blk null;
        };

        if (symbolic_batch_dims and
            ((lhs_has_batch and lhs_free == null and lhs_symbolic_batch_factor == null) or
                (rhs_has_batch and rhs_free == null and rhs_symbolic_batch_factor == null)))
        {
            std.log.warn("dot_general symbolic batch/free ambiguity lhs_shape={any} rhs_shape={any} lhs_len={d} rhs_len={d} lhs_batch={any} rhs_batch={any} lc={d} rc={d}", .{
                lhs_effective_shape,
                rhs_effective_shape,
                lhs_len,
                rhs_raw_data.len,
                lhs_batch,
                rhs_batch,
                lc,
                rc,
            });
            return error.UnsupportedShape;
        }

        const m = lhs_free orelse try resolveSymbolicDimFromElementCount(
            lhs_len,
            (if (lhs_has_batch and !symbolic_batch_dims)
                safeShapeNumel(lhs_batch_shape) orelse return error.UnsupportedShape
            else if (lhs_symbolic_batch_factor) |factor|
                factor
            else
                1) * k,
        );
        const n = rhs_free orelse try resolveSymbolicDimFromElementCount(
            rhs_raw_data.len,
            (if (rhs_has_batch and !symbolic_batch_dims)
                safeShapeNumel(rhs_batch_shape) orelse return error.UnsupportedShape
            else if (rhs_symbolic_batch_factor) |factor|
                factor
            else
                1) * k,
        );
        var lhs_batch_elems = blk: {
            if (!lhs_has_batch) break :blk 1;
            if (!symbolic_batch_dims) break :blk safeShapeNumel(lhs_batch_shape) orelse return error.UnsupportedShape;
            if (lhs_free != null) break :blk resolveSymbolicDimFromElementCount(lhs_len, m * k) catch if (lhs_symbolic_batch_factor) |factor| factor else return error.UnsupportedShape;
            if (lhs_symbolic_batch_factor) |factor| break :blk factor;
            break :blk resolveSymbolicDimFromElementCount(lhs_len, m * k) catch return error.UnsupportedShape;
        };
        var rhs_batch_elems = blk: {
            if (!rhs_has_batch) break :blk 1;
            if (!symbolic_batch_dims) break :blk safeShapeNumel(rhs_batch_shape) orelse return error.UnsupportedShape;
            if (rhs_free != null) break :blk resolveSymbolicDimFromElementCount(rhs_raw_data.len, k * n) catch if (rhs_symbolic_batch_factor) |factor| factor else return error.UnsupportedShape;
            if (rhs_symbolic_batch_factor) |factor| break :blk factor;
            break :blk resolveSymbolicDimFromElementCount(rhs_raw_data.len, k * n) catch return error.UnsupportedShape;
        };
        const lhs_buf2 = toBuf(lhs);
        const lhs_view = if (lhs_buf2.view_strides != null or lhs_buf2.source_tensor != null) try denseWeightView(self, lhs) else null;
        defer if (lhs_view) |view| if (view.owned) |owned| self.allocator.free(owned);
        const lhs_data = if (lhs_view) |view| view.data else lhs_buf2.data;
        var effective_rhs_raw_data = rhs_raw_data;
        if (symbolic_batch_dims and lhs_batch_elems != rhs_batch_elems) {
            const lhs_expected_rhs_len = lhs_batch_elems * k * n;
            if (lhs_expected_rhs_len > 0 and rhs_raw_data.len % lhs_expected_rhs_len == 0 and allRepeatedBlocksEqual(rhs_raw_data, lhs_expected_rhs_len)) {
                effective_rhs_raw_data = rhs_raw_data[0..lhs_expected_rhs_len];
                rhs_batch_elems = lhs_batch_elems;
            }
            const rhs_expected_lhs_len = rhs_batch_elems * m * k;
            if (rhs_expected_lhs_len > 0 and lhs_data.len % rhs_expected_lhs_len == 0 and allRepeatedBlocksEqual(lhs_data, rhs_expected_lhs_len)) {
                lhs_batch_elems = rhs_batch_elems;
            }
        }
        const batch_size = blk: {
            if (!symbolic_batch_dims) {
                break :blk if (out_batch_shape.len > 0)
                    safeShapeNumel(out_batch_shape) orelse return error.UnsupportedShape
                else
                    1;
            }
            if (lhs_batch_elems == rhs_batch_elems) break :blk lhs_batch_elems;
            if (lhs_batch_elems == 1) break :blk rhs_batch_elems;
            if (rhs_batch_elems == 1) break :blk lhs_batch_elems;
            if (lhs_batch_elems > rhs_batch_elems and lhs_batch_elems % rhs_batch_elems == 0) break :blk lhs_batch_elems;
            if (rhs_batch_elems > lhs_batch_elems and rhs_batch_elems % lhs_batch_elems == 0) break :blk rhs_batch_elems;
            return error.UnsupportedShape;
        };
        const expected_lhs_len = lhs_batch_elems * m * k;
        const expected_rhs_len = rhs_batch_elems * k * n;
        const rhs_data = blk: {
            if (effective_rhs_raw_data.len == expected_rhs_len) break :blk effective_rhs_raw_data;
            if (expected_rhs_len > 0 and effective_rhs_raw_data.len % expected_rhs_len == 0 and rhs_effective_shape.len > 0 and rhs_effective_shape[0] == 1) {
                if (allRepeatedBlocksEqual(effective_rhs_raw_data, expected_rhs_len)) {
                    break :blk effective_rhs_raw_data[0..expected_rhs_len];
                }
            }
            break :blk effective_rhs_raw_data;
        };
        if (lhs_data.len != expected_lhs_len) {
            std.log.warn("dot_general lhs size mismatch lhs_shape={any} rhs_shape={any} lhs_len={d} rhs_len={d} expected_lhs={d} expected_rhs={d} batch_size={d} m={d} n={d} k={d} lhs_free={?d} rhs_free={?d} lhs_batch={any} rhs_batch={any}", .{
                lhs_effective_shape,
                rhs_effective_shape,
                lhs_data.len,
                rhs_raw_data.len,
                expected_lhs_len,
                expected_rhs_len,
                batch_size,
                m,
                n,
                k,
                lhs_free,
                rhs_free,
                lhs_batch,
                rhs_batch,
            });
            return error.UnsupportedShape;
        }
        if (rhs_data.len != expected_rhs_len) {
            std.log.warn("dot_general rhs size mismatch lc={d} rc={d} lhs_shape={any} rhs_shape={any} lhs_declared={any} rhs_declared={any} lhs_stored={?any} rhs_stored={?any} lhs_len={d} rhs_len={d} expected_lhs={d} expected_rhs={d} batch_size={d} m={d} n={d} k={d} lhs_free={?d} rhs_free={?d} lhs_batch={any} rhs_batch={any}", .{
                lc,
                rc,
                lhs_effective_shape,
                rhs_effective_shape,
                lhs_shape,
                rhs_shape,
                tensorStoredShape(lhs),
                tensorStoredShape(rhs),
                lhs_data.len,
                rhs_raw_data.len,
                expected_lhs_len,
                expected_rhs_len,
                batch_size,
                m,
                n,
                k,
                lhs_free,
                rhs_free,
                lhs_batch,
                rhs_batch,
            });
            return error.UnsupportedShape;
        }
        const output_len = batch_size * m * n;
        maybeLogLargeTensor("dot_general", output_len, null);
        const output = try self.allocator.alloc(f32, output_len);
        var raw_output: ?[]f32 = output;
        errdefer if (raw_output) |raw| self.allocator.free(raw);
        @memset(output, 0.0);

        var out_batch_strides: [8]usize = undefined;
        if (!symbolic_batch_dims and out_batch_shape.len > 0) computeStrides(out_batch_shape, out_batch_strides[0..out_batch_shape.len]);
        var lhs_batch_strides: [8]usize = undefined;
        if (!symbolic_batch_dims and lhs_has_batch and lhs_batch_shape.len > 0) computeStrides(lhs_batch_shape, lhs_batch_strides[0..lhs_batch_shape.len]);
        var rhs_batch_strides: [8]usize = undefined;
        if (!symbolic_batch_dims and rhs_has_batch and rhs_batch_shape.len > 0) computeStrides(rhs_batch_shape, rhs_batch_strides[0..rhs_batch_shape.len]);
        if (symbolic_batch_dims or flattened_batch_broadcast or lhs_free_axis == null or rhs_free_axis == null or lhs_buf2.source_tensor != null or rhs_buf2.source_tensor != null) {
            for (0..batch_size) |b| {
                const lhs_batch_index = if (symbolic_batch_dims or flattened_batch_broadcast)
                    if (lhs_batch_elems == 1) 0 else b % lhs_batch_elems
                else if (lhs_has_batch and out_batch_shape.len > 0)
                    broadcastIndexForOutput(b, out_batch_shape, out_batch_strides[0..out_batch_shape.len], lhs_batch_shape, lhs_batch_strides[0..lhs_batch_shape.len])
                else
                    0;
                const rhs_batch_index = if (symbolic_batch_dims or flattened_batch_broadcast)
                    if (rhs_batch_elems == 1) 0 else b % rhs_batch_elems
                else if (rhs_has_batch and out_batch_shape.len > 0)
                    broadcastIndexForOutput(b, out_batch_shape, out_batch_strides[0..out_batch_shape.len], rhs_batch_shape, rhs_batch_strides[0..rhs_batch_shape.len])
                else
                    0;
                const lhs_off = if (lhs_has_batch) lhs_batch_index * m * k else 0;
                const rhs_off = if (rhs_has_batch) rhs_batch_index * k * n else 0;
                const out_off = b * m * n;
                try self.dispatchSgemm(m, n, k, 1.0, lhs_data[lhs_off..][0 .. m * k], rhs_data[rhs_off..][0 .. k * n], 0.0, output[out_off..][0 .. m * n]);
            }
        } else {
            var lhs_stride_scratch: [8]usize = undefined;
            var rhs_stride_scratch: [8]usize = undefined;
            const lhs_strides = logicalStridesOrContiguous(lhs, lhs_effective_shape, lhs_stride_scratch[0..lhs_effective_shape.len]);
            const rhs_strides = logicalStridesOrContiguous(rhs, rhs_effective_shape, rhs_stride_scratch[0..rhs_effective_shape.len]);

            for (0..batch_size) |b| {
                const lhs_batch_offset = if (lhs_has_batch and out_batch_shape.len > 0)
                    broadcastTensorOffsetForOutputBatch(
                        b,
                        out_batch_shape,
                        out_batch_strides[0..out_batch_shape.len],
                        lhs_batch_shape,
                        lhs_batch,
                        lhs_strides,
                    )
                else
                    0;
                const rhs_batch_offset = if (rhs_has_batch and out_batch_shape.len > 0)
                    broadcastTensorOffsetForOutputBatch(
                        b,
                        out_batch_shape,
                        out_batch_strides[0..out_batch_shape.len],
                        rhs_batch_shape,
                        rhs_batch,
                        rhs_strides,
                    )
                else
                    0;
                const out_off = b * m * n;
                for (0..m) |i| {
                    for (0..n) |j| {
                        var acc: f64 = 0.0;
                        for (0..k) |ki| {
                            const lhs_offset = lhs_batch_offset + i * lhs_strides[lhs_free_axis.?] + ki * lhs_strides[lc];
                            const rhs_offset = rhs_batch_offset + ki * rhs_strides[rc] + j * rhs_strides[rhs_free_axis.?];
                            if (lhs_offset >= lhs_data.len or rhs_offset >= rhs_data.len) return error.UnsupportedShape;
                            acc += @as(f64, lhs_data[lhs_offset]) * @as(f64, rhs_data[rhs_offset]);
                        }
                        output[out_off + i * n + j] = @floatCast(acc);
                    }
                }
            }
        }
        const result = try self.makeBuf(output, true);
        raw_output = null;
        errdefer freeTensor(self, result);
        var out_shape: [8]i64 = undefined;
        var out_rank: usize = 0;
        if (resolveDeclaredBatchShape(lhs_shape, lhs_batch, batch_size)) |resolved_batch| {
            for (resolved_batch[0..lhs_batch.len]) |dim| {
                out_shape[out_rank] = dim;
                out_rank += 1;
            }
        } else if (resolveDeclaredBatchShape(rhs_shape, rhs_batch, batch_size)) |resolved_batch| {
            for (resolved_batch[0..rhs_batch.len]) |dim| {
                out_shape[out_rank] = dim;
                out_rank += 1;
            }
        } else if (!symbolic_batch_dims) {
            for (out_batch_shape) |dim| {
                out_shape[out_rank] = dim;
                out_rank += 1;
            }
        } else if (lhs_has_batch and allShapeDimsPositive(lhs_batch_shape) and (safeShapeNumel(lhs_batch_shape) orelse 0) == batch_size) {
            for (lhs_batch_shape) |dim| {
                out_shape[out_rank] = dim;
                out_rank += 1;
            }
        } else if (rhs_has_batch and allShapeDimsPositive(rhs_batch_shape) and (safeShapeNumel(rhs_batch_shape) orelse 0) == batch_size) {
            for (rhs_batch_shape) |dim| {
                out_shape[out_rank] = dim;
                out_rank += 1;
            }
        } else if (lhs_batch.len == 1 or rhs_batch.len == 1) {
            out_shape[out_rank] = @intCast(batch_size);
            out_rank += 1;
        }
        out_shape[out_rank] = @intCast(m);
        out_rank += 1;
        out_shape[out_rank] = @intCast(n);
        out_rank += 1;

        var all_positive = true;
        var has_zero_dim = false;
        for (out_shape[0..out_rank]) |dim| {
            if (dim <= 0) {
                all_positive = false;
                if (dim == 0) has_zero_dim = true;
            }
        }
        if (all_positive) {
            return self.withLogicalShape(result, out_shape[0..out_rank]);
        }
        if (!has_zero_dim and out_rank > 0) {
            return self.withLogicalShape(result, out_shape[0..out_rank]);
        }
        return result;
    }

    return error.UnsupportedPrimitiveOp;
}

fn primScatterAddOp(ctx: *anyopaque, input: CT, indices: CT, input_shape: []const i64, indices_shape: []const i64, axis: u8) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const in_data = getData(input);
    const idx_data = getData(indices);
    _ = axis; // Currently only axis=0 supported for simple case.

    // Simple case: input is [N, D], indices is [N] (as f32-encoded ints).
    // Output rows come from indices_shape[0] (the graph's declared output dim),
    // falling back to max(indices)+1 if indices_shape is unavailable.
    if (input_shape.len == 2) {
        const n = @as(usize, @intCast(input_shape[0]));
        const d = @as(usize, @intCast(input_shape[1]));
        // Use indices_shape to determine output rows when available.
        const out_rows: usize = if (indices_shape.len > 0)
            @as(usize, @intCast(indices_shape[0]))
        else blk: {
            var max_idx: usize = 0;
            for (idx_data) |v| {
                const idx = @as(usize, @intFromFloat(v));
                if (idx > max_idx) max_idx = idx;
            }
            break :blk max_idx + 1;
        };
        const output = try self.allocator.alloc(f32, out_rows * d);
        errdefer self.allocator.free(output);
        @memset(output, 0.0);
        for (0..n) |i| {
            const row = @as(usize, @intFromFloat(idx_data[i]));
            if (row >= out_rows) return error.IndexOutOfBounds;
            for (0..d) |j| {
                output[row * d + j] += in_data[i * d + j];
            }
        }
        return self.makeBuf(output, true);
    }

    return error.UnsupportedPrimitiveOp;
}

fn primGatherOp(ctx: *anyopaque, input: CT, indices: CT, axis: u8, input_shape: []const i64) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const idx_data = getData(indices);
    const effective_input_shape = storedOrDeclaredShape(input, input_shape);
    const source_tensor = toBuf(input).source_tensor;
    const indices_shape = tensorStoredShape(indices);
    var resolved_input_shape_buf: [8]i64 = undefined;
    var resolved_indices_shape_buf: [8]i64 = undefined;
    var runtime_shape_owned: ?[]i64 = null;
    var runtime_indices_shape_owned: ?[]i64 = null;
    defer if (runtime_shape_owned) |shape| self.allocator.free(shape);
    defer if (runtime_indices_shape_owned) |shape| self.allocator.free(shape);
    const input_elem_count = if (source_tensor) |tensor| tensor.elementCount() else toBuf(input).data.len;
    var resolved_input_shape = if (resolveShapeFromDataLen(effective_input_shape, input_elem_count)) |resolved| blk: {
        resolved_input_shape_buf = resolved;
        break :blk resolved_input_shape_buf[0..effective_input_shape.len];
    } else effective_input_shape;
    var resolved_indices_shape = if (indices_shape) |shape|
        if (resolveShapeFromDataLen(shape, idx_data.len)) |resolved| blk: {
            resolved_indices_shape_buf = resolved;
            break :blk resolved_indices_shape_buf[0..shape.len];
        } else shape
    else
        null;

    for (resolved_input_shape) |dim| {
        if (dim > 0) continue;
        if (tensorShapeOp(ctx, input, self.allocator)) |runtime_shape| {
            runtime_shape_owned = runtime_shape;
            resolved_input_shape = if (resolveShapeFromDataLen(runtime_shape, input_elem_count)) |resolved| blk: {
                resolved_input_shape_buf = resolved;
                break :blk resolved_input_shape_buf[0..runtime_shape.len];
            } else runtime_shape;
        } else |_| {}
        break;
    }

    if (resolved_indices_shape) |shape| {
        for (shape) |dim| {
            if (dim > 0) continue;
            if (tensorShapeOp(ctx, indices, self.allocator)) |runtime_shape| {
                runtime_indices_shape_owned = runtime_shape;
                resolved_indices_shape = if (resolveShapeFromDataLen(runtime_shape, idx_data.len)) |resolved| blk: {
                    resolved_indices_shape_buf = resolved;
                    break :blk resolved_indices_shape_buf[0..runtime_shape.len];
                } else runtime_shape;
            } else |_| {}
            break;
        }
    }

    if (resolved_indices_shape) |idx_shape| {
        const axis_index = @as(usize, axis);
        const gather_nd_style = axis == 0 and idx_shape.len >= 1 and idx_shape[idx_shape.len - 1] > 1 and idx_shape[idx_shape.len - 1] <= effective_input_shape.len;
        if (axis_index < resolved_input_shape.len and source_tensor == null and idx_shape.len > 0 and !gather_nd_style) {
            const in_data = getData(input);

            var normalized_idx_shape_buf: [8]i64 = undefined;
            const normalized_idx_shape = blk: {
                if (idx_shape.len > 1 and idx_data.len == 1) {
                    var all_ones = true;
                    for (idx_shape) |dim| {
                        if (dim != 1) {
                            all_ones = false;
                            break;
                        }
                    }
                    if (all_ones) {
                        normalized_idx_shape_buf[0] = 1;
                        break :blk normalized_idx_shape_buf[0..1];
                    }
                }
                break :blk idx_shape;
            };

            var prefix_count: usize = 1;
            for (resolved_input_shape[0..axis_index]) |dim| {
                if (dim <= 0) return error.UnsupportedShape;
                prefix_count *= @as(usize, @intCast(dim));
            }

            const axis_extent_i64 = resolved_input_shape[axis_index];
            if (axis_extent_i64 <= 0) return error.UnsupportedShape;
            const axis_extent = @as(usize, @intCast(axis_extent_i64));

            var suffix_size: usize = 1;
            for (resolved_input_shape[axis_index + 1 ..]) |dim| {
                if (dim <= 0) return error.UnsupportedShape;
                suffix_size *= @as(usize, @intCast(dim));
            }

            const index_count = idx_data.len;
            const output = try self.allocator.alloc(f32, prefix_count * index_count * suffix_size);
            var raw_output: ?[]f32 = output;
            errdefer if (raw_output) |raw| self.allocator.free(raw);
            for (0..prefix_count) |prefix_idx| {
                for (0..index_count) |idx_pos| {
                    var gather_index = @as(i64, @intFromFloat(idx_data[idx_pos]));
                    if (gather_index < 0) gather_index += @as(i64, @intCast(axis_extent));
                    if (gather_index < 0 or gather_index >= axis_extent) return error.IndexOutOfBounds;
                    const gather_pos = @as(usize, @intCast(gather_index));
                    const src_offset = (prefix_idx * axis_extent + gather_pos) * suffix_size;
                    const dst_offset = (prefix_idx * index_count + idx_pos) * suffix_size;
                    if (src_offset + suffix_size > in_data.len or dst_offset + suffix_size > output.len) return error.ShapeMismatch;
                    @memcpy(output[dst_offset..][0..suffix_size], in_data[src_offset..][0..suffix_size]);
                }
            }

            var out_shape_buf: [8]i64 = undefined;
            var out_rank: usize = 0;
            for (resolved_input_shape[0..axis_index]) |dim| {
                out_shape_buf[out_rank] = dim;
                out_rank += 1;
            }
            for (normalized_idx_shape) |dim| {
                out_shape_buf[out_rank] = dim;
                out_rank += 1;
            }
            for (resolved_input_shape[axis_index + 1 ..]) |dim| {
                out_shape_buf[out_rank] = dim;
                out_rank += 1;
            }

            const result = try self.makeBuf(output, true);
            raw_output = null;
            errdefer freeTensor(self, result);
            return self.withLogicalShape(result, out_shape_buf[0..out_rank]);
        }
    }

    if (axis == 0) {
        if (resolved_indices_shape) |idx_shape| {
            if (idx_shape.len >= 1) {
                const index_depth = idx_shape[idx_shape.len - 1];
                if (index_depth > 1 and index_depth <= effective_input_shape.len) {
                    const in_data = getData(input);
                    if (source_tensor != null) {
                        std.log.warn("gather axis0 source-tensor gather_nd unsupported input_shape={any} effective_shape={any} indices_shape={?any} index_depth={d} axis={d}", .{
                            input_shape,
                            effective_input_shape,
                            indices_shape,
                            index_depth,
                            axis,
                        });
                        return error.UnsupportedPrimitiveOp;
                    }

                    const k = @as(usize, @intCast(index_depth));
                    var gather_shape_buf: [8]i64 = undefined;
                    @memcpy(gather_shape_buf[0..resolved_input_shape.len], resolved_input_shape);
                    var idx_prefix_count: usize = 1;
                    for (idx_shape[0 .. idx_shape.len - 1]) |dim| {
                        if (dim <= 0) return error.UnsupportedShape;
                        idx_prefix_count *= @as(usize, @intCast(dim));
                    }
                    if (idx_prefix_count * k > idx_data.len) return error.ShapeMismatch;

                    for (0..k) |coord_idx| {
                        if (gather_shape_buf[coord_idx] > 0) continue;
                        var max_coord: usize = 0;
                        for (0..idx_prefix_count) |prefix_idx| {
                            const coord = @as(usize, @intFromFloat(idx_data[prefix_idx * k + coord_idx]));
                            if (coord > max_coord) max_coord = coord;
                        }
                        gather_shape_buf[coord_idx] = @as(i64, @intCast(max_coord + 1));
                    }

                    var slice_size: usize = 1;
                    for (gather_shape_buf[k..resolved_input_shape.len]) |dim| {
                        if (dim <= 0) return error.UnsupportedShape;
                        slice_size *= @as(usize, @intCast(dim));
                    }

                    const output_len = idx_prefix_count * slice_size;
                    const output = try self.allocator.alloc(f32, output_len);
                    var raw_output: ?[]f32 = output;
                    errdefer if (raw_output) |raw| self.allocator.free(raw);

                    var coord_strides: [8]usize = undefined;
                    for (0..k) |dim_idx| {
                        var stride: usize = 1;
                        for ((dim_idx + 1)..k) |next_idx| {
                            const dim = gather_shape_buf[next_idx];
                            if (dim <= 0) return error.UnsupportedShape;
                            stride *= @as(usize, @intCast(dim));
                        }
                        coord_strides[dim_idx] = stride;
                    }

                    for (0..idx_prefix_count) |prefix_idx| {
                        var flat_index: usize = 0;
                        for (0..k) |coord_idx| {
                            const coord = @as(usize, @intFromFloat(idx_data[prefix_idx * k + coord_idx]));
                            const dim = @as(usize, @intCast(gather_shape_buf[coord_idx]));
                            if (coord >= dim) {
                                std.log.warn("gather_nd OOB coord_idx={d} coord={d} dim={d} data_shape={any} resolved={any} gather_shape={any} idx_shape={?any} prefix_idx={d} input_len={d}", .{
                                    coord_idx,
                                    coord,
                                    dim,
                                    effective_input_shape,
                                    resolved_input_shape,
                                    gather_shape_buf[0..resolved_input_shape.len],
                                    resolved_indices_shape,
                                    prefix_idx,
                                    in_data.len,
                                });
                                return error.IndexOutOfBounds;
                            }
                            flat_index += coord * coord_strides[coord_idx];
                        }
                        const src_offset = flat_index * slice_size;
                        const dst_offset = prefix_idx * slice_size;
                        if (src_offset + slice_size > in_data.len or dst_offset + slice_size > output.len) return error.ShapeMismatch;
                        @memcpy(output[dst_offset..][0..slice_size], in_data[src_offset..][0..slice_size]);
                    }

                    var out_shape_buf: [8]i64 = undefined;
                    var out_rank: usize = 0;
                    for (idx_shape[0 .. idx_shape.len - 1]) |dim| {
                        out_shape_buf[out_rank] = dim;
                        out_rank += 1;
                    }
                    for (gather_shape_buf[k..resolved_input_shape.len]) |dim| {
                        out_shape_buf[out_rank] = dim;
                        out_rank += 1;
                    }

                    const result = try self.makeBuf(output, true);
                    raw_output = null;
                    errdefer freeTensor(self, result);
                    return self.withLogicalShape(result, out_shape_buf[0..out_rank]);
                }
            }
        }
    }

    if ((indices_shape == null or indices_shape.?.len == 0) and idx_data.len == 1) {
        const axis_index = @as(usize, axis);
        if (axis_index >= resolved_input_shape.len) return error.UnsupportedShape;
        if (source_tensor != null) return error.UnsupportedPrimitiveOp;

        var prefix_count: usize = 1;
        for (resolved_input_shape[0..axis_index]) |dim| {
            if (dim <= 0) return error.UnsupportedShape;
            prefix_count *= @as(usize, @intCast(dim));
        }
        const axis_extent_i64 = resolved_input_shape[axis_index];
        if (axis_extent_i64 <= 0) return error.UnsupportedShape;
        const axis_extent = @as(usize, @intCast(axis_extent_i64));

        var suffix_size: usize = 1;
        for (resolved_input_shape[axis_index + 1 ..]) |dim| {
            if (dim <= 0) return error.UnsupportedShape;
            suffix_size *= @as(usize, @intCast(dim));
        }

        var gather_index = @as(i64, @intFromFloat(idx_data[0]));
        if (gather_index < 0) gather_index += @as(i64, @intCast(axis_extent));
        if (gather_index < 0 or gather_index >= axis_extent) return error.IndexOutOfBounds;
        const gather_pos = @as(usize, @intCast(gather_index));

        const in_data = getData(input);
        const output = try self.allocator.alloc(f32, prefix_count * suffix_size);
        var raw_output: ?[]f32 = output;
        errdefer if (raw_output) |raw| self.allocator.free(raw);
        for (0..prefix_count) |prefix_idx| {
            const src_offset = (prefix_idx * axis_extent + gather_pos) * suffix_size;
            const dst_offset = prefix_idx * suffix_size;
            if (src_offset + suffix_size > in_data.len or dst_offset + suffix_size > output.len) return error.ShapeMismatch;
            @memcpy(output[dst_offset..][0..suffix_size], in_data[src_offset..][0..suffix_size]);
        }

        var out_shape_buf: [8]i64 = undefined;
        var out_rank: usize = 0;
        for (resolved_input_shape, 0..) |dim, dim_idx| {
            if (dim_idx == axis_index) continue;
            out_shape_buf[out_rank] = dim;
            out_rank += 1;
        }

        const result = try self.makeBuf(output, true);
        raw_output = null;
        errdefer freeTensor(self, result);
        return self.withLogicalShape(result, out_shape_buf[0..out_rank]);
    }

    // Simple: input [M, D], indices [N] → output [N, D]
    if (effective_input_shape.len == 2) {
        const in_data = getData(input);
        const max_row = blk: {
            var max_idx: usize = 0;
            for (idx_data) |v| {
                const idx = @as(usize, @intFromFloat(v));
                if (idx > max_idx) max_idx = idx;
            }
            break :blk max_idx;
        };
        const inferred_layout = inferGather2DLayoutFromElementCount(input_elem_count, max_row);
        const d = positiveShapeDim(resolved_input_shape, 1) catch blk: {
            if (source_tensor) |tensor| {
                if (tensor.shape.len == 2 and tensor.shape[1] > 0) {
                    break :blk @as(usize, @intCast(tensor.shape[1]));
                }
            }
            if (inferred_layout) |layout| {
                break :blk layout.dim;
            }
            const rows = positiveShapeDim(resolved_input_shape, 0) catch {
                std.log.warn("gather unresolved 2d shape shape={any} resolved={any} data_len={d} elem_count={d} source_tensor={any} max_row={d}", .{
                    effective_input_shape,
                    resolved_input_shape,
                    in_data.len,
                    input_elem_count,
                    source_tensor != null,
                    max_row,
                });
                return error.UnsupportedShape;
            };
            if (rows == 0 or in_data.len % rows != 0) return error.UnsupportedShape;
            break :blk in_data.len / rows;
        };
        const n = idx_data.len;
        const output = try self.allocator.alloc(f32, n * d);
        var raw_output: ?[]f32 = output;
        errdefer if (raw_output) |raw| self.allocator.free(raw);
        var out_shape_buf: [8]i64 = .{0} ** 8;
        var out_rank: usize = 0;
        if (indices_shape) |idx_shape| {
            for (idx_shape) |dim| {
                out_shape_buf[out_rank] = dim;
                out_rank += 1;
            }
        } else {
            out_shape_buf[0] = @intCast(n);
            out_rank = 1;
        }
        out_shape_buf[out_rank] = @intCast(d);
        out_rank += 1;
        if (source_tensor) |tensor| {
            const rows = positiveShapeDim(resolved_input_shape, 0) catch blk_rows: {
                if (inferred_layout) |layout| {
                    break :blk_rows layout.rows;
                }
                if (tensor.shape.len == 2 and tensor.shape[0] > 0) {
                    break :blk_rows @as(usize, @intCast(tensor.shape[0]));
                }
                const elem_count = tensor.elementCount();
                if (elem_count == 0 or elem_count % d != 0) return error.UnsupportedShape;
                break :blk_rows elem_count / d;
            };
            for (0..n) |i| {
                var row_i64 = @as(i64, @intFromFloat(idx_data[i]));
                if (row_i64 < 0) row_i64 += @as(i64, @intCast(rows));
                if (row_i64 < 0) return error.IndexOutOfBounds;
                const row = @as(usize, @intCast(row_i64));
                if (row >= rows) {
                    std.log.warn("gather source_tensor OOB row={d} rows={d} d={d} input_shape={any} resolved={any} tensor_shape={any} idx_len={d} idx_sample={d:.3}", .{
                        row,
                        rows,
                        d,
                        effective_input_shape,
                        resolved_input_shape,
                        tensor.shape,
                        idx_data.len,
                        idx_data[i],
                    });
                    return error.IndexOutOfBounds;
                }
                try convertTensorRowsToF32(tensor, row, 1, d, output[i * d ..][0..d]);
            }
            const result = try self.makeBuf(output, true);
            raw_output = null;
            errdefer freeTensor(self, result);
            return self.withLogicalShape(result, out_shape_buf[0..out_rank]);
        }
        const rows = positiveShapeDim(resolved_input_shape, 0) catch blk_rows: {
            if (inferred_layout) |layout| {
                break :blk_rows layout.rows;
            }
            if (d == 0 or in_data.len % d != 0) return error.UnsupportedShape;
            break :blk_rows in_data.len / d;
        };
        for (0..n) |i| {
            var row_i64 = @as(i64, @intFromFloat(idx_data[i]));
            if (row_i64 < 0) row_i64 += @as(i64, @intCast(rows));
            if (row_i64 < 0) return error.IndexOutOfBounds;
            const row = @as(usize, @intCast(row_i64));
            if (row >= rows or (row + 1) * d > in_data.len) {
                std.log.warn("gather dense OOB row={d} rows={d} d={d} input_shape={any} resolved={any} in_len={d} idx_len={d} idx_sample={d:.3}", .{
                    row,
                    rows,
                    d,
                    effective_input_shape,
                    resolved_input_shape,
                    in_data.len,
                    idx_data.len,
                    idx_data[i],
                });
                return error.IndexOutOfBounds;
            }
            @memcpy(output[i * d ..][0..d], in_data[row * d ..][0..d]);
        }
        const result = try self.makeBuf(output, true);
        raw_output = null;
        errdefer freeTensor(self, result);
        return self.withLogicalShape(result, out_shape_buf[0..out_rank]);
    }

    std.log.warn("gather unsupported axis={d} input_shape={any} effective_shape={any} indices_shape={?any} source_tensor={any}", .{
        axis,
        input_shape,
        effective_input_shape,
        indices_shape,
        source_tensor != null,
    });
    return error.UnsupportedPrimitiveOp;
}

fn primSliceOp(ctx: *anyopaque, input: CT, starts: []const i64, limits: []const i64, strides: []const i64, input_shape: []const i64) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const in_data = getData(input);
    const rank = input_shape.len;
    if (rank > 8 or starts.len < rank or limits.len < rank or strides.len < rank) return error.UnsupportedShape;

    const effective_input_shape = storedOrDeclaredShape(input, input_shape);
    var full_range_passthrough = effective_input_shape.len == rank;
    if (full_range_passthrough) {
        for (0..rank) |d| {
            const dim = effective_input_shape[d];
            const limit = limits[d];
            const limit_covers_axis = if (limit < 0)
                true
            else if (dim > 0)
                limit >= dim
            else
                false;
            if (starts[d] != 0 or strides[d] != 1 or !limit_covers_axis) {
                full_range_passthrough = false;
                break;
            }
        }
    }
    if (full_range_passthrough) {
        return aliasDenseBufWithShape(self, input, effective_input_shape) catch blk: {
            const dense_view = try denseWeightView(self, input);
            defer if (dense_view.owned) |owned| self.allocator.free(owned);
            const output = try self.allocator.dupe(f32, dense_view.data);
            const result = try self.makeOwnedBuf(output);
            errdefer freeTensor(self, result);
            break :blk self.withLogicalShape(result, effective_input_shape);
        };
    }

    var resolved_input_shape_buf: [8]i64 = undefined;
    const resolved_input_shape = if (resolveShapeFromDataLen(effective_input_shape, in_data.len)) |resolved| blk: {
        resolved_input_shape_buf = resolved;
        break :blk resolved_input_shape_buf[0..rank];
    } else blk: {
        if (effective_input_shape.len != rank or !allShapeDimsPositive(effective_input_shape)) return error.UnsupportedShape;
        break :blk effective_input_shape;
    };

    // Compute output shape.
    var out_shape: [8]i64 = undefined;
    var out_numel: usize = 1;
    var normalized_starts: [8]usize = undefined;
    var normalized_strides: [8]usize = undefined;
    for (0..rank) |d| {
        const dim = resolved_input_shape[d];
        if (dim < 0 or strides[d] <= 0) return error.UnsupportedShape;
        var start = starts[d];
        var limit = limits[d];
        if (start < 0) start += dim;
        if (limit < 0) {
            limit = if (d < input_shape.len and input_shape[d] < 0 and start == 0 and strides[d] == 1)
                dim
            else
                limit + dim;
        }
        start = std.math.clamp(start, 0, dim);
        limit = std.math.clamp(limit, 0, dim);

        const size = if (limit <= start) 0 else @divTrunc(limit - start + strides[d] - 1, strides[d]);
        out_shape[d] = size;
        out_numel = std.math.mul(usize, out_numel, @as(usize, @intCast(size))) catch return error.UnsupportedShape;
        normalized_starts[d] = @intCast(start);
        normalized_strides[d] = @intCast(strides[d]);
    }
    var in_strides: [8]usize = undefined;
    computeStrides(resolved_input_shape, in_strides[0..rank]);
    var out_strides: [8]usize = undefined;
    computeStrides(out_shape[0..rank], out_strides[0..rank]);

    const output = try self.allocator.alloc(f32, out_numel);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    for (0..out_numel) |flat_out| {
        var remaining = flat_out;
        var flat_in: usize = 0;
        for (0..rank) |d| {
            const out_coord = remaining / out_strides[d];
            remaining %= out_strides[d];
            const in_coord = normalized_starts[d] + out_coord * normalized_strides[d];
            flat_in += in_coord * in_strides[d];
        }
        if (flat_in >= in_data.len) return error.ShapeMismatch;
        output[flat_out] = in_data[flat_in];
    }
    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    return self.withLogicalShape(result, out_shape[0..rank]);
}

fn primConcatPrimOp(ctx: *anyopaque, a: CT, b: CT, axis: u8, a_shape: []const i64, b_shape: []const i64) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const a_data = getData(a);
    const b_data = getData(b);
    const effective_a_shape = storedOrDeclaredShape(a, a_shape);
    const effective_b_shape = storedOrDeclaredShape(b, b_shape);
    var resolved_a_shape_buf: [8]i64 = undefined;
    var resolved_b_shape_buf: [8]i64 = undefined;
    const resolved_a_shape = if (resolveShapeFromTensorMetadata(a, effective_a_shape, a_data.len)) |resolved| blk: {
        resolved_a_shape_buf = resolved;
        break :blk resolved_a_shape_buf[0..effective_a_shape.len];
    } else if (resolveConcatShapeFromDataLen(effective_a_shape, axis, a_data.len)) |resolved| blk: {
        resolved_a_shape_buf = resolved;
        break :blk resolved_a_shape_buf[0..effective_a_shape.len];
    } else effective_a_shape;
    const resolved_b_shape = if (resolveShapeFromTensorMetadata(b, effective_b_shape, b_data.len)) |resolved| blk: {
        resolved_b_shape_buf = resolved;
        break :blk resolved_b_shape_buf[0..effective_b_shape.len];
    } else if (resolveConcatShapeFromDataLen(effective_b_shape, axis, b_data.len)) |resolved| blk: {
        resolved_b_shape_buf = resolved;
        break :blk resolved_b_shape_buf[0..effective_b_shape.len];
    } else effective_b_shape;
    const rank = resolved_a_shape.len;

    if (rank == 1 and axis == 0) {
        const out = try self.allocator.alloc(f32, a_data.len + b_data.len);
        var raw_output: ?[]f32 = out;
        errdefer if (raw_output) |raw| self.allocator.free(raw);
        @memcpy(out[0..a_data.len], a_data);
        @memcpy(out[a_data.len..][0..b_data.len], b_data);
        const result = try self.makeBuf(out, true);
        raw_output = null;
        errdefer freeTensor(self, result);
        const out_shape = [_]i64{@intCast(a_data.len + b_data.len)};
        return self.withLogicalShape(result, &out_shape);
    }

    // Compute output shape.
    var out_shape: [8]i64 = undefined;
    for (0..rank) |d| {
        if (d == axis) {
            out_shape[d] = resolved_a_shape[d] + resolved_b_shape[d];
        } else if (resolved_a_shape[d] == resolved_b_shape[d]) {
            out_shape[d] = resolved_a_shape[d];
        } else if (resolved_a_shape[d] == 1) {
            out_shape[d] = resolved_b_shape[d];
        } else if (resolved_b_shape[d] == 1) {
            out_shape[d] = resolved_a_shape[d];
        } else {
            out_shape[d] = resolved_a_shape[d];
        }
    }

    if (axis == 0) {
        const inner = if (rank > 1) safeShapeNumel(resolved_a_shape[1..]) orelse return error.UnsupportedShape else 1;
        if (inner == 0) return error.UnsupportedShape;
        if (a_data.len % inner != 0 or b_data.len % inner != 0) return error.UnsupportedShape;
        out_shape[0] = @intCast((a_data.len + b_data.len) / inner);
        const out = try self.allocator.alloc(f32, a_data.len + b_data.len);
        var raw_output: ?[]f32 = out;
        errdefer if (raw_output) |raw| self.allocator.free(raw);
        @memcpy(out[0..a_data.len], a_data);
        @memcpy(out[a_data.len..][0..b_data.len], b_data);
        const result = try self.makeBuf(out, true);
        raw_output = null;
        errdefer freeTensor(self, result);
        return self.withLogicalShape(result, out_shape[0..rank]);
    }

    const a_layout = resolveConcatLayout(resolved_a_shape, axis, a_data.len) orelse {
        std.log.warn("concat layout unresolved axis={d} a_shape={any} b_shape={any} a_len={d} b_len={d}", .{
            axis,
            resolved_a_shape,
            resolved_b_shape,
            a_data.len,
            b_data.len,
        });
        return error.UnsupportedShape;
    };
    const b_layout = resolveConcatLayout(resolved_b_shape, axis, b_data.len) orelse {
        std.log.warn("concat layout unresolved axis={d} a_shape={any} b_shape={any} a_len={d} b_len={d}", .{
            axis,
            resolved_a_shape,
            resolved_b_shape,
            a_data.len,
            b_data.len,
        });
        return error.UnsupportedShape;
    };
    if (a_layout.outer != b_layout.outer or a_layout.inner != b_layout.inner) {
        const generic_result = concatWithResolvedBroadcastShapes(self, a, b, axis, resolved_a_shape, resolved_b_shape, out_shape[0..rank]) catch |err| switch (err) {
            error.InvalidTensorShape, error.UnsupportedShape => null,
            else => return err,
        };
        if (generic_result) |result| {
            return result;
        }
        if (a_layout.inner == b_layout.inner and (a_layout.outer == 1 or b_layout.outer == 1)) {
            const outer = @max(a_layout.outer, b_layout.outer);
            const a_chunk = a_layout.axis_size * a_layout.inner;
            const b_chunk = b_layout.axis_size * b_layout.inner;
            const out_chunk = (a_layout.axis_size + b_layout.axis_size) * a_layout.inner;
            const output = try self.allocator.alloc(f32, outer * out_chunk);
            var raw_output: ?[]f32 = output;
            errdefer if (raw_output) |raw| self.allocator.free(raw);
            for (0..outer) |o| {
                const a_src = if (a_layout.outer == 1) 0 else o * a_chunk;
                const b_src = if (b_layout.outer == 1) 0 else o * b_chunk;
                @memcpy(output[o * out_chunk ..][0..a_chunk], a_data[a_src..][0..a_chunk]);
                @memcpy(output[o * out_chunk + a_chunk ..][0..b_chunk], b_data[b_src..][0..b_chunk]);
            }
            const result = try self.makeBuf(output, true);
            raw_output = null;
            errdefer freeTensor(self, result);
            if (resolveShapeFromDataLen(out_shape[0..rank], output.len)) |resolved_out_shape| {
                return self.withLogicalShape(result, resolved_out_shape[0..rank]);
            }
            return self.withLogicalShape(result, out_shape[0..rank]);
        }
        if (allKnownDimsAreOne(resolved_a_shape) and allKnownDimsAreOne(resolved_b_shape)) {
            const out = try self.allocator.alloc(f32, a_data.len + b_data.len);
            var raw_output: ?[]f32 = out;
            errdefer if (raw_output) |raw| self.allocator.free(raw);
            @memcpy(out[0..a_data.len], a_data);
            @memcpy(out[a_data.len..][0..b_data.len], b_data);
            const result = try self.makeBuf(out, true);
            raw_output = null;
            errdefer freeTensor(self, result);
            const flat_out_shape = [_]i64{@intCast(a_data.len + b_data.len)};
            return self.withLogicalShape(result, &flat_out_shape);
        }
        std.log.warn("concat layout mismatch axis={d} a_shape={any} b_shape={any} a_len={d} b_len={d} a_layout={any} b_layout={any}", .{
            axis,
            resolved_a_shape,
            resolved_b_shape,
            a_data.len,
            b_data.len,
            a_layout,
            b_layout,
        });
        return error.ShapeMismatch;
    }
    const out_numel = a_data.len + b_data.len;

    // For concat, we copy chunks along the concat axis.
    // Compute the "outer" (before axis), "inner" (after axis) sizes.
    const outer = a_layout.outer;
    const inner = a_layout.inner;
    const a_axis = a_layout.axis_size;
    const b_axis = b_layout.axis_size;

    const output = try self.allocator.alloc(f32, out_numel);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);
    for (0..outer) |o| {
        const a_chunk = a_axis * inner;
        const b_chunk = b_axis * inner;
        const out_chunk = (a_axis + b_axis) * inner;
        @memcpy(output[o * out_chunk ..][0..a_chunk], a_data[o * a_chunk ..][0..a_chunk]);
        @memcpy(output[o * out_chunk + a_chunk ..][0..b_chunk], b_data[o * b_chunk ..][0..b_chunk]);
    }
    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    if (resolveShapeFromDataLen(out_shape[0..rank], out_numel)) |resolved_out_shape| {
        return self.withLogicalShape(result, resolved_out_shape[0..rank]);
    }
    if (safeShapeNumel(out_shape[0..rank]) != null) {
        return self.withLogicalShape(result, out_shape[0..rank]);
    }
    return result;
}

fn primSoftmaxOp(ctx: *anyopaque, input: CT, dim: u32) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const data = getData(input);
    const d = resolveSoftmaxLastDim(input, dim) orelse return error.InvalidTensorShape;
    if (d == 0 or data.len % d != 0) return error.InvalidTensorShape;
    const rows = data.len / d;
    const output = try self.allocator.alloc(f32, data.len);
    var raw_output: ?[]f32 = output;
    errdefer if (raw_output) |raw| self.allocator.free(raw);

    for (0..rows) |r| {
        const row = data[r * d ..][0..d];
        const out = output[r * d ..][0..d];

        // Find max for numerical stability.
        var max_val: f32 = -std.math.inf(f32);
        for (row) |v| max_val = @max(max_val, v);

        // exp(x - max) and sum.
        var sum: f32 = 0;
        for (out, row) |*o, v| {
            o.* = @exp(v - max_val);
            sum += o.*;
        }

        // Normalize.
        const inv_sum = 1.0 / sum;
        for (out) |*o| o.* *= inv_sum;
    }
    const result = try self.makeBuf(output, true);
    raw_output = null;
    errdefer freeTensor(self, result);
    return propagateLogicalShapeLike(self, result, input);
}

fn softmaxConsumeOp(_: *anyopaque, input: CT, dim: u32) anyerror!?CT {
    const buf = ownedDenseBufWithMaxSharedRefs(input, 2) orelse return null;
    const d = resolveSoftmaxLastDim(input, dim) orelse return error.InvalidTensorShape;
    if (d == 0 or buf.data.len % d != 0) return error.InvalidTensorShape;
    activations_mod.softmax(buf.data, d);
    return input;
}

fn primLogSoftmaxOp(ctx: *anyopaque, input: CT, dim: u32) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const data = getData(input);
    const d = resolveSoftmaxLastDim(input, dim) orelse return error.InvalidTensorShape;
    if (d == 0 or data.len % d != 0) return error.InvalidTensorShape;
    const output = try self.allocator.dupe(f32, data);
    errdefer self.allocator.free(output);
    activations_mod.logSoftmaxInPlace(output, d);
    const result = try self.makeBuf(output, true);
    errdefer freeTensor(self, result);
    return propagateLogicalShapeLike(self, result, input);
}

fn logSoftmaxConsumeOp(_: *anyopaque, input: CT, dim: u32) anyerror!?CT {
    const buf = ownedDenseBufWithMaxSharedRefs(input, 2) orelse return null;
    const d = resolveSoftmaxLastDim(input, dim) orelse return error.InvalidTensorShape;
    if (d == 0 or buf.data.len % d != 0) return error.InvalidTensorShape;
    activations_mod.logSoftmaxInPlace(buf.data, d);
    return input;
}

fn fromFloat32Op(ctx: *anyopaque, data: []const f32) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const owned = try self.allocator.dupe(f32, data);
    return self.makeBuf(owned, true);
}

fn fromFloat32ShapeOp(ctx: *anyopaque, data: []const f32, shape: []const i32) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const owned = try self.allocator.dupe(f32, data);
    errdefer self.allocator.free(owned);
    const logical_shape = try self.allocator.alloc(i64, shape.len);
    errdefer self.allocator.free(logical_shape);
    for (shape, 0..) |dim, i| logical_shape[i] = dim;

    const buf = try self.makeBuf(owned, true);
    toBuf(buf).logical_shape = logical_shape;
    return buf;
}

fn toFloat32Op(ctx: *anyopaque, tensor: CT, allocator: std.mem.Allocator) anyerror![]f32 {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const buf = toBuf(tensor);
    if (buf.data.len != 0) return allocator.dupe(f32, getData(tensor));
    if (buf.source_tensor) |source| return convertTensorToOwnedF32(allocator, source);
    if (buf.quantized_storage) |storage| {
        var elem_count: usize = 1;
        for (storage.shape) |dim| {
            if (dim <= 0) return error.UnsupportedShape;
            elem_count *= @as(usize, @intCast(dim));
        }
        const out = try allocator.alloc(f32, elem_count);
        try quant_codec.dequantizeToFloat32(storage.tensor_type, storage.raw_bytes, out);
        return out;
    }
    if (buf.lazy_entry) |entry| {
        if (entry.loaded) |*loaded| {
            if (loaded.quantized_storage) |*storage| {
                var elem_count: usize = 1;
                for (storage.shape) |dim| {
                    if (dim <= 0) return error.UnsupportedShape;
                    elem_count *= @as(usize, @intCast(dim));
                }
                const out = try allocator.alloc(f32, elem_count);
                try quant_codec.dequantizeToFloat32(storage.tensor_type, storage.raw_bytes, out);
                return out;
            }
            return convertTensorToOwnedF32(allocator, &loaded.tensor);
        }

        self.data.prefetch.lock();
        defer self.data.prefetch.unlock();
        try ensureLazyWeightLoadedLocked(self.data, self.run_budget, entry);
        if (entry.loaded) |*loaded| {
            if (loaded.quantized_storage) |*storage| {
                var elem_count: usize = 1;
                for (storage.shape) |dim| {
                    if (dim <= 0) return error.UnsupportedShape;
                    elem_count *= @as(usize, @intCast(dim));
                }
                const out = try allocator.alloc(f32, elem_count);
                try quant_codec.dequantizeToFloat32(storage.tensor_type, storage.raw_bytes, out);
                return out;
            }
            return convertTensorToOwnedF32(allocator, &loaded.tensor);
        }
    }
    if (buf.data.len == 0 and buf.name.len == 0) {
        return allocator.dupe(f32, buf.data);
    }
    return error.MissingWeight;
}

fn splitLastDim3Op(ctx: *anyopaque, input: CT, rows: usize, dim: usize) anyerror!ops.SplitLastDim3Result {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const data = getData(input);
    if (data.len != rows * dim * 3) return error.UnexpectedOutputShape;

    const total = rows * dim;
    const first = try self.allocator.alloc(f32, total);
    errdefer self.allocator.free(first);
    const second = try self.allocator.alloc(f32, total);
    errdefer self.allocator.free(second);
    const third = try self.allocator.alloc(f32, total);
    errdefer self.allocator.free(third);

    for (0..rows) |row| {
        const src = row * dim * 3;
        const dst = row * dim;
        @memcpy(first[dst..][0..dim], data[src..][0..dim]);
        @memcpy(second[dst..][0..dim], data[src + dim ..][0..dim]);
        @memcpy(third[dst..][0..dim], data[src + dim * 2 ..][0..dim]);
    }

    return .{
        .first = try self.makeBuf(first, true),
        .second = try self.makeBuf(second, true),
        .third = try self.makeBuf(third, true),
    };
}

fn concatRows2DOp(ctx: *anyopaque, a: CT, b: CT, rows_a: usize, rows_b: usize, cols: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const a_data = getData(a);
    const b_data = getData(b);
    if (a_data.len != rows_a * cols or b_data.len != rows_b * cols) return error.UnexpectedOutputShape;

    const out = try self.allocator.alloc(f32, (rows_a + rows_b) * cols);
    errdefer self.allocator.free(out);
    @memcpy(out[0..a_data.len], a_data);
    @memcpy(out[a_data.len..][0..b_data.len], b_data);
    return self.makeBuf(out, true);
}

fn sliceRows2DOp(ctx: *anyopaque, input: CT, start_row: usize, row_count: usize, cols: usize) anyerror!CT {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const data = getData(input);
    const total_rows = @divExact(data.len, cols);
    if (total_rows * cols != data.len) return error.UnexpectedOutputShape;
    if (start_row + row_count > total_rows) return error.UnexpectedOutputShape;
    const out = try self.allocator.alloc(f32, row_count * cols);
    errdefer self.allocator.free(out);
    @memcpy(out, data[start_row * cols ..][0 .. row_count * cols]);
    return self.makeBuf(out, true);
}

fn exportDenseTensorBytes(
    allocator: std.mem.Allocator,
    tensor: *const tensor_mod.Tensor,
) !?ops.ExportTensorData {
    const expected_bytes = tensorExpectedDenseByteLen(tensor) orelse return error.InvalidTensorShape;
    if (tensor.data.len != expected_bytes) return error.InvalidTensorShape;
    return switch (tensor.dtype) {
        .f32, .f16, .bf16, .f64, .i8, .i16, .i32, .i64, .u8, .bool_ => .{
            .dtype = tensor.dtype,
            .payload = .{ .bytes = try allocator.dupe(u8, tensor.data) },
        },
    };
}

fn tensorExpectedDenseByteLen(tensor: *const tensor_mod.Tensor) ?usize {
    var element_count: usize = 1;
    for (tensor.shape) |dim| {
        if (dim < 0) return null;
        element_count = std.math.mul(usize, element_count, @intCast(dim)) catch return null;
    }
    return std.math.mul(usize, element_count, tensor.dtype.byteSize()) catch null;
}

fn exportQuantizedTensorStorage(
    allocator: std.mem.Allocator,
    storage: *const QuantizedStorage,
) !ops.ExportTensorData {
    return .{
        .dtype = .f32,
        .payload = .{
            .quantized_f32 = .{
                .tensor_type = storage.tensor_type,
                .raw_bytes = try allocator.dupe(u8, storage.raw_bytes),
                .shape = try allocator.dupe(i64, storage.shape),
            },
        },
    };
}

fn exportDenseTensorDType(tensor: *const tensor_mod.Tensor) tensor_mod.DType {
    return tensor.dtype;
}

fn exportTensorDataOp(ctx: *anyopaque, tensor: CT, allocator: std.mem.Allocator) anyerror!?ops.ExportTensorData {
    if (@intFromPtr(tensor) == 0) return error.InvalidTensorHandle;
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const buf = toBuf(tensor);

    if (buf.name.len > 0) {
        if (self.data.resident_weights.getPtr(buf.name)) |weight| {
            if (weight.quantized_storage) |*storage| {
                return try exportQuantizedTensorStorage(allocator, storage);
            }
            if (weight.tensor.data.len > 0) {
                return try exportDenseTensorBytes(allocator, &weight.tensor);
            }
        }

        self.data.prefetch.lock();
        defer self.data.prefetch.unlock();
        if (self.data.lazy_weights.getPtr(buf.name)) |entry| {
            if (entry.loaded) |*loaded| {
                if (loaded.quantized_storage) |*storage| {
                    return try exportQuantizedTensorStorage(allocator, storage);
                }
                if (loaded.tensor.data.len > 0) {
                    return try exportDenseTensorBytes(allocator, &loaded.tensor);
                }
            }
        }
    }

    if (buf.quantized_storage) |storage| {
        return try exportQuantizedTensorStorage(allocator, storage);
    }

    if (buf.source_tensor) |source| {
        return try exportDenseTensorBytes(allocator, source);
    }

    if (buf.data.len > 0) {
        const dense = getData(tensor);
        return .{
            .dtype = .f32,
            .payload = .{ .bytes = try allocator.dupe(u8, std.mem.sliceAsBytes(dense)) },
        };
    }

    return null;
}

fn tensorDTypeOp(ctx: *anyopaque, tensor: CT) anyerror!tensor_mod.DType {
    const self: *NativeCompute = @ptrCast(@alignCast(ctx));
    const buf = toBuf(tensor);

    if (buf.name.len > 0) {
        if (self.data.resident_weights.getPtr(buf.name)) |weight| {
            if (weight.tensor.data.len > 0) {
                return exportDenseTensorDType(&weight.tensor);
            }
        }

        self.data.prefetch.lock();
        defer self.data.prefetch.unlock();
        if (self.data.lazy_weights.getPtr(buf.name)) |entry| {
            if (entry.loaded) |*loaded| {
                if (loaded.tensor.data.len > 0) {
                    return exportDenseTensorDType(&loaded.tensor);
                }
            }
        }
    }

    if (buf.source_tensor) |source| return exportDenseTensorDType(source);
    if (buf.declared_dtype) |dtype| return dtype;
    if (buf.data.len > 0) return .f32;
    if (buf.quantized_storage != null) return .f32;
    return error.UnsupportedTensorType;
}

fn tensorShapeOp(_: *anyopaque, tensor: CT, allocator: std.mem.Allocator) anyerror![]i64 {
    const buf = toBuf(tensor);
    if (buf.logical_shape) |shape| return allocator.dupe(i64, shape);
    if (buf.quantized_storage) |storage| return allocator.dupe(i64, storage.shape);
    if (buf.source_tensor) |source| return allocator.dupe(i64, source.shape);
    if (buf.lazy_entry) |entry| {
        if (entry.loaded) |*loaded| {
            if (loaded.quantized_storage) |*storage| return allocator.dupe(i64, storage.shape);
            return allocator.dupe(i64, loaded.tensor.shape);
        }
    }
    return error.UnsupportedShape;
}

fn sliceLastDimOp(_: *anyopaque, tensor: CT, start: usize, stop: usize) anyerror!CT {
    const input = toBuf(tensor);
    const shape = input.logical_shape orelse return error.UnsupportedShape;
    if (shape.len != 2) return error.UnsupportedShape;
    const input_data = getData(tensor);

    const rows: usize = @intCast(shape[0]);
    const cols: usize = @intCast(shape[1]);
    if (start > stop or stop > cols) return error.OutOfBounds;

    const out_cols = stop - start;
    const out = try input.allocator.alloc(f32, rows * out_cols);
    errdefer input.allocator.free(out);
    for (0..rows) |row| {
        const src = input_data[row * cols + start .. row * cols + stop];
        const dst = out[row * out_cols ..][0..out_cols];
        @memcpy(dst, src);
    }

    const out_shape = try input.allocator.alloc(i64, 2);
    errdefer input.allocator.free(out_shape);
    out_shape[0] = @intCast(rows);
    out_shape[1] = @intCast(out_cols);

    const out_buf = try input.allocator.create(Buf);
    out_buf.* = .{
        .data = out,
        .allocator = input.allocator,
        .owned = true,
        .logical_shape = out_shape,
    };
    return out_buf;
}

fn evalTensorOp(_: *anyopaque, _: CT) anyerror!void {}

fn argmaxLastRowOp(_: *anyopaque, tensor: CT, rows: usize, dim: usize) anyerror!?u32 {
    const data = getData(tensor);
    if (rows == 0 or dim == 0) return error.InvalidTensorShape;
    if (data.len != rows * dim) return error.InvalidTensorShape;
    const last_row = data[(rows - 1) * dim ..][0..dim];
    return @intCast(activations_mod.argmax(last_row));
}

test "linear q8_0 kernel computes direct matmul" {
    var input: [32]f32 = [_]f32{1.0} ** 32;
    var output: [2]f32 = [_]f32{ 0.0, 0.0 };
    var weight_raw: [68]u8 = [_]u8{0} ** 68;

    // Row 0: scale 1.0, all quantized values 1.
    weight_raw[0] = 0x00;
    weight_raw[1] = 0x3C;
    for (0..32) |i| weight_raw[2 + i] = @bitCast(@as(i8, 1));

    // Row 1: scale 1.0, all quantized values 2.
    weight_raw[34] = 0x00;
    weight_raw[35] = 0x3C;
    for (0..32) |i| weight_raw[36 + i] = @bitCast(@as(i8, 2));

    try linearNoBiasQuantizedGeneric(null, &input, &weight_raw, &output, 1, 32, 2, .{ .known = .Q8_0 }, &dotQ8_0Block);
    try std.testing.expectApproxEqAbs(@as(f32, 32.0), output[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 64.0), output[1], 1e-4);
}

test "linear q8_0 ranged columns match full output" {
    const rows = 2;
    const in_dim = 32;
    const out_dim = 5;
    const block_size = 34;
    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 11);
        value.* = @floatFromInt(signed - 5);
    }

    var weight_raw: [out_dim * block_size]u8 = [_]u8{0} ** (out_dim * block_size);
    for (0..out_dim) |row| {
        const base = row * block_size;
        weight_raw[base] = 0x00;
        weight_raw[base + 1] = 0x3C;
        for (0..32) |i| {
            const q: i8 = @intCast(@as(i32, @intCast((row + i) % 9)) - 4);
            weight_raw[base + 2 + i] = @bitCast(q);
        }
    }

    var full: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var ranged: [rows * out_dim]f32 = [_]f32{-999.0} ** (rows * out_dim);
    linearQ8_0Range(&input, &weight_raw, &full, rows, in_dim, out_dim, 0, out_dim, null);
    linearQ8_0Range(&input, &weight_raw, &ranged, rows, in_dim, out_dim, 0, 2, null);
    linearQ8_0Range(&input, &weight_raw, &ranged, rows, in_dim, out_dim, 2, out_dim, null);

    for (full, ranged) |want, got| {
        try std.testing.expectApproxEqAbs(want, got, 1e-4);
    }
}

test "linear q8_0 mr=2 ranged rows match generic full output" {
    const rows = 3;
    const in_dim = 64;
    const out_dim = 5;
    const block_size = 34;
    const row_blocks = in_dim / 32;
    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 19);
        value.* = @floatFromInt(signed - 9);
    }

    var weight_raw: [out_dim * row_blocks * block_size]u8 = [_]u8{0} ** (out_dim * row_blocks * block_size);
    for (0..out_dim) |row| {
        for (0..row_blocks) |block_idx| {
            const base = row * row_blocks * block_size + block_idx * block_size;
            weight_raw[base] = 0x00;
            weight_raw[base + 1] = 0x3C;
            for (0..32) |i| {
                const q: i8 = @intCast(@as(i32, @intCast((row * 7 + block_idx * 5 + i) % 15)) - 7);
                weight_raw[base + 2 + i] = @bitCast(q);
            }
        }
    }

    var full: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try linearNoBiasQuantizedGeneric(null, &input, &weight_raw, &full, rows, in_dim, out_dim, .{ .known = .Q8_0 }, &dotQ8_0Block);

    var ranged: [rows * out_dim]f32 = [_]f32{-999.0} ** (rows * out_dim);
    linearQ8_0Range(&input, &weight_raw, &ranged, rows, in_dim, out_dim, 0, 1, null);
    linearQ8_0Range(&input, &weight_raw, &ranged, rows, in_dim, out_dim, 1, 4, null);
    linearQ8_0Range(&input, &weight_raw, &ranged, rows, in_dim, out_dim, 4, out_dim, null);

    for (full, ranged) |want, got| {
        try std.testing.expectApproxEqAbs(want, got, 1e-4);
    }
}

test "linear q8_0 pair kernel matches separate sibling matmuls" {
    const allocator = std.testing.allocator;
    const rows = 3;
    const in_dim = 32;
    const out_dim = 2;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q8_0 };
    const block_size = 34;
    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 7);
        value.* = @floatFromInt(signed - 3);
    }

    var weight_raw_a: [68]u8 = [_]u8{0} ** 68;
    var weight_raw_b: [68]u8 = [_]u8{0} ** 68;
    for (0..out_dim) |row| {
        const base = row * block_size;
        weight_raw_a[base] = 0x00;
        weight_raw_a[base + 1] = 0x3C;
        weight_raw_b[base] = 0x00;
        weight_raw_b[base + 1] = 0x3C;
        for (0..32) |i| {
            const qa: i32 = @as(i32, @intCast(i % 5)) - 2;
            const qb: i32 = @as(i32, @intCast(i % 3)) + 1;
            weight_raw_a[base + 2 + i] = @bitCast(@as(i8, @intCast(qa)));
            weight_raw_b[base + 2 + i] = @bitCast(@as(i8, @intCast(qb)));
        }
    }

    const shape = [_]i64{ out_dim, in_dim };
    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = &weight_raw_a,
        .shape = &shape,
        .raw_owned = false,
        .allocator = allocator,
    };
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = &weight_raw_b,
        .shape = &shape,
        .raw_owned = false,
        .allocator = allocator,
    };

    var output_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var output_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantizedPair(null, allocator, &storage_a, &storage_b, &input, &output_a, &output_b, rows, in_dim, out_dim));

    var ref_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var ref_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_a, &input, &ref_a, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, &input, &ref_b, rows, in_dim, out_dim));

    for (output_a, ref_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
    for (output_b, ref_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
}

test "q8_0 activation-quantized input path stays close to f32-input direct path" {
    const allocator = std.testing.allocator;
    const rows = 2;
    const in_dim = 64;
    const out_dim = 3;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q8_0 };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const values_per_block = gguf_tensor_types.valuesPerBlock(tensor_type).?;
    const row_blocks = in_dim / values_per_block;

    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 17);
        value.* = @as(f32, @floatFromInt(signed - 8)) / 9.0;
    }

    const weight_raw = try allocator.alloc(u8, out_dim * row_blocks * block_size);
    defer allocator.free(weight_raw);
    var dense_weight: [out_dim * in_dim]f32 = undefined;
    for (&dense_weight, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 23);
        value.* = @as(f32, @floatFromInt(signed - 11)) / 32.0;
    }
    for (0..(out_dim * row_blocks)) |block_idx| {
        quant_codec.quantizeQ8_0Block(
            dense_weight[block_idx * values_per_block ..][0..values_per_block],
            weight_raw[block_idx * block_size ..][0..block_size],
        );
    }

    var exact_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    linearQ8_0Range(&input, weight_raw, &exact_output, rows, in_dim, out_dim, 0, out_dim, null);

    const q_values = try allocator.alloc(u8, rows * row_blocks * values_per_block);
    defer allocator.free(q_values);
    const input_scales = try allocator.alloc(f32, rows * row_blocks);
    defer allocator.free(input_scales);
    quantizeQ8_0ActivationRows(&input, q_values, input_scales, rows, in_dim, row_blocks);

    var quant_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    linearQ8_0QuantizedInputRange(false, q_values, input_scales, weight_raw, &quant_output, rows, in_dim, out_dim, 0, out_dim, null);

    for (quant_output, exact_output) |actual, expected| {
        try std.testing.expectApproxEqAbs(expected, actual, 2e-2);
    }

    const prepared = try allocator.alloc(u8, out_dim * row_blocks * prepared_q8_0_block_bytes);
    defer allocator.free(prepared);
    for (0..(out_dim * row_blocks)) |block_idx| {
        writePreparedQ8_0Block(
            prepared[block_idx * prepared_q8_0_block_bytes ..][0..prepared_q8_0_block_bytes],
            weight_raw[block_idx * block_size ..][0..block_size],
        );
    }
    var prepared_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    linearQ8_0QuantizedInputRange(true, q_values, input_scales, prepared, &prepared_output, rows, in_dim, out_dim, 0, out_dim, null);

    for (prepared_output, quant_output) |actual, expected| {
        try std.testing.expectApproxEqAbs(expected, actual, 1e-6);
    }
}

test "i8 dot block matches scalar reference" {
    var input: [32]u8 = undefined;
    var weight: [32]u8 = undefined;
    var expected: i32 = 0;
    for (0..32) |idx| {
        const x: i8 = @intCast(@as(i32, @intCast(idx % 17)) - 8);
        const w: i8 = @intCast(@as(i32, @intCast((idx * 5 + 3) % 19)) - 9);
        input[idx] = @bitCast(x);
        weight[idx] = @bitCast(w);
        expected += @as(i32, x) * @as(i32, w);
    }

    try std.testing.expectEqual(expected, dotI8I8Block(&input, &weight));
}

test "q8_0 prepared panel-packed activation path matches row-major prepared path" {
    const allocator = std.testing.allocator;
    const rows = 3;
    const in_dim = 64;
    const out_dim = 8;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q8_0 };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const values_per_block = gguf_tensor_types.valuesPerBlock(tensor_type).?;
    const row_blocks = in_dim / values_per_block;

    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 7 + 5) % 29);
        value.* = @as(f32, @floatFromInt(signed - 14)) / 13.0;
    }

    const weight_raw = try allocator.alloc(u8, out_dim * row_blocks * block_size);
    var dense_weight: [out_dim * in_dim]f32 = undefined;
    for (&dense_weight, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 11 + 3) % 31);
        value.* = @as(f32, @floatFromInt(signed - 15)) / 17.0;
    }
    for (0..(out_dim * row_blocks)) |block_idx| {
        quant_codec.quantizeQ8_0Block(
            dense_weight[block_idx * values_per_block ..][0..values_per_block],
            weight_raw[block_idx * block_size ..][0..block_size],
        );
    }

    var storage = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw,
        .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage.deinit();
    try prepareNativeQuantizedStorage(&storage);
    try std.testing.expect(storage.preparedBytes(.row_major_blocks) != null);
    try std.testing.expect(storage.preparedBytes(.panel4) != null);
    try std.testing.expectEqual(preparedQ8_0PanelByteSize(out_dim, row_blocks), storage.preparedBytes(.panel4).?.len);

    const q_values = try allocator.alloc(u8, rows * row_blocks * values_per_block);
    defer allocator.free(q_values);
    const input_scales = try allocator.alloc(f32, rows * row_blocks);
    defer allocator.free(input_scales);
    quantizeQ8_0ActivationRows(&input, q_values, input_scales, rows, in_dim, row_blocks);

    var row_major_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    linearQ8_0QuantizedInputRange(true, q_values, input_scales, storage.preparedBytes(.row_major_blocks).?, &row_major_output, rows, in_dim, out_dim, 0, out_dim, null);

    var panel_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    linearQ8_0QuantizedInputPreparedPanelRange(q_values, input_scales, storage.preparedBytes(.row_major_blocks).?, storage.preparedBytes(.panel4).?, &panel_output, rows, in_dim, out_dim, 0, out_dim, null);

    for (panel_output, row_major_output) |actual, expected| {
        try std.testing.expectApproxEqAbs(expected, actual, 1e-6);
    }

    try prepareQ8_0Panel8PackedStorage(&storage);
    try std.testing.expect(storage.preparedBytes(.panel8) != null);
    try std.testing.expectEqual(preparedQ8_0Panel8ByteSize(out_dim, row_blocks), storage.preparedBytes(.panel8).?.len);

    var panel8_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    linearQ8_0QuantizedInputGroupedPanel8Range(
        1,
        q_values,
        input_scales,
        .{storage.preparedBytes(.row_major_blocks).?},
        .{storage.preparedBytes(.panel4)},
        .{storage.preparedBytes(.panel8).?},
        .{null},
        .{&panel8_output},
        rows,
        in_dim,
        out_dim,
        0,
        out_dim,
    );
    for (panel8_output, row_major_output) |actual, expected| {
        try std.testing.expectApproxEqAbs(expected, actual, 1e-6);
    }
}

test "q8_1 prepared activation paths match explicit prepared helper" {
    const allocator = std.testing.allocator;
    const rows = 1;
    const in_dim = 256;
    const out_dim = 512;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q8_1 };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const values_per_block = gguf_tensor_types.valuesPerBlock(tensor_type).?;
    const row_blocks = in_dim / values_per_block;
    try std.testing.expect(shouldUseQ8_0ActivationQuant(rows, out_dim, row_blocks));

    const input = try allocator.alloc(f32, rows * in_dim);
    defer allocator.free(input);
    for (input, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 7 + 5) % 31);
        value.* = @as(f32, @floatFromInt(signed - 15)) / 23.0;
    }

    const raw_a = try allocator.alloc(u8, out_dim * row_blocks * block_size);
    const raw_b = try allocator.alloc(u8, out_dim * row_blocks * block_size);
    const raw_c = try allocator.alloc(u8, out_dim * row_blocks * block_size);
    var block_values: [32]f32 = undefined;
    for (0..(out_dim * row_blocks)) |block_idx| {
        for (&block_values, 0..) |*value, i| {
            const signed: i32 = @intCast((block_idx * 13 + i * 5 + 3) % 37);
            value.* = @as(f32, @floatFromInt(signed - 18)) / 29.0;
        }
        quant_codec.quantizeQ8_1Block(&block_values, raw_a[block_idx * block_size ..][0..block_size]);
        for (&block_values, 0..) |*value, i| {
            const signed: i32 = @intCast((block_idx * 17 + i * 7 + 11) % 41);
            value.* = @as(f32, @floatFromInt(signed - 20)) / 31.0;
        }
        quant_codec.quantizeQ8_1Block(&block_values, raw_b[block_idx * block_size ..][0..block_size]);
        for (&block_values, 0..) |*value, i| {
            const signed: i32 = @intCast((block_idx * 19 + i * 3 + 23) % 43);
            value.* = @as(f32, @floatFromInt(signed - 21)) / 37.0;
        }
        quant_codec.quantizeQ8_1Block(&block_values, raw_c[block_idx * block_size ..][0..block_size]);
    }

    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_a,
        .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_a.deinit();
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_b,
        .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_b.deinit();
    var storage_c = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_c,
        .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_c.deinit();
    try prepareNativeQuantizedStorage(&storage_a);
    try prepareNativeQuantizedStorage(&storage_b);
    try prepareNativeQuantizedStorage(&storage_c);
    try std.testing.expect(storage_a.preparedBytes(.row_major_blocks) != null);
    try std.testing.expect(storage_a.preparedBytes(.panel4) != null);
    try std.testing.expectEqual(out_dim * row_blocks * prepared_q8_0_block_bytes, storage_a.preparedBytes(.row_major_blocks).?.len);
    try std.testing.expectEqual(preparedQ8_0PanelByteSize(out_dim, row_blocks), storage_a.preparedBytes(.panel4).?.len);

    const single = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(single);
    @memset(single, 0.0);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_a, input, single, rows, in_dim, out_dim));

    const explicit = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(explicit);
    @memset(explicit, 0.0);
    try linearNoBiasQ8_1PreparedActivation(
        allocator,
        null,
        input,
        storage_a.preparedBytes(.row_major_blocks).?,
        storage_a.preparedBytes(.panel4),
        explicit,
        rows,
        in_dim,
        out_dim,
    );
    for (single, explicit) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-6);

    const pair_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(pair_a);
    const pair_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(pair_b);
    @memset(pair_a, 0.0);
    @memset(pair_b, 0.0);
    try std.testing.expect(try linearNoBiasQuantizedPair(null, allocator, &storage_a, &storage_b, input, pair_a, pair_b, rows, in_dim, out_dim));

    const ref_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(ref_b);
    @memset(ref_b, 0.0);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, input, ref_b, rows, in_dim, out_dim));
    const ref_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(ref_c);
    @memset(ref_c, 0.0);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_c, input, ref_c, rows, in_dim, out_dim));
    for (pair_a, single) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-6);
    for (pair_b, ref_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-6);

    const bias_a = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_a);
    const bias_b = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_b);
    const bias_c = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_c);
    for (0..out_dim) |idx| {
        bias_a[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 5)) - 2)) / 17.0;
        bias_b[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 7)) - 3)) / 19.0;
        bias_c[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 11)) - 5)) / 23.0;
    }

    const triple_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(triple_a);
    const triple_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(triple_b);
    const triple_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(triple_c);
    @memset(triple_a, 0.0);
    @memset(triple_b, 0.0);
    @memset(triple_c, 0.0);
    try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, bias_a, bias_b, bias_c, triple_a, triple_b, triple_c, rows, in_dim, out_dim));

    for (triple_a, single, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_a[idx % out_dim], actual, 1e-6);
    for (triple_b, ref_b, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_b[idx % out_dim], actual, 1e-6);
    for (triple_c, ref_c, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_c[idx % out_dim], actual, 1e-6);
}

test "legacy prepared activation panel path matches row-major prepared path" {
    const allocator = std.testing.allocator;
    const rows = 3;
    const in_dim = 64;
    const out_dim = 8;
    const formats = [_]gguf_tensor_types.KnownTensorType{ .Q4_0, .Q4_1, .Q5_0, .Q5_1 };

    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 7 + 5) % 31);
        value.* = @as(f32, @floatFromInt(signed - 15)) / 19.0;
    }

    inline for (formats) |known| {
        const tensor_type: gguf_tensor_types.TensorType = .{ .known = known };
        const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
        const values_per_block = gguf_tensor_types.valuesPerBlock(tensor_type).?;
        const row_blocks = in_dim / values_per_block;
        const weight_raw = try allocator.alloc(u8, out_dim * row_blocks * block_size);
        var dense_weight: [out_dim * in_dim]f32 = undefined;
        for (&dense_weight, 0..) |*value, idx| {
            const signed: i32 = @intCast((idx * 11 + @intFromEnum(known)) % 37);
            value.* = @as(f32, @floatFromInt(signed - 18)) / 23.0;
        }
        for (0..(out_dim * row_blocks)) |block_idx| {
            const src = dense_weight[block_idx * values_per_block ..][0..values_per_block];
            const dst = weight_raw[block_idx * block_size ..][0..block_size];
            switch (known) {
                .Q4_0 => quant_codec.quantizeQ4_0Block(src, dst),
                .Q4_1 => quant_codec.quantizeQ4_1Block(src, dst),
                .Q5_0 => quant_codec.quantizeQ5_0Block(src, dst),
                .Q5_1 => quant_codec.quantizeQ5_1Block(src, dst),
                else => unreachable,
            }
        }

        var storage = QuantizedStorage{
            .tensor_type = tensor_type,
            .raw_bytes = weight_raw,
            .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
            .raw_owned = true,
            .allocator = allocator,
        };
        defer storage.deinit();
        try prepareNativeQuantizedStorage(&storage);
        try std.testing.expect(storage.preparedBytes(.row_major_blocks) != null);
        try std.testing.expect(storage.preparedBytes(.panel4) != null);
        try std.testing.expectEqual(out_dim * row_blocks * prepared_legacy_block_bytes, storage.preparedBytes(.row_major_blocks).?.len);
        try std.testing.expectEqual(preparedLegacyPanelByteSize(out_dim, row_blocks), storage.preparedBytes(.panel4).?.len);

        const q = try quantizeLegacyActivation(allocator, &input, rows, in_dim, row_blocks);
        defer allocator.free(q.q_values);
        defer allocator.free(q.input_scales);
        defer allocator.free(q.input_sums);
        var row_major_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
        legacyPreparedActivationApply(q.q_values, q.input_scales, q.input_sums, storage.preparedBytes(.row_major_blocks).?, null, null, &row_major_output, rows, in_dim, out_dim, 0, out_dim, false);
        var panel_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
        legacyPreparedActivationApply(q.q_values, q.input_scales, q.input_sums, storage.preparedBytes(.row_major_blocks).?, storage.preparedBytes(.panel4), null, &panel_output, rows, in_dim, out_dim, 0, out_dim, false);

        for (panel_output, row_major_output) |actual, expected| {
            try std.testing.expectApproxEqAbs(expected, actual, 1e-6);
        }
    }
}

