        defer storage_b.deinit();
        var storage_c = QuantizedStorage{
            .tensor_type = tensor_type,
            .raw_bytes = raw_c,
            .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
            .raw_owned = true,
            .allocator = allocator,
        };
        defer storage_c.deinit();
        try prepareNativeQuantizedStorage(&storage_a);
        try prepareNativeQuantizedStorage(&storage_b);
        try prepareNativeQuantizedStorage(&storage_c);
        try std.testing.expect(storage_a.preparedBytes(.row_major_blocks) != null);
        try std.testing.expect(storage_a.preparedBytes(.panel4) != null);
        try std.testing.expectEqual(preparedLegacyPanelByteSize(out_dim, format_row_blocks), storage_a.preparedBytes(.panel4).?.len);

        const single_a = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(single_a);
        const single_b = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(single_b);
        const single_c = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(single_c);
        @memset(single_a, 0.0);
        @memset(single_b, 0.0);
        @memset(single_c, 0.0);
        try std.testing.expect(try linearNoBiasQuantized(null, &storage_a, input, single_a, rows, in_dim, out_dim));
        try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, input, single_b, rows, in_dim, out_dim));
        try std.testing.expect(try linearNoBiasQuantized(null, &storage_c, input, single_c, rows, in_dim, out_dim));

        const pair_a = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(pair_a);
        const pair_b = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(pair_b);
        @memset(pair_a, 0.0);
        @memset(pair_b, 0.0);
        try std.testing.expect(try linearNoBiasQuantizedPair(null, allocator, &storage_a, &storage_b, input, pair_a, pair_b, rows, in_dim, out_dim));
        for (pair_a, single_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
        for (pair_b, single_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);

        const bias_a = try allocator.alloc(f32, out_dim);
        defer allocator.free(bias_a);
        const bias_b = try allocator.alloc(f32, out_dim);
        defer allocator.free(bias_b);
        const bias_c = try allocator.alloc(f32, out_dim);
        defer allocator.free(bias_c);
        for (0..out_dim) |idx| {
            bias_a[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 5)) - 2)) / 17.0;
            bias_b[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 7)) - 3)) / 19.0;
            bias_c[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 11)) - 5)) / 23.0;
        }
        const triple_a = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(triple_a);
        const triple_b = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(triple_b);
        const triple_c = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(triple_c);
        @memset(triple_a, 0.0);
        @memset(triple_b, 0.0);
        @memset(triple_c, 0.0);
        try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, bias_a, bias_b, bias_c, triple_a, triple_b, triple_c, rows, in_dim, out_dim));
        for (triple_a, single_a, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_a[idx % out_dim], actual, tolerance);
        for (triple_b, single_b, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_b[idx % out_dim], actual, tolerance);
        for (triple_c, single_c, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_c[idx % out_dim], actual, tolerance);
    }
}

test "q2_q3_k prepared q8_k activation paths are wired and panel-safe" {
    const allocator = std.testing.allocator;
    setK16Panel8DirectOverrideForBench(true);
    setK16Panel16DirectOverrideForBench(true);
    setK16RawQ8DirectOverrideForBench(true);
    setK16Rows3DirectOverrideForBench(true);
    setQ3KNoDmnPanelOverrideForBench(true);
    setQ3KNoDmnGroupedOverrideForBench(true);
    defer setK16Panel8DirectOverrideForBench(null);
    defer setK16Panel16DirectOverrideForBench(null);
    defer setK16RawQ8DirectOverrideForBench(null);
    defer setK16Rows3DirectOverrideForBench(null);
    defer setQ3KNoDmnPanelOverrideForBench(null);
    defer setQ3KNoDmnGroupedOverrideForBench(null);
    const rows = 1;
    const in_dim = 768;
    const out_dim = 512;
    const formats = [_]gguf_tensor_types.KnownTensorType{ .Q2_K, .Q3_K };
    const row_blocks = in_dim / 256;
    const tolerance: f32 = 5e-6;
    try std.testing.expect(shouldUseQ4_Q5_KQ8KActivationQuant(rows, out_dim, row_blocks));

    const input = try allocator.alloc(f32, rows * in_dim);
    defer allocator.free(input);
    for (input, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 7 + 3) % 29);
        value.* = @as(f32, @floatFromInt(signed - 14)) / 17.0;
    }

    inline for (formats) |known| {
        const tensor_type: gguf_tensor_types.TensorType = .{ .known = known };
        const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
        const raw_a = try allocator.alloc(u8, out_dim * row_blocks * block_size);
        const raw_b = try allocator.alloc(u8, out_dim * row_blocks * block_size);
        const raw_c = try allocator.alloc(u8, out_dim * row_blocks * block_size);
        var dense_block: [256]f32 = undefined;
        const raws = [_][]u8{ raw_a, raw_b, raw_c };
        const seeds = [_]usize{ 3, 17, 29 };
        for (raws, seeds) |raw, seed| {
            for (0..(out_dim * row_blocks)) |block_idx| {
                for (&dense_block, 0..) |*value, i| {
                    const signed: i32 = @intCast((block_idx * 11 + i * 5 + seed + @intFromEnum(known)) % 41);
                    value.* = @as(f32, @floatFromInt(signed - 20)) / 23.0;
                }
                const dst = raw[block_idx * block_size ..][0..block_size];
                switch (known) {
                    .Q2_K => quant_codec.quantizeQ2_KBlock(&dense_block, dst),
                    .Q3_K => quant_codec.quantizeQ3_KBlock(&dense_block, dst),
                    else => unreachable,
                }
            }
        }

        var storage_a = QuantizedStorage{
            .tensor_type = tensor_type,
            .raw_bytes = raw_a,
            .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
            .raw_owned = true,
            .allocator = allocator,
        };
        defer storage_a.deinit();
        var storage_b = QuantizedStorage{
            .tensor_type = tensor_type,
            .raw_bytes = raw_b,
            .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
            .raw_owned = true,
            .allocator = allocator,
        };
        defer storage_b.deinit();
        var storage_c = QuantizedStorage{
            .tensor_type = tensor_type,
            .raw_bytes = raw_c,
            .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
            .raw_owned = true,
            .allocator = allocator,
        };
        defer storage_c.deinit();
        try prepareNativeQuantizedStorage(&storage_a);
        try prepareNativeQuantizedStorage(&storage_b);
        try prepareNativeQuantizedStorage(&storage_c);
        try std.testing.expect(storage_a.preparedBytes(.row_major_blocks) != null);
        try std.testing.expect(storage_a.preparedBytes(.panel4) != null);
        try std.testing.expect(storage_a.preparedBytes(.panel8) != null);
        try std.testing.expect(storage_a.preparedBytes(.panel16) != null);
        if (known == .Q3_K) {
            try std.testing.expect(storage_a.preparedBytes(.panel4_k16_no_min) != null);
        } else {
            try std.testing.expect(storage_a.preparedBytes(.panel4_k16_no_min) == null);
        }
        try std.testing.expectEqual(out_dim * row_blocks * prepared_k16_block_bytes, storage_a.preparedBytes(.row_major_blocks).?.len);
        try std.testing.expectEqual(preparedK16PanelByteSize(out_dim, row_blocks), storage_a.preparedBytes(.panel4).?.len);
        try std.testing.expectEqual(preparedK16Panel8ByteSize(out_dim, row_blocks), storage_a.preparedBytes(.panel8).?.len);
        try std.testing.expectEqual(preparedK16Panel16ByteSize(out_dim, row_blocks), storage_a.preparedBytes(.panel16).?.len);
        if (known == .Q3_K) try std.testing.expectEqual(preparedQ3KNoDmnPanelByteSize(out_dim, row_blocks), storage_a.preparedBytes(.panel4_k16_no_min).?.len);

        const q_input = try quantizeK16Activation(allocator, null, input, rows, in_dim, row_blocks);
        defer allocator.free(q_input);
        const row_major = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(row_major);
        const panel = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(panel);
        const panel8 = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(panel8);
        const panel16 = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(panel16);
        const q3_nodmn = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(q3_nodmn);
        const raw_direct = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(raw_direct);
        @memset(row_major, 0.0);
        @memset(panel, 0.0);
        @memset(panel8, 0.0);
        @memset(panel16, 0.0);
        @memset(q3_nodmn, 0.0);
        @memset(raw_direct, 0.0);
        k16PreparedQ8KActivationApply(known == .Q2_K, q_input, storage_a.preparedBytes(.row_major_blocks).?, null, null, null, row_major, rows, in_dim, out_dim, 0, out_dim);
        k16PreparedQ8KActivationApply(known == .Q2_K, q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), null, null, panel, rows, in_dim, out_dim, 0, out_dim);
        k16PreparedQ8KActivationApply(known == .Q2_K, q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_a.preparedBytes(.panel8), null, panel8, rows, in_dim, out_dim, 0, out_dim);
        k16PreparedQ8KActivationPanel16Apply(known == .Q2_K, q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel16).?, panel16, rows, in_dim, out_dim, 0, out_dim);
        if (known == .Q3_K) k16PreparedQ8KActivationQ3NoDmnPanelApply(q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4_k16_no_min).?, q3_nodmn, rows, in_dim, out_dim, 0, out_dim);
        k16RawQ8KActivationApply(known == .Q2_K, q_input, storage_a.raw_bytes, raw_direct, rows, in_dim, out_dim, 0, out_dim);
        for (panel, row_major) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
        for (panel8, row_major) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
        for (panel16, row_major) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
        if (known == .Q3_K) for (q3_nodmn, row_major) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
        for (raw_direct, row_major) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);

        const single_a = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(single_a);
        const single_b = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(single_b);
        const single_c = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(single_c);
        @memset(single_a, 0.0);
        @memset(single_b, 0.0);
        @memset(single_c, 0.0);
        try std.testing.expect(try linearNoBiasQuantized(null, &storage_a, input, single_a, rows, in_dim, out_dim));
        try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, input, single_b, rows, in_dim, out_dim));
        try std.testing.expect(try linearNoBiasQuantized(null, &storage_c, input, single_c, rows, in_dim, out_dim));
        for (single_a, panel16) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);

        const grouped_rows = 3;
        const grouped_out_start: usize = 1;
        const grouped_out_end: usize = out_dim - 1;
        const grouped_input = try allocator.alloc(f32, grouped_rows * in_dim);
        defer allocator.free(grouped_input);
        for (grouped_input, 0..) |*value, idx| {
            const signed: i32 = @intCast((idx * 13 + (idx / in_dim) * 5 + 11) % 47);
            value.* = @as(f32, @floatFromInt(signed - 23)) / 31.0;
        }
        const grouped_q_input = try quantizeK16Activation(allocator, null, grouped_input, grouped_rows, in_dim, row_blocks);
        defer allocator.free(grouped_q_input);
        const grouped_single_a = try allocator.alloc(f32, grouped_rows * out_dim);
        defer allocator.free(grouped_single_a);
        const grouped_single_b = try allocator.alloc(f32, grouped_rows * out_dim);
        defer allocator.free(grouped_single_b);
        const grouped_single_c = try allocator.alloc(f32, grouped_rows * out_dim);
        defer allocator.free(grouped_single_c);
        const grouped_pair_a = try allocator.alloc(f32, grouped_rows * out_dim);
        defer allocator.free(grouped_pair_a);
        const grouped_pair_b = try allocator.alloc(f32, grouped_rows * out_dim);
        defer allocator.free(grouped_pair_b);
        @memset(grouped_single_a, 0.0);
        @memset(grouped_single_b, 0.0);
        @memset(grouped_single_c, 0.0);
        @memset(grouped_pair_a, 0.0);
        @memset(grouped_pair_b, 0.0);
        k16PreparedQ8KActivationApply(known == .Q2_K, grouped_q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_a.preparedBytes(.panel8), null, grouped_single_a, grouped_rows, in_dim, out_dim, grouped_out_start, grouped_out_end);
        k16PreparedQ8KActivationApply(known == .Q2_K, grouped_q_input, storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), storage_b.preparedBytes(.panel8), null, grouped_single_b, grouped_rows, in_dim, out_dim, grouped_out_start, grouped_out_end);
        k16PreparedQ8KActivationApply(known == .Q2_K, grouped_q_input, storage_c.preparedBytes(.row_major_blocks).?, storage_c.preparedBytes(.panel4), storage_c.preparedBytes(.panel8), null, grouped_single_c, grouped_rows, in_dim, out_dim, grouped_out_start, grouped_out_end);
        k16PreparedQ8KActivationPairApply(known == .Q2_K, grouped_q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_a.preparedBytes(.panel8), storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), storage_b.preparedBytes(.panel8), grouped_pair_a, grouped_pair_b, grouped_rows, in_dim, out_dim, grouped_out_start, grouped_out_end);
        for (0..grouped_rows) |row_idx| {
            for (grouped_out_start..grouped_out_end) |out_idx| {
                const idx = row_idx * out_dim + out_idx;
                try std.testing.expectApproxEqAbs(grouped_single_a[idx], grouped_pair_a[idx], tolerance);
                try std.testing.expectApproxEqAbs(grouped_single_b[idx], grouped_pair_b[idx], tolerance);
            }
        }

        const pair_a = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(pair_a);
        const pair_b = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(pair_b);
        @memset(pair_a, 0.0);
        @memset(pair_b, 0.0);
        if (known == .Q3_K) {
            const q3_pair_a = try allocator.alloc(f32, rows * out_dim);
            defer allocator.free(q3_pair_a);
            const q3_pair_b = try allocator.alloc(f32, rows * out_dim);
            defer allocator.free(q3_pair_b);
            @memset(q3_pair_a, 0.0);
            @memset(q3_pair_b, 0.0);
            try linearNoBiasQ3KNoDmnPanelActivationPair(
                allocator,
                null,
                input,
                storage_a.preparedBytes(.row_major_blocks).?,
                storage_b.preparedBytes(.row_major_blocks).?,
                storage_a.preparedBytes(.panel4_k16_no_min).?,
                storage_b.preparedBytes(.panel4_k16_no_min).?,
                q3_pair_a,
                q3_pair_b,
                rows,
                in_dim,
                out_dim,
            );
            for (q3_pair_a, single_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
            for (q3_pair_b, single_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
        }
        try std.testing.expect(try linearNoBiasQuantizedPair(null, allocator, &storage_a, &storage_b, input, pair_a, pair_b, rows, in_dim, out_dim));
        for (pair_a, single_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
        for (pair_b, single_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);

        const bias_a = try allocator.alloc(f32, out_dim);
        defer allocator.free(bias_a);
        const bias_b = try allocator.alloc(f32, out_dim);
        defer allocator.free(bias_b);
        const bias_c = try allocator.alloc(f32, out_dim);
        defer allocator.free(bias_c);
        for (0..out_dim) |idx| {
            bias_a[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 5)) - 2)) / 17.0;
            bias_b[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 7)) - 3)) / 19.0;
            bias_c[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 11)) - 5)) / 23.0;
        }
        const triple_a = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(triple_a);
        const triple_b = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(triple_b);
        const triple_c = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(triple_c);
        @memset(triple_a, 0.0);
        @memset(triple_b, 0.0);
        @memset(triple_c, 0.0);
        try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, bias_a, bias_b, bias_c, triple_a, triple_b, triple_c, rows, in_dim, out_dim));
        for (triple_a, single_a, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_a[idx % out_dim], actual, tolerance);
        for (triple_b, single_b, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_b[idx % out_dim], actual, tolerance);
        for (triple_c, single_c, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_c[idx % out_dim], actual, tolerance);
        if (known == .Q3_K) {
            const q3_triple_a = try allocator.alloc(f32, rows * out_dim);
            defer allocator.free(q3_triple_a);
            const q3_triple_b = try allocator.alloc(f32, rows * out_dim);
            defer allocator.free(q3_triple_b);
            const q3_triple_c = try allocator.alloc(f32, rows * out_dim);
            defer allocator.free(q3_triple_c);
            @memset(q3_triple_a, 0.0);
            @memset(q3_triple_b, 0.0);
            @memset(q3_triple_c, 0.0);
            try linearQ3KNoDmnPanelActivationTriple(
                allocator,
                null,
                input,
                storage_a.preparedBytes(.row_major_blocks).?,
                storage_b.preparedBytes(.row_major_blocks).?,
                storage_c.preparedBytes(.row_major_blocks).?,
                storage_a.preparedBytes(.panel4_k16_no_min).?,
                storage_b.preparedBytes(.panel4_k16_no_min).?,
                storage_c.preparedBytes(.panel4_k16_no_min).?,
                bias_a,
                bias_b,
                bias_c,
                q3_triple_a,
                q3_triple_b,
                q3_triple_c,
                rows,
                in_dim,
                out_dim,
            );
            for (q3_triple_a, triple_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
            for (q3_triple_b, triple_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
            for (q3_triple_c, triple_c) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
        }

        const grouped_triple_a = try allocator.alloc(f32, grouped_rows * out_dim);
        defer allocator.free(grouped_triple_a);
        const grouped_triple_b = try allocator.alloc(f32, grouped_rows * out_dim);
        defer allocator.free(grouped_triple_b);
        const grouped_triple_c = try allocator.alloc(f32, grouped_rows * out_dim);
        defer allocator.free(grouped_triple_c);
        @memset(grouped_triple_a, 0.0);
        @memset(grouped_triple_b, 0.0);
        @memset(grouped_triple_c, 0.0);
        k16PreparedQ8KActivationTripleApply(known == .Q2_K, grouped_q_input, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_a.preparedBytes(.panel8), storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), storage_b.preparedBytes(.panel8), storage_c.preparedBytes(.row_major_blocks).?, storage_c.preparedBytes(.panel4), storage_c.preparedBytes(.panel8), bias_a, bias_b, bias_c, grouped_triple_a, grouped_triple_b, grouped_triple_c, grouped_rows, in_dim, out_dim, grouped_out_start, grouped_out_end);
        for (0..grouped_rows) |row_idx| {
            for (grouped_out_start..grouped_out_end) |out_idx| {
                const idx = row_idx * out_dim + out_idx;
                try std.testing.expectApproxEqAbs(grouped_single_a[idx] + bias_a[out_idx], grouped_triple_a[idx], tolerance);
                try std.testing.expectApproxEqAbs(grouped_single_b[idx] + bias_b[out_idx], grouped_triple_b[idx], tolerance);
                try std.testing.expectApproxEqAbs(grouped_single_c[idx] + bias_c[out_idx], grouped_triple_c[idx], tolerance);
            }
        }
    }
}

test "wide panel16 keeps k16 q8 force-only while q6 q3 auto-promote" {
    setK16Panel16DirectOverrideForBench(null);
    setQ6KPanel16DirectOverrideForBench(null);
    setQ8KPanel16DirectOverrideForBench(null);
    setQ3KNoDmnPanelOverrideForBench(null);
    defer setK16Panel16DirectOverrideForBench(null);
    defer setQ6KPanel16DirectOverrideForBench(null);
    defer setQ8KPanel16DirectOverrideForBench(null);
    defer setQ3KNoDmnPanelOverrideForBench(null);

    const out_dim: usize = 512;
    const row_blocks: usize = 3;

    try std.testing.expect(!k16Panel16PreparedEnabledFor(.Q2_K));
    try std.testing.expect(!k16Panel16PreparedEnabledFor(.Q3_K));
    try std.testing.expect(!k16Panel16SingleEnabledForShape(.Q2_K, 1, out_dim, row_blocks));
    try std.testing.expect(!k16Panel16SingleEnabledForShape(.Q2_K, 4, out_dim, row_blocks));
    try std.testing.expect(!k16Panel16SingleEnabledForShape(.Q2_K, 6, out_dim, row_blocks));
    try std.testing.expect(!k16Panel16SingleEnabledForShape(.Q2_K, 8, out_dim, row_blocks));
    try std.testing.expect(!k16Panel16SingleEnabledForShape(.Q3_K, 8, out_dim, row_blocks));
    try std.testing.expect(!k16Panel16SingleEnabledForShape(.Q3_K, 6, out_dim, row_blocks));

    try std.testing.expect(q6KPanel16PreparedEnabled());
    try std.testing.expect(q6KPanel16SingleEnabledForShape(6, out_dim, row_blocks));
    try std.testing.expect(q6KPanel16GroupedEnabledForShape(6, out_dim, row_blocks, 2));
    try std.testing.expect(q6KPanel16GroupedEnabledForShape(6, out_dim, row_blocks, 3));
    try std.testing.expect(shouldUseQ6KGroupedTriple(6));
    try std.testing.expect(!shouldUseQ6KGroupedTriple(77));
    try std.testing.expect(shouldUseQ6KSharedActivationTriple(6, out_dim, row_blocks));
    try std.testing.expect(!shouldUseQ6KSharedActivationTriple(77, out_dim, row_blocks));
    try std.testing.expect(!q8KPanel16PreparedEnabled());
    try std.testing.expect(!q8KPanel16SingleEnabledForShape(4, out_dim, row_blocks));
    try std.testing.expect(q3KNoDmnPanelPreparedEnabled());
    try std.testing.expect(!q3KNoDmnPanelSingleEnabledForShape(3, out_dim, row_blocks));
    try std.testing.expect(q3KNoDmnPanelSingleEnabledForShape(64, out_dim, row_blocks));
    try std.testing.expect(shouldUseQ8_0GroupedActivationPair(64, out_dim, row_blocks));
    try std.testing.expect(!shouldUseQ8_0GroupedActivationPair(77, out_dim, row_blocks));
    try std.testing.expect(shouldUseQ8_1GroupedActivationPair(77, out_dim, row_blocks));
    try std.testing.expect(!shouldUseQ8_1GroupedActivationPair(257, out_dim, row_blocks));
    try std.testing.expect(shouldUseQ8_1GroupedActivationTriple(64, out_dim, row_blocks));
    try std.testing.expect(!shouldUseQ8_1GroupedActivationTriple(77, out_dim, row_blocks));
    try std.testing.expect(shouldUseQ8_0GroupedActivationTriple(64, out_dim, row_blocks));
    try std.testing.expect(!shouldUseQ8_0GroupedActivationTriple(77, out_dim, row_blocks));
    try std.testing.expect(shouldUseQ8_0GroupedActivationTriple(257, out_dim, row_blocks));
    try std.testing.expect(q8_0GroupedInterleavedEnabledForShape(64, out_dim, row_blocks, 2));
    try std.testing.expect(!q8_0GroupedInterleavedEnabledForShape(77, out_dim, row_blocks, 2));
    try std.testing.expect(q8_0GroupedInterleavedEnabledForShape(77, out_dim, row_blocks, 3));
    try std.testing.expect(!q6KPanel16DirectEnabled());
    try std.testing.expect(!q8KPanel16DirectEnabled());

    setK16Panel16DirectOverrideForBench(false);
    setQ6KPanel16DirectOverrideForBench(false);
    setQ8KPanel16DirectOverrideForBench(false);
    setQ3KNoDmnPanelOverrideForBench(false);
    try std.testing.expect(!k16Panel16PreparedEnabledFor(.Q2_K));
    try std.testing.expect(!q6KPanel16PreparedEnabled());
    try std.testing.expect(!q8KPanel16PreparedEnabled());
    try std.testing.expect(!q3KNoDmnPanelPreparedEnabled());
    try std.testing.expect(!k16Panel16SingleEnabledForShape(.Q2_K, 1, out_dim, row_blocks));
    try std.testing.expect(!q6KPanel16SingleEnabledForShape(1, out_dim, row_blocks));
    try std.testing.expect(!q6KPanel16GroupedEnabledForShape(1, out_dim, row_blocks, 2));
    try std.testing.expect(!q8KPanel16SingleEnabledForShape(1, out_dim, row_blocks));
    try std.testing.expect(!q3KNoDmnPanelSingleEnabledForShape(64, out_dim, row_blocks));

    setK16Panel16DirectOverrideForBench(true);
    setQ6KPanel16DirectOverrideForBench(true);
    setQ8KPanel16DirectOverrideForBench(true);
    setQ3KNoDmnPanelOverrideForBench(true);
    try std.testing.expect(k16Panel16SingleEnabledForShape(.Q2_K, 6, out_dim, row_blocks));
    try std.testing.expect(q6KPanel16DirectEnabled());
    try std.testing.expect(q8KPanel16DirectEnabled());
    try std.testing.expect(q3KNoDmnPanelSingleEnabledForShape(3, out_dim, row_blocks));
}

test "q2_q3_k q3 no-dmn panel auto preparation is shape gated" {
    const allocator = std.testing.allocator;
    setQ3KNoDmnPanelOverrideForBench(null);
    defer setQ3KNoDmnPanelOverrideForBench(null);

    const in_dim: usize = 768;
    const row_blocks = in_dim / 256;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q3_K };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const Case = struct {
        out_dim: usize,
        expect_q3_panel: bool,
    };
    const cases = [_]Case{
        .{ .out_dim = 256, .expect_q3_panel = false },
        .{ .out_dim = 512, .expect_q3_panel = true },
    };

    for (cases) |case| {
        try std.testing.expectEqual(case.expect_q3_panel, q3KNoDmnPanelPreparedEnabledForShape(case.out_dim, row_blocks));
        const raw = try allocator.alloc(u8, case.out_dim * row_blocks * block_size);
        @memset(raw, 0);
        var storage = QuantizedStorage{
            .tensor_type = tensor_type,
            .raw_bytes = raw,
            .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(case.out_dim)), @as(i64, in_dim) }),
            .raw_owned = true,
            .allocator = allocator,
        };
        defer storage.deinit();

        try prepareNativeQuantizedStorage(&storage);
        try std.testing.expect(storage.preparedBytes(.row_major_blocks) != null);
        try std.testing.expect(storage.preparedBytes(.panel4) != null);
        try std.testing.expectEqual(case.expect_q3_panel, storage.preparedBytes(.panel4_k16_no_min) != null);
    }
}

test "q1_0 prepared activation paths are wired and panel-safe" {
    const allocator = std.testing.allocator;
    const rows = 1;
    const in_dim = 256;
    const out_dim = 512;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q1_0 };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const values_per_block = gguf_tensor_types.valuesPerBlock(tensor_type).?;
    const row_blocks = in_dim / values_per_block;
    const input_blocks = in_dim / 32;
    try std.testing.expect(shouldUseQ8_0ActivationQuant(rows, out_dim, input_blocks));

    const input = try allocator.alloc(f32, rows * in_dim);
    defer allocator.free(input);
    for (input, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 7 + 5) % 31);
        value.* = @as(f32, @floatFromInt(signed - 15)) / 19.0;
    }

    const raw_a = try allocator.alloc(u8, out_dim * row_blocks * block_size);
    const raw_b = try allocator.alloc(u8, out_dim * row_blocks * block_size);
    const raw_c = try allocator.alloc(u8, out_dim * row_blocks * block_size);
    var dense_block: [128]f32 = undefined;
    for (0..(out_dim * row_blocks)) |block_idx| {
        for (&dense_block, 0..) |*value, i| {
            const signed: i32 = @intCast((block_idx * 11 + i * 5 + 3) % 37);
            value.* = @as(f32, @floatFromInt(signed - 18)) / 23.0;
        }
        quant_codec.quantizeQ1_0Block(&dense_block, raw_a[block_idx * block_size ..][0..block_size]);
        for (&dense_block, 0..) |*value, i| {
            const signed: i32 = @intCast((block_idx * 13 + i * 7 + 17) % 41);
            value.* = @as(f32, @floatFromInt(signed - 20)) / 29.0;
        }
        quant_codec.quantizeQ1_0Block(&dense_block, raw_b[block_idx * block_size ..][0..block_size]);
        for (&dense_block, 0..) |*value, i| {
            const signed: i32 = @intCast((block_idx * 17 + i * 3 + 29) % 43);
            value.* = @as(f32, @floatFromInt(signed - 21)) / 31.0;
        }
        quant_codec.quantizeQ1_0Block(&dense_block, raw_c[block_idx * block_size ..][0..block_size]);
    }

    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_a,
        .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_a.deinit();
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_b,
        .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_b.deinit();
    var storage_c = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_c,
        .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_c.deinit();
    try prepareNativeQuantizedStorage(&storage_a);
    try prepareNativeQuantizedStorage(&storage_b);
    try prepareNativeQuantizedStorage(&storage_c);
    try std.testing.expect(storage_a.preparedBytes(.row_major_blocks) != null);
    try std.testing.expect(storage_a.preparedBytes(.panel4) != null);
    try std.testing.expectEqual(out_dim * row_blocks * prepared_q1_0_block_bytes, storage_a.preparedBytes(.row_major_blocks).?.len);
    try std.testing.expectEqual(preparedQ1_0PanelByteSize(out_dim, row_blocks), storage_a.preparedBytes(.panel4).?.len);

    const q = try quantizeQ1_0Activation(allocator, input, rows, in_dim);
    defer allocator.free(q.q_values);
    defer allocator.free(q.input_scales);
    const row_major = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(row_major);
    const panel = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(panel);
    @memset(row_major, 0.0);
    @memset(panel, 0.0);
    q1_0PreparedActivationApply(q.q_values, q.input_scales, storage_a.preparedBytes(.row_major_blocks).?, null, null, row_major, rows, in_dim, out_dim, 0, out_dim);
    q1_0PreparedActivationApply(q.q_values, q.input_scales, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), null, panel, rows, in_dim, out_dim, 0, out_dim);
    for (panel, row_major) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-6);

    const single = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(single);
    @memset(single, 0.0);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_a, input, single, rows, in_dim, out_dim));
    for (single, panel) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-6);

    const pair_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(pair_a);
    const pair_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(pair_b);
    @memset(pair_a, 0.0);
    @memset(pair_b, 0.0);
    try std.testing.expect(try linearNoBiasQuantizedPair(null, allocator, &storage_a, &storage_b, input, pair_a, pair_b, rows, in_dim, out_dim));
    const ref_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(ref_b);
    @memset(ref_b, 0.0);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, input, ref_b, rows, in_dim, out_dim));
    for (pair_a, single) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-6);
    for (pair_b, ref_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-6);

    const bias_a = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_a);
    const bias_b = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_b);
    const bias_c = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_c);
    for (0..out_dim) |idx| {
        bias_a[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 5)) - 2)) / 17.0;
        bias_b[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 7)) - 3)) / 19.0;
        bias_c[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 11)) - 5)) / 23.0;
    }
    const ref_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(ref_c);
    @memset(ref_c, 0.0);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_c, input, ref_c, rows, in_dim, out_dim));
    const triple_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(triple_a);
    const triple_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(triple_b);
    const triple_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(triple_c);
    @memset(triple_a, 0.0);
    @memset(triple_b, 0.0);
    @memset(triple_c, 0.0);
    try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, bias_a, bias_b, bias_c, triple_a, triple_b, triple_c, rows, in_dim, out_dim));
    for (triple_a, single, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_a[idx % out_dim], actual, 1e-6);
    for (triple_b, ref_b, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_b[idx % out_dim], actual, 1e-6);
    for (triple_c, ref_c, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_c[idx % out_dim], actual, 1e-6);

    const grouped_rows = 3;
    const grouped_out_start = 1;
    const grouped_out_end = out_dim - 1;
    const grouped_input = try allocator.alloc(f32, grouped_rows * in_dim);
    defer allocator.free(grouped_input);
    for (grouped_input, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 19 + 23) % 47);
        value.* = @as(f32, @floatFromInt(signed - 23)) / 37.0;
    }
    const grouped_q = try quantizeQ1_0Activation(allocator, grouped_input, grouped_rows, in_dim);
    defer allocator.free(grouped_q.q_values);
    defer allocator.free(grouped_q.input_scales);

    const grouped_single_a = try allocator.alloc(f32, grouped_rows * out_dim);
    defer allocator.free(grouped_single_a);
    const grouped_single_b = try allocator.alloc(f32, grouped_rows * out_dim);
    defer allocator.free(grouped_single_b);
    const grouped_single_c = try allocator.alloc(f32, grouped_rows * out_dim);
    defer allocator.free(grouped_single_c);
    @memset(grouped_single_a, 0.0);
    @memset(grouped_single_b, 0.0);
    @memset(grouped_single_c, 0.0);
    q1_0PreparedActivationApply(grouped_q.q_values, grouped_q.input_scales, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), null, grouped_single_a, grouped_rows, in_dim, out_dim, grouped_out_start, grouped_out_end);
    q1_0PreparedActivationApply(grouped_q.q_values, grouped_q.input_scales, storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), null, grouped_single_b, grouped_rows, in_dim, out_dim, grouped_out_start, grouped_out_end);
    q1_0PreparedActivationApply(grouped_q.q_values, grouped_q.input_scales, storage_c.preparedBytes(.row_major_blocks).?, storage_c.preparedBytes(.panel4), null, grouped_single_c, grouped_rows, in_dim, out_dim, grouped_out_start, grouped_out_end);

    const grouped_pair_a = try allocator.alloc(f32, grouped_rows * out_dim);
    defer allocator.free(grouped_pair_a);
    const grouped_pair_b = try allocator.alloc(f32, grouped_rows * out_dim);
    defer allocator.free(grouped_pair_b);
    @memset(grouped_pair_a, 0.0);
    @memset(grouped_pair_b, 0.0);
    q1_0PreparedActivationPairApply(grouped_q.q_values, grouped_q.input_scales, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), grouped_pair_a, grouped_pair_b, grouped_rows, in_dim, out_dim, grouped_out_start, grouped_out_end);

    const grouped_triple_a = try allocator.alloc(f32, grouped_rows * out_dim);
    defer allocator.free(grouped_triple_a);
    const grouped_triple_b = try allocator.alloc(f32, grouped_rows * out_dim);
    defer allocator.free(grouped_triple_b);
    const grouped_triple_c = try allocator.alloc(f32, grouped_rows * out_dim);
    defer allocator.free(grouped_triple_c);
    @memset(grouped_triple_a, 0.0);
    @memset(grouped_triple_b, 0.0);
    @memset(grouped_triple_c, 0.0);
    q1_0PreparedActivationTripleApply(grouped_q.q_values, grouped_q.input_scales, storage_a.preparedBytes(.row_major_blocks).?, storage_a.preparedBytes(.panel4), storage_b.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.panel4), storage_c.preparedBytes(.row_major_blocks).?, storage_c.preparedBytes(.panel4), bias_a, bias_b, bias_c, grouped_triple_a, grouped_triple_b, grouped_triple_c, grouped_rows, in_dim, out_dim, grouped_out_start, grouped_out_end);
    for (0..grouped_rows) |row_idx| {
        for (grouped_out_start..grouped_out_end) |out_idx| {
            const idx = row_idx * out_dim + out_idx;
            try std.testing.expectApproxEqAbs(grouped_single_a[idx], grouped_pair_a[idx], 1e-6);
            try std.testing.expectApproxEqAbs(grouped_single_b[idx], grouped_pair_b[idx], 1e-6);
            try std.testing.expectApproxEqAbs(grouped_single_a[idx] + bias_a[out_idx], grouped_triple_a[idx], 1e-6);
            try std.testing.expectApproxEqAbs(grouped_single_b[idx] + bias_b[out_idx], grouped_triple_b[idx], 1e-6);
            try std.testing.expectApproxEqAbs(grouped_single_c[idx] + bias_c[out_idx], grouped_triple_c[idx], 1e-6);
        }
    }
}

test "linear q8_0 pair kernel applies bias during writeback" {
    const allocator = std.testing.allocator;
    const rows = 3;
    const in_dim = 32;
    const out_dim = 2;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q8_0 };
    const block_size = 34;
    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 7);
        value.* = @floatFromInt(signed - 3);
    }

    var weight_raw_a: [68]u8 = [_]u8{0} ** 68;
    var weight_raw_b: [68]u8 = [_]u8{0} ** 68;
    for (0..out_dim) |row| {
        const base = row * block_size;
        weight_raw_a[base] = 0x00;
        weight_raw_a[base + 1] = 0x3C;
        weight_raw_b[base] = 0x00;
        weight_raw_b[base + 1] = 0x3C;
        for (0..32) |i| {
            const qa: i32 = @as(i32, @intCast(i % 5)) - 2;
            const qb: i32 = @as(i32, @intCast(i % 3)) + 1;
            weight_raw_a[base + 2 + i] = @bitCast(@as(i8, @intCast(qa)));
            weight_raw_b[base + 2 + i] = @bitCast(@as(i8, @intCast(qb)));
        }
    }

    const shape = [_]i64{ out_dim, in_dim };
    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = &weight_raw_a,
        .shape = &shape,
        .raw_owned = false,
        .allocator = allocator,
    };
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = &weight_raw_b,
        .shape = &shape,
        .raw_owned = false,
        .allocator = allocator,
    };

    const bias_a = [_]f32{ 0.25, -0.5 };
    const bias_b = [_]f32{ -0.75, 0.125 };
    var output_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var output_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try linearQ8_0Pair(allocator, null, &input, &weight_raw_a, &weight_raw_b, null, null, null, null, null, null, &bias_a, &bias_b, &output_a, &output_b, rows, in_dim, out_dim);

    var ref_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var ref_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_a, &input, &ref_a, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, &input, &ref_b, rows, in_dim, out_dim));
    addLinearBiasRows(&ref_a, &bias_a, rows, out_dim);
    addLinearBiasRows(&ref_b, &bias_b, rows, out_dim);

    for (output_a, ref_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
    for (output_b, ref_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
}

test "ComputeBackend linearTriple matches three biased linears" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);
    const cb = compute.computeBackend();

    var input_data = [_]f32{
        1.0,  2.0, 3.0,
        -1.0, 0.5, 4.0,
    };
    var weight_a_data = [_]f32{
        0.5, -1.0, 2.0,
        1.5, 0.25, -0.5,
    };
    var weight_b_data = [_]f32{
        -0.25, 0.75, 1.0,
        2.0,   -1.0, 0.5,
    };
    var weight_c_data = [_]f32{
        1.25, 0.0, -0.75,
        -0.5, 1.0, 1.5,
    };
    var bias_a_data = [_]f32{ 0.1, -0.2 };
    var bias_b_data = [_]f32{ -0.3, 0.4 };
    var bias_c_data = [_]f32{ 0.5, -0.6 };

    const input = try compute.makeBuf(&input_data, false);
    defer cb.free(input);
    const weight_a = try compute.makeBuf(&weight_a_data, false);
    defer cb.free(weight_a);
    const weight_b = try compute.makeBuf(&weight_b_data, false);
    defer cb.free(weight_b);
    const weight_c = try compute.makeBuf(&weight_c_data, false);
    defer cb.free(weight_c);
    const bias_a = try compute.makeBuf(&bias_a_data, false);
    defer cb.free(bias_a);
    const bias_b = try compute.makeBuf(&bias_b_data, false);
    defer cb.free(bias_b);
    const bias_c = try compute.makeBuf(&bias_c_data, false);
    defer cb.free(bias_c);

    const separate_a = try cb.linear(input, weight_a, bias_a, 2, 3, 2);
    defer cb.free(separate_a);
    const separate_b = try cb.linear(input, weight_b, bias_b, 2, 3, 2);
    defer cb.free(separate_b);
    const separate_c = try cb.linear(input, weight_c, bias_c, 2, 3, 2);
    defer cb.free(separate_c);

    const triple = try cb.linearTriple(input, weight_a, bias_a, weight_b, bias_b, weight_c, bias_c, 2, 3, 2);
    defer cb.free(triple.first);
    defer cb.free(triple.second);
    defer cb.free(triple.third);

    try std.testing.expectEqualSlices(f32, getData(separate_a), getData(triple.first));
    try std.testing.expectEqualSlices(f32, getData(separate_b), getData(triple.second));
    try std.testing.expectEqualSlices(f32, getData(separate_c), getData(triple.third));
}

test "ComputeBackend linearPair matches two biased linears" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);
