}

test "linear q8_0 triple kernel matches separate sibling matmuls" {
    const allocator = std.testing.allocator;
    const rows = 3;
    const in_dim = 32;
    const out_dim = 2;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q8_0 };
    const block_size = 34;
    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 7);
        value.* = @floatFromInt(signed - 3);
    }

    var weight_raw_a: [68]u8 = [_]u8{0} ** 68;
    var weight_raw_b: [68]u8 = [_]u8{0} ** 68;
    var weight_raw_c: [68]u8 = [_]u8{0} ** 68;
    for (0..out_dim) |row| {
        const base = row * block_size;
        weight_raw_a[base] = 0x00;
        weight_raw_a[base + 1] = 0x3C;
        weight_raw_b[base] = 0x00;
        weight_raw_b[base + 1] = 0x3C;
        weight_raw_c[base] = 0x00;
        weight_raw_c[base + 1] = 0x3C;
        for (0..32) |i| {
            const qa: i32 = @as(i32, @intCast(i % 5)) - 2;
            const qb: i32 = @as(i32, @intCast(i % 3)) + 1;
            const qc: i32 = @as(i32, @intCast((row + i) % 9)) - 4;
            weight_raw_a[base + 2 + i] = @bitCast(@as(i8, @intCast(qa)));
            weight_raw_b[base + 2 + i] = @bitCast(@as(i8, @intCast(qb)));
            weight_raw_c[base + 2 + i] = @bitCast(@as(i8, @intCast(qc)));
        }
    }

    const shape = [_]i64{ out_dim, in_dim };
    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = &weight_raw_a,
        .shape = &shape,
        .raw_owned = false,
        .allocator = allocator,
    };
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = &weight_raw_b,
        .shape = &shape,
        .raw_owned = false,
        .allocator = allocator,
    };
    var storage_c = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = &weight_raw_c,
        .shape = &shape,
        .raw_owned = false,
        .allocator = allocator,
    };

    var output_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var output_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var output_c: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    const bias_a = [_]f32{ 0.25, -0.5 };
    const bias_b = [_]f32{ -0.75, 0.125 };
    const bias_c = [_]f32{ 1.0, -1.25 };
    try std.testing.expect(try linearQuantizedTriple(
        null,
        &storage_a,
        &storage_b,
        &storage_c,
        &input,
        &bias_a,
        &bias_b,
        &bias_c,
        &output_a,
        &output_b,
        &output_c,
        rows,
        in_dim,
        out_dim,
    ));

    var ref_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var ref_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var ref_c: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_a, &input, &ref_a, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, &input, &ref_b, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_c, &input, &ref_c, rows, in_dim, out_dim));
    addLinearBiasRows(&ref_a, &bias_a, rows, out_dim);
    addLinearBiasRows(&ref_b, &bias_b, rows, out_dim);
    addLinearBiasRows(&ref_c, &bias_c, rows, out_dim);

    for (output_a, ref_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
    for (output_b, ref_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
    for (output_c, ref_c) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
}

test "q8_0 activation quant grouped pair and triple match separate matmuls" {
    const allocator = std.testing.allocator;
    const rows = 3;
    const in_dim = 96;
    const out_dim = 512;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q8_0 };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const values_per_block = gguf_tensor_types.valuesPerBlock(tensor_type).?;
    const row_blocks = in_dim / values_per_block;
    try std.testing.expect(shouldUseQ8_0ActivationQuant(rows, out_dim, row_blocks));

    const input = try allocator.alloc(f32, rows * in_dim);
    defer allocator.free(input);
    for (input, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 13 + 7) % 41);
        value.* = @as(f32, @floatFromInt(signed - 20)) / 31.0;
    }

    const raw_a = try allocator.alloc(u8, out_dim * row_blocks * block_size);
    const raw_b = try allocator.alloc(u8, out_dim * row_blocks * block_size);
    const raw_c = try allocator.alloc(u8, out_dim * row_blocks * block_size);
    var block_values: [32]f32 = undefined;
    for (0..(out_dim * row_blocks)) |block_idx| {
        for (&block_values, 0..) |*value, i| {
            const signed: i32 = @intCast((block_idx * 17 + i * 5 + 3) % 43);
            value.* = @as(f32, @floatFromInt(signed - 21)) / 29.0;
        }
        quant_codec.quantizeQ8_0Block(&block_values, raw_a[block_idx * block_size ..][0..block_size]);
        for (&block_values, 0..) |*value, i| {
            const signed: i32 = @intCast((block_idx * 19 + i * 7 + 11) % 47);
            value.* = @as(f32, @floatFromInt(signed - 23)) / 37.0;
        }
        quant_codec.quantizeQ8_0Block(&block_values, raw_b[block_idx * block_size ..][0..block_size]);
        for (&block_values, 0..) |*value, i| {
            const signed: i32 = @intCast((block_idx * 23 + i * 3 + 5) % 53);
            value.* = @as(f32, @floatFromInt(signed - 26)) / 41.0;
        }
        quant_codec.quantizeQ8_0Block(&block_values, raw_c[block_idx * block_size ..][0..block_size]);
    }

    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_a,
        .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_a.deinit();
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_b,
        .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_b.deinit();
    var storage_c = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_c,
        .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_c.deinit();

    const single_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(single_a);
    const single_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(single_b);
    const single_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(single_c);
    @memset(single_a, 0.0);
    @memset(single_b, 0.0);
    @memset(single_c, 0.0);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_a, input, single_a, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, input, single_b, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_c, input, single_c, rows, in_dim, out_dim));

    const pair_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(pair_a);
    const pair_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(pair_b);
    @memset(pair_a, 0.0);
    @memset(pair_b, 0.0);
    try std.testing.expect(try linearNoBiasQuantizedPair(null, allocator, &storage_a, &storage_b, input, pair_a, pair_b, rows, in_dim, out_dim));
    for (pair_a, single_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-5);
    for (pair_b, single_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-5);

    const bias_a = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_a);
    const bias_b = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_b);
    const bias_c = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_c);
    for (0..out_dim) |idx| {
        bias_a[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 13)) - 6)) / 53.0;
        bias_b[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 17)) - 8)) / 59.0;
        bias_c[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 19)) - 9)) / 61.0;
    }

    const triple_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(triple_a);
    const triple_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(triple_b);
    const triple_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(triple_c);
    @memset(triple_a, 0.0);
    @memset(triple_b, 0.0);
    @memset(triple_c, 0.0);
    try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, bias_a, bias_b, bias_c, triple_a, triple_b, triple_c, rows, in_dim, out_dim));
    for (triple_a, single_a, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_a[idx % out_dim], actual, 1e-5);
    for (triple_b, single_b, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_b[idx % out_dim], actual, 1e-5);
    for (triple_c, single_c, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_c[idx % out_dim], actual, 1e-5);
}

test "linear q8_1 kernel computes direct matmul" {
    var input: [32]f32 = [_]f32{1.0} ** 32;
    var output: [2]f32 = [_]f32{ 0.0, 0.0 };
    var weight_raw: [72]u8 = [_]u8{0} ** 72;

    // Row 0: scale 1.0, all quantized values 1.
    weight_raw[0] = 0x00;
    weight_raw[1] = 0x3C;
    for (0..32) |i| weight_raw[4 + i] = @bitCast(@as(i8, 1));

    // Row 1: scale 2.0, all quantized values 2.
    weight_raw[36] = 0x00;
    weight_raw[37] = 0x40;
    for (0..32) |i| weight_raw[40 + i] = @bitCast(@as(i8, 2));

    try linearNoBiasQuantizedGeneric(null, &input, &weight_raw, &output, 1, 32, 2, .{ .known = .Q8_1 }, &dotQ8_1Block);
    try std.testing.expectApproxEqAbs(@as(f32, 32.0), output[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 128.0), output[1], 1e-4);
}

test "linear i2_s kernel computes direct matmul" {
    var input: [128]f32 = [_]f32{1.0} ** 128;
    var output: [2]f32 = [_]f32{ 0.0, 0.0 };
    var weight_raw: [64]u8 = [_]u8{0} ** 64;

    // Row 0: all packed ternary codes decode to +1.
    for (0..32) |i| weight_raw[i] = 0b10_10_10_10;

    // Row 1: all packed ternary codes decode to -1.
    for (32..64) |i| weight_raw[i] = 0b00_00_00_00;

    const shape = [_]i64{ 2, 128 };
    var storage: QuantizedStorage = .{
        .tensor_type = .{ .known = .I2_S },
        .raw_bytes = &weight_raw,
        .shape = &shape,
        .raw_owned = false,
        .allocator = std.testing.allocator,
    };

    try std.testing.expect(try linearNoBiasQuantized(null, &storage, &input, &output, 1, 128, 2));
    try std.testing.expectApproxEqAbs(@as(f32, 128.0), output[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, -128.0), output[1], 1e-4);
}

