test "linear q4_0 kernel computes direct matmul" {
    var input: [32]f32 = [_]f32{1.0} ** 32;
    var output: [2]f32 = [_]f32{ 0.0, 0.0 };
    var weight_raw: [36]u8 = [_]u8{0x88} ** 36;

    // Row 0: scale 1.0, all quantized values decode to 0.
    weight_raw[0] = 0x00;
    weight_raw[1] = 0x3C;

    // Row 1: scale 1.0, all quantized values decode to 1.
    weight_raw[18] = 0x00;
    weight_raw[19] = 0x3C;
    for (20..36) |i| weight_raw[i] = 0x99;

    try linearNoBiasQuantizedGeneric(null, &input, &weight_raw, &output, 1, 32, 2, .{ .known = .Q4_0 }, &dotQ4_0Block);
    try std.testing.expectApproxEqAbs(@as(f32, 0.0), output[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 32.0), output[1], 1e-4);
}

test "linear q4_0 kernel uses low-half then high-half nibble order" {
    var input: [32]f32 = [_]f32{0.0} ** 32;
    input[0] = 1.0;
    input[1] = 1.0;
    input[16] = 1.0;
    input[17] = 1.0;
    var output: [1]f32 = .{0.0};
    var weight_raw: [18]u8 = [_]u8{0x88} ** 18;
    weight_raw[0] = 0x00;
    weight_raw[1] = 0x3C; // d = 1.0
    weight_raw[2] = 0x10;
    weight_raw[3] = 0x32;

    try linearNoBiasQuantizedGeneric(null, &input, &weight_raw, &output, 1, 32, 1, .{ .known = .Q4_0 }, &dotQ4_0Block);
    try std.testing.expectApproxEqAbs(@as(f32, -26.0), output[0], 1e-4);
}

test "linear q4_1 kernel computes direct matmul" {
    var input: [32]f32 = [_]f32{1.0} ** 32;
    var output: [2]f32 = [_]f32{ 0.0, 0.0 };
    var weight_raw: [40]u8 = [_]u8{0x11} ** 40;

    // Row 0: d=2.0, m=1.0, all quantized values decode to 3.
    weight_raw[0] = 0x00;
    weight_raw[1] = 0x40;
    weight_raw[2] = 0x00;
    weight_raw[3] = 0x3C;

    // Row 1: d=1.0, m=2.0, all quantized values decode to 3.
    weight_raw[20] = 0x00;
    weight_raw[21] = 0x3C;
    weight_raw[22] = 0x00;
    weight_raw[23] = 0x40;

    try linearNoBiasQuantizedGeneric(null, &input, &weight_raw, &output, 1, 32, 2, .{ .known = .Q4_1 }, &dotQ4_1Block);
    try std.testing.expectApproxEqAbs(@as(f32, 96.0), output[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 96.0), output[1], 1e-4);
}

test "linear q4_1 kernel uses low-half then high-half nibble order" {
