test "linear q5_1 kernel computes direct matmul" {
    var input: [32]f32 = [_]f32{1.0} ** 32;
    var output: [2]f32 = [_]f32{ 0.0, 0.0 };
    var weight_raw: [48]u8 = [_]u8{0x11} ** 48;

    // Row 0: d=2.0, m=1.0, all low 4-bit values decode to 3.
    weight_raw[0] = 0x00;
    weight_raw[1] = 0x40;
    weight_raw[2] = 0x00;
    weight_raw[3] = 0x3C;
    @memset(weight_raw[4..8], 0);

    // Row 1: d=1.0, m=2.0, all low 4-bit values decode to 3.
    weight_raw[24] = 0x00;
    weight_raw[25] = 0x3C;
    weight_raw[26] = 0x00;
    weight_raw[27] = 0x40;
    @memset(weight_raw[28..32], 0);

    try linearNoBiasQuantizedGeneric(null, &input, &weight_raw, &output, 1, 32, 2, .{ .known = .Q5_1 }, &dotQ5_1Block);
    try std.testing.expectApproxEqAbs(@as(f32, 96.0), output[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 96.0), output[1], 1e-4);
}

