test "linear q4_0 kernel matches dense dequantized matmul for multi-row matrix" {
    const allocator = std.testing.allocator;
    const rows: usize = 3;
    const in_dim: usize = 96;
    const out_dim: usize = 11;
    const block_size = gguf_tensor_types.bytesPerBlock(.{ .known = .Q4_0 }).?;
    const blocks_per_row = in_dim / 32;

    var prng = std.Random.DefaultPrng.init(0x5EED1234);
    const random = prng.random();

    const input = try allocator.alloc(f32, rows * in_dim);
    defer allocator.free(input);
    for (input) |*value| value.* = random.float(f32) * 2.0 - 1.0;

    const raw_len = out_dim * blocks_per_row * block_size;
    const weight_raw = try allocator.alloc(u8, raw_len);
    defer allocator.free(weight_raw);
    for (weight_raw, 0..) |*byte, idx| {
        byte.* = @truncate((idx * 37 + 11) & 0xFF);
    }
    for (0..out_dim * blocks_per_row) |block_index| {
        const base = block_index * block_size;
        weight_raw[base] = 0x00;
        weight_raw[base + 1] = 0x3C; // d = 1.0
    }

    const output_quant = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(output_quant);
    @memset(output_quant, 0.0);
    try linearNoBiasQuantizedGeneric(
        null,
        input,
        weight_raw,
        output_quant,
        rows,
        in_dim,
        out_dim,
        .{ .known = .Q4_0 },
        &dotQ4_0Block,
    );

    const dense_weight = try allocator.alloc(f32, out_dim * in_dim);
    defer allocator.free(dense_weight);
    try quant_codec.dequantizeToFloat32(.{ .known = .Q4_0 }, weight_raw, dense_weight);

    const output_dense = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(output_dense);
    @memset(output_dense, 0.0);
    native.sgemmTransBSync(rows, out_dim, in_dim, 1.0, input, dense_weight, 0.0, output_dense);

    for (output_quant, output_dense) |actual, expected| {
        try std.testing.expectApproxEqAbs(expected, actual, 1e-3);
    }
}

test "linear q4_0 pair kernel matches separate sibling matmuls" {
    const allocator = std.testing.allocator;
    const rows: usize = 2;
    const in_dim: usize = 64;
    const out_dim: usize = 3;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q4_0 };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const blocks_per_row = in_dim / gguf_tensor_types.valuesPerBlock(tensor_type).?;

    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 15);
        value.* = @floatFromInt(signed - 7);
    }

    const raw_len = out_dim * blocks_per_row * block_size;
    const weight_raw_a = try allocator.alloc(u8, raw_len);
    defer allocator.free(weight_raw_a);
    const weight_raw_b = try allocator.alloc(u8, raw_len);
    defer allocator.free(weight_raw_b);
    for (weight_raw_a, 0..) |*byte, idx| byte.* = @truncate((idx * 37 + 11) & 0xFF);
    for (weight_raw_b, 0..) |*byte, idx| byte.* = @truncate((idx * 29 + 7) & 0xFF);
    for (0..out_dim * blocks_per_row) |block_index| {
        const base = block_index * block_size;
        weight_raw_a[base] = 0x00;
        weight_raw_a[base + 1] = 0x3C;
        weight_raw_b[base] = 0x00;
        weight_raw_b[base + 1] = 0x3C;
    }

    const shape = [_]i64{ out_dim, in_dim };
    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw_a,
        .shape = &shape,
        .raw_owned = false,
        .allocator = allocator,
    };
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw_b,
        .shape = &shape,
        .raw_owned = false,
        .allocator = allocator,
    };

    var output_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var output_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantizedPair(null, allocator, &storage_a, &storage_b, &input, &output_a, &output_b, rows, in_dim, out_dim));

    var ref_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var ref_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_a, &input, &ref_a, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, &input, &ref_b, rows, in_dim, out_dim));

    for (output_a, ref_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
    for (output_b, ref_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
}

test "linear packed q8_0 kernel computes direct matmul" {
    var input: [32]f32 = [_]f32{1.0} ** 32;
    var output: [2]f32 = [_]f32{ 0.0, 0.0 };
    var weight_raw: [136]u8 = [_]u8{0} ** 136;

    // Layout shape [2 rows, 2 experts, 32 in_dim] with expert axis = 1.
    // Row 0, expert 1 -> all quantized values 3.
    weight_raw[34] = 0x00;
    weight_raw[35] = 0x3C;
    for (0..32) |i| weight_raw[36 + i] = @bitCast(@as(i8, 3));

    // Row 1, expert 1 -> all quantized values 4.
    weight_raw[102] = 0x00;
    weight_raw[103] = 0x3C;
    for (0..32) |i| weight_raw[104 + i] = @bitCast(@as(i8, 4));

    const storage = QuantizedStorage{
        .tensor_type = .{ .known = .Q8_0 },
        .raw_bytes = &weight_raw,
        .shape = &.{ 2, 2, 32 },
        .packed_expert = .{
            .expert_index = 1,
            .expert_count = 2,
            .expert_axis = 1,
        },
        .allocator = std.testing.allocator,
    };

    try linearNoBiasPackedQuantized(&input, &storage, storage.packed_expert.?, &output, 1, 32, 2, .{ .known = .Q8_0 });
    try std.testing.expectApproxEqAbs(@as(f32, 96.0), output[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 128.0), output[1], 1e-4);
}

test "linear packed q8_0 kernel supports ggml expert-last layout" {
    var input: [32]f32 = [_]f32{1.0} ** 32;
    var output: [2]f32 = [_]f32{ 0.0, 0.0 };
    var weight_raw: [136]u8 = [_]u8{0} ** 136;
    const block_size = gguf_tensor_types.bytesPerBlock(.{ .known = .Q8_0 }).?;
    const out_dim = 2;
    const expert = 1;

    // GGML stores quantized blocks with the input axis first:
    // [32 in_dim, 2 rows, 2 experts]. Select expert 1.
    var base = (0 + out_dim * expert) * block_size;
    weight_raw[base] = 0x00;
    weight_raw[base + 1] = 0x3C;
    for (0..32) |i| weight_raw[base + 2 + i] = @bitCast(@as(i8, 3));

    base = (1 + out_dim * expert) * block_size;
    weight_raw[base] = 0x00;
    weight_raw[base + 1] = 0x3C;
    for (0..32) |i| weight_raw[base + 2 + i] = @bitCast(@as(i8, 4));

    const storage = QuantizedStorage{
        .tensor_type = .{ .known = .Q8_0 },
        .raw_bytes = &weight_raw,
        .shape = &.{ 32, 2, 2 },
        .packed_expert = .{
            .expert_index = expert,
            .expert_count = 2,
            .expert_axis = 2,
        },
        .allocator = std.testing.allocator,
    };

    try linearNoBiasPackedQuantized(&input, &storage, storage.packed_expert.?, &output, 1, 32, 2, .{ .known = .Q8_0 });
    try std.testing.expectApproxEqAbs(@as(f32, 96.0), output[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 128.0), output[1], 1e-4);
}

test "native mulMatId supports ggml expert-last dense layout" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{
        .allocator = allocator,
        .resident_weights = .{},
        .lazy_weights = .{},
    };
    var compute = NativeCompute.init(allocator, &weight_store, null);
    var cb = compute.computeBackend();

    const input_ct = try fromFloat32ShapeOp(&compute, &.{ 1.0, 2.0, 3.0, 4.0 }, &.{ 2, 2 });
    defer freeTensor(&compute, input_ct);

    var weight: [8]f32 = [_]f32{0.0} ** 8;
    const experts = 2;
    const out_dim = 2;
    weight[(0 * out_dim + 0) * experts + 0] = 1.0;
    weight[(1 * out_dim + 0) * experts + 0] = 2.0;
    weight[(0 * out_dim + 1) * experts + 0] = 3.0;
    weight[(1 * out_dim + 1) * experts + 0] = 4.0;
    weight[(0 * out_dim + 0) * experts + 1] = 10.0;
    weight[(1 * out_dim + 0) * experts + 1] = 20.0;
    weight[(0 * out_dim + 1) * experts + 1] = 30.0;
    weight[(1 * out_dim + 1) * experts + 1] = 40.0;

    const weight_ct = try fromFloat32ShapeOp(&compute, &weight, &.{ 2, 2, 2 });
    defer freeTensor(&compute, weight_ct);

    const out_ct = (try cb.mulMatId(&.{
        .input = input_ct,
        .expert_ids = &.{ 1, 0 },
        .weight = weight_ct,
        .rows = 2,
        .in_dim = 2,
        .out_dim = 2,
    })).?;
    defer freeTensor(&compute, out_ct);

    const out = getData(out_ct);
    try std.testing.expectApproxEqAbs(@as(f32, 50.0), out[0], 1e-5);
    try std.testing.expectApproxEqAbs(@as(f32, 110.0), out[1], 1e-5);
    try std.testing.expectApproxEqAbs(@as(f32, 11.0), out[2], 1e-5);
    try std.testing.expectApproxEqAbs(@as(f32, 25.0), out[3], 1e-5);
}

test "native mulMatId keeps ggml expert-last q8_0 layout quantized" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{
        .allocator = allocator,
        .resident_weights = .{},
        .lazy_weights = .{},
    };
    var compute = NativeCompute.init(allocator, &weight_store, null);
    var cb = compute.computeBackend();

    var input_data: [64]f32 = [_]f32{1.0} ** 64;
    const input_ct = try compute.makeBuf(&input_data, false);
    defer freeTensor(&compute, input_ct);

    var weight_raw: [136]u8 = [_]u8{0} ** 136;
    const block_size = gguf_tensor_types.bytesPerBlock(.{ .known = .Q8_0 }).?;
    const out_dim = 2;
    for (0..2) |expert| {
        for (0..out_dim) |row| {
            const base = (row + out_dim * expert) * block_size;
            weight_raw[base] = 0x00;
            weight_raw[base + 1] = 0x3C;
            const value: i8 = @intCast(expert * 2 + row + 1);
            for (0..32) |i| weight_raw[base + 2 + i] = @bitCast(value);
        }
    }

    const shape = [_]i64{ 32, 2, 2 };
    const storage = QuantizedStorage{
        .tensor_type = .{ .known = .Q8_0 },
        .raw_bytes = &weight_raw,
        .shape = &shape,
        .packed_expert = .{
            .expert_index = 0,
            .expert_count = 2,
            .expert_axis = 2,
        },
        .raw_owned = false,
        .allocator = allocator,
    };
    const weight_ct = try compute.makeBufWithEntry(empty_f32[0..], false, "q8_moe.weight", null, &storage, null);
    defer freeTensor(&compute, weight_ct);

    const out_ct = (try cb.mulMatId(&.{
        .input = input_ct,
        .expert_ids = &.{ 1, 0 },
        .weight = weight_ct,
        .rows = 2,
        .in_dim = 32,
        .out_dim = out_dim,
    })).?;
    defer freeTensor(&compute, out_ct);

    const out = getData(out_ct);
    try std.testing.expectApproxEqAbs(@as(f32, 96.0), out[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 128.0), out[1], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 32.0), out[2], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 64.0), out[3], 1e-4);
}

test "linear q2_k kernel computes direct matmul" {
    var input: [256]f32 = [_]f32{1.0} ** 256;
    var output: [2]f32 = [_]f32{ 0.0, 0.0 };
    var weight_raw: [168]u8 = [_]u8{0} ** 168;

    for (0..16) |i| weight_raw[i] = 0x22; // scale 2, min 2
    weight_raw[16] = 0x00;
    weight_raw[17] = 0x3C;
    for (20..84) |i| weight_raw[i] = 0xAA; // all q = 2

    const row1 = 84;
    for (0..16) |i| weight_raw[row1 + i] = 0x31; // scale 1, min 3
    weight_raw[row1 + 16] = 0x00;
    weight_raw[row1 + 17] = 0x3C;
    for (row1 + 20..row1 + 84) |i| weight_raw[i] = 0x55; // all q = 1

    try linearNoBiasQuantizedGeneric(null, &input, &weight_raw, &output, 1, 256, 2, .{ .known = .Q2_K }, &dotQ2_KBlock);
    try std.testing.expectApproxEqAbs(@as(f32, 1024.0), output[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 256.0), output[1], 1e-4);
}

test "linear q3_k kernel computes direct matmul" {
    var input: [256]f32 = [_]f32{1.0} ** 256;
    var output: [2]f32 = [_]f32{ 0.0, 0.0 };
    var weight_raw: [220]u8 = [_]u8{0} ** 220;

    for (96..108) |i| weight_raw[i] = 0xAA; // scale 42 -> 10 after centering
    weight_raw[108] = 0x00;
    weight_raw[109] = 0x3C;

    const row1 = 110;
    for (row1 + 96..row1 + 108) |i| weight_raw[i] = 0x88; // scale 8 -> -24 after centering
    weight_raw[row1 + 108] = 0x00;
    weight_raw[row1 + 109] = 0x3C;

    try linearNoBiasQuantizedGeneric(null, &input, &weight_raw, &output, 1, 256, 2, .{ .known = .Q3_K }, &dotQ3_KBlock);
    try std.testing.expectApproxEqAbs(@as(f32, -10240.0), output[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 8192.0), output[1], 1e-4);
}

test "linear q4_1 pair kernel matches separate sibling matmuls" {
    const allocator = std.testing.allocator;
    const rows: usize = 2;
    const in_dim: usize = 64;
    const out_dim: usize = 3;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q4_1 };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const blocks_per_row = in_dim / gguf_tensor_types.valuesPerBlock(tensor_type).?;

    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 11);
        value.* = @floatFromInt(signed - 5);
    }

    const raw_len = out_dim * blocks_per_row * block_size;
    const weight_raw_a = try allocator.alloc(u8, raw_len);
    defer allocator.free(weight_raw_a);
    const weight_raw_b = try allocator.alloc(u8, raw_len);
    defer allocator.free(weight_raw_b);
    for (weight_raw_a, 0..) |*byte, idx| byte.* = @truncate((idx * 13 + 5) & 0xFF);
    for (weight_raw_b, 0..) |*byte, idx| byte.* = @truncate((idx * 19 + 7) & 0xFF);
    for (0..out_dim * blocks_per_row) |block_index| {
        const base = block_index * block_size;
        weight_raw_a[base] = 0x00;
        weight_raw_a[base + 1] = 0x3C;
        weight_raw_a[base + 2] = 0x00;
        weight_raw_a[base + 3] = 0x00;
        weight_raw_b[base] = 0x00;
        weight_raw_b[base + 1] = 0x3C;
        weight_raw_b[base + 2] = 0x00;
        weight_raw_b[base + 3] = 0x00;
    }

    const shape = [_]i64{ out_dim, in_dim };
    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw_a,
        .shape = &shape,
        .raw_owned = false,
        .allocator = allocator,
    };
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw_b,
        .shape = &shape,
        .raw_owned = false,
        .allocator = allocator,
    };

    var output_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var output_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantizedPair(null, allocator, &storage_a, &storage_b, &input, &output_a, &output_b, rows, in_dim, out_dim));

    var ref_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var ref_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_a, &input, &ref_a, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, &input, &ref_b, rows, in_dim, out_dim));

    for (output_a, ref_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
    for (output_b, ref_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
}

test "linear q4_k kernel computes direct matmul" {
    var input: [256]f32 = [_]f32{1.0} ** 256;
    var output: [2]f32 = [_]f32{ 0.0, 0.0 };
    var weight_raw: [288]u8 = [_]u8{0} ** 288;

    weight_raw[0] = 0x00;
    weight_raw[1] = 0x3C;
    for (0..4) |i| weight_raw[4 + i] = 1;
    for (0..4) |i| weight_raw[12 + i] = 1;
    for (16..144) |i| weight_raw[i] = 0x11;

    const row1 = 144;
    weight_raw[row1 + 0] = 0x00;
    weight_raw[row1 + 1] = 0x3C;
    for (0..4) |i| weight_raw[row1 + 4 + i] = 1;
    for (0..4) |i| weight_raw[row1 + 12 + i] = 1;
    for (row1 + 16..row1 + 144) |i| weight_raw[i] = 0x22;

    try linearNoBiasQuantizedGeneric(null, &input, &weight_raw, &output, 1, 256, 2, .{ .known = .Q4_K }, &dotQ4_KBlock);
    try std.testing.expectApproxEqAbs(@as(f32, 256.0), output[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 512.0), output[1], 1e-4);
}

test "prepared q4_k headers preserve quantized linear output" {
    const allocator = std.testing.allocator;
    const rows = 2;
    const in_dim = 256;
    const out_dim = 3;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q4_K };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const block_count = out_dim;

    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 17);
        value.* = @floatFromInt(signed - 8);
    }

    const weight_raw = try allocator.alloc(u8, out_dim * block_size);
    defer allocator.free(weight_raw);
    for (weight_raw, 0..) |*byte, idx| byte.* = @truncate((idx * 29 + 7) & 0xFF);
    for (0..out_dim) |row| {
        const base = row * block_size;
        weight_raw[base] = 0x00;
        weight_raw[base + 1] = 0x3C;
        weight_raw[base + 2] = 0x00;
        weight_raw[base + 3] = 0x3C;
    }

    var storage = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw,
        .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
        .raw_owned = false,
        .allocator = allocator,
    };
    defer storage.deinit();

    try prepareNativeQuantizedStorage(&storage);
    try std.testing.expect(storage.preparedBytes(.row_major_blocks) != null);
    try std.testing.expectEqual(block_count * prepared_q4_k_block_bytes, storage.preparedBytes(.row_major_blocks).?.len);

    var prepared_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage, &input, &prepared_output, rows, in_dim, out_dim));

    var raw_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try linearNoBiasQuantizedGeneric(null, &input, weight_raw, &raw_output, rows, in_dim, out_dim, tensor_type, &dotQ4_KBlock);

    for (prepared_output, raw_output) |actual, expected| {
        try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
    }
}

test "q4_q5_k prepared panel f32 path matches row-major prepared path" {
    const allocator = std.testing.allocator;
    const rows = 1;
    const in_dim = 256;
    const out_dim = 8;
    const formats = [_]gguf_tensor_types.KnownTensorType{ .Q4_K, .Q5_K };

    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 7 + 5) % 31);
        value.* = @as(f32, @floatFromInt(signed - 15)) / 19.0;
    }

    inline for (formats) |known| {
        const tensor_type: gguf_tensor_types.TensorType = .{ .known = known };
        const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
        const row_blocks = in_dim / 256;
        const weight_raw = try allocator.alloc(u8, out_dim * row_blocks * block_size);
        var dense_block: [256]f32 = undefined;
        for (0..(out_dim * row_blocks)) |block_idx| {
            for (&dense_block, 0..) |*value, i| {
                const signed: i32 = @intCast((block_idx * 11 + i * 5 + @intFromEnum(known)) % 41);
                value.* = @as(f32, @floatFromInt(signed - 20)) / 23.0;
            }
            const dst = weight_raw[block_idx * block_size ..][0..block_size];
            switch (known) {
                .Q4_K => quant_codec.quantizeQ4_KBlock(&dense_block, dst),
                .Q5_K => quant_codec.quantizeQ5_KBlock(&dense_block, dst),
                else => unreachable,
            }
        }

        var storage = QuantizedStorage{
            .tensor_type = tensor_type,
            .raw_bytes = weight_raw,
            .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
            .raw_owned = true,
            .allocator = allocator,
        };
        defer storage.deinit();
        try prepareNativeQuantizedStorage(&storage);
        try std.testing.expect(storage.preparedBytes(.row_major_blocks) != null);
        try std.testing.expect(storage.preparedBytes(.panel4) != null);

        var row_major: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
        try linearNoBiasQ4KPrepared(null, &input, storage.preparedBytes(.row_major_blocks).?, &row_major, rows, in_dim, out_dim);
        var panel: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
        try linearNoBiasQ4Q5KPreparedPanel(&input, storage.preparedBytes(.row_major_blocks).?, storage.preparedBytes(.panel4).?, &panel, rows, in_dim, out_dim);
        for (panel, row_major) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-5);
    }
}

