        const signed_c: i32 = @intCast((idx * 19 + 29) % 53);
        weight_f32_a[idx] = @as(f32, @floatFromInt(signed_a - 20)) / 23.0;
        weight_f32_b[idx] = @as(f32, @floatFromInt(signed_b - 21)) / 29.0;
