        .tensor_type = tensor_type,
        .raw_bytes = raw_c,
        .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(out_dim)), @as(i64, @intCast(in_dim)) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_c.deinit();
    try prepareNativeQuantizedStorage(&storage_a);
    try prepareNativeQuantizedStorage(&storage_b);
    try prepareNativeQuantizedStorage(&storage_c);
    try preparePreparedKPanel16PackedStorage(&storage_a);
    try preparePreparedKPanel16PackedStorage(&storage_b);
    try preparePreparedKPanel16PackedStorage(&storage_c);
    try std.testing.expect(storage_a.preparedBytes(.row_major_blocks) != null);
    try std.testing.expect(storage_b.preparedBytes(.row_major_blocks) != null);
    try std.testing.expect(storage_c.preparedBytes(.row_major_blocks) != null);
    try std.testing.expect(storage_a.preparedBytes(.panel4) != null);
    try std.testing.expect(storage_b.preparedBytes(.panel4) != null);
