            try std.testing.expectApproxEqAbs(direct_single_b[idx], direct_triple_b[idx], 1e-6);
            try std.testing.expectApproxEqAbs(direct_single_c[idx], direct_triple_c[idx], 1e-6);
        }
    }

    const routed_single_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(routed_single_a);
    const routed_single_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(routed_single_b);
    const routed_single_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(routed_single_c);
    const routed_pair_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(routed_pair_a);
    const routed_pair_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(routed_pair_b);
    @memset(routed_single_a, 0.0);
    @memset(routed_single_b, 0.0);
