    try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, input, routed_single_b, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_c, input, routed_single_c, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantizedPair(null, allocator, &storage_a, &storage_b, input, routed_pair_a, routed_pair_b, rows, in_dim, out_dim));
    for (routed_pair_a, routed_single_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-6);
    for (routed_pair_b, routed_single_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-6);

    const bias_a = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_a);
    const bias_b = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_b);
    const bias_c = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_c);
    for (0..out_dim) |idx| {
        bias_a[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 5)) - 2)) / 17.0;
        bias_b[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 7)) - 3)) / 19.0;
        bias_c[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 11)) - 5)) / 23.0;
    }
    const routed_triple_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(routed_triple_a);
    const routed_triple_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(routed_triple_b);
    const routed_triple_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(routed_triple_c);
    @memset(routed_triple_a, 0.0);
    @memset(routed_triple_b, 0.0);
    @memset(routed_triple_c, 0.0);
    try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, bias_a, bias_b, bias_c, routed_triple_a, routed_triple_b, routed_triple_c, rows, in_dim, out_dim));
    for (routed_triple_a, routed_single_a, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_a[idx % out_dim], actual, 1e-6);
    for (routed_triple_b, routed_single_b, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_b[idx % out_dim], actual, 1e-6);
    for (routed_triple_c, routed_single_c, 0..) |actual, expected_no_bias, idx| try std.testing.expectApproxEqAbs(expected_no_bias + bias_c[idx % out_dim], actual, 1e-6);

    @memset(storage_a.preparedBytes(.row_major_blocks).?, 0xA5);
    @memset(storage_b.preparedBytes(.row_major_blocks).?, 0xA5);
    @memset(storage_c.preparedBytes(.row_major_blocks).?, 0xA5);
    @memset(storage_a.preparedBytes(.panel4).?, 0xA5);
    @memset(storage_b.preparedBytes(.panel4).?, 0xA5);
    @memset(storage_c.preparedBytes(.panel4).?, 0xA5);
    @memset(storage_a.preparedBytes(.panel8).?, 0xA5);
    @memset(storage_b.preparedBytes(.panel8).?, 0xA5);
    @memset(storage_c.preparedBytes(.panel8).?, 0xA5);
    @memset(direct_pair_a, 0.0);
    @memset(direct_pair_b, 0.0);
    @memset(direct_triple_a, 0.0);
    @memset(direct_triple_b, 0.0);
    @memset(direct_triple_c, 0.0);
    linearQ6KPreparedQ8KActivationGroupedRange(2, q_input, .{ storage_a.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.row_major_blocks).? }, .{ storage_a.preparedBytes(.panel4), storage_b.preparedBytes(.panel4) }, .{ storage_a.preparedBytes(.panel8), storage_b.preparedBytes(.panel8) }, .{ storage_a.preparedBytes(.panel16), storage_b.preparedBytes(.panel16) }, .{ direct_pair_a, direct_pair_b }, rows, in_dim, out_dim, range_start, range_end);
    linearQ6KPreparedQ8KActivationGroupedRange(3, q_input, .{ storage_a.preparedBytes(.row_major_blocks).?, storage_b.preparedBytes(.row_major_blocks).?, storage_c.preparedBytes(.row_major_blocks).? }, .{ storage_a.preparedBytes(.panel4), storage_b.preparedBytes(.panel4), storage_c.preparedBytes(.panel4) }, .{ storage_a.preparedBytes(.panel8), storage_b.preparedBytes(.panel8), storage_c.preparedBytes(.panel8) }, .{ storage_a.preparedBytes(.panel16), storage_b.preparedBytes(.panel16), storage_c.preparedBytes(.panel16) }, .{ direct_triple_a, direct_triple_b, direct_triple_c }, rows, in_dim, out_dim, range_start, range_end);
    for (0..rows) |row_idx| {
        for (range_start..range_end) |out_idx| {
            const idx = row_idx * out_dim + out_idx;
            try std.testing.expectApproxEqAbs(direct_single_a[idx], direct_pair_a[idx], 1e-6);
            try std.testing.expectApproxEqAbs(direct_single_b[idx], direct_pair_b[idx], 1e-6);
            try std.testing.expectApproxEqAbs(direct_single_a[idx], direct_triple_a[idx], 1e-6);
            try std.testing.expectApproxEqAbs(direct_single_b[idx], direct_triple_b[idx], 1e-6);
            try std.testing.expectApproxEqAbs(direct_single_c[idx], direct_triple_c[idx], 1e-6);
        }
    }
}

// Cross-checks the MR=2 row-pair path in linearNoBiasQ4KPreparedTiledRange
// against the scalar reference (linearNoBiasQuantizedGeneric + dotQ4_KBlock).
// Uses an odd row count + non-aligned out range to exercise:
//   - the row-pair main loop
//   - the M-tail single-row fallback (last row when rows is odd)
//   - both the 4-col main tile and the N-head/N-tail single-col path
test "q4_k mr=2 row tile matches scalar reference for odd rows + mixed col tile" {
    const allocator = std.testing.allocator;
    const rows: usize = 5; // odd: exercises the M-tail
    const in_dim: usize = 256;
    const out_dim: usize = 6; // 6 = one 4-col tile + a 2-col N-tail
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q4_K };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;

    var prng = std.Random.DefaultPrng.init(0xC4D5_F00D);
    const rand = prng.random();

    var input: [rows * in_dim]f32 = undefined;
    for (&input) |*value| value.* = (rand.float(f32) * 2.0 - 1.0) * 0.5;

    const weight_raw = try allocator.alloc(u8, out_dim * block_size);
    defer allocator.free(weight_raw);
    for (weight_raw) |*byte| byte.* = rand.int(u8);
    // Make sure d/dmin (fp16, first 4 bytes) decode to finite positive
    // values per row -- avoids NaN/Inf from random fp16 patterns.
    for (0..out_dim) |row| {
        const base = row * block_size;
        weight_raw[base] = 0x00;
        weight_raw[base + 1] = 0x3C; // d = 1.0
        weight_raw[base + 2] = 0x00;
        weight_raw[base + 3] = 0x3C; // dmin = 1.0
    }

    var storage = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw,
        .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
        .raw_owned = false,
        .allocator = allocator,
    };
    defer storage.deinit();
    try prepareNativeQuantizedStorage(&storage);

    var prepared_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage, &input, &prepared_output, rows, in_dim, out_dim));

    var ref_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try linearNoBiasQuantizedGeneric(null, &input, weight_raw, &ref_output, rows, in_dim, out_dim, tensor_type, &dotQ4_KBlock);

    for (prepared_output, ref_output) |actual, expected| {
        try std.testing.expectApproxEqAbs(expected, actual, 5e-3);
    }
}

