test "small-row quant column planner chunks output columns" {
    try std.testing.expectEqual(@as(usize, 1), chooseQuantLinearColumnParallelPlan(false, true, 1, 1024, 8, 4).worker_count);
    try std.testing.expectEqual(@as(usize, 1), chooseQuantLinearColumnParallelPlan(true, false, 3, 1024, 8, 4).worker_count);
    try std.testing.expectEqual(@as(usize, 1), chooseQuantLinearColumnParallelPlan(true, true, 3, 1024, 8, 4).worker_count);
    try std.testing.expectEqual(@as(usize, 4), chooseQuantLinearColumnParallelPlanWithMaxRows(true, 77, 1024, 8, 4, 128).worker_count);
    try std.testing.expectEqual(@as(usize, 1), chooseQuantLinearColumnParallelPlanWithMaxRows(true, 129, 1024, 8, 4, 128).worker_count);
    try std.testing.expectEqual(@as(usize, 1), chooseQuantLinearColumnParallelPlan(true, true, 1, 128, 8, 4).worker_count);

    var chunks: [max_q4_k_parallel_workers]QuantColChunk = undefined;
    const count = chunkColsForWorkers(1025, .{ .worker_count = 4 }, &chunks);
    try std.testing.expectEqual(@as(usize, 4), count);
    try std.testing.expectEqual(@as(usize, 0), chunks[0].start);
    try std.testing.expectEqual(@as(usize, 1025), chunks[count - 1].end);
    for (chunks[0 .. count - 1], 0..) |chunk, idx| {
        try std.testing.expect(chunk.start < chunk.end);
        try std.testing.expectEqual(chunk.end, chunks[idx + 1].start);
    }
}

test "quantized storage budget bytes include prepared q4_k cache" {
    const allocator = std.testing.allocator;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q4_K };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const out_dim = 2;
    const in_dim = 256;
    const raw = try allocator.alloc(u8, out_dim * block_size);
    defer allocator.free(raw);
    for (raw, 0..) |*byte, idx| byte.* = @truncate((idx * 13 + 5) & 0xFF);
    for (0..out_dim) |row| {
        const base = row * block_size;
        raw[base] = 0x00;
        raw[base + 1] = 0x3C;
        raw[base + 2] = 0x00;
        raw[base + 3] = 0x3C;
    }

    var storage = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw,
        .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
        .raw_owned = false,
        .allocator = allocator,
    };
    defer storage.deinit();

    try std.testing.expectEqual(raw.len, quantizedStorageBudgetBytes(&storage));
    try prepareNativeQuantizedStorage(&storage);
    try std.testing.expectEqual(raw.len + storage.preparedBytes(.row_major_blocks).?.len, quantizedStorageBudgetBytes(&storage));
}

test "quantized storage budget bytes include packed q4_k qkv panel16 cache" {
    const allocator = std.testing.allocator;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q4_K };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const out_dim = 16;
    const in_dim = 256;

    const raw_a = try allocator.alloc(u8, out_dim * block_size);
    defer allocator.free(raw_a);
    const raw_b = try allocator.alloc(u8, out_dim * block_size);
    defer allocator.free(raw_b);
    const raw_c = try allocator.alloc(u8, out_dim * block_size);
    defer allocator.free(raw_c);
    for (raw_a, 0..) |*byte, idx| byte.* = @truncate((idx * 13 + 5) & 0xFF);
    for (raw_b, 0..) |*byte, idx| byte.* = @truncate((idx * 17 + 7) & 0xFF);
    for (raw_c, 0..) |*byte, idx| byte.* = @truncate((idx * 19 + 11) & 0xFF);
    for (0..out_dim) |row| {
        const base = row * block_size;
        inline for (.{ raw_a, raw_b, raw_c }) |raw| {
            raw[base] = 0x00;
            raw[base + 1] = 0x3C;
            raw[base + 2] = 0x00;
            raw[base + 3] = 0x3C;
        }
    }

    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_a,
        .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
        .raw_owned = false,
        .allocator = allocator,
    };
    defer storage_a.deinit();
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_b,
        .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
        .raw_owned = false,
        .allocator = allocator,
    };
    defer storage_b.deinit();
    var storage_c = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_c,
        .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
        .raw_owned = false,
        .allocator = allocator,
    };
    defer storage_c.deinit();

    try prepareNativeQuantizedStorage(&storage_a);
    try prepareNativeQuantizedStorage(&storage_b);
    try prepareNativeQuantizedStorage(&storage_c);
    const before = quantizedStorageBudgetBytes(&storage_a);
    try prepareQ4Q5QKVPanel16PackedStorageForBench(&storage_a, &storage_b, &storage_c, "k.weight", "v.weight");
    const qkv_cache = storage_a.prepared_group_cache orelse return error.TestExpectedEqual;
    try std.testing.expectEqual(QuantizedStorage.PreparedGroupCache.Format.panel16_projection_group, qkv_cache.format);
    try std.testing.expectEqual(preparedKQKVPanel16ByteSize(out_dim, in_dim / 256), qkv_cache.packed_bytes.len);
    try std.testing.expectEqual(@as(u8, 2), qkv_cache.partner_count);
    try std.testing.expectEqual(@as(u8, prepared_k_qkv_panel16_proj), qkv_cache.projection_count);
    try std.testing.expectEqual(@as(u16, prepared_k_panel16_nr), qkv_cache.panel_cols);
    try std.testing.expectEqual(@as(u32, in_dim / 256), qkv_cache.row_blocks);
    try std.testing.expectEqualStrings("k.weight", qkv_cache.partnerKeys()[0]);
    try std.testing.expectEqualStrings("v.weight", qkv_cache.partnerKeys()[1]);
    const qkv_cache_bytes = qkv_cache.ownedBytes();
    try std.testing.expectEqual(before + qkv_cache_bytes, quantizedStorageBudgetBytes(&storage_a));
}

test "prepared q4_k tiled range matches full tiled output" {
    const allocator = std.testing.allocator;
