test "prepared q4_k fused triple kernel matches biased separate matmuls" {
    const allocator = std.testing.allocator;
    const rows = 3;
    const in_dim = 256;
    const out_dim = 6;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q4_K };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;

    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 17);
        value.* = @floatFromInt(signed - 8);
    }

    const weight_raw_a = try allocator.alloc(u8, out_dim * block_size);
    defer allocator.free(weight_raw_a);
    const weight_raw_b = try allocator.alloc(u8, out_dim * block_size);
    defer allocator.free(weight_raw_b);
    const weight_raw_c = try allocator.alloc(u8, out_dim * block_size);
    defer allocator.free(weight_raw_c);
    for (weight_raw_a, 0..) |*byte, idx| byte.* = @truncate((idx * 17 + 3) & 0xFF);
    for (weight_raw_b, 0..) |*byte, idx| byte.* = @truncate((idx * 19 + 5) & 0xFF);
    for (weight_raw_c, 0..) |*byte, idx| byte.* = @truncate((idx * 23 + 7) & 0xFF);
    for (0..out_dim) |row| {
        const base = row * block_size;
        weight_raw_a[base] = 0x00;
        weight_raw_a[base + 1] = 0x3C;
        weight_raw_a[base + 2] = 0x00;
        weight_raw_a[base + 3] = 0x3C;
        weight_raw_b[base] = 0x00;
        weight_raw_b[base + 1] = 0x3C;
        weight_raw_b[base + 2] = 0x00;
        weight_raw_b[base + 3] = 0x3C;
        weight_raw_c[base] = 0x00;
        weight_raw_c[base + 1] = 0x3C;
        weight_raw_c[base + 2] = 0x00;
        weight_raw_c[base + 3] = 0x3C;
    }

    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw_a,
        .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
        .raw_owned = false,
        .allocator = allocator,
    };
    defer storage_a.deinit();
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw_b,
        .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
        .raw_owned = false,
        .allocator = allocator,
    };
    defer storage_b.deinit();
    var storage_c = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw_c,
        .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
        .raw_owned = false,
        .allocator = allocator,
    };
    defer storage_c.deinit();

    try prepareNativeQuantizedStorage(&storage_a);
    try prepareNativeQuantizedStorage(&storage_b);
    try prepareNativeQuantizedStorage(&storage_c);

    const bias_a = [_]f32{ 0.25, -0.5, 0.75, -1.0, 1.25, -1.5 };
    const bias_b = [_]f32{ -0.125, 0.375, -0.625, 0.875, -1.125, 1.375 };
    const bias_c = [_]f32{ 1.0, 0.5, 0.0, -0.5, -1.0, -1.5 };
    var output_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var output_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var output_c: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearQuantizedTriple(
        null,
        &storage_a,
        &storage_b,
        &storage_c,
        &input,
        &bias_a,
        &bias_b,
        &bias_c,
        &output_a,
        &output_b,
        &output_c,
        rows,
        in_dim,
        out_dim,
    ));

    var ref_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var ref_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var ref_c: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_a, &input, &ref_a, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, &input, &ref_b, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_c, &input, &ref_c, rows, in_dim, out_dim));
    addLinearBiasRows(&ref_a, &bias_a, rows, out_dim);
    addLinearBiasRows(&ref_b, &bias_b, rows, out_dim);
    addLinearBiasRows(&ref_c, &bias_c, rows, out_dim);

    for (output_a, ref_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
    for (output_b, ref_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
    for (output_c, ref_c) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
}

test "prepared q4_k packed qkv panel16 triple kernel matches unpacked triple dot" {
    const allocator = std.testing.allocator;
    const rows = 3;
    const in_dim = 768;
    const out_dim = 16;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q4_K };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;
    const row_blocks = in_dim / 256;

    setQ4Q5Panel16DirectOverrideForBench(true);
    setQ4Q5FusedTripleDirectOverrideForBench(true);
    setQ4Q5TriplePanel16DotOverrideForBench(true);
    setQ4Q5PackedQKVPanel16OverrideForBench(false);
    defer setQ4Q5Panel16DirectOverrideForBench(null);
    defer setQ4Q5FusedTripleDirectOverrideForBench(null);
    defer setQ4Q5TriplePanel16DotOverrideForBench(null);
    defer setQ4Q5PackedQKVPanel16OverrideForBench(null);

    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 19);
        value.* = @as(f32, @floatFromInt(signed - 9)) / 7.0;
    }

    const raw_len = out_dim * row_blocks * block_size;
    const weight_raw_a = try allocator.alloc(u8, raw_len);
    defer allocator.free(weight_raw_a);
    const weight_raw_b = try allocator.alloc(u8, raw_len);
    defer allocator.free(weight_raw_b);
    const weight_raw_c = try allocator.alloc(u8, raw_len);
    defer allocator.free(weight_raw_c);
    for (weight_raw_a, 0..) |*byte, idx| byte.* = @truncate((idx * 17 + 3) & 0xFF);
    for (weight_raw_b, 0..) |*byte, idx| byte.* = @truncate((idx * 19 + 5) & 0xFF);
    for (weight_raw_c, 0..) |*byte, idx| byte.* = @truncate((idx * 23 + 7) & 0xFF);
    for (0..out_dim) |row| {
        for (0..row_blocks) |block_idx| {
            const base = (row * row_blocks + block_idx) * block_size;
            inline for (.{ weight_raw_a, weight_raw_b, weight_raw_c }) |raw| {
                raw[base] = 0x00;
                raw[base + 1] = 0x3C;
                raw[base + 2] = 0x00;
                raw[base + 3] = 0x3C;
            }
        }
    }

    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw_a,
        .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
        .raw_owned = false,
        .allocator = allocator,
    };
    defer storage_a.deinit();
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw_b,
        .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
        .raw_owned = false,
        .allocator = allocator,
    };
    defer storage_b.deinit();
    var storage_c = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw_c,
        .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
        .raw_owned = false,
        .allocator = allocator,
    };
    defer storage_c.deinit();

    try prepareNativeQuantizedStorage(&storage_a);
    try prepareNativeQuantizedStorage(&storage_b);
    try prepareNativeQuantizedStorage(&storage_c);
    try std.testing.expect(storage_a.preparedBytes(.panel16) != null);
    try std.testing.expect(storage_b.preparedBytes(.panel16) != null);
    try std.testing.expect(storage_c.preparedBytes(.panel16) != null);

    var bias_a: [out_dim]f32 = undefined;
    var bias_b: [out_dim]f32 = undefined;
    var bias_c: [out_dim]f32 = undefined;
    for (0..out_dim) |idx| {
        bias_a[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 5)) - 2)) / 17.0;
        bias_b[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 7)) - 3)) / 19.0;
        bias_c[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 11)) - 5)) / 23.0;
    }

    var unpacked_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var unpacked_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var unpacked_c: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, &input, &bias_a, &bias_b, &bias_c, &unpacked_a, &unpacked_b, &unpacked_c, rows, in_dim, out_dim));

    try prepareQ4Q5QKVPanel16PackedStorageForBench(&storage_a, &storage_b, &storage_c, "k.weight", "v.weight");
    try std.testing.expect(preparedQKVPanel16GroupPackedBytes(&storage_a, out_dim, in_dim / 256) != null);
    setQ4Q5PackedQKVPanel16AutoOverrideForBench();

    var packed_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var packed_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var packed_c: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, &input, &bias_a, &bias_b, &bias_c, &packed_a, &packed_b, &packed_c, rows, in_dim, out_dim));

    for (packed_a, unpacked_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
    for (packed_b, unpacked_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
    for (packed_c, unpacked_c) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
}

test "prepared q4_q5 packed qkv physical panel16 kernel does not read separate panels" {
    const allocator = std.testing.allocator;
    const rows = 6;
    const in_dim = 768;
    const out_dim = 16;
    const row_blocks = in_dim / 256;
    const formats = [_]gguf_tensor_types.KnownTensorType{ .Q4_K, .Q5_K };

    setQ4Q5Panel16DirectOverrideForBench(true);
    setQ4Q5FusedTripleDirectOverrideForBench(true);
    setQ4Q5TriplePanel16DotOverrideForBench(false);
    setQ4Q5PackedQKVPanel16OverrideForBench(false);
    defer setQ4Q5Panel16DirectOverrideForBench(null);
    defer setQ4Q5FusedTripleDirectOverrideForBench(null);
    defer setQ4Q5TriplePanel16DotOverrideForBench(null);
    defer setQ4Q5PackedQKVPanel16OverrideForBench(null);

    const input = try allocator.alloc(f32, rows * in_dim);
    defer allocator.free(input);
    for (input, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 7 + 3) % 29);
        value.* = @as(f32, @floatFromInt(signed - 14)) / 11.0;
    }

    var bias_a: [out_dim]f32 = undefined;
    var bias_b: [out_dim]f32 = undefined;
    var bias_c: [out_dim]f32 = undefined;
    for (0..out_dim) |idx| {
        bias_a[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 5)) - 2)) / 17.0;
        bias_b[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 7)) - 3)) / 19.0;
        bias_c[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 11)) - 5)) / 23.0;
    }

    inline for (formats) |known| {
        const tensor_type: gguf_tensor_types.TensorType = .{ .known = known };
        const dense_a = try allocator.alloc(f32, out_dim * in_dim);
        defer allocator.free(dense_a);
        const dense_b = try allocator.alloc(f32, out_dim * in_dim);
        defer allocator.free(dense_b);
        const dense_c = try allocator.alloc(f32, out_dim * in_dim);
        defer allocator.free(dense_c);
        for (dense_a, 0..) |*value, idx| {
            const signed: i32 = @intCast((idx * 11 + 5) % 37);
            value.* = @as(f32, @floatFromInt(signed - 18)) / 23.0;
        }
        for (dense_b, 0..) |*value, idx| {
            const signed: i32 = @intCast((idx * 13 + 7) % 41);
            value.* = @as(f32, @floatFromInt(signed - 20)) / 29.0;
        }
        for (dense_c, 0..) |*value, idx| {
            const signed: i32 = @intCast((idx * 17 + 11) % 43);
            value.* = @as(f32, @floatFromInt(signed - 21)) / 31.0;
        }

        const raw_a = switch (known) {
            .Q4_K => try quant_codec.quantizeQ4_KFromF32(allocator, dense_a),
            .Q5_K => try quant_codec.quantizeQ5_KFromF32(allocator, dense_a),
            else => unreachable,
        };
        const raw_b = switch (known) {
            .Q4_K => try quant_codec.quantizeQ4_KFromF32(allocator, dense_b),
            .Q5_K => try quant_codec.quantizeQ5_KFromF32(allocator, dense_b),
            else => unreachable,
        };
        const raw_c = switch (known) {
            .Q4_K => try quant_codec.quantizeQ4_KFromF32(allocator, dense_c),
            .Q5_K => try quant_codec.quantizeQ5_KFromF32(allocator, dense_c),
            else => unreachable,
        };

        var storage_a = QuantizedStorage{
            .tensor_type = tensor_type,
            .raw_bytes = raw_a,
            .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
            .raw_owned = true,
            .allocator = allocator,
        };
        defer storage_a.deinit();
        var storage_b = QuantizedStorage{
            .tensor_type = tensor_type,
            .raw_bytes = raw_b,
            .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
            .raw_owned = true,
            .allocator = allocator,
        };
        defer storage_b.deinit();
        var storage_c = QuantizedStorage{
            .tensor_type = tensor_type,
            .raw_bytes = raw_c,
            .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
            .raw_owned = true,
            .allocator = allocator,
        };
        defer storage_c.deinit();

        try prepareNativeQuantizedStorage(&storage_a);
        try prepareNativeQuantizedStorage(&storage_b);
        try prepareNativeQuantizedStorage(&storage_c);
        try std.testing.expect(storage_a.preparedBytes(.panel16) != null);
        try std.testing.expect(storage_b.preparedBytes(.panel16) != null);
        try std.testing.expect(storage_c.preparedBytes(.panel16) != null);

        const unpacked_a = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(unpacked_a);
        const unpacked_b = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(unpacked_b);
        const unpacked_c = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(unpacked_c);
        try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, &bias_a, &bias_b, &bias_c, unpacked_a, unpacked_b, unpacked_c, rows, in_dim, out_dim));

        try prepareQ4Q5QKVPanel16PackedStorageForBench(&storage_a, &storage_b, &storage_c, "k.weight", "v.weight");
        try std.testing.expectEqual(preparedKQKVPanel16ByteSize(out_dim, row_blocks), preparedQKVPanel16GroupPackedBytes(&storage_a, out_dim, row_blocks).?.len);
        @memset(storage_a.preparedBytes(.panel16).?, 0xA5);
        @memset(storage_b.preparedBytes(.panel16).?, 0xA5);
        @memset(storage_c.preparedBytes(.panel16).?, 0xA5);
        setQ4Q5PackedQKVPanel16OverrideForBench(true);

        const packed_a = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(packed_a);
        const packed_b = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(packed_b);
        const packed_c = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(packed_c);
        try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, &bias_a, &bias_b, &bias_c, packed_a, packed_b, packed_c, rows, in_dim, out_dim));

        for (packed_a, unpacked_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
        for (packed_b, unpacked_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
        for (packed_c, unpacked_c) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
        setQ4Q5PackedQKVPanel16OverrideForBench(false);
    }
}

test "prepared q4_q5 packed qkv panel16 covers mr tails and multiple panels" {
    const allocator = std.testing.allocator;
    const cases = [_]struct {
        rows: usize,
        in_dim: usize,
        out_dim: usize,
    }{
        .{ .rows = 1, .in_dim = 1024, .out_dim = 32 },
        .{ .rows = 2, .in_dim = 1024, .out_dim = 32 },
        .{ .rows = 3, .in_dim = 1024, .out_dim = 32 },
        .{ .rows = 4, .in_dim = 1024, .out_dim = 32 },
        .{ .rows = 5, .in_dim = 1024, .out_dim = 32 },
        .{ .rows = 6, .in_dim = 1024, .out_dim = 32 },
    };
    const formats = [_]gguf_tensor_types.KnownTensorType{ .Q4_K, .Q5_K };

    setQ4Q5Panel16DirectOverrideForBench(true);
    setQ4Q5FusedTripleDirectOverrideForBench(true);
