    setQ4Q5PackedQKVPanel16OverrideForBench(false);
    defer setQ4Q5Panel16DirectOverrideForBench(null);
    defer setQ4Q5FusedTripleDirectOverrideForBench(null);
    defer setQ4Q5TriplePanel16DotOverrideForBench(null);
    defer setQ4Q5PackedQKVPanel16OverrideForBench(null);

    inline for (formats) |known| {
        for (cases) |case| {
            const tensor_type: gguf_tensor_types.TensorType = .{ .known = known };
            const row_blocks = case.in_dim / 256;
            const input = try allocator.alloc(f32, case.rows * case.in_dim);
            defer allocator.free(input);
            for (input, 0..) |*value, idx| {
                const signed: i32 = @intCast((idx * 7 + case.rows * 3) % 31);
                value.* = @as(f32, @floatFromInt(signed - 15)) / 13.0;
            }

            const dense_a = try allocator.alloc(f32, case.out_dim * case.in_dim);
            defer allocator.free(dense_a);
            const dense_b = try allocator.alloc(f32, case.out_dim * case.in_dim);
            defer allocator.free(dense_b);
            const dense_c = try allocator.alloc(f32, case.out_dim * case.in_dim);
            defer allocator.free(dense_c);
            for (dense_a, 0..) |*value, idx| {
                const signed: i32 = @intCast((idx * 11 + 5) % 37);
                value.* = @as(f32, @floatFromInt(signed - 18)) / 23.0;
            }
            for (dense_b, 0..) |*value, idx| {
                const signed: i32 = @intCast((idx * 13 + 7) % 41);
                value.* = @as(f32, @floatFromInt(signed - 20)) / 29.0;
            }
            for (dense_c, 0..) |*value, idx| {
                const signed: i32 = @intCast((idx * 17 + 11) % 43);
                value.* = @as(f32, @floatFromInt(signed - 21)) / 31.0;
            }

            const raw_a = switch (known) {
                .Q4_K => try quant_codec.quantizeQ4_KFromF32(allocator, dense_a),
                .Q5_K => try quant_codec.quantizeQ5_KFromF32(allocator, dense_a),
                else => unreachable,
            };
            const raw_b = switch (known) {
                .Q4_K => try quant_codec.quantizeQ4_KFromF32(allocator, dense_b),
                .Q5_K => try quant_codec.quantizeQ5_KFromF32(allocator, dense_b),
                else => unreachable,
            };
            const raw_c = switch (known) {
                .Q4_K => try quant_codec.quantizeQ4_KFromF32(allocator, dense_c),
                .Q5_K => try quant_codec.quantizeQ5_KFromF32(allocator, dense_c),
                else => unreachable,
            };

            var storage_a = QuantizedStorage{
                .tensor_type = tensor_type,
                .raw_bytes = raw_a,
                .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(case.out_dim)), @as(i64, @intCast(case.in_dim)) }),
                .raw_owned = true,
                .allocator = allocator,
            };
            defer storage_a.deinit();
            var storage_b = QuantizedStorage{
                .tensor_type = tensor_type,
                .raw_bytes = raw_b,
                .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(case.out_dim)), @as(i64, @intCast(case.in_dim)) }),
