            defer storage_b.deinit();
            var storage_c = QuantizedStorage{
                .tensor_type = tensor_type,
                .raw_bytes = raw_c,
                .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(case.out_dim)), @as(i64, @intCast(case.in_dim)) }),
                .raw_owned = true,
                .allocator = allocator,
            };
            defer storage_c.deinit();
            try prepareNativeQuantizedStorage(&storage_a);
            try prepareNativeQuantizedStorage(&storage_b);
            try prepareNativeQuantizedStorage(&storage_c);
            try std.testing.expect(storage_a.preparedBytes(.panel16) != null);
            try std.testing.expect(storage_b.preparedBytes(.panel16) != null);
            try std.testing.expect(storage_c.preparedBytes(.panel16) != null);

            const bias_a = try allocator.alloc(f32, case.out_dim);
            defer allocator.free(bias_a);
            const bias_b = try allocator.alloc(f32, case.out_dim);
            defer allocator.free(bias_b);
            const bias_c = try allocator.alloc(f32, case.out_dim);
            defer allocator.free(bias_c);
            for (0..case.out_dim) |idx| {
                bias_a[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 5)) - 2)) / 17.0;
                bias_b[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 7)) - 3)) / 19.0;
                bias_c[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 11)) - 5)) / 23.0;
            }

            setQ4Q5PackedQKVPanel16OverrideForBench(false);
            const unpacked_a = try allocator.alloc(f32, case.rows * case.out_dim);
            defer allocator.free(unpacked_a);
            const unpacked_b = try allocator.alloc(f32, case.rows * case.out_dim);
            defer allocator.free(unpacked_b);
            const unpacked_c = try allocator.alloc(f32, case.rows * case.out_dim);
            defer allocator.free(unpacked_c);
            try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, bias_a, bias_b, bias_c, unpacked_a, unpacked_b, unpacked_c, case.rows, case.in_dim, case.out_dim));

            try prepareQ4Q5QKVPanel16PackedStorageForBench(&storage_a, &storage_b, &storage_c, "k.weight", "v.weight");
            try std.testing.expectEqual(preparedKQKVPanel16ByteSize(case.out_dim, row_blocks), preparedQKVPanel16GroupPackedBytes(&storage_a, case.out_dim, row_blocks).?.len);
            @memset(storage_a.preparedBytes(.panel16).?, 0xA5);
            @memset(storage_b.preparedBytes(.panel16).?, 0xA5);
            @memset(storage_c.preparedBytes(.panel16).?, 0xA5);

            const packed_a = try allocator.alloc(f32, case.rows * case.out_dim);
            defer allocator.free(packed_a);
            const packed_b = try allocator.alloc(f32, case.rows * case.out_dim);
            defer allocator.free(packed_b);
            const packed_c = try allocator.alloc(f32, case.rows * case.out_dim);
            defer allocator.free(packed_c);
            setQ4Q5PackedQKVPanel16OverrideForBench(true);
            try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, bias_a, bias_b, bias_c, packed_a, packed_b, packed_c, case.rows, case.in_dim, case.out_dim));

            for (packed_a, unpacked_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
            for (packed_b, unpacked_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
            for (packed_c, unpacked_c) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
        }
    }
}

test "prepared q5_k packed qkv panel16 mr2 uses packed cache" {
    const allocator = std.testing.allocator;
    const rows = 2;
    const in_dim = 768;
    const out_dim = 512;
    const row_blocks = in_dim / 256;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q5_K };

    setQ4Q5Panel16DirectOverrideForBench(true);
    setQ4Q5FusedTripleDirectOverrideForBench(true);
    setQ4Q5TriplePanel16DotOverrideForBench(true);
    setQ4Q5PackedQKVPanel16OverrideForBench(false);
    defer setQ4Q5Panel16DirectOverrideForBench(null);
    defer setQ4Q5FusedTripleDirectOverrideForBench(null);
    defer setQ4Q5TriplePanel16DotOverrideForBench(null);
    defer setQ4Q5PackedQKVPanel16OverrideForBench(null);

    const input = try allocator.alloc(f32, rows * in_dim);
    defer allocator.free(input);
    for (input, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 7 + 3) % 31);
        value.* = @as(f32, @floatFromInt(signed - 15)) / 13.0;
    }

    const dense_a = try allocator.alloc(f32, out_dim * in_dim);
    defer allocator.free(dense_a);
    const dense_b = try allocator.alloc(f32, out_dim * in_dim);
    defer allocator.free(dense_b);
    const dense_c = try allocator.alloc(f32, out_dim * in_dim);
    defer allocator.free(dense_c);
    for (dense_a, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 11 + 5) % 37);
        value.* = @as(f32, @floatFromInt(signed - 18)) / 23.0;
    }
    for (dense_b, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 13 + 7) % 41);
        value.* = @as(f32, @floatFromInt(signed - 20)) / 29.0;
    }
    for (dense_c, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 17 + 11) % 43);
        value.* = @as(f32, @floatFromInt(signed - 21)) / 31.0;
    }

    const raw_a = try quant_codec.quantizeQ5_KFromF32(allocator, dense_a);
    const raw_b = try quant_codec.quantizeQ5_KFromF32(allocator, dense_b);
    const raw_c = try quant_codec.quantizeQ5_KFromF32(allocator, dense_c);

    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_a,
        .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(out_dim)), @as(i64, @intCast(in_dim)) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_a.deinit();
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_b,
        .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(out_dim)), @as(i64, @intCast(in_dim)) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_b.deinit();
    var storage_c = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_c,
        .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(out_dim)), @as(i64, @intCast(in_dim)) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_c.deinit();
    try prepareNativeQuantizedStorage(&storage_a);
    try prepareNativeQuantizedStorage(&storage_b);
    try prepareNativeQuantizedStorage(&storage_c);
    try std.testing.expect(storage_a.preparedBytes(.panel16) != null);
    try std.testing.expect(storage_b.preparedBytes(.panel16) != null);
    try std.testing.expect(storage_c.preparedBytes(.panel16) != null);

    const reference_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(reference_a);
    const reference_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(reference_b);
    const reference_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(reference_c);
    try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, null, null, null, reference_a, reference_b, reference_c, rows, in_dim, out_dim));

    try prepareQ4Q5QKVPanel16PackedStorageForBench(&storage_a, &storage_b, &storage_c, "k.weight", "v.weight");
    try std.testing.expectEqual(preparedKQKVPanel16ByteSize(out_dim, row_blocks), preparedQKVPanel16GroupPackedBytes(&storage_a, out_dim, row_blocks).?.len);
    @memset(storage_a.preparedBytes(.panel16).?, 0xA5);
    @memset(storage_b.preparedBytes(.panel16).?, 0xA5);
    @memset(storage_c.preparedBytes(.panel16).?, 0xA5);

    const actual_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(actual_a);
    const actual_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(actual_b);
    const actual_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(actual_c);
    setQ4Q5PackedQKVPanel16OverrideForBench(true);
    resetNativeQuantDispatchStatsForTest();
    try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, null, null, null, actual_a, actual_b, actual_c, rows, in_dim, out_dim));
    const stats = nativeQuantDispatchStatsForTest();
    try std.testing.expectEqual(@as(u64, 1), stats.q4_q5_k_q8k_activation_triple);
    try std.testing.expect(stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr2 > 0);
    try std.testing.expectEqual(@as(u64, 0), stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr4);

    const tolerance: f32 = if (shouldUseQ4_Q5_KQ8KActivationQuant(rows, out_dim, row_blocks)) 1e-4 else 2e-2;
    for (actual_a, reference_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
    for (actual_b, reference_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
    for (actual_c, reference_c) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
}

test "prepared q4_q5 packed qkv panel16 production dispatch uses packed cache" {
    const allocator = std.testing.allocator;
    const rows = 6;
    const in_dim = 768;
    const out_dim = 512;
    const row_blocks = in_dim / 256;
    const formats = [_]gguf_tensor_types.KnownTensorType{ .Q4_K, .Q5_K };

    setQ4Q5Panel16DirectOverrideForBench(true);
    setQ4Q5FusedTripleDirectOverrideForBench(true);
    setQ4Q5TriplePanel16DotOverrideForBench(true);
    setQ4Q5PackedQKVPanel16OverrideForBench(false);
    defer setQ4Q5Panel16DirectOverrideForBench(null);
    defer setQ4Q5FusedTripleDirectOverrideForBench(null);
    defer setQ4Q5TriplePanel16DotOverrideForBench(null);
    defer setQ4Q5PackedQKVPanel16OverrideForBench(null);

    const input = try allocator.alloc(f32, rows * in_dim);
    defer allocator.free(input);
    for (input, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 7 + 3) % 31);
        value.* = @as(f32, @floatFromInt(signed - 15)) / 13.0;
    }

    const bias_a = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_a);
    const bias_b = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_b);
    const bias_c = try allocator.alloc(f32, out_dim);
    defer allocator.free(bias_c);
    for (0..out_dim) |idx| {
        bias_a[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 5)) - 2)) / 17.0;
        bias_b[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 7)) - 3)) / 19.0;
        bias_c[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(idx % 11)) - 5)) / 23.0;
    }

    inline for (formats) |known| {
        const tensor_type: gguf_tensor_types.TensorType = .{ .known = known };
        const dense_a = try allocator.alloc(f32, out_dim * in_dim);
        defer allocator.free(dense_a);
        const dense_b = try allocator.alloc(f32, out_dim * in_dim);
        defer allocator.free(dense_b);
        const dense_c = try allocator.alloc(f32, out_dim * in_dim);
        defer allocator.free(dense_c);
        for (dense_a, 0..) |*value, idx| {
            const signed: i32 = @intCast((idx * 11 + 5) % 37);
            value.* = @as(f32, @floatFromInt(signed - 18)) / 23.0;
        }
        for (dense_b, 0..) |*value, idx| {
            const signed: i32 = @intCast((idx * 13 + 7) % 41);
            value.* = @as(f32, @floatFromInt(signed - 20)) / 29.0;
        }
        for (dense_c, 0..) |*value, idx| {
            const signed: i32 = @intCast((idx * 17 + 11) % 43);
            value.* = @as(f32, @floatFromInt(signed - 21)) / 31.0;
        }

        const raw_a = switch (known) {
            .Q4_K => try quant_codec.quantizeQ4_KFromF32(allocator, dense_a),
            .Q5_K => try quant_codec.quantizeQ5_KFromF32(allocator, dense_a),
            else => unreachable,
        };
        const raw_b = switch (known) {
            .Q4_K => try quant_codec.quantizeQ4_KFromF32(allocator, dense_b),
            .Q5_K => try quant_codec.quantizeQ5_KFromF32(allocator, dense_b),
            else => unreachable,
        };
        const raw_c = switch (known) {
            .Q4_K => try quant_codec.quantizeQ4_KFromF32(allocator, dense_c),
            .Q5_K => try quant_codec.quantizeQ5_KFromF32(allocator, dense_c),
            else => unreachable,
        };

        var storage_a = QuantizedStorage{
            .tensor_type = tensor_type,
            .raw_bytes = raw_a,
            .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
            .raw_owned = true,
            .allocator = allocator,
        };
        defer storage_a.deinit();
        var storage_b = QuantizedStorage{
            .tensor_type = tensor_type,
            .raw_bytes = raw_b,
            .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
            .raw_owned = true,
            .allocator = allocator,
        };
        defer storage_b.deinit();
        var storage_c = QuantizedStorage{
            .tensor_type = tensor_type,
            .raw_bytes = raw_c,
            .shape = try allocator.dupe(i64, &.{ out_dim, in_dim }),
            .raw_owned = true,
            .allocator = allocator,
        };
        defer storage_c.deinit();
        try prepareNativeQuantizedStorage(&storage_a);
        try prepareNativeQuantizedStorage(&storage_b);
        try prepareNativeQuantizedStorage(&storage_c);
        try std.testing.expect(storage_a.preparedBytes(.panel16) != null);
        try std.testing.expect(storage_b.preparedBytes(.panel16) != null);
        try std.testing.expect(storage_c.preparedBytes(.panel16) != null);

        const reference_a = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(reference_a);
        const reference_b = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(reference_b);
        const reference_c = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(reference_c);
        resetNativeQuantDispatchStatsForTest();
        setQ4Q5PackedQKVPanel16OverrideForBench(false);
        try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, bias_a, bias_b, bias_c, reference_a, reference_b, reference_c, rows, in_dim, out_dim));
        try std.testing.expectEqual(@as(u64, 1), nativeQuantDispatchStatsForTest().q4_q5_k_q8k_activation_triple);

        try prepareQ4Q5QKVPanel16PackedStorageForBench(&storage_a, &storage_b, &storage_c, "k.weight", "v.weight");
        try std.testing.expectEqual(preparedKQKVPanel16ByteSize(out_dim, row_blocks), preparedQKVPanel16GroupPackedBytes(&storage_a, out_dim, row_blocks).?.len);
        @memset(storage_a.preparedBytes(.panel16).?, 0xA5);
        @memset(storage_b.preparedBytes(.panel16).?, 0xA5);
        @memset(storage_c.preparedBytes(.panel16).?, 0xA5);

        const packed_a = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(packed_a);
        const packed_b = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(packed_b);
        const packed_c = try allocator.alloc(f32, rows * out_dim);
        defer allocator.free(packed_c);
        resetNativeQuantDispatchStatsForTest();
        setQ4Q5PackedQKVPanel16OverrideForBench(true);
        try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, bias_a, bias_b, bias_c, packed_a, packed_b, packed_c, rows, in_dim, out_dim));
        const packed_stats = nativeQuantDispatchStatsForTest();
        try std.testing.expectEqual(@as(u64, 1), packed_stats.q4_q5_k_q8k_activation_triple);
        try std.testing.expect(packed_stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr4 > 0);
        try std.testing.expect(packed_stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr2 > 0);

        for (packed_a, reference_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
        for (packed_b, reference_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
        for (packed_c, reference_c) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
    }
}

const AutoPackedQKVExpectation = enum {
    unpacked_panel16,
    packed_mr1,
    packed_mr2,
    packed_mr4,
    packed_mr8,
};

fn expectAutoPackedQKVDispatchBucket(
    allocator: std.mem.Allocator,
    known: gguf_tensor_types.KnownTensorType,
    rows: usize,
    in_dim: usize,
    out_dim: usize,
    expected_dispatch: AutoPackedQKVExpectation,
) !void {
    const row_blocks = in_dim / 256;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = known };

    setClipClapDequantSgemmOverrideForBench(false);
    setQ4Q5Panel16DirectOverrideForBench(true);
    setQ4Q5FusedTripleDirectOverrideForBench(false);
    setQ4Q5TriplePanel16DotOverrideForBench(false);
    defer setClipClapDequantSgemmOverrideForBench(null);
    defer setQ4Q5Panel16DirectOverrideForBench(null);
    defer setQ4Q5FusedTripleDirectOverrideForBench(null);
    defer setQ4Q5TriplePanel16DotOverrideForBench(null);
    defer setQ4Q5PackedQKVPanel16OverrideForBench(null);

    const input = try allocator.alloc(f32, rows * in_dim);
    defer allocator.free(input);
    fillNativeQuantDispatchValues(input, rows + in_dim + @intFromEnum(known), 0.015);

    const weight_a = try allocator.alloc(f32, out_dim * in_dim);
    defer allocator.free(weight_a);
    const weight_b = try allocator.alloc(f32, out_dim * in_dim);
    defer allocator.free(weight_b);
    const weight_c = try allocator.alloc(f32, out_dim * in_dim);
    defer allocator.free(weight_c);
    fillNativeQuantDispatchValues(weight_a, out_dim + @intFromEnum(known), 0.0125);
    fillNativeQuantDispatchValues(weight_b, out_dim + @intFromEnum(known) + 5, 0.0115);
    fillNativeQuantDispatchValues(weight_c, out_dim + @intFromEnum(known) + 11, 0.0105);

    const raw_a = try quantizeNativeDispatchWeight(allocator, known, weight_a);
    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_a,
        .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(out_dim)), @as(i64, @intCast(in_dim)) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_a.deinit();
    const raw_b = try quantizeNativeDispatchWeight(allocator, known, weight_b);
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_b,
        .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(out_dim)), @as(i64, @intCast(in_dim)) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_b.deinit();
    const raw_c = try quantizeNativeDispatchWeight(allocator, known, weight_c);
    var storage_c = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_c,
        .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(out_dim)), @as(i64, @intCast(in_dim)) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_c.deinit();

    try prepareNativeQuantizedStorage(&storage_a);
    try prepareNativeQuantizedStorage(&storage_b);
    try prepareNativeQuantizedStorage(&storage_c);
    try std.testing.expect(storage_a.preparedBytes(.panel16) != null);
    try std.testing.expect(storage_b.preparedBytes(.panel16) != null);
    try std.testing.expect(storage_c.preparedBytes(.panel16) != null);

    const reference_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(reference_a);
    const reference_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(reference_b);
    const reference_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(reference_c);

    setQ4Q5PackedQKVPanel16OverrideForBench(false);
    resetNativeQuantDispatchStatsForTest();
    try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, null, null, null, reference_a, reference_b, reference_c, rows, in_dim, out_dim));
    const reference_stats = nativeQuantDispatchStatsForTest();
    if (shouldUseQ4_Q5_KQ8KActivationQuant(rows, out_dim, row_blocks)) {
        try std.testing.expectEqual(@as(u64, 1), reference_stats.q4_q5_k_q8k_activation_triple);
    } else {
        try std.testing.expectEqual(@as(u64, 0), reference_stats.q4_q5_k_q8k_activation_triple);
    }

    try prepareQ4Q5QKVPanel16PackedStorageForBench(&storage_a, &storage_b, &storage_c, "k.weight", "v.weight");
    try std.testing.expectEqual(preparedKQKVPanel16ByteSize(out_dim, row_blocks), preparedQKVPanel16GroupPackedBytes(&storage_a, out_dim, row_blocks).?.len);

    const actual_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(actual_a);
    const actual_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(actual_b);
    const actual_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(actual_c);

    setQ4Q5PackedQKVPanel16AutoOverrideForBench();
    resetNativeQuantDispatchStatsForTest();
    try std.testing.expect(try linearQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, null, null, null, actual_a, actual_b, actual_c, rows, in_dim, out_dim));
    const stats = nativeQuantDispatchStatsForTest();
    try std.testing.expectEqual(@as(u64, 1), stats.q4_q5_k_q8k_activation_triple);
    switch (expected_dispatch) {
        .unpacked_panel16 => {
            try std.testing.expectEqual(@as(u64, 0), stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr8);
            try std.testing.expectEqual(@as(u64, 0), stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr4);
            try std.testing.expectEqual(@as(u64, 0), stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr2);
            try std.testing.expectEqual(@as(u64, 0), stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr1);
        },
        .packed_mr1 => {
            try std.testing.expect(stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr1 > 0);
            try std.testing.expectEqual(@as(u64, 0), stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr8);
            try std.testing.expectEqual(@as(u64, 0), stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr2);
            try std.testing.expectEqual(@as(u64, 0), stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr4);
        },
        .packed_mr2 => {
            try std.testing.expect(stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr2 > 0);
            try std.testing.expectEqual(@as(u64, 0), stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr8);
            try std.testing.expectEqual(@as(u64, 0), stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr1);
            try std.testing.expectEqual(@as(u64, 0), stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr4);
        },
        .packed_mr4 => {
            try std.testing.expect(stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr4 > 0);
            try std.testing.expectEqual(@as(u64, 0), stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr8);
        },
        .packed_mr8 => {
            try std.testing.expect(stats.q4_q5_k_q8k_triple_packed_qkv_panel16_mr8 > 0);
        },
    }

    const tolerance: f32 = if (shouldUseQ4_Q5_KQ8KActivationQuant(rows, out_dim, row_blocks)) 1e-4 else 2e-2;
    for (actual_a, reference_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
    for (actual_b, reference_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
    for (actual_c, reference_c) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, tolerance);
}

