test "linear q5_k kernel computes direct matmul" {
    var input: [256]f32 = [_]f32{1.0} ** 256;
    var output: [2]f32 = [_]f32{ 0.0, 0.0 };
    var weight_raw: [352]u8 = [_]u8{0} ** 352;

    // Row 0: all decoded values 1.
    weight_raw[0] = 0x00;
    weight_raw[1] = 0x3C; // d = 1.0
    for (0..4) |i| weight_raw[4 + i] = 1;
    for (0..4) |i| weight_raw[12 + i] = 1;
    for (16..144) |i| weight_raw[i] = 0x11;

    // Row 1: all decoded values 2.
    const row1 = 176;
    weight_raw[row1 + 0] = 0x00;
    weight_raw[row1 + 1] = 0x3C; // d = 1.0
    for (0..4) |i| weight_raw[row1 + 4 + i] = 1;
    for (0..4) |i| weight_raw[row1 + 12 + i] = 1;
    for (row1 + 16..row1 + 144) |i| weight_raw[i] = 0x22;

    try linearNoBiasQuantizedGeneric(null, &input, &weight_raw, &output, 1, 256, 2, .{ .known = .Q5_K }, &dotQ5_KBlock);
    try std.testing.expectApproxEqAbs(@as(f32, 1216.0), output[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 1408.0), output[1], 1e-4);
}

test "prepared q5_k headers preserve quantized linear output" {
    const allocator = std.testing.allocator;
    const rows = 3;
    const in_dim = 256;
    const out_dim = 5;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q5_K };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;

    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 19);
        value.* = @floatFromInt(signed - 9);
    }

    const weight_raw = try allocator.alloc(u8, out_dim * block_size);
    defer allocator.free(weight_raw);
    for (weight_raw, 0..) |*byte, idx| byte.* = @truncate((idx * 31 + 11) & 0xFF);
    for (0..out_dim) |row| {
        const base = row * block_size;
        weight_raw[base] = 0x00;
        weight_raw[base + 1] = 0x3C;
        weight_raw[base + 2] = 0x00;
        weight_raw[base + 3] = 0x3C;
    }

    var storage = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw,
        .shape = try allocator.dupe(i64, &.{ @as(i64, out_dim), @as(i64, in_dim) }),
        .raw_owned = false,
        .allocator = allocator,
    };
    defer storage.deinit();
    try prepareNativeQuantizedStorage(&storage);
    try std.testing.expect(storage.preparedBytes(.row_major_blocks) != null);

    var prepared_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage, &input, &prepared_output, rows, in_dim, out_dim));

    var ref_output: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try linearNoBiasQuantizedGeneric(null, &input, weight_raw, &ref_output, rows, in_dim, out_dim, tensor_type, &dotQ5_KBlock);

    for (prepared_output, ref_output) |actual, expected| {
        try std.testing.expectApproxEqAbs(expected, actual, 5e-3);
    }
}

test "linear q5_k pair kernel matches separate sibling matmuls" {
    const allocator = std.testing.allocator;
    const rows = 2;
    const in_dim = 256;
    const out_dim = 2;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q5_K };
    const block_size = 176;
    var input: [rows * in_dim]f32 = undefined;
    for (&input, 0..) |*value, idx| {
        const signed: i32 = @intCast(idx % 9);
        value.* = @floatFromInt(signed - 4);
    }

    var weight_raw_a: [352]u8 = [_]u8{0} ** 352;
    var weight_raw_b: [352]u8 = [_]u8{0} ** 352;
    for (&weight_raw_a, 0..) |*byte, idx| byte.* = @truncate((idx * 23 + 7) & 0xFF);
    for (&weight_raw_b, 0..) |*byte, idx| byte.* = @truncate((idx * 31 + 9) & 0xFF);
    for (0..out_dim) |row| {
        const base = row * block_size;
        weight_raw_a[base] = 0x00;
        weight_raw_a[base + 1] = 0x3C;
        weight_raw_b[base] = 0x00;
        weight_raw_b[base + 1] = 0x3C;
    }

    const shape = [_]i64{ out_dim, in_dim };
    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = &weight_raw_a,
        .shape = &shape,
        .raw_owned = false,
        .allocator = allocator,
    };
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = &weight_raw_b,
        .shape = &shape,
        .raw_owned = false,
        .allocator = allocator,
    };

    var output_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var output_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantizedPair(null, allocator, &storage_a, &storage_b, &input, &output_a, &output_b, rows, in_dim, out_dim));

    var ref_a: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    var ref_b: [rows * out_dim]f32 = [_]f32{0.0} ** (rows * out_dim);
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_a, &input, &ref_a, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, &input, &ref_b, rows, in_dim, out_dim));

    for (output_a, ref_a) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
    for (output_b, ref_b) |actual, expected| try std.testing.expectApproxEqAbs(expected, actual, 1e-4);
}

test "linear q6_k kernel computes direct matmul" {
    var input: [256]f32 = [_]f32{1.0} ** 256;
    var output: [2]f32 = [_]f32{ 0.0, 0.0 };
    var weight_raw: [420]u8 = [_]u8{0} ** 420;

    // Row 0: scale 1.0, per-subblock scale 1, all decoded values -32.
    for (192..208) |i| weight_raw[i] = 1;
    weight_raw[208] = 0x00;
    weight_raw[209] = 0x3C;

    // Row 1: scale 1.0, per-subblock scale 2, all decoded values -64.
    const row1 = 210;
    for (row1 + 192..row1 + 208) |i| weight_raw[i] = 2;
    weight_raw[row1 + 208] = 0x00;
    weight_raw[row1 + 209] = 0x3C;

    try linearNoBiasQuantizedGeneric(null, &input, &weight_raw, &output, 1, 256, 2, .{ .known = .Q6_K }, &dotQ6_KBlock);
    try std.testing.expectApproxEqAbs(@as(f32, -8192.0), output[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, -16384.0), output[1], 1e-4);
}

