fn fillNativeQuantDispatchValues(values: []f32, seed: usize, scale: f32) void {
    for (values, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 17 + seed * 31 + 7) % 67);
        value.* = @as(f32, @floatFromInt(signed - 33)) * scale;
    }
}

fn quantizeNativeDispatchWeight(
    allocator: std.mem.Allocator,
    known: gguf_tensor_types.KnownTensorType,
    weight: []const f32,
) ![]u8 {
    return switch (known) {
        .Q4_0 => try quant_codec.quantizeQ4_0FromF32(allocator, weight),
        .Q4_1 => try quant_codec.quantizeQ4_1FromF32(allocator, weight),
        .Q4_K => try quant_codec.quantizeQ4_KFromF32(allocator, weight),
        .Q5_K => try quant_codec.quantizeQ5_KFromF32(allocator, weight),
        .Q8_0 => try quant_codec.quantizeQ8_0FromF32(allocator, weight),
        else => unreachable,
    };
}

fn nativeDispatchTolerance(known: gguf_tensor_types.KnownTensorType, expected: f32) f32 {
    const Tolerance = struct {
        abs: f32,
        rel: f32,
    };
    const tolerance = switch (known) {
        .Q8_0 => Tolerance{ .abs = 7.5e-2, .rel = 5.0e-2 },
        .Q5_K => Tolerance{ .abs = 3.5e-1, .rel = 2.0e-1 },
        .Q4_K => Tolerance{ .abs = 5.0e-1, .rel = 2.5e-1 },
        .Q4_0, .Q4_1 => Tolerance{ .abs = 6.0e-1, .rel = 3.0e-1 },
        else => unreachable,
    };
    return @max(tolerance.abs, @abs(expected) * tolerance.rel);
}

fn expectNativeQuantDispatchBucket(
    allocator: std.mem.Allocator,
    known: gguf_tensor_types.KnownTensorType,
    rows: usize,
    in_dim: usize,
) !void {
    const out_dim: usize = 512;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = known };

    const input = try allocator.alloc(f32, rows * in_dim);
    defer allocator.free(input);
    fillNativeQuantDispatchValues(input, rows + @intFromEnum(known), 0.015);

    const weight_f32 = try allocator.alloc(f32, out_dim * in_dim);
    defer allocator.free(weight_f32);
    fillNativeQuantDispatchValues(weight_f32, in_dim + @intFromEnum(known), 0.0125);

    const weight_raw = try quantizeNativeDispatchWeight(allocator, known, weight_f32);
    var storage = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw,
        .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(out_dim)), @as(i64, @intCast(in_dim)) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage.deinit();
    try prepareNativeQuantizedStorage(&storage);
    try std.testing.expect(storage.preparedBytes(.row_major_blocks) != null);
    try std.testing.expect(storage.preparedBytes(.panel4) != null);
    if (known == .Q4_K or known == .Q5_K) try std.testing.expect(storage.preparedBytes(.panel8) != null);

    const actual = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(actual);
    @memset(actual, 0.0);

    resetNativeQuantDispatchStatsForTest();
    try std.testing.expect(try linearNoBiasQuantized(null, &storage, input, actual, rows, in_dim, out_dim));
    const stats = nativeQuantDispatchStatsForTest();
    try std.testing.expectEqual(@as(u64, 0), stats.dequant_sgemm);
    try std.testing.expectEqual(@as(u64, 0), stats.dequant_sgemm_pair);
    try std.testing.expectEqual(@as(u64, 0), stats.dequant_sgemm_triple);
    switch (known) {
        .Q4_0, .Q4_1 => try std.testing.expectEqual(@as(u64, 1), stats.legacy_activation),
        .Q4_K, .Q5_K => try std.testing.expectEqual(@as(u64, 1), stats.q4_q5_k_q8k_activation),
        .Q8_0 => try std.testing.expectEqual(@as(u64, 1), stats.q8_0_direct),
        else => unreachable,
    }

    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);
    defer deinitPrefetchQueue(&weight_store);
    const dispatched = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(dispatched);
    @memset(dispatched, 0.0);

    resetNativeQuantDispatchStatsForTest();
    try std.testing.expect(try dispatchQuantizedLinear(.{
        .compute = &compute,
        .kind = .single_no_bias,
        .input = input,
        .rows = rows,
        .in_dim = in_dim,
        .out_dim = out_dim,
        .storage_a = &storage,
        .name_a = "test.weight",
        .output_a = dispatched,
    }));
    const dispatch_stats = nativeQuantDispatchStatsForTest();
    try std.testing.expectEqual(@as(u64, 0), dispatch_stats.dequant_sgemm);
    switch (known) {
        .Q4_0, .Q4_1 => try std.testing.expectEqual(@as(u64, 1), dispatch_stats.legacy_activation),
        .Q4_K, .Q5_K => try std.testing.expectEqual(@as(u64, 1), dispatch_stats.q4_q5_k_q8k_activation),
        .Q8_0 => try std.testing.expectEqual(@as(u64, 1), dispatch_stats.q8_0_direct),
        else => unreachable,
    }
    for (dispatched, actual) |got, expected| {
        try std.testing.expectApproxEqAbs(expected, got, 1e-5);
    }

    const dense_weight = try allocator.alloc(f32, out_dim * in_dim);
    defer allocator.free(dense_weight);
    try quant_codec.dequantizeToFloat32(tensor_type, storage.raw_bytes, dense_weight);

    for (0..rows) |r| {
        const input_row = input[r * in_dim ..][0..in_dim];
        for (0..out_dim) |o| {
            const weight_row = dense_weight[o * in_dim ..][0..in_dim];
            var expected: f32 = 0.0;
            for (0..in_dim) |k| expected += input_row[k] * weight_row[k];
            const got = actual[r * out_dim + o];
            try std.testing.expect(std.math.isFinite(got));
            try std.testing.expect(@abs(got - expected) <= nativeDispatchTolerance(known, expected));
        }
    }
}

