test "native linearNoBiasWithPlan routes quantized storage through planned op" {
    const allocator = std.testing.allocator;
    const rows: usize = 4;
    const in_dim: usize = 96;
    const out_dim: usize = 16;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q8_0 };

    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);
    defer deinitPrefetchQueue(&weight_store);
    var cb = compute.computeBackend();
    try std.testing.expect(vtable_impl.linearNoBiasPlanned != null);

    const input = try allocator.alloc(f32, rows * in_dim);
    fillNativeQuantDispatchValues(input, rows, 0.015);
    const input_ct = try compute.makeBuf(input, true);
    defer cb.free(input_ct);

    const weight_f32 = try allocator.alloc(f32, out_dim * in_dim);
    defer allocator.free(weight_f32);
    fillNativeQuantDispatchValues(weight_f32, in_dim, 0.0125);

    const weight_raw = try quant_codec.quantizeQ8_0FromF32(allocator, weight_f32);
    var storage = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw,
        .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(out_dim)), @as(i64, @intCast(in_dim)) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage.deinit();
    try prepareNativeQuantizedStorage(&storage);

    const weight_ct = try compute.makeBufWithEntry(empty_f32[0..], false, "planned_q8_0.weight", null, &storage, null);
    defer cb.free(weight_ct);

    resetNativeQuantDispatchStatsForTest();
    const plan = ops.OperatorPlan{ .quant_matmul = quant_matmul.plan(.{
        .rows = rows,
        .in_dim = in_dim,
        .out_dim = out_dim,
        .format = .q8_0,
    }) };
    const out_ct = try cb.linearNoBiasWithPlan(input_ct, weight_ct, rows, in_dim, out_dim, plan);
    defer cb.free(out_ct);
    const stats = nativeQuantDispatchStatsForTest();
    try std.testing.expectEqual(@as(u64, 1), stats.q8_0_direct);
    try std.testing.expectEqual(@as(u64, 0), stats.dequant_sgemm);

    const out = try cb.toFloat32(out_ct, allocator);
    defer allocator.free(out);
    try std.testing.expectEqual(rows * out_dim, out.len);
    for (out) |value| try std.testing.expect(std.math.isFinite(value));

    const bad_rows_plan = ops.OperatorPlan{ .quant_matmul = quant_matmul.plan(.{
        .rows = rows + 1,
        .in_dim = in_dim,
        .out_dim = out_dim,
        .format = .q8_0,
    }) };
    try std.testing.expectError(error.InvalidPartitionPlan, cb.linearNoBiasWithPlan(input_ct, weight_ct, rows, in_dim, out_dim, bad_rows_plan));

    const bad_format_plan = ops.OperatorPlan{ .quant_matmul = quant_matmul.plan(.{
        .rows = rows,
        .in_dim = in_dim,
        .out_dim = out_dim,
        .format = .q4_0,
    }) };
    try std.testing.expectError(error.InvalidPartitionPlan, cb.linearNoBiasWithPlan(input_ct, weight_ct, rows, in_dim, out_dim, bad_format_plan));

    var fallback_quant_plan = quant_matmul.plan(.{
        .rows = rows,
        .in_dim = in_dim,
        .out_dim = out_dim,
        .format = .q8_0,
    });
    fallback_quant_plan.operator = .fallback;
    try std.testing.expectError(error.InvalidPartitionPlan, cb.linearNoBiasWithPlan(input_ct, weight_ct, rows, in_dim, out_dim, .{ .quant_matmul = fallback_quant_plan }));

    const row_plan = ops.OperatorPlan{ .quant_row = quant_matmul.rowOpPlan(.q8_0, .get_rows, rows, in_dim) };
    try std.testing.expectError(error.InvalidPartitionPlan, cb.linearNoBiasWithPlan(input_ct, weight_ct, rows, in_dim, out_dim, row_plan));
}

fn expectNativeQuantPairTripleDispatchBucket(
    allocator: std.mem.Allocator,
    known: gguf_tensor_types.KnownTensorType,
    rows: usize,
    in_dim: usize,
) !void {
    const out_dim: usize = 512;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = known };

    const input = try allocator.alloc(f32, rows * in_dim);
    defer allocator.free(input);
    fillNativeQuantDispatchValues(input, rows + @intFromEnum(known), 0.015);

    const weight_a = try allocator.alloc(f32, out_dim * in_dim);
    defer allocator.free(weight_a);
    const weight_b = try allocator.alloc(f32, out_dim * in_dim);
    defer allocator.free(weight_b);
    const weight_c = try allocator.alloc(f32, out_dim * in_dim);
    defer allocator.free(weight_c);
    fillNativeQuantDispatchValues(weight_a, in_dim + @intFromEnum(known), 0.0125);
    fillNativeQuantDispatchValues(weight_b, in_dim + @intFromEnum(known) + 3, 0.0115);
    fillNativeQuantDispatchValues(weight_c, in_dim + @intFromEnum(known) + 7, 0.0105);

    const raw_a = try quantizeNativeDispatchWeight(allocator, known, weight_a);
    var storage_a = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_a,
        .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(out_dim)), @as(i64, @intCast(in_dim)) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_a.deinit();

    const raw_b = try quantizeNativeDispatchWeight(allocator, known, weight_b);
    var storage_b = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_b,
        .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(out_dim)), @as(i64, @intCast(in_dim)) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_b.deinit();

    const raw_c = try quantizeNativeDispatchWeight(allocator, known, weight_c);
    var storage_c = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = raw_c,
        .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(out_dim)), @as(i64, @intCast(in_dim)) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage_c.deinit();

    try prepareNativeQuantizedStorage(&storage_a);
    try prepareNativeQuantizedStorage(&storage_b);
    try prepareNativeQuantizedStorage(&storage_c);

    const sep_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(sep_a);
    const sep_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(sep_b);
    const sep_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(sep_c);
    const pair_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(pair_a);
    const pair_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(pair_b);
    const triple_a = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(triple_a);
    const triple_b = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(triple_b);
    const triple_c = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(triple_c);

    try std.testing.expect(try linearNoBiasQuantized(null, &storage_a, input, sep_a, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_b, input, sep_b, rows, in_dim, out_dim));
    try std.testing.expect(try linearNoBiasQuantized(null, &storage_c, input, sep_c, rows, in_dim, out_dim));

    resetNativeQuantDispatchStatsForTest();
    try std.testing.expect(try linearNoBiasQuantizedPair(null, allocator, &storage_a, &storage_b, input, pair_a, pair_b, rows, in_dim, out_dim));
    const pair_stats = nativeQuantDispatchStatsForTest();
    try std.testing.expectEqual(@as(u64, 0), pair_stats.dequant_sgemm_pair);
    switch (known) {
        .Q4_0, .Q4_1 => try std.testing.expectEqual(@as(u64, 1), pair_stats.legacy_activation_pair),
        .Q4_K, .Q5_K => try std.testing.expectEqual(@as(u64, 1), pair_stats.q4_q5_k_q8k_activation_pair),
        .Q8_0 => try std.testing.expectEqual(@as(u64, 1), pair_stats.q8_0_pair),
        else => unreachable,
    }

    resetNativeQuantDispatchStatsForTest();
    try std.testing.expect(try linearNoBiasQuantizedTriple(null, &storage_a, &storage_b, &storage_c, input, triple_a, triple_b, triple_c, rows, in_dim, out_dim));
    const triple_stats = nativeQuantDispatchStatsForTest();
    try std.testing.expectEqual(@as(u64, 0), triple_stats.dequant_sgemm_triple);
    switch (known) {
        .Q4_0, .Q4_1 => try std.testing.expectEqual(@as(u64, 1), triple_stats.legacy_activation_triple),
        .Q4_K, .Q5_K => try std.testing.expectEqual(@as(u64, 1), triple_stats.q4_q5_k_q8k_activation_triple),
        .Q8_0 => try std.testing.expectEqual(@as(u64, 1), triple_stats.q8_0_triple),
        else => unreachable,
    }

    const outputs = [_]struct { actual: []const f32, expected: []const f32 }{
        .{ .actual = pair_a, .expected = sep_a },
        .{ .actual = pair_b, .expected = sep_b },
        .{ .actual = triple_a, .expected = sep_a },
        .{ .actual = triple_b, .expected = sep_b },
        .{ .actual = triple_c, .expected = sep_c },
    };
    for (outputs) |entry| {
        for (entry.actual, entry.expected) |got, expected| {
            try std.testing.expect(std.math.isFinite(got));
            try std.testing.expect(@abs(got - expected) <= nativeDispatchTolerance(known, expected));
        }
    }
}

