test "q4_k panel16 mr8 activation range matches prepared f32 path" {
    const allocator = std.testing.allocator;
    const rows: usize = 77;
    const in_dim: usize = 768;
    const out_dim: usize = 768;
    const range_start: usize = 0;
    const range_end: usize = 32;
    const row_blocks = in_dim / 256;
    const tensor_type: gguf_tensor_types.TensorType = .{ .known = .Q4_K };
    const block_size = gguf_tensor_types.bytesPerBlock(tensor_type).?;

    try std.testing.expect(chooseQ4Q5Panel16MR8DirectShape(rows, out_dim, row_blocks, .Q4_K));

    const input = try allocator.alloc(f32, rows * in_dim);
    defer allocator.free(input);
    for (input, 0..) |*value, idx| {
        const signed: i32 = @intCast((idx * 13 + (idx / in_dim) * 7 + 5) % 47);
        value.* = @as(f32, @floatFromInt(signed - 23)) / 31.0;
    }

    const weight_raw = try allocator.alloc(u8, out_dim * row_blocks * block_size);
    var dense_block: [256]f32 = undefined;
    for (0..(out_dim * row_blocks)) |block_idx| {
        for (&dense_block, 0..) |*value, i| {
            const signed: i32 = @intCast((block_idx * 11 + i * 5 + 3) % 41);
            value.* = @as(f32, @floatFromInt(signed - 20)) / 23.0;
        }
        quant_codec.quantizeQ4_KBlock(&dense_block, weight_raw[block_idx * block_size ..][0..block_size]);
    }

    var storage = QuantizedStorage{
        .tensor_type = tensor_type,
        .raw_bytes = weight_raw,
        .shape = try allocator.dupe(i64, &.{ @as(i64, @intCast(out_dim)), @as(i64, @intCast(in_dim)) }),
        .raw_owned = true,
        .allocator = allocator,
    };
    defer storage.deinit();
    try prepareNativeQuantizedStorage(&storage);
    try std.testing.expect(storage.preparedBytes(.row_major_blocks) != null);
    try std.testing.expect(storage.preparedBytes(.panel16) != null);

    const expected = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(expected);
    const actual = try allocator.alloc(f32, rows * out_dim);
    defer allocator.free(actual);
    @memset(expected, 0.0);
    @memset(actual, 0.0);

    try linearQ4KPreparedTiledRange(input, storage.preparedBytes(.row_major_blocks).?, expected, rows, in_dim, out_dim, range_start, range_end);
    const q_input = try quantizeK16Activation(allocator, null, input, rows, in_dim, row_blocks);
    defer allocator.free(q_input);
    linearQ4Q5KPreparedQ8KActivationRange(q_input, storage.preparedBytes(.row_major_blocks).?, storage.preparedBytes(.panel4), storage.preparedBytes(.panel8), storage.preparedBytes(.panel16), null, actual, rows, in_dim, out_dim, range_start, range_end, .Q4_K);

    for (0..rows) |row_idx| {
        for (range_start..range_end) |out_idx| {
            const idx = row_idx * out_dim + out_idx;
            const tolerance = @max(@abs(expected[idx]) * 1.0e-2, 5.0e-2);
            try std.testing.expect(@abs(expected[idx] - actual[idx]) <= tolerance);
        }
    }
}

