test "whereSelect resolves concrete imported bert mask against flat sequence operand" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    const elem_count = 3 * 512;
    const cond_data = try allocator.alloc(f32, elem_count);
    defer allocator.free(cond_data);
    const true_data = try allocator.alloc(f32, elem_count);
    defer allocator.free(true_data);
    var false_data = [_]f32{-1.0};

    for (0..elem_count) |i| {
        cond_data[i] = if ((i % 2) == 0) 1.0 else 0.0;
        true_data[i] = @floatFromInt(i);
    }

    const raw_c_ct = try compute.makeBuf(cond_data, false);
    defer freeTensor(&compute, raw_c_ct);
    const raw_t_ct = try compute.makeBuf(true_data, false);
    defer freeTensor(&compute, raw_t_ct);
    const f_ct = try compute.makeBuf(false_data[0..], false);
    defer freeTensor(&compute, f_ct);

    const c_ct = try compute.withLogicalShape(raw_c_ct, &.{ 3, 1, 1, 512 });
    defer if (c_ct != raw_c_ct) freeTensor(&compute, c_ct);
    const t_ct = try compute.withLogicalShape(raw_t_ct, &.{@intCast(elem_count)});
    defer if (t_ct != raw_t_ct) freeTensor(&compute, t_ct);

    const out_ct = try whereSelectOp(&compute, c_ct, t_ct, f_ct);
    defer freeTensor(&compute, out_ct);
    const out = getData(out_ct);

    try std.testing.expectEqual(@as(usize, elem_count), out.len);
    try std.testing.expectEqualSlices(i64, &.{ 3, 1, 1, 512 }, tensorStoredShape(out_ct).?);
    try std.testing.expectApproxEqAbs(@as(f32, 0.0), out[0], 1e-6);
    try std.testing.expectApproxEqAbs(@as(f32, -1.0), out[1], 1e-6);
    try std.testing.expectApproxEqAbs(@as(f32, 2.0), out[2], 1e-6);
    try std.testing.expectApproxEqAbs(@as(f32, -1.0), out[3], 1e-6);
}

