    const t_ct = try compute.withLogicalShape(raw_t_ct, &.{ 2, 4 });
    defer if (t_ct != raw_t_ct) freeTensor(&compute, t_ct);
    const f_ct = try compute.withLogicalShape(raw_f_ct, &.{ 2, 4 });
