test "whereSelect reads broadcast view condition without materializing it first" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    const cond_owned = try allocator.dupe(f32, &.{ 1.0, 0.0, 1.0 });
    const true_owned = try allocator.dupe(f32, &.{ 10.0, 20.0, 30.0, 40.0, 50.0, 60.0 });
    var false_data = [_]f32{-1.0};

    const cond_ct = try compute.makeBuf(cond_owned, true);
    defer freeTensor(&compute, cond_ct);
    const cond_shaped = try compute.withLogicalShape(cond_ct, &.{3});
    const cond_view = try primBroadcastInDimOp(&compute, cond_shaped, &.{ 2, 3 }, &.{1}, &.{3});
    defer freeTensor(&compute, cond_view);

    const true_ct = try compute.makeBuf(true_owned, true);
    defer freeTensor(&compute, true_ct);
    const true_shaped = try compute.withLogicalShape(true_ct, &.{ 2, 3 });

    const false_ct = try compute.makeBuf(false_data[0..], false);
    defer freeTensor(&compute, false_ct);

    try std.testing.expect(toBuf(cond_view).view_strides != null);
    const out_ct = try whereSelectOp(&compute, cond_view, true_shaped, false_ct);
    defer freeTensor(&compute, out_ct);

    try std.testing.expect(toBuf(cond_view).view_strides != null);
    try std.testing.expectEqualSlices(f32, &.{ 10.0, -1.0, 30.0, 40.0, -1.0, 60.0 }, getData(out_ct));
}

test "addConsumeLeft reads broadcast view rhs without materializing it first" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    const lhs_owned = try allocator.dupe(f32, &.{ 1, 2, 3, 4, 5, 6 });
    const rhs_owned = try allocator.dupe(f32, &.{ 10, 20, 30 });

    const lhs_ct = try compute.makeBuf(lhs_owned, true);
    defer freeTensor(&compute, lhs_ct);
    const lhs_shaped = try compute.withLogicalShape(lhs_ct, &.{ 2, 3 });

    const rhs_ct = try compute.makeBuf(rhs_owned, true);
    defer freeTensor(&compute, rhs_ct);
    const rhs_shaped = try compute.withLogicalShape(rhs_ct, &.{3});
    const rhs_view = try primBroadcastInDimOp(&compute, rhs_shaped, &.{ 2, 3 }, &.{1}, &.{3});
    defer freeTensor(&compute, rhs_view);

    try std.testing.expect(toBuf(rhs_view).view_strides != null);
    const out_ct = (try addConsumeLeftOp(&compute, lhs_shaped, rhs_view)).?;
    try std.testing.expectEqual(lhs_shaped, out_ct);
    try std.testing.expect(toBuf(rhs_view).view_strides != null);
    try std.testing.expectEqualSlices(f32, &.{ 11, 22, 33, 14, 25, 36 }, getData(out_ct));
}

