test "transpose resolves clip text attention shape" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    const elem_count = 8 * 77 * 64;
    const input_data = try allocator.alloc(f32, elem_count);
    for (input_data, 0..) |*value, i| value.* = @floatFromInt(i);

    const raw = try compute.makeBuf(input_data, true);
    defer freeTensor(&compute, raw);
    const shaped = try compute.withLogicalShape(raw, &.{ -1, -1, 64 });
    defer if (shaped != raw) freeTensor(&compute, shaped);

    const out = try primTransposeOp(&compute, shaped, &.{ 0, 2, 1 }, &.{ -1, -1, 64 });
    defer freeTensor(&compute, out);

    try std.testing.expectEqualSlices(i64, &.{ 8, 64, 77 }, tensorStoredShape(out).?);
    const out_data = getData(out);
    try std.testing.expectEqual(@as(usize, elem_count), out_data.len);

    const h: usize = 3;
    const d: usize = 5;
    const s: usize = 11;
    const input_index = h * 77 * 64 + s * 64 + d;
    const output_index = h * 64 * 77 + d * 77 + s;
    try std.testing.expectEqual(input_data[input_index], out_data[output_index]);
}

test "whereSelect preserves inferred attention cube shape" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    const elem_count = 3 * 8 * 3 * 3;
    const cond_data = try allocator.alloc(f32, elem_count);
    defer allocator.free(cond_data);
    const true_data = try allocator.alloc(f32, elem_count);
    defer allocator.free(true_data);
    const false_data = try allocator.alloc(f32, elem_count);
    defer allocator.free(false_data);

    for (0..elem_count) |i| {
        cond_data[i] = if ((i % 2) == 0) 1.0 else 0.0;
        true_data[i] = @floatFromInt(i);
        false_data[i] = -@as(f32, @floatFromInt(i));
    }

    const raw_c_ct = try compute.makeBuf(cond_data, false);
    defer freeTensor(&compute, raw_c_ct);
    const raw_t_ct = try compute.makeBuf(true_data, false);
    defer freeTensor(&compute, raw_t_ct);
    const raw_f_ct = try compute.makeBuf(false_data, false);
    defer freeTensor(&compute, raw_f_ct);

    const c_ct = try compute.withLogicalShape(raw_c_ct, &.{ -1, 8, -1, -1 });
    defer if (c_ct != raw_c_ct) freeTensor(&compute, c_ct);
    const t_ct = try compute.withLogicalShape(raw_t_ct, &.{ 3, 8, 3, 3 });
    defer if (t_ct != raw_t_ct) freeTensor(&compute, t_ct);
    const f_ct = try compute.withLogicalShape(raw_f_ct, &.{ 3, 8, 3, 3 });
    defer if (f_ct != raw_f_ct) freeTensor(&compute, f_ct);

    const out_ct = try whereSelectOp(&compute, c_ct, t_ct, f_ct);
    defer freeTensor(&compute, out_ct);
    const out = getData(out_ct);

    try std.testing.expectEqual(@as(usize, elem_count), out.len);
    try std.testing.expectEqualSlices(i64, &.{ 3, 8, 3, 3 }, tensorStoredShape(out_ct).?);
    try std.testing.expectApproxEqAbs(@as(f32, 0.0), out[0], 1e-6);
    try std.testing.expectApproxEqAbs(@as(f32, -1.0), out[1], 1e-6);
    try std.testing.expectApproxEqAbs(@as(f32, 2.0), out[2], 1e-6);
    try std.testing.expectApproxEqAbs(@as(f32, -3.0), out[3], 1e-6);
}

