    defer allocator.free(lhs_data);
    const rhs_data = try allocator.alloc(f32, 8);
    defer allocator.free(rhs_data);

    for (0..elem_count) |i| lhs_data[i] = @floatFromInt(i);
    for (0..8) |i| rhs_data[i] = @floatFromInt(i);

    const raw_lhs = try compute.makeBuf(lhs_data, false);
    defer freeTensor(&compute, raw_lhs);
    const raw_rhs = try compute.makeBuf(rhs_data, false);
    defer freeTensor(&compute, raw_rhs);

    const lhs = try compute.withLogicalShape(raw_lhs, &.{ -1, 8, -1, -1 });
