    defer freeTensor(&compute, in_ct);
    const shaped = try compute.withLogicalShape(in_ct, &.{ 2, 3 });

    const out_ct = try primTransposeOp(&compute, shaped, &.{ 1, 0 }, &.{ 2, 3 });
    defer freeTensor(&compute, out_ct);

    try std.testing.expect(toBuf(out_ct).view_strides != null);
    try std.testing.expectEqualSlices(i64, &.{ 3, 2 }, tensorStoredShape(out_ct).?);
    try std.testing.expectEqualSlices(f32, &.{ 1, 4, 2, 5, 3, 6 }, getData(out_ct));
    try std.testing.expect(toBuf(out_ct).view_strides == null);
}

