test "scatterAdd uses indices_shape for output rows" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    // input [2, 3], indices [2] pointing to rows 0 and 1, output shape [3] (3 output rows)
    var in_data = [_]f32{ 1, 2, 3, 4, 5, 6 };
    var idx_data = [_]f32{ 0, 1 };
    const in_ct = try compute.makeBuf(in_data[0..], false);
    defer freeTensor(&compute, in_ct);
    const idx_ct = try compute.makeBuf(idx_data[0..], false);
    defer freeTensor(&compute, idx_ct);

    const in_shape = [_]i64{ 2, 3 };
    const idx_shape = [_]i64{3}; // declares 3 output rows
    const out_ct = try primScatterAddOp(&compute, in_ct, idx_ct, &in_shape, &idx_shape, 0);
    defer freeTensor(&compute, out_ct);
    const out = getData(out_ct);
    // Output should be [3, 3]: row 0 = input row 0, row 1 = input row 1, row 2 = zeros
    try std.testing.expectEqual(@as(usize, 9), out.len);
    try std.testing.expectApproxEqAbs(@as(f32, 1.0), out[0], 1e-6);
    try std.testing.expectApproxEqAbs(@as(f32, 2.0), out[1], 1e-6);
    try std.testing.expectApproxEqAbs(@as(f32, 3.0), out[2], 1e-6);
    try std.testing.expectApproxEqAbs(@as(f32, 4.0), out[3], 1e-6);
    try std.testing.expectApproxEqAbs(@as(f32, 0.0), out[6], 1e-6); // row 2 is zeros
}

