test "softmax produces correct row-wise probabilities" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    // 2 rows of 3 elements each, last_dim_size = 3
    var data = [_]f32{ 1.0, 2.0, 3.0, 1.0, 2.0, 3.0 };
    const in_ct = try compute.makeBuf(data[0..], false);
    defer freeTensor(&compute, in_ct);

    const out_ct = try primSoftmaxOp(&compute, in_ct, 3);
    defer freeTensor(&compute, out_ct);
    const out = getData(out_ct);

    // Each row should sum to 1.0
    try std.testing.expectApproxEqAbs(@as(f32, 1.0), out[0] + out[1] + out[2], 1e-5);
    try std.testing.expectApproxEqAbs(@as(f32, 1.0), out[3] + out[4] + out[5], 1e-5);
    // Probabilities should be monotonically increasing within each row
    try std.testing.expect(out[0] < out[1]);
    try std.testing.expect(out[1] < out[2]);
}

