    const true_owned = try allocator.dupe(f32, &.{ 10.0, 20.0, 30.0, 40.0, 50.0, 60.0 });
    var false_data = [_]f32{-1.0};
    const cond_ct = try compute.makeBuf(cond_data[0..], false);
    defer freeTensor(&compute, cond_ct);
    const true_raw = try compute.makeBuf(true_owned, true);
    defer freeTensor(&compute, true_raw);
    const false_ct = try compute.makeBuf(false_data[0..], false);
    defer freeTensor(&compute, false_ct);
    _ = try compute.withLogicalShape(cond_ct, &.{ 2, 3 });

    const true_ct = try primReshapeOp(&compute, true_raw, &.{ 2, 3 });
    defer if (true_ct != true_raw) freeTensor(&compute, true_ct);

    const out_ct = (try whereSelectConsumeTrueOp(&compute, cond_ct, true_ct, false_ct)).?;
    try std.testing.expectEqual(true_ct, out_ct);
    try std.testing.expectEqualSlices(i64, &.{ 2, 3 }, tensorStoredShape(out_ct).?);
    try std.testing.expectEqualSlices(f32, &.{ 10.0, -1.0, 30.0, -1.0, -1.0, 60.0 }, getData(out_ct));
}

