    const out = getData(out_ct);
    try std.testing.expectApproxEqAbs(@as(f32, -1.3416407), out[0], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, -0.4472136), out[1], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 0.4472136), out[2], 1e-4);
    try std.testing.expectApproxEqAbs(@as(f32, 1.3416407), out[3], 1e-4);
}

