test "sdpaOp respects flattened batch-head layout" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    const batch: usize = 2;
    const seq_len: usize = 3;
    const num_heads: usize = 2;
    const head_dim: usize = 4;
    const bh = batch * num_heads;
    const total = bh * seq_len * head_dim;

    const q_data = try allocator.alloc(f32, total);
    defer allocator.free(q_data);
    const k_data = try allocator.alloc(f32, total);
    defer allocator.free(k_data);
    const v_data = try allocator.alloc(f32, total);
    defer allocator.free(v_data);
    const bias_data = try allocator.alloc(f32, bh * seq_len * seq_len);
    defer allocator.free(bias_data);
    const mask = [_]i64{
        1, 1, 0,
        1, 0, 0,
    };

    for (0..bh) |bh_idx| {
        for (0..seq_len) |s| {
            for (0..head_dim) |d| {
                const idx = (bh_idx * seq_len + s) * head_dim + d;
                q_data[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(1 + bh_idx * 17 + s * 5 + d))));
                k_data[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(2 + bh_idx * 13 + s * 7 + d * 2)))) * 0.5;
                v_data[idx] = @as(f32, @floatFromInt(@as(i32, @intCast(bh_idx * 11 + s * 3)) - @as(i32, @intCast(d)) - 3));
            }
        }
    }
    for (0..bh) |bh_idx| {
        for (0..seq_len) |qi| {
            for (0..seq_len) |ki| {
                const idx = (bh_idx * seq_len + qi) * seq_len + ki;
                const centered: i32 = @as(i32, @intCast(qi)) - @as(i32, @intCast(ki));
                bias_data[idx] = @as(f32, @floatFromInt(centered)) * 0.125;
            }
        }
    }

    const q_ct = try compute.makeBuf(q_data, false);
    defer freeTensor(&compute, q_ct);
    const k_ct = try compute.makeBuf(k_data, false);
    defer freeTensor(&compute, k_ct);
    const v_ct = try compute.makeBuf(v_data, false);
    defer freeTensor(&compute, v_ct);
    const bias_ct = try compute.makeBuf(bias_data, false);
    defer freeTensor(&compute, bias_ct);

    const out_ct = try sdpaOp(&compute, q_ct, k_ct, v_ct, &mask, bias_ct, batch, seq_len, num_heads, head_dim);
    defer freeTensor(&compute, out_ct);
    const out = getData(out_ct);

    const ref = try allocator.alloc(f32, total);
    defer allocator.free(ref);
    @memset(ref, 0.0);

    const score_row = try allocator.alloc(f32, seq_len);
    defer allocator.free(score_row);
    const scale: f32 = 1.0 / @sqrt(@as(f32, @floatFromInt(head_dim)));

    for (0..bh) |bh_idx| {
        const b = bh_idx / num_heads;
        for (0..seq_len) |qi| {
            var row_max: f32 = -std.math.inf(f32);
            for (0..seq_len) |ki| {
                if (mask[b * seq_len + ki] == 0) {
                    score_row[ki] = -std.math.inf(f32);
                    continue;
                }
                const q_base = (bh_idx * seq_len + qi) * head_dim;
                const k_base = (bh_idx * seq_len + ki) * head_dim;
                var dot: f32 = 0.0;
                for (0..head_dim) |d| {
                    dot += q_data[q_base + d] * k_data[k_base + d];
                }
                score_row[ki] = dot * scale + bias_data[(bh_idx * seq_len + qi) * seq_len + ki];
                row_max = @max(row_max, score_row[ki]);
            }

            var sum_exp: f32 = 0.0;
            for (0..seq_len) |ki| {
                if (score_row[ki] == -std.math.inf(f32)) {
                    score_row[ki] = 0.0;
                } else {
                    score_row[ki] = @exp(score_row[ki] - row_max);
                    sum_exp += score_row[ki];
                }
            }
            if (sum_exp > 0.0) {
                for (0..seq_len) |ki| score_row[ki] /= sum_exp;
            }

            const out_base = (bh_idx * seq_len + qi) * head_dim;
            for (0..seq_len) |vi| {
                const weight = score_row[vi];
                if (weight == 0.0) continue;
                const v_base = (bh_idx * seq_len + vi) * head_dim;
                for (0..head_dim) |d| {
                    ref[out_base + d] += weight * v_data[v_base + d];
                }
            }
        }
    }

    for (0..total) |i| {
        try std.testing.expectApproxEqAbs(ref[i], out[i], 1e-4);
    }
}

test "sdpaOp preserves 4d logical shape from query input" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    const batch: usize = 1;
    const seq_len: usize = 3;
    const num_heads: usize = 2;
    const head_dim: usize = 4;
    const total = batch * num_heads * seq_len * head_dim;

    const q_data = try allocator.alloc(f32, total);
    defer allocator.free(q_data);
    const k_data = try allocator.alloc(f32, total);
    defer allocator.free(k_data);
    const v_data = try allocator.alloc(f32, total);
    defer allocator.free(v_data);
    for (0..total) |i| {
        q_data[i] = @floatFromInt((i % 7) + 1);
        k_data[i] = @floatFromInt((i % 5) + 1);
        v_data[i] = @floatFromInt(@as(i32, @intCast(i % 11)) - 5);
    }
    const mask = [_]i64{ 1, 1, 1 };

    const raw_q = try compute.makeBuf(q_data, false);
    defer freeTensor(&compute, raw_q);
    const q_ct = try compute.withLogicalShape(raw_q, &.{ 1, 2, 3, 4 });
    const raw_k = try compute.makeBuf(k_data, false);
    defer freeTensor(&compute, raw_k);
    const k_ct = try compute.withLogicalShape(raw_k, &.{ 1, 2, 3, 4 });
    const raw_v = try compute.makeBuf(v_data, false);
    defer freeTensor(&compute, raw_v);
    const v_ct = try compute.withLogicalShape(raw_v, &.{ 1, 2, 3, 4 });

    const out_ct = try sdpaOp(&compute, q_ct, k_ct, v_ct, &mask, null, batch, seq_len, num_heads, head_dim);
    defer freeTensor(&compute, out_ct);

    try std.testing.expectEqualSlices(i64, &.{ 1, 2, 3, 4 }, tensorStoredShape(out_ct).?);
}

fn expectApproxEqSlice(expected: []const f32, actual: []const f32, tolerance: f32) !void {
    try std.testing.expectEqual(expected.len, actual.len);
    for (expected, actual) |want, got| {
        try std.testing.expectApproxEqAbs(want, got, tolerance);
    }
}

fn referenceBidirectionalHeadMajorAttention(
    allocator: std.mem.Allocator,
    q_data: []const f32,
    k_data: []const f32,
    v_data: []const f32,
    bias_data: ?[]const f32,
    mask: []const i64,
    batch: usize,
    seq_len: usize,
    num_heads: usize,
    head_dim: usize,
) ![]f32 {
    const bh = batch * num_heads;
    const total = bh * seq_len * head_dim;
    const ref = try allocator.alloc(f32, total);
    errdefer allocator.free(ref);
    @memset(ref, 0.0);

    const score_row = try allocator.alloc(f32, seq_len);
    defer allocator.free(score_row);
    const scale: f32 = 1.0 / @sqrt(@as(f32, @floatFromInt(head_dim)));
    const bias_shared_len = num_heads * seq_len * seq_len;
    const bias_batched_len = batch * bias_shared_len;

    for (0..bh) |bh_idx| {
        const b = bh_idx / num_heads;
        const h = bh_idx % num_heads;
        const bias_offset: ?usize = if (bias_data) |bias|
            if (bias.len == bias_batched_len)
                bh_idx * seq_len * seq_len
            else if (bias.len == bias_shared_len)
                h * seq_len * seq_len
            else
                null
        else
            null;

        for (0..seq_len) |qi| {
            var row_max: f32 = -std.math.inf(f32);
            for (0..seq_len) |ki| {
                if (mask[b * seq_len + ki] == 0) {
                    score_row[ki] = -std.math.inf(f32);
                    continue;
                }
                const q_base = (bh_idx * seq_len + qi) * head_dim;
                const k_base = (bh_idx * seq_len + ki) * head_dim;
                var dot: f32 = 0.0;
                for (0..head_dim) |d| dot += q_data[q_base + d] * k_data[k_base + d];
                var score = dot * scale;
                if (bias_data) |bias| if (bias_offset) |off| {
                    score += bias[off + qi * seq_len + ki];
                };
                score_row[ki] = score;
                row_max = @max(row_max, score);
            }

            var sum_exp: f32 = 0.0;
            for (0..seq_len) |ki| {
                if (score_row[ki] == -std.math.inf(f32)) {
                    score_row[ki] = 0.0;
                } else {
                    score_row[ki] = @exp(score_row[ki] - row_max);
                    sum_exp += score_row[ki];
                }
            }
            if (sum_exp > 0.0) {
                for (0..seq_len) |ki| score_row[ki] /= sum_exp;
            }

            const out_base = (bh_idx * seq_len + qi) * head_dim;
            for (0..seq_len) |vi| {
                const weight = score_row[vi];
                if (weight == 0.0) continue;
                const v_base = (bh_idx * seq_len + vi) * head_dim;
                for (0..head_dim) |d| ref[out_base + d] += weight * v_data[v_base + d];
            }
        }
    }

    return ref;
}

fn referenceCausalSeqMajorAttention(
    allocator: std.mem.Allocator,
    q_data: []const f32,
    k_data: []const f32,
    v_data: []const f32,
    bias_data: ?[]const f32,
    batch: usize,
    seq_len: usize,
    num_heads: usize,
    head_dim: usize,
) ![]f32 {
    const H = num_heads * head_dim;
    const total = batch * seq_len * H;
    const ref = try allocator.alloc(f32, total);
    errdefer allocator.free(ref);
    @memset(ref, 0.0);

    const score_row = try allocator.alloc(f32, seq_len);
    defer allocator.free(score_row);
    const scale: f32 = 1.0 / @sqrt(@as(f32, @floatFromInt(head_dim)));

    for (0..batch) |b| {
        for (0..num_heads) |h| {
            for (0..seq_len) |qi| {
                var row_max: f32 = -std.math.inf(f32);
                for (0..seq_len) |ki| {
                    if (ki > qi) {
                        score_row[ki] = -std.math.inf(f32);
                        continue;
                    }
                    const q_base = (b * seq_len + qi) * H + h * head_dim;
                    const k_base = (b * seq_len + ki) * H + h * head_dim;
                    var dot: f32 = 0.0;
                    for (0..head_dim) |d| dot += q_data[q_base + d] * k_data[k_base + d];
                    var score = dot * scale;
                    if (bias_data) |bias| score += bias[h * seq_len * seq_len + qi * seq_len + ki];
                    score_row[ki] = score;
                    row_max = @max(row_max, score);
                }

                var sum_exp: f32 = 0.0;
                for (0..seq_len) |ki| {
                    if (score_row[ki] == -std.math.inf(f32)) {
                        score_row[ki] = 0.0;
                    } else {
                        score_row[ki] = @exp(score_row[ki] - row_max);
                        sum_exp += score_row[ki];
                    }
                }
                if (sum_exp > 0.0) {
                    for (0..seq_len) |ki| score_row[ki] /= sum_exp;
                }

                const out_base = (b * seq_len + qi) * H + h * head_dim;
                for (0..seq_len) |vi| {
                    const weight = score_row[vi];
                    if (weight == 0.0) continue;
                    const v_base = (b * seq_len + vi) * H + h * head_dim;
                    for (0..head_dim) |d| ref[out_base + d] += weight * v_data[v_base + d];
                }
            }
        }
    }

    return ref;
}

fn referenceCrossSeqMajorAttention(
    allocator: std.mem.Allocator,
    q_data: []const f32,
    k_data: []const f32,
    v_data: []const f32,
    enc_mask: []const i64,
    batch: usize,
    dec_seq: usize,
    enc_seq: usize,
    num_heads: usize,
    head_dim: usize,
) ![]f32 {
    const H = num_heads * head_dim;
    const total = batch * dec_seq * H;
    const ref = try allocator.alloc(f32, total);
    errdefer allocator.free(ref);
    @memset(ref, 0.0);

    const score_row = try allocator.alloc(f32, enc_seq);
    defer allocator.free(score_row);
    const scale: f32 = 1.0 / @sqrt(@as(f32, @floatFromInt(head_dim)));

    for (0..batch) |b| {
        for (0..num_heads) |h| {
            for (0..dec_seq) |qi| {
                var row_max: f32 = -std.math.inf(f32);
                for (0..enc_seq) |ki| {
                    if (enc_mask[b * enc_seq + ki] == 0) {
                        score_row[ki] = -std.math.inf(f32);
                        continue;
                    }
                    const q_base = (b * dec_seq + qi) * H + h * head_dim;
                    const k_base = (b * enc_seq + ki) * H + h * head_dim;
                    var dot: f32 = 0.0;
                    for (0..head_dim) |d| dot += q_data[q_base + d] * k_data[k_base + d];
                    score_row[ki] = dot * scale;
                    row_max = @max(row_max, score_row[ki]);
                }

                var sum_exp: f32 = 0.0;
                for (0..enc_seq) |ki| {
                    if (score_row[ki] == -std.math.inf(f32)) {
                        score_row[ki] = 0.0;
                    } else {
                        score_row[ki] = @exp(score_row[ki] - row_max);
                        sum_exp += score_row[ki];
                    }
                }
                if (sum_exp > 0.0) {
                    for (0..enc_seq) |ki| score_row[ki] /= sum_exp;
                }

                const out_base = (b * dec_seq + qi) * H + h * head_dim;
                for (0..enc_seq) |vi| {
                    const weight = score_row[vi];
                    if (weight == 0.0) continue;
                    const v_base = (b * enc_seq + vi) * H + h * head_dim;
                    for (0..head_dim) |d| ref[out_base + d] += weight * v_data[v_base + d];
                }
            }
        }
    }

    return ref;
}

test "ComputeBackend scaledDotProductAttention call site exercises flash layout" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);
    const cb = ComputeBackend{ .ptr = &compute, .vtable = &vtable_impl };

    const batch: usize = 2;
    const seq_len: usize = 32;
    const num_heads: usize = 2;
    const head_dim: usize = 4;
    const bh = batch * num_heads;
    const total = bh * seq_len * head_dim;

    const q_data = try allocator.alloc(f32, total);
    defer allocator.free(q_data);
    const k_data = try allocator.alloc(f32, total);
    defer allocator.free(k_data);
    const v_data = try allocator.alloc(f32, total);
    defer allocator.free(v_data);
    const bias_data = try allocator.alloc(f32, bh * seq_len * seq_len);
    defer allocator.free(bias_data);
    var mask = [_]i64{1} ** (batch * seq_len);

    for (0..total) |i| {
        q_data[i] = @as(f32, @floatFromInt(@as(i32, @intCast((i * 7) % 23)) - 11)) * 0.07;
        k_data[i] = @as(f32, @floatFromInt(@as(i32, @intCast((i * 5) % 19)) - 9)) * 0.09;
        v_data[i] = @as(f32, @floatFromInt(@as(i32, @intCast((i * 3) % 17)) - 8)) * 0.11;
    }
    for (0..bias_data.len) |i| {
        bias_data[i] = @as(f32, @floatFromInt(@as(i32, @intCast(i % 13)) - 6)) * 0.01;
    }
    mask[seq_len + 7] = 0;
    mask[seq_len + 19] = 0;

    const q_ct = try compute.makeBuf(q_data, false);
    defer freeTensor(&compute, q_ct);
    const k_ct = try compute.makeBuf(k_data, false);
    defer freeTensor(&compute, k_ct);
    const v_ct = try compute.makeBuf(v_data, false);
    defer freeTensor(&compute, v_ct);
    const bias_ct = try compute.makeBuf(bias_data, false);
    defer freeTensor(&compute, bias_ct);

    const out_ct = try cb.scaledDotProductAttention(q_ct, k_ct, v_ct, &mask, bias_ct, batch, seq_len, num_heads, head_dim);
    defer freeTensor(&compute, out_ct);
    const ref = try referenceBidirectionalHeadMajorAttention(allocator, q_data, k_data, v_data, bias_data, &mask, batch, seq_len, num_heads, head_dim);
    defer allocator.free(ref);
    try expectApproxEqSlice(ref, getData(out_ct), 1e-4);
}

