test "dot_general flattens lhs suffix for shared rhs source tensor" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    const lhs_len = 3 * 8 * 64;
    const rhs_k = 8 * 64;
    const rhs_n = 5;

    const lhs_data = try allocator.alloc(f32, lhs_len);
    defer allocator.free(lhs_data);
    for (0..lhs_len) |i| lhs_data[i] = @floatFromInt((i % 11) + 1);

    const rhs_data = try allocator.alloc(f32, rhs_k * rhs_n);
    defer allocator.free(rhs_data);
    for (0..rhs_k) |row| {
        for (0..rhs_n) |col| {
            rhs_data[row * rhs_n + col] = @floatFromInt(((row + col) % 7) + 1);
        }
    }

    const lhs_ct = try compute.makeBuf(lhs_data, false);
    defer freeTensor(&compute, lhs_ct);
    const rhs_tensor = try tensor_mod.Tensor.initFloat32(allocator, "rhs", &.{ @as(i64, @intCast(rhs_k)), @as(i64, @intCast(rhs_n)) }, rhs_data);
    const rhs_ct = try compute.makeBufWithOwnedSourceTensor(rhs_tensor);
    defer freeTensor(&compute, rhs_ct);

    const out_ct = try primDotGeneralOp(
        &compute,
        lhs_ct,
        rhs_ct,
        &.{ 3, 8, 64 },
        &.{ @as(i64, @intCast(rhs_k)), @as(i64, @intCast(rhs_n)) },
        &.{2},
        &.{0},
        &.{0},
        &.{},
    );
    defer freeTensor(&compute, out_ct);
    const out = getData(out_ct);

    try std.testing.expectEqual(@as(usize, 3 * rhs_n), out.len);
    try std.testing.expectEqualSlices(i64, &.{ 3, rhs_n }, tensorStoredShape(out_ct).?);

    var expected: [3 * rhs_n]f32 = undefined;
    @memset(expected[0..], 0.0);
    for (0..3) |row| {
        for (0..rhs_n) |col| {
            var acc: f32 = 0.0;
            for (0..rhs_k) |k| {
                acc += lhs_data[row * rhs_k + k] * rhs_data[k * rhs_n + col];
            }
            expected[row * rhs_n + col] = acc;
        }
    }

    for (out, expected) |actual, want| {
        try std.testing.expectApproxEqAbs(want, actual, 1e-4);
    }
}

test "dot_general handles rank2 lhs transpose view without materializing input first" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    const lhs_owned = try allocator.dupe(f32, &.{ 1, 2, 3, 4, 5, 6 });
    var rhs_data = [_]f32{
        1, 2, 3, 4,
        5, 6, 7, 8,
    };

    const lhs_ct = try compute.makeBuf(lhs_owned, true);
    defer freeTensor(&compute, lhs_ct);
    const lhs_shaped = try compute.withLogicalShape(lhs_ct, &.{ 2, 3 });
    const lhs_t = try primTransposeOp(&compute, lhs_shaped, &.{ 1, 0 }, &.{ 2, 3 });
    defer freeTensor(&compute, lhs_t);

    const rhs_ct = try compute.makeBuf(rhs_data[0..], false);
    defer freeTensor(&compute, rhs_ct);
    const rhs_shaped = try compute.withLogicalShape(rhs_ct, &.{ 2, 4 });

    try std.testing.expect(toBuf(lhs_t).view_strides != null);
    const out_ct = try primDotGeneralOp(&compute, lhs_t, rhs_shaped, &.{ 3, 2 }, &.{ 2, 4 }, &.{1}, &.{0}, &.{}, &.{});
    defer freeTensor(&compute, out_ct);
    const out = getData(out_ct);

    try std.testing.expectEqualSlices(i64, &.{ 3, 4 }, tensorStoredShape(out_ct).?);
    try std.testing.expectEqualSlices(f32, &.{
        21, 26, 31, 36,
        27, 34, 41, 48,
        33, 42, 51, 60,
    }, out);
}

test "dot_general handles flattened lhs transpose view for shared rhs linear" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    const lhs_len = 2 * 3 * 4;
    const rhs_k = 4;
    const rhs_n = 5;

    const lhs_data = try allocator.alloc(f32, lhs_len);
    defer allocator.free(lhs_data);
    for (0..lhs_len) |i| lhs_data[i] = @floatFromInt(i + 1);

    const rhs_data = try allocator.alloc(f32, rhs_k * rhs_n);
    defer allocator.free(rhs_data);
    for (0..rhs_k) |row| {
        for (0..rhs_n) |col| rhs_data[row * rhs_n + col] = @floatFromInt(((row + 1) * 10) + col);
    }

    const lhs_ct = try compute.makeBuf(lhs_data, false);
    defer freeTensor(&compute, lhs_ct);
    const lhs_shaped = try compute.withLogicalShape(lhs_ct, &.{ 2, 3, 4 });
    const lhs_t = try primTransposeOp(&compute, lhs_shaped, &.{ 1, 0, 2 }, &.{ 2, 3, 4 });
    defer freeTensor(&compute, lhs_t);

    const rhs_ct = try compute.makeBuf(rhs_data, false);
    defer freeTensor(&compute, rhs_ct);
    const rhs_shaped = try compute.withLogicalShape(rhs_ct, &.{ rhs_k, rhs_n });

    try std.testing.expect(toBuf(lhs_t).view_strides != null);
    const out_ct = try primDotGeneralOp(&compute, lhs_t, rhs_shaped, &.{ 3, 2, 4 }, &.{ rhs_k, rhs_n }, &.{2}, &.{0}, &.{0}, &.{});
    defer freeTensor(&compute, out_ct);
    const out = getData(out_ct);

    try std.testing.expectEqualSlices(i64, &.{ 3, 2, rhs_n }, tensorStoredShape(out_ct).?);
    var expected: [3 * 2 * rhs_n]f32 = undefined;
    var out_idx: usize = 0;
    for (0..3) |a| {
        for (0..2) |b| {
            for (0..rhs_n) |col| {
                var acc: f32 = 0.0;
                for (0..rhs_k) |k| {
                    acc += lhs_data[(b * 3 + a) * rhs_k + k] * rhs_data[k * rhs_n + col];
                }
                expected[out_idx] = acc;
                out_idx += 1;
            }
        }
    }
    for (out, expected) |actual, want| {
        try std.testing.expectApproxEqAbs(want, actual, 1e-4);
    }
}

test "dot_general resolves symbolic batched output from peer dimensions" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    const lhs_data = try allocator.alloc(f32, 2 * 3 * 4);
    defer allocator.free(lhs_data);
    @memset(lhs_data, 1.0);

    const rhs_data = try allocator.alloc(f32, 2 * 4 * 5);
    defer allocator.free(rhs_data);
    @memset(rhs_data, 1.0);

    const lhs_ct = try compute.makeBuf(lhs_data, false);
    defer freeTensor(&compute, lhs_ct);
    const lhs_shaped = try compute.withLogicalShape(lhs_ct, &.{ -1, -1, 4 });

    const rhs_ct = try compute.makeBuf(rhs_data, false);
    defer freeTensor(&compute, rhs_ct);
    const rhs_shaped = try compute.withLogicalShape(rhs_ct, &.{ -1, 4, 5 });

    const out_ct = try primDotGeneralOp(&compute, lhs_shaped, rhs_shaped, &.{ -1, -1, 4 }, &.{ -1, 4, 5 }, &.{2}, &.{1}, &.{0}, &.{0});
    defer freeTensor(&compute, out_ct);

    try std.testing.expectEqual(@as(usize, 2 * 3 * 5), getData(out_ct).len);
    for (getData(out_ct)) |v| {
        try std.testing.expectApproxEqAbs(@as(f32, 4.0), v, 1e-6);
    }
}

