test "dot_general handles batched rhs free-before-contract layout" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);

    const batch = 1;
    const heads = 2;
    const seq = 3;
    const dim = 4;
    const total = batch * heads * seq * dim;

    const lhs_data = try allocator.alloc(f32, total);
    defer allocator.free(lhs_data);
    const rhs_data = try allocator.alloc(f32, total);
    defer allocator.free(rhs_data);
    for (0..total) |i| {
        lhs_data[i] = @floatFromInt((i % 7) + 1);
        rhs_data[i] = @floatFromInt((i % 5) + 1);
    }

    const lhs_ct = try compute.makeBuf(lhs_data, false);
    defer freeTensor(&compute, lhs_ct);
    const lhs_shaped = try compute.withLogicalShape(lhs_ct, &.{ batch, heads, seq, dim });

    const rhs_ct = try compute.makeBuf(rhs_data, false);
    defer freeTensor(&compute, rhs_ct);
    const rhs_shaped = try compute.withLogicalShape(rhs_ct, &.{ batch, heads, seq, dim });

    const out_ct = try primDotGeneralOp(
        &compute,
        lhs_shaped,
        rhs_shaped,
        &.{ batch, heads, seq, dim },
        &.{ batch, heads, seq, dim },
        &.{3},
        &.{3},
        &.{ 0, 1 },
        &.{ 0, 1 },
    );
    defer freeTensor(&compute, out_ct);

    try std.testing.expectEqualSlices(i64, &.{ batch, heads, seq, seq }, tensorStoredShape(out_ct).?);
    const out = getData(out_ct);

    var expected: [batch * heads * seq * seq]f32 = undefined;
    var out_idx: usize = 0;
    for (0..batch) |b| {
        for (0..heads) |h| {
            for (0..seq) |i| {
                for (0..seq) |j| {
                    var acc: f32 = 0.0;
                    for (0..dim) |k| {
                        const lhs_idx = (((b * heads + h) * seq + i) * dim) + k;
                        const rhs_idx = (((b * heads + h) * seq + j) * dim) + k;
                        acc += lhs_data[lhs_idx] * rhs_data[rhs_idx];
                    }
                    expected[out_idx] = acc;
                    out_idx += 1;
                }
            }
        }
    }

    for (out, expected) |actual, want| {
        try std.testing.expectApproxEqAbs(want, actual, 1e-5);
    }
}

