test "slice aliases full-range symbolic tensors" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);
    var cb = compute.computeBackend();

    const raw = try allocator.dupe(f32, &.{ 1, 2, 3, 4, 5, 6 });
    defer allocator.free(raw);
    const ct = try compute.makeBuf(raw, false);
    defer freeTensor(&compute, ct);
    const shaped = try compute.withLogicalShape(ct, &.{ -1, -1 });

    const sliced = try primSliceOp(&compute, shaped, &.{ 0, 0 }, &.{ -1, -1 }, &.{ 1, 1 }, &.{ -1, -1 });
    defer freeTensor(&compute, sliced);

    const actual_shape = try cb.tensorShape(sliced, allocator);
    defer allocator.free(actual_shape);
    try std.testing.expectEqualSlices(i64, &.{ -1, -1 }, actual_shape);

    const actual = try cb.toFloat32(sliced, allocator);
    defer allocator.free(actual);
    try std.testing.expectEqualSlices(f32, &.{ 1, 2, 3, 4, 5, 6 }, actual);
}

test "native conv ops preserve runtime logical shape" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);
    const cb = compute.computeBackend();

    var conv1_input = [_]f32{
        1, 2, 3,
        4, 5, 6,
    };
    var conv1_weight = [_]f32{1};
    var conv1_bias = [_]f32{0};
    const conv1_input_ct = try compute.makeBuf(conv1_input[0..], false);
    defer freeTensor(&compute, conv1_input_ct);
    const conv1_weight_ct = try compute.makeBuf(conv1_weight[0..], false);
    defer freeTensor(&compute, conv1_weight_ct);
    const conv1_bias_ct = try compute.makeBuf(conv1_bias[0..], false);
    defer freeTensor(&compute, conv1_bias_ct);

    const conv1_out = try conv1dOp(&compute, conv1_input_ct, conv1_weight_ct, conv1_bias_ct, 2, 1, 1, 3, 1, 1, 0);
    defer freeTensor(&compute, conv1_out);
    const conv1_shape = try cb.tensorShape(conv1_out, allocator);
    defer allocator.free(conv1_shape);
    try std.testing.expectEqualSlices(i64, &.{ 2, 1, 3 }, conv1_shape);

    var conv2_input = [_]f32{
        1, 2, 3, 4,
        5, 6, 7, 8,
    };
    var conv2_weight = [_]f32{1};
    var conv2_bias = [_]f32{0};
    const conv2_input_ct = try compute.makeBuf(conv2_input[0..], false);
    defer freeTensor(&compute, conv2_input_ct);
    const conv2_weight_ct = try compute.makeBuf(conv2_weight[0..], false);
    defer freeTensor(&compute, conv2_weight_ct);
    const conv2_bias_ct = try compute.makeBuf(conv2_bias[0..], false);
    defer freeTensor(&compute, conv2_bias_ct);

    const conv2_out = try conv2dOp(&compute, conv2_input_ct, conv2_weight_ct, conv2_bias_ct, 2, 1, 1, 2, 2, 1, 1, 1, 1, 0, 0, 1);
    defer freeTensor(&compute, conv2_out);
    const conv2_shape = try cb.tensorShape(conv2_out, allocator);
    defer allocator.free(conv2_shape);
    try std.testing.expectEqualSlices(i64, &.{ 2, 1, 2, 2 }, conv2_shape);
}

