test "exportTensorData rejects source tensors with inconsistent byte length" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);
    var cb = compute.computeBackend();

    const tensor = tensor_mod.Tensor{
        .data = &.{},
        .dtype = .f32,
        .shape = &.{ 2, 2 },
        .name = "bad_source",
        .allocator = allocator,
        .owns_data = false,
        .owns_shape = false,
    };

    const ct = try compute.makeBufWithOwnedSourceTensor(tensor);
    defer freeTensor(&compute, ct);

    try std.testing.expectError(error.InvalidTensorShape, cb.exportTensorData(ct, allocator));
}

test "exportTensorData allows zero-sized source tensors" {
    const allocator = std.testing.allocator;
    var weight_store = WeightStore{ .allocator = allocator, .resident_weights = .{}, .lazy_weights = .{} };
    var compute = NativeCompute.init(allocator, &weight_store, null);
    var cb = compute.computeBackend();

    const tensor = tensor_mod.Tensor{
        .data = &.{},
        .dtype = .f32,
        .shape = &.{ 0, 4 },
        .name = "empty_source",
        .allocator = allocator,
        .owns_data = false,
        .owns_shape = false,
    };

    const ct = try compute.makeBufWithOwnedSourceTensor(tensor);
    defer freeTensor(&compute, ct);

    const exported = (try cb.exportTensorData(ct, allocator)).?;
    defer switch (exported.payload) {
        .bytes => |bytes| allocator.free(bytes),
        .quantized_f32 => |storage| {
            allocator.free(storage.raw_bytes);
            allocator.free(storage.shape);
        },
    };
    try std.testing.expectEqual(tensor_mod.DType.f32, exported.dtype);
    try std.testing.expectEqual(@as(usize, 0), exported.payload.bytes.len);
}

test "inferReshapeShapeWithNumel splits attention heads from concrete last dim" {
    const resolved = inferReshapeShapeWithNumel(&.{ 4, 512, 768 }, &.{ -1, -1, 12, -1 }, 4 * 512 * 768) orelse return error.TestUnexpectedResult;
    try std.testing.expectEqualSlices(i64, &.{ 4, 512, 12, 64 }, resolved[0..4]);
}

test "aligned quant row chunks preserve MR4 groups" {
    var chunks: [max_q4_k_parallel_workers]QuantRowChunk = undefined;
    const count = chunkRowsForWorkersAligned(77, .{ .worker_count = 8 }, 4, &chunks);
    try std.testing.expectEqual(@as(usize, 7), count);
    try std.testing.expectEqual(QuantRowChunk{ .start = 0, .end = 12 }, chunks[0]);
    try std.testing.expectEqual(QuantRowChunk{ .start = 12, .end = 24 }, chunks[1]);
    try std.testing.expectEqual(QuantRowChunk{ .start = 60, .end = 72 }, chunks[5]);
    try std.testing.expectEqual(QuantRowChunk{ .start = 72, .end = 77 }, chunks[6]);
}

test "aligned quant row chunks preserve MR8 groups" {
    var chunks: [max_q4_k_parallel_workers]QuantRowChunk = undefined;
    const count = chunkRowsForWorkersAligned(77, .{ .worker_count = 8 }, 8, &chunks);
    try std.testing.expectEqual(@as(usize, 5), count);
    try std.testing.expectEqual(QuantRowChunk{ .start = 0, .end = 16 }, chunks[0]);
    try std.testing.expectEqual(QuantRowChunk{ .start = 16, .end = 32 }, chunks[1]);
    try std.testing.expectEqual(QuantRowChunk{ .start = 64, .end = 77 }, chunks[4]);
}

