test "convertTensorToOwnedF32 handles unaligned int64 tensor data" {
    const allocator = std.testing.allocator;
    const values = [_]i64{ 1, 3, 7 };
    const raw = std.mem.sliceAsBytes(&values);
    const bytes = try allocator.alloc(u8, raw.len + 1);
    defer allocator.free(bytes);
    bytes[0] = 0;
    @memcpy(bytes[1..], raw);

    var tensor = tensor_mod.Tensor{
        .data = bytes[1..],
        .dtype = .i64,
        .shape = &.{3},
        .name = "unaligned_i64",
        .allocator = allocator,
        .owns_data = false,
        .owns_shape = false,
    };

    const converted = try convertTensorToOwnedF32(allocator, &tensor);
    defer allocator.free(converted);
    try std.testing.expectEqualSlices(f32, &.{ 1.0, 3.0, 7.0 }, converted);
}

